0,0,0,.022)}.gantt-today-band{position:absolute;top:0;bottom:0;width:3px;background:var(--red);opacity:.55;z-index:5;pointer-events:none;border-radius:1px}.gantt-today-band::before{content:'▼';position:absolute;top:-10px;left:50%;transform:translateX(-50%);font-size:8px;color:var(--red);opacity:.8}.gantt-row-left{height:38px;display:flex;align-items:center;padding:0 8px;border-bottom:1px solid var(--border);cursor:pointer;transition:background .1s;gap:5px;overflow:hidden}.gantt-row-left:hover{background:var(--surface2)}.gantt-row-left.mission{background:rgba(0,112,242,.04);font-weight:700;font-size:12px;border-bottom:2px solid var(--border)}.gantt-row-left.task{padding-left:24px;font-size:12px}.gantt-row-left.subtask{padding-left:42px;font-size:11px;color:var(--text-muted)}.gantt-row-left.milestone-row{padding-left:24px;font-size:11px;font-style:italic;color:var(--yellow)}.gantt-row-toggle{width:14px;height:14px;border-radius:3px;background:var(--surface3);border:1px solid var(--border);display:grid;place-items:center;font-size:8px;cursor:pointer;flex-shrink:0;transition:all .15s;color:var(--text-muted)}.gantt-row-toggle:hover{background:var(--accent);border-color:var(--accent);color:#fff}.gantt-row-name{flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:12px}.gantt-assignees{display:flex;gap:2px;flex-shrink:0}.g-avatar{width:20px;height:20px;border-radius:50%;display:grid;place-items:center;font-size:8px;font-weight:700;color:#fff;border:1.5px solid #fff;flex-shrink:0;box-shadow:0 0 0 1px rgba(0,0,0,.1)}.chef-badge{font-size:8.5px;font-weight:700;background:var(--yellow-bg);color:var(--yellow);padding:1px 5px;border-radius:3px;flex-shrink:0;white-space:nowrap;border:1px solid rgba(196,125,0,.2)}.soc-badge{font-size:8.5px;background:var(--purple-bg);color:var(--purple);padding:1px 5px;border-radius:3px;font-weight:500;white-space:nowrap;border:1px solid rgba(105,65,198,.2)}.gantt-row-right{height:38px;border-bottom:1px solid var(--border);position:absolute;left:0;right:0}.gantt-row-right.mission-bg{background:rgba(0,112,242,.02)}.gantt-bar{position:absolute;border-radius:4px;display:flex;align-items:center;overflow:hidden;white-space:nowrap;cursor:pointer;transition:box-shadow .15s,filter .12s;z-index:2}.gantt-bar:hover{filter:brightness(1.08);box-shadow:0 2px 8px rgba(0,0,0,.22);z-index:3}.gantt-bar.bm{background:linear-gradient(90deg,#0064d9,#338ef7);height:24px;top:7px;border-radius:5px;box-shadow:0 1px 4px rgba(0,100,217,.3)}.gantt-bar.bt{background:linear-gradient(90deg,#1e9c6a,#34c38f);height:18px;top:10px;box-shadow:0 1px 3px rgba(30,156,106,.25)}.gantt-bar.bs{background:linear-gradient(90deg,#74c0fc,#a5d8ff);height:12px;top:13px;box-shadow:0 1px 2px rgba(116,192,252,.3)}.gantt-bar-label{position:relative;z-index:2;padding:0 7px;font-size:10px;font-weight:600;color:#fff;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;text-shadow:0 1px 2px rgba(0,0,0,.2)}.gantt-bar.bs .gantt-bar-label{color:rgba(0,60,120,.8);font-size:9px;text-shadow:none}.gantt-bar-prog{position:absolute;left:0;top:0;height:100%;background:rgba(255,255,255,.22);border-radius:4px;pointer-events:none;transition:width .6s}.gantt-milestone-diamond{position:absolute;width:14px;height:14px;background:var(--yellow);transform:rotate(45deg);z-index:4;cursor:pointer;border:2px solid #fff;border-radius:2px;box-shadow:0 1px 4px rgba(196,125,0,.4);transition:all .15s}.gantt-milestone-diamond:hover{background:var(--orange);transform:rotate(45deg) scale(1.15)}.gantt-milestone-label{position:absolute;font-size:9px;font-weight:600;color:var(--yellow);white-space:nowrap;z-index:4;pointer-events:none;margin-top:1px}.g-tooltip{position:fixed;background:var(--surface);border:1px solid var(--border2);border-radius:7px;padding:11px 14px;font-size:11.5px;box-shadow:0 6px 24px rgba(0,0,0,.15);z-index:9999;pointer-events:none;max-width:270px;display:none}.g-tooltip-title{font-weight:700;margin-bottom:7px;font-size:12.5px;border-bottom:1px solid var(--border);padding-bottom:6px}.g-tooltip-row{display:flex;gap:6px;margin-bottom:4px;align-items:flex-start}.g-tooltip-label{color:var(--text-muted);min-width:74px;font-size:10.5px;flex-shrink:0}.g-tooltip-val{font-size:11px;font-weight:500}.g-tooltip-prog{display:flex;align-items:center;gap:6px;margin-top:5px}.g-tooltip-pbar{flex:1;height:5px;background:var(--surface3);border-radius:3px;overflow:hidden}.g-tooltip-pfill{height:100%;background:var(--accent);border-radius:3px}.g-tooltip-pct{font-size:10px;font-weight:700;color:var(--accent)}.gantt-excel-row:hover{filter:brightness(.97)}.gantt-excel-row:hover .gantt-row-toggle{background:var(--accent-bg)}
/* ── Cohérence visuelle globale ── */
.toast{background:var(--surface);border:1px solid var(--border2);border-radius:var(--radius);padding:9px 13px;font-size:12px;display:flex;align-items:center;gap:9px;box-shadow:var(--shadow2);animation:tin .25s ease;min-width:210px}
.gantt-toolbar{border-radius:var(--radius) var(--radius) 0 0}
.gantt-outer{border-radius:0 0 var(--radius) var(--radius)}
.user-card{border-radius:var(--radius-sm)}
.g-tooltip{border-radius:var(--radius-lg)}
.chip{border-radius:12px}
/* Séparateur visuel section Navigation / Rapports */
.sidebar-section + .sidebar-section{border-top:1px solid var(--border);margin-top:4px;padding-top:12px}
/* Assure que les nav-icons emoji ont une taille uniforme */
.nav-icon{font-size:13px;width:18px;text-align:center;flex-shrink:0;line-height:1}
/* Hover sur wzoom plus lisible */
.wzoom:hover{background:var(--surface3);color:var(--text)}

select[multiple].finp{height:auto;padding:4px;background-image:none;appearance:auto;border-radius:4px;scrollbar-width:thin;}
select[multiple].finp option{padding:4px 8px;border-radius:3px;font-size:11.5px;}
select[multiple].finp option:checked{background:var(--accent);color:#fff;}
.multi-select-hint{font-size:9px;color:var(--text-dim);margin-top:3px;font-style:italic;}
/* ── Impression Ordre de Mission & RCM ── */
@media print {
  body > * { display:none !important; }
  #om-print-area { display:block !important; }
  #om-print-area * { -webkit-print-color-adjust:exact !important; print-color-adjust:exact !important; }

  /* ── Neutraliser le layout body (display:flex + overflow:hidden) qui
     affecte #om-print-area et peut couper du contenu ── */
  body {
    display        : block  !important;
    overflow       : visible !important;
    min-height     : 0      !important;
    height         : auto   !important;
  }

  /* ── Neutraliser les classes CSS globales qui fuient dans le printDoc ── */
  /* .widget : overflow:hidden + display:flex coupent les labels KPI */
  #om-print-area .widget {
    overflow       : visible !important;
    display        : block   !important;
    box-shadow     : none    !important;
    border-radius  : 0       !important;
  }
  /* .wtable th / .atable th : white-space:nowrap peut couper les en-têtes */
  #om-print-area th {
    white-space    : normal  !important;
    overflow       : visible !important;
    text-overflow  : unset   !important;
  }
  /* .wbody : padding intégré au widget peut décaler le contenu */
  #om-print-area .wbody {
    overflow       : visible !important;
    max-height     : none    !important;
  }
  /* .gantt-row-name, .gantt-bar-label et autres éléments text-overflow:ellipsis */
  #om-print-area * {
    text-overflow  : unset   !important;
  }
  .rcm-tdr-doc { page-break-after:always; }
  .tdr-page-cover { page: portrait-page; }
  .ra-a4-print-root { width:210mm; min-height:297mm; page-break-after:always; }



  /* ══════════════════════════════════════════════════════════════
     PAGE 1 (COUVERTURE) — AUCUN en-tête ni pied de page courant
     La couverture a son propre header/footer intégrés (cover-header
     et cover-footer) qui ne sont PAS des running headers.
     On masque explicitement tout élément fixed qui viendrait
     de la structure parente sur la couverture.
  ══════════════════════════════════════════════════════════════ */
  .tdr-page-cover {
    page-break-after : always !important;
    break-after      : page   !important;
    padding-top      : 0      !important;
    padding-bottom   : 0      !important;
  }

  /* ══════════════════════════════════════════════════════════════
     PAGE 2 (contenu TDR texte)
  ══════════════════════════════════════════════════════════════ */
  .tdr-p2-page {
    page-break-after : always    !important;
    break-after      : page      !important;
    min-height       : 297mm     !important;
    display          : flex      !important;
    flex-direction   : column    !important;
  }
  .tdr-p2-page .tdr-spacer-flex {
    display   : block    !important;
    flex      : 1 1 auto !important;
    min-height: 0        !important;
  }
  .tdr-p2-page .tdr-page-footer {
    margin-top       : 0     !important;
    flex-shrink      : 0     !important;
    page-break-before: avoid !important;
    break-before     : avoid !important;
    page-break-inside: avoid !important;
    break-inside     : avoid !important;
  }

  /* ══════════════════════════════════════════════════════════════
     PAGES DE CONTENU (tableaux RCM)
     page-break-before : force un saut avant chaque nouveau cycle.
  ══════════════════════════════════════════════════════════════ */
  .tdr-page.tdr-page-content {
    page-break-after  : auto       !important;
    break-after       : auto       !important;
    page-break-before : always     !important;
    break-before      : page       !important;
    display           : block      !important;
    min-height        : auto       !important;
    height            : auto       !important;
    max-height        : none       !important;
    box-sizing        : border-box !important;
  }
  .tdr-page-content .tdr-spacer-flex {
    display: none !important;
  }
  .tdr-page.tdr-page-content .tdr-page-footer {
    page-break-before: avoid !important;
    break-before     : avoid !important;
    page-break-inside: avoid !important;
    break-inside     : avoid !important;
  }

  /* ══════════════════════════════════════════════════════════════
     WRAPPER TABLE — structure maîtresse pour header/footer répétés
     Chrome répète thead et tfoot à chaque saut de page physique,
     y compris lors des splits internes du tableau RCM imbriqué.
     La couverture (.tdr-page-cover) n'a PAS ce wrapper → pas
     d'en-tête/pied courant sur la page 1.
  ══════════════════════════════════════════════════════════════ */

  /* Wrapper pleine page : hauteur A4 exacte (marges @page = 0) */
  .tdr-page-wrapper-table {
    width           : 100%      !important;
    height          : 297mm     !important;   /* A4 hauteur — colle le tfoot en bas */
    border-collapse : collapse  !important;
    table-layout    : fixed     !important;
    display         : table     !important;
  }

  /* thead / tfoot */
  .tdr-page-wrapper-thead,
  .tdr-page-wrapper-tfoot {
    display : table-header-group !important;
  }
  .tdr-page-wrapper-tfoot {
    display : table-footer-group !important;
  }
  .tdr-page-wrapper-tbody {
    display : table-row-group    !important;
    height  : 100%               !important;
  }
  .tdr-page-wrapper-thead td,
  .tdr-page-wrapper-tfoot td,
  .tdr-page-wrapper-tbody td {
    padding : 0 !important;
    border  : none !important;
  }
  /* tbody : s'étend, contenu en haut */
  .tdr-page-wrapper-tbody td {
    vertical-align : top    !important;
    width          : 100%   !important;
    height         : 100%   !important;
  }
  /* tfoot : cellule ancrée en bas de page */
  .tdr-page-wrapper-tfoot td {
    vertical-align : bottom !important;
  }

  /* Running header : dans le thead, pas besoin de position fixed */
  .tdr-page-wrapper-thead .tdr-running-header {
    position        : static          !important;
    display         : flex            !important;
    align-items     : center          !important;
    justify-content : space-between   !important;
    padding         : 8px 15mm 6px    !important;
    background      : #fff            !important;
    -webkit-print-color-adjust: exact !important;
    print-color-adjust        : exact !important;
  }
  .tdr-page-wrapper-thead .tdr-running-header .tdr-running-left {
    display        : flex         !important;
    flex-direction : column       !important;
    align-items    : flex-start   !important;
    gap            : 3px          !important;
  }
  .tdr-page-wrapper-thead .tdr-running-logo {
    height  : 32px !important;
    width   : auto !important;
    display : block !important;
  }
  .tdr-page-wrapper-thead .tdr-running-title1 {
    font-size   : 8pt     !important;
    font-weight : 700     !important;
    color       : #1a1a2e !important;
    white-space : nowrap  !important;
    display     : block   !important;
    line-height : 1.2     !important;
  }
  .tdr-page-wrapper-thead .tdr-running-right {
    font-size   : 9pt     !important;
    font-weight : 700     !important;
    color       : #1a1a2e !important;
    align-self  : center  !important;
    white-space : nowrap  !important;
  }
  /* Séparateur dans le thead : static */
  .tdr-page-wrapper-thead .tdr-running-separator {
    position   : static  !important;
    height     : 2px     !important;
    background : #1a1a2e !important;
    margin     : 0 15mm 4px !important;
    -webkit-print-color-adjust: exact !important;
    print-color-adjust        : exact !important;
  }

  /* Footer dans le tfoot : static */
  .tdr-page-wrapper-tfoot .tdr-page-footer {
    position        : relative !important;   /* ancre le ::after de pagination */
    display         : flex    !important;
    justify-content : space-between !important;
    border-top      : 1px solid #e0e0e0 !important;
    padding         : 6px 15mm !important;
    background      : #fff    !important;
    font-size       : 8pt     !important;
    color           : #555    !important;
    -webkit-print-color-adjust: exact !important;
    print-color-adjust        : exact !important;
  }

  /* ── Pagination "Page X sur Y" — CSS counters natifs (Chromium) ─────────
     counter(page)  : numéro de la page courante
     counter(pages) : nombre total de pages
     Injecté au centre absolu du footer via ::after — aucun JS requis.
     La couverture n'a pas de wrapper-table → non affectée.
  ── */
  .tdr-page-wrapper-tfoot .tdr-page-footer::after {
    content        : "Page " counter(page) " sur " counter(pages);
    position       : absolute;
    left           : 50%;
    top            : 50%;
    transform      : translateX(-50%) translateY(-50%);
    font-size      : 8pt;
    font-style     : italic;
    color          : #888888;
    white-space    : nowrap;
    pointer-events : none;
  }

  /* ── Masquer les anciens éléments fixed qui sont maintenant dans le wrapper ── */
  /* (au cas où des instances anciennes resteraient dans le DOM) */
  .tdr-page-content > .tdr-running-header,
  .tdr-page-content > .tdr-running-separator,
  .tdr-page-content > .tdr-page-footer,
  .tdr-p2-page      > .tdr-running-header,
  .tdr-p2-page      > .tdr-running-separator,
  .tdr-p2-page      > .tdr-page-footer {
    display : none !important;
  }

  /* ── Contenu des pages : AUCUN padding-top/bottom puisque thead/tfoot gèrent ── */
  .tdr-page-content,
  .tdr-p2-page {
    padding-top    : 0 !important;
    padding-bottom : 0 !important;
    box-sizing     : border-box !important;
  }

  /* ── Couverture : inchangée, aucun wrapper table ── */
  .tdr-page-cover {
    padding-top    : 0 !important;
    padding-bottom : 0 !important;
  }

  /* ── Le thead se répète automatiquement sur chaque nouvelle feuille ── */
  .tdr-rcm-table                 { page-break-inside:auto;  break-inside:auto;  }
  .tdr-rcm-table thead           { display:table-header-group; }
  .tdr-rcm-table tbody           { display:table-row-group;    }
  /* Une ligne de données ne doit jamais être coupée en deux */
  .tdr-rcm-table tbody tr        { page-break-inside:avoid; break-inside:avoid; }

  /* Notes : restent groupées */
  .tdr-page-content .tdr-notes   { page-break-before:avoid; break-before:avoid;
                                    page-break-inside:avoid; break-inside:avoid;
                                    margin-bottom:8px !important; }
  .tdr-page-footer               { page-break-before:avoid; break-before:avoid;
                                    page-break-inside:avoid; break-inside:avoid; }

  /* ── Impression Récapitulatif des Recommandations ── */
  #om-print-area table { min-width:0 !important; width:100% !important; }
  #om-print-area table thead { display:table-header-group; }
  #om-print-area table tbody tr { page-break-inside:avoid; break-inside:avoid; }
  .rr-print-doc { page: rr-page; }
}

/* ── Page 2 TDR — Contenu Principal ── */
.tdr-p2-page {
  width: 210mm;
  min-height: 297mm;
  background: #fff;
  font-family: 'IBM Plex Sans','Segoe UI','Calibri',Arial,sans-serif;
  font-size: 10pt;
  color: #1a1a2e;
  page-break-after: always;
  box-sizing: border-box;
  display: flex;
  flex-direction: column;
}
.tdr-p2-page .tdr-running-header { padding: 14px 25mm 8px; }
.tdr-p2-page .tdr-running-separator { margin: 0 25mm 10px; }
.tdr-p2-section {
  margin: 0 25mm 14px;
}
.tdr-p2-section-title {
  font-size: 9.5pt;
  font-weight: 700;
  color: #fff;
  background: #0d2240;
  text-transform: uppercase;
  letter-spacing: .5px;
  padding: 5px 12px;
  margin: 0 0 8px 0;
  border-radius: 2px;
}
.tdr-p2-text {
  font-size: 9.5pt;
  line-height: 1.6;
  color: #1a1a2e;
  margin-bottom: 6px;
}
.tdr-p2-sub-title {
  font-size: 9.5pt;
  font-weight: 700;
  color: #0d2240;
  margin: 8px 0 4px;
}
.tdr-p2-list {
  margin: 0 0 6px 16px;
  padding: 0;
}
.tdr-p2-list li {
  font-size: 9.5pt;
  line-height: 1.6;
  color: #1a1a2e;
  margin-bottom: 2px;
}
.tdr-p2-divider {
  height: 1.5px;
  background: linear-gradient(90deg, #0d2240, #C5A335, #0d2240);
  margin: 12px 25mm;
  border: none;
}
.tdr-p2-cols {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 0 20px;
}
.tdr-editable-block {
  border: 1.5px dashed #b0bec5;
  border-radius: 5px;
  padding: 6px 10px;
  min-height: 30px;
  transition: border-color 0.2s, background 0.2s;
  cursor: text;
}
.tdr-editable-block:focus, .tdr-editable-block:hover {
  border-color: #C5A335;
  background: #fffdf5;
}
@media print {
  .tdr-no-print { display: none !important; }
  .tdr-editable-block { border: none !important; background: transparent !important; padding: 0 !important; }
}

@page portrait-page { size: A4 portrait; margin: 0; }
@page rr-page { size: A4 portrait; margin: 12mm 15mm 14mm; }
@page {
  size: A4 portrait;
  margin: 0;
}


.rcm-tdr-doc {
  font-family:'IBM Plex Sans',Arial,sans-serif;
  font-size:10pt;
  color:#1a1a2e;
  background:#fff;
  max-width:960px;
  margin:0 auto;
  padding:0 0 24px;
}
.rcm-tdr-doc table { border-collapse:collapse; }
.rcm-tdr-doc th, .rcm-tdr-doc td { vertical-align:middle; text-align:left; }
.om-doc {
  font-family:'IBM Plex Sans',Arial,sans-serif;
  font-size:11pt;
  color:#1a1a2e;
  background:#fff;
  max-width:800px;
  margin:0 auto;
  padding:0;
}
.om-header {
  display:flex;
  align-items:flex-start;
  justify-content:space-between;
  padding:22px 28px 16px;
  border-bottom:3px solid #0070f2;
  background:linear-gradient(135deg,#0070f2 0%,#1a4fa0 100%);
  color:#fff;
}
.om-header-left { flex:1; }
.om-header-title {
  font-size:20pt;
  font-weight:700;
  letter-spacing:.02em;
  margin-bottom:2px;
}
.om-header-sub { font-size:10pt; opacity:.85; }
.om-header-ref {
  font-size:9pt;
  font-family:monospace;
  background:rgba(255,255,255,.2);
  padding:3px 10px;
  border-radius:4px;
  margin-top:6px;
  display:inline-block;
}
.om-header-logo {
  font-size:28pt;
  font-weight:900;
  opacity:.25;
  letter-spacing:-.02em;
}
.om-body { padding:20px 28px; }
.om-section-title {
  font-size:10pt;
  font-weight:700;
  color:#0070f2;
  text-transform:uppercase;
  letter-spacing:.08em;
  margin:18px 0 8px;
  padding-bottom:4px;
  border-bottom:1.5px solid #e2e8f0;
}
.om-grid {
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:8px 20px;
}
.om-field { margin-bottom:4px; }
.om-label { font-size:8pt; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:.05em; margin-bottom:1px; }
.om-value { font-size:10.5pt; color:#1a1a2e; border-bottom:1px solid #e2e8f0; padding-bottom:2px; min-height:18px; }
.om-value-full { font-size:10.5pt; color:#1a1a2e; min-height:18px; line-height:1.5; }
.om-team-table { width:100%; border-collapse:collapse; margin-top:6px; font-size:9.5pt; }
.om-team-table th { background:#f1f5f9; font-weight:700; font-size:8.5pt; text-transform:uppercase; letter-spacing:.05em; color:#64748b; padding:5px 8px; text-align:left; border:1px solid #e2e8f0; }
.om-team-table td { padding:5px 8px; border:1px solid #e2e8f0; vertical-align:top; }
.om-team-table tr:nth-child(even) td { background:#fafbfc; }
.om-obj-list { padding-left:18px; margin:0; }
.om-obj-list li { margin-bottom:4px; line-height:1.5; font-size:10.5pt; }
.om-sign-grid { display:grid; grid-template-columns:1fr 1fr; gap:20px; margin-top:16px; }
.om-sign-box { border:1px solid #e2e8f0; border-radius:5px; padding:12px 14px; }
.om-sign-box .om-label { margin-bottom:6px; }
.om-sign-line { border-bottom:1px solid #94a3b8; margin-top:50px; margin-bottom:4px; }
.om-sign-name { font-size:9pt; color:#64748b; text-align:center; }
.om-footer { margin-top:24px; padding:10px 28px; background:#f8fafc; border-top:1.5px solid #e2e8f0; display:flex; justify-content:space-between; align-items:center; font-size:8pt; color:#94a3b8; }
.om-badge { display:inline-block; padding:2px 10px; border-radius:12px; font-size:8.5pt; font-weight:700; }
.om-badge-planned { background:#dbeafe; color:#1e40af; }
.om-badge-inprogress { background:#fef3c7; color:#92400e; }
.om-badge-done { background:#dcfce7; color:#166534; }


/* ════════════════════════════════════
   IMPRESSION TDR — Risk Control Matrix
════════════════════════════════════ */
/* Page de couverture */
.tdr-page { background:#fff; padding:0; margin:0; page-break-after:always; font-family:'IBM Plex Sans','Segoe UI','Calibri',Arial,sans-serif; font-size:10.5pt; color:#1a1a2e; }
/* Pages de contenu : flex colonne, hauteur exacte A4 → footer toujours en bas */
.tdr-page.tdr-page-content {
  page-break-after : auto;
  break-after      : auto;
  display          : flex;
  flex-direction   : column;
  min-height       : 297mm;
  box-sizing       : border-box;
}
.tdr-page:last-child { page-break-after: auto; }
/* Le spacer absorbe l'espace vide entre contenu et footer — valable pour toutes les pages flex */
.tdr-page-content .tdr-spacer-flex,
.tdr-p2-page      .tdr-spacer-flex {
  flex: 1 1 auto;
  min-height: 8px;
}

/* ── NOUVELLE PAGE DE GARDE PAYSAGE ── */
.tdr-page-cover {
  width: 210mm;
  min-height: 297mm;
  display: flex;
  flex-direction: column;
  position: relative;
  overflow: hidden;
  page-break-after: always;
  box-sizing: border-box;
  background: #fff;
  border-top: 6px solid #0d2240;
}

/* Zone principale */
.tdr-cover-main {
  flex: 1;
  display: flex;
  flex-direction: column;
  padding: 10mm 20mm 10mm 20mm;
  box-sizing: border-box;
  position: relative;
  background: #fff;
}

/* En-tête logos */
.tdr-cover-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-bottom: 8mm;
  border-bottom: 1.5px solid #e0e0e0;
  margin-bottom: 0;
}
.tdr-logo-arbiochem { height: 60px; width: auto; object-fit: contain; }
.tdr-logo-filiale   { height: 54px; width: auto; object-fit: contain; }
.tdr-logo-filiale-placeholder {
  height: 54px; display: flex; align-items: center; justify-content: flex-end;
  font-size: 12pt; font-weight: 700; color: #0d2240;
}

/* Corps central (titres) */
.tdr-cover-body {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 8mm 0 6mm 0;
}
.tdr-cover-dept {
  font-size: 11pt;
  font-weight: 700;
  color: #1a3a6b;
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: 7mm;
}
.tdr-cover-sep {
  width: 60px; height: 3px;
  background: linear-gradient(90deg, #C5A335, #f0c842, #C5A335);
  margin: 0 auto 7mm auto;
  border-radius: 2px;
}
.tdr-cover-title {
  font-size: 32pt;
  font-weight: 900;
  color: #0d2240;
  letter-spacing: 1.5px;
  line-height: 1.1;
  text-transform: uppercase;
  margin-bottom: 8mm;
}
.tdr-cover-mission {
  font-size: 14pt;
  font-weight: 600;
  font-style: italic;
  color: #2c4a7a;
  letter-spacing: 0.5px;
  margin-bottom: 4mm;
}
.tdr-cover-ref {
  font-size: 11pt;
  font-weight: 700;
  color: #1a3a6b;
  letter-spacing: 1px;
  margin-top: 0;
  font-style: normal;
}

/* Pied de page */
.tdr-cover-footer {
  padding-top: 6mm;
  border-top: 1px solid #e0e0e0;
  display: flex;
  justify-content: flex-end;
  align-items: center;
}
.tdr-cover-confidential {
  font-size: 8pt;
  color: #888;
  font-style: italic;
  letter-spacing: 0.3px;
}

/* Meta label old compat */
.tdr-cover-meta-label { width:20px; border-right:1px solid #ccc; border-bottom:1px solid #eee; padding:6px 8px; text-align:center; font-size:10pt; color:#444; }
.tdr-meta-ref { font-size:9pt; font-weight:700; margin-left:6px; }
.tdr-cover-meta-value { padding:7px 16px; border-bottom:1px solid #eee; font-size:10pt; }
.tdr-cover-meta-item  { display:flex; gap:8px; align-items:baseline; }

/* Section tables (I, II) */
.tdr-section-table { width:calc(100% - 64px); margin:18px 32px 0; border-collapse:collapse; border:1px solid #ccc; }
.tdr-section-header { padding:6px 12px; font-size:9.5pt; font-weight:700; color:#1a1a2e; border-bottom:1px solid #ccc; text-transform:uppercase; letter-spacing:.3px; }
.tdr-section-body   { padding:10px 14px; font-size:9.5pt; line-height:1.55; color:#222; }

/* Running header (pages 2+) */
.tdr-running-header { display:flex; align-items:center; justify-content:space-between; padding:14px 15mm 8px; }
.tdr-running-left   { display:flex; align-items:center; gap:12px; }
.tdr-running-logo   { height:38px; width:auto; object-fit:contain; }
.tdr-running-title1 { font-size:9pt; font-weight:700; color:#1a1a2e; }
.tdr-running-title2 { font-size:8pt; color:#6B4F2A; font-weight:600; margin-top:1px; }
.tdr-running-right  { font-size:9pt; font-weight:700; color:#1a1a2e; letter-spacing:.5px; }
.tdr-running-separator { height:2px; background:#1a1a2e; margin:0 15mm 10px; }

/* Cycle title */
.tdr-cycle-title { font-size:9.5pt; font-weight:700; color:#1a1a2e; margin:8px 15mm 10px; letter-spacing:.2px; }

/* RCM table — largeur exacte A4 portrait avec marges 15mm de chaque côté
   A4 = 210mm, marges gauche+droite = 30mm → zone utile = 180mm
   Le conteneur .tdr-page-content a padding 0, donc on contrôle via margin du tableau.
*/
.tdr-rcm-table {
  width: calc(210mm - 30mm);   /* 180mm = A4 - 2×15mm de marge */
  margin: 0 auto;
  border-collapse: collapse;
  table-layout: fixed;         /* colonnes à largeur fixe, pas de débordement */
}
@media print {
  .tdr-rcm-table {
    width: calc(210mm - 30mm) !important;
    margin: 0 auto !important;
    table-layout: fixed !important;
  }
  /* ── Répétition de l'en-tête ET de la colonne Processus sur chaque page ── */
  .tdr-rcm-table thead { display: table-header-group; }
}
.tdr-rcm-thead-row { background:#C7956B; color:#fff; }
.tdr-rcm-th   { padding:8px 10px; font-size:8.5pt; font-weight:700; border:1px solid #a8784e; vertical-align:middle; }
.tdr-th-sub   { font-size:7pt; font-weight:400; opacity:.88; display:block; margin-top:2px; }
/* Colonnes en mm → total = 14+56+8+102 = 180mm = 100% */
.tdr-th-processus {
  width:14mm;
  text-align:center;
  vertical-align:middle;
  padding:4px 2px;
}
.tdr-th-processus span {
  display:inline-block;
  writing-mode: horizontal-tb;
  transform: rotate(-45deg);
  white-space: nowrap;
  font-size:8.5pt;
  font-weight:700;
}
.tdr-th-risques   { width:56mm;  text-align:left; }
.tdr-th-eval      { width:8mm;   text-align:center; }
.tdr-th-controles { width:102mm; text-align:left; }

.tdr-rcm-td { padding:7px 10px; border:1px solid #ddd; font-size:9pt; vertical-align:middle; text-align:left; word-wrap:break-word; overflow-wrap:break-word; }
/* Processus — chaque ligne a sa propre cellule (pas de rowspan) */
.tdr-td-processus {
  text-align:center;
  font-weight:700;
  font-size:8pt;
  color:#fff;
  background:#8B6343;
  vertical-align:middle;
  line-height:1.4;
  word-break:break-word;
  width:14mm;
  padding:6px 4px;
}
.tdr-proc-vertical {
  writing-mode: vertical-rl;
  text-orientation: mixed;
  transform: rotate(180deg);
  white-space: nowrap;
  display: inline-block;
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.5px;
}
/* Ligne de continuation : même processus, style légèrement atténué */
.tdr-td-processus.tdr-proc-cont {
  background:#a07858;
  font-weight:500;
  font-size:7.5pt;
  opacity:0.88;
}
/* Petite étiquette "(suite)" sur les lignes de continuation */
.tdr-proc-cont-label {
  display:block;
  font-size:6.5pt;
  font-weight:400;
  opacity:0.75;
  margin-top:2px;
  font-style:italic;
}
.tdr-td-risques   { vertical-align:middle; text-align:left; }
.tdr-td-eval      { text-align:center; vertical-align:middle; padding:4px; }
.tdr-td-controles { font-size:9pt; line-height:1.5; vertical-align:middle; text-align:left; }

.tdr-ref-tag  { display:inline-block; font-size:8pt; font-weight:700; background:#f0e8dc; color:#6B4F2A; padding:1px 6px; border-radius:3px; margin-right:4px; font-family:monospace; }
.tdr-tache-text { font-size:8pt; color:#555; margin-top:3px; font-style:italic; }
.tdr-eval-square { width:22px; height:22px; border-radius:3px; margin:auto; }

/* Notes de bas de page */
.tdr-notes { margin:12px 15mm 0; font-size:8.5pt; color:#333; line-height:1.55; }
.tdr-notes p { margin:3px 0; font-style:italic; }
.tdr-legend-line { display:flex; align-items:center; gap:6px; flex-wrap:wrap; margin-top:5px; font-style:normal !important; }
.tdr-legend-sq { display:inline-block; width:13px; height:13px; border-radius:2px; margin-left:4px; }

/* ── Wrapper table (mode écran) ──
   En impression, thead/tfoot se répètent automatiquement (voir @media print).
   En mode écran, on laisse tout en flux normal. */
.tdr-page-wrapper-table {
  width: 100%;
  border-collapse: collapse;
  table-layout: fixed;
}
.tdr-page-wrapper-thead td,
.tdr-page-wrapper-tfoot td,
.tdr-page-wrapper-tbody td {
  padding: 0;
  border: none;
  vertical-align: top;
}
.tdr-page-wrapper-tfoot .tdr-page-footer {
  display: flex;
  justify-content: space-between;
  border-top: 1px solid #e0e0e0;
  padding: 6px 15mm;
  font-size: 8pt;
  color: #555;
  background: #fff;
}

/* Numéro de page — texte injecté par JS */


/* Pied de page des sections de contenu — toujours collé en bas */
.tdr-page-footer {
  flex-shrink: 0;             /* ne se compresse jamais */
  margin-top: 0;
  padding: 8px 15mm;
  border-top: 1px solid #e0e0e0;
  display: flex;
  justify-content: space-between;
  font-size: 7.5pt;
  color: #888;
  font-style: italic;
}

/* ── Sidebar toggle ── */
#btn-sidebar-toggle {
  width: 32px; height: 32px;
  display: grid; place-items: center;
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: var(--text-muted);
  font-size: 16px;
  flex-shrink: 0;
  transition: background .15s, color .15s;
  margin-right: 2px;
}
#btn-sidebar-toggle:hover { background: var(--surface2); color: var(--text); }

/* Sidebar visible (état par défaut) */
.sidebar {
  transition: transform .22s ease, width .22s ease;
  transform: translateX(0);
}
/* Sidebar masquée */
body.sidebar-hidden .sidebar {
  transform: translateX(-216px);
}
/* Zone principale s'étend quand sidebar masquée */
.main {
  transition: margin-left .22s ease;
}
body.sidebar-hidden .main {
  margin-left: 0 !important;
}

/* ── Responsive : tablette / mobile ── */
.sidebar-backdrop{display:none;position:fixed;inset:0;background:rgba(0,0,0,.4);z-index:99}
@media (max-width:880px){
  .sidebar{
    position:fixed;left:0;top:0;z-index:200;
    transform:translateX(-100%);
    box-shadow:0 0 0 transparent;
  }
  body.sidebar-mobile-open .sidebar{
    transform:translateX(0);
    box-shadow:2px 0 18px rgba(0,0,0,.22);
  }
  body.sidebar-hidden .sidebar{ transform:translateX(-100%); }
  .main{ margin-left:0 !important; }
  body.sidebar-mobile-open .sidebar-backdrop{ display:block; }
  .topbar{ padding:0 8px; gap:5px; flex-wrap:nowrap; overflow-x:auto; }
  .tb-sap{ display:none; }
  .tb-title{ font-size:12px; }
  .srch{ width:96px; }
  .srch input::placeholder{ font-size:11px; }
  #autosave-indicator span#autosave-label{ display:none; }
  .wg3,.wg32{ grid-template-columns:1fr !important; }
  .content{ padding:10px 8px 16px; }
  .modal{ width:94vw !important; max-width:94vw; }
  .fgrid{ grid-template-columns:1fr; }
  .panel,.widget{ overflow-x:auto; }
  .atable,.wtable{ min-width:560px; }
  .gantt-left{ width:160px; }
  #widget-zoom-overlay{ padding:10px; }
}
@media (max-width:520px){
  .srch{ display:none; }
  .tb-title{ max-width:120px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap; }
  select.fsel{ display:none; }
}
</style>
</head>
