          <tbody id="actions-tbody"></tbody>
        </table>
        </div>
      </div>
    </div>

    <div id="view-recap-reco" style="display:none;margin-top:10px;">

      <!-- ── Barre de contrôle hors A4 ── -->
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;flex-wrap:wrap;padding:10px 14px;background:var(--surface2);border:1px solid var(--border);border-radius:8px;">
        <strong style="font-size:13px;font-weight:700;color:var(--text);">📊 Récapitulatif des Recommandations</strong>
        <select id="rr-filter-societe" class="fsel" style="height:28px;font-size:11px;min-width:150px;"><option value="">Toutes les sociétés</option></select>
        <select id="rr-filter-criticite" class="fsel" style="height:28px;font-size:11px;min-width:110px;">
          <option value="">Toutes criticités</option>
          <option value="critical">🔴 Critique</option>
          <option value="high">🟠 Élevé</option>
          <option value="medium">🟡 Moyen</option>
          <option value="low">🟢 Faible</option>
        </select>
        <select id="rr-filter-statut" class="fsel" style="height:28px;font-size:11px;min-width:160px;">
          <option value="">Tous les statuts</option>
          <option value="fully">✅ Clos — Implémenté</option>
          <option value="partially">📂 Dossier à suivre — Partiel</option>
          <option value="echu">⏰ Échu — Non implémenté</option>
          <option value="nonechu">📅 Non échue</option>
        </select>
        <select id="rr-filter-cycle" class="fsel" style="height:28px;font-size:11px;min-width:130px;"><option value="">Tous les cycles</option></select>
        <select id="rr-filter-responsable" class="fsel" style="height:28px;font-size:11px;min-width:150px;"><option value="">Tous les responsables</option></select>
        <button id="rr-reset-filters" class="btn" style="font-size:11px;padding:3px 10px;height:28px;">↻ Réinitialiser</button>
        <input id="rr-mission-ref" class="finp" placeholder="N° de la mission" style="height:28px;font-size:11px;width:160px;padding:2px 8px;">
        <button id="rr-print-btn" class="btn p" style="font-size:11px;padding:4px 14px;height:28px;margin-left:auto;" title="Imprimer le Récapitulatif des Recommandations">🖨️ Imprimer — Récap. Recommandations</button>
      </div>

      <!-- ══════════════════════════
           FEUILLE A4
      ══════════════════════════ -->
      <div style="display:flex;justify-content:center;background:#e8eaed;padding:24px 16px;border-radius:8px;min-height:400px;">
        <div id="rr-a4-sheet" style="
          width:794px;
          min-height:1123px;
          background:#fff;
          border-radius:3px;
          box-shadow:0 4px 24px rgba(0,0,0,.18);
          padding:36px 48px 48px;
          font-family:'Segoe UI',Arial,sans-serif;
          font-size:11px;
          color:#1a1a1a;
          box-sizing:border-box;
          display:flex;
          flex-direction:column;
          gap:18px;
        ">

          <!-- En-tête A4 -->
          <div style="display:flex;align-items:flex-start;justify-content:space-between;border-bottom:2.5px solid #1a3a5c;padding-bottom:12px;gap:12px;">
            <div>
              <div style="font-size:16px;font-weight:800;color:#1a3a5c;letter-spacing:-.2px;">📊 Récapitulatif des Recommandations</div>
              <div id="rr-a4-subtitle" style="font-size:10.5px;color:#555;margin-top:3px;">Direction Audit &amp; Contrôle Interne</div>
            </div>
            <div style="text-align:right;font-size:9.5px;color:#888;line-height:1.7;">
              <div id="rr-a4-date" style="font-weight:600;color:#1a3a5c;"></div>
              <div id="rr-a4-filtres" style="font-style:italic;"></div>
            </div>
          </div>

          <!-- Graphiques côte à côte -->
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;">
            <div style="border:1px solid #e5e7eb;border-radius:6px;padding:10px 12px;">
              <div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#6b7280;margin-bottom:8px;border-bottom:1px solid #f3f4f6;padding-bottom:5px;">Société · Responsable · Fonction</div>
              <div id="rr-bar-responsable">
                <!-- nav sociétés -->
                <div id="rr-resp-nav" style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px;"></div>
                <!-- liste responsables de la société active -->
                <div id="rr-resp-list" style="max-height:100px;overflow-y:auto;"></div>
              </div>
            </div>
            <div style="border:1px solid #e5e7eb;border-radius:6px;padding:10px 12px;">
              <div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#6b7280;margin-bottom:8px;border-bottom:1px solid #f3f4f6;padding-bottom:5px;">Répartition par statut</div>
              <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
                <svg id="rr-donut-statut" width="100" height="100" viewBox="0 0 140 140" style="flex-shrink:0;"></svg>
                <div id="rr-donut-statut-legend" style="flex:1;min-width:70px;font-size:9.5px;"></div>
              </div>
            </div>
          </div>

          <!-- Taux de mise en œuvre -->
          <div style="border:1px solid #e5e7eb;border-radius:6px;padding:12px 16px;">
            <div style="display:flex;align-items:center;gap:14px;flex-wrap:wrap;">
              <div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#6b7280;white-space:nowrap;">Taux de mise en œuvre global</div>
              <div style="flex:1;min-width:160px;">
                <div style="height:11px;border-radius:6px;background:#f3f4f6;overflow:hidden;">
                  <div id="rr-global-bar" style="height:11px;border-radius:6px;width:0%;background:linear-gradient(90deg,#22c55e,#16a34a);transition:width .5s;"></div>
                </div>
              </div>
              <div id="rr-global-pct" style="font-size:20px;font-weight:800;font-family:var(--mono);color:var(--green);min-width:52px;text-align:right;">0%</div>
            </div>
          </div>

          <!-- Tableau détaillé -->
          <div style="flex:1;border:1px solid #e5e7eb;border-radius:6px;overflow:hidden;">
            <div style="padding:8px 12px;background:#f8f9fa;border-bottom:1px solid #e5e7eb;display:flex;align-items:center;gap:8px;">
              <strong style="font-size:10.5px;color:#1a3a5c;">Liste détaillée des recommandations &amp; dispositions</strong>
              <span id="rr-list-count" style="font-size:10px;color:#888;"></span>
            </div>
            <div style="overflow-x:auto;overflow-y:auto;max-height:580px;">
              <table class="wtable" id="rr-table" style="width:100%;min-width:680px;font-size:9.5px;border-collapse:collapse;">
                <thead style="position:sticky;top:0;z-index:5;background:#1a3a5c;color:#fff;">
                  <tr>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:center;border:none;white-space:nowrap;width:48px;">Crit.</th>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:left;border:none;">Anomalie</th>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:left;border:none;">Disposition</th>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:left;border:none;white-space:nowrap;width:85px;">Responsable</th>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:left;border:none;white-space:nowrap;width:68px;">Échéance</th>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:center;border:none;white-space:nowrap;width:80px;">Statut</th>
                    <th style="padding:6px 8px;font-size:9px;font-weight:700;text-align:center;border:none;white-space:nowrap;width:58px;">Retard</th>
                  </tr>
                </thead>
                <tbody id="rr-tbody"></tbody>
              </table>
            </div>
          </div>

          <!-- Pied de page A4 -->
          <div style="border-top:1px solid #e5e7eb;padding-top:8px;display:flex;justify-content:space-between;align-items:center;font-size:8.5px;color:#aaa;">
            <span>Direction Audit &amp; Contrôle Interne — Confidentiel</span>
            <span id="rr-a4-footer-date"></span>
          </div>

        </div><!-- /rr-a4-sheet -->
      </div><!-- /A4 wrapper -->

    </div>



    <!-- ══════════════════════════════════════
         VUE RAPPORT RCM — Version imprimable
    ═══════════════════════════════════════ -->
    <div id="view-rapport-rcm" style="display:none;margin-top:10px;">

      <!-- Barre de filtres + bouton imprimer -->
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap;">
        <strong style="font-size:14px;font-weight:700;color:var(--text);">🛡️ Risk Control Matrix — Version imprimable</strong>
        <div style="display:flex;align-items:center;gap:4px;">
          <span style="font-size:10px;color:var(--text-muted);white-space:nowrap;">Filiale :</span>
          <select id="rrcm-f-filiale" class="fsel" style="height:28px;font-size:11px;min-width:160px;">
            <option value="">Toutes filiales</option>
          </select>
        </div>
        <div style="display:flex;align-items:center;gap:4px;">
          <span style="font-size:10px;color:var(--text-muted);white-space:nowrap;">Cycle :</span>
          <select id="rrcm-f-cycle" class="fsel" style="height:28px;font-size:11px;min-width:150px;">
            <option value="">Tous les cycles</option>
          </select>
        </div>
        <select id="rrcm-f-level" class="fsel" style="height:28px;font-size:11px;min-width:140px;">
          <option value="">Tous niveaux</option>
          <option value="high">🔴 Critique / Élevé (≥10)</option>
          <option value="medium">🟡 Moyen (5–9)</option>
          <option value="low">🟢 Faible (&lt;5)</option>
        </select>
        <input id="rrcm-mission-ref" class="finp" placeholder="N° de la mission" style="height:28px;font-size:11px;width:160px;padding:2px 8px;">
        <button id="rrcm-print-btn" class="btn p" style="font-size:11px;padding:4px 14px;height:28px;margin-left:auto;" title="Imprimer les Termes de Référence (TDR)">🖨️ Imprimer — Termes de Référence</button>
      </div>

      <!-- Sélecteur Mission depuis Plans d'audit interne -->
      <div style="background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:7px;padding:10px 14px;margin-bottom:14px;display:flex;align-items:flex-start;gap:12px;flex-wrap:wrap;">
        <div style="display:flex;align-items:center;gap:7px;flex-shrink:0;">
          <span style="font-size:13px;">📋</span>
          <span style="font-size:12px;font-weight:700;color:var(--accent);">Importer depuis Plans d'audit interne</span>
        </div>
        <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;flex:1;">
          <select id="rrcm-audit-select" class="fsel" style="height:28px;font-size:11px;min-width:240px;flex:1;">
            <option value="">— Sélectionner une mission —</option>
          </select>
          <button id="rrcm-audit-load-btn" class="btn p" style="font-size:11px;padding:3px 12px;height:28px;background:var(--accent);border-color:var(--accent);color:#fff;">Charger</button>
          <button id="rrcm-audit-clear-btn" class="btn" style="font-size:11px;padding:3px 10px;height:28px;color:var(--text-muted);">✕ Effacer</button>
        </div>
        <div id="rrcm-audit-preview-badge" style="display:none;background:#fff;border:1px solid var(--border);border-radius:5px;padding:4px 10px;font-size:10.5px;color:var(--text-muted);white-space:nowrap;"></div>
      </div>

      <!-- Panneau prévisualisation des rubriques chargées depuis l'audit -->
      <div id="rrcm-tdr-sections-panel" style="display:none;background:#fff;border:1px solid var(--accent);border-radius:7px;margin-bottom:14px;overflow:hidden;">
        <div style="background:var(--accent);padding:7px 14px;display:flex;align-items:center;justify-content:space-between;">
          <span style="font-size:12px;font-weight:700;color:#fff;">📝 Sections TDR chargées depuis la mission</span>
          <span id="rrcm-tdr-mission-label" style="font-size:11px;color:rgba(255,255,255,0.85);"></span>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:0;border-top:none;">
          <div style="padding:12px 14px;border-right:1px solid var(--border);">
            <div style="font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:.07em;color:var(--accent);margin-bottom:7px;">1. Contexte et Justification</div>
            <div id="rrcm-preview-contexte" style="font-size:11.5px;color:var(--text);line-height:1.55;white-space:pre-wrap;"></div>
          </div>
          <div style="padding:12px 14px;border-right:1px solid var(--border);">
            <div style="font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:.07em;color:var(--accent);margin-bottom:7px;">2. Objectifs de la Mission</div>
            <div id="rrcm-preview-objectifs" style="font-size:11.5px;color:var(--text);line-height:1.55;"></div>
          </div>
          <div style="padding:12px 14px;">
            <div style="font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:.07em;color:var(--accent);margin-bottom:7px;">3. Périmètre de la Mission</div>
            <div id="rrcm-preview-perimetre" style="font-size:11.5px;color:var(--text);line-height:1.55;"></div>
          </div>
        </div>
      </div>

      <!-- Indicateur filtres actifs -->
      <div id="rrcm-active-filters" style="display:none;background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:5px;padding:6px 12px;margin-bottom:8px;font-size:11px;color:var(--accent);display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
        <span style="font-weight:700;">🔍 Filtres actifs :</span>
        <span id="rrcm-af-filiale" style="display:none;background:#fff;border:1px solid var(--border);border-radius:3px;padding:1px 8px;">Filiale: <strong id="rrcm-af-filiale-val"></strong></span>
        <span id="rrcm-af-cycle" style="display:none;background:#fff;border:1px solid var(--border);border-radius:3px;padding:1px 8px;">Cycle: <strong id="rrcm-af-cycle-val"></strong></span>
        <span id="rrcm-af-level" style="display:none;background:#fff;border:1px solid var(--border);border-radius:3px;padding:1px 8px;">Niveau: <strong id="rrcm-af-level-val"></strong></span>
      </div>

      <!-- Prévisualisation TDR scrollable -->
      <div id="rrcm-preview" style="background:#e8e8e8;padding:20px;border-radius:8px;min-height:400px;overflow-y:auto;max-height:calc(100vh - 200px);">
        <div style="text-align:center;padding:60px 20px;color:#888;font-size:13px;">
          Sélectionnez les filtres puis la vue se mettra à jour automatiquement.
        </div>
      </div>

    </div>

    <div id="view-risks" style="display:none;margin-top:10px;">

      <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap;">
        <strong style="font-size:14px;font-weight:700;color:var(--text);">◇ Registre des risques</strong>

        <select id="risk-f-statut" class="fsel" style="height:28px;font-size:11px;">
          <option value="">Tous les statuts</option>
          <option value="open">Ouvert</option>
          <option value="mitigé">Mitigé</option>
          <option value="clos">Clos</option>
        </select>
        <select id="risk-f-cat" class="fsel" style="height:28px;font-size:11px;">
          <option value="">Toutes catégories</option>
          <option value="Opérationnel">Opérationnel</option>
          <option value="Financier">Financier</option>
          <option value="Technologique">Technologique</option>
          <option value="Conformité">Conformité</option>
          <option value="Stratégique">Stratégique</option>
          <option value="Réputation">Réputation</option>
        </select>
        <select id="risk-f-soc" class="fsel" style="height:28px;font-size:11px;"><option value="">Toutes sociétés</option></select>
        <button class="tbtn p" id="risk-add-btn" style="font-size:11px;padding:3px 10px;">+ Ajouter un risque</button>
      </div>

      <div id="risk-kpi-bar" style="display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:10px;"></div>

      <div>

        <div class="panel" style="padding:0;overflow:hidden;">
          <table class="wtable" id="risk-table" style="min-width:100%;">
            <thead>
              <tr>
                <th style="width:72px;">ID</th>
                <th>Risque</th>
                <th style="width:95px;">Société</th>
                <th style="width:90px;">Catégorie</th>
                <th style="width:66px;text-align:center;">Prob.</th>
                <th style="width:66px;text-align:center;">Impact</th>
                <th style="width:60px;text-align:center;">Inhér. ▸Rés.</th>
                <th style="width:80px;text-align:center;">Contrôle COSO</th>
                <th style="width:90px;">Plan Mitigation</th>
                <th style="width:68px;text-align:center;">Statut</th>
                <th style="width:80px;">Responsable</th>
                <th style="width:76px;">Échéance</th>
                <th style="width:56px;">Actions</th>
              </tr>
            </thead>
            <tbody id="risk-tbody"></tbody>
          </table>
          <div id="risk-empty" style="display:none;padding:40px;text-align:center;color:var(--text-dim);font-size:13px;">Aucun risque enregistré. Cliquez sur <strong>+ Ajouter un risque</strong> pour commencer.</div>
        </div>

        <div class="panel" style="margin-top:14px;padding:14px;">
          <div style="font-size:12px;font-weight:700;color:var(--text);margin-bottom:10px;">🎯 Matrice des risques — Probabilité × Impact</div>
          <div id="risk-matrix-wrap" style="overflow:auto;"></div>
          <div id="risk-matrix-legend" style="display:flex;gap:12px;margin-top:8px;flex-wrap:wrap;"></div>
        </div>

      </div>
    </div>

    <!-- ══════════════════════════════════════════════════════════
         VIEW — RISK CONTROL MATRIX (RCM)
         ══════════════════════════════════════════════════════════ -->
    <div id="view-rcm" style="display:none;margin-top:10px;">

      <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap;">
        <strong style="font-size:14px;font-weight:700;color:var(--text);">🛡️ Risk Control Matrix</strong>
        <span style="font-size:11px;color:var(--text-muted);">Matrice Risques &amp; Contrôles — conformité COSO</span>

        <select id="rcm-f-cycle" class="fsel" style="height:28px;font-size:11px;">
          <option value="">Tous les cycles</option>
        </select>
        <select id="rcm-f-filiale" class="fsel" style="height:28px;font-size:11px;">
          <option value="">Toutes filiales</option>
        </select>
        <select id="rcm-f-level" class="fsel" style="height:28px;font-size:11px;">
          <option value="">Tous niveaux résiduel</option>
          <option value="low">Faible (1–4)</option>
          <option value="medium">Moyen (5–9)</option>
          <option value="high">Élevé (10–16)</option>
        </select>
        <input id="rcm-search" class="finp" type="text" placeholder="🔍 Rechercher…" style="width:180px;height:28px;font-size:11px;padding:3px 8px;">
        <button class="tbtn p" id="rcm-add-btn" style="font-size:11px;padding:3px 10px;">+ Ajouter</button>
        <button class="tbtn" id="rcm-export-btn" style="font-size:11px;padding:3px 10px;">⬇️ Exporter</button>
        <button class="tbtn" id="rcm-print-btn" style="font-size:11px;padding:3px 10px;">🖨️ Imprimer</button>
      </div>

      <!-- KPI bar -->
      <div id="rcm-kpi-bar" style="display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:10px;"></div>

      <!-- Tableau RCM -->
      <div class="panel" style="padding:0;overflow:hidden;">
        <div style="overflow-x:auto;overflow-y:auto;max-height:calc(100vh - 220px);position:relative;">
          <table class="atable" id="rcm-table" style="min-width:1400px;">
            <thead style="position:sticky;top:0;z-index:20;">
              <!-- Ligne 1 : titres principaux -->
              <tr>
                <th rowspan="2" style="width:95px;vertical-align:middle;">Filiale</th>
                <th rowspan="2" style="width:75px;vertical-align:middle;">Réf #</th>
                <th rowspan="2" style="width:100px;vertical-align:middle;">Cycle</th>
                <th rowspan="2" style="width:110px;vertical-align:middle;">Processus</th>
                <th rowspan="2" style="min-width:160px;vertical-align:middle;">Tâche / Contrôle</th>
                <th rowspan="2" style="min-width:180px;vertical-align:middle;">Objectif du contrôle</th>
                <th rowspan="2" style="min-width:180px;vertical-align:middle;">Risque identifié</th>
                <th colspan="2" style="text-align:center;background:var(--surface2);" title="Impact Opérationnel — Les conséquences directes d'un événement sur le fonctionnement quotidien, les processus et les ressources d'une organisation.">Impact Opérationnel<br><span style="font-weight:400;font-size:9px;opacity:0.75;">Conséquences sur le fonctionnement quotidien &amp; processus</span></th>
                <th colspan="2" style="text-align:center;background:var(--surface2);" title="Impact Financier — Les conséquences pécuniaires directes sur l'organisation.">Impact Financier<br><span style="font-weight:400;font-size:9px;opacity:0.75;">Conséquences pécuniaires directes</span></th>
                <th colspan="2" style="text-align:center;background:var(--surface2);" title="Impact Réputation — Désigne l'atteinte à l'image de marque, à la crédibilité et à la confiance.">Impact Réputation<br><span style="font-weight:400;font-size:9px;opacity:0.75;">Atteinte à l'image &amp; crédibilité</span></th>
                <th rowspan="2" style="width:60px;text-align:center;vertical-align:middle;">Impact</th>
                <th rowspan="2" style="width:60px;text-align:center;vertical-align:middle;">Proba.</th>
                <th rowspan="2" style="width:75px;text-align:center;vertical-align:middle;">Inhérent</th>
                <th rowspan="2" style="min-width:180px;vertical-align:middle;">Contrôles de mitigation</th>
                <th rowspan="2" style="width:75px;text-align:center;vertical-align:middle;">Efficacité</th>
                <th rowspan="2" style="width:75px;text-align:center;vertical-align:middle;">Résiduel</th>
                <th rowspan="2" style="width:54px;text-align:center;vertical-align:middle;">Actions</th>
              </tr>
              <!-- Ligne 2 : sous-titres des 3 groupes Impact -->
              <tr style="background:var(--surface3);font-size:10px;color:var(--text-muted);">
                <th style="text-align:center;font-weight:600;padding:3px 4px;font-style:italic;min-width:140px;background:var(--surface3);">Description</th>
                <th style="text-align:center;font-weight:600;padding:3px 4px;width:52px;background:var(--surface3);">Éval. (1-5)</th>
                <th style="text-align:center;font-weight:600;padding:3px 4px;font-style:italic;min-width:140px;background:var(--surface3);">Description</th>
                <th style="text-align:center;font-weight:600;padding:3px 4px;width:52px;background:var(--surface3);">Éval. (1-5)</th>
                <th style="text-align:center;font-weight:600;padding:3px 4px;font-style:italic;min-width:140px;background:var(--surface3);">Description</th>
                <th style="text-align:center;font-weight:600;padding:3px 4px;width:52px;background:var(--surface3);">Éval. (1-5)</th>
              </tr>
            </thead>
            <tbody id="rcm-tbody-subheader" style="display:none;"></tbody>
            <tbody id="rcm-tbody"></tbody>
          </table>
        </div>
        <div id="rcm-empty" style="display:none;padding:40px;text-align:center;color:var(--text-dim);font-size:13px;">
          Aucune entrée RCM. Cliquez sur <strong>+ Ajouter</strong> ou importez un fichier Excel avec l'onglet <strong>RCM</strong>.
        </div>
      </div>


    </div>

    <!-- Modal RCM Add/Edit -->
    <div class="mbk" id="rcm-modal-bk">
      <div class="modal" style="width:700px;max-width:98vw;">
        <div class="mhd">
          <span class="mtitle" id="rcm-modal-title">Ajouter une entrée RCM</span>
          <span class="mclose" id="rcm-modal-close">✕</span>
        </div>
        <div class="mbody">
          <div class="fgrid frow2">
            <div>
              <div class="flbl2">Filiale *</div>
              <select class="finp" id="rcm-f-filiale-in" style="appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 8px center;">
                <option value="">— Sélectionner une société —</option>
              </select>
            </div>
            <div>
              <div class="flbl2">Réf #</div>
              <input class="finp" id="rcm-f-ref-in" placeholder="Ex: CC-01">
            </div>
          </div>
          <div class="fgrid frow2">
            <div>
              <div class="flbl2">Cycle <span class="t-red">*</span></div>
              <select class="finp" id="rcm-f-cycle-in" style="appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 8px center;">
                <option value="">— Sélectionner un cycle —</option>
              </select>
            </div>
            <div>
              <div class="flbl2">Processus <span class="t-red">*</span></div>
              <select class="finp" id="rcm-f-proc-in" style="appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 8px center;">
                <option value="">— Sélectionner d'abord un cycle —</option>
              </select>
              <input class="finp" id="rcm-f-proc-custom" placeholder="Saisir un processus…" style="margin-top:5px;display:none;">
            </div>
          </div>
          <div class="frow2">
            <div class="flbl2">Tâche / Contrôle *</div>
            <input class="finp" id="rcm-f-tache-in" placeholder="Description de la tâche">
          </div>
          <div class="frow2">
            <div class="flbl2">Objectif du contrôle interne</div>
            <textarea class="finp" id="rcm-f-obj-in" rows="2" placeholder="À quoi sert la tâche ?"></textarea>
          </div>
          <div class="frow2">
            <div class="flbl2">Risque identifié</div>
            <textarea class="finp" id="rcm-f-risk-in" rows="2" placeholder="Que peut-il se passer si la tâche n'est pas bien réalisée ?"></textarea>
          </div>
          <div style="display:grid;grid-template-columns:1fr;gap:10px;" class="frow2">
            <div style="border:1px solid var(--border);border-radius:6px;padding:10px;background:var(--surface2);">
              <div style="font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;">⚙️ Impact Opérationnel
                <span style="font-weight:400;font-size:10px;color:var(--text-muted);display:block;margin-top:2px;">Conséquences directes sur le fonctionnement quotidien, les processus et les ressources. Évalue la désorganisation concrète du travail.</span>
              </div>
              <div style="display:grid;grid-template-columns:1fr 120px;gap:8px;align-items:start;">
                <div>
                  <div class="flbl2">Description</div>
                  <textarea class="finp" id="rcm-f-desc-op" rows="2" placeholder="Décrivez les conséquences opérationnelles…" style="resize:vertical;height:52px;"></textarea>
                </div>
                <div>
                  <div class="flbl2">Évaluation (1–5)</div>
                  <input class="finp" id="rcm-f-imp-op" type="number" min="0" max="5" value="0">
                </div>
              </div>
            </div>
            <div style="border:1px solid var(--border);border-radius:6px;padding:10px;background:var(--surface2);">
              <div style="font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;">💰 Impact Financier
                <span style="font-weight:400;font-size:10px;color:var(--text-muted);display:block;margin-top:2px;">Conséquences pécuniaires directes : perte monétaire, coûts de réparation ou manque à gagner.</span>
              </div>
              <div style="display:grid;grid-template-columns:1fr 120px;gap:8px;align-items:start;">
                <div>
                  <div class="flbl2">Description</div>
                  <textarea class="finp" id="rcm-f-desc-fin" rows="2" placeholder="Décrivez les conséquences financières…" style="resize:vertical;height:52px;"></textarea>
                </div>
                <div>
                  <div class="flbl2">Évaluation (1–5)</div>
                  <input class="finp" id="rcm-f-imp-fin" type="number" min="0" max="5" value="0">
                </div>
              </div>
            </div>
            <div style="border:1px solid var(--border);border-radius:6px;padding:10px;background:var(--surface2);">
              <div style="font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;">🏛️ Impact Réputation
                <span style="font-weight:400;font-size:10px;color:var(--text-muted);display:block;margin-top:2px;">Atteinte à l'image de marque, à la crédibilité et à la confiance auprès des parties prenantes.</span>
              </div>
              <div style="display:grid;grid-template-columns:1fr 120px;gap:8px;align-items:start;">
                <div>
                  <div class="flbl2">Description</div>
                  <textarea class="finp" id="rcm-f-desc-rep" rows="2" placeholder="Décrivez les conséquences réputationnelles…" style="resize:vertical;height:52px;"></textarea>
                </div>
                <div>
                  <div class="flbl2">Évaluation (1–5)</div>
                  <input class="finp" id="rcm-f-imp-rep" type="number" min="0" max="5" value="0">
                </div>
              </div>
            </div>
          </div>
          <div class="frow2 fgrid">
            <div>
              <div class="flbl2">Likelihood / Probabilité (1–5)</div>
              <input class="finp" id="rcm-f-likelihood" type="number" min="0" max="5" value="2">
            </div>
            <div>
              <div class="flbl2">Efficacité des contrôles (1–5)</div>
              <input class="finp" id="rcm-f-eff" type="number" min="0" max="5" value="3">
            </div>
          </div>
          <div class="frow2">
            <div class="flbl2">Contrôles de mitigation</div>
            <textarea class="finp" id="rcm-f-ctrl-in" rows="2" placeholder="Décrire les contrôles mis en place"></textarea>
          </div>
          <div class="frow2">
            <div class="flbl2">🏢 Sociétés additionnelles concernées <span style="font-weight:400;color:var(--text-dim);">(en plus de la filiale principale ci-dessus)</span></div>
            <div id="rcm-f-societes-multi" style="display:flex;flex-wrap:wrap;gap:8px;border:1px solid var(--border);border-radius:6px;padding:8px 10px;background:var(--surface2);max-height:110px;overflow-y:auto;"></div>
          </div>
          <div class="frow2">
            <div class="flbl2">🔍 Plans d'audit interne liés <span style="font-weight:400;color:var(--text-dim);">(relation 1 → plusieurs : cette entrée RCM peut être rattachée à plusieurs missions ; pré-cochés automatiquement selon le Cycle Opérationnel/Processus ci-dessus)</span></div>
            <div id="rcm-f-audit-refs" style="display:flex;flex-direction:column;gap:5px;border:1px solid var(--border);border-radius:6px;padding:8px 10px;background:var(--surface2);max-height:130px;overflow-y:auto;"></div>
          </div>
          <div class="frow2">
            <div class="flbl2">📋 Constats FRAP liés <span style="font-weight:400;color:var(--text-dim);">(cette entrée RCM peut être rattachée à plusieurs FRAP)</span></div>
            <div id="rcm-f-frap-refs" style="display:flex;flex-direction:column;gap:5px;border:1px solid var(--border);border-radius:6px;padding:8px 10px;background:var(--surface2);max-height:130px;overflow-y:auto;"></div>
          </div>
        </div>
        <div class="mft">
          <button class="btn" id="rcm-modal-cancel">Annuler</button>
          <button class="btn p" id="rcm-modal-save">Enregistrer</button>
        </div>
      </div>
    </div>

    <div id="view-gantt" style="display:none;margin-top:10px;">

      <!-- Bandeau de statut synchro Plans d'audit → Gantt -->
      <div id="gantt-sync-banner" style="display:flex;align-items:center;gap:8px;padding:7px 14px;background:#eff6ff;border:1px solid #bfdbfe;border-radius:6px;margin-bottom:8px;font-size:11.5px;color:#1e40af;">
        <span style="font-size:14px;">🔗</span>
        <span id="gantt-sync-banner-text">Planning Missions — synchronisation avec les plans d'audit interne active.</span>
        <button onclick="$('#gantt-sync-audits-btn').click();" style="margin-left:auto;padding:3px 10px;border-radius:4px;font-size:11px;font-weight:600;cursor:pointer;border:1px solid #93c5fd;background:#dbeafe;color:#1e40af;">🔄 Synchroniser maintenant</button>
      </div>

      <div id="gantt-kpi-strip" style="display:flex;gap:8px;margin-bottom:8px;flex-wrap:wrap;">
        <div class="gantt-kpi-card" id="gkpi-total" style="flex:1;min-width:110px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:8px 14px;display:flex;align-items:center;gap:10px;box-shadow:var(--shadow);">
          <span style="font-size:22px;">📋</span>
          <div><div id="gkpi-total-val" style="font-size:20px;font-weight:800;color:var(--accent);font-family:var(--mono);line-height:1;">0</div><div style="font-size:10px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.06em;">Missions</div></div>
        </div>
        <div class="gantt-kpi-card" id="gkpi-done" style="flex:1;min-width:110px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:8px 14px;display:flex;align-items:center;gap:10px;box-shadow:var(--shadow);">
          <span style="font-size:22px;">✅</span>
          <div><div id="gkpi-done-val" style="font-size:20px;font-weight:800;color:var(--green);font-family:var(--mono);line-height:1;">0</div><div style="font-size:10px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.06em;">Terminées</div></div>
        </div>
        <div class="gantt-kpi-card" id="gkpi-late" style="flex:1;min-width:110px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:8px 14px;display:flex;align-items:center;gap:10px;box-shadow:var(--shadow);">
          <span style="font-size:22px;">⚠️</span>
          <div><div id="gkpi-late-val" style="font-size:20px;font-weight:800;color:var(--red);font-family:var(--mono);line-height:1;">0</div><div style="font-size:10px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.06em;">En retard</div></div>
        </div>
        <div class="gantt-kpi-card" id="gkpi-inprog" style="flex:1;min-width:110px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:8px 14px;display:flex;align-items:center;gap:10px;box-shadow:var(--shadow);">
          <span style="font-size:22px;">🔄</span>
          <div><div id="gkpi-inprog-val" style="font-size:20px;font-weight:800;color:var(--purple);font-family:var(--mono);line-height:1;">0</div><div style="font-size:10px;color:var(--text-muted);font-weight:600;text-transform:uppercase;letter-spacing:.06em;">En cours</div></div>
        </div>
      </div>

      <div style="background:var(--surface);border:1px solid var(--border);border-radius:6px 6px 0 0;padding:10px 14px;display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
        <strong style="font-size:13px;font-weight:700;color:var(--text);white-space:nowrap;">📅 Planning Gantt</strong>

        <div style="display:flex;gap:0;border:1px solid var(--border);border-radius:4px;overflow:hidden;margin-left:4px;">
          <button class="gantt-zoom-btn" data-zoom="day"   style="border:none;border-radius:0;border-right:1px solid var(--border);">Jour</button>
          <button class="gantt-zoom-btn active" data-zoom="week"  style="border:none;border-radius:0;border-right:1px solid var(--border);">Semaine</button>
          <button class="gantt-zoom-btn" data-zoom="month" style="border:none;border-radius:0;">Mois</button>
        </div>

        <div style="display:flex;gap:0;border:1px solid var(--border);border-radius:4px;overflow:hidden;">
          <button id="gantt-view-gantt"    class="gantt-zoom-btn active" style="border:none;border-radius:0;border-right:1px solid var(--border);padding:4px 10px;" title="Vue Gantt">▤ Gantt</button>
          <button id="gantt-view-list"     class="gantt-zoom-btn"        style="border:none;border-radius:0;padding:4px 10px;" title="Vue Liste">☰ Liste</button>
        </div>

        <select id="gantt-filter-mission" class="fsel" style="height:26px;font-size:11.5px;max-width:180px;"><option value="">— Toutes les missions —</option></select>
        <select id="gantt-filter-soc"     class="fsel" style="height:26px;font-size:11.5px;"><option value="">— Toutes les sociétés —</option></select>
        <select id="gantt-filter-type"    class="fsel" style="height:26px;font-size:11.5px;"><option value="">— Tous les types —</option></select>
        <select id="gantt-filter-status"  class="fsel" style="height:26px;font-size:11.5px;">
          <option value="">— Tous statuts —</option>
          <option value="planned">Planifié</option>
          <option value="inprogress">En cours</option>
          <option value="completed">Terminé</option>
          <option value="late">En retard</option>
        </select>
        <select id="gantt-filter-chef"    class="fsel" style="height:26px;font-size:11.5px;max-width:160px;"><option value="">— Tous les chefs —</option></select>
        <button id="gantt-reset-filters" class="tbtn" style="padding:4px 9px;font-size:11px;color:var(--text-muted);" title="Réinitialiser tous les filtres">↻ Filtres</button>
        <button id="gantt-auto-dates" class="tbtn" style="padding:4px 9px;font-size:11px;color:var(--accent);border-color:var(--accent);" title="Recalculer automatiquement les dates de fin de toutes les missions depuis leurs tâches">⚙ Auto-dates</button>

        <div style="display:flex;gap:10px;margin-left:auto;align-items:center;flex-wrap:wrap;" id="gantt-legend">
          <span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);font-weight:500;"><i style="width:12px;height:12px;border-radius:3px;background:linear-gradient(135deg,#0064d9,#338ef7);display:inline-block;"></i>Mission</span>
          <span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);font-weight:500;"><i style="width:12px;height:12px;border-radius:3px;background:linear-gradient(135deg,#1e9c6a,#34c38f);display:inline-block;"></i>Tâche</span>
          <span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);font-weight:500;"><i style="width:12px;height:12px;border-radius:3px;background:linear-gradient(135deg,#74c0fc,#a5d8ff);display:inline-block;"></i>Sous-tâche</span>
          <span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);font-weight:500;"><i style="width:10px;height:10px;background:var(--yellow);transform:rotate(45deg);border-radius:1px;display:inline-block;"></i>Jalon</span>
          <span style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);font-weight:500;"><i style="width:2px;height:14px;background:var(--red);border-radius:1px;opacity:.7;display:inline-block;"></i>Aujourd'hui</span>
        </div>

        <button class="tbtn" id="gantt-sync-audits-btn" title="Synchroniser tous les plans d'audit interne vers le Planning Gantt" style="padding:4px 9px;font-size:11px;background:linear-gradient(135deg,#0070f2,#338ef7);color:#fff;border-color:#0070f2;">🔄 Sync Audits → Gantt</button>
        <button class="tbtn" id="gantt-today-btn" title="Aller à aujourd'hui" style="padding:4px 9px;font-size:11px;">📍 Auj.</button>
        <button class="tbtn" id="gantt-expand-all" title="Tout développer" style="padding:4px 9px;font-size:11px;">⊞</button>
        <button class="tbtn" id="gantt-collapse-all" title="Tout réduire" style="padding:4px 9px;font-size:11px;">⊟</button>
        <button class="tbtn" id="gantt-export-csv" title="Exporter CSV" style="padding:4px 9px;font-size:11px;">⬇ CSV</button>
        <button class="tbtn" id="gantt-clear-all" style="border-color:var(--red);color:var(--red);" title="Effacer toutes les missions et taches du Gantt">🗑</button>
        <button class="tbtn p" id="gantt-add-mission">+ Nouvelle entrée</button>
      </div>

      <div id="gantt-scroll" style="border:1px solid var(--border);border-top:none;border-radius:0 0 6px 6px;overflow:auto;max-height:calc(100vh - 310px);background:var(--surface);box-shadow:var(--shadow);position:relative;">
        <div id="gantt-excel-container" style="display:flex;flex-direction:column;min-width:max-content;">

          <div style="display:flex;position:sticky;top:0;z-index:12;background:#1e293b;flex-shrink:0;">

            <div style="flex-shrink:0;width:430px;position:sticky;left:0;z-index:13;background:#1e293b;border-right:2px solid #334155;">
              <div style="display:flex;height:56px;color:#fff;align-items:stretch;border-bottom:2px solid #334155;">
                <div style="width:28px;flex-shrink:0;border-right:1px solid #334155;display:flex;align-items:center;justify-content:center;font-size:10px;color:#64748b;">#</div>
                <div style="flex:2;border-right:1px solid #334155;display:flex;align-items:center;padding:0 10px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#94a3b8;">Mission / Tâche</div>
                <div style="width:70px;flex-shrink:0;border-right:1px solid #334155;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#94a3b8;">Début</div>
                <div style="width:70px;flex-shrink:0;border-right:1px solid #334155;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#94a3b8;">Fin</div>
                <div style="width:50px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#94a3b8;">Dur.</div>
              </div>
            </div>

            <div id="gantt-excel-timeline-header" style="flex:1;background:#1e293b;"></div>
          </div>

          <div style="display:flex;flex:1;">

            <div id="gantt-excel-left" style="flex-shrink:0;width:430px;position:sticky;left:0;z-index:10;background:var(--surface);border-right:2px solid var(--border2);">
              <div id="gantt-excel-rows-left"></div>
            </div>

            <div id="gantt-excel-right" style="flex:1;min-width:0;">
              <div id="gantt-excel-rows-right" style="position:relative;"></div>
            </div>
          </div>
        </div>

        <div id="gantt-excel-empty" style="display:none;padding:48px;text-align:center;color:var(--text-muted);font-size:13px;">
          <div style="font-size:36px;margin-bottom:10px;">📋</div>
          <div style="font-weight:600;margin-bottom:6px;" id="gantt-empty-title">Aucune mission planifiée</div>
          <div style="font-size:11.5px;" id="gantt-empty-sub">Cliquez sur <strong>🔄 Sync Audits → Gantt</strong> si vous avez des plans d'audit, ou sur <strong>+ Nouvelle entrée</strong> pour créer manuellement.</div>
        </div>
      </div>

      <div id="gantt-list-view" style="display:none;border:1px solid var(--border);border-top:none;border-radius:0 0 6px 6px;background:var(--surface);box-shadow:var(--shadow);overflow:auto;max-height:calc(100vh - 310px);">
        <table class="atable" style="min-width:900px;">
          <thead><tr>
            <th style="width:220px;">Mission</th>
            <th style="width:200px;">Tâche</th>
            <th style="width:80px;">Début</th>
            <th style="width:80px;">Fin</th>
            <th style="width:100px;">Responsable</th>
            <th style="width:90px;">Statut</th>
            <th style="width:70px;">Durée (j)</th>
          </tr></thead>
          <tbody id="gantt-list-tbody"></tbody>
        </table>
      </div>

    </div>

    <div id="view-daily" style="display:none;margin-top:10px;">
      <div class="panel">
        <div class="phd">
          <div class="ptitle">📅 Tâches Quotidiennes</div>
                    <button class="tbtn" id="daily-alert-btn" title="Envoyer une alerte mail pour les tâches quotidiennes en retard" style="margin-left:4px;">📧 Alerter</button>
