            <label style="font-size:11px;font-weight:600;color:var(--text-muted);">Priorité :</label>
            <select id="daily-f-prio" class="fsel" style="min-width:110px;height:28px;font-size:11px;padding:3px 24px 3px 8px;">
              <option value="">Toutes</option>
