            <label style="font-size:11px;font-weight:600;color:var(--text-muted);">Responsable :</label>
            <select id="daily-f-resp" class="fsel" style="min-width:140px;height:28px;font-size:11px;padding:3px 24px 3px 8px;">
              <option value="">Tous</option>
            </select>
          </div>
