            </select>
          </div>

          <div style="display:flex;align-items:center;gap:5px;padding:3px 10px;border:1px solid var(--border);border-radius:4px;background:var(--surface);cursor:pointer;user-select:none;" id="daily-group-toggle" title="Regrouper par mission">
            <span id="daily-group-icon" style="font-size:12px;">▤</span>
