    <!-- ══════════ VUE TRAVAIL À FAIRE (TAF) ══════════ -->
    <div id="view-taf" style="display:none;margin-top:10px;">
      <div class="panel">
        <div class="phd" style="flex-wrap:wrap;gap:8px;">
          <div class="ptitle">📝 Travail à Faire (TAF) <span id="taf-count-badge" style="font-size:10px;font-weight:600;background:var(--accent-bg);color:var(--accent);padding:1px 7px;border-radius:10px;margin-left:6px;">0</span></div>
          <div style="display:flex;gap:6px;margin-left:auto;flex-wrap:wrap;align-items:center;">
