            <select id="taf-filter-priorite" class="wsel" style="font-size:11px;">
              <option value="">Toutes priorités</option><option value="critical">Critique</option>
              <option value="high">Élevée</option><option value="medium">Moyenne</option><option value="low">Faible</option>
            </select>
            <select id="taf-filter-categorie" class="wsel" style="font-size:11px;">
              <option value="">Toutes catégories</option>
            </select>
            <select id="taf-filter-societe" class="wsel" style="font-size:11px;">
              <option value="">Toutes sociétés</option>
            </select>
            <select id="taf-filter-audit-ref" class="wsel" style="font-size:11px;">
              <option value="">Toutes réf. Plans d'audit</option>
            </select>
            <button class="tbtn p" id="taf-add-btn" style="font-size:11px;">➕ Nouveau TAF</button>
          </div>
        </div>
        <div class="fchips" id="taf-chips" style="flex-wrap:wrap;"></div>
        <div style="overflow-x:auto;">
          <table class="atable" id="taf-table">
            <thead><tr>
              <th>Réf # <span class="sico">↕</span></th>
              <th>Travail à Faire <span class="sico">↕</span></th>
              <th>Programme de travail <span class="sico">↕</span></th>
              <th>Doc à demander <span class="sico">↕</span></th>
              <th>Personne à contacter <span class="sico">↕</span></th>
              <th>Timing <span class="sico">↕</span></th>
              <th>Test Plan <span class="sico">↕</span></th>
              <th>Test Results <span class="sico">↕</span></th>
              <th>Priorité <span class="sico">↕</span></th>
              <th>Auditeur <span class="sico">↕</span></th>
              <th>Notes</th>
              <th>Mis à jour <span class="sico">↕</span></th>
              <th>Actions</th>
            </tr></thead>
            <tbody id="taf-tbody"></tbody>
          </table>
        </div>
        <div id="taf-empty" style="padding:40px;text-align:center;color:var(--text-dim);font-size:12px;display:none;">
          <div style="font-size:28px;margin-bottom:8px;">📝</div>
          Aucun travail à faire enregistré. Cliquez sur <strong>➕ Nouveau TAF</strong> pour en ajouter.
        </div>
      </div>
    </div>

    <!-- Modal Ajouter / Modifier TAF -->
    <div class="mbk" id="taf-modal-bk">
      <div class="modal" style="width:640px;max-width:96vw;">
        <div class="mhd">
          <span class="mtitle" id="taf-modal-title">➕ Nouveau TAF</span>
          <span class="mclose" id="taf-modal-close">✕</span>
        </div>
        <div class="mbody">
          <div style="display:flex;flex-direction:column;gap:11px;">
            <div class="fgrid">
              <div><div class="flbl2">Réf # <span class="t-red">*</span></div><input class="finp" id="taf-cfg-ref" placeholder="Ex: TRS-ENC-01"></div>
              <div><div class="flbl2">Catégorie / Cycle</div><input class="finp" id="taf-cfg-categorie" placeholder="Ex: Encaissement…"></div>
            </div>
            <div><div class="flbl2">🛡️ Risque RCM lié <span style="font-weight:400;color:var(--text-dim);">(synchronise Société, Catégorie/Cycle, Priorité, Conséquences)</span></div>
              <select class="finp" id="taf-cfg-rcm-ref" style="appearance:none;">
                <option value="">— Aucun —</option>
              </select></div>
            <div><div class="flbl2">Société / Entité</div>
              <select class="finp" id="taf-cfg-societe" style="appearance:none;">
                <option value="">— Sélectionner —</option>
              </select></div>
            <div><div class="flbl2">Travail à Faire (TAF) <span class="t-red">*</span></div>
              <textarea class="finp" id="taf-cfg-titre" rows="2" style="resize:vertical;" placeholder="Décrire le contrôle à effectuer…"></textarea></div>
            <div><div class="flbl2">Programme de travail (Comment ?)</div>
              <textarea class="finp" id="taf-cfg-programme" rows="3" style="resize:vertical;" placeholder="Détails des vérifications…"></textarea></div>
            <div><div class="flbl2">Doc à demander (Quoi ?)</div>
              <input class="finp" id="taf-cfg-docs" placeholder="Ex: Factures, reçus, journal de caisse…"></div>
            <div><div class="flbl2">Personne à contacter (Qui ?)</div>
              <input class="finp" id="taf-cfg-contact" placeholder="Ex: Caissier, Comptable…"></div>
            <div class="fgrid">
              <div><div class="flbl2">Timing</div><input class="finp" id="taf-cfg-timing" placeholder="Ex: Mensuel…"></div>
              <div><div class="flbl2">Test Plan</div><input class="finp" id="taf-cfg-testplan" placeholder="Ex: Échantillon de 20 opérations"></div>
            </div>
            <div class="fgrid">
              <div><div class="flbl2">Test Results</div>
                <select class="finp" id="taf-cfg-testresults" style="appearance:none;">
                  <option value="">— Résultat —</option><option value="OK">✅ OK</option>
                  <option value="KO">❌ KO</option><option value="Partiel">⚠️ Partiel</option><option value="NA">— N/A</option>
                </select></div>
              <div><div class="flbl2">Priorité</div>
                <select class="finp" id="taf-cfg-priorite" style="appearance:none;">
                  <option value="medium">Moyenne</option><option value="critical">Critique</option>
                  <option value="high">Élevée</option><option value="low">Faible</option>
                </select></div>
            </div>
            <div class="fgrid">
              <div><div class="flbl2">Statut</div>
                <select class="finp" id="taf-cfg-statut" style="appearance:none;">
                  <option value="todo">À faire</option><option value="inprogress">En cours</option>
                  <option value="done">Terminé</option><option value="na">N/A</option>
                </select></div>
              <div><div class="flbl2">Auditeur assigné</div>
                <select class="finp" id="taf-cfg-auditeur" style="appearance:none;"><option value="">— Sélectionner —</option></select></div>
            </div>
            <div><div class="flbl2">Conséquences / Risques</div>
              <textarea class="finp" id="taf-cfg-consequences" rows="2" style="resize:vertical;" placeholder="Impacts potentiels en cas d'anomalie sur ce point de contrôle…"></textarea></div>
            <div><div class="flbl2">Notes</div>
              <textarea class="finp" id="taf-cfg-notes" rows="2" style="resize:vertical;" placeholder="Anomalies, observations…"></textarea></div>
            <div><div class="flbl2">🏢 Sociétés additionnelles concernées <span style="font-weight:400;color:var(--text-dim);">(en plus de la Société / Entité ci-dessus)</span></div>
              <div id="taf-cfg-societes-multi" style="display:flex;flex-wrap:wrap;gap:8px;border:1px solid var(--border);border-radius:6px;padding:8px 10px;background:var(--surface2);max-height:110px;overflow-y:auto;"></div></div>
            <div><div class="flbl2">📋 Constats FRAP liés à ce TAF</div>
              <div id="taf-cfg-frap-linked" style="display:flex;flex-direction:column;gap:4px;border:1px solid var(--border);border-radius:6px;padding:8px 10px;background:var(--surface2);max-height:110px;overflow-y:auto;font-size:10.5px;color:var(--text-muted);"></div></div>
            <!-- Zone Upload — Fiche de test -->
            <div>
              <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:5px;">
                <div class="flbl2" style="margin:0;">📎 Zone Upload — Fiche de test</div>
                <button class="tbtn" id="taf-add-fiche" type="button" style="font-size:10px;padding:2px 8px;">➕ Ajouter un fichier</button>
              </div>
              <input type="file" id="taf-cfg-fiche-input" multiple accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.csv" style="display:none;">
              <div id="taf-fiche-dropzone" class="taf-fiche-dropzone">
                <div id="taf-fiches-list" class="taf-fiche-list"></div>
              </div>
              <div style="font-size:9.5px;color:var(--text-dim);margin-top:5px;font-style:italic;">Images, PDF, Word, Excel — 4 Mo max par fichier.</div>
            </div>
            <input type="hidden" id="taf-cfg-edit-id">
          </div>
        </div>
        <div class="mft">
          <button class="btn" id="taf-cfg-reset-btn">↺ Réinitialiser</button>
          <button class="btn p" id="taf-cfg-save-btn">✓ Enregistrer</button>
        </div>
      </div>
    </div>

    <!-- ══════════ VUE FRAP — FICHES DE RELEVÉ D'ANOMALIES ET DE PRATIQUES ══════════ -->
