            <span id="frap-count-badge" style="font-size:10px;font-weight:600;background:var(--red-bg);color:var(--red);padding:1px 7px;border-radius:10px;margin-left:6px;">0</span>
          </div>
          <div style="display:flex;gap:6px;margin-left:auto;flex-wrap:wrap;align-items:center;">
            <input id="frap-search" class="finp" style="width:170px;height:28px;font-size:11px;padding:3px 9px;" placeholder="🔍 Rechercher…">
            <select id="frap-filter-crit" class="wsel" style="font-size:11px;">
              <option value="">Toutes criticités</option>
