            <button class="tbtn p" id="frap-add-btn" style="font-size:11px;">➕ Nouvelle FRAP</button>
          </div>
        </div>
      </div>

      <!-- Zone d'impression A4 -->
      <div id="frap-print-area">
        <div id="frap-cards-container"></div>
        <div id="frap-empty" style="padding:60px;text-align:center;color:var(--text-dim);font-size:12px;display:none;">
          <div style="font-size:32px;margin-bottom:10px;">📋</div>
