    <!-- ══════ Modal FRAP ══════ -->
    <div class="mbk" id="frap-modal-bk">
      <div class="modal" style="width:700px;max-width:96vw;">
        <div class="mhd">
          <span class="mtitle" id="frap-modal-title">➕ Nouvelle FRAP</span>
          <span class="mclose" id="frap-modal-close">✕</span>
        </div>
        <div class="mbody" style="padding:14px 17px;">
          <div style="display:flex;flex-direction:column;gap:11px;">
            <div><div class="flbl2">🔗 Mission (Plan d'audit interne) <span style="font-weight:400;color:var(--text-dim);">— la Référence interne hérite automatiquement de la mission sélectionnée</span></div>
              <select class="finp" id="frap-f-audit-ref" style="appearance:none;">
                <option value="">— Aucune —</option>
              </select></div>
