              <div><div class="flbl2">N° Constat <span class="t-red">*</span></div>
                <input class="finp" id="frap-f-num" placeholder="Ex: C-001"></div>
              <div><div class="flbl2">Référence interne</div>
                <input class="finp" id="frap-f-ref" placeholder="Ex: C-004"></div>
            </div>
