              <select class="finp" id="frap-f-taf-ref" style="appearance:none;">
                <option value="">— Aucun —</option>
              </select></div>
            <div><div class="flbl2">Titre / Intitulé du constat <span class="t-red">*</span></div>
              <textarea class="finp" id="frap-f-titre" rows="2" style="resize:vertical;" placeholder="Intitulé précis de l'anomalie constatée…"></textarea></div>
            <div class="fgrid">
              <div><div class="flbl2">Criticité</div>
                <select class="finp" id="frap-f-crit" style="appearance:none;">
                  <option value="critique">Critique</option>
                  <option value="majeur">Majeur</option>
                  <option value="modere">Modéré</option>
                  <option value="mineur">Mineur</option>
                </select></div>
              <div><div class="flbl2">Société / Entité</div>
                <select class="finp" id="frap-f-societe" style="appearance:none;">
                  <option value="">— Sélectionner —</option>
                </select></div>
            </div>
            <div class="fgrid">
              <div><div class="flbl2">Cycle / Processus</div>
                <input class="finp" id="frap-f-cycle" placeholder="Ex: Achats, Trésorerie…"></div>
              <div><div class="flbl2">Auditeur responsable</div>
                <select class="finp" id="frap-f-auditeur" style="appearance:none;">
