              <textarea class="finp" id="frap-f-causes" rows="2" style="resize:vertical;" placeholder="Explications de l'écart entre les critères de référence et les faits…"></textarea></div>
            <div><div class="flbl2">Conséquences / Risques</div>
              <textarea class="finp" id="frap-f-consequences" rows="2" style="resize:vertical;" placeholder="Impacts potentiels si non corrigé…"></textarea></div>
            <!-- Recommandations dynamiques -->
