           ONGLET CONFIG : MATRICE D'EISENHOWER
           ══════════════════════════════════════════════ -->
      <div id="cfg-eisenhower" style="display:none;">
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start;">

          <!-- Colonne gauche : Statistiques & Résumé -->
          <div style="display:flex;flex-direction:column;gap:12px;">

            <!-- KPI globaux -->
            <div class="panel">
              <div class="phd"><div class="ptitle">📊 Statistiques globales</div></div>
              <div style="padding:14px;display:grid;grid-template-columns:1fr 1fr;gap:8px;" id="cfg-eis-stats"></div>
            </div>

            <!-- Répartition par quadrant -->
            <div class="panel">
              <div class="phd"><div class="ptitle">🎯 Répartition par quadrant</div></div>
              <div style="padding:14px;display:flex;flex-direction:column;gap:8px;" id="cfg-eis-quadrant-stats"></div>
            </div>

            <!-- Répartition par difficulté -->
            <div class="panel">
              <div class="phd"><div class="ptitle">🔵 Répartition par difficulté</div></div>
              <div style="padding:14px;display:flex;flex-direction:column;gap:6px;" id="cfg-eis-diff-stats"></div>
            </div>

          </div>

          <!-- Colonne droite : Paramètres & Valeurs par défaut -->
          <div style="display:flex;flex-direction:column;gap:12px;">

            <!-- Valeurs par défaut à la création -->
            <div class="panel">
              <div class="phd"><div class="ptitle">⚙️ Valeurs par défaut (nouvelle tâche)</div></div>
              <div style="padding:14px;display:flex;flex-direction:column;gap:12px;">
                <div>
                  <div class="flbl2">Quadrant par défaut</div>
                  <select class="finp fsel" id="cfg-eis-def-quadrant" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
                    <option value="q1">Q1 – Important & Urgent</option>
                    <option value="q2">Q2 – Important & Non Urgent</option>
                    <option value="q3">Q3 – Non Important & Urgent</option>
                    <option value="q4">Q4 – Non Important & Non Urgent</option>
                  </select>
                </div>
                <div>
                  <div class="flbl2">Priorité par défaut</div>
                  <select class="finp fsel" id="cfg-eis-def-priorite" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
                    <option value="normal">Normal</option>
                    <option value="high">Haute</option>
                    <option value="critical">Critique</option>
                  </select>
                </div>
                <div>
                  <div class="flbl2">Difficulté par défaut</div>
                  <select class="finp fsel" id="cfg-eis-def-difficulte" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
                    <option value="facile">🟢 Facile</option>
                    <option value="moyen">🟡 Moyen</option>
                    <option value="difficile">🔴 Difficile</option>
                  </select>
                </div>
                <div>
                  <div class="flbl2">Unité de durée par défaut</div>
                  <select class="finp fsel" id="cfg-eis-def-unite" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
                    <option value="h">Heure(s)</option>
                    <option value="j">Jour(s)</option>
                    <option value="sem">Semaine(s)</option>
                  </select>
                </div>
                <div style="padding-top:4px;border-top:1px solid var(--border);">
                  <button class="btn p" id="cfg-eis-save-defaults" style="width:100%;">💾 Enregistrer les valeurs par défaut</button>
                </div>
              </div>
            </div>

            <!-- Maintenance : nettoyage -->
            <div class="panel">
              <div class="phd"><div class="ptitle">🧹 Maintenance des tâches</div></div>
              <div style="padding:14px;display:flex;flex-direction:column;gap:10px;">
                <div style="display:flex;align-items:center;justify-content:space-between;padding:8px 10px;background:var(--surface2);border-radius:var(--radius-sm);">
                  <div>
                    <div style="font-size:12px;font-weight:600;">Supprimer toutes les tâches closes</div>
                    <div style="font-size:10.5px;color:var(--text-muted);">Efface définitivement les tâches Terminées et Abandonnées</div>
                  </div>
                  <button class="btn" id="cfg-eis-del-closed" style="border-color:var(--red);color:var(--red);white-space:nowrap;font-size:11px;">🗑 Purger</button>
                </div>
                <div style="display:flex;align-items:center;justify-content:space-between;padding:8px 10px;background:var(--surface2);border-radius:var(--radius-sm);">
                  <div>
                    <div style="font-size:12px;font-weight:600;">Réinitialiser toute la matrice</div>
                    <div style="font-size:10.5px;color:var(--text-muted);">Supprime <strong>toutes</strong> les tâches — action irréversible</div>
                  </div>
                  <button class="btn" id="cfg-eis-reset-all" style="border-color:var(--red);color:var(--red);white-space:nowrap;font-size:11px;">⚠️ Tout effacer</button>
                </div>
              </div>
            </div>

            <!-- Export rapide -->
            <div class="panel">
              <div class="phd"><div class="ptitle">📤 Export</div></div>
              <div style="padding:14px;display:flex;flex-direction:column;gap:8px;">
                <button class="btn" id="cfg-eis-export-json" style="font-size:12px;width:100%;">⬇️ Exporter les tâches (JSON)</button>
                <div style="font-size:10px;color:var(--text-dim);">Sauvegarde toutes vos tâches Eisenhower dans un fichier JSON pour archivage ou transfert.</div>
              </div>
            </div>

          </div>
        </div>
      </div>

      <div id="cfg-database" style="display:none;">
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px;align-items:start;">

          <div class="panel">
            <div class="phd"><div class="ptitle">💾 Sauvegarde &amp; Export</div></div>
            <div style="padding:16px;display:flex;flex-direction:column;gap:14px;">
              <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;">
                <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:4px;">💿 Sauvegarde automatique (JSON)</div>
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;">Les données sont sauvegardées automatiquement dans le navigateur. Exportez un fichier <code style="font-family:var(--mono);background:var(--surface3);padding:1px 4px;border-radius:2px;">.json</code> sur disque pour une sauvegarde complète (inclut Risques &amp; Tâches Quotidiennes). Fonctionne <strong>hors ligne</strong>.</div>
                <div style="display:flex;gap:8px;flex-wrap:wrap;">
                  <button class="btn p" id="db-save-json">⬇️ Exporter JSON</button>
                  <button class="btn" id="db-load-json-btn">⬆️ Charger JSON</button>
                  <input type="file" id="db-load-json-input" accept=".json" style="display:none;">
                </div>
              </div>
              <div style="background:var(--green-bg);border:1px solid #b2dfcb;border-radius:6px;padding:12px 14px;">
                <div style="font-size:12px;font-weight:600;color:var(--green);margin-bottom:4px;">📊 Export Excel</div>
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;">Exporte toutes les données (Sociétés, Auditeurs, Audits, Recommandations, Risques, Tâches Quotidiennes, Absences) en fichier <code style="font-family:var(--mono);background:var(--surface3);padding:1px 4px;border-radius:2px;">.xlsx</code> multi-onglets. Disponible <strong>hors ligne</strong> — aucune connexion requise.</div>
                <button class="btn" id="db-export-excel" style="background:var(--green);border-color:var(--green);color:#fff;">⬇️ Exporter Excel (.xlsx)</button>
              </div>
              <div style="background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:6px;padding:12px 14px;">
                <div style="font-size:12px;font-weight:600;color:var(--accent);margin-bottom:4px;">⬆️ Import Excel</div>
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;">Importez un fichier <code style="font-family:var(--mono);background:var(--surface3);padding:1px 4px;border-radius:2px;">.xlsx</code> — fonctionne <strong>hors ligne</strong>. Onglets reconnus : <em>Societes</em>, <em>Auditeurs</em>, <em>Audits</em>, <em>Recommandations</em>, <em>Risques</em>, <em>Taches_Quotidiennes</em>, <em>Missions</em>, <em>Taches</em>, <em>Absences</em>, <em>RCM</em>, <em>TAF</em>. Téléchargez le modèle de chaque module ci-dessous.</div>
                <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:12px;">
                  <button class="btn p" id="db-import-excel-btn">⬆️ Importer Excel</button>
                  <input type="file" id="db-import-excel-input" accept=".xlsx,.xls" style="display:none;">
                  <select id="db-import-mode" class="finp" style="height:28px;font-size:11px;width:auto;padding:3px 24px 3px 7px;appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 6px center;">
                    <option value="merge">Fusionner</option>
                    <option value="replace">Remplacer</option>
                  </select>
                </div>
                <div style="font-size:11px;font-weight:600;color:var(--text);margin-bottom:8px;">📄 Modèles d'import par module :</div>
                <div style="display:flex;flex-direction:column;gap:5px;">
                  <!-- Ligne par module : [📥 Modèle] [⬆️ Importer] [⚠️ Remise à zéro] -->
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-societes"  style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">🏢 Sociétés &amp; Filiales</button>
                    <button class="btn tpl-imp-btn" data-sheet="Societes"  style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Societes"  title="Remettre à zéro les Sociétés" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-auditeurs" style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">👥 Équipe Auditeurs</button>
                    <button class="btn tpl-imp-btn" data-sheet="Auditeurs" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Auditeurs" title="Remettre à zéro les Auditeurs" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                    <button class="btn tpl-btn" id="tpl-responsables" style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">👤 Responsables Recos</button>
                    <button class="btn tpl-imp-btn" data-sheet="Responsables" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Responsables" title="Remettre à zéro les Responsables" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-audits"    style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">◈ Plans d'audit interne</button>
                    <button class="btn tpl-imp-btn" data-sheet="Audits"    style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Audits"    title="Remettre à zéro les Audits" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-recos"     style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">◎ Suivi Recommandations</button>
                    <button class="btn tpl-imp-btn" data-sheet="Recommandations" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Recommandations" title="Remettre à zéro les Recommandations" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-risques"   style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">◇ Risques</button>
                    <button class="btn tpl-imp-btn" data-sheet="Risques"   style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Risques"   title="Remettre à zéro les Risques" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-planning"  style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">▤ Planning Missions</button>
                    <button class="btn tpl-imp-btn" data-sheet="Missions"  style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Missions"  title="Remettre à zéro le Planning" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-daily"     style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">📅 Tâches Quotidiennes</button>
                    <button class="btn tpl-imp-btn" data-sheet="Taches_Quotidiennes" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Taches_Quotidiennes" title="Remettre à zéro les Tâches Quotidiennes" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-absences"  style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">🏖️ Absences &amp; Congés</button>
                    <button class="btn tpl-imp-btn" data-sheet="Absences"  style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="Absences"  title="Remettre à zéro les Absences" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-rcm"       style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">🛡️ Risk Control Matrix</button>
                    <button class="btn tpl-imp-btn" data-sheet="RCM"       style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="RCM"       title="Remettre à zéro le RCM" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                  <div style="display:grid;grid-template-columns:1fr auto auto;gap:5px;align-items:center;">
                    <button class="btn tpl-btn" id="tpl-taf"       style="font-size:11px;padding:5px 10px;text-align:left;justify-content:flex-start;gap:6px;display:flex;align-items:center;">📝 Travail à Faire (TAF)</button>
                    <button class="btn tpl-imp-btn" data-sheet="TAF"       style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--accent);border-color:var(--accent);">⬆️ Importer</button>
                    <button class="btn tpl-reset-btn" data-sheet="TAF"       title="Remettre à zéro les TAF" style="font-size:11px;padding:5px 10px;white-space:nowrap;display:flex;align-items:center;gap:4px;color:var(--orange);border-color:var(--orange);">⚠️ Remise à zéro</button>
                  </div>
                </div>
                <!-- Input file caché unique — réutilisé pour chaque module -->
                <input type="file" id="tpl-imp-file-input" accept=".xlsx,.xls" style="display:none;">
              </div>
            </div>
          </div>

          <div class="panel">
            <div class="phd"><div class="ptitle">💥 Remise à zéro &amp; État</div></div>
            <div style="padding:16px;display:flex;flex-direction:column;gap:14px;">
              <div style="background:var(--red-bg);border:1px solid #f5b8b8;border-radius:6px;padding:12px 14px;">
                <div style="font-size:12px;font-weight:600;color:var(--red);margin-bottom:6px;">💥 Remise à zéro complète</div>
                <div style="font-size:11px;color:var(--text-muted);margin-bottom:10px;">Efface <strong>toutes</strong> les données sans exception. Base de données entièrement vide. <strong>Irréversible.</strong></div>
                <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
                  <input type="text" id="db-confirm-input" class="finp" style="height:28px;font-size:11px;padding:3px 8px;width:170px;" placeholder="Tapez CONFIRMER">
                  <button class="btn" id="db-reset-all" style="background:var(--red);border-color:var(--red);color:#fff;">💥 Tout effacer</button>
                </div>
              </div>
              <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;">
                <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
                  <div style="font-size:12px;font-weight:600;color:var(--text);">📊 État de la base de données</div>
                  <button class="btn" onclick="updateStorageInfo()" style="font-size:10px;padding:2px 8px;border-color:var(--accent);color:var(--accent);" title="Actualiser les statistiques">↻ Actualiser</button>
                </div>
                <div id="db-storage-info" style="font-size:11px;color:var(--text-muted);padding:4px 0;">Chargement…</div>
              </div>
            </div>
          </div>
        </div>
      </div>

    </div>

    <div id="view-auditeurs" style="display:none;margin-top:10px;">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:8px;">
        <div>
          <div style="font-size:15px;font-weight:700;color:var(--text);">👥 Équipe Auditeurs — Missions &amp; Charge</div>
          <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">Missions en cours, planifiées et clôturées par auditeur</div>
        </div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
          <div class="litem"><span style="font-size:11px;">En cours</span></div>
          <div class="litem"><span style="font-size:11px;">Planifiée</span></div>
          <div class="litem"><span style="font-size:11px;">Clôturée</span></div>
          <div class="litem"><span style="font-size:11px;">En retard</span></div>
          <input id="aud-view-search" class="finp" style="width:160px;height:28px;font-size:11px;padding:3px 8px;" placeholder="🔍 Rechercher…">
        </div>
      </div>
      <div id="w-auditeurs-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:12px;"></div>
    </div>

    <div id="view-absences" style="display:none;margin-top:10px;">

      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:8px;">
        <div>
          <div style="font-size:15px;font-weight:700;color:var(--text);">🏖️ Absences &amp; Congés</div>
          <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">Disponibilité &amp; charge par auditeur</div>
        </div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
          <button class="tbtn p" id="btn-add-absence" style="font-size:12px;padding:5px 12px;background:var(--orange,#e67e22);border-color:var(--orange,#e67e22);">📅 + Absence / Congé</button>
        </div>
      </div>

      <div id="absence-cal-section" style="border:1px solid var(--border);border-radius:8px;overflow:hidden;background:var(--surface);">
        <div style="display:flex;align-items:center;gap:10px;padding:10px 16px;background:var(--surface2);border-bottom:1px solid var(--border);flex-wrap:wrap;">
          <span style="font-size:13px;font-weight:700;color:var(--text);">📋 Absences &amp; Congés</span>
          <select id="absence-filter-aud" class="finp" style="margin-left:auto;height:26px;font-size:11px;padding:2px 22px 2px 7px;width:auto;min-width:140px;appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 6px center;">
            <option value="">— Tous les auditeurs —</option>
          </select>
        </div>

        <div id="absence-list-view" style="padding:12px 16px;">
          <table class="atable">
            <thead><tr>
              <th>Auditeur</th>
              <th>Type</th>
              <th>Statut</th>
              <th>Début</th>
              <th>Fin</th>
              <th>Durée (j)</th>
              <th>Motif / Note</th>
              <th>Conflit mission</th>
              <th>Actions</th>
            </tr></thead>
            <tbody id="absence-list-tbody"></tbody>
          </table>
          <div id="absence-list-empty" style="display:none;padding:30px;text-align:center;color:var(--text-dim);font-size:12px;">Aucune absence enregistrée.</div>
        </div>
      </div>

      <div style="border:1px solid var(--border);border-radius:8px;overflow:hidden;background:var(--surface);margin-top:16px;">
        <div style="display:flex;align-items:center;gap:10px;padding:10px 16px;background:var(--surface2);border-bottom:1px solid var(--border);">
          <span style="font-size:13px;font-weight:700;color:var(--text);">📊 Disponibilité &amp; Charge par Auditeur</span>
          <span style="font-size:10px;color:var(--text-muted);margin-left:4px;">— Absences enregistrées vs missions affectées</span>
          <select id="dispo-filter-aud" class="finp" style="margin-left:auto;height:26px;font-size:11px;padding:2px 22px 2px 7px;width:auto;min-width:160px;appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 6px center;">
            <option value="">— Tous les auditeurs —</option>
          </select>
        </div>
        <div style="overflow-x:auto;">
          <table class="atable" id="dispo-table">
            <thead><tr>
              <th>Auditeur</th>
              <th>Statut</th>
              <th>Missions actives</th>
              <th>Absences à venir</th>
              <th>Conflits détectés</th>
              <th>Disponibilité</th>
              <th style="width:90px;">Actions</th>
            </tr></thead>
            <tbody id="dispo-tbody"></tbody>
          </table>
        </div>
      </div>

    </div>

    <div id="view-ordre-mission" style="display:none;margin-top:10px;">
      <div class="panel">
        <div class="phd">
          <div class="ptitle">📄 Ordre de Mission</div>
          <button class="tbtn p" id="om-new-btn">+ Nouveau</button>
          <button class="tbtn" id="om-print-btn" style="margin-left:4px;">🖨️ Imprimer</button>
        </div>

        <div id="om-list-section" style="padding:12px 16px;">
          <div style="display:flex;gap:8px;align-items:center;margin-bottom:10px;flex-wrap:wrap;">
            <input id="om-search" class="finp" style="height:28px;font-size:11px;padding:3px 8px;width:200px;" placeholder="🔍 Rechercher…">
            <select id="om-filter-soc" class="fsel" style="height:28px;font-size:11px;padding:3px 24px 3px 8px;min-width:160px;">
              <option value="">Toutes les sociétés</option>
            </select>
            <span id="om-count" style="font-size:11px;color:var(--text-muted);margin-left:auto;"></span>
          </div>
          <div id="om-cards-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:12px;"></div>
          <div id="om-empty" style="display:none;padding:40px;text-align:center;color:var(--text-dim);font-size:13px;">
            Aucun ordre de mission. Cliquez sur <strong>+ Nouveau</strong> pour en créer un.
          </div>
        </div>
      </div>

    </div>

    <div id="view-calendrier" style="display:none;margin-top:10px;">

      <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;flex-wrap:wrap;">
        <div>
          <div style="font-size:15px;font-weight:700;color:var(--text);">🗓️ Calendrier Unifié</div>
          <div style="font-size:11px;color:var(--text-muted);margin-top:2px;">Missions · Tâches · Absences · Rendez-vous</div>
        </div>

        <div style="display:flex;border:1px solid var(--border);border-radius:4px;overflow:hidden;margin-left:4px;">
          <button class="ucal-zoom-btn" data-zoom="day"   style="padding:5px 13px;font-size:11.5px;font-weight:600;border:none;border-right:1px solid var(--border);background:var(--surface2);color:var(--text-muted);cursor:pointer;">Jour</button>
          <button class="ucal-zoom-btn" data-zoom="week"  style="padding:5px 13px;font-size:11.5px;font-weight:600;border:none;border-right:1px solid var(--border);background:var(--surface2);color:var(--text-muted);cursor:pointer;">Semaine</button>
          <button class="ucal-zoom-btn active" data-zoom="month" style="padding:5px 13px;font-size:11.5px;font-weight:600;border:none;border-right:1px solid var(--border);background:var(--accent);color:#fff;cursor:pointer;">Mois</button>
          <button class="ucal-zoom-btn" data-zoom="year"  style="padding:5px 13px;font-size:11.5px;font-weight:600;border:none;background:var(--surface2);color:var(--text-muted);cursor:pointer;">Année</button>
        </div>

        <div style="display:flex;gap:4px;align-items:center;">
          <button id="ucal-prev" class="tbtn" style="padding:4px 10px;font-size:13px;">◀</button>
          <button id="ucal-today" class="tbtn" style="padding:4px 10px;font-size:11px;">Auj.</button>
          <button id="ucal-next" class="tbtn" style="padding:4px 10px;font-size:13px;">▶</button>
        </div>

        <div id="ucal-period-label" style="font-size:13px;font-weight:600;color:var(--text);min-width:160px;"></div>

        <div style="display:flex;gap:6px;margin-left:auto;flex-wrap:wrap;align-items:center;">
          <label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;"><input type="checkbox" id="ucal-show-missions" checked style="accent-color:var(--accent);"> <span style="color:#0064d9;font-weight:600;">📋 Missions</span></label>
          <label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;"><input type="checkbox" id="ucal-show-tasks" checked style="accent-color:#1e9c6a;"> <span style="color:#1e9c6a;font-weight:600;">✅ Tâches</span></label>
          <label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;"><input type="checkbox" id="ucal-show-absences" checked style="accent-color:#e67e22;"> <span style="color:#e67e22;font-weight:600;">🏖️ Absences</span></label>
          <label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;"><input type="checkbox" id="ucal-show-rdv" checked style="accent-color:#6941c6;"> <span style="color:#6941c6;font-weight:600;">📌 Rendez-vous</span></label>
          <button id="ucal-add-rdv" class="tbtn p" style="padding:4px 11px;font-size:11px;">+ Rendez-vous</button>
        </div>
      </div>

      <div style="display:flex;gap:10px;flex-wrap:wrap;margin-bottom:8px;padding:6px 10px;background:var(--surface);border:1px solid var(--border);border-radius:5px;">
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:12px;height:8px;border-radius:2px;background:linear-gradient(90deg,#0064d9,#338ef7);display:inline-block;"></i>Mission</span>
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:12px;height:8px;border-radius:2px;background:linear-gradient(90deg,#1e9c6a,#34c38f);display:inline-block;"></i>Tâche</span>
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:12px;height:8px;border-radius:2px;background:#e67e22;display:inline-block;"></i>Congé</span>
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:12px;height:8px;border-radius:2px;background:#ef4444;display:inline-block;"></i>Maladie</span>
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:12px;height:8px;border-radius:2px;background:#6941c6;display:inline-block;"></i>Formation</span>
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:12px;height:8px;border-radius:2px;background:#8b5cf6;display:inline-block;"></i>Rendez-vous</span>
        <span style="display:flex;align-items:center;gap:5px;font-size:10.5px;color:var(--text-muted);"><i style="width:10px;height:10px;background:#f59e0b;transform:rotate(45deg);border-radius:1px;display:inline-block;"></i>Jalon</span>
      </div>

      <div id="ucal-body" style="background:var(--surface);border:1px solid var(--border);border-radius:6px;overflow:hidden;box-shadow:var(--shadow);min-height:500px;"></div>
    </div>

    <div id="view-societes" style="display:none;margin-top:10px;">

      <div style="display:flex;gap:8px;align-items:center;margin-bottom:10px;">
        <div style="font-size:15px;font-weight:700;color:var(--text);">🏢 Tableau de bord Sociétés</div>

        <input id="soc-view-search" class="finp" style="width:180px;height:28px;font-size:11px;padding:3px 8px;" placeholder="🔍 Rechercher…">
        <select id="soc-view-filter" class="finp" style="height:28px;font-size:11px;padding:3px 20px 3px 7px;appearance:none;background-image:url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E');background-repeat:no-repeat;background-position:right 6px center;">
          <option value="all">Tous les secteurs</option>
          <option value="Finance">Finance</option>
          <option value="Technologie">Technologie</option>
          <option value="Industrie">Industrie</option>
          <option value="Commerce">Commerce</option>
          <option value="Services">Services</option>
          <option value="Santé">Santé</option>
          <option value="Énergie">Énergie</option>
        </select>
      </div>
      <div style="margin-bottom:8px;">
        <button class="btn" id="soc-debug-btn" style="font-size:10px;padding:2px 10px;color:var(--text-muted);">🔍 Diagnostic correspondances</button>
        <span id="soc-debug-out" style="font-size:10px;color:var(--text-muted);margin-left:8px;"></span>
      </div>
      <div id="soc-kpi-bar" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:8px;margin-bottom:12px;"></div>
      <div id="soc-view-grid" style="display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:12px;"></div>
    </div>

  </div>
</div>

<!-- ═══════════════════════════════════════════════════════
     VUE : RAPPORT D'AUDIT (Normes IIA)
════════════════════════════════════════════════════════ -->
<div id="view-rapport-audit" style="display:none;margin-top:10px;">

  <!-- Barre de contrôle -->
  <div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;flex-wrap:wrap;padding:10px 14px;background:var(--surface2);border:1px solid var(--border);border-radius:8px;">
    <strong style="font-size:13px;font-weight:700;color:var(--text);">📑 Rapport d'Audit — Normes IIA</strong>
    <select id="ra-select-audit" class="fsel" style="height:28px;font-size:11px;min-width:220px;">
      <option value="">— Sélectionner un audit —</option>
    </select>
    <select id="ra-filter-criticite" class="fsel" style="height:28px;font-size:11px;min-width:120px;">
      <option value="">Toutes criticités</option>
      <option value="critical">🔴 Critique</option>
      <option value="high">🟠 Élevé</option>
      <option value="medium">🟡 Moyen</option>
      <option value="low">🟢 Faible</option>
    </select>
    <label style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);cursor:pointer;">
      <input type="checkbox" id="ra-chk-executive" checked style="accent-color:var(--accent);"> Synthèse exécutive
    </label>
    <label style="display:flex;align-items:center;gap:5px;font-size:11px;color:var(--text-muted);cursor:pointer;">
      <input type="checkbox" id="ra-chk-recos" checked style="accent-color:var(--accent);"> Recommandations détaillées
    </label>

    <button id="ra-refresh-btn" class="btn" style="font-size:11px;padding:3px 10px;height:28px;">↻ Actualiser</button>

    <!-- ── Workflow Statut du document ── -->
    <div id="ra-statut-workflow" style="display:flex;align-items:center;gap:0;margin-left:8px;border:1px solid var(--border);border-radius:7px;overflow:hidden;opacity:.4;pointer-events:none;" title="Sélectionnez un audit pour modifier le statut">
      <button class="ra-wf-btn" data-statut="Projet de rapport"
        style="display:flex;align-items:center;gap:5px;padding:4px 11px;height:28px;font-size:10.5px;font-weight:600;border:none;border-right:1px solid var(--border);cursor:pointer;background:#f3f4f6;color:#6b7280;white-space:nowrap;">
        <span style="font-size:12px;">📝</span> Projet
      </button>
      <button class="ra-wf-btn" data-statut="Rapport provisoire"
        style="display:flex;align-items:center;gap:5px;padding:4px 11px;height:28px;font-size:10.5px;font-weight:600;border:none;border-right:1px solid var(--border);cursor:pointer;background:#f3f4f6;color:#6b7280;white-space:nowrap;">
        <span style="font-size:12px;">🔄</span> Provisoire
      </button>
      <button class="ra-wf-btn" data-statut="Rapport définitif"
        style="display:flex;align-items:center;gap:5px;padding:4px 11px;height:28px;font-size:10.5px;font-weight:600;border:none;cursor:pointer;background:#f3f4f6;color:#6b7280;white-space:nowrap;">
        <span style="font-size:12px;">✅</span> Définitif
      </button>
    </div>

    <div style="margin-left:auto;display:flex;gap:6px;">
      <button id="ra-preview-btn" class="btn" style="font-size:11px;padding:4px 14px;height:28px;background:var(--surface3);border:1px solid var(--border);">👁 Prévisualiser</button>
      <button id="ra-print-btn" class="btn p" style="font-size:11px;padding:4px 14px;height:28px;">🖨️ Imprimer / Exporter PDF</button>
    </div>
  </div>

  <!-- Alerte si aucun audit sélectionné -->
  <div id="ra-no-audit-msg" style="padding:40px;text-align:center;color:var(--text-muted);font-size:13px;background:var(--surface);border:1px dashed var(--border);border-radius:8px;display:none;">
    <div style="font-size:32px;margin-bottom:10px;">📋</div>
    <div>Sélectionnez un audit dans la liste ci-dessus pour générer le rapport.</div>
    <div style="font-size:11px;margin-top:6px;color:var(--text-dim);">Les audits sont créés dans « Plans d'audit interne ».</div>
  </div>

  <!-- Aperçu A4 -->
  <div id="ra-preview-wrapper" style="display:flex;justify-content:center;background:#e8eaed;padding:24px 16px;border-radius:8px;min-height:400px;">
    <div id="ra-a4-root" style="width:794px;min-height:1123px;background:#fff;border-radius:3px;box-shadow:0 4px 24px rgba(0,0,0,.18);font-family:'IBM Plex Sans','Segoe UI',Arial,sans-serif;font-size:11px;color:#1a1a2e;box-sizing:border-box;">
      <!-- Contenu généré dynamiquement par renderRapportAudit() -->
    </div>
  </div>

</div>

<!-- MODALE PRÉVISUALISATION RAPPORT D'AUDIT -->
<div id="ra-modal-preview" style="display:none;position:fixed;inset:0;z-index:9000;background:rgba(0,0,0,.72);flex-direction:column;">
  <div id="ra-modal-toolbar" style="display:flex;align-items:center;gap:8px;padding:8px 16px;background:#1a2236;border-bottom:1px solid #2d3a55;flex-shrink:0;flex-wrap:wrap;">
    <span id="ra-modal-title" style="font-size:12px;font-weight:700;color:#e2e8f0;white-space:nowrap;margin-right:6px;">Rapport d'Audit</span>
    <div style="width:1px;height:22px;background:#2d3a55;margin:0 4px;"></div>
    <div style="display:flex;align-items:center;gap:4px;flex-wrap:wrap;">
      <span style="font-size:10px;color:#94a3b8;margin-right:2px;">Section :</span>
      <button class="ra-sec-btn" data-sec="cover"    style="font-size:10px;padding:3px 9px;background:#0070f2;color:#fff;border:none;border-radius:4px;cursor:pointer;font-weight:600;">Garde</button>
      <button class="ra-sec-btn" data-sec="exec"     style="font-size:10px;padding:3px 9px;background:#374151;color:#d1d5db;border:none;border-radius:4px;cursor:pointer;">Synthèse</button>
      <button class="ra-sec-btn" data-sec="constats" style="font-size:10px;padding:3px 9px;background:#374151;color:#d1d5db;border:none;border-radius:4px;cursor:pointer;">Constats</button>
      <button class="ra-sec-btn" data-sec="pforts"   style="font-size:10px;padding:3px 9px;background:#374151;color:#d1d5db;border:none;border-radius:4px;cursor:pointer;">Points forts</button>
      <button class="ra-sec-btn" data-sec="recos"    style="font-size:10px;padding:3px 9px;background:#374151;color:#d1d5db;border:none;border-radius:4px;cursor:pointer;">Recommandations</button>
      <button class="ra-sec-btn" data-sec="annexe"   style="font-size:10px;padding:3px 9px;background:#374151;color:#d1d5db;border:none;border-radius:4px;cursor:pointer;">Annexe</button>
    </div>
    <div style="width:1px;height:22px;background:#2d3a55;margin:0 4px;"></div>
    <div style="display:flex;align-items:center;gap:5px;">
      <span style="font-size:10px;color:#94a3b8;">Zoom :</span>
      <button id="ra-zoom-out" style="width:22px;height:22px;background:#374151;color:#d1d5db;border:none;border-radius:3px;cursor:pointer;font-size:14px;line-height:1;">&#8722;</button>
      <span id="ra-zoom-label" style="font-size:10px;color:#e2e8f0;min-width:34px;text-align:center;">85%</span>
      <button id="ra-zoom-in"  style="width:22px;height:22px;background:#374151;color:#d1d5db;border:none;border-radius:3px;cursor:pointer;font-size:14px;line-height:1;">+</button>
      <button id="ra-zoom-fit" style="font-size:10px;padding:3px 7px;background:#374151;color:#d1d5db;border:none;border-radius:3px;cursor:pointer;">Ajuster</button>
    </div>
    <div style="width:1px;height:22px;background:#2d3a55;margin:0 4px;"></div>
    <div id="ra-modal-kpis" style="display:flex;gap:6px;align-items:center;"></div>
    <div style="margin-left:auto;display:flex;gap:6px;align-items:center;">
      <button id="ra-modal-print-btn" style="font-size:10px;padding:4px 12px;background:#0070f2;color:#fff;border:none;border-radius:5px;cursor:pointer;font-weight:600;">Imprimer</button>
      <button id="ra-modal-close" style="width:28px;height:28px;background:#4b5563;color:#d1d5db;border:none;border-radius:5px;cursor:pointer;font-size:16px;line-height:28px;font-weight:700;">&#10005;</button>
    </div>
  </div>
  <div id="ra-modal-body" style="flex:1;overflow-y:auto;overflow-x:auto;background:#525659;padding:28px 0;display:flex;justify-content:center;align-items:flex-start;">
    <div id="ra-modal-pages" style="display:flex;flex-direction:column;gap:16px;align-items:center;transform-origin:top center;transition:transform .2s;"></div>
  </div>
  <div id="ra-modal-footer" style="background:#1a2236;border-top:1px solid #2d3a55;padding:8px 16px;display:flex;align-items:center;gap:10px;flex-shrink:0;overflow-x:auto;">
    <span style="font-size:10px;color:#64748b;white-space:nowrap;">Pages :</span>
    <div id="ra-modal-thumbs" style="display:flex;gap:8px;"></div>
    <div style="margin-left:auto;font-size:10px;color:#475569;" id="ra-modal-page-info"></div>
  </div>
</div>

<!-- ─── @print styles pour le Rapport d'Audit ─── -->
<style id="ra-print-style">
@media print {
  .ra-print-only { display:block !important; }
}
.ra-print-only { display:none; }
</style>

<!-- ─── Styles FRAP ─── -->
<style id="frap-style">
/* ── Carte FRAP (A4-ready) ── */
.frap-card {
  width: 794px;
  max-width: 100%;
  background: #fff;
  font-family: Arial, Helvetica, sans-serif;
  font-size: 10.5px;
  color: #1a1a1a;
  border: 0.5px solid #d3d1c7;
  border-radius: 5px;
  overflow: hidden;
  margin-bottom: 18px;
  box-shadow: 0 1px 4px rgba(0,0,0,.07);
  page-break-inside: avoid;
}
.frap-head {
  background: #f9f8f6;
  border-bottom: 0.5px solid #d3d1c7;
  padding: 7px 12px;
  display: flex;
  align-items: flex-start;
  gap: 8px;
  justify-content: space-between;
}
.frap-num  { color: #c0392b; font-weight: bold; font-size: 10px; white-space: nowrap; padding-top: 1px; }
.frap-tit  { font-size: 11px; font-weight: bold; flex: 1; line-height: 1.4; }
.frap-badges { display: flex; gap: 4px; align-items: center; flex-shrink: 0; flex-wrap: wrap; }
.frap-badge  { display: inline-block; padding: 2px 8px; border-radius: 3px; font-size: 8.5px; font-weight: bold; white-space: nowrap; }
.frap-b-critique { background: #c0392b; color: #fff; }
.frap-b-majeur   { background: #e67e22; color: #fff; }
.frap-b-modere   { background: #f1c40f; color: #1a1a1a; }
.frap-b-mineur   { background: #27ae60; color: #fff; }
.frap-b-ref      { background: #eee; color: #555; border: 0.5px solid #ccc; }
.frap-b-soc      { background: #e8f1fd; color: #0064d9; border: 0.5px solid #b0ccf0; }
.frap-b-taf      { background: #f0e8fd; color: #6b21a8; border: 0.5px solid #d4bef0; cursor: pointer; }

/* ── Dossier de mission — badges compteurs sur les audits Ouverts ── */
.dossier-badges { display: flex; gap: 4px; flex-wrap: wrap; margin-top: 5px; }
.dossier-badge {
  display: inline-block; padding: 1.5px 6px; border-radius: 3px; font-size: 8.5px;
  font-weight: 700; white-space: nowrap; cursor: pointer; border: 0.5px solid transparent;
}
.dossier-badge:hover { filter: brightness(0.94); }
.db-rcm     { background: #e8fdf1; color: #0a7d4b; border-color: #a8ecc6; }
.db-taf     { background: #f0e8fd; color: #6b21a8; border-color: #d4bef0; }
.db-frap    { background: #fdeee8; color: #c0392b; border-color: #f0c3b0; }
.db-actions { background: #e8f1fd; color: #0064d9; border-color: #b0ccf0; }
.db-rapport { background: #f3f4f6; color: #374151; border-color: #d1d5db; }
.frap-b-rcm      { background: #e8fdf1; color: #0a7d4b; border: 0.5px solid #a8ecc6; cursor: pointer; }
.frap-row        { display: flex; border-bottom: 0.5px solid #ede9e0; }
.frap-row:last-child { border-bottom: none; }
.frap-lbl {
  width: 130px; min-width: 130px;
  font-weight: bold; font-size: 9px; color: #555;
  background: #faf9f7;
  border-right: 0.5px solid #ede9e0;
  padding: 6px 8px;
  display: flex; align-items: flex-start;
  line-height: 1.4;
}
.frap-val   { flex: 1; padding: 6px 10px; font-size: 10px; color: #2c2c2a; line-height: 1.5; }
.frap-warn  { color: #7a2a1a; }
.frap-empty { color: #aaa; font-style: italic; }
.frap-list-item { display: flex; gap: 7px; align-items: flex-start; margin-bottom: 5px; }
.frap-list-item:last-child { margin-bottom: 0; }
.frap-dot {
  width: 16px; height: 16px; min-width: 16px;
  border-radius: 50%; color: #fff;
  font-size: 8px; font-weight: bold;
  display: flex; align-items: center; justify-content: center;
  margin-top: 1px; flex-shrink: 0;
}
.frap-dot-reco   { background: #c0392b; }
.frap-dot-action { background: #888; }
.frap-card-actions {
  display: flex; gap: 5px; padding: 5px 10px;
  background: #faf9f7; border-top: 0.5px solid #ede9e0;
  justify-content: flex-end;
}
.frap-card-btn {
  font-size: 10px; padding: 2px 8px; border-radius: 3px;
  cursor: pointer; border: 1px solid #ddd;
  background: #fff; color: #444; font-family: Arial, sans-serif;
  transition: all .12s;
}
.frap-card-btn:hover { background: #f0f2f4; border-color: #bbb; }
.frap-card-btn.danger { color: #bb2222; border-color: #f0bfbf; }
.frap-card-btn.danger:hover { background: #fdecea; }

/* ── Zone Preuve (pièces jointes) — modale FRAP + Fiche de test TAF ── */
.frap-preuve-dropzone, .taf-fiche-dropzone, .dly-fiche-dropzone {
  border: 1.5px dashed var(--border); border-radius: 6px; padding: 10px;
  min-height: 40px; transition: all .12s;
}
.frap-preuve-dropzone.dragover, .taf-fiche-dropzone.dragover, .dly-fiche-dropzone.dragover {
  border-color: var(--accent); background: rgba(0,112,242,.06);
}
.frap-preuve-list, .taf-fiche-list, .dly-fiche-list { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 8px; }
.frap-preuve-chip, .taf-fiche-chip, .dly-fiche-chip { width: 84px; position: relative; }
.frap-preuve-thumb, .taf-fiche-thumb, .dly-fiche-thumb {
  width: 84px; height: 84px; border-radius: 5px; object-fit: cover;
  border: 1px solid var(--border); display: block; background: #fff; cursor: pointer;
}
.frap-preuve-file, .taf-fiche-file, .dly-fiche-file {
  width: 84px; height: 84px; border-radius: 5px; border: 1px solid var(--border);
  background: var(--surface2); display: flex; align-items: center; justify-content: center;
  font-size: 24px; cursor: pointer;
}
.frap-preuve-name, .taf-fiche-name, .dly-fiche-name {
  font-size: 8.5px; color: var(--text-muted); text-align: center; margin-top: 3px;
  overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
}
.frap-preuve-size, .taf-fiche-size, .dly-fiche-size { font-size: 8px; color: var(--text-dim); text-align: center; }
.frap-preuve-rm, .taf-fiche-rm, .dly-fiche-rm {
  position: absolute; top: -6px; right: -6px; width: 18px; height: 18px; border-radius: 50%;
  background: #bb2222; color: #fff; display: flex; align-items: center; justify-content: center;
  font-size: 11px; line-height: 1; cursor: pointer; border: 2px solid #fff;
  box-shadow: 0 1px 3px rgba(0,0,0,.25);
}
.frap-preuve-rm:hover, .taf-fiche-rm:hover, .dly-fiche-rm:hover { background: #931b1b; }

/* ── Zone Preuve — carte FRAP (écran + impression) ── */
.frap-preuve-card-thumb {
  width: 52px; height: 52px; border-radius: 4px; object-fit: cover;
  border: 1px solid #d3d1c7; cursor: pointer; background: #fff;
}
.frap-preuve-card-file {
  width: 52px; height: 52px; border-radius: 4px; border: 1px solid #d3d1c7;
  background: #faf9f7; display: flex; align-items: center; justify-content: center;
  font-size: 18px; cursor: pointer;
}

/* ── Zone d'impression FRAP ── */
#frap-print-area {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

/* L'impression FRAP (unitaire ou groupée) passe désormais par #om-print-area
   (voir _buildFrapPrintHeader / frapBuildPrintDoc / frapPrint / frapPrintOne),
   déjà géré par la règle @media print générale (ligne ~859). */
@media print {
  .frap-card { box-shadow: none; border-radius: 0; page-break-inside: avoid; }
  .frap-card-actions { display: none !important; }
  #om-print-area .frap-print-doc .frap-card { border: none; box-shadow: none; margin-bottom: 0; }
  .frap-preuve-rm { display: none !important; }
  @page { size: A4 portrait; margin: 15mm 12mm; }
}
</style>

