<!-- ═══════════════════════════════════════════════════════════
     VUE MATRICE D'EISENHOWER
     ═══════════════════════════════════════════════════════════ -->
<div id="view-eisenhower" style="display:none;margin-top:10px;">

  <!-- Toolbar -->
  <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap;">
    <button class="tbtn p" id="eis-add-btn" style="font-size:11px;">➕ Nouvelle tâche</button>
    <select id="eis-filter-resp" class="wsel" style="font-size:11px;min-width:160px;"><option value="">— Tous les responsables —</option></select>
    <select id="eis-filter-state" class="wsel" style="font-size:11px;">
      <option value="">— Tous statuts —</option>
      <option value="todo">À faire</option>
      <option value="inprogress">En cours</option>
      <option value="done">Terminée</option>
      <option value="cancelled">Abandonnée</option>
    </select>
    <div style="margin-left:auto;display:flex;align-items:center;gap:6px;">
      <button class="tbtn" id="eis-view-matrix" style="font-size:11px;font-weight:600;background:var(--accent-bg);border-color:var(--accent);color:var(--accent);">⊞ Matrice</button>
      <button class="tbtn" id="eis-view-list" style="font-size:11px;">☰ Liste</button>
    </div>
  </div>

  <!-- Layout : panneau clos gauche + contenu principal droite -->
