  <!-- ═══ PANNEAU GAUCHE : TÂCHES CLOSES ═══ -->
  <div id="eis-left-panel" style="width:230px;flex-shrink:0;background:var(--surface);border:1px solid var(--border);border-radius:var(--radius-lg);overflow:hidden;box-shadow:var(--shadow);display:flex;flex-direction:column;max-height:calc(100vh - 160px);">
    <!-- En-tête panneau -->
    <div style="padding:8px 11px;background:var(--green-bg);border-bottom:1px solid #a8d9b8;display:flex;align-items:center;justify-content:space-between;flex-shrink:0;">
