      <div style="display:flex;gap:4px;">
        <span id="eis-left-cnt-done"    style="font-size:9.5px;font-weight:700;background:#fff;color:var(--green);border:1px solid #a8d9b8;border-radius:9px;padding:1px 6px;">0 ✓</span>
        <span id="eis-left-cnt-cancel"  style="font-size:9.5px;font-weight:700;background:#fff;color:var(--text-muted);border:1px solid var(--border);border-radius:9px;padding:1px 6px;">0 ✕</span>
      </div>
    </div>
    <!-- Filtre type -->
    <div style="padding:5px 8px;border-bottom:1px solid var(--border);flex-shrink:0;">
