    <div id="eis-left-list" style="flex:1;overflow-y:auto;padding:6px 7px;display:flex;flex-direction:column;gap:4px;scrollbar-width:thin;scrollbar-color:var(--border) transparent;">
      <div id="eis-left-empty" style="padding:20px 8px;text-align:center;color:var(--text-dim);font-size:11px;display:none;">
