      </div>
    </div>
  </div>

  <!-- ═══ CONTENU PRINCIPAL ═══ -->
  <div style="flex:1;min-width:0;">

  <!-- KPI strip -->
  <div class="wgrid wg3" style="margin-bottom:10px;grid-template-columns:repeat(4,1fr);">
    <div class="widget" style="border-left:3px solid #bb2222;">
      <div class="wbody" style="padding:8px 11px;">
        <div style="font-size:10px;color:var(--text-muted);margin-bottom:2px;">Q1 – Priorité</div>
        <div id="eis-kpi-q1" style="font-size:22px;font-weight:600;color:#bb2222;">0</div>
        <div style="font-size:10px;color:var(--text-muted);">Important & Urgent</div>
      </div>
    </div>
    <div class="widget" style="border-left:3px solid #1a8a4a;">
      <div class="wbody" style="padding:8px 11px;">
        <div style="font-size:10px;color:var(--text-muted);margin-bottom:2px;">Q2 – Planifier</div>
        <div id="eis-kpi-q2" style="font-size:22px;font-weight:600;color:#1a8a4a;">0</div>
        <div style="font-size:10px;color:var(--text-muted);">Important & Non Urgent</div>
      </div>
    </div>
    <div class="widget" style="border-left:3px solid #c47d00;">
      <div class="wbody" style="padding:8px 11px;">
        <div style="font-size:10px;color:var(--text-muted);margin-bottom:2px;">Q3 – Déléguer</div>
        <div id="eis-kpi-q3" style="font-size:22px;font-weight:600;color:#c47d00;">0</div>
        <div style="font-size:10px;color:var(--text-muted);">Non Imp. & Urgent</div>
