        <div style="font-size:10px;color:var(--text-muted);">Non Imp. & Non Urgent</div>
      </div>
    </div>
  </div>

  <!-- Vue Matrice 2x2 -->
  <div id="eis-matrix-view">
    <!-- Axes labels -->
    <div style="display:flex;align-items:stretch;gap:6px;min-height:calc(100vh - 260px);">
      <!-- Axe vertical IMPORTANCE -->
      <div style="display:flex;flex-direction:column;align-items:center;justify-content:center;min-width:18px;padding:4px 0;">
        <div style="writing-mode:vertical-rl;transform:rotate(180deg);font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.06em;white-space:nowrap;">
          ↑ Important · Non Important ↓
        </div>
