      <!-- Grille -->
      <div style="flex:1;display:flex;flex-direction:column;gap:6px;">
        <!-- Axe horizontal URGENCE -->
        <div style="display:flex;justify-content:space-between;padding:0 4px;">
          <span style="font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.06em;">← Non urgent</span>
          <span style="font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.06em;">Urgent →</span>
        </div>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;flex:1;">
          <!-- Q2 : Important / Non Urgent -->
          <div class="eis-quadrant" data-q="q2" style="background:#f2fdf5;border:1.5px solid #a8d9b8;border-radius:var(--radius-lg);padding:10px;display:flex;flex-direction:column;gap:6px;">
