              <span style="font-size:11.5px;font-weight:600;color:#1a7a40;">Important & Non Urgent</span>
            </div>
            <div style="font-size:10px;color:#1a8a4a;margin-bottom:4px;">📅 À planifier</div>
            <div id="eis-cards-q2" style="display:flex;flex-direction:column;gap:5px;flex:1;overflow-y:auto;"></div>
          </div>
          <!-- Q1 : Important / Urgent -->
          <div class="eis-quadrant" data-q="q1" style="background:#fdecea;border:1.5px solid #e8b4b4;border-radius:var(--radius-lg);padding:10px;display:flex;flex-direction:column;gap:6px;">
            <div style="display:flex;align-items:center;gap:6px;margin-bottom:2px;">
              <span style="background:#bb2222;color:#fff;font-size:9px;font-weight:700;padding:2px 8px;border-radius:10px;">Q1</span>
              <span style="font-size:11.5px;font-weight:600;color:#aa1111;">Important & Urgent</span>
            </div>
            <div style="font-size:10px;color:#bb2222;margin-bottom:4px;">⚡ À traiter en priorité</div>
            <div id="eis-cards-q1" style="display:flex;flex-direction:column;gap:5px;flex:1;overflow-y:auto;"></div>
          </div>
          <!-- Q4 : Non Important / Non Urgent -->
          <div class="eis-quadrant" data-q="q4" style="background:#f4f0fd;border:1.5px solid #c5b4e8;border-radius:var(--radius-lg);padding:10px;display:flex;flex-direction:column;gap:6px;">
            <div style="display:flex;align-items:center;gap:6px;margin-bottom:2px;">
              <span style="background:#6941c6;color:#fff;font-size:9px;font-weight:700;padding:2px 8px;border-radius:10px;">Q4</span>
              <span style="font-size:11.5px;font-weight:600;color:#5030a0;">Non Important & Non Urgent</span>
            </div>
            <div style="font-size:10px;color:#6941c6;margin-bottom:4px;">🗑 À abandonner</div>
            <div id="eis-cards-q4" style="display:flex;flex-direction:column;gap:5px;flex:1;overflow-y:auto;"></div>
          </div>
          <!-- Q3 : Non Important / Urgent -->
          <div class="eis-quadrant" data-q="q3" style="background:#fef0e4;border:1.5px solid #f0c890;border-radius:var(--radius-lg);padding:10px;display:flex;flex-direction:column;gap:6px;">
            <div style="display:flex;align-items:center;gap:6px;margin-bottom:2px;">
              <span style="background:#c47d00;color:#fff;font-size:9px;font-weight:700;padding:2px 8px;border-radius:10px;">Q3</span>
              <span style="font-size:11.5px;font-weight:600;color:#a06500;">Non Important & Urgent</span>
            </div>
            <div style="font-size:10px;color:#c47d00;margin-bottom:4px;">↗ À déléguer</div>
            <div id="eis-cards-q3" style="display:flex;flex-direction:column;gap:5px;flex:1;overflow-y:auto;"></div>
          </div>
        </div>
      </div>
    </div>
  </div>

  <!-- Vue Liste -->
  <div id="eis-list-view" style="display:none;">
    <div class="panel">
      <div style="overflow-x:auto;">
        <table class="atable" id="eis-table">
