        Aucune tâche enregistrée. Cliquez sur <strong>➕ Nouvelle tâche</strong> pour commencer.
      </div>
    </div>
  </div>

  <!-- Vue Tâches Closes -->
  <div id="eis-closed-view" style="display:none;">
    <!-- Bandeau résumé -->
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding:10px 14px;background:var(--green-bg);border:1px solid #a8d9b8;border-radius:var(--radius-lg);">
      <span style="font-size:22px;">✅</span>
      <div>
        <div style="font-size:13px;font-weight:700;color:var(--green);">Tâches Closes</div>
        <div style="font-size:11px;color:var(--text-muted);">Tâches terminées (<span style="font-weight:600;color:var(--green);" id="eis-closed-count-done">0</span>) et abandonnées (<span style="font-weight:600;color:var(--text-muted);" id="eis-closed-count-cancelled">0</span>)</div>
      </div>
      <div style="margin-left:auto;display:flex;gap:6px;flex-wrap:wrap;align-items:center;">
        <label style="font-size:11px;color:var(--text-muted);">Quadrant :</label>
        <select id="eis-closed-filter-q" class="wsel" style="font-size:11px;">
          <option value="">Tous</option>
          <option value="q1">Q1 – Important & Urgent</option>
          <option value="q2">Q2 – Important & Non Urgent</option>
          <option value="q3">Q3 – Non Imp. & Urgent</option>
          <option value="q4">Q4 – Non Imp. & Non Urgent</option>
        </select>
        <select id="eis-closed-filter-type" class="wsel" style="font-size:11px;">
          <option value="">Terminées + Abandonnées</option>
          <option value="done">Terminées seulement</option>
          <option value="cancelled">Abandonnées seulement</option>
        </select>
      </div>
    </div>
    <!-- Table -->
    <div class="panel">
      <div style="overflow-x:auto;">
        <table class="atable" id="eis-closed-table">
          <thead><tr>
            <th>Statut</th>
            <th>Quadrant</th>
            <th>Tâche</th>
            <th>Responsable</th>
            <th>Échéance</th>
            <th>Durée</th>
            <th>Difficulté</th>
            <th>Notes</th>
            <th style="width:80px;">Actions</th>
          </tr></thead>
          <tbody id="eis-closed-tbody"></tbody>
        </table>
      </div>
      <div id="eis-closed-empty" style="padding:40px;text-align:center;color:var(--text-dim);font-size:12px;display:none;">
        <div style="font-size:28px;margin-bottom:8px;">📭</div>
        Aucune tâche close pour le moment.
      </div>
    </div>
  </div>

  </div><!-- /contenu principal -->
  </div><!-- /layout flex gauche+droite -->

</div><!-- /#view-eisenhower -->

<!-- Modal Eisenhower -->
<div class="mbk" id="eis-modal">
  <div class="modal" style="width:560px;">
    <div class="mhd">
      <span class="mtitle" id="eis-modal-title">➕ Nouvelle tâche</span>
      <span class="mclose" id="eis-modal-close">✕</span>
    </div>
    <div class="mbody" style="display:flex;flex-direction:column;gap:12px;">
      <input type="hidden" id="eis-edit-idx">
      <div>
        <div class="flbl2">Intitulé de la tâche <span class="t-red">*</span></div>
        <input class="finp" id="eis-name" placeholder="Ex: Clôturer le rapport d'audit T3">
      </div>
      <div class="fgrid">
        <div>
          <div class="flbl2">Quadrant <span class="t-red">*</span></div>
          <select class="finp fsel" id="eis-quadrant" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
            <option value="q1">Q1 – Important & Urgent (Priorité)</option>
            <option value="q2">Q2 – Important & Non Urgent (Planifier)</option>
            <option value="q3">Q3 – Non Important & Urgent (Déléguer)</option>
            <option value="q4">Q4 – Non Important & Non Urgent (Abandonner)</option>
          </select>
        </div>
        <div>
          <div class="flbl2">Priorité</div>
          <select class="finp fsel" id="eis-priority" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
            <option value="normal">Normal</option>
            <option value="high">Haute</option>
            <option value="critical">Critique</option>
          </select>
        </div>
      </div>
      <div class="fgrid">
        <div>
          <div class="flbl2">Responsable de mise en œuvre <span class="t-red">*</span></div>
          <select class="finp fsel" id="eis-responsable" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
            <option value="">— Sélectionner un auditeur —</option>
          </select>
        </div>
        <div id="eis-delegue-wrap">
          <div class="flbl2">Délégué à <small style="font-weight:400;text-transform:none;font-size:9px;">(Q3 uniquement)</small></div>
          <select class="finp fsel" id="eis-delegue" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
            <option value="">— Aucun —</option>
          </select>
