      </div>
      <div class="fgrid">
        <div>
          <div class="flbl2">Date de début</div>
          <input class="finp" type="date" id="eis-date-debut">
        </div>
        <div>
          <div class="flbl2">Date d'échéance</div>
          <input class="finp" type="date" id="eis-date-fin">
        </div>
      </div>
      <div class="fgrid">
        <div>
          <div class="flbl2">Durée estimée de traitement</div>
          <div style="display:flex;gap:6px;align-items:center;">
            <input class="finp" type="number" id="eis-duree-val" min="0" step="0.5" placeholder="Ex: 2" style="width:80px;text-align:center;">
            <select class="finp fsel" id="eis-duree-unite" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;flex:1;">
              <option value="h">Heure(s)</option>
