            <button type="button" class="eis-diff-opt" data-val="facile"    style="flex:1;padding:5px 4px;border-radius:4px;font-size:10.5px;font-weight:600;cursor:pointer;border:1.5px solid #a8d9b8;background:#f2fdf5;color:#1a8a4a;transition:all .15s;">🟢 Facile</button>
            <button type="button" class="eis-diff-opt" data-val="moyen"     style="flex:1;padding:5px 4px;border-radius:4px;font-size:10.5px;font-weight:600;cursor:pointer;border:1.5px solid var(--border);background:var(--surface2);color:var(--text-muted);transition:all .15s;">🟡 Moyen</button>
            <button type="button" class="eis-diff-opt" data-val="difficile" style="flex:1;padding:5px 4px;border-radius:4px;font-size:10.5px;font-weight:600;cursor:pointer;border:1.5px solid var(--border);background:var(--surface2);color:var(--text-muted);transition:all .15s;">🔴 Difficile</button>
            <input type="hidden" id="eis-difficulte" value="moyen">
