        <div class="flbl2">Statut</div>
        <select class="finp fsel" id="eis-state" style="appearance:none;background-image:var(--_SA);background-repeat:no-repeat;background-position:right 8px center;">
          <option value="todo">À faire</option>
          <option value="inprogress">En cours</option>
          <option value="done">Terminée</option>
          <option value="cancelled">Abandonnée</option>
        </select>
      </div>
      <div>
        <div class="flbl2">Description / Notes</div>
        <textarea class="finp" id="eis-notes" rows="3" style="resize:vertical;" placeholder="Contexte, objectifs, ressources nécessaires…"></textarea>
      </div>
    </div>
    <div class="mft">
      <button class="btn" id="eis-modal-cancel">Annuler</button>
      <button class="btn p" id="eis-modal-save">💾 Enregistrer</button>
    </div>
  </div>
</div>

<script>
const SEED_SOCIETES=()=>[];
const SEED_RESPONSABLES=()=>[];
const SEED_AUDITEURS=()=>[];
const SEED_AUDITS=()=>[];
const SEED_ACTIONS=()=>[];
const SEED_GANTT=()=>[];
const SEED_RISKS=()=>[];
const SEED_ABSENCES=()=>[];

/* ══════════════════════════════════════════════════════════
   RCM_CYCLES — source unique, globale, partagée entre
   Nouvel Audit (#f-cycle) et modal RCM (#rcm-f-cycle-in)
   ══════════════════════════════════════════════════════════ */
var RCM_CYCLES = {
  "Ventes – Clients (Order to Cash)": [
