    "Encaissement","Gestion des créances clients"
  ],
  "Achats – Fournisseurs (Procure to Pay)": [
    "Expression du besoin","Sélection fournisseur","Commande",
    "Réception des biens/services","Comptabilisation des factures","Paiement fournisseurs"
  ],
  "Stocks et Inventaires": [
    "Entrée en stock","Sortie de stock","Mouvements internes",
    "Inventaires physiques","Valorisation des stocks","Gestion des écarts d'inventaire"
  ],
  "Trésorerie (Cash Management)": [
    "Encaissements espèces et bancaires","Décaissements","Gestion de caisse",
    "Rapprochements bancaires","Sécurisation des fonds","Gestion des transferts de fonds"
  ],
  "Banque": [
    "Ouverture/gestion des comptes bancaires","Mouvements bancaires",
    "Rapprochement bancaire","Autorisation des opérations bancaires"
  ],
  "Comptabilité Générale": [
    "Saisie comptable","Lettrage des comptes","Rapprochements comptables",
    "Clôture mensuelle/annuelle","Élaboration des états financiers"
  ],
  "Immobilisations": [
    "Acquisition des actifs","Mise en service","Amortissement",
    "Cession / mise au rebut","Inventaire des immobilisations"
  ],
  "Fiscal et Social": [
    "Déclarations fiscales (TVA, IS, IR…)","Paiement des impôts",
    "Déclarations sociales","Contrôle de conformité réglementaire"
  ],
  "Budget et Contrôle de Gestion": [
    "Élaboration budgétaire","Suivi budgétaire",
    "Analyse des écarts","Reporting de performance"
  ],
  "Paie et Ressources Humaines": [
    "Recrutement","Gestion du personnel","Calcul de la paie",
    "Paiement des salaires","Déclarations sociales","Gestion des congés et absences"
  ],
  "Gouvernance et Contrôle Interne": [
    "Organisation et séparation des tâches","Politique de contrôle interne",
    "Gestion des risques","Audit interne","Reporting de conformité"
  ],
  "Sécurité et Protection des actifs": [
    "Sécurisation des fonds et biens","Accès aux systèmes",
    "Contrôle des accès physiques","Gestion des habilitations"
  ],
  "Systèmes d'Information (IT)": [
    "Gestion des accès utilisateurs","Sécurité informatique",
    "Sauvegarde des données","Intégrité des systèmes comptables","Traçabilité des opérations"
  ],
  "Juridique et Contractuel": [
    "Contrats clients et fournisseurs","Suivi des engagements",
    "Respect des clauses contractuelles","Litiges et contentieux"
  ]
};

$(function(){

/* ── Peupler #rcm-f-cycle-in depuis RCM_CYCLES (source unique) ── */
(function(){
  const $s=$('#rcm-f-cycle-in');
  Object.keys(RCM_CYCLES).forEach(c=>$s.append(`<option value="${c}">${c}</option>`));
})();

let AUDITS=SEED_AUDITS();
let ACTIONS=SEED_ACTIONS();
let RISKS=SEED_RISKS();
let ABSENCES=SEED_ABSENCES();

/* ── Types d'audit personnalisés ── */
let CUSTOM_AUDIT_TYPES = [];
// Exemple de structure :

/* ── Risk Control Matrix data store ── */
let RCM_DATA = [
  {
    id:'RCM-001', filiale:'ARBIOCHEM', ref:'CC-01', cycle:'Trésorerie',
    processus:'Encaissement', tache:'Encaissement clients',
    objectif:"S'assurer que l'authenticité de chaque billet encaissé est vérifiée avant la finalisation de la vente",
    risque:'Réception et acceptation de fausse monnaie',
    imp_op:0, imp_fin:3, imp_rep:0,
    impact:3, likelihood:2, inherent:6,
    controle:"Existence de détecteur fausse monnaie\nUtilisation systématique d'un détecteur fausse monnaie",
    efficacite:3, residuel:3
  }
];
const sLabel={

  planned:'Planifiée',
  open:'Ouverte',
  inprogress:'En cours',
  completed:'Clôturée',
  overdue:'En retard',

  draft:'Brouillon',

  fully:'✅ Clos',
  partially:'📂 Dossier à suivre',
  nonechu:'📅 Non échue',
  notimplemented:'📂 Dossier à suivre'
};
const svLabel={critical:'Critical',high:'High',medium:'Medium',low:'Low'};
const aColors={MA:'#0070f2',LM:'#1a8a4a',SR:'#6941c6',PD:'#c47d00',NB:'#bb2222'};
const AUDIT_STATUS_LABELS={planned:'Planifiée',open:'Ouverte',inprogress:'En cours',overdue:'En retard',completed:'Clôturée'};

const VM={overview:'view-overview',audits:'view-audits',taf:'view-taf',frap:'view-frap',actions:'view-actions',risks:'view-risks',rcm:'view-rcm',gantt:'view-gantt',daily:'view-daily','ordre-mission':'view-ordre-mission',config:'view-config',auditeurs:'view-auditeurs',societes:'view-societes',absences:'view-absences','recap-reco':'view-recap-reco',calendrier:'view-calendrier','rapport-rcm':'view-rapport-rcm','rapport-audit':'view-rapport-audit','points-forts':'view-points-forts',eisenhower:'view-eisenhower'};
const VH={
  overview:'Audits planifiés — Année en cours et à venir',
  audits:'Plans d\'audit',
  actions:'Suivi des Recommandations',
  risks:'Registre des risques',
  rcm:'🛡️ Risk Control Matrix',
  gantt:'📅 Planning Gantt',
  daily:'📅 Tâches Quotidiennes',
  'ordre-mission':'📄 Ordre de Mission',

  taf:'📝 Travail à Faire (TAF)',
  frap:'📋 FRAP — Fiches de Relevé d\'Anomalies et de Pratiques',
  config:'Configuration — Sociétés & Auditeurs',
  auditeurs:'Équipe Auditeurs — Missions & Charge',
  societes:'Tableau de bord Sociétés',
  absences:'🏖️ Absences & Congés',
  'recap-reco':'📊 Récapitulatif des Recommandations',
  calendrier:'🗓️ Calendrier Unifié',
  'rapport-rcm':'🛡️ TERMES DE REFERENCE',
  'rapport-audit':'📑 Rapport d\'Audit — Normes IIA',
  eisenhower:'🎯 Matrice d\'Eisenhower'
};

function donut(svgId, lgId, data, cx=48, cy=48, r=34, sw=13){
  const $s=$('#'+svgId); $s.empty();
  const tot=data.reduce((a,d)=>a+d.v,0);
  const circ=2*Math.PI*r; let off=0;
  $s.append(`<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="#e8eaed" stroke-width="${sw}"/>`);
  data.forEach(d=>{
    const pct=d.v/tot, dash=pct*circ, gap=circ-dash;
    $s.append(`<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${d.c}" stroke-width="${sw}"
      stroke-dasharray="${dash.toFixed(2)} ${gap.toFixed(2)}" stroke-dashoffset="${(-off).toFixed(2)}"
      style="transform:rotate(-90deg);transform-origin:${cx}px ${cy}px;"/>`);
    off+=dash;
  });
  $s.append(`<text x="${cx}" y="${cy+4}" text-anchor="middle" font-size="12" font-weight="700" fill="#1d2126" font-family="IBM Plex Mono,monospace">${tot}</text>`);
  if(lgId){
    const $l=$('#'+lgId).empty();
    data.forEach(d=>$l.append(`<div class="litem"><span>${d.label}</span><span style="margin-left:4px;font-weight:700;color:var(--text)">${d.v}</span></div>`));
  }
}

function vbar(svgId, data, colors, W=252, H=126){
  const $s=$('#'+svgId); $s.empty();
  const pL=24,pB=20,pT=7; const cW=W-pL-5,cH=H-pB-pT;
  const n=data.length, ns=data[0].vals.length;
  const gW=cW/n, bw=Math.max(7,Math.min(16,(gW-4)/ns-2));
  const maxV=Math.max(...data.flatMap(d=>d.vals),1);
  [0,.5,1].forEach(p=>{
    const y=pT+cH*(1-p);
    $s.append(`<line x1="${pL}" y1="${y}" x2="${W-4}" y2="${y}" stroke="#e8eaed" stroke-width="1"/>`);
    $s.append(`<text x="${pL-2}" y="${y+3}" font-size="7" fill="#9aa0a8" text-anchor="end">${Math.round(p*maxV)}</text>`);
  });
  data.forEach((d,i)=>{
    const cx=pL+i*gW+gW/2;
    d.vals.forEach((v,j)=>{
      const bh=(v/maxV)*cH||0;
      const x=cx-(ns*bw+(ns-1)*2)/2+j*(bw+2);
      $s.append(`<rect x="${x.toFixed(1)}" y="${(pT+cH-bh).toFixed(1)}" width="${bw}" height="${bh.toFixed(1)}" rx="2" fill="${colors[j]||colors[0]}" opacity=".85"/>`);
      if(v>0)$s.append(`<text x="${(x+bw/2).toFixed(1)}" y="${(pT+cH-bh-2).toFixed(1)}" font-size="7" fill="#6b7785" text-anchor="middle">${v}</text>`);
    });
    $s.append(`<text x="${cx.toFixed(1)}" y="${H-4}" font-size="7.5" fill="#6b7785" text-anchor="middle">${d.label}</text>`);
  });
}

function hbar(svgId, data, color='#0070f2', W=252, H=126){
  const $s=$('#'+svgId); $s.empty();
  const pL=52,pR=28,pT=5; const cW=W-pL-pR;
  const n=data.length, bh=Math.min(15,(H-pT*2)/n-3);
  const maxV=Math.max(...data.map(d=>d.v),1);
  data.forEach((d,i)=>{
    const y=pT+i*(H-pT*2)/n;
    const bw=(d.v/maxV)*cW;
    $s.append(`<text x="${pL-3}" y="${y+bh/2+3.5}" font-size="8" fill="#6b7785" text-anchor="end">${d.label}</text>`);
    $s.append(`<rect x="${pL}" y="${y}" width="${cW}" height="${bh}" rx="2" fill="#e8eaed"/>`);
    $s.append(`<rect x="${pL}" y="${y}" width="${bw.toFixed(1)}" height="${bh}" rx="2" fill="${color}" opacity=".8"/>`);
    $s.append(`<text x="${(pL+bw+3).toFixed(1)}" y="${y+bh/2+3.5}" font-size="8" fill="#6b7785">${d.v}</text>`);
  });
}

function line(svgId, datasets, labels, W=252, H=116){
  const $s=$('#'+svgId); $s.empty();
  const pL=22,pB=18,pT=7; const cW=W-pL-6,cH=H-pB-pT;
  const n=labels.length;
  const maxV=Math.max(...datasets.flatMap(d=>d.vals),1);
  [0,.5,1].forEach(p=>{
    const y=pT+cH*(1-p);
    $s.append(`<line x1="${pL}" y1="${y}" x2="${W-4}" y2="${y}" stroke="#e8eaed" stroke-width="1"/>`);
    $s.append(`<text x="${pL-2}" y="${y+3}" font-size="7" fill="#9aa0a8" text-anchor="end">${Math.round(p*maxV)}</text>`);
  });
  labels.forEach((l,i)=>{
    const x=pL+i*(cW/(n-1));
    $s.append(`<text x="${x.toFixed(1)}" y="${H-2}" font-size="7" fill="#9aa0a8" text-anchor="middle">${l}</text>`);
  });
  datasets.forEach(ds=>{
    let pts=[];
    ds.vals.forEach((v,i)=>{const x=pL+i*(cW/(n-1));const y=pT+cH*(1-v/maxV);pts.push(`${x.toFixed(1)},${y.toFixed(1)}`);});
    $s.append(`<polyline points="${pts.join(' ')}" fill="none" stroke="${ds.c}" stroke-width="2" stroke-linejoin="round"/>`);
    ds.vals.forEach((v,i)=>{
      const x=pL+i*(cW/(n-1));const y=pT+cH*(1-v/maxV);
      $s.append(`<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="2.5" fill="${ds.c}" stroke="#fff" stroke-width="1.5"/>`);
      $s.append(`<text x="${x.toFixed(1)}" y="${(y-5).toFixed(1)}" font-size="7" fill="${ds.c}" text-anchor="middle">${v}</text>`);
    });
  });
}

function renderAuditeurCards(){
  const $grid=$('#w-auditeurs-grid');
  if(!$grid.length) return;
  $grid.empty();

  let _aud, _audits, _missions, _soc;
  try { _aud=AUDITEURS; _audits=AUDITS; _missions=GANTT_MISSIONS; _soc=SOCIETES; } catch(e){ return; }
  if(!_aud||!_audits) return;
  const statusGroups={
    inprogress:{label:'En cours',   color:'var(--accent)',  bg:'var(--accent-bg)'},
    open:      {label:'Ouverte',    color:'var(--accent)',  bg:'var(--accent-bg)'},
    planned:   {label:'Planifiée',  color:'var(--yellow)',  bg:'var(--yellow-bg)'},
    overdue:   {label:'En retard',  color:'var(--red)',     bg:'var(--red-bg)'},
    completed: {label:'Clôturée',   color:'var(--green)',   bg:'var(--green-bg)'},
    draft:     {label:'Brouillon',  color:'var(--text-muted)',bg:'var(--surface3)'},
  };

  _aud.forEach(aud=>{
    const fullName = `${aud.prenom} ${aud.nom}`;

    const myMissions = (_missions||[]).filter(m=>{
      if(m.chef===fullName) return true;
      return (m.tasks||[]).some(t=>
        (t.assignees||[]).includes(fullName) ||
        (t.subtasks||[]).some(st=>(st.assignees||[]).includes(fullName))
      );
    });

    const myMissionRefs = new Set(myMissions.map(m=>m.ref).filter(Boolean));
    const myAudits = _audits.filter(a=>
      (a.auditor===fullName) ||
      (Array.isArray(a.equipe) && a.equipe.indexOf(fullName)>=0) ||
      (!a.auditor && myMissionRefs.has(a.ref))
    );

    const counts={inprogress:0,planned:0,overdue:0,completed:0,open:0,draft:0};
    myAudits.forEach(a=>{ if(counts[a.status]!==undefined) counts[a.status]++; });

    const total = myAudits.length;
    const enCours = (counts.inprogress||0) + (counts.open||0);
    const cloture = counts.completed||0;
    const enRetard = counts.overdue||0;
    const planifie = counts.planned||0;

    const mEnCours = myMissions.filter(m=>m.progress>0 && m.progress<100).length;
    const mClos    = myMissions.filter(m=>m.progress>=100).length;
    const mPlan    = myMissions.filter(m=>m.progress===0).length;

    const col = avatarColor(aud.nom);
    const ini = initials(aud.prenom, aud.nom);

    const statMap={active:'Actif',inactive:'Inactif',leave:'En congé'};
    const statCls={active:'completed',inactive:'planned',leave:'medium'};

    const progPct = total>0 ? Math.round((cloture/total)*100) : 0;
    const progColor = progPct>=80?'var(--green)':progPct>=40?'var(--accent)':'var(--yellow)';

    const missionRows = myAudits.slice(0,4).map(a=>{
      const sg = statusGroups[a.status]||{label:a.status,color:'var(--text-muted)',bg:'var(--surface3)'};
      const logoUrl = getSocLogo ? getSocLogo(
        (()=>{ const _f=(_soc||[]).find(s=>s.nom===a.societe||s.nom.includes((a.societe||'').split(' ')[0])); return _f?socKey(_f):''; })()
      ) : null;
      const socIcon = logoUrl
        ? `<img src="${logoUrl}" style="width:16px;height:16px;object-fit:contain;border-radius:2px;flex-shrink:0;" title="${a.societe||''}" alt="Logo ${a.societe||''}">`
        : `<span style="font-size:10px;color:var(--text-dim);flex-shrink:0;" title="${a.societe||''}">🏢</span>`;
      const allCycles=[];
      if(a.cycle){ allCycles.push(a.cycle==='Autre (préciser)'&&a.cycle_custom ? a.cycle_custom : a.cycle); }
      (a.cycles_multi||[]).forEach(c=>{ if(c && allCycles.indexOf(c)<0) allCycles.push(c); });
      const cycleTxt = allCycles.length ? allCycles.join(', ') : '—';
      return `<div style="display:flex;align-items:center;gap:6px;padding:5px 0;border-bottom:1px solid var(--border);">
        <span style="font-family:var(--mono);font-size:10px;color:var(--accent);flex-shrink:0;min-width:84px;">${a.ref}</span>
        <span style="flex:1;min-width:0;font-size:10.5px;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${cycleTxt}">🔄 ${cycleTxt}</span>
        <div style="display:flex;align-items:center;gap:4px;flex-shrink:0;max-width:130px;">
          ${socIcon}
          <span style="font-size:10px;color:var(--text-muted);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">${a.societe||'—'}</span>
        </div>
        <span style="font-size:9.5px;font-weight:600;color:${sg.color};background:${sg.bg};padding:1px 6px;border-radius:3px;flex-shrink:0;">${sg.label}</span>
      </div>`;
    }).join('');

    const moreRow = myAudits.length>4
      ? `<div style="font-size:10.5px;color:var(--text-muted);padding:5px 0;text-align:center;">+ ${myAudits.length-4} autre(s) mission(s)</div>`
      : (myAudits.length===0 ? `<div style="font-size:11px;color:var(--text-dim);padding:8px 0;text-align:center;">Aucune mission assignée</div>` : '');

    $grid.append(`
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:6px;overflow:hidden;box-shadow:var(--shadow);display:flex;flex-direction:column;">

        <div style="display:flex;align-items:center;gap:10px;padding:10px 12px;background:var(--surface2);border-bottom:1px solid var(--border);">
          <div style="width:36px;height:36px;border-radius:50%;background:${col};display:grid;place-items:center;font-size:13px;font-weight:700;color:#fff;flex-shrink:0;">${ini}</div>
          <div style="flex:1;min-width:0;">
            <div style="font-size:13px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${fullName}</div>
            <div style="font-size:10.5px;color:var(--text-muted);">${aud.role||'—'}${(()=>{
              if(!aud.groupe) return '';
              const d=new Date(aud.groupe),now=new Date();
              if(isNaN(d)) return '';
              let ans=now.getFullYear()-d.getFullYear();
              let mois=now.getMonth()-d.getMonth();
              if(now.getDate()<d.getDate()) mois--;
              if(mois<0){ans--;mois+=12;}
              if(ans<0){ans=0;mois=Math.max(0,mois);}
              let label;
              if(ans===0&&mois===0)      label="< 1 mois d'ancienneté";
              else if(ans===0)           label=`${mois} mois d'ancienneté`;
              else if(mois===0)          label=`${ans} an${ans>1?'s':''} d'ancienneté`;
              else                       label=`${ans} an${ans>1?'s':''} ${mois} mois d'ancienneté`;
              return ' · ' + label;
            })()}</div>
          </div>
          <span class="badge ${statCls[aud.statut]||'planned'}" style="font-size:10px;flex-shrink:0;">${statMap[aud.statut]||aud.statut}</span>
        </div>

