          ${mPlan>0?`<span style="font-size:10px;color:var(--yellow);background:var(--yellow-bg);padding:1px 7px;border-radius:3px;">${mPlan} planifiée${mPlan>1?'s':''}</span>`:''}
          ${mClos>0?`<span style="font-size:10px;color:var(--green);background:var(--green-bg);padding:1px 7px;border-radius:3px;">${mClos} clôturée${mClos>1?'s':''}</span>`:''}
        </div>`:''}

        <div style="padding:7px 12px 5px;border-bottom:1px solid var(--border);">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px;">
            <span style="font-size:10px;color:var(--text-muted);">Taux de clôture</span>
            <span style="font-size:11px;font-weight:700;color:${progColor};font-family:var(--mono);">${progPct}%</span>
          </div>
          <div style="height:5px;background:var(--surface3);border-radius:3px;overflow:hidden;">

          </div>
        </div>

        <div style="padding:4px 12px 8px;flex:1;">
          ${missionRows}${moreRow}
        </div>

        <div style="padding:7px 12px;background:var(--surface2);border-top:1px solid var(--border);display:flex;gap:8px;align-items:center;flex-wrap:wrap;">
          ${aud.spec?`<span style="font-size:10px;color:var(--text-muted);">🎯 ${aud.spec}</span>`:''}
          ${aud.cert?`<span style="font-size:10px;font-family:var(--mono);color:var(--purple);background:var(--purple-bg);padding:1px 6px;border-radius:3px;">${aud.cert}</span>`:''}
          <button class="btn aud-assign-btn" data-fullname="${encodeURIComponent(fullName)}" style="margin-left:auto;font-size:10px;padding:3px 9px;" title="Affecter ${fullName} à une ou plusieurs missions">➕ Affecter à une mission</button>
        </div>

      </div>`);
  });
}

