$(document).on('click','.aud-assign-btn',function(e){
  e.stopPropagation();
  const fullName=decodeURIComponent($(this).data('fullname')||'');
  _audOpenAssignModal(fullName);
});

function _audOpenAssignModal(fullName){
  $('#aud-assign-title').text('➕ Affecter — '+fullName);
  const $list=$('#aud-assign-list').empty();
  const list=(typeof AUDITS!=='undefined'?AUDITS:[]);
  if(!list.length){ $list.html('<span style="font-size:10.5px;color:var(--text-dim);">Aucune mission enregistrée.</span>'); }
  list.forEach(function(a,i){
    const checked=(Array.isArray(a.equipe)&&a.equipe.indexOf(fullName)>=0)?' checked':'';
    const isLead=(a.auditor===fullName)?' <span style="font-size:9px;color:var(--accent);font-weight:600;">(déjà Chef de mission)</span>':'';
    $list.append('<label style="display:flex;align-items:flex-start;gap:6px;font-size:11px;cursor:pointer;padding:6px 2px;border-bottom:1px solid var(--border);">'
      +'<input type="checkbox" class="aud-assign-cb" data-idx="'+i+'"'+checked+' style="accent-color:var(--accent);margin-top:2px;"> '
      +'<span><strong style="color:var(--accent);">'+escHtml(a.ref||'')+'</strong> — '+escHtml(a.title||'')+isLead+'<br><span style="font-size:9.5px;color:var(--text-muted);">'+escHtml(a.societe||'')+'</span></span>'
      +'</label>');
  });
  $('#aud-assign-modal').data('fullname',fullName).css('display','flex');
}
$('#aud-assign-cancel').on('click',function(){ $('#aud-assign-modal').hide(); });
$('#aud-assign-modal').on('click',function(e){ if(e.target===this) $(this).hide(); });
$('#aud-assign-save').on('click',function(){
  const fullName=$('#aud-assign-modal').data('fullname');
  let nbAdd=0, nbRemove=0;
  document.querySelectorAll('.aud-assign-cb').forEach(function(cb){
    const idx=parseInt(cb.getAttribute('data-idx'),10);
    const a=(typeof AUDITS!=='undefined')?AUDITS[idx]:null; if(!a) return;
    if(!Array.isArray(a.equipe)) a.equipe=[];
    const has=a.equipe.indexOf(fullName)>=0;
    if(cb.checked && !has){ a.equipe.push(fullName); nbAdd++; }
    else if(!cb.checked && has){ a.equipe=a.equipe.filter(function(m){return m!==fullName;}); nbRemove++; }
  });
  dbSave();
  $('#aud-assign-modal').hide();
  if(isViewVisible('view-auditeurs')) tryRender(()=>renderAuditeurCards());
  if(isViewVisible('view-audits')) tryRender(()=>renderAudits());
  toast('success','👥',fullName+' : '+nbAdd+' mission(s) ajoutée(s), '+nbRemove+' retirée(s).');
});

/* ══════════════════════════════════════════════════════════════
   GESTION DES ABSENCES & CONGÉS — CALENDRIER & DISPONIBILITÉ
══════════════════════════════════════════════════════════════ */

const ABSENCE_TYPES = {
  conge:       {label:'Congé',        color:'#e67e22', bg:'rgba(230,126,34,.15)'},
  maladie:     {label:'Maladie',      color:'#ef4444', bg:'rgba(239,68,68,.15)'},
  formation:   {label:'Formation',    color:'#6941c6', bg:'rgba(105,65,198,.15)'},
  recuperation:{label:'Récupération', color:'#0891b2', bg:'rgba(8,145,178,.15)'},
};

const MONTHS_FR_FULL  = ['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
const MONTHS_FR_SHORT = ['Jan','Fév','Mar','Avr','Mai','Jun','Jul','Aoû','Sep','Oct','Nov','Déc'];
const DAYS_FR_SHORT   = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];

function datesBetween(d1Str, d2Str){
  const result=[];
  const d=new Date(d1Str); const end=new Date(d2Str);
  while(d<=end){result.push(d.toISOString().slice(0,10));d.setDate(d.getDate()+1);}
  return result;
}

/* ── Jours fériés Madagascar ─────────────────────────────────────────
   Fériés fixes (MM-DD) + Pâques et jours mobiles calculés par année  */
function feriesMadagascar(year){
  /* Calcul Pâques (algorithme de Butcher) */
  const a=year%19,b=Math.floor(year/100),c=year%100;
  const d=Math.floor(b/4),e=b%4,f=Math.floor((b+8)/25);
  const g=Math.floor((b-f+1)/3),h=(19*a+b-d-g+15)%30;
  const i=Math.floor(c/4),k=c%4,l=(32+2*e+2*i-h-k)%7;
  const m=Math.floor((a+11*h+22*l)/451);
  const month=Math.floor((h+l-7*m+114)/31);
  const day=((h+l-7*m+114)%31)+1;
  const paques=new Date(year,month-1,day);
  const addDays=(d,n)=>{const r=new Date(d);r.setDate(r.getDate()+n);return r.toISOString().slice(0,10);};
  const fmt=d=>`${year}-${String(d.getMonth()+1).padStart(2,'0')}-${String(d.getDate()).padStart(2,'0')}`;

  const fixes=[
    `${year}-01-01`, /* Nouvel An */
    `${year}-03-29`, /* Insurrection 1947 */
    `${year}-04-01`, /* Abolition de la royauté */
    `${year}-05-01`, /* Fête du Travail */
    `${year}-06-26`, /* Indépendance */
    `${year}-08-15`, /* Assomption */
    `${year}-11-01`, /* Toussaint */
    `${year}-12-25`, /* Noël */
  ];
  const mobiles=[
    addDays(paques,1),   /* Lundi de Pâques */
    addDays(paques,39),  /* Ascension */
    addDays(paques,49),  /* Pentecôte */
    addDays(paques,50),  /* Lundi de Pentecôte */
  ];
  return new Set([...fixes,...mobiles]);
}

/* Cache par année pour éviter de recalculer à chaque appel */
const _feriesCache={};
function isFerie(dateStr){
  const year=parseInt(dateStr.slice(0,4));
  if(!_feriesCache[year]) _feriesCache[year]=feriesMadagascar(year);
  return _feriesCache[year].has(dateStr);
}

function isJourOuvre(dateStr){
  const dow=new Date(dateStr).getDay();
  return dow!==0 && dow!==6 && !isFerie(dateStr);
}

function workdaysBetween(d1Str, d2Str){
  return datesBetween(d1Str,d2Str).filter(isJourOuvre).length;
}
function absenceFutureDays(abs){
  const today=new Date(); today.setHours(0,0,0,0);
  return datesBetween(abs.debut,abs.fin).filter(d=>new Date(d)>=today&&isJourOuvre(d)).length;
}
function detectAbsenceConflicts(abs){
  const absDays = new Set(datesBetween(abs.debut, abs.fin));
  const conflicts = [];
  GANTT_MISSIONS.forEach(m=>{
    const audName=abs.auditeur;
    const isChef=m.chef===audName;
    const inTask=(m.tasks||[]).some(t=>(t.assignees||[]).includes(audName)||(t.subtasks||[]).some(st=>(st.assignees||[]).includes(audName)));
    if(!isChef&&!inTask) return;
    if(!m.start||!m.end) return;
    const overlap=[...absDays].filter(d=>datesBetween(m.start,m.end).includes(d));
    if(overlap.length>0) conflicts.push({mission:m.title||m.id, jours:overlap.length, debut:overlap[0], fin:overlap[overlap.length-1]});
  });
  AUDITS.forEach(a=>{
    if(a.auditor!==abs.auditeur||!a.start||!a.end) return;
    const overlap=[...absDays].filter(d=>datesBetween(a.start,a.end).includes(d));
    if(overlap.length>0) conflicts.push({mission:(a.ref||'')+(a.title?' — '+a.title:''), jours:overlap.length, debut:overlap[0], fin:overlap[overlap.length-1]});
  });
  return conflicts;
}

function openAbsenceModal(idx){
  const isEdit=idx>=0;
  const a=isEdit?ABSENCES[idx]:{};
  const todayStr=new Date().toISOString().slice(0,10);
  const _SA2="url('data:image/svg+xml,%3Csvg xmlns=%22http://www.w3.org/2000/svg%22 width=%228%22 height=%225%22%3E%3Cpath d=%22M0 0l4 5 4-5z%22 fill=%22%236c7682%22/%3E%3C/svg%3E')";
  const audOptions=AUDITEURS.map(aud=>{const val=`${aud.prenom} ${aud.nom}`;return `<option value="${val}"${a.auditeur===val?' selected':''}>${val}</option>`;}).join('');
  const typeOptions=Object.entries(ABSENCE_TYPES).map(([k,v])=>`<option value="${k}"${(a.type||'conge')===k?' selected':''}>${v.label}</option>`).join('');
  const html=`
    <div class="fgrid">
      <div class="frow2" style="grid-column:1/-1"><div class="flbl2">Auditeur <span class="t-red">*</span></div>
        <select class="finp" id="ab-auditeur" style="appearance:none;background-image:${_SA2};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>${audOptions}
        </select></div>
      <div class="frow2"><div class="flbl2">Type d'absence <span class="t-red">*</span></div>
        <select class="finp" id="ab-type" style="appearance:none;background-image:${_SA2};background-repeat:no-repeat;background-position:right 8px center;">${typeOptions}</select></div>
      <div class="frow2"><div class="flbl2">Statut <span class="t-red">*</span></div>
        <select class="finp" id="ab-statut" style="appearance:none;background-image:${_SA2};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="planifie"${(a.statut||'planifie')==='planifie'?' selected':''}>🗓️ Planifié</option>
          <option value="valide"${(a.statut)==='valide'?' selected':''}>✅ Validé</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Date de début <span class="t-red">*</span></div>
        <input class="finp" id="ab-debut" type="date" value="${a.debut||todayStr}"></div>
      <div class="frow2"><div class="flbl2">Date de fin <span class="t-red">*</span></div>
        <input class="finp" id="ab-fin" type="date" value="${a.fin||todayStr}"></div>
      <div id="ab-heures-row" style="grid-column:1/-1;display:none;margin-top:2px;">
        <div class="fgrid">
          <div class="frow2"><div class="flbl2">⏰ Heure de début</div>
            <input class="finp" id="ab-hdebut" type="time" value="${a.hdebut||'08:00'}"></div>
          <div class="frow2"><div class="flbl2">⏰ Heure de fin</div>
            <input class="finp" id="ab-hfin" type="time" value="${a.hfin||'12:00'}"></div>
        </div>
        <div id="ab-duree-heures" style="font-size:11px;color:var(--accent);margin-top:6px;font-weight:600;padding:4px 8px;background:var(--accent-bg);border-radius:4px;display:none;"></div>
      </div>
    </div>
    <div class="frow2"><div class="flbl2">Motif / Remarque</div>
      <textarea class="finp" id="ab-note" rows="2" style="resize:vertical;">${a.note||''}</textarea></div>
    <div id="ab-conflict-preview" style="margin-top:8px;"></div>`;
  openModal(isEdit?"✏️ Modifier l'absence":"📅 Ajouter une Absence / Congé",html);
  $('#msave').text(isEdit?'Enregistrer':'Ajouter').data('mode','absence-save');

  function updateHeuresVisibility(){
    const deb=$('#ab-debut').val(),fin=$('#ab-fin').val();
    const same=deb&&fin&&deb===fin;
    $('#ab-heures-row').toggle(!!same);
    if(same){
      const hd=$('#ab-hdebut').val(),hf=$('#ab-hfin').val();
      if(hd&&hf){
        const [hh1,mm1]=hd.split(':').map(Number),[hh2,mm2]=hf.split(':').map(Number);
        const diff=(hh2*60+mm2)-(hh1*60+mm1);
        if(diff>0){
          const hh=Math.floor(diff/60),mm=diff%60;
          $('#ab-duree-heures').text(`⏱ Durée : ${hh>0?hh+'h':''}${mm>0?mm+'min':''}`).show();
        } else {
          $('#ab-duree-heures').text('⚠️ Heure de fin doit être après heure de début').show();
        }
      } else {$('#ab-duree-heures').hide();}
    }
  }
  $(document).on('change.abheures','#ab-debut,#ab-fin,#ab-hdebut,#ab-hfin',updateHeuresVisibility);
  updateHeuresVisibility();
  function previewConflicts(){
    const aud=$('#ab-auditeur').val(),deb=$('#ab-debut').val(),fin=$('#ab-fin').val();
    if(!aud||!deb||!fin||deb>fin){$('#ab-conflict-preview').empty();return;}
    const conflicts=detectAbsenceConflicts({auditeur:aud,debut:deb,fin:fin});
    const wdays=workdaysBetween(deb,fin);
    let h=`<div style="font-size:11px;color:var(--text-muted);background:var(--surface2);border:1px solid var(--border);border-radius:5px;padding:8px 12px;">`;
    h+=`<div style="margin-bottom:4px;font-weight:600;color:var(--text);">📊 ${wdays} jour(s) ouvrable(s) <span style="font-size:10px;font-weight:400;color:var(--text-muted);">(hors week-ends &amp; fériés MG)</span></div>`;
    if(conflicts.length){
      h+=`<div style="color:var(--red);font-weight:600;margin-bottom:4px;">⚠️ ${conflicts.length} conflit(s) avec des missions :</div>`;
      conflicts.forEach(c=>{h+=`<div style="padding:2px 0;border-bottom:1px solid var(--border);font-size:10.5px;">• <strong>${c.mission}</strong> — ${c.jours} j en commun (${c.debut}→${c.fin})</div>`;});
    } else {h+=`<div style="color:var(--green);">✅ Aucun conflit avec les missions planifiées</div>`;}
    h+=`</div>`;$('#ab-conflict-preview').html(h);
  }
  $(document).on('change.abpreview','#ab-auditeur,#ab-debut,#ab-fin',previewConflicts);
  previewConflicts();
  window._absenceSaveHandler=function(){
    const auditeur=$('#ab-auditeur').val().trim(),debut=$('#ab-debut').val(),fin=$('#ab-fin').val(),type=$('#ab-type').val();
    if(!auditeur){toast('error','!','Auditeur requis');return;}
    if(!debut||!fin){toast('error','!','Dates requises');return;}
    if(debut>fin){toast('error','!','La date de début doit être ≤ la date de fin');return;}
    const isIntraDay=debut===fin;
    const hdebut=isIntraDay?($('#ab-hdebut').val()||''):'' ;
    const hfin=isIntraDay?($('#ab-hfin').val()||''):'';
    if(isIntraDay&&hdebut&&hfin&&hdebut>=hfin){toast('error','!','L\'heure de début doit être < l\'heure de fin');return;}
    const obj={id:isEdit?a.id:('ABS-'+(Date.now()%1000000)),auditeur,debut,fin,hdebut,hfin,type,statut:$('#ab-statut').val(),note:$('#ab-note').val().trim()};
    $(document).off('change.abpreview');$(document).off('change.abheures');delete window._absenceSaveHandler;
    if(isEdit){Object.assign(ABSENCES[idx],obj);}else{ABSENCES.push(obj);}
    closeModal();renderAbsenceList();renderDispoTable();renderAuditeurCards();updateAbsenceBadge();
    dbSave();
    const nConf=detectAbsenceConflicts(obj).length;
    toast(nConf>0?'warning':'success',nConf>0?'⚠️':'✅',(isEdit?'Absence mise à jour':'Absence enregistrée')+(nConf>0?' — '+nConf+' conflit(s)':''));

  };
}

$(document).on('click','#btn-add-absence',function(){openAbsenceModal(-1);});
$(document).on('change','#absence-filter-aud',function(){renderAbsenceList();});

function renderAbsenceList(){

  const $faud=$('#absence-filter-aud'),curAud=$faud.val();
  $faud.find('option:not(:first-child)').remove();
  AUDITEURS.forEach(a=>{const v=`${a.prenom} ${a.nom}`;$faud.append(`<option value="${v}"${v===curAud?' selected':''}>${v}</option>`);});
  const filterAud=$faud.val()||'';
  const list=filterAud?ABSENCES.filter(a=>a.auditeur===filterAud):ABSENCES;
  const $tb=$('#absence-list-tbody').empty();
  if(!list.length){$('#absence-list-empty').show();return;}
  $('#absence-list-empty').hide();
  const today=new Date();today.setHours(0,0,0,0);
  list.forEach(ab=>{
    const realIdx=ABSENCES.indexOf(ab),tc=ABSENCE_TYPES[ab.type]||ABSENCE_TYPES.recuperation,wdays=workdaysBetween(ab.debut,ab.fin),conflicts=detectAbsenceConflicts(ab);
    const isPast=new Date(ab.fin)<today,isActive=new Date(ab.debut)<=today&&new Date(ab.fin)>=today;
    const statut=ab.statut||'planifie';
    const statutHtml=statut==='valide'
      ?`<span style="font-size:10px;background:#d1fae5;color:#059669;border-radius:4px;padding:2px 8px;font-weight:700;border:1px solid #a7f3d0;">✅ Validé</span>`
      :`<span style="font-size:10px;background:var(--yellow-bg);color:var(--yellow);border-radius:4px;padding:2px 8px;font-weight:700;border:1px solid var(--yellow);">🗓️ Planifié</span>`;
    let stateHtml=isPast?`<span style="font-size:9px;background:var(--surface3);color:var(--text-dim);border-radius:3px;padding:1px 5px;">Passée</span>`:isActive?`<span style="font-size:9px;background:#fff3e0;color:#e67e22;border-radius:3px;padding:1px 5px;font-weight:700;">En cours</span>`:`<span style="font-size:9px;background:var(--accent-bg);color:var(--accent);border-radius:3px;padding:1px 5px;font-weight:700;">À venir</span>`;

    let dureeTxt='';
    if(ab.debut===ab.fin&&ab.hdebut&&ab.hfin){
      const [hh1,mm1]=(ab.hdebut||'00:00').split(':').map(Number),[hh2,mm2]=(ab.hfin||'00:00').split(':').map(Number);
      const diff=(hh2*60+mm2)-(hh1*60+mm1);
      if(diff>0){const hh=Math.floor(diff/60),mm=diff%60;dureeTxt=`⏱ ${hh>0?hh+'h':''}${mm>0?(mm+'min'):''}`;}      else{dureeTxt='< 1h';}
    } else {dureeTxt=wdays+' j';}
    $tb.append(`<tr>
      <td style="font-weight:600;font-size:12px;">${ab.auditeur}</td>
      <td><span style="font-size:10px;font-weight:600;color:${tc.color};background:${tc.bg};padding:2px 7px;border-radius:10px;">${tc.label}</span>&nbsp;${stateHtml}</td>
      <td>${statutHtml}</td>
      <td style="font-family:var(--mono);font-size:11px;">${ab.debut}${ab.debut===ab.fin&&ab.hdebut?` <span style="color:var(--accent);font-size:10px;">${ab.hdebut}</span>`:''}</td>
      <td style="font-family:var(--mono);font-size:11px;">${ab.fin}${ab.debut===ab.fin&&ab.hfin?` <span style="color:var(--accent);font-size:10px;">${ab.hfin}</span>`:''}</td>
      <td style="font-family:var(--mono);font-size:11px;text-align:center;font-weight:700;">${dureeTxt}</td>
      <td style="font-size:11px;color:var(--text-muted);">${ab.note||'—'}</td>
      <td>${conflicts.length?`<span style="color:var(--red);font-size:10px;font-weight:700;">⚠️ ${conflicts.length} conflit(s)</span><br>`+conflicts.slice(0,2).map(c=>`<span style="font-size:9px;color:var(--text-muted);">• ${c.mission} (${c.jours}j)</span>`).join('<br>'):`<span style="color:var(--green);font-size:10px;">✅ Aucun</span>`}</td>
      <td style="white-space:nowrap;vertical-align:top;padding:5px 6px;">
        <div style="display:flex;flex-direction:column;gap:3px;align-items:stretch;">
          <button class="btn abs-edit-btn" data-absidx="${realIdx}" style="padding:2px 6px;font-size:10px;border-radius:4px;white-space:nowrap;">✏️ Modifier</button>
          <button class="btn abs-del-btn" data-absidx="${realIdx}" style="padding:2px 6px;font-size:10px;border-radius:4px;color:var(--red);border-color:var(--red);white-space:nowrap;">🗑️ Suppr.</button>
          <button class="btn abs-add-like-btn" data-auditeur="${ab.auditeur}" style="padding:2px 6px;font-size:10px;border-radius:4px;color:var(--green);border-color:var(--green);white-space:nowrap;" title="Ajouter une absence pour cet auditeur">＋ Ajouter</button>
        </div>
      </td>
    </tr>`);
  });
}
$(document).on('click','.abs-edit-btn',function(){openAbsenceModal(parseInt($(this).data('absidx')));});
$(document).on('click','.abs-del-btn',function(){
  const idx=parseInt($(this).data('absidx')),ab=ABSENCES[idx];if(!ab)return;
  if(!confirm(`Supprimer l'absence de ${ab.auditeur} (${ab.debut} → ${ab.fin}) ?`))return;
  ABSENCES.splice(idx,1);renderAbsenceList();renderDispoTable();renderAuditeurCards();updateAbsenceBadge();dbSave();
  toast('success','🗑','Absence supprimée');
});

$(document).on('click','.abs-add-like-btn',function(){
  const auditeur=$(this).data('auditeur');
  openAbsenceModal(-1);

  setTimeout(()=>{ $('#ab-auditeur').val(auditeur).trigger('change'); },50);
});

function renderDispoTable(){
  const $tb=$('#dispo-tbody').empty();
  const today=new Date();today.setHours(0,0,0,0);

  const $faud=$('#dispo-filter-aud');
  const curAud=$faud.val()||'';
  $faud.find('option:not(:first-child)').remove();
  AUDITEURS.forEach(a=>{const v=`${a.prenom} ${a.nom}`;$faud.append(`<option value="${v}"${v===curAud?' selected':''}>${v}</option>`);});

  const filterAud=curAud;
  const audsToRender=filterAud?AUDITEURS.filter(a=>`${a.prenom} ${a.nom}`===filterAud):AUDITEURS;

  const statMap={active:'Actif',inactive:'Inactif',leave:'En congé'};
  const statCls={active:'completed',inactive:'planned',leave:'medium'};

  let totalConflictsAll=0;

  audsToRender.forEach(aud=>{
    const fullName=`${aud.prenom} ${aud.nom}`;
    const myMissions=(GANTT_MISSIONS||[]).filter(m=>{
      const st=m.status||'planned';if(st!=='inprogress'&&st!=='planned'&&st!=='open')return false;
      return m.chef===fullName||(m.tasks||[]).some(t=>(t.assignees||[]).includes(fullName)||(t.subtasks||[]).some(st=>(st.assignees||[]).includes(fullName)));
    });
    const myAuditsActive=(AUDITS||[]).filter(a=>a.auditor===fullName&&(a.status==='inprogress'||a.status==='planned'||a.status==='open'));
    const totalActive=myMissions.length+myAuditsActive.length;
    const myAbsFutur=ABSENCES.filter(a=>a.auditeur===fullName&&new Date(a.fin)>=today);
    const myAbsAll=ABSENCES.filter(a=>a.auditeur===fullName);
    const todayStr3=today.toISOString().slice(0,10);
    const absAujourd3=ABSENCES.find(a=>a.auditeur===fullName&&a.debut<=todayStr3&&a.fin>=todayStr3);
    const statutCard=absAujourd3?'leave':(aud.statut||'active');
    const totalAbsJours=myAbsFutur.reduce((s,a)=>s+absenceFutureDays(a),0);
    let totalConflicts=0; myAbsFutur.forEach(ab=>{totalConflicts+=detectAbsenceConflicts(ab).length;});
    totalConflictsAll+=totalConflicts;

    const todayStr2=new Date().toISOString().slice(0,10);
    const absAujourd=ABSENCES.find(ab=>ab.auditeur===fullName&&ab.debut<=todayStr2&&ab.fin>=todayStr2);
    const statutEffectif=absAujourd?'leave':(aud.statut||'active');
    let dispoLabel,dispoBg,dispoColor;
    if(statutEffectif==='leave'){dispoLabel=absAujourd?(ABSENCE_TYPES[absAujourd.type]||{label:'En congé'}).label:'En congé';dispoColor='#e67e22';dispoBg='#fff3e0';}
    else if(statutEffectif==='inactive'){dispoLabel='Inactif';dispoColor='var(--text-dim)';dispoBg='var(--surface3)';}
    else if(totalConflicts>0){dispoLabel='Conflit(s)';dispoColor='var(--red)';dispoBg='var(--red-bg)';}
    else if(totalActive>=3){dispoLabel='Chargé';dispoColor='var(--yellow)';dispoBg='var(--yellow-bg)';}
    else if(totalAbsJours>0&&totalActive>0){dispoLabel='Partiellement dispo';dispoColor='#e67e22';dispoBg='#fff3e0';}
    else if(totalActive>0){dispoLabel='En mission';dispoColor='var(--accent)';dispoBg='var(--accent-bg)';}
    else{dispoLabel='Disponible';dispoColor='var(--green)';dispoBg='var(--green-bg)';}

    const absHtml=myAbsFutur.length
      ? myAbsFutur.map(ab=>{
          const tc=ABSENCE_TYPES[ab.type]||ABSENCE_TYPES.recuperation,jrs=absenceFutureDays(ab);
          return `<div style="margin-bottom:2px;"><span style="font-size:9px;font-weight:600;background:${tc.bg};color:${tc.color};border-radius:3px;padding:1px 6px;display:inline-block;">${tc.label}</span> <span style="font-size:9px;color:var(--text-muted);font-family:var(--mono);">${ab.debut} → ${ab.fin}</span> <span style="font-size:9px;font-weight:700;color:${tc.color};">(${jrs}j)</span></div>`;
        }).join('')
      : `<span style="font-size:10px;color:var(--text-dim);">—</span>`;

    /* Missions actives */
    const allActive=[...myMissions,...myAuditsActive.map(a=>({title:a.title||a.ref,status:a.status}))];
    const missionHtml=allActive.length
      ? allActive.slice(0,3).map(m=>`<span style="font-size:9px;background:var(--accent-bg);color:var(--accent);border-radius:3px;padding:1px 5px;margin:1px;display:inline-block;border:1px solid rgba(0,112,242,.15);">${m.title||'Mission'}</span>`).join('')+(totalActive>3?`<span style="font-size:9px;color:var(--text-muted);margin-left:2px;">+${totalActive-3}</span>`:'')
      : `<span style="font-size:10px;color:var(--text-dim);">—</span>`;

    /* Total absences (historique) pour mini badge */
    const histBadge=myAbsAll.length>0
      ? `<span style="font-size:9px;background:var(--surface3);color:var(--text-muted);border-radius:3px;padding:1px 5px;margin-left:6px;">${myAbsAll.length} abs. total</span>`
      : '';

    const audNameEsc=fullName.replace(/'/g,"\\'");

    $tb.append(`<tr>
      <td>
        <div style="font-weight:700;font-size:12px;">${fullName}</div>
        <div style="font-size:10px;color:var(--text-muted);">${aud.role||'—'}</div>
      </td>
      <td><span class="badge ${statCls[statutEffectif]||'planned'}" style="font-size:10px;" title="${absAujourd?'Absence en cours : '+absAujourd.debut+' → '+absAujourd.fin:''}">${statMap[statutEffectif]||statutEffectif}${absAujourd?' 🏖️':''}</span></td>
      <td>${missionHtml}</td>
      <td>${absHtml}</td>
      <td class="t-center">
        ${totalConflicts>0
          ? `<span style="font-size:11px;font-weight:700;color:var(--red);">⚠️ ${totalConflicts}</span>`
          : `<span style="font-size:10px;color:var(--green);">✅ 0</span>`}
      </td>
      <td>
        <span style="font-size:10px;font-weight:700;color:${dispoColor};background:${dispoBg};padding:3px 9px;border-radius:10px;display:inline-block;">${dispoLabel}</span>
        ${histBadge}
      </td>
      <td style="white-space:nowrap;vertical-align:top;padding:5px 6px;">
        <div style="display:flex;flex-direction:column;gap:3px;align-items:stretch;">
          <button class="btn dispo-edit-btn" data-aud="${audNameEsc}" style="padding:2px 6px;font-size:10px;border-radius:4px;white-space:nowrap;" title="Modifier la prochaine absence">✏️ Modifier</button>
          <button class="btn dispo-del-btn"  data-aud="${audNameEsc}" style="padding:2px 6px;font-size:10px;border-radius:4px;color:var(--red);border-color:var(--red);white-space:nowrap;" title="Supprimer la prochaine absence">🗑️ Suppr.</button>
          <button class="btn abs-quick-add"  data-aud="${audNameEsc}" style="padding:2px 6px;font-size:10px;border-radius:4px;color:var(--green);border-color:var(--green);white-space:nowrap;" title="Ajouter une absence pour cet auditeur">＋ Ajouter</button>
        </div>
      </td>
    </tr>`);
  });

  if(!AUDITEURS.length){
    $tb.html('<tr><td colspan="7" class="nodata">Aucun auditeur enregistré.</td></tr>');
  } else if(!audsToRender.length){
    $tb.html('<tr><td colspan="7" class="nodata">Aucun auditeur trouvé.</td></tr>');
  }
}
$(document).on('click','.abs-quick-add',function(){
  const aud=$(this).data('aud');
  openAbsenceModal(-1);
  setTimeout(()=>$('#ab-auditeur').val(aud).trigger('change'),50);
});

$(document).on('click','.dispo-edit-btn',function(){
  const aud=$(this).data('aud');
  const today=new Date();today.setHours(0,0,0,0);
  const idx=ABSENCES.findIndex(a=>a.auditeur===aud&&new Date(a.fin)>=today);
  if(idx<0){toast('info','ℹ️','Aucune absence à venir pour '+aud);return;}
  openAbsenceModal(idx);
});

$(document).on('click','.dispo-del-btn',function(){
  const aud=$(this).data('aud');
  const today=new Date();today.setHours(0,0,0,0);
  const idx=ABSENCES.findIndex(a=>a.auditeur===aud&&new Date(a.fin)>=today);
  if(idx<0){toast('info','ℹ️','Aucune absence à venir pour '+aud);return;}
  const ab=ABSENCES[idx];
  if(!confirm(`Supprimer l'absence de ${ab.auditeur} (${ab.debut} → ${ab.fin}) ?`))return;
  ABSENCES.splice(idx,1);renderAbsenceList();renderDispoTable();renderAuditeurCards();updateAbsenceBadge();dbSave();
  toast('success','🗑','Absence supprimée');
});

/* ── Badge nav absences ── */
function updateAbsenceBadge(){
  const today=new Date(); today.setHours(0,0,0,0);
  const futur=ABSENCES.filter(a=>new Date(a.fin)>=today).length;
  $('#nb-absences').text(futur||ABSENCES.length);
}

/* ── Filtre disponibilité ── */
$(document).on('change','#dispo-filter-aud',function(){renderDispoTable();});

// ── RENDER SOCIETES VIEW ──────────────────────────────────────
function renderSocietesView(){
  SOCIETES.forEach((s,i)=>{ if(!s._uid) s._uid='soc_'+i+'_'+Date.now()+'_'+Math.random().toString(36).slice(2,7); });
  let _soc, _audits, _actions;
  try{ _soc=SOCIETES; _audits=AUDITS; _actions=ACTIONS; }catch(e){ return; }
  if(!_soc) return;

  const filter=$('#soc-view-filter').val()||'all';
  const q=($('#soc-view-search').val()||'').toLowerCase();

  // ── Global KPI bar ──
  const totalAudits=_audits.length;
  const planif=_audits.filter(a=>a.status==='planned').length;
  const ouverte=_audits.filter(a=>a.status==='open').length;
  const enCours=_audits.filter(a=>a.status==='inprogress').length;
  const clos=_audits.filter(a=>a.status==='completed').length;
  const retard=_audits.filter(a=>a.status==='overdue').length;

  const kpiItems=[
    {label:'Audits total',val:totalAudits,color:'var(--accent)',bg:'var(--accent-bg)',icon:'◈'},
    {label:'Planifiées',val:planif,color:'var(--text-muted)',bg:'var(--surface3)',icon:'📅'},
    {label:'Ouvertes',val:ouverte,color:'var(--accent)',bg:'var(--accent-bg)',icon:'📂'},
    {label:'En cours',val:enCours,color:'var(--purple)',bg:'var(--purple-bg)',icon:'▶'},
    {label:'Clôturées',val:clos,color:'var(--green)',bg:'var(--green-bg)',icon:'✓'},
    {label:'En retard',val:retard,color:'var(--red)',bg:'var(--red-bg)',icon:'⚠'},
  ];
  $('#soc-kpi-bar').html(kpiItems.map(k=>`
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:12px 14px;display:flex;align-items:center;gap:10px;box-shadow:var(--shadow);">
      <div style="width:36px;height:36px;border-radius:8px;background:${k.bg};display:grid;place-items:center;font-size:16px;flex-shrink:0;">${k.icon}</div>
      <div>
        <div style="font-size:22px;font-weight:800;color:${k.color};font-family:var(--mono);line-height:1;">${k.val}</div>
        <div style="font-size:10.5px;color:var(--text-muted);margin-top:2px;">${k.label}</div>
      </div>
    </div>`).join(''));

  // ── Society cards ──
  let societies = _soc.filter(s=>{
    if(filter!=='all' && s.secteur!==filter) return false;
    if(q && !(`${s.nom} ${s.code} ${s.secteur} ${s.pays}`.toLowerCase().includes(q))) return false;
    return true;
  });

  const $grid=$('#soc-view-grid').empty();
  if(!societies.length){
    $grid.html('<div style="grid-column:1/-1;padding:40px;text-align:center;color:var(--text-dim);font-size:13px;">Aucune société correspond aux filtres.</div>');
    return;
  }

  const statusGroups={
    planned:{label:'Planifiée',color:'var(--text-muted)',bg:'var(--surface3)'},
    open:{label:'Ouverte',color:'var(--accent)',bg:'var(--accent-bg)'},
    inprogress:{label:'En cours',color:'var(--purple)',bg:'var(--purple-bg)'},
    completed:{label:'Clôturée',color:'var(--green)',bg:'var(--green-bg)'},
    overdue:{label:'En retard',color:'var(--red)',bg:'var(--red-bg)'},
    draft:{label:'Brouillon',color:'var(--text-muted)',bg:'var(--surface3)'},
  };
  const secteurColors={'Finance':'#0070f2','Technologie':'#6941c6','Industrie':'#c05c00','Commerce':'#1a8a4a','Services':'#007d8c','Santé':'#bb2222','Énergie':'#c47d00'};
  const statutBadge={active:{cls:'completed',lbl:'Active'},inactive:{cls:'planned',lbl:'Inactive'},suspended:{cls:'overdue',lbl:'Suspendue'}};

  societies.forEach(soc=>{
    const myAudits = _audits.filter(a => a.societe === soc.nom);
    // fallback: match by group
    const myAuditsFull = myAudits.length>0 ? myAudits : _audits.filter(a=>a.group===soc.groupe);

    const aOuverte = myAuditsFull.filter(a=>a.status==='open').length;
    const aEnCours = myAuditsFull.filter(a=>a.status==='inprogress').length;
    const aClos    = myAuditsFull.filter(a=>a.status==='completed').length;
    const aPlanif  = myAuditsFull.filter(a=>a.status==='planned').length;
    const aRetard  = myAuditsFull.filter(a=>a.status==='overdue').length;
    const aTotal   = myAuditsFull.length;

    // ── Stats issues de Suivi des Recommandations (ACTIONS) ──
    const _socNom = (soc.nom||'').trim().toLowerCase();
    const mySuivi = _actions.filter(a => (a.societe||'').trim().toLowerCase() === _socNom);
    const today_s = new Date(); today_s.setHours(0,0,0,0);

    // Risque : criticité la plus élevée parmi les constats de cette société
    const criticiteRank = {critical:4, high:3, medium:2, low:1};
    let maxCriticite = 0;
    mySuivi.forEach(a => { maxCriticite = Math.max(maxCriticite, criticiteRank[a.criticite]||0); });
    const riskLabel = maxCriticite>=4 ? {l:'Critical', c:'var(--red)',    bg:'var(--red-bg)'}
                    : maxCriticite>=3 ? {l:'Élevé',    c:'var(--orange)', bg:'var(--orange-bg)'}
                    : maxCriticite>=2 ? {l:'Moyen',    c:'var(--yellow)', bg:'var(--yellow-bg)'}
                    : maxCriticite>=1 ? {l:'Faible',   c:'var(--green)',  bg:'var(--green-bg)'}
                    :                   {l:'—',         c:'var(--text-muted)', bg:'var(--surface3)'};

    // Constats : nombre total de recommandations de cette société
    let nbConstats = 0;
    mySuivi.forEach(a => { nbConstats += (a.recommandations||[]).length; });

    // Actions — nombre de jours max de retard sur les recommandations non-fully
    let maxRetardJours = 0;
    mySuivi.forEach(a => {
      (a.recommandations||[]).forEach(r => {
        if(computeStatutEffectif(r, today_s)==='fully') return;
        if(r.echeance){
          const du=new Date(r.echeance);
          if(!isNaN(du) && du<today_s){
            const jours=Math.floor((today_s-du)/(1000*60*60*24));
            if(jours>maxRetardJours) maxRetardJours=jours;
          }
        }
      });
    });

    // Clôture : nombre de recommandations "Fully Implemented" (statut effectif, comme dans Suivi)
    let nbFully = 0;
    mySuivi.forEach(a => {
      (a.recommandations||[]).forEach(r => { if(computeStatutEffectif(r, today_s)==='fully') nbFully++; });
    });

    // Completion rate (audits) — gardé pour la barre de progression
    const compPct = aTotal>0 ? Math.round((aClos/aTotal)*100) : 0;
    const compColor = compPct>=80?'var(--green)':compPct>=40?'var(--accent)':'var(--yellow)';

    const sectColor = secteurColors[soc.secteur]||'var(--accent)';
    const sb = statutBadge[soc.statut]||{cls:'planned',lbl:soc.statut};

    // Recent audits list
    const recentRows = myAuditsFull.slice(0,3).map(a=>{
      const sg=statusGroups[a.status]||{label:a.status,color:'var(--text-muted)',bg:'var(--surface3)'};
      const globalIdx = AUDITS.indexOf(a);
      return `<div style="padding:4px 0;border-bottom:1px solid var(--border);">
        <div style="display:flex;align-items:center;gap:6px;">
          <span style="font-family:var(--mono);font-size:10px;color:var(--accent);flex-shrink:0;min-width:86px;">${a.ref}</span>
          <span style="flex:1;font-size:11px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${a.title}">${a.title}</span>
          <span style="font-size:9.5px;font-weight:600;color:${sg.color};background:${sg.bg};padding:1px 5px;border-radius:3px;flex-shrink:0;">${sg.label}</span>
        </div>
        <div style="display:flex;gap:4px;margin-top:3px;padding-left:2px;flex-wrap:wrap;">
          <button class="soc-row-print-tdr-btn" data-idx="${globalIdx}" style="font-size:9px;padding:1px 6px;border:1px solid var(--border);border-radius:3px;background:var(--surface);color:var(--text-muted);cursor:pointer;" title="Imprimer les Termes de Référence (TDR) de ${a.ref}">📄 TDR</button>
          <button class="soc-row-print-ra-btn" data-idx="${globalIdx}" style="font-size:9px;padding:1px 6px;border:1px solid var(--border);border-radius:3px;background:var(--surface);color:var(--text-muted);cursor:pointer;" title="Imprimer le Rapport d'Audit de ${a.ref}">📑 Rapport d'Audit</button>
          <button class="soc-row-print-rr-btn" data-soc="${encodeURIComponent(soc.nom)}" style="font-size:9px;padding:1px 6px;border:1px solid var(--border);border-radius:3px;background:var(--surface);color:var(--text-muted);cursor:pointer;" title="Imprimer le Récapitulatif des Recommandations de ${soc.nom}">📊 Récap. Reco.</button>
        </div>
      </div>`;
    }).join('');

    const moreRow = myAuditsFull.length>3
      ? `<div style="font-size:10.5px;color:var(--text-muted);padding:4px 0;text-align:center;">+ ${myAuditsFull.length-3} autre(s)</div>` : '';
    const emptyRow = myAuditsFull.length===0
      ? `<div style="font-size:11px;color:var(--text-dim);padding:8px 0;text-align:center;">Aucun audit lié</div>` : '';

    const logoUrl = getSocLogo(socKey(soc));
    const logoHtml = logoUrl
      ? `<div style="width:38px;height:38px;border-radius:8px;background:#fff;border:1px solid var(--border);overflow:hidden;flex-shrink:0;display:flex;align-items:center;justify-content:center;position:relative;">
           <img src="${logoUrl}" style="max-width:36px;max-height:36px;object-fit:contain;" alt="${soc.nom}">
         </div>`
      : `<div style="width:38px;height:38px;border-radius:8px;background:${sectColor};display:grid;place-items:center;font-size:17px;flex-shrink:0;">🏢</div>`;

    $grid.append(`
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:6px;overflow:hidden;box-shadow:var(--shadow);display:flex;flex-direction:column;">

        <div style="padding:11px 13px;background:var(--surface2);border-bottom:1px solid var(--border);display:flex;align-items:flex-start;gap:10px;">
          ${logoHtml}
          <div style="flex:1;min-width:0;">
            <div style="font-size:13px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${soc.nom}</div>
            <div style="display:flex;gap:6px;align-items:center;margin-top:2px;flex-wrap:wrap;">
              <span style="font-family:var(--mono);font-size:10px;color:var(--text-dim);">${soc.code||'—'}</span>
              <span style="font-size:10px;color:${sectColor};background:rgba(0,0,0,.05);padding:1px 6px;border-radius:3px;font-weight:600;">${soc.secteur||'—'}</span>
              <span style="font-size:10px;color:var(--text-muted);">📍 ${soc.pays||'—'}</span>
            </div>
          </div>
          <div style="display:flex;flex-direction:column;align-items:flex-end;gap:4px;">
            <span class="badge ${sb.cls}" style="font-size:10px;">${sb.lbl}</span>
