/* ── Impression ciblée par société (carte Tableau de bord Sociétés) ── */
/* Retourne TOUS les index (dans AUDITS) des missions liées à une société donnée */
function _socFindAuditIdxs(socNom){
  if(!AUDITS || !AUDITS.length || !socNom) return [];
  const nomLc = socNom.trim().toLowerCase();
  let idxs = AUDITS.reduce(function(acc,a,i){ if((a.societe||'').trim().toLowerCase()===nomLc) acc.push(i); return acc; },[]);
  if(!idxs.length){
    // Repli : correspondance via le groupe de la société
    const soc = (SOCIETES||[]).find(s=>(s.nom||'').trim().toLowerCase()===nomLc);
    if(soc && soc.groupe) idxs = AUDITS.reduce(function(acc,a,i){ if(a.group===soc.groupe) acc.push(i); return acc; },[]);
  }
  return idxs;
}

const _socMissionStatusLabel={planned:'Planifiée',open:'Ouverte',inprogress:'En cours',completed:'Clôturée',overdue:'En retard',draft:'Brouillon'};

/* Ouvre la popup de sélection de mission quand une société en a plusieurs ; appelle onPick(idx) au choix */
function _socOpenMissionPicker(socNom, idxs, onPick){
  $('#soc-mp-title').text('Sélectionner une mission — '+socNom);
  const $list=$('#soc-mp-list').empty();
  idxs.forEach(function(i){
    const a=AUDITS[i]||{};
    const stLbl=_socMissionStatusLabel[a.status]||a.status||'—';
    $list.append(
      '<button class="btn soc-mp-item" data-idx="'+i+'" style="text-align:left;font-size:11.5px;padding:8px 10px;display:flex;flex-direction:column;gap:2px;">'+
        '<span style="font-weight:700;color:var(--accent);">'+(a.ref||'—')+'</span>'+
        '<span style="color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;">'+(a.title||'')+'</span>'+
        '<span style="font-size:10px;color:var(--text-muted);">'+stLbl+(a.dateDebut?' · '+a.dateDebut:'')+'</span>'+
      '</button>'
    );
  });
  $('#soc-mission-picker-modal').data('onpick', onPick).css('display','flex');
}
$(document).on('click','.soc-mp-item',function(){
  const idx=parseInt($(this).data('idx'),10);
  const cb=$('#soc-mission-picker-modal').data('onpick');
  $('#soc-mission-picker-modal').hide();
  if(typeof cb==='function') cb(idx);
});
$(document).on('click','#soc-mp-cancel',function(){ $('#soc-mission-picker-modal').hide(); });
$(document).on('click','#soc-mission-picker-modal',function(e){ if(e.target===this) $(this).hide(); });

function _socPrintTDRForAudit(idx){
  showView('rapport-rcm');
  setTimeout(function(){
    $('#rrcm-audit-select').val(String(idx));
    $('#rrcm-audit-load-btn').trigger('click');
    setTimeout(function(){ $('#rrcm-print-btn').trigger('click'); }, 250);
  }, 100);
}

function _socPrintRAForAudit(idx){
  showView('rapport-audit');
  setTimeout(function(){
    $('#ra-select-audit').val(String(idx)).trigger('change');
    setTimeout(function(){ $('#ra-print-btn').trigger('click'); }, 250);
  }, 100);
}

function _socPrintRRForSociete(socNom){
  showView('recap-reco');
  setTimeout(function(){
    const $sel=$('#rr-filter-societe');
    if($sel.find('option[value="'+socNom.replace(/"/g,'\\"')+'"]').length===0){
      $sel.append('<option value="'+socNom+'">'+socNom+'</option>');
    }
    $sel.val(socNom).trigger('change');
    setTimeout(function(){ $('#rr-print-btn').trigger('click'); }, 250);
  }, 100);
}

$(document).on('click','.soc-print-tdr-btn',function(e){
  e.stopPropagation();
  const socNom = decodeURIComponent($(this).data('soc')||'');
  const idxs = _socFindAuditIdxs(socNom);
  if(!idxs.length){ toast('error','!','Aucune mission liée à « '+socNom+' » pour générer les Termes de Référence.'); return; }
  if(idxs.length===1) _socPrintTDRForAudit(idxs[0]);
  else _socOpenMissionPicker(socNom, idxs, _socPrintTDRForAudit);
});

$(document).on('click','.soc-print-ra-btn',function(e){
  e.stopPropagation();
  const socNom = decodeURIComponent($(this).data('soc')||'');
  const idxs = _socFindAuditIdxs(socNom);
  if(!idxs.length){ toast('error','!','Aucune mission liée à « '+socNom+' » pour générer le Rapport d\'Audit.'); return; }
  if(idxs.length===1) _socPrintRAForAudit(idxs[0]);
  else _socOpenMissionPicker(socNom, idxs, _socPrintRAForAudit);
});

$(document).on('click','.soc-print-rr-btn',function(e){
  e.stopPropagation();
  const socNom = decodeURIComponent($(this).data('soc')||'');
