$(document).on('click','#soc-debug-btn',function(){
  const socNoms = SOCIETES.map(s=>s.nom);
  const actSocs = [...new Set(ACTIONS.map(a=>a.societe||'(vide)'))];
  const matched = actSocs.filter(n => socNoms.some(s=>s.trim().toLowerCase()===n.trim().toLowerCase()));
  const unmatched = actSocs.filter(n => !socNoms.some(s=>s.trim().toLowerCase()===n.trim().toLowerCase()));
  let msg = '=== SOCIETES ===\n'+socNoms.join('\n');
  msg += '\n\n=== ACTIONS.societe ===\n'+actSocs.join('\n');
  msg += '\n\n=== CORRESPONDANCES OK ===\n'+(matched.join('\n')||'aucune');
  msg += '\n\n=== SANS CORRESPONDANCE ===\n'+(unmatched.join('\n')||'aucune');
  alert(msg);
  $('#soc-debug-out').text('Sociétés:'+socNoms.length+' | Actions sociétés:'+actSocs.length+' | Matches:'+matched.length+' | Sans match:'+unmatched.length);
});
