let SOC_LOGOS = (()=>{
  try{ const s=localStorage.getItem('audit_soc_logos'); return s?JSON.parse(s):{};} catch(e){return {};}
})();
function saveSocLogos(){ try{localStorage.setItem('audit_soc_logos',JSON.stringify(SOC_LOGOS));}catch(e){} }
/* Clé de logo : utilise _uid de la société (unique), sinon fallback sur code */
function socLogoKey(codeOrUid){ return codeOrUid||''; }
function getSocLogo(codeOrUid){ const e=SOC_LOGOS[socLogoKey(codeOrUid)]; if(!e) return null; return typeof e==='string'?e:(e.orig||null); }
function getSocLogoThumb(codeOrUid){ const e=SOC_LOGOS[socLogoKey(codeOrUid)]; if(!e) return null; return typeof e==='string'?e:(e.thumb||e.orig||null); }
function setSocLogo(codeOrUid,dataUrl,thumbUrl){ if(!codeOrUid) return; SOC_LOGOS[socLogoKey(codeOrUid)]={orig:dataUrl, thumb:thumbUrl||dataUrl}; saveSocLogos(); }
function delSocLogo(codeOrUid){ delete SOC_LOGOS[socLogoKey(codeOrUid)]; saveSocLogos(); }
/* Retourne la clé unique d'une société : _uid si dispo, sinon code, sinon nom */
function socKey(s){ return s._uid || s.code || s.nom || ''; }

$(document).on('click','.soc-logo-upload-btn',function(){
  const code=$(this).data('uid')||$(this).data('code');
  const $inp=$('<input type="file" accept="image/jpeg,image/png,.jpg,.png" style="display:none">');
  $('body').append($inp);
  $inp.trigger('click');
  $inp.on('change',function(){
    const file=this.files[0];
    if(!file) return;
    if(!file.type.match(/image\/(jpe?g|png)/i)){ toast('error','!','Seuls les fichiers JPG et PNG sont acceptés'); $inp.remove(); return; }
    if(file.size>3*1024*1024){ toast('error','!','Image trop lourde (max 3 Mo)'); $inp.remove(); return; }
    const reader=new FileReader();
    reader.onload=function(ev){
      const original=ev.target.result;
      const img=new Image();
      img.onload=function(){
        const canvas=document.createElement('canvas');
        const MAX=80; let w=img.width,h=img.height;
        if(w>h){ h=Math.round(h*MAX/w); w=MAX; } else { w=Math.round(w*MAX/h); h=MAX; }
        canvas.width=w; canvas.height=h;
        canvas.getContext('2d').drawImage(img,0,0,w,h);
        const thumb=canvas.toDataURL('image/jpeg',0.85);
        setSocLogo(code, original, thumb);
        toast('success','🖼','Logo mis à jour');
        tryRender(()=>renderSocietesView());
      };
      img.src=original;
    };
    reader.readAsDataURL(file);
    $inp.remove();
  });
});

$(document).on('click','.soc-logo-del-btn',function(e){
  e.stopPropagation();
  const code=$(this).data('uid')||$(this).data('code');
  delSocLogo(code);
  toast('info','✕','Logo supprimé');
  tryRender(()=>renderSocietesView())
});

