  vbar('w3b',[{label:'Planning',vals:[2,1]},{label:'Fieldwork',vals:[3,2]},{label:'Execution',vals:[1,2]},{label:'Reporting',vals:[2,1]}],['#e67e22','#f39c12'],252,126);
  $('#w3lg').html(`<div class="litem">Assurance</div><div class="litem">Conformité</div>`);

