  (function(){
    try{ if(!GANTT_MISSIONS || !AUDITS) return; }catch(e){ return; }
    const today = new Date();
    const quarters = [];
    const labels = [];

    for(let i=7;i>=0;i--){
      const d = new Date(today.getFullYear(), today.getMonth() - i*3, 1);
      const q = Math.floor(d.getMonth()/3)+1;
      labels.push(`Q${q}'${String(d.getFullYear()).slice(2)}`);
      quarters.push({year:d.getFullYear(), q});
    }
    const vals = quarters.map(({year,q})=>{
      return GANTT_MISSIONS.filter(m=>{
        if((m.status||'planned')!=='completed') return false;
        const d = m.end ? new Date(m.end) : null;
        if(!d||isNaN(d)) return false;
        return d.getFullYear()===year && Math.floor(d.getMonth()/3)+1===q;
      }).length;
    });

    const vals2 = quarters.map(({year,q},qi)=>{
      return AUDITS.filter(a=>{
        if(a.status!=='completed') return false;
        const d = a.end ? new Date(a.end) : null;
        if(!d||isNaN(d)) return false;
        return d.getFullYear()===year && Math.floor(d.getMonth()/3)+1===q;
      }).length + vals[qi];
    });

    const totalClosed = GANTT_MISSIONS.filter(m=>(m.status||'planned')==='completed').length
                      + AUDITS.filter(a=>a.status==='completed').length;

  })();

  donut('w6d','w6lg',[{label:'Draft',v:2,c:'#9aa0a8'},{label:'Open',v:3,c:'#0070f2'}]);

  hbar('w7h',[
    {label:'Analamanga',v:4},
    {label:'Atsinanana',v:3},
    {label:'Boeny',v:2},
    {label:'Diana',v:1},
    {label:'Haute Matsiatra',v:1}
  ],'#0070f2',252,126);

  populateW8Filters();
