  vbar('w9b',[{label:'Finance A',vals:[2,1]},{label:'Finance B',vals:[1,1]},{label:'IT',vals:[3,1]},{label:'Ops',vals:[1,0]}],['#0070f2','#34c38f'],252,126);

  renderW10();

  donut('w11d','w11lg',[{label:'Draft',v:1,c:'#9aa0a8'},{label:'Open',v:2,c:'#0070f2'}],43,43,30,11);
