function renderW4(){
  try{
    const soc  = $('#w4-filter-soc').val()||'';
    const type = $('#w4-filter-type').val()||'';

    // Populate filters
    const socs  = [...new Set(AUDITS.map(a=>a.societe).filter(Boolean))].sort();
    const types = [...new Set(AUDITS.map(a=>a.type).filter(Boolean))].sort();
    const $fs = $('#w4-filter-soc'), $ft = $('#w4-filter-type');
    const curS = $fs.val(), curT = $ft.val();
    $fs.find('option:not(:first-child)').remove();
    $ft.find('option:not(:first-child)').remove();
    socs.forEach(s => $fs.append(`<option value="${s}"${s===curS?' selected':''}>${s}</option>`));
    types.forEach(t => $ft.append(`<option value="${t}"${t===curT?' selected':''}>${t}</option>`));

    const missions = AUDITS.filter(a => {
      if(soc  && a.societe !== soc)  return false;
      if(type && a.type   !== type)  return false;
      return true;
    });

    const total = missions.length;
    $('#w4-sub').text(total ? total + ' mission' + (total>1?'s':'') + ' au total' : 'Aucune mission');

    const STATUTS = [
      { key:'planned',    label:'Planifiée', color:'#9aa0a8' },
      { key:'open',       label:'Ouverte',   color:'#0070f2' },
      { key:'inprogress', label:'En cours',  color:'#6941c6' },
      { key:'overdue',    label:'En retard', color:'#ef4444' },
      { key:'completed',  label:'Clôturée',  color:'#22c55e' },
    ];
    const counts = {};
    STATUTS.forEach(s => { counts[s.key] = 0; });
    missions.forEach(a => { if(counts[a.status] !== undefined) counts[a.status]++; });

    const maxVal = Math.max(...STATUTS.map(s => counts[s.key]), 1);

    const $chart = $('#w4-chart').empty();

    const BAR_H = 22;
    let html = `<div style="display:flex;flex-direction:column;gap:5px;">`;

    STATUTS.forEach(s => {
      const v    = counts[s.key];
      const pct  = Math.round(v / maxVal * 100);
      const pctT = total > 0 ? Math.round(v / total * 100) : 0;
      html += `
        <div style="display:grid;grid-template-columns:68px 1fr 28px;gap:6px;align-items:center;">
          <div style="display:flex;align-items:center;gap:5px;">
            <span style="width:8px;height:8px;border-radius:2px;background:${s.color};flex-shrink:0;display:inline-block;"></span>
            <span style="font-size:10px;color:var(--text);font-weight:500;white-space:nowrap;">${s.label}</span>
          </div>
          <div style="background:var(--surface3);border-radius:3px;height:${BAR_H}px;overflow:hidden;position:relative;">

            ${v>0 ? `<span style="position:absolute;left:${Math.min(pct,85)}%;top:50%;transform:translate(4px,-50%);font-size:9px;color:${pct>50?'rgba(255,255,255,.7)':'var(--text-muted)'};font-weight:600;">${pctT}%</span>` : ''}
          </div>
          <div style="font-size:13px;font-weight:800;color:${v>0?s.color:'var(--text-dim)'};font-family:var(--mono);text-align:right;">${v}</div>
        </div>`;
    });

    html += `</div>`;

    if(total > 0){
      html += `<div style="margin-top:8px;height:6px;border-radius:3px;overflow:hidden;display:flex;gap:1px;">`;
      STATUTS.forEach(s => {
        const v = counts[s.key];
        if(v > 0) html += ``;
      });
      html += `</div>`;
    }

    $chart.html(html);

  }catch(e){  }
}
$(document).on('change','#w4-filter-soc,#w4-filter-type', ()=>renderW4());

/* ── W10 : Risques Majeurs par Société ── */
function renderW10(){
  const sevFilter = $('#w10-filter-sev').val()||'';
  const $tb = $('#w10-risks-tbody').empty();

  const sevCfg = {
    critical:{label:'🔴 Critique', bg:'var(--red-bg)',    c:'var(--red)',    score:4},
    high:    {label:'🟠 Élevé',    bg:'var(--orange-bg)', c:'var(--orange)', score:3},
    medium:  {label:'🟡 Moyen',    bg:'var(--yellow-bg)', c:'var(--yellow)', score:2},
    low:     {label:'🟢 Faible',   bg:'var(--green-bg)',  c:'var(--green)',  score:1},
  };

  // Calcul score résiduel COSO
  function scoreResiduel(r){
    const prob = r.probabilite||r.probability||3;
    const imp  = r.impact||3;
    const coso = ['coso_env_controle','coso_eval_risques','coso_activites_ctrl','coso_info_comm','coso_pilotage']
      .reduce((s,k)=>s+(r[k]||0),0);
    const reduction = Math.min(coso/25, 0.7);
    return Math.round(prob * imp * (1 - reduction));
  }

  // Agrégation par société
  const bySoc = {};
  RISKS.forEach(r=>{
    const sev = r.severity||r.niveau||'medium';
    if(sevFilter && sev !== sevFilter) return;
    if(sev==='low' && !sevFilter) return; // n'afficher que critical/high/medium par défaut
    const soc = r.societe||r.entity||'Non assigné';
    if(!bySoc[soc]) bySoc[soc]=[];
    bySoc[soc].push(r);
  });

  // Trier sociétés par risque max
  const rows = Object.entries(bySoc)
    .map(([soc,risks])=>{
      risks.sort((a,b)=>(sevCfg[b.severity||'medium']?.score||0)-(sevCfg[a.severity||'medium']?.score||0));
      return {soc, risks, topSev: risks[0]?.severity||'medium'};
    })
    .sort((a,b)=>(sevCfg[b.topSev]?.score||0)-(sevCfg[a.topSev]?.score||0));

  const total = rows.reduce((s,r)=>s+r.risks.length,0);
  const nCrit = rows.reduce((s,r)=>s+r.risks.filter(x=>(x.severity||'medium')==='critical').length,0);
  $('#w10-sub').text(`${total} risque${total>1?'s':''} · ${nCrit} critique${nCrit>1?'s':''}`);

  if(!rows.length){
    $tb.html('<tr><td colspan="4" class="nodata">Aucun risque majeur enregistré</td></tr>');
    return;
  }

  rows.forEach(({soc,risks,topSev})=>{
    risks.slice(0,3).forEach((r,i)=>{
      const sev = r.severity||r.niveau||'medium';
      const cfg = sevCfg[sev]||sevCfg.medium;
      const score = scoreResiduel(r);
      const scoreColor = score>=12?'var(--red)':score>=6?'var(--orange)':score>=3?'var(--yellow)':'var(--green)';
      $tb.append(`<tr>
        <td style="font-size:11px;font-weight:${i===0?'700':'400'};color:${i===0?'var(--text)':'var(--text-muted)'};">${i===0?soc:'↳'}</td>
        <td style="font-size:11px;max-width:140px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${(r.title||r.risque||'—').replace(/"/g,'')}">${(r.title||r.risque||'—').slice(0,35)}</td>
        <td><span style="display:inline-block;padding:1px 6px;border-radius:3px;font-size:10px;font-weight:600;background:${cfg.bg};color:${cfg.c};white-space:nowrap;">${cfg.label}</span></td>
        <td style="font-family:var(--mono);font-size:11px;font-weight:700;color:${scoreColor};text-align:center;">${score}</td>
      </tr>`);
    });
    if(risks.length>3){
      $tb.append(`<tr><td colspan="4" style="font-size:10px;color:var(--text-dim);padding:2px 11px;">+ ${risks.length-3} autre${risks.length-3>1?'s':''} risque${risks.length-3>1?'s':''}…</td></tr>`);
    }
  });
}

function populateW8Filters(){
  const $fs  = $('#w8-filter-societe');
  const $fr  = $('#w8-filter-responsable');
  const curS = $fs.val();
  const curR = $fr.val();

  const socs = [...new Set(ACTIONS.map(a => a.societe||'Non spécifié').filter(Boolean))].sort();
  $fs.empty().append('<option value="">Toutes les sociétés</option>');
  socs.forEach(s => $fs.append(`<option value="${s}"${s===curS?' selected':''}>${s}</option>`));

  const resps = new Set();
  ACTIONS.forEach(a => {
    if(curS && (a.societe||'Non spécifié') !== curS) return;
    (a.recommandations||[]).forEach(r => {
      const v = r.responsable||'';
      if(v && v!=='—') resps.add(v);
    });
  });
  $fr.empty().append('<option value="">Tous les responsables</option>');
  [...resps].sort().forEach(r => $fr.append(`<option value="${r}"${r===curR?' selected':''}>${r}</option>`));

  // Si le responsable sélectionné n'existe plus dans la nouvelle liste, reset
  if(curR && !resps.has(curR)) $fr.val('');
}

function renderW8(){
  const COLORS = ['#6366f1','#22c55e','#f59e0b','#0070f2'];
  const KEYS   = ['total','fully','partial','nonechu'];
  const LABELS = ['Total','Clos','Dossier à suivre','Non échue'];

  const filterSoc  = $('#w8-filter-societe').val()     || '';
  const filterResp = $('#w8-filter-responsable').val() || '';

  // ── Agrégation — 4 compteurs globaux selon filtres ──
  const today_w8 = new Date(); today_w8.setHours(0,0,0,0);
  const agg = {total:0, fully:0, partial:0, nonechu:0};
  ACTIONS.forEach(a => {
    const soc = a.societe || 'Non spécifié';
    if(filterSoc && soc !== filterSoc) return;
    (a.recommandations||[]).forEach(r => {
      const resp = (r.responsable && r.responsable !== '—') ? r.responsable : 'Non assigné';
      if(filterResp && resp !== filterResp) return;
      agg.total++;
      if(r.statut==='fully'){ agg.fully++; return; }
      if(r.echeance){
        const dR = new Date(r.echeance); dR.setHours(0,0,0,0);
        if(!isNaN(dR) && dR > today_w8){ agg.nonechu++; return; }
        // échue : dossier à suivre si appréciation ≠ Satisfaisant
        const apprR=(r.appreciation_preuve||'').toLowerCase();
        const isSatR=apprR.includes('satisfaisant')&&!apprR.includes('pas')&&!apprR.includes('partiel');
        if(isSatR) agg.fully++; else agg.partial++;
      } else {
        agg.partial++;
      }
    });
  });

  // Sous-titre
  let sub = '';
  if(filterSoc)  sub += `🏢 ${filterSoc}`;
  if(filterResp) sub += (sub?' · ':'') + `👤 ${filterResp}`;
  if(!sub) sub = `${agg.total} recommandation${agg.total>1?'s':''}`;
  $('#w8-sub').text(sub);

  const $s = $('#w8b');
  $s.empty().attr({viewBox:'0 0 252 126'});

  if(!agg.total){
    $s.attr({viewBox:'0 0 252 126'});
    $s.append(`<text x="126" y="63" font-size="9" fill="#9aa0a8" text-anchor="middle" dominant-baseline="middle">Aucune donnée pour cette sélection</text>`);
    return;
  }

  // ── Dimensions — identiques à vbar (252×126) ──
  const W  = 252, H = 126;
  const pL = 24, pB = 20, pT = 7;
  const cW = W - pL - 5;
  const cH = H - pB - pT;

  // 4 barres centrées dans le graphique
  const ns = 4;
  const bw = 28;
  const gap = 10;
  const totalBarsW = ns * bw + (ns-1) * gap;
  const startX = pL + (cW - totalBarsW) / 2;

  const maxV = Math.max(agg.total, 1);

  // Gridlines — identiques à vbar
  [0, .5, 1].forEach(p => {
    const y = pT + cH * (1 - p);
    $s.append(`<line x1="${pL}" y1="${y}" x2="${W-4}" y2="${y}" stroke="#e8eaed" stroke-width="1"/>`);
    $s.append(`<text x="${pL-2}" y="${y+3}" font-size="7" fill="#9aa0a8" text-anchor="end">${Math.round(p*maxV)}</text>`);
  });

  // 4 barres
  KEYS.forEach((k, j) => {
    const v  = agg[k];
    const bh = (v / maxV) * cH || 0;
    const x  = startX + j * (bw + gap);
    const cx = x + bw / 2;
    $s.append(`<rect x="${x.toFixed(1)}" y="${(pT+cH-bh).toFixed(1)}" width="${bw}" height="${bh.toFixed(1)}" rx="2" fill="${COLORS[j]}" opacity=".85"
      class="w8-bar"
      data-label="${LABELS[j]}"
      data-total="${agg.total}" data-fully="${agg.fully}" data-partial="${agg.partial}" data-not="${agg.not}"
      style="cursor:pointer;"
      onmouseenter="w8Tip(event,this)" onmouseleave="w8HideTip()"/>`);
    if(v > 0)
      $s.append(`<text x="${cx.toFixed(1)}" y="${(pT+cH-bh-2).toFixed(1)}" font-size="7" fill="#6b7785" text-anchor="middle">${v}</text>`);
    // label sous la barre
    $s.append(`<text x="${cx.toFixed(1)}" y="${H-4}" font-size="7.5" fill="#6b7785" text-anchor="middle">${LABELS[j]}</text>`);
  });
}

