// ── W8 Tooltip ──
window.w8Tip = function w8Tip(e, el){
  let tt = document.getElementById('w8-tooltip');
  if(!tt){
    tt = document.createElement('div');
    tt.id = 'w8-tooltip';
    tt.style.cssText = 'position:fixed;background:var(--surface3,#1c2030);border:1px solid var(--border2);border-radius:6px;padding:8px 12px;font-size:11px;pointer-events:none;z-index:9999;box-shadow:0 4px 12px rgba(0,0,0,.4);min-width:160px;font-family:var(--font);color:var(--text);';
    document.body.appendChild(tt);
  }
  const pct = el.dataset.total>0 ? Math.round(el.dataset.fully/el.dataset.total*100) : 0;
  tt.innerHTML = `
    <div style="font-weight:700;margin-bottom:6px;font-size:12px;border-bottom:1px solid var(--border);padding-bottom:5px;">${el.dataset.label}</div>
    <div style="display:flex;justify-content:space-between;gap:16px;margin-bottom:3px;"><span style="color:var(--text-muted)">Total</span><span style="font-family:var(--mono);color:#6366f1;font-weight:700;">${el.dataset.total}</span></div>
    <div style="display:flex;justify-content:space-between;gap:16px;margin-bottom:3px;"><span style="color:var(--text-muted)">Clos</span><span style="font-family:var(--mono);color:#22c55e;font-weight:700;">${el.dataset.fully}</span></div>
    <div style="display:flex;justify-content:space-between;gap:16px;margin-bottom:3px;"><span style="color:var(--text-muted)">Dossier à suivre</span><span style="font-family:var(--mono);color:#f59e0b;font-weight:700;">${el.dataset.partial}</span></div>
    <div style="display:flex;justify-content:space-between;gap:16px;margin-bottom:4px;"><span style="color:var(--text-muted)">Non échue</span><span style="font-family:var(--mono);color:#0070f2;font-weight:700;">${el.dataset.not}</span></div>
    <div style="border-top:1px solid var(--border);padding-top:4px;text-align:right;font-size:10px;color:var(--text-dim);">Taux fully : <b style="color:${pct>=80?'var(--green)':pct>=40?'#f59e0b':'#ef4444'}">${pct}%</b></div>`;
  tt.style.display = 'block';
  tt.style.left = (e.clientX+14)+'px';
  tt.style.top  = (e.clientY-80)+'px';
}
window.w8HideTip = function w8HideTip(){
  const tt = document.getElementById('w8-tooltip');
  if(tt) tt.style.display='none';
}

