let aflt='all';
// ══════════════════════════════════════════════════════════════════
// DOSSIER DE MISSION — Association Audit (Ouvert) ↔ RCM (par cycle),
// TAF, FRAP — Constats, Suivi Recommandations et Rapport d'Audit
// ══════════════════════════════════════════════════════════════════
function auditRealCycle(a){
  return (a.cycle==='Autre (préciser)' && a.cycle_custom) ? a.cycle_custom : (a.cycle||'');
}
function auditDossierBadgesHtml(a, idx){
  if(a.status !== 'open') return '';
  var cyc = auditRealCycle(a);
  var rcmCount = (typeof RCM_DATA!=='undefined') ? RCM_DATA.filter(function(r){
    return cyc && r.cycle===cyc && (!r.filiale || r.filiale===a.societe || r.filiale==='Toutes filiales');
  }).length : 0;
  var tafCount = (typeof TAF_ITEMS!=='undefined') ? TAF_ITEMS.filter(function(t){
    return cyc && t.categorie===cyc && (!t.societe || t.societe===a.societe);
  }).length : 0;
  var frapCount = (typeof FRAP_DATA!=='undefined') ? FRAP_DATA.filter(function(f){
    return cyc && f.cycle===cyc && (!f.societe || f.societe===a.societe);
  }).length : 0;
  var actionsCount = (typeof ACTIONS!=='undefined') ? ACTIONS.filter(function(x){ return x.ref===a.ref; }).length : 0;
  return '<div class="dossier-badges" onclick="event.stopPropagation();">'
    + '<span class="dossier-badge db-rcm" title="Risk Control Matrix lié au cycle '+escHtml(cyc||'—')+'" onclick="auditGoToRCM('+idx+')">🛡️ RCM '+rcmCount+'</span>'
    + '<span class="dossier-badge db-taf" title="Travail à Faire lié au cycle" onclick="auditGoToTAF('+idx+')">✅ TAF '+tafCount+'</span>'
    + '<span class="dossier-badge db-frap" title="Constats FRAP liés au cycle" onclick="auditGoToFRAP('+idx+')">🔎 FRAP '+frapCount+'</span>'
    + '<span class="dossier-badge db-actions" title="Suivi des Recommandations de cette mission" onclick="auditGoToActions('+idx+')">📌 Suivi '+actionsCount+'</span>'
    + '<span class="dossier-badge db-rapport" title="Rapport d\'Audit de cette mission" onclick="auditGoToRapport('+idx+')">📑 Rapport</span>'
  +'</div>';
}
function auditGoToRCM(idx){
  var a = AUDITS[idx]; if(!a) return;
  var cyc = auditRealCycle(a);
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="rcm"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('rcm');
  setTimeout(function(){
    if(typeof renderRCM === 'function') renderRCM();
    $('#rcm-f-cycle').val(cyc||'');
    $('#rcm-f-filiale').val(a.societe||'');
    if(typeof renderRCM === 'function') renderRCM();
  }, 60);
}
function auditGoToTAF(idx){
  var a = AUDITS[idx]; if(!a) return;
  var cyc = auditRealCycle(a);
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="taf"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('taf');
  setTimeout(function(){
    _tafSearch = '';
    _tafFilterCategorie = cyc || '';
    if(document.getElementById('taf-search')) $('#taf-search').val('');
    if(typeof renderTAF === 'function') renderTAF();
    $('#taf-filter-categorie').val(cyc||'');
  }, 60);
}
function auditGoToFRAP(idx){
  var a = AUDITS[idx]; if(!a) return;
  var cyc = auditRealCycle(a);
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="frap"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('frap');
  setTimeout(function(){
    $('#frap-filter-societe').val(a.societe||'');
    $('#frap-search').val(cyc||'');
    $('#frap-filter-crit').val('');
    if(typeof renderFRAP === 'function') renderFRAP();
  }, 60);
}
function auditGoToActions(idx){
  var a = AUDITS[idx]; if(!a) return;
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="actions"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('actions');
  setTimeout(function(){
    if(typeof populateActionsFilters === 'function') populateActionsFilters();
    $('#actions-filter-societe').val('');
    $('#actions-filter-cycle').val('');
    $('#actions-filter-ref').val(a.ref||'');
    if(typeof renderActions === 'function') renderActions();
