}
function auditGoToRapport(idx){
  var a = AUDITS[idx]; if(!a) return;
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="rapport-audit"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('rapport-audit');
  setTimeout(function(){
    if(typeof _raPopulateAuditSelect === 'function') _raPopulateAuditSelect();
    $('#ra-select-audit').val(String(idx));
    if(typeof renderRapportAudit === 'function') renderRapportAudit();
    if(typeof _raUpdateWorkflow === 'function') _raUpdateWorkflow();
  }, 60);
}

window.auditGoToRCM = auditGoToRCM;
