  $(document).on('input.aqprog','#aq-progress',function(){$('#aq-prog-lbl').text($(this).val()+'%');});
  $(document).on('click.aqpreset','.aq-prog-preset',function(){
    const v=$(this).data('val');
    $('#aq-progress').val(v);$('#aq-prog-lbl').text(v+'%');
  });
  $('#mbk').data('auditEditIdx',idx).data('auditQuick',true);
  $('#msave').data('mode','audit-edit');
});


$(document).on('click','#view-audits .chip[data-filter]',function(){
  $(this).siblings('.chip').removeClass('active');$(this).addClass('active');renderAudits($(this).data('filter'));

  $('#nb-audits').text(AUDITS.length);
});

function renderActions(){
  const today=new Date(); today.setHours(0,0,0,0);
  const $tb=$('#actions-tbody');
  if(!$tb.length){return;}

  const filterSociete = $('#actions-filter-societe').val() || '';
  const filterRef = $('#actions-filter-ref').val() || '';
  const filterCycle = $('#actions-filter-cycle').val() || '';
  const filterResponsable = $('#actions-filter-responsable').val() || '';
  const filterCriticite = $('#actions-filter-criticite').val() || '';
  const filterStatut = $('#actions-filter-statut').val() || '';
  const filterRetard = $('#actions-filter-retard').val() || '';

  $tb.empty();
  if(!ACTIONS.length){
    $tb.html('<tr><td colspan="16" class="nodata">Aucun constat enregistré. Cliquez sur « + Nouveau » pour en créer un.</td></tr>');
    $('#actions-count').text('');
    return;
  }

  const svLbl={critical:'Critical',high:'High',medium:'Medium',low:'Low'};
  const statColors={
    fully:         {bg:'var(--green-bg)',  c:'var(--green)'},
    partially:     {bg:'var(--yellow-bg)', c:'var(--yellow)'},
    notimplemented:{bg:'var(--red-bg)',    c:'var(--red)'},
  };

  let html='';
  let totalRows = 0;
  let filteredRows = 0;

  ACTIONS.forEach((a,ai)=>{
    // Application des filtres au niveau du constat
    if(filterSociete && a.societe !== filterSociete) return;
    if(filterRef && a.ref !== filterRef) return;
    if(filterCycle && a.cycle !== filterCycle) return;
    if(filterCriticite && a.criticite !== filterCriticite) return;

    const recos=(a.recommandations&&a.recommandations.length)
      ? a.recommandations
      : [{id:a.id+'-R1', recommandation:'—', disposition:'—', responsable:'—', echeance:'', statut:'notimplemented', avancement:0}];

    let filteredRecos = recos.filter((r) => {
      totalRows++;

      if(filterResponsable && r.responsable !== filterResponsable) return false;

      const seActual = computeStatutEffectif(r, today);
      if(filterStatut && seActual !== filterStatut) return false;

      if(filterRetard) {
        let isRetard = false;
        const echeRet = r.echeance_revisee || r.echeance;
        if(echeRet && seActual !== 'fully') {
          const dueDate = new Date(echeRet);
          if(!isNaN(dueDate)) {
            const diff = Math.floor((today - dueDate) / (1000*60*60*24));
            isRetard = diff > 0;
          }
        }
        if(filterRetard === 'oui' && !isRetard) return false;
        if(filterRetard === 'non' && isRetard) return false;
      }

      const filterDossier = $('#actions-filter-dossier').val()||'';
      if(filterDossier){
        if(filterDossier === 'clos'    && seActual !== 'fully')     return false;
        if(filterDossier === 'suivre'  && seActual !== 'partially') return false;
        if(filterDossier === 'echu'    && seActual !== 'echu')      return false;
        if(filterDossier === 'nonechu' && seActual !== 'nonechu')   return false;
      }

      return true;
    });

    if(filteredRecos.length === 0) return;

    const nRows = filteredRecos.length;
    filteredRows += nRows;

    filteredRecos.forEach((r,ri)=>{

      let retardHtml='<span style="color:var(--text-dim)">—</span>';
      if(r.echeance && r.statut!=='fully'){
        const dueDate=new Date(r.echeance);
        if(!isNaN(dueDate)){
          const diff=Math.floor((today-dueDate)/(1000*60*60*24));
          if(diff>0)
            retardHtml=`<span style="font-family:var(--mono);font-size:11px;color:var(--red);font-weight:700;">+${diff} j</span>`;
          else if(diff>=-7)
            retardHtml=`<span style="font-family:var(--mono);font-size:11px;color:var(--yellow);font-weight:600;">${Math.abs(diff)} j</span>`;
        }
      }

      const sc=statColors[r.statut]||{bg:'var(--surface3)',c:'var(--text-muted)'};
      const statLabel=sLabel[r.statut]||r.statut;
      const av=Number(r.avancement)||0;
      const pc=av>=80?'var(--green)':av>=40?'var(--accent)':'var(--yellow)';
      const rowBg=ri===0?'':'background:var(--surface2);';
      const bTop=ri===0?'':'border-top:1px dashed var(--border2);';

      /* palette couleur de fond par constat (alternance) */
      const rowAccent = ['#f0f4ff','#f5f0ff','#f0fff4','#fff8f0','#f0f9ff','#fff0f5'];
      const baseColor = rowAccent[ai % rowAccent.length];
      const rowStyle = ri===0
        ? `background:${baseColor};`
        : `background:${baseColor}cc;border-top:1px solid rgba(0,0,0,.04);`;

      html+=`<tr style="${rowStyle}">`;

      const CLIP = (txt, fs='10.5px', fw='400', clr='inherit') => {
        const safe = (txt||'—').replace(/"/g,'&quot;').replace(/</g,'&lt;');
        return `<div title="${safe}" style="font-size:${fs};font-weight:${fw};color:${clr};overflow:hidden;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;line-height:1.4;word-break:break-word;">${txt||'—'}</div>`;
      };

      const C  = 'padding:5px 6px;vertical-align:top;';   /* cellule normale */
      const CB = C+'border-right:1px solid rgba(0,0,0,.07);'; /* cellule avec séparateur droit */

      /* ── Cellules communes (rowspan) — 1ère ligne uniquement ── */
      if(ri===0){
        /* Société */
        html+=`<td rowspan="${nRows}" style="${CB}font-size:10px;font-weight:600;color:var(--text);display:none;">${a.societe||'—'}</td>`;
        /* Réf + Date */
        html+=`<td rowspan="${nRows}" style="${CB}display:none;">
          <div style="font-family:var(--mono);font-size:10px;font-weight:700;color:var(--accent);">${a.ref||'—'}</div>
          ${a.date_rapport?`<div style="font-size:9px;color:var(--text-muted);margin-top:1px;">${a.date_rapport}</div>`:''}
        </td>`;
        /* Cycle */
        html+=`<td rowspan="${nRows}" style="${CB}font-size:10px;color:var(--text-muted);text-align:center;display:none;">
          <span style="display:inline-block;padding:1px 5px;border-radius:3px;background:var(--surface3);font-size:9px;font-weight:600;">${a.cycle||'—'}</span>
        </td>`;
        /* Code anomalie */
        html+=`<td rowspan="${nRows}" style="${CB}text-align:center;">
          <span style="font-family:var(--mono);font-size:9px;font-weight:700;color:#7c3aed;background:#ede9fe;padding:2px 5px;border-radius:3px;white-space:nowrap;">${a.code_anomalie||'—'}</span>
        </td>`;
        /* Intitulé */
        html+=`<td rowspan="${nRows}" style="${CB}">${CLIP(a.intitule||'—','10px','400','var(--text-muted)')}</td>`;
        /* Anomalie */
        html+=`<td rowspan="${nRows}" style="${CB}">${CLIP(a.findingTitle,'10.5px','600','var(--text)')}</td>`;
        /* Risques */
        html+=`<td rowspan="${nRows}" style="${CB}">${CLIP(a.consequences||'—','10px','400','var(--text-muted)')}</td>`;
        /* Criticité */
        const critIco={critical:'🔴',high:'🟠',medium:'🟡',low:'🟢'};
        html+=`<td rowspan="${nRows}" style="${CB}text-align:center;padding:5px 2px;overflow:hidden;">
          <span style="font-size:13px;" title="${svLbl[a.criticite]||'—'}">${critIco[a.criticite]||'⚪'}</span>
        </td>`;
      }

      /* ── Cellules par recommandation ── */
      const bTop2 = ri===0?'':'border-top:1px dashed rgba(0,0,0,.08);';

      /* Recommandation */
      const hasNote = !!(r.explication||'').trim() || !!(r.commentaire_auditeur||'').trim();
      const noteIcon = hasNote ? (()=>{
        const expl = (r.explication||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;');
        const comm = (r.commentaire_auditeur||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;');
        return `<span class="reco-note-icon" data-expl="${expl}" data-comm="${comm}">i</span>`;
      })() : '';
      html+=`<td style="${C}${bTop2}"><div style="display:flex;align-items:flex-start;gap:2px;">${CLIP(r.recommandation,'10px','400','var(--text-muted)')}${noteIcon}</div></td>`;
      /* Disposition */
      html+=`<td style="${C}${bTop2}">${CLIP(r.disposition,'10px','400','var(--text)')}</td>`;
      /* Responsable */
      const respParts = (r.responsable||'').split(' ');
      const respShort = respParts.length>1 ? respParts[0]+' '+respParts[respParts.length-1][0]+'.' : r.responsable||'—';
      html+=`<td style="${C}${bTop2}" title="${(r.responsable||'').replace(/"/g,'&quot;')}">
        <div style="font-size:10px;font-weight:600;color:var(--text);">${respShort}</div>
      </td>`;
      /* Échéance */
      const echeRef = r.echeance_revisee || r.echeance;
      const echeColor = (()=>{
        if(!echeRef || r.statut==='fully') return 'var(--text-muted)';
        const d=new Date(echeRef); if(isNaN(d)) return 'var(--text-muted)';
        return d<=today ? 'var(--red)' : 'var(--text-muted)';
      })();
      html+=`<td style="${C}${bTop2}padding:5px 4px;">
        <div style="font-family:var(--mono);font-size:9.5px;color:${echeColor};font-weight:${echeColor==='var(--red)'?700:400};">${r.echeance||'—'}</div>
        ${r.echeance_revisee?`<div style="font-size:8.5px;color:#7c3aed;margin-top:2px;" title="Échéance révisée">↺ ${r.echeance_revisee}</div>`:''}
      </td>`;

      let statutBadge='';
      const apprRawB = (r.appreciation_preuve||'').toLowerCase().trim();
      const isSatisfB    = apprRawB.includes('satisfaisant') && !apprRawB.includes('pas') && !apprRawB.includes('partiel');
      const isPartielB   = apprRawB.includes('partiel');
      const isPasSatisfB = apprRawB.includes('pas');

      const seB = computeStatutEffectif(r, today);

      if(seB === 'fully') {
        const lblB = isSatisfB ? '✅ Fully Implemented' : '✅ Clos';
        statutBadge=`<span style="display:inline-flex;align-items:center;gap:2px;padding:2px 6px;border-radius:6px;font-size:9.5px;font-weight:700;background:#dcfce7;color:#166534;border:1px solid #86efac;white-space:nowrap;">${lblB}</span>`;
      } else if(seB === 'partially') {
        const lblB2 = isPartielB ? '📂 Partially Implemented' : '📂 Dossier à suivre';
        statutBadge=`<span style="display:inline-flex;align-items:center;gap:2px;padding:2px 6px;border-radius:6px;font-size:9.5px;font-weight:700;background:#fff3cd;color:#7a5c00;border:1px solid #f0c040;white-space:nowrap;">${lblB2}</span>`;
      } else if(seB === 'echu') {
        const lblB3   = isPasSatisfB ? '❌ Not Implemented' : '⏰ Échu';
        const bgB3    = isPasSatisfB ? '#fee2e2' : '#fce7f3';
        const colB3   = isPasSatisfB ? '#991b1b' : '#9d174d';
        const brdB3   = isPasSatisfB ? '#fca5a5' : '#f9a8d4';
        statutBadge=`<span style="display:inline-flex;align-items:center;gap:2px;padding:2px 6px;border-radius:6px;font-size:9.5px;font-weight:700;background:${bgB3};color:${colB3};border:1px solid ${brdB3};white-space:nowrap;">${lblB3}</span>`;
      } else {
        statutBadge=`<span style="display:inline-flex;align-items:center;gap:2px;padding:2px 6px;border-radius:6px;font-size:9.5px;font-weight:700;background:#e8f1fd;color:#0064d9;border:1px solid #93c5fd;white-space:nowrap;">📅 Non échue</span>`;
      }
      html+=`<td style="${C}${bTop2}padding:5px 4px;text-align:center;">${statutBadge}</td>`;

      const avPct=av;
      const avColor=av>=80?'#16a34a':av>=40?'var(--accent)':'#d97706';
      html+=`<td style="${C}${bTop2}padding:5px 4px;text-align:center;">
        <div style="font-family:var(--mono);font-size:10px;font-weight:700;color:${avColor};">${av}%</div>
        <div style="margin-top:2px;height:4px;border-radius:2px;background:var(--surface3);overflow:hidden;">
          <div style="height:4px;width:${av}%;background:${avColor};border-radius:2px;"></div>
        </div>
      </td>`;

      const appr=r.appreciation_preuve||'';
      let apprIco='—'; let apprTip=appr;
      if(appr.toLowerCase().includes('satisfaisant')&&!appr.toLowerCase().includes('pas')&&!appr.toLowerCase().includes('partiel')) apprIco='✅';
      else if(appr.toLowerCase().includes('partiel')) apprIco='📂';
      else if(appr.toLowerCase().includes('pas')) apprIco='❌';
      html+=`<td style="${C}${bTop2}padding:5px 4px;text-align:center;" title="${apprTip.replace(/"/g,'&quot;')}">
        <span style="font-size:13px;">${apprIco}</span>
      </td>`;

      html+=`<td style="${C}${bTop2}padding:5px 4px;text-align:center;">
        <div style="font-family:var(--mono);font-size:9px;color:var(--text-muted);">${(r.mise_a_jour||'—').replace(/^(\d{4})-(\d{2})-(\d{2})$/,'$3/$2/$1')}</div>
      </td>`;

      html+=`<td style="${C}${bTop2}padding:5px 4px;text-align:center;white-space:nowrap;">
        <div style="display:flex;flex-direction:column;gap:3px;align-items:stretch;">
          <button class="btn action-reco-edit-btn" data-idx="${ai}" data-ri="${recos.indexOf(r)}" style="padding:2px 5px;font-size:10px;border-radius:4px;white-space:nowrap;" title="Modifier cette recommandation">✏️ Modifier</button>
          <button class="btn action-reco-del-btn" data-idx="${ai}" data-ri="${recos.indexOf(r)}" style="padding:2px 5px;font-size:10px;border-radius:4px;color:var(--red);border-color:var(--red);white-space:nowrap;" title="Supprimer cette recommandation">🗑️ Suppr. reco</button>
          ${ri===0?`<button class="btn action-reco-add-btn" data-idx="${ai}" style="padding:2px 5px;font-size:10px;border-radius:4px;color:var(--green);border-color:var(--green);white-space:nowrap;" title="Ajouter une recommandation">＋ Ajouter</button>`:''}
          ${ri===0?`<button class="btn action-constat-del-btn" data-idx="${ai}" style="padding:2px 5px;font-size:10px;border-radius:4px;color:#fff;background:var(--red);border-color:var(--red);white-space:nowrap;" title="Supprimer tout le constat et ses recommandations">🗑️ Suppr. constat</button>`:''}
        </div>
      </td>`;

      html+=`</tr>`;
    });
  });

  if(filteredRows === 0) {
    $tb.html('<tr><td colspan="16" class="nodata">Aucune recommandation ne correspond aux filtres sélectionnés.</td></tr>');
    $('#actions-count').text('0 recommandation');
  } else {
    $tb.html(html);
    $('#actions-count').text(`${filteredRows} recommandation${filteredRows > 1 ? 's' : ''}`);
  }

  const nbOpen=ACTIONS.reduce((s,a)=>{
    const recos=a.recommandations||[];
    return s+recos.filter(r=>r.statut!=='fully').length;
  },0);
  $('#nb-actions').text(nbOpen||ACTIONS.length);
}

function populateActionsFilters(){
  const $societe = $('#actions-filter-societe');
  const $ref = $('#actions-filter-ref');
  const $responsable = $('#actions-filter-responsable');

  if($societe.find('option').length <= 1){
    const societes = [...new Set(ACTIONS.map(a => a.societe).filter(Boolean))].sort();
    societes.forEach(s => $societe.append(`<option value="${s}">${s}</option>`));
  }

  if($('#actions-filter-cycle').find('option').length <= 1){
    const cycles = [...new Set(ACTIONS.map(a => a.cycle).filter(Boolean))].sort();
    cycles.forEach(c => $('#actions-filter-cycle').append(`<option value="${c}">${c}</option>`));
  }

  const curRef = $ref.val();
  $ref.find('option:not(:first-child)').remove();
  const refs = [...new Set(ACTIONS.map(a => a.ref).filter(Boolean))].sort();
  refs.forEach(r => $ref.append(`<option value="${r}"${r===curRef?' selected':''}>${r}</option>`));

  if($responsable.find('option').length <= 1){
    const responsables = new Set();
    ACTIONS.forEach(a => {
      const recos = a.recommandations || [];
      recos.forEach(r => {
        if(r.responsable && r.responsable !== '—') responsables.add(r.responsable);
      });
    });
    [...responsables].sort().forEach(r => $responsable.append(`<option value="${r}">${r}</option>`));
  }
}

$('#actions-filter-societe, #actions-filter-ref, #actions-filter-cycle, #actions-filter-responsable, #actions-filter-criticite, #actions-filter-statut, #actions-filter-retard, #actions-filter-dossier').on('change', function(){
  renderActions();
});

$('#actions-reset-filters').on('click', function(){
  $('#actions-filter-societe').val('');
  $('#actions-filter-ref').val('');
  $('#actions-filter-cycle').val('');
  $('#actions-filter-responsable').val('');
  $('#actions-filter-criticite').val('');
  $('#actions-filter-statut').val('');
  $('#actions-filter-retard').val('');
  $('#actions-filter-dossier').val('');
  renderActions();
});

// MODAL
var _modalLastFocus=null;
function _modalWireLabels(){
  // A11Y: associe automatiquement chaque .flbl2 (label visuel) au champ qui le suit (input/select/textarea)
  $('#modal-body .frow2,#modal-body .fgrid > div').each(function(){
    var $row=$(this);
    var $lbl=$row.find('.flbl2').first();
    var $field=$row.find('input,select,textarea').first();
    if($lbl.length && $field.length){
      var id=$field.attr('id');
      if(id){
        $lbl.attr('id', id+'-lbl');
        $field.attr('aria-labelledby', id+'-lbl');
      } else {
        $field.attr('aria-label', $lbl.text().trim());
      }
    }
  });
}
function _elVisible(el){ return !!(el && (el.offsetWidth||el.offsetHeight||el.getClientRects().length)); }
function _modalTrapFocus(e){
  if(e.key!=='Tab') return;
  var $focusable=$('#mbk').find('a[href],button,input,select,textarea,[tabindex]:not([tabindex="-1"])').filter(function(){return _elVisible(this);});
  if(!$focusable.length) return;
  var first=$focusable[0], last=$focusable[$focusable.length-1];
  if(e.shiftKey && document.activeElement===first){ e.preventDefault(); last.focus(); }
  else if(!e.shiftKey && document.activeElement===last){ e.preventDefault(); first.focus(); }
}
function _modalKeydown(e){
  if(e.key==='Escape') closeModal();
  else _modalTrapFocus(e);
}
function openModal(title,html){
  _modalLastFocus=document.activeElement;
  $('#modal-title').text(title);$('#modal-body').html(html);$('#mbk').addClass('open');
  _modalWireLabels();
  document.addEventListener('keydown',_modalKeydown);
  setTimeout(function(){
    var $first=$('#mbk').find('input,select,textarea,button').filter(function(){return _elVisible(this);}).first();
    ($first.length?$first:$('#mclose')).trigger('focus');
  },30);
}
function closeModal(){
  $(document).off('input.recoav click.recoadd click.remodel input.dlyprog input.dqprange click.dqppreset change.acycle change.tmtype input.tmprog input.qprange click.qppreset change.fduree click.userpick');
  $('#msave').show();
  // Nettoyer aussi tous les handlers du modal Gantt mission / tâches
  $(document).off('click.colorpick click.gmtype click.gmtask click.gmst click.gmstcancel click.gmstadd click.gmdel click.gmdelst change.gmtype click.gmedittask click.gmsavetaskedit click.gmcanceltaskedit click.gmeditst click.gmcancelstedit click.gmsavest change.gmaudit input.gmprog input.gmdates change.gmdates input.gmetedit change.gmetedit input.gmtasknj change.gmtasknj input.uniprog change.uniref');
  gmEditingTaskIdx = -1;
  $('.modal').css('width','');
  $('#mbk').removeClass('open');
  document.removeEventListener('keydown',_modalKeydown);
  if(_modalLastFocus && _modalLastFocus.focus) _modalLastFocus.focus();
}
$('#mclose,#mcancel').on('click',closeModal);
$('#mclose').on('keydown',function(e){if(e.key==='Enter'||e.key===' '){e.preventDefault();closeModal();}});
$('#mbk').on('click',function(e){if($(e.target).is('#mbk'))closeModal();});

function FEDIT(x){
