  <div class="frow2"><div class="flbl2">Intitulé du constat</div><input class="finp" id="fe-title" value="${escHtml(x.title||'')}"></div>
  <div class="fgrid">
    <div class="frow2"><div class="flbl2">Société</div>
      <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="fe-societe">
        <option value="">— Sélectionner —</option>
        ${SOCIETES.map(s=>`<option value="${s.nom}"${s.nom===x.societe?' selected':''}>${s.nom}</option>`).join('')}
      </select></div>
    <div class="frow2"><div class="flbl2">Audit lié</div>
      <select class="finp" style="appearance:none;" id="fe-audit">
        ${AUDITS.map(a=>`<option value="${a.ref}"${a.ref===x.audit?' selected':''}>${a.ref}</option>`).join('')}
      </select></div>
  </div>
  <div class="fgrid">
    <div class="frow2"><div class="flbl2">Sévérité</div>
      <select class="finp" style="appearance:none;" id="fe-sev">
        <option value="critical"${x.severity==='critical'?' selected':''}>Critical</option>
        <option value="high"${x.severity==='high'?' selected':''}>High</option>
        <option value="medium"${x.severity==='medium'?' selected':''}>Medium</option>
        <option value="low"${x.severity==='low'?' selected':''}>Low</option>
      </select></div>
    <div class="frow2"><div class="flbl2">Statut</div>
      <select class="finp" style="appearance:none;" id="fe-status">
        <option value="open"${x.status==='open'?' selected':''}>Open</option>
        <option value="inprogress"${x.status==='inprogress'?' selected':''}>In Progress</option>
        <option value="completed"${x.status==='completed'?' selected':''}>Completed</option>
      </select></div>
  </div>
  <div class="fgrid">
    <div class="frow2"><div class="flbl2">Responsable</div>
      <input class="finp" id="fe-owner" value="${x.ownerFull||x.owner||''}" placeholder="Nom du responsable…"></div>
    <div class="frow2"><div class="flbl2">Échéance</div><input class="finp" id="fe-due" type="date" value="${x.due||''}"></div>
  </div>`;
}

/* ── Formulaire Constat (Nouveau / Modifier) ── */
/* ══════════════════════════════════════════════════════════════
   FORMULAIRE UNIFIÉ — Suivi Recommandations
   Constat + N recommandations inline, dynamiques
   ══════════════════════════════════════════════════════════════ */

/* ─ Helper : génère le HTML d'une ligne recommandation ─ */
function RECO_ROW(r, idx){
  const i = idx;
  const av = r ? r.avancement||0 : 0;
  const statut = r ? r.statut||'notimplemented' : 'notimplemented';
  return `
  <div class="reco-row" data-ri="${i}" style="border:1px solid var(--border);border-radius:5px;padding:11px 13px;margin-bottom:8px;background:var(--surface2);position:relative;">
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:9px;">
      <span style="font-size:10.5px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:.05em;">Recommandation ${i+1}</span>
      <button type="button" class="btn reco-row-del" data-ri="${i}" style="padding:1px 8px;font-size:11px;color:var(--red);border-color:var(--red-bg);">✕ Supprimer</button>
    </div>
    <div class="frow2"><div class="flbl2">Recommandation</div>
      <textarea class="finp reco-field" name="reco" rows="2" style="resize:vertical;height:54px;" placeholder="Recommandation de l'auditeur…">${r?r.recommandation||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Disposition</div>
      <input class="finp reco-field" name="disposition" placeholder="Mesure corrective prévue…" value="${r?r.disposition||'':''}"></div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Responsable</div>
        <div style="display:flex;flex-direction:column;gap:4px;">
          <select class="finp" id="reco-resp-select" style="appearance:none;">
            <option value="">— Choisir dans la liste —</option>
            ${(RESPONSABLES||[]).map(x=>{const v=x.prenom+' '+x.nom;return '<option value="'+v+'"'+(r&&r.responsable===v?' selected':'')+'>'+ v+(x.fonction?' — '+x.fonction:'')+'</option>';}).join('')}
            ${(r&&r.responsable&&!(RESPONSABLES||[]).find(x=>x.prenom+' '+x.nom===r.responsable))?'<option value="'+(r.responsable||'')+'" selected>'+(r.responsable||'')+'</option>':''}
          </select>
          <input class="finp reco-field" id="reco-resp-manual" name="responsable" placeholder="Ou saisir manuellement…" value="${r?r.responsable||'':''}">
        </div></div>
      <div class="frow2"><div class="flbl2">Fonction / Poste</div>
        <input class="finp reco-field" name="fonction_responsable" placeholder="Ex: Responsable Magasins" value="${r?r.fonction_responsable||'':''}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Échéance</div>
        <input class="finp reco-field" name="echeance" type="date" value="${r?r.echeance||'':''}"></div>
      <div class="frow2"><div class="flbl2">Statut</div>
        <select class="finp reco-field" name="statut" style="appearance:none;">
          <option value="notimplemented"${statut==='notimplemented'?' selected':''}>3- Not Implemented</option>
          <option value="partially"${statut==='partially'?' selected':''}>2- Partially Implemented</option>
          <option value="fully"${statut==='fully'?' selected':''}>1- Fully Implemented</option>
        </select></div>
    </div>
    <div class="fgrid">
      <div class="frow2">
        <div class="flbl2">Avancement : <span class="reco-av-lbl">${av}%</span></div>
        <input type="range" class="reco-field reco-av-range" name="avancement" min="0" max="100" step="5" value="${av}" style="width:100%;margin-top:6px;accent-color:var(--accent);">
      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:2px;">
      <div class="frow2"><div class="flbl2">Date d'échéance révisée</div>
        <input class="finp reco-field" name="echeance_revisee" type="date" value="${r?r.echeance_revisee||'':''}"></div>
      <div class="frow2"><div class="flbl2">Mise à jour fait le</div>
        <input class="finp reco-field" name="mise_a_jour" type="date" value="${r?r.mise_a_jour||'':''}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Alerte</div>
        <select class="finp reco-field" name="alerte" style="appearance:none;">
          <option value=""${(!r||!r.alerte)?' selected':''}>— Aucune —</option>
          <option value="Alerte!!!"${r&&r.alerte==='Alerte!!!'?' selected':''}>⚠️ Alerte</option>
          <option value="Clos"${r&&r.alerte==='Clos'?' selected':''}>✅ Clos</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Appréciation de la preuve</div>
        <select class="finp reco-field" name="appreciation_preuve" style="appearance:none;">
          <option value=""${(!r||!r.appreciation_preuve)?' selected':''}>— Non renseigné —</option>
          <option value="Satisfaisant"${r&&r.appreciation_preuve==='Satisfaisant'?' selected':''}>✅ Satisfaisant</option>
          <option value="Partiellement Satisfaisant"${r&&r.appreciation_preuve==='Partiellement Satisfaisant'?' selected':''}>📂 Partiellement Satisfaisant</option>
          <option value="Pas Satisfaisant"${r&&r.appreciation_preuve==='Pas Satisfaisant'?' selected':''}>❌ Pas Satisfaisant</option>
        </select></div>
    </div>
    <div class="frow2"><div class="flbl2">Explication (Alternative Action / Not Implemented / Revised Date)</div>
      <textarea class="finp reco-field" name="explication" rows="2" style="resize:vertical;height:48px;" placeholder="Explication du statut ou de l'action alternative…">${r?r.explication||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Commentaire de l'auditeur</div>
      <textarea class="finp reco-field" name="commentaire_auditeur" rows="2" style="resize:vertical;height:48px;" placeholder="Observations de l'auditeur sur cette recommandation…">${r?r.commentaire_auditeur||'':''}</textarea></div>
  </div>`;
}
window.RECO_ROW = RECO_ROW;

function SUIVI_FORM(a){
    const isEdit=!!a;
  const recos = isEdit ? (a.recommandations||[]) : [];
  const recoRows = recos.length
    ? recos.map((r,i)=>RECO_ROW(r,i)).join('')
    : RECO_ROW(null,0);   // 1 ligne vide par défaut
  return `

  <div style="background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:5px;padding:10px 13px;margin-bottom:14px;">
    <div style="font-size:11px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px;">📋 Informations du constat</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Société</div>
        <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="ce-societe">
          <option value="">— Sélectionner —</option>
          ${SOCIETES.map(s=>`<option value="${s.nom}"${isEdit&&s.nom===a.societe?' selected':''}>${s.nom}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Réf. Rapport</div>
        <input class="finp" id="ce-ref" placeholder="Ex: MI/03/2025…" value="${isEdit?a.ref||'':''}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Date du Rapport</div>
        <input class="finp" id="ce-date-rapport" type="date" value="${isEdit?a.date_rapport||'':''}"></div>
      <div class="frow2"><div class="flbl2">Cycle</div>
        <input class="finp" id="ce-cycle" placeholder="Ex: Stock, RH, Finance…" value="${isEdit?a.cycle||'':''}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Code Anomalie</div>
        <input class="finp" id="ce-code-anomalie" placeholder="Ex: STK-R6…" value="${isEdit?a.code_anomalie||'':''}"></div>
      <div class="frow2"><div class="flbl2">Intitulé</div>
        <input class="finp" id="ce-intitule" placeholder="Intitulé de l'anomalie…" value="${isEdit?a.intitule||'':''}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Criticité</div>
        <select class="finp" style="appearance:none;" id="ce-criticite">
          <option value="critical"${isEdit&&a.criticite==='critical'?' selected':''}>Critical</option>
          <option value="high"${isEdit&&a.criticite==='high'?' selected':''}>High</option>
          <option value="medium"${!isEdit||a.criticite==='medium'?' selected':''}>Medium</option>
          <option value="low"${isEdit&&a.criticite==='low'?' selected':''}>Low</option>
        </select></div>
    </div>
    <div class="frow2"><div class="flbl2">Description — État actuel du processus (faits &amp; référentiels)</div>
      <textarea class="finp" id="ce-title" rows="3" style="resize:vertical;height:64px;" placeholder="Présentation de l'état actuel du processus audité et explication des critères d'observation…">${isEdit?a.findingTitle||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Causes — Écart entre les critères de référence et les faits</div>
      <textarea class="finp" id="ce-causes" rows="2" style="resize:vertical;height:52px;" placeholder="Explications de l'écart entre les critères de référence et les faits observés…">${isEdit?a.causes||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Conséquences / Risques — Risques liés aux écarts</div>
      <textarea class="finp" id="ce-consequences" rows="2" style="resize:vertical;height:52px;" placeholder="Risques liés aux écarts entre faits et critères de référence…">${isEdit?a.consequences||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Entité / Processus impacté</div>
      <input class="finp" id="ce-impacte" placeholder="Processus / entité impactée…" value="${isEdit?a.impacte||'':''}">
</div>
  </div>

  <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px;">
    <div style="font-size:11px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.06em;">📝 Recommandations</div>
    <button type="button" id="reco-add-inline" class="btn p" style="font-size:11px;padding:3px 10px;">+ Ajouter</button>
  </div>
  <div id="recos-container">${recoRows}</div>`;
}

/* ── Ouvrir le modal en mode "grand" pour le formulaire suivi ── */
function openSuiviModal(title, a){
  _modalLastFocus=document.activeElement;
  $('#modal-title').text(title);
  $('#modal-body').html(SUIVI_FORM(a));
  // Agrandir le modal pour ce formulaire
  $('.modal').css('width','780px');
  $('#mbk').addClass('open');
  _modalWireLabels();
  document.addEventListener('keydown',_modalKeydown);
  setTimeout(function(){
    var $first=$('#mbk').find('input,select,textarea,button').filter(function(){return _elVisible(this);}).first();
    ($first.length?$first:$('#mclose')).trigger('focus');
  },30);
  // Listeners sur les sliders existants
  $(document).on('input.recoav','.reco-av-range',function(){
    $(this).closest('.reco-row').find('.reco-av-lbl').text($(this).val()+'%');
  });
  // Bouton + Ajouter ligne reco
  $(document).on('click.recoadd','#reco-add-inline',function(){
    const n=$('#recos-container .reco-row').length;
    $('#recos-container').append(RECO_ROW(null,n));
  });
  // Bouton supprimer ligne reco
  $(document).on('click.remodel','.reco-row-del',function(){
    const $rows=$('#recos-container .reco-row');
    if($rows.length<=1){toast('error','!','Au moins une recommandation est requise.');return;}
    $(this).closest('.reco-row').remove();
    // Renuméroter
    $('#recos-container .reco-row').each(function(i){
      $(this).attr('data-ri',i);
      $(this).find('span[style*="accent"]').first().text('Recommandation '+(i+1));
      $(this).find('.reco-row-del').attr('data-ri',i);
    });
  });
}

/* ── Fermeture : nettoyer les listeners ── */
function closeSuiviModal(){
  $(document).off('input.recoav click.recoadd click.remodel');
  $('.modal').css('width','');
  closeModal();
}

/* ── Lire les recommandations depuis le DOM ── */
function readRecos(existingRecos){
  const recos=[];
  $('#recos-container .reco-row').each(function(i){
    const $r=$(this);
    const existing = existingRecos ? existingRecos[i] : null;
    const rid = existing ? existing.id : ('R-TMP-'+i);
    const existing2 = existingRecos ? existingRecos[i] : null;
    recos.push({
      id: rid,
      recommandation:       $r.find('[name="reco"]').val()||'',
      disposition:          $r.find('[name="disposition"]').val()||'',
      responsable:          $r.find('[name="responsable"]').val()||'',
      fonction_responsable: $r.find('[name="fonction_responsable"]').val()||'',
      echeance:             $r.find('[name="echeance"]').val()||'',
      echeance_revisee:     $r.find('[name="echeance_revisee"]').val()||'',
      mise_a_jour:          $r.find('[name="mise_a_jour"]').val()||'',
      alerte:               $r.find('[name="alerte"]').val()||'',
      appreciation_preuve:  $r.find('[name="appreciation_preuve"]').val()||'',
      explication:          $r.find('[name="explication"]').val()||'',
      commentaire_auditeur: $r.find('[name="commentaire_auditeur"]').val()||'',
      statut:               $r.find('[name="statut"]').val()||'notimplemented',
      avancement:           parseInt($r.find('[name="avancement"]').val())||0,
      fonction:             existing2 ? existing2.fonction||'' : '',
      deadline_echu:        existing2 ? existing2.deadline_echu||'' : '',
      procedure_suivi:      existing2 ? existing2.procedure_suivi||'' : '',
      statut_label:         existing2 ? existing2.statut_label||'' : '',
      duree:                existing2 ? existing2.duree||'' : '',
      echeance_initiale:    existing2 ? existing2.echeance_initiale||'' : '',
    });
  });
  return recos;
}

$(document).on('click','#actions-new',function(){
  openSuiviModal('Nouveau suivi de recommandations', null);
  $('#msave').data('mode','suivi-new');
});

/* ── Bouton Modifier constat ── */
$(document).on('click','.action-constat-edit-btn',function(){
  const idx=+$(this).data('idx');
  const a=ACTIONS[idx];
  if(!a) return;
  openSuiviModal('Modifier — '+a.ref, a);
  $('#msave').data('mode','suivi-edit').data('idx',idx);
});

/* ── Bouton + Ajouter recommandation (depuis le tableau) ── */
$(document).on('click','.action-reco-add-btn',function(){
  const idx=+$(this).data('idx');
  const a=ACTIONS[idx];
  if(!a) return;
  openSuiviModal('Ajouter une recommandation — '+a.ref, a);
  $('#msave').data('mode','suivi-edit').data('idx',idx);
});

/* ── Bouton Modifier recommandation (depuis le tableau) ── */
$(document).on('click','.action-reco-edit-btn',function(){
  const idx=+$(this).data('idx');
  const a=ACTIONS[idx];
  if(!a) return;
  openSuiviModal('Modifier — '+a.ref, a);
  $('#msave').data('mode','suivi-edit').data('idx',idx);
});

/* ── Bouton Supprimer recommandation ── */
$(document).on('click','.action-reco-del-btn',function(){
  const idx=+$(this).data('idx');
  const ri=+$(this).data('ri');
  const a=ACTIONS[idx];
  if(!a) return;
  const recos=a.recommandations||[];
  if(recos.length<=1){
    if(!confirm('Ceci est la dernière recommandation de ce constat. La supprimer supprimera également tout le constat. Continuer ?')) return;
    ACTIONS.splice(idx,1);
    renderActions();renderW10();dbSave();
    toast('info','🗑','Constat et recommandation supprimés');
    return;
  }
  if(!confirm('Supprimer cette recommandation ?')) return;
  recos.splice(ri,1);
  // Renuméroter les IDs
  recos.forEach((r,i)=>{r.id=a.id+'-R'+(i+1);});
  renderActions();renderW10();dbSave();
  toast('info','🗑','Recommandation supprimée');
});

/* ── Bouton Supprimer constat entier ── */
$(document).on('click','.action-constat-del-btn',function(){
  const idx=+$(this).data('idx');
  const a=ACTIONS[idx];
  if(!a) return;
  if(!confirm(`Supprimer tout le constat « ${a.findingTitle||a.ref||a.id} » et toutes ses recommandations ?`)) return;
  ACTIONS.splice(idx,1);
  renderActions();renderW10();dbSave();
  toast('info','🗑','Constat supprimé');
});

/* ══════════════════════════════════════════════════════════
   RCM_CYCLES — source unique partagée entre Nouvel Audit et RCM
   ══════════════════════════════════════════════════════════ */
function AFORM(a){
    const isEdit=!!a;
  const today=new Date().toISOString().slice(0,10);
  const yy=String(new Date().getFullYear()).slice(-2);
  // Calcul du prochain numéro de dossier par catégorie (format ARB-XX-[Filiale]-[NN]-[yy])
  function _nextNum(cat){
    const prefix={'plan_audit':'ARB-PA-','mission_speciale':'ARB-MS-','mission_controle':'ARB-MC-'}[cat]||'ARB-PA-';
    const existing=AUDITS.filter(x=>(x.missionCategory||'plan_audit')===cat&&x.ref&&x.ref.startsWith(prefix));
    if(!existing.length) return '01';
    const nums=existing.map(x=>{
      const parts=x.ref.split('-');
      const n=parseInt(parts[3]||parts[2]||'0',10);
      return isNaN(n)?0:n;
    });
    return String(Math.max(...nums)+1).padStart(2,'0');
  }
  const defaultCat=isEdit?(a.missionCategory||'plan_audit'):'plan_audit';
  const prefixMap={'plan_audit':'ARB-PA-','mission_speciale':'ARB-MS-','mission_controle':'ARB-MC-'};
  const defaultRef=isEdit?a.ref||'':( prefixMap[defaultCat]+'[Filiale]-'+_nextNum(defaultCat)+'-'+yy );

  // Période sous revue : décomposer si déjà renseignée (format "MM/AAAA")
  const psr = isEdit&&a.periodeRevue ? a.periodeRevue : {debMois:'',debAnnee:'',finMois:'',finAnnee:''};
  const _mm = ['01','02','03','04','05','06','07','08','09','10','11','12'];
  const _mmlbl = ['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
  const _mmOpts = (sel)=>_mm.map((m,i)=>`<option value="${m}"${sel===m?' selected':''}>${_mmlbl[i]}</option>`).join('');
  const _curY = new Date().getFullYear();
  const _yrOpts = (sel)=>[...[...' '.repeat(10)].map((_,i)=>_curY-5+i)].map(y=>`<option value="${y}"${String(sel)===String(y)||(!sel&&y===_curY)?' selected':''}>${y}</option>`).join('');

  return `

  <!-- ══════════════════════════════════════
       📋 TERMES DE RÉFÉRENCE (TDR) — EN TÊTE
       ══════════════════════════════════════ -->
  <div style="background:linear-gradient(90deg,var(--accent-bg),var(--surface));border:1px solid rgba(0,112,242,.25);border-left:3px solid var(--accent);border-radius:6px;padding:10px 14px;margin-bottom:14px;display:flex;align-items:center;gap:8px;">
    <span style="font-size:14px;">📋</span>
    <span style="font-size:11.5px;font-weight:700;color:var(--accent);letter-spacing:.02em;">Termes de Référence (TDR)</span>
    <span style="font-size:10px;color:var(--text-muted);margin-left:2px;">— Renseignez d'abord les éléments de cadrage</span>
  </div>

  <div class="frow2">
    <div class="flbl2">Plan d'Audit — Réf.</div>
    <input class="finp" id="f-plan-ref" placeholder="Ex: PA-2026-01" value="${isEdit?a.planRef||'':''}">
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:5px;padding:10px 12px;margin-bottom:13px;">
    <div style="font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px;">1. Contexte et Justification</div>
    <textarea class="finp" id="f-contexte" rows="3" style="resize:vertical;height:72px;" placeholder="Décrire le contexte et la justification de la mission…">${isEdit?a.contexte||'':''}</textarea>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:5px;padding:10px 12px;margin-bottom:13px;">
    <div style="font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px;">2. Objectifs de la Mission</div>
    <div class="flbl2" style="margin-bottom:4px;">Objectif général</div>
    <textarea class="finp" id="f-obj-general" rows="2" style="resize:vertical;height:54px;margin-bottom:8px;" placeholder="Objectif général de la mission…">${isEdit?a.objGeneral||'':''}</textarea>
    <div class="flbl2" style="margin-bottom:4px;">Objectifs spécifiques</div>
    <textarea class="finp" id="f-obj-specifiques" rows="3" style="resize:vertical;height:72px;" placeholder="- Objectif 1&#10;- Objectif 2&#10;- Objectif 3">${isEdit?a.objSpecifiques||'':''}</textarea>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:5px;padding:10px 12px;margin-bottom:13px;">
    <div style="font-size:10px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.05em;margin-bottom:8px;">3. Périmètre de la Mission</div>
    <div class="flbl2" style="margin-bottom:4px;">Direction et Service Concernés</div>
    <input class="finp" id="f-services" placeholder="Ex: Production, Magasin, Logistique, Finance" value="${isEdit?a.services||'':''}" style="margin-bottom:12px;">

    <!-- Période sous revue -->
    <div class="flbl2" style="margin-bottom:6px;">Période sous revue <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel)</span></div>
    <div style="display:grid;grid-template-columns:1fr auto 1fr;align-items:center;gap:8px;margin-bottom:6px;">
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">
        <select class="finp" id="f-psr-deb-mois" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;font-size:11.5px;padding:5px 24px 5px 8px;">
          <option value="">Mois</option>${_mmOpts(psr.debMois)}
        </select>
        <select class="finp" id="f-psr-deb-an" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;font-size:11.5px;padding:5px 24px 5px 8px;">
          <option value="">Année</option>${_yrOpts(psr.debAnnee)}
        </select>
      </div>
      <span style="font-size:11px;color:var(--text-muted);font-weight:600;white-space:nowrap;padding:0 2px;">→</span>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;">
        <select class="finp" id="f-psr-fin-mois" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;font-size:11.5px;padding:5px 24px 5px 8px;">
          <option value="">Mois</option>${_mmOpts(psr.finMois)}
        </select>
        <select class="finp" id="f-psr-fin-an" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;font-size:11.5px;padding:5px 24px 5px 8px;">
          <option value="">Année</option>${_yrOpts(psr.finAnnee)}
        </select>
      </div>
    </div>
    <div id="f-psr-preview" style="font-size:10.5px;color:var(--accent);font-weight:600;margin-bottom:6px;min-height:16px;"></div>
    <div style="display:flex;align-items:center;gap:8px;">
      <div style="font-size:9.5px;font-weight:700;color:var(--text-muted);text-transform:uppercase;letter-spacing:.06em;white-space:nowrap;">Durée :</div>
      <input class="finp" id="f-psr-duree" type="number" min="1" max="120" placeholder="—"
        value="${(()=>{const p=isEdit&&a.periodeRevue?a.periodeRevue:{};return p.dureeM||'';})()}"
        style="width:72px;text-align:center;font-weight:700;font-family:var(--mono);font-size:12px;padding:4px 8px;">
      <span style="font-size:11.5px;color:var(--text-muted);font-weight:600;">mois</span>
      <span id="f-psr-duree-auto" style="font-size:10px;color:var(--text-dim);font-style:italic;margin-left:4px;"></span>
    </div>
  </div>

  <!-- ══════════════════════════════════════
       POINTS FORTS CONSTATÉS
       ══════════════════════════════════════ -->
  <div style="border-top:1px solid var(--border);margin:14px 0 10px;padding-top:12px;">
    <div class="flbl2" style="margin-bottom:4px;">✅ Points Forts Constatés <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(une ligne par point : Processus | Point Fort | Impact)</span></div>
    <textarea class="finp" id="f-points-forts" rows="4" style="resize:vertical;height:90px;font-size:11.5px;font-family:var(--mono);" placeholder="Gestion des Achats | Numérisation à 100% des validations | Réduction des délais de 5 jours&#10;Ressources Humaines | Onboarding automatisé | Conformité des dossiers&#10;Sécurité Informatique | 98% au test phishing | Forte culture de vigilance">${isEdit?a.pointsForts||'':''}</textarea>
  </div>

  <!-- ══════════════════════════════════════
       SÉPARATEUR — INFOS PLANIFICATION
       ══════════════════════════════════════ -->
  <div style="border-top:2px solid var(--border);margin:2px 0 14px;"></div>
  <div style="font-size:10.5px;font-weight:700;color:var(--text-muted);margin-bottom:12px;display:flex;align-items:center;gap:6px;text-transform:uppercase;letter-spacing:.04em;">🗂 Identification &amp; Planification</div>

  <input type="hidden" id="f-mission-category" value="${defaultCat}">
  <div class="fgrid">
    <div class="frow2">
      <div class="flbl2">Référence <span style="color:var(--red);font-weight:700;" title="Champ obligatoire">*</span></div>
      <input class="finp" id="f-ref" placeholder="ARB-PA-[Filiale]-[NN]-[yy]" value="${defaultRef}">
      <div id="f-ref-hint" style="font-size:10px;color:var(--text-muted);margin-top:3px;">
        Format : <code style="background:var(--surface3);padding:1px 4px;border-radius:3px;">ARB-PA-[Filiale]-<em>NN</em>-${yy}</code>
      </div>
    </div>
    <div class="frow2"><div class="flbl2">Statut</div>
      <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-status">
        ${Object.entries(AUDIT_STATUS_LABELS).map(([k,v])=>`<option value="${k}"${(isEdit?a.status:'')=== k?' selected':(!isEdit&&k==='planned'?' selected':'')}>  ${v}</option>`).join('')}
      </select></div>
  </div>
  <div class="fgrid">
    <div class="frow2"><div class="flbl2">Type d'audit</div>
      <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-type">
        ${['Assurance','Conseil (Advisory)','Conformité (Compliance)','Audit Opérationnel','Audit Financier','Audit IT / Systèmes','Fraude / Investigation','Gouvernance','Gestion des Risques','Organisation','Formation','Autres'].map(t=>`<option${isEdit&&a.type===t?' selected':''}>${t}</option>`).join('')}
      </select></div>
    <div class="frow2"><div class="flbl2">Risque</div>
      <select class="finp" style="appearance:none;" id="f-risk">
        ${['critical','high','medium','low'].map(r=>`<option value="${r}"${(isEdit?a.risk:'')=== r?' selected':(!isEdit&&r==='medium'?' selected':'')}>  ${r.charAt(0).toUpperCase()+r.slice(1)}</option>`).join('')}
      </select></div>
  </div>
  <div class="frow2">
    <div class="flbl2">Intitulé <span style="color:var(--red);font-weight:700;" title="Champ obligatoire">*</span></div>
    <input class="finp" id="f-title" placeholder="Ex: Audit des achats 2026" value="${isEdit?a.title||'':''}">
  </div>
  <div class="frow2">
    <div class="flbl2">Société auditée <span style="color:var(--red);font-weight:700;" title="Champ obligatoire">*</span></div>
    <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-societe">
      <option value="">— Sélectionner une société —</option>
      ${SOCIETES.map(s=>`<option value="${s.nom}"${isEdit&&s.nom===a.societe?' selected':''}>${s.nom}</option>`).join('')}
    </select>
  </div>
  <div class="fgrid">
    <div class="frow2">
      <div class="flbl2">Date de début <span style="color:var(--red);font-weight:700;" title="Champ obligatoire">*</span></div>
      <input class="finp" id="f-start" type="date" value="${isEdit?a.start||'':today}">
    </div>
    <div class="frow2">
      <div class="flbl2">Date de fin <span style="color:var(--red);font-weight:700;" title="Champ obligatoire">*</span></div>
      <input class="finp" id="f-end" type="date" value="${isEdit?a.end||'':today}">
    </div>
  </div>
  <div id="f-duree-banner" style="display:flex;align-items:center;gap:8px;padding:6px 10px;background:var(--accent-bg);border:1px solid rgba(0,112,242,.2);border-radius:5px;margin-bottom:13px;font-size:11.5px;color:var(--accent);font-weight:600;">
    <span>📅</span>
    <span id="f-duree-txt">—</span>
    <span style="font-size:10px;font-weight:400;color:var(--text-muted);">(jours ouvrés lun–ven, hors week-ends)</span>
  </div>
  <div class="fgrid">
    <div class="frow2">
      <div class="flbl2">Début réel <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel)</span></div>
      <input class="finp" id="f-actual-start" type="date" value="${isEdit?a.actual_start||'':''}" placeholder="jj/mm/aaaa">
    </div>
    <div class="frow2">
      <div class="flbl2">Fin réelle <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel)</span></div>
      <input class="finp" id="f-actual-end" type="date" value="${isEdit?a.actual_end||'':''}" placeholder="jj/mm/aaaa">
    </div>
  </div>
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:10px;">
    <div class="frow2">
      <div class="flbl2">Lieu de la mission</div>
      <input class="finp" id="f-lieu" type="text" value="${isEdit?a.lieu||'':''}" placeholder="Ex. : Siège social, Site de production…">
    </div>
    <div class="frow2">
      <div class="flbl2">Statut du document</div>
      <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-statut-doc">
        <option value="Projet de rapport"${(isEdit?a.statut_doc:'Projet de rapport')==='Projet de rapport'?' selected':''}>📝 Projet de rapport</option>
        <option value="Rapport provisoire"${(isEdit?a.statut_doc:'')==='Rapport provisoire'?' selected':''}>🔄 Rapport provisoire</option>
        <option value="Rapport définitif"${(isEdit?a.statut_doc:'')==='Rapport définitif'?' selected':''}>✅ Rapport définitif</option>
      </select>
    </div>
  </div>
  <div class="frow2"><div class="flbl2">Niveau de difficulté</div>
    <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-difficulte">
      <option value="facile"${(isEdit?a.difficulte:'')==='facile'?' selected':''}>✅ Facile</option>
      <option value="moyenne"${(isEdit&&a.difficulte==='moyenne')||(!isEdit)?' selected':''}>🟡 Moyenne</option>
      <option value="difficile"${(isEdit?a.difficulte:'')==='difficile'?' selected':''}>🔴 Difficile</option>
      <option value="très difficile"${(isEdit?a.difficulte:'')==='très difficile'?' selected':''}>💀 Très difficile</option>
    </select>
  </div>
  <div class="frow2">
    <div class="flbl2">Cycle Opérationnel / Processus <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel)</span></div>
    <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-cycle">
      <option value="">— Sélectionner un cycle —</option>
      ${Object.keys(RCM_CYCLES).map(c=>`<option value="${c}"${isEdit&&a.cycle===c?' selected':''}>${c}</option>`).join('')}
      <option value="Autre (préciser)"${isEdit&&a.cycle==='Autre (préciser)'?' selected':''}>Autre (préciser ci-dessous)</option>
    </select>
    <input class="finp" id="f-cycle-custom" placeholder="Préciser si Autre…" value="${isEdit&&a.cycle_custom?a.cycle_custom:''}" style="margin-top:5px;display:${isEdit&&a.cycle==='Autre (préciser)'?'block':'none'};">
    <div style="margin-top:7px;">
      <div class="flbl2" style="margin-bottom:4px;">Cycles additionnels <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel — choix multiple, en plus du cycle ci-dessus)</span></div>
      <div id="f-cycles-multi" style="display:flex;flex-wrap:wrap;gap:8px;border:1px solid var(--border);border-radius:6px;padding:8px 10px;background:var(--surface2);max-height:110px;overflow-y:auto;">
        ${Object.keys(RCM_CYCLES).map(c=>`<label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;"><input type="checkbox" class="f-cycle-multi-cb" value="${c}"${isEdit&&(a.cycles_multi||[]).indexOf(c)>=0?' checked':''} style="accent-color:var(--accent);"> ${c}</label>`).join('')}
      </div>
    </div>
  </div>
  <div class="frow2">
    <div class="flbl2">Avancement : <span id="f-prog-lbl" style="color:var(--accent);font-weight:700;">${isEdit?a.progress||0:0}%</span></div>
    <input type="range" id="f-progress" min="0" max="100" step="5" value="${isEdit?a.progress||0:0}" style="width:100%;margin-top:8px;accent-color:var(--accent);">
    <div style="display:flex;justify-content:space-between;font-size:9px;color:var(--text-dim);margin-top:2px;"><span>0%</span><span>25%</span><span>50%</span><span>75%</span><span>100%</span></div>
  </div>

  <!-- ── Équipe d'audit ── -->
  <div style="border-top:2px solid var(--border);margin:6px 0 14px;"></div>
  <div style="font-size:10.5px;font-weight:700;color:var(--text-muted);margin-bottom:12px;display:flex;align-items:center;gap:6px;text-transform:uppercase;letter-spacing:.04em;">👥 Équipe d'audit</div>

  <div class="frow2">
    <div class="flbl2">Chef de mission</div>
    <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-auditor">
      <option value="">— Sélectionner un chef de mission —</option>
      ${(AUDITEURS||[]).map(u=>{const v=u.prenom+' '+u.nom;return `<option value="${v}"${isEdit&&a.auditor===v?' selected':''}>${v}${u.poste?' — '+u.poste:''}</option>`;}).join('')}
    </select>
  </div>

  <div class="frow2">
    <div class="flbl2">Supervision <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel)</span></div>
    <select class="finp" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;" id="f-superviseur">
      <option value="">— Sélectionner un superviseur —</option>
      ${(AUDITEURS||[]).map(u=>{const v=u.prenom+' '+u.nom;return `<option value="${v}"${isEdit&&a.superviseur===v?' selected':''}>${v}${u.poste?' — '+u.poste:''}</option>`;}).join('')}
    </select>
  </div>

  <div class="frow2">
    <div class="flbl2">Membres de l'équipe <span style="font-size:9px;color:var(--text-muted);font-weight:400;">(optionnel)</span></div>
    <div id="f-equipe-list" style="display:flex;flex-direction:column;gap:5px;max-height:160px;overflow-y:auto;background:var(--surface2);border:1px solid var(--border);border-radius:4px;padding:7px 10px;">
      ${(AUDITEURS||[]).length===0
        ? `<div style="font-size:11px;color:var(--text-dim);font-style:italic;">Aucun auditeur enregistré — ajoutez-en dans Configuration.</div>`
        : (AUDITEURS||[]).map(u=>{
            const v=u.prenom+' '+u.nom;
            const checked=isEdit&&Array.isArray(a.equipe)&&a.equipe.includes(v);
            return `<label style="display:flex;align-items:center;gap:8px;font-size:12px;cursor:pointer;padding:2px 0;">
              <input type="checkbox" class="f-equipe-cb" value="${v}"${checked?' checked':''} style="width:14px;height:14px;accent-color:var(--accent);cursor:pointer;">
              <span style="font-weight:500;">${v}</span>${u.poste?`<span style="font-size:10px;color:var(--text-muted);">— ${u.poste}</span>`:''}
            </label>`;
          }).join('')
      }
    </div>
    <div id="f-equipe-preview" style="font-size:10.5px;color:var(--accent);font-weight:600;margin-top:5px;min-height:16px;"></div>
  </div>

  <div style="font-size:10px;color:var(--text-dim);margin-top:6px;"><span style="color:var(--red);font-weight:700;">*</span> Champs obligatoires</div>`;
}

function _updateRefFromCategory(cat){
  const prefixMap={'plan_audit':'ARB-PA-','mission_speciale':'ARB-MS-','mission_controle':'ARB-MC-'};
  const hintMap={
    'plan_audit':      'Format : <code style="background:var(--surface3);padding:1px 4px;border-radius:3px;">ARB-PA-[Filiale]-<em>NN</em>-'+String(new Date().getFullYear()).slice(-2)+'</code>',
    'mission_speciale':'Format : <code style="background:var(--surface3);padding:1px 4px;border-radius:3px;">ARB-MS-[Filiale]-<em>NN</em>-'+String(new Date().getFullYear()).slice(-2)+'</code>',
    'mission_controle':'Format : <code style="background:var(--surface3);padding:1px 4px;border-radius:3px;">ARB-MC-[Filiale]-<em>NN</em>-'+String(new Date().getFullYear()).slice(-2)+'</code>',
  };
  const prefix=prefixMap[cat]||'ARB-PA-';
  const yy=String(new Date().getFullYear()).slice(-2);
  // Calculer le prochain numéro
  const existing=AUDITS.filter(x=>(x.missionCategory||'plan_audit')===cat&&x.ref&&x.ref.startsWith(prefix));
  const nums=existing.map(x=>{
    const parts=x.ref.split('-');
    const n=parseInt(parts[3]||parts[2]||'0',10);
    return isNaN(n)?0:n;
  });
  const max=nums.length?Math.max(...nums):0;
  const nn=String(max+1).padStart(2,'0');
  // Récupérer la société sélectionnée pour l'insérer dans la référence
  const socVal=$('#f-societe').val()||'';
  const socCode=socVal
    ? (socVal.length<=10 ? socVal : socVal.replace(/\s+/g,'').slice(0,8).toUpperCase())
    : '[Filiale]';
  // Mettre à jour le champ seulement si l'utilisateur n'a pas encore modifié
  const $ref=$('#f-ref');
  const val=$ref.val();
  const isDefault= !val || /^ARB-(PA|MS|MC)-/.test(val);
  if(isDefault) $ref.val(prefix+socCode+'-'+nn+'-'+yy);
  $('#f-ref-hint').html(hintMap[cat]||hintMap['plan_audit']);
}

$(document).on('click','.audits-new-cat',function(){
  const cat=$(this).data('category')||'plan_audit';
  openModal('Nouvel audit',AFORM(null));
  // Pré-sélectionner la catégorie selon le bouton cliqué
  $('#f-mission-category').val(cat);
  // Mettre à jour la référence et le hint selon la catégorie pré-sélectionnée
  _updateRefFromCategory(cat);
  // Réagir aux changements de catégorie dans le formulaire
  $(document).off('change.catref').on('change.catref','#f-mission-category',function(){
    _updateRefFromCategory($(this).val());
  });
  // Réagir au changement de société pour mettre à jour la référence
  $(document).off('change.socref').on('change.socref','#f-societe',function(){
    _updateRefFromCategory($('#f-mission-category').val()||'plan_audit');
  });
  $('#msave').data('mode','audit-new');
  $('#f-progress').on('input',function(){$('#f-prog-lbl').text($(this).val()+'%');});
  // Live-preview Période sous revue
  function _updatePsrPreview(){
    const mm=['','Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
    const dm=$('#f-psr-deb-mois').val(), da=$('#f-psr-deb-an').val();
    const fm=$('#f-psr-fin-mois').val(), fa=$('#f-psr-fin-an').val();
    const dStr=(dm&&da)?mm[parseInt(dm,10)]+' '+da:'';
    const fStr=(fm&&fa)?mm[parseInt(fm,10)]+' '+fa:'';
    if(dStr||fStr) $('#f-psr-preview').html('📅 '+(dStr||'…')+' → '+(fStr||'…'));
    else $('#f-psr-preview').html('');
    // Calcul automatique de la durée en mois
    if(dm&&da&&fm&&fa){
      const totalDeb=parseInt(da,10)*12+parseInt(dm,10);
      const totalFin=parseInt(fa,10)*12+parseInt(fm,10);
      const diff=totalFin-totalDeb+1;
      if(diff>0){
        const $dur=$('#f-psr-duree');
        if(!$dur.data('manual')) $dur.val(diff);
        $('#f-psr-duree-auto').text(diff>0?'(calculé automatiquement)':'');
      }
    }
  }
  $(document).on('change.psr','#f-psr-deb-mois,#f-psr-deb-an,#f-psr-fin-mois,#f-psr-fin-an',_updatePsrPreview);
  $(document).on('input.psrman','#f-psr-duree',function(){ $(this).data('manual',true); $('#f-psr-duree-auto').text(''); });
  _updatePsrPreview();
  // Live-preview équipe d'audit
  function _updateEquipePreview(){
    const chef=$('#f-auditor').val();
    const sup=$('#f-superviseur').val();
    const membres=[...document.querySelectorAll('.f-equipe-cb:checked')].map(cb=>cb.value);
    const parts=[];
    if(sup) parts.push('🔍 '+sup+' (supervision)');
    if(chef) parts.push('👤 '+chef+' (chef)');
    membres.filter(m=>m!==chef&&m!==sup).forEach(m=>parts.push(m));
    $('#f-equipe-preview').text(parts.length ? parts.join(' · ') : '');
  }
  $(document).on('change.equipe','#f-auditor,#f-superviseur,.f-equipe-cb',_updateEquipePreview);
  _updateEquipePreview();
  $(document).on('change','#f-cycle',function(){
    const v=$(this).val();
    $('#f-cycle-custom').css('display', v==='Autre (préciser)' ? 'block' : 'none');
  });
  $(document).off('click.addrcmfromaudit');
  _attachAuditDureeHandler();
});

function _attachAuditDureeHandler(){
  function _calcDuree(){
    const s=$('#f-start').val(), e=$('#f-end').val();
    const $txt=$('#f-duree-txt'), $ban=$('#f-duree-banner');
    if(!s||!e){ $txt.text('Saisissez les deux dates'); $ban.css({background:'var(--surface2)',borderColor:'var(--border)',color:'var(--text-muted)'}); return; }
    const d1=new Date(s), d2=new Date(e);
    if(isNaN(d1)||isNaN(d2)||d2<d1){ $txt.text('⚠ Date de fin antérieure au début'); $ban.css({background:'var(--red-bg)',borderColor:'var(--red)',color:'var(--red)'}); return; }
    let c=0, cur=new Date(d1);
    while(cur<=d2){const dw=cur.getDay();if(dw!==0&&dw!==6)c++;cur.setDate(cur.getDate()+1);}
    const semaines = (c/5).toFixed(1).replace('.0','');
    const extra = c>=5 ? ` — ${semaines} sem.` : '';
    $txt.text(`Durée : ${c} jour${c>1?'s':''} ouvré${c>1?'s':''}${extra}`);
    const col = c<=5?'var(--green)':c<=20?'var(--accent)':c<=60?'var(--yellow)':'var(--orange)';
    const bg  = c<=5?'var(--green-bg)':c<=20?'var(--accent-bg)':c<=60?'var(--yellow-bg)':'var(--orange-bg)';
    $ban.css({background:bg, borderColor:col, color:col});
  }
  $(document).on('change.fduree','#f-start,#f-end', _calcDuree);
  _calcDuree();
}

// ── Association RCM/TAF ↔ Cycle(s) Opérationnel(s) du Plan d'audit interne ──
// Déclenché quand une mission passe au statut « Ouverte » : toutes les entrées RCM et TAF
// dont le Cycle/Catégorie correspond à l'un des Cycles Opérationnels/Processus de la mission
// (cycle principal + cycles additionnels, tous deux optionnels) sont rattachées à celle-ci
// (via un tableau audit_refs), pour tracer Plan d'audit → RCM/TAF.
function _auditCycleLabel(a){
  if(!a) return '';
  return (a.cycle==='Autre (préciser)' ? (a.cycle_custom||'') : (a.cycle||'')).trim();
}

// Retourne la liste complète (dédupliquée) des cycles associés à une mission : cycle principal + cycles additionnels
function _auditAllCycleLabels(a){
  if(!a) return [];
  const list=[];
  const primary=_auditCycleLabel(a);
  if(primary) list.push(primary);
  (a.cycles_multi||[]).forEach(function(c){ if(c && list.indexOf(c)<0) list.push(c); });
  return list;
}

function linkRCMTAFToOpenedAudit(a){
  const cycleLbls = _auditAllCycleLabels(a);
  if(!a || !cycleLbls.length) return; // aucun cycle renseigné (optionnel) → rien à associer
  const cycleLcSet = cycleLbls.map(function(c){ return c.toLowerCase(); });
  const socLc = (a.societe||'').trim().toLowerCase();
  let nbRCM=0, nbTAF=0;

  (typeof RCM_DATA!=='undefined' ? RCM_DATA : []).forEach(function(r){
    if(cycleLcSet.indexOf((r.cycle||'').trim().toLowerCase())<0) return;
    // Filtre société si les deux côtés en ont une renseignée (évite les faux rapprochements inter-filiales)
    if(socLc && r.filiale && r.filiale!=='Toutes filiales' && r.filiale.trim().toLowerCase()!==socLc) return;
    if(!Array.isArray(r.audit_refs)) r.audit_refs=[];
    if(r.audit_refs.indexOf(a.ref)<0){ r.audit_refs.push(a.ref); nbRCM++; }
  });

  (typeof TAF_ITEMS!=='undefined' ? TAF_ITEMS : []).forEach(function(t){
    const cat=(t.categorie||'').trim().toLowerCase();
    if(!cat) return;
    // categorie contient souvent « Cycle / Processus » (cf. tafApplyRCMLink) → égalité ou préfixe « cycle / »
    const matches = cycleLcSet.some(function(cycleLc){ return cat===cycleLc || cat.indexOf(cycleLc+' /')===0 || cat.indexOf(cycleLc+' -')===0; });
    if(!matches) return;
    if(socLc && t.societe && t.societe.trim().toLowerCase()!==socLc) return;
    if(!Array.isArray(t.audit_refs)) t.audit_refs=[];
    if(t.audit_refs.indexOf(a.ref)<0){ t.audit_refs.push(a.ref); nbTAF++; }
  });

  if(nbRCM || nbTAF){
    dbSave();
    if(typeof tafSave==='function') tafSave();
    if(isViewVisible('view-rcm')) tryRender(()=>renderRCM());
    if(isViewVisible('view-taf')) tryRender(()=>renderTAF());
    toast('success','🔗','Mission '+a.ref+' ouverte → '+nbRCM+' RCM et '+nbTAF+' TAF associé(s) au(x) cycle(s) « '+cycleLbls.join(', ')+' ».');
  }
}

$('#msave').on('click',function(){
  const mode=$(this).data('mode');

  if(mode==='om-save'){ saveOM(+$(this).data('idx')); return; }
  if(mode==='om-preview-print'){ printOM(ORDRES_MISSION[+$(this).data('omref')]); closeModal(); return; }

  if(mode==='absence-save'){
    $(this).removeData('mode').text('Enregistrer');
    if(typeof window._absenceSaveHandler==='function') window._absenceSaveHandler();
    return;
  }

  if(mode==='audit-edit'){
    const idx=$('#mbk').data('auditEditIdx');
    if(idx===undefined||idx===null) return;
    const prevStatus=(AUDITS[idx]||{}).status;
    const quick=$('#mbk').data('auditQuick');
    if(quick){
      AUDITS[idx].status=$('#aq-status').val();
      AUDITS[idx].progress=parseInt($('#aq-progress').val());
      $(document).off('click.aqstat input.aqprog click.aqpreset');
      $('#mbk').data('auditQuick',false);
    } else if($('#f-title').length){
      const errs=[];
      const $ref=$('#f-ref'), $title=$('#f-title'), $soc=$('#f-societe'), $start=$('#f-start'), $end=$('#f-end');
      [$ref,$title,$soc,$start,$end].forEach($f=>$f.css('border-color',''));
      if(!$ref.val().trim()){errs.push('Référence');$ref.css('border-color','var(--red)');}
      if(!$title.val().trim()){errs.push('Intitulé');$title.css('border-color','var(--red)');}
      if(!$soc.val()){errs.push('Société auditée');$soc.css('border-color','var(--red)');}
      if(!$start.val()){errs.push('Date de début');$start.css('border-color','var(--red)');}
      if(!$end.val()){errs.push('Date de fin');$end.css('border-color','var(--red)');}
      if(errs.length){$('#aform-error').html('⚠ Champs obligatoires manquants : <strong>'+errs.join(', ')+'</strong>').show();return;}
      AUDITS[idx].ref=$ref.val().trim()||AUDITS[idx].ref;
      AUDITS[idx].title=$title.val().trim()||AUDITS[idx].title;
      AUDITS[idx].societe=$soc.val()||AUDITS[idx].societe;
      AUDITS[idx].start=$start.val()||AUDITS[idx].start;
      AUDITS[idx].end=$end.val()||AUDITS[idx].end;
      AUDITS[idx].type=$('#f-type').val();
      AUDITS[idx].missionCategory=$('#f-mission-category').val()||'plan_audit';
      AUDITS[idx].risk=$('#f-risk').val();
      AUDITS[idx].difficulte=$('#f-difficulte').val()||AUDITS[idx].difficulte||'moyenne';
      AUDITS[idx].status=$('#f-status').val();
      AUDITS[idx].objectifs=$('#f-objectifs').val();
      AUDITS[idx].cycle=$('#f-cycle').val()||AUDITS[idx].cycle||'';
      AUDITS[idx].cycle_custom=$('#f-cycle-custom').val()||AUDITS[idx].cycle_custom||'';
      AUDITS[idx].cycles_multi=[...document.querySelectorAll('.f-cycle-multi-cb:checked')].map(cb=>cb.value);
      AUDITS[idx].progress=parseInt($('#f-progress').val());
      AUDITS[idx].actual_start=$('#f-actual-start').val()||AUDITS[idx].actual_start||'';
      AUDITS[idx].actual_end=$('#f-actual-end').val()||AUDITS[idx].actual_end||'';
      AUDITS[idx].lieu=$('#f-lieu').val()||AUDITS[idx].lieu||'';
      AUDITS[idx].statut_doc=$('#f-statut-doc').val()||AUDITS[idx].statut_doc||'Projet de rapport';
      AUDITS[idx].planRef=$('#f-plan-ref').val()||AUDITS[idx].planRef||'';
      AUDITS[idx].contexte=$('#f-contexte').val()||AUDITS[idx].contexte||'';
      AUDITS[idx].objGeneral=$('#f-obj-general').val()||AUDITS[idx].objGeneral||'';
      AUDITS[idx].objSpecifiques=$('#f-obj-specifiques').val()||AUDITS[idx].objSpecifiques||'';
      AUDITS[idx].services=$('#f-services').val()||AUDITS[idx].services||'';
      AUDITS[idx].perimetreFonc=$('#f-perimetre-fonc').val()||AUDITS[idx].perimetreFonc||'';
      AUDITS[idx].pointsForts=$('#f-points-forts').val()||AUDITS[idx].pointsForts||'';
      AUDITS[idx].periodeRevue={
        debMois:$('#f-psr-deb-mois').val()||'',
        debAnnee:$('#f-psr-deb-an').val()||'',
        finMois:$('#f-psr-fin-mois').val()||'',
        finAnnee:$('#f-psr-fin-an').val()||'',
        dureeM:parseInt($('#f-psr-duree').val())||''
      };
      AUDITS[idx].auditor=$('#f-auditor').val()||AUDITS[idx].auditor||'';
      AUDITS[idx].superviseur=$('#f-superviseur').val()||AUDITS[idx].superviseur||'';
      AUDITS[idx].equipe=[...document.querySelectorAll('.f-equipe-cb:checked')].map(cb=>cb.value);
    } else { return; }
    const _a=AUDITS[idx];
    if(_a&&_a.status==='open') tryRender(()=>injectDomV_IIA(_a.ref));
    if(_a&&_a.status==='open'&&prevStatus!=='open') tryRender(()=>linkRCMTAFToOpenedAudit(_a));
    $('#mbk').removeData('auditEditIdx');
    closeModal();
    tryRender(()=>syncMissionsFromAudits(_a&&_a.ref));
