const DOW_LABELS = ['Dim','Lun','Mar','Mer','Jeu','Ven','Sam'];
const DOW_FULL   = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi'];

function recurrenceLabel(t){
  if(!t.permanent) return t.date||'—';
  if(t.recurrenceType==='dow' && t.recurrenceDow && t.recurrenceDow.length){
    return '↻ ' + t.recurrenceDow.map(d=>DOW_LABELS[d]).join(', ');
  }
  if(t.recurrenceType==='dom' && t.recurrenceDom && t.recurrenceDom.length){
    return '↻ ' + t.recurrenceDom.map(d=>d===0?'Dernier j.':`${d}`).join(', ');
  }
  return '∞ Récurrent';
}

function nextOccurrence(t){
  if(!t.permanent) return null;
  const now = new Date(); now.setHours(0,0,0,0);
  if(t.recurrenceType==='dow' && t.recurrenceDow && t.recurrenceDow.length){
    const days = [...t.recurrenceDow].sort((a,b)=>a-b);
    for(let i=0;i<7;i++){
      const d=new Date(now); d.setDate(now.getDate()+i);
      if(days.includes(d.getDay())) return d;
    }
    return null;
  }
  if(t.recurrenceType==='dom' && t.recurrenceDom && t.recurrenceDom.length){
    const doms = [...t.recurrenceDom].sort((a,b)=>a-b);
    const y=now.getFullYear(), m=now.getMonth();

    for(let mo=0;mo<=1;mo++){
      const yr = m+mo>11?y+1:y, mn = (m+mo)%12;
      const lastDay = new Date(yr,mn+1,0).getDate();
      for(const dom of doms){
        const day = dom===0?lastDay:Math.min(dom,lastDay);
        const d = new Date(yr,mn,day);
        if(d>=now) return d;
      }
    }
    return null;
  }
  return null;
}

function fmtDate(d){
  if(!d||isNaN(d)) return '—';
  return String(d.getDate()).padStart(2,'0')+'/'+String(d.getMonth()+1).padStart(2,'0')+'/'+d.getFullYear();
}

let DAILY_TASKS = (()=>{

  try {
    const saved = localStorage.getItem('audit_daily_tasks');
    if(saved){
      const parsed = JSON.parse(saved);

      const existingPermIds = new Set(parsed.filter(t=>t.permanent).map(t=>t.id));
      const missing = PERMANENT_TASKS_DEFAULT.filter(p=>!existingPermIds.has(p.id));
      return [...missing, ...parsed];
    }
  } catch(e){}
  return [...PERMANENT_TASKS_DEFAULT];
})();

const AC={MA:'#0070f2',LM:'#1a8a4a',SR:'#6941c6',PD:'#c47d00',NB:'#bb2222'};

let ganttZoom='week';
let ganttCollapsed={};
let ganttFilterMission='';
let ganttFilterSoc='';
let ganttFilterType='';
let ganttFilterChef='';

function dayW(){return ganttZoom==='day'?28:ganttZoom==='week'?20:8;}

function parseD(s){const[y,m,d]=s.split('-').map(Number);return new Date(y,m-1,d);}
function fmtD(d){return d.toLocaleDateString('fr-FR',{day:'2-digit',month:'2-digit'});}
function fmtDShort(d){return String(d.getDate());}
function diffDays(a,b){return Math.round((b-a)/(1000*60*60*24));}

function ganttBounds(){
  const today = new Date(); today.setHours(0,0,0,0);
  let mn=parseD('2025-01-01'), mx=parseD('2025-05-31');
  GANTT_MISSIONS.forEach(m=>{
    if(m.ref){
      const la=AUDITS.find(a=>a.ref===m.ref||(m.id==='M-'+a.ref));
      if(la&&(la.status==='planned'||la.status==='completed')) return;
    }
    const ms=parseD(m.start), me=parseD(m.end);
    if(ms<mn)mn=ms; if(me>mx)mx=me;
  });

  if(today<mn) mn=new Date(today);
  if(today>mx) mx=new Date(today);
  mn.setDate(mn.getDate()-7);
  mx.setDate(mx.getDate()+14);
  return{start:mn,end:mx,days:diffDays(mn,mx)+1};
}

function buildGanttRows(){
  const rows=[];
  let lastSoc=null;

  const socMissions={};
  GANTT_MISSIONS.forEach(m=>{
    if(ganttFilterMission && m.id!==ganttFilterMission) return;
    if(ganttFilterSoc && m.societe!==ganttFilterSoc) return;
    if(ganttFilterType){
      const audit=AUDITS.find(a=>a.ref===m.ref||(m.id==='M-'+a.ref));
      if(!audit||audit.type!==ganttFilterType) return;
    }
    if(ganttFilterChef && (m.chef||'')!==ganttFilterChef) return;
    if(ganttFilterStatus && ganttStatusOf(m)!==ganttFilterStatus) return;
    const soc=m.societe||'';
    if(!socMissions[soc]) socMissions[soc]=[];
    socMissions[soc].push(m);
  });

  // Helper: get the latest date across mission + all its tasks/subtasks
  function missionLastDate(m){
    const dates=[];
    if(m.start) dates.push(m.start);
    if(m.end) dates.push(m.end);
    (m.tasks||[]).forEach(t=>{
      if(t.start) dates.push(t.start);
      if(t.end) dates.push(t.end);
      (t.subtasks||[]).forEach(st=>{ if(st.start) dates.push(st.start); if(st.end) dates.push(st.end); });
    });
    dates.sort();
    return { first: dates[0]||m.start, last: dates[dates.length-1]||m.end };
  }

  Object.entries(socMissions).forEach(([soc, missions])=>{
    // Compute société date range
    let socStart=null, socEnd=null;
    missions.forEach(m=>{
      const {first, last}=missionLastDate(m);
      if(first && (!socStart || first < socStart)) socStart=first;
      if(last  && (!socEnd   || last  > socEnd))   socEnd=last;
    });
    // Jours ouvrés (lun–ven) entre socStart et socEnd
    function countWd(s,e){if(!s||!e)return 0;const d=new Date(s),end=new Date(e);let c=0,cur=new Date(d);while(cur<=end){if(cur.getDay()!==0&&cur.getDay()!==6)c++;cur.setDate(cur.getDate()+1);}return c;}
    const socDur=(socStart&&socEnd)?countWd(socStart,socEnd)+'j ouv.':'—';
    const fmtD=s=>{ if(!s)return'—'; const p=s.split('-'); return `${p[2]}/${p[1]}`; };

    rows.push({
      type:'societe-group',
      data:{title:soc||'— Sans société —', socStart, socEnd, socDur, socFmtStart:fmtD(socStart), socFmtEnd:fmtD(socEnd)},
      id:'soc-'+soc
    });

    missions.forEach(m=>{
      rows.push({type:'mission',data:m,id:m.id});
      if(ganttCollapsed[m.id]) return;
      m.tasks.forEach(t=>{
        if(t.type==='milestone'){rows.push({type:'milestone',data:t,id:t.id,missionId:m.id});return;}
        rows.push({type:'task',data:t,id:t.id,missionId:m.id});
        if(ganttCollapsed[t.id]) return;
        (t.subtasks||[]).forEach(st=>{rows.push({type:'subtask',data:st,id:st.id,taskId:t.id,missionId:m.id});});
      });
    });
  });
  return rows;
}

function ganttStatusOf(m){
  const today=new Date(); today.setHours(0,0,0,0);

  // Récupérer le statut réel depuis l'audit lié (source de vérité)
  const linkedAudit = m.ref ? AUDITS.find(a=>a.ref===m.ref) : null;
  // Statut effectif : audit lié > statut mission > 'planned' par défaut
  const auditStatus  = linkedAudit ? linkedAudit.status : (m.status||'planned');
  const missionStatus = m.status||auditStatus||'planned';

  // Terminé : statut explicite OU avancement 100%
  if(auditStatus==='completed' || missionStatus==='completed' || (m.progress||0)>=100)
    return 'completed';

  // Planifiée : statut 'planned' dans l'audit — jamais late, jamais inprogress
  if(auditStatus==='planned') return 'planned';

  // En cours / Ouverte → vérifier le retard par date
  if(auditStatus==='open' || auditStatus==='inprogress' ||
     missionStatus==='open' || missionStatus==='inprogress') {
    const end = parseD(m.end||m.start);
    if(end && end<today && (m.progress||0)<100) return 'late';
    return 'inprogress';
  }

  // En retard selon audit
  if(auditStatus==='overdue') return 'late';

  // Fallback : calcul par date pour missions sans audit lié
  const end = parseD(m.end||m.start);
  if(end && end<today && (m.progress||0)<100) return 'late';
  const start = parseD(m.start);
  if(start && start<=today) return 'inprogress';
  return 'planned';
}

function updateGanttKpis(){
  const today=new Date(); today.setHours(0,0,0,0);
  let total=0,done=0,late=0,inprog=0;
  GANTT_MISSIONS.forEach(m=>{
    total++;
    const st=ganttStatusOf(m);
    if(st==='completed') done++;
    else if(st==='late') late++;
    else if(st==='inprogress') inprog++;
  });
  const el=function(id){return document.getElementById(id);};
  if(el('gkpi-total-val')) el('gkpi-total-val').textContent=total;
  if(el('gkpi-done-val'))  el('gkpi-done-val').textContent=done;
  if(el('gkpi-late-val'))  el('gkpi-late-val').textContent=late;
  if(el('gkpi-inprog-val'))el('gkpi-inprog-val').textContent=inprog;

  const lateCard=document.getElementById('gkpi-late');
  if(lateCard) lateCard.style.borderColor=late>0?'var(--red)':'var(--border)';
}

let ganttFilterStatus='';

function renderGantt(){
  updateGanttKpis();
  const bounds = ganttBounds();
  const DW     = dayW();
  const RH     = 38;
  const today  = new Date(); today.setHours(0,0,0,0);
  const rows   = buildGanttRows();
  // Filtre statut : garder toutes les lignes appartenant aux missions qui passent le filtre
  let filteredRows = rows;
  if(ganttFilterStatus){
    const passedMissionIds = new Set(
      rows.filter(r=>r.type==='mission' && ganttStatusOf(r.data)===ganttFilterStatus).map(r=>r.id)
    );
    filteredRows = rows.filter(r=>
      r.type==='mission' ? passedMissionIds.has(r.id)
      : passedMissionIds.has(r.missionId)
    );
  }

  const $left  = $('#gantt-excel-rows-left').empty();
  const $right = $('#gantt-excel-rows-right').empty();
  const $hdr   = $('#gantt-excel-timeline-header').empty();
  const $empty = $('#gantt-excel-empty');
  const $cont  = $('#gantt-excel-container');

  if(!filteredRows.length){
    $cont.hide(); $empty.show(); return;
  }
  $cont.show(); $empty.hide();

  const days=[];
  for(let i=0;i<bounds.days;i++){
    const d=new Date(bounds.start); d.setDate(d.getDate()+i); days.push(d);
  }
  const totalW = days.length * DW;

  function isoWeek(d){
    const t=new Date(d); t.setHours(0,0,0,0);
    t.setDate(t.getDate()-((t.getDay()+6)%7)+3);
    const jan4=new Date(t.getFullYear(),0,4);
    return 1+Math.round(((t-jan4)/864e5-3+((jan4.getDay()+6)%7))/7);
  }
  const DAYS_FR=['Di','Lu','Ma','Me','Je','Ve','Sa'];

  const monthSpans=[], weekSpans=[];
  days.forEach((d,i)=>{
    const mk=`${d.getFullYear()}-${d.getMonth()}`;
    const wk=`${d.getFullYear()}-W${isoWeek(d)}`;
    if(!monthSpans.length||monthSpans.at(-1).key!==mk)
      monthSpans.push({key:mk,label:`${MONTHS_FR_FULL[d.getMonth()]} ${d.getFullYear()}`,start:i,span:0,px:0});
    monthSpans.at(-1).span++;
    monthSpans.at(-1).px+=DW;
    if(!weekSpans.length||weekSpans.at(-1).key!==wk)
      weekSpans.push({key:wk,label:`S${isoWeek(d)}`,start:i,span:0,px:0});
    weekSpans.at(-1).span++;
    weekSpans.at(-1).px+=DW;
  });

  let hdrHtml=`<div style="display:flex;flex-direction:column;width:max-content;">`;

  hdrHtml+=`<div style="height:28px;display:flex;background:#1e293b;border-bottom:1px solid #334155;">`;
  monthSpans.forEach(ms=>{
    hdrHtml+=`<div style="width:${ms.px}px;flex-shrink:0;border-right:2px solid #475569;display:flex;align-items:center;padding:0 8px;font-size:10.5px;font-weight:800;color:#e2e8f0;letter-spacing:.06em;text-transform:uppercase;white-space:nowrap;overflow:hidden;">${ms.label}</div>`;
  });
  hdrHtml+=`</div>`;

  hdrHtml+=`<div style="height:28px;display:flex;background:#1e293b;border-bottom:2px solid #334155;">`;
  days.forEach(d=>{
    const dow=d.getDay(), isToday=d.getTime()===today.getTime();
    const isWk=dow===0||dow===6;
    const isMon=dow===1;
    const bg=isToday?'#0070f2':isWk?'#0f172a':'transparent';
    const col=isToday?'#fff':isWk?'#475569':'#94a3b8';
    const fw=isToday||isMon?'800':'500';
    const br=isMon&&ganttZoom!=='day'?'border-left:1px solid #475569;':'';
    hdrHtml+=`<div style="width:${DW}px;min-width:${DW}px;flex-shrink:0;background:${bg};${br}display:flex;flex-direction:column;align-items:center;justify-content:center;gap:1px;border-right:1px solid rgba(71,85,105,.4);">
      <span style="font-size:${DW>16?'10':'8.5'}px;font-weight:${fw};color:${col};line-height:1;">${d.getDate()}</span>
      ${DW>14?`<span style="font-size:7.5px;color:${isToday?'rgba(255,255,255,.75)':isWk?'#334155':'#475569'};text-transform:uppercase;line-height:1;">${DAYS_FR[dow]}</span>`:''}
    </div>`;
  });
  hdrHtml+=`</div></div>`;
  $hdr.html(hdrHtml);

  /* ── Filter dropdowns ── */
  const $mf=$('#gantt-filter-mission').empty().append('<option value="">— Toutes les missions —</option>');
  const $sf=$('#gantt-filter-soc').empty().append('<option value="">— Toutes les sociétés —</option>');
  const $tf=$('#gantt-filter-type').empty().append('<option value="">— Tous les types —</option>');
  const socs=new Set(), types=new Set();
  GANTT_MISSIONS.forEach(m=>{
    $mf.append(`<option value="${m.id}">${m.title}</option>`);
    if(m.societe) socs.add(m.societe);
    const audit=AUDITS.find(a=>a.ref===m.ref||(m.id==='M-'+a.ref));
    if(audit&&audit.type) types.add(audit.type);
  });
  socs.forEach(s=>$sf.append(`<option value="${s}">${s}</option>`));
  [...types].sort().forEach(t=>$tf.append(`<option value="${t}">${t}</option>`));
  // Populate chef filter
  const $cf=$('#gantt-filter-chef').empty().append('<option value="">— Tous les chefs —</option>');
  const chefs=new Set();
  GANTT_MISSIONS.forEach(m=>{ if(m.chef) chefs.add(m.chef); });
  [...chefs].sort().forEach(c=>$cf.append(`<option value="${c}">${c}</option>`));
  $mf.val(ganttFilterMission); $sf.val(ganttFilterSoc); $tf.val(ganttFilterType);
  $cf.val(ganttFilterChef);

  /* ── Rows ── */
  const todayX = diffDays(bounds.start,today);

  filteredRows.forEach((row,ri)=>{
    const d=row.data;

    // ── Société group header row ──
    if(row.type==='societe-group'){
      const socGrpH=28;
      const sd=row.data;
      $left.append(`
        <div style="display:flex;height:${socGrpH}px;background:linear-gradient(90deg,#1e293b,#334155);border-bottom:2px solid #475569;border-left:4px solid #6366f1;align-items:center;padding:0 10px;gap:7px;position:sticky;left:0;">
          <span style="font-size:9px;font-weight:800;text-transform:uppercase;letter-spacing:.1em;color:#a5b4fc;">🏢</span>
          <span style="font-size:11px;font-weight:700;color:#e2e8f0;letter-spacing:.04em;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1;">${sd.title}</span>
          ${sd.socStart?`<span style="font-size:9px;font-family:var(--mono);color:#94a3b8;flex-shrink:0;">📅 ${sd.socFmtStart}</span>
          <span style="font-size:9px;color:#475569;flex-shrink:0;">→</span>
          <span style="font-size:9px;font-family:var(--mono);color:#94a3b8;flex-shrink:0;">${sd.socFmtEnd}</span>
          <span style="font-size:8.5px;font-weight:700;padding:1px 6px;border-radius:10px;background:rgba(99,102,241,.25);color:#a5b4fc;flex-shrink:0;">${sd.socDur}</span>`:''}
        </div>`);
      $right.append(`
        <div style="height:${socGrpH}px;width:${totalW}px;background:linear-gradient(90deg,rgba(99,102,241,.12),rgba(99,102,241,.04));border-bottom:2px solid #475569;"></div>`);
      return;
    }

    const isCollapsed=!!ganttCollapsed[row.id];
    const hasChildren=row.type==='mission'||(row.type==='task'&&(d.subtasks||[]).length>0);
    let missionStatus='';
    if(row.type==='mission') missionStatus=ganttStatusOf(d);

    /* ── LEFT cell (spreadsheet columns) ── */
    const isMission=row.type==='mission';
    const isTask=row.type==='task';
    const isSub=row.type==='subtask';
    const isMile=row.type==='milestone';

    // Row background alternation + status
    let rowBg='';
    if(isMission){
      if(missionStatus==='completed')  rowBg='#f0fdf4';
      else if(missionStatus==='late')       rowBg='#fff5f5';
      else if(missionStatus==='planned')    rowBg='#f8fafc';
      else                                  rowBg='#eff6ff';
    } else {
      rowBg = ri%2===0?'var(--surface)':'var(--surface2)';
    }

    // Left border color per type
    const lBorderColor=isMission
      ? (missionStatus==='late'     ?'#ef4444'
        :missionStatus==='completed'?'#22c55e'
        :missionStatus==='planned'  ?'#94a3b8'
        :'#3b82f6')
      : isTask?'#10b981':isSub?'#6366f1':'#f59e0b';

    // Indent
    const indent=isMission?0:isTask?16:isSub?30:16;

    // Toggle button
    const toggleHtml=hasChildren
      ?`<span class="gantt-row-toggle" data-rowid="${row.id}" style="width:14px;height:14px;border-radius:3px;background:${isMission?'rgba(59,130,246,.15)':'var(--surface3)'};border:1px solid var(--border);display:inline-flex;align-items:center;justify-content:center;font-size:8px;cursor:pointer;flex-shrink:0;color:var(--text-muted);margin-right:4px;">${isCollapsed?'▶':'▼'}</span>`
      :`<span style="width:14px;display:inline-block;flex-shrink:0;margin-right:4px;"></span>`;

    // Start/end dates
    const ds=d.start?d.start.slice(0,10):'—', de=d.end?d.end.slice(0,10):'—';
    const fmtShort=s=>{ if(!s||s==='—')return'—'; const p=s.split('-'); return `${p[2]}/${p[1]}`; };
    const dur=(d.start&&d.end)?(()=>{const s=new Date(d.start),e=new Date(d.end);let c=0,cur=new Date(s);while(cur<=e){if(cur.getDay()!==0&&cur.getDay()!==6)c++;cur.setDate(cur.getDate()+1);}return c+'j';})():'—';

    // Progress bar
    // Status badge (missions only)
    let stBadge='';
    if(isMission){
      const stL={completed:'✓ Terminé',late:'⚠ Retard',inprogress:'● En cours',planned:'○ Planifié'};
      const stC={completed:'#15803d',late:'#dc2626',inprogress:'#7c3aed',planned:'#64748b'};
      const stBg={completed:'#dcfce7',late:'#fee2e2',inprogress:'#f3e8ff',planned:'#f1f5f9'};
      stBadge=`<span style="font-size:8px;font-weight:700;padding:1px 5px;border-radius:3px;background:${stBg[missionStatus]||'#f1f5f9'};color:${stC[missionStatus]||'#64748b'};white-space:nowrap;flex-shrink:0;">${stL[missionStatus]||''}</span>`;
    }

    // Edit/del buttons (missions only)
    let editBtns='';
    if(isMission){
      const mIdx=GANTT_MISSIONS.findIndex(m=>m.id===row.id);
      editBtns=`<button class="btn gantt-mission-edit-btn" data-missionidx="${mIdx}" style="padding:1px 5px;font-size:10px;flex-shrink:0;margin-left:2px;" title="Modifier">✏️</button>
                <button class="btn gantt-mission-del-btn"  data-missionidx="${mIdx}" style="padding:1px 5px;font-size:10px;flex-shrink:0;background:rgba(239,68,68,.08);color:#ef4444;border-color:rgba(239,68,68,.2);" title="Supprimer">🗑</button>`;
    }

    const borderBot=isMission?'2px solid var(--border2)':'1px solid var(--border)';

    const leftRowHtml=`
      <div style="display:flex;height:${RH}px;border-bottom:${borderBot};border-left:3px solid ${lBorderColor};background:${rowBg};cursor:pointer;transition:background .1s;" class="gantt-excel-row" data-rowid="${row.id}">
        <div style="width:28px;flex-shrink:0;border-right:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:9px;color:var(--text-dim);font-family:var(--mono);">${ri+1}</div>
        <div style="flex:2;border-right:1px solid var(--border);display:flex;align-items:center;padding:0 6px 0 ${6+indent}px;overflow:hidden;gap:3px;min-width:0;">
          ${toggleHtml}
          <span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:${isMission?'12.5':isSub?'11':'12'}px;font-weight:${isMission?'700':isTask?'600':'400'};color:${isMile?'var(--yellow)':isSub?'var(--text-muted)':'var(--text)'};" title="${d.title}">${d.title}</span>
          ${stBadge}${editBtns}
        </div>
        <div style="width:70px;flex-shrink:0;border-right:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:10.5px;font-family:var(--mono);color:var(--text-muted);">${fmtShort(ds)}</div>
        <div style="width:70px;flex-shrink:0;border-right:1px solid var(--border);display:flex;align-items:center;justify-content:center;font-size:10.5px;font-family:var(--mono);color:var(--text-muted);">${fmtShort(de)}</div>
        <div style="width:50px;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:10.5px;color:var(--text-muted);">${dur}</div>
      </div>`;
    $left.append(leftRowHtml);

    /* ── RIGHT cell (timeline bars) ── */
    // Today column highlight + vertical line
    let todayHighlight='', todayLine='';
    if(todayX>=0&&todayX<days.length){
      const tx=todayX*DW;
      todayHighlight=`<div style="position:absolute;left:${tx}px;top:0;width:${DW}px;height:100%;background:rgba(0,112,242,.06);pointer-events:none;z-index:1;"></div>`;
      todayLine=`<div style="position:absolute;left:${tx+DW/2-1}px;top:0;width:2px;height:100%;background:#ef4444;opacity:.6;z-index:5;pointer-events:none;border-radius:1px;"></div>`;
    }

    // Weekend columns
    let wkendHtml='';
    days.forEach((dd,di)=>{
      const dow=dd.getDay();
      if(dow===0||dow===6){
        wkendHtml+=`<div style="position:absolute;left:${di*DW}px;top:0;width:${DW}px;height:100%;background:rgba(0,0,0,.025);pointer-events:none;z-index:0;"></div>`;
      }
    });

    // Gantt bar
    let barHtml='';
    if(isMile){
      const ms=parseD(d.start);
      const colIdx=diffDays(bounds.start,ms);
      if(colIdx>=0&&colIdx<days.length){
        const cx=colIdx*DW+DW/2, sz=12, ml=cx-sz/2, mt=(RH-sz)/2;
        barHtml=`<div style="position:absolute;left:${ml}px;top:${mt}px;width:${sz}px;height:${sz}px;background:var(--yellow);transform:rotate(45deg);border:2px solid #fff;border-radius:2px;box-shadow:0 1px 4px rgba(196,125,0,.4);z-index:4;cursor:pointer;"></div>
                  <div style="position:absolute;left:${cx+sz/2+6}px;top:${(RH-12)/2}px;font-size:9px;font-weight:600;color:var(--yellow);white-space:nowrap;pointer-events:none;z-index:3;">${d.title}</div>`;
      }
    } else if(d.start&&d.end){
      const ds2=parseD(d.start), de2=parseD(d.end);
      const x=diffDays(bounds.start,ds2)*DW;
      const w=Math.max((diffDays(ds2,de2)+1)*DW, DW);
      const prog2=d.progress||0;
      // Bar height & style per type — GanttExcel-inspired: full-width rounded pill
      let barH, barTop, gradient, radius='5px';
      if(isMission){
        barH=26; barTop=(RH-26)/2;
        if(missionStatus==='completed')  gradient='linear-gradient(90deg,#15803d,#22c55e)';
        else if(missionStatus==='late')       gradient='linear-gradient(90deg,#dc2626,#f87171)';
        else if(missionStatus==='planned')    gradient='linear-gradient(90deg,#475569,#94a3b8)';
        else                                  gradient='linear-gradient(90deg,#1d4ed8,#3b82f6)';
      } else if(isTask){
        barH=18; barTop=(RH-18)/2;
        gradient='linear-gradient(90deg,#0f766e,#10b981)';
      } else {
        barH=12; barTop=(RH-12)/2;
        gradient='linear-gradient(90deg,#6366f1,#a5b4fc)';
      }
      // Late stripes
      const lStripe=(isMission&&missionStatus==='late')
        ?`<div style="position:absolute;inset:0;background:repeating-linear-gradient(-45deg,transparent,transparent 4px,rgba(255,255,255,.1) 4px,rgba(255,255,255,.1) 8px);border-radius:${radius};pointer-events:none;"></div>`:'';
      // Label inside bar
      const barLabel=w>60?`<span style="position:relative;z-index:2;padding:0 8px;font-size:10px;font-weight:700;color:#fff;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;text-shadow:0 1px 2px rgba(0,0,0,.3);">${d.title}</span>`:'';
      barHtml=`
        <div style="position:absolute;left:${x}px;top:${barTop}px;width:${w}px;height:${barH}px;background:${gradient};border-radius:${radius};display:flex;align-items:center;overflow:hidden;cursor:pointer;z-index:3;box-shadow:0 1px 6px rgba(0,0,0,.18);transition:filter .12s;" data-rowid="${row.id}">
          ${lStripe}${barLabel}
        </div>`;
    }

    const rightRowHtml=`
      <div style="height:${RH}px;width:${totalW}px;position:relative;border-bottom:${borderBot};background:${rowBg};">
        ${wkendHtml}
        ${todayHighlight}
        ${barHtml}
        ${todayLine}
      </div>`;
    $right.append(rightRowHtml);
  });

  // Set right panel width
  $('#gantt-excel-rows-right').css('width', totalW+'px');

  // Scroll to today
  if(todayX>=0&&todayX<days.length){
    const scrollTarget=todayX*DW-200;
    requestAnimationFrame(()=>{
      const scroller=document.getElementById('gantt-scroll');
      if(scroller) scroller.scrollLeft=Math.max(0,scrollTarget);
    });
  }
}

// ── Widget Zoom ──────────────────────────────────────────────
$(document).on('click','.wzoom',function(e){
  e.stopPropagation();
  const $widget = $(this).closest('.widget');
  const $clone  = $widget.clone(true);
  // Enlève le bouton zoom du clone pour éviter boucle
  $clone.find('.wzoom').remove();
  // Agrandit les SVG et charts dans le clone
  $clone.find('svg').each(function(){
    $(this).attr('width','100%').css({width:'100%',height:'auto',minHeight:'260px'});
  });
  $clone.find('[style*="max-height"]').css('max-height','none');
  $clone.find('[style*="overflow-y"]').css('overflow-y','visible');

  $('#widget-zoom-content').empty().append($clone);
  $('#widget-zoom-overlay').addClass('open');

  tryRender(()=>renderWidgets())
  tryRender(()=>renderW4())
  tryRender(()=>renderW8())
  tryRender(()=>renderRisks())
});

function closeWidgetZoom(){
  $('#widget-zoom-overlay').removeClass('open');
  $('#widget-zoom-content').empty();
}
$('#widget-zoom-close').on('click', closeWidgetZoom);
$('#widget-zoom-overlay').on('click',function(e){
  if($(e.target).is('#widget-zoom-overlay')) closeWidgetZoom();
});
$(document).on('keydown',function(e){
  if(e.key==='Escape') closeWidgetZoom();
});

$(document).on('click','.gantt-row-toggle',function(e){
  e.stopPropagation();
  const id=$(this).data('rowid');
  ganttCollapsed[id]=!ganttCollapsed[id];
  renderGantt();
});

$(document).on('click','.gantt-zoom-btn',function(){

  if($(this).attr('id')==='gantt-view-gantt'||$(this).attr('id')==='gantt-view-list') return;
  $('.gantt-zoom-btn:not(#gantt-view-gantt):not(#gantt-view-list)').removeClass('active');
  $(this).addClass('active');
  ganttZoom=$(this).data('zoom');
  renderGantt();
});

$(document).on('change','#gantt-filter-mission',function(){ganttFilterMission=$(this).val();renderGantt();});
$(document).on('change','#gantt-filter-soc',function(){ganttFilterSoc=$(this).val();renderGantt();});
$(document).on('change','#gantt-filter-type',function(){ganttFilterType=$(this).val();renderGantt();});
$(document).on('change','#gantt-filter-status',function(){ganttFilterStatus=$(this).val();renderGantt();});
$(document).on('change','#gantt-filter-chef',function(){ganttFilterChef=$(this).val();renderGantt();});
$(document).on('click','#gantt-reset-filters',function(){
  ganttFilterMission=''; ganttFilterSoc=''; ganttFilterType=''; ganttFilterStatus=''; ganttFilterChef='';
  $('#gantt-filter-mission,#gantt-filter-soc,#gantt-filter-type,#gantt-filter-status,#gantt-filter-chef').val('');
  renderGantt();
  toast('info','↻','Filtres réinitialisés — toutes les missions affichées');
});

// ── Bouton Auto-dates : recalcule toutes les dates de fin de mission depuis leurs tâches ──
$(document).on('click','#gantt-auto-dates',function(){
  let count = 0, fixed = 0;
  GANTT_MISSIONS.forEach(m=>{
    if(!(m.tasks&&m.tasks.length)) return;
    count++;
    const oldEnd = m.end;
    recalcMissionEndFromTasks(m);
    recalcMissionDates(m);
    if(m.end !== oldEnd) fixed++;
  });
  renderGantt();
  dbSave();
  if(count === 0) toast('info','📅','Aucune mission avec des tâches à recalculer');
  else toast('success','⚙','Auto-dates : '+fixed+' mission(s) recalculée(s) sur '+count);
});

$(document).on('click','#gantt-view-gantt',function(){
  $('#gantt-view-gantt').addClass('active');
  $('#gantt-view-list').removeClass('active');
  $('#gantt-scroll').show();
  $('#gantt-list-view').hide();
  $('#gantt-legend').show();
});
$(document).on('click','#gantt-view-list',function(){
  $('#gantt-view-list').addClass('active');
  $('#gantt-view-gantt').removeClass('active');
  $('#gantt-scroll').hide();
  $('#gantt-list-view').show();
  $('#gantt-legend').hide();
  renderGanttList();
});

$(document).on('click','#gantt-sync-audits-btn',function(){
  const before=GANTT_MISSIONS.length;
  tryRender(()=>syncMissionsFromAudits());
  tryRender(()=>renderGantt());
  tryRender(()=>renderWidgets());
  dbSave();
  const after=GANTT_MISSIONS.length;
  const created=after-before;
  const total=AUDITS.length;
  // Mettre à jour le bandeau
  const $banner=$('#gantt-sync-banner-text');
  if(total===0){
    $banner.text('Aucun plan d\'audit enregistré. Créez des audits dans la section "Plans d\'audit interne".');
    toast('info','📋','Aucun plan d\'audit enregistré. Créez des audits d\'abord.');
  } else {
    $banner.html(`<strong>${total}</strong> plan(s) d'audit interne → <strong>${after}</strong> mission(s) dans le Planning Gantt${created>0?' <span style="color:#1a8a4a;font-weight:700;">(+'+created+' nouvelle(s))</span>':' <span style="color:#1a8a4a;">✓ À jour</span>'}`);
    toast('success','🔄',`Synchronisation terminée — ${total} plan(s) d'audit → ${after} mission(s) Gantt${created>0?' ('+created+' nouvelle(s))':' (déjà à jour)'}`);
  }
});

$(document).on('click','#gantt-expand-all',function(){
  ganttCollapsed={};
  renderGantt();
});
$(document).on('click','#gantt-collapse-all',function(){
  GANTT_MISSIONS.forEach(m=>{
    ganttCollapsed[m.id]=true;
    m.tasks.forEach(t=>{ ganttCollapsed[t.id]=true; });
  });
  renderGantt();
});

$(document).on('click','#gantt-today-btn',function(){
  const bounds=ganttBounds();
  const today=new Date(); today.setHours(0,0,0,0);
  const DW=dayW();
  const col=diffDays(bounds.start,today);
  const scroller=document.getElementById('gantt-scroll');
  if(scroller) scroller.scrollLeft=Math.max(0,col*DW-200);
});

$(document).on('click','#gantt-export-csv',function(){
  let csv='Mission;Tâche;Type;Début;Fin;Avancement;Chef;Assignés;Statut\n';
  GANTT_MISSIONS.forEach(m=>{
    const st=ganttStatusOf(m);
    csv+=`"${m.title}";"${m.title}";"Mission";"${m.start}";"${m.end}";"${m.progress||0}%";"${m.chef||''}";"${(m.assignees||[]).join(', ')}";"${st}"\n`;
    m.tasks.forEach(t=>{
      if(t.type==='milestone'){
        csv+=`"${m.title}";"${t.title}";"Jalon";"${t.start}";"${t.start}";"—";"${t.chef||''}";"${(t.assignees||[]).join(', ')}";""\n`;
      } else {
        csv+=`"${m.title}";"${t.title}";"Tâche";"${t.start}";"${t.end||t.start}";"${t.progress||0}%";"${t.chef||''}";"${(t.assignees||[]).join(', ')}";""\n`;
        (t.subtasks||[]).forEach(st2=>{
          csv+=`"${m.title}";"${st2.title}";"Sous-tâche";"${st2.start}";"${st2.end||st2.start}";"${st2.progress||0}%";"";"${(st2.assignees||[]).join(', ')}";""\n`;
        });
      }
    });
  });
  const blob=new Blob(['\uFEFF'+csv],{type:'text/csv;charset=utf-8;'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download='planning_gantt.csv'; a.click();
  URL.revokeObjectURL(url);
  toast('success','✓','Export CSV généré');
});

(function(){
  let isDragging=false, startX=0, startScrollLeft=0;
  document.addEventListener('mousedown',function(e){
    const scroller=document.getElementById('gantt-scroll');
    if(!scroller||!scroller.contains(e.target)) return;

    if(e.target.tagName==='BUTTON'||e.target.closest('button')) return;
    isDragging=true; startX=e.pageX; startScrollLeft=scroller.scrollLeft;
    scroller.style.cursor='grabbing'; scroller.style.userSelect='none';
  });
  document.addEventListener('mousemove',function(e){
    if(!isDragging) return;
    const scroller=document.getElementById('gantt-scroll');
    if(!scroller) return;
    const dx=e.pageX-startX;
    scroller.scrollLeft=startScrollLeft-dx;
  });
  document.addEventListener('mouseup',function(){
    if(!isDragging) return;
    isDragging=false;
    const scroller=document.getElementById('gantt-scroll');
    if(scroller){scroller.style.cursor='grab';scroller.style.userSelect='';}
  });
})();

// Render list view
function renderGanttList(){
  const today=new Date(); today.setHours(0,0,0,0);
  const $lb=$('#gantt-list-tbody').empty();
  const stLabels={completed:'✅ Terminé',late:'⚠️ En retard',inprogress:'🔄 En cours',planned:'○ Planifié'};
  const stColors={completed:'var(--green)',late:'var(--red)',inprogress:'var(--purple)',planned:'var(--text-muted)'};
  GANTT_MISSIONS.forEach(m=>{
    const st=ganttStatusOf(m);
    const dur=(!isNaN(parseD(m.start))&&!isNaN(parseD(m.end)))?diffDays(parseD(m.start),parseD(m.end))+1:'—';
    const refBadge=m.ref?`<span style="display:inline-block;padding:1px 6px;border-radius:8px;font-size:9px;font-weight:700;background:#dbeafe;color:#1e40af;margin-left:5px;font-family:var(--mono);">${m.ref}</span>`:'';
    const socBadge=m.societe?`<span style="font-size:10px;color:var(--text-muted);margin-left:6px;">• ${m.societe}</span>`:'';
    $lb.append(`<tr style="background:rgba(0,112,242,.04);">
      <td style="font-weight:700;">${m.title}${refBadge}${socBadge}</td>
      <td style="color:var(--text-muted);font-size:11px;">—</td>
      <td style="font-family:var(--mono);font-size:11px;">${m.start||'—'}</td>
      <td style="font-family:var(--mono);font-size:11px;">${m.end||'—'}</td>
      <td style="font-size:11px;">${m.chef||'—'}</td>
      <td><span style="font-size:10px;font-weight:700;color:${stColors[st]};">${stLabels[st]||st}</span></td>
      <td style="font-family:var(--mono);font-size:11px;color:var(--text-muted);">${dur}j</td>
    </tr>`);
    m.tasks.forEach(t=>{
      if(t.type==='milestone'){
        $lb.append(`<tr>
          <td></td>
          <td style="padding-left:20px;font-size:11px;color:var(--yellow);">🔶 ${t.title}</td>
          <td style="font-family:var(--mono);font-size:11px;">${t.start}</td><td>—</td>
          <td style="font-size:11px;">${(t.assignees||[]).join(', ')||'—'}</td>
          <td>—</td><td>—</td>
        </tr>`);
        return;
      }
      const tdur=diffDays(parseD(t.start),parseD(t.end||t.start))+1;
      $lb.append(`<tr>
        <td></td>
        <td style="padding-left:20px;font-size:11px;">📋 ${t.title}</td>
        <td style="font-family:var(--mono);font-size:11px;">${t.start}</td>
        <td style="font-family:var(--mono);font-size:11px;">${t.end||t.start}</td>
        <td style="font-size:11px;">${(t.assignees||[]).join(', ')||'—'}</td>
        <td>—</td>
        <td style="font-family:var(--mono);font-size:11px;color:var(--text-muted);">${tdur}j</td>
      </tr>`);
      (t.subtasks||[]).forEach(st2=>{
        const sdur=diffDays(parseD(st2.start),parseD(st2.end||st2.start))+1;
        $lb.append(`<tr style="background:var(--surface2);">
          <td></td>
          <td style="padding-left:38px;font-size:11px;color:var(--text-muted);">↳ ${st2.title}</td>
          <td style="font-family:var(--mono);font-size:11px;">${st2.start}</td>
          <td style="font-family:var(--mono);font-size:11px;">${st2.end||st2.start}</td>
          <td style="font-size:11px;">${(st2.assignees||[]).join(', ')||'—'}</td>
          <td>—</td>
          <td style="font-family:var(--mono);font-size:11px;color:var(--text-muted);">${sdur}j</td>
        </tr>`);
      });
    });
  });
  if(!GANTT_MISSIONS.length){
    const auditCount=AUDITS.length;
    $lb.append(`<tr><td colspan="8" style="text-align:center;padding:28px;color:var(--text-dim);font-size:12px;">
      ${auditCount>0
        ? `<div style="font-size:18px;margin-bottom:8px;">🔄</div><div style="font-weight:600;margin-bottom:6px;">${auditCount} plan(s) d'audit disponibles non encore synchronisés</div><div>Cliquez sur <strong>🔄 Sync Audits → Gantt</strong> pour les intégrer au Planning.</div>`
        : '<div style="font-size:18px;margin-bottom:8px;">📋</div>Aucune mission. Créez des Plans d\'audit interne ou utilisez <strong>+ Nouvelle entrée</strong>.'
      }
    </td></tr>`);
  }
}

const $tt=$('#g-tooltip');
$(document).on('mouseenter','.gantt-bar,.gantt-milestone-diamond',function(e){
  const id=$(this).data('rowid');
  let item=null, missionTitle='', socName='';
  GANTT_MISSIONS.forEach(m=>{
    if(m.id===id){item=m;missionTitle='Mission';socName=m.societe;}
    m.tasks.forEach(t=>{
      if(t.id===id){item=t;missionTitle=m.title;socName=m.societe;}
      (t.subtasks||[]).forEach(st=>{if(st.id===id){item=st;missionTitle=m.title+' › '+t.title;socName=m.societe;}});
    });
  });
  if(!item) return;
  const assigns=(item.assignees||[]).join(', ');
  const prog=item.type==='milestone'?'—':(item.progress||0)+'%';
  $tt.html(`<div class="g-tooltip-title">${item.title}</div>
    <div class="g-tooltip-row"><span class="g-tooltip-label">Mission</span><span class="g-tooltip-val">${missionTitle}</span></div>
    <div class="g-tooltip-row"><span class="g-tooltip-label">Société</span><span class="g-tooltip-val">${socName||'—'}</span></div>
    ${item.chef?`<div class="g-tooltip-row"><span class="g-tooltip-label">Chef</span><span class="g-tooltip-val">⭐ ${item.chef}</span></div>`:''}
    <div class="g-tooltip-row"><span class="g-tooltip-label">Auditeurs</span><span class="g-tooltip-val">${assigns||'—'}</span></div>
    <div class="g-tooltip-row"><span class="g-tooltip-label">Début</span><span class="g-tooltip-val">${item.start}</span></div>
    <div class="g-tooltip-row"><span class="g-tooltip-label">Fin</span><span class="g-tooltip-val">${item.end||item.start}</span></div>
    <div class="g-tooltip-row"><span class="g-tooltip-label">Avancement</span><span class="g-tooltip-val">${prog}</span></div>
  `).css({top:e.clientY+12,left:Math.min(e.clientX+10,window.innerWidth-280)}).show();
}).on('mousemove','.gantt-bar,.gantt-milestone-diamond',function(e){
  $tt.css({top:e.clientY+12,left:Math.min(e.clientX+10,window.innerWidth-280)});
}).on('mouseleave','.gantt-bar,.gantt-milestone-diamond',function(){$tt.hide();});

let gmTasks=[];
let gmEditingTaskIdx=-1;

function gmAuditeurOptions(selectedArr){
  return AUDITEURS.map(a=>{
    const val=`${a.prenom} ${a.nom}`;
    const sel=(selectedArr||[]).includes(val)?'selected':'';
    return `<option value="${val}" ${sel}>${a.prenom} ${a.nom}</option>`;
  }).join('');
}

function gmRebuildTaskList(){
  const $list=$('#gm-tasks-list');
  $list.empty();
  if(!gmTasks.length){
    $list.html('<div style="font-size:11px;color:var(--text-dim);padding:8px 0;">Aucune tâche ajoutée.</div>');
    return;
  }
  gmTasks.forEach((t,ti)=>{
    const isJ = t.type==='milestone';
    const isEditing = (gmEditingTaskIdx===ti);
    const assignStr = (t.assignees||[]).join(', ')||'—';

    const subtasksHtml = (t.subtasks||[]).map((st,si)=>`
      <div style="display:flex;align-items:center;gap:6px;padding:4px 10px 4px 28px;background:var(--surface);border-top:1px solid var(--border);font-size:11px;">
        <span style="color:var(--text-dim);flex-shrink:0;">↳</span>
        <span style="flex:1;font-weight:500;">${st.title}</span>
        <span style="color:var(--text-muted);font-size:10px;">${st.start}→${st.end||st.start}</span>
        <span style="color:var(--accent);font-size:10px;background:var(--accent-bg);padding:1px 5px;border-radius:3px;">${(st.assignees||[]).join(', ')||'—'}</span>
        <button class="btn gm-edit-subtask-btn" data-ti="${ti}" data-si="${si}" style="padding:1px 5px;font-size:10px;">✏️</button>
        <button class="btn gm-del-subtask" data-ti="${ti}" data-si="${si}" style="padding:1px 5px;font-size:10px;color:var(--red);border-color:var(--red-bg);">✕</button>
      </div>`).join('');

    // Inline edit form for this task
    const diffOpts = ['facile','moyenne','difficile','très difficile'];
    const diffCfg  = {facile:{c:'#15803d',bg:'#dcfce7',lbl:'✅ Facile'},moyenne:{c:'#b45309',bg:'#fef3c7',lbl:'🟡 Moyenne'},difficile:{c:'#c2410c',bg:'#ffedd5',lbl:'🔴 Difficile'},'très difficile':{c:'#7f1d1d',bg:'#fee2e2',lbl:'💀 Très difficile'}};
    const diffBadge=(d)=>{ const cfg=diffCfg[d]||diffCfg['moyenne']; return `<span style="font-size:9px;font-weight:700;padding:1px 6px;border-radius:8px;background:${cfg.bg};color:${cfg.c};white-space:nowrap;">${cfg.lbl}</span>`; };
    const editForm = isEditing ? `
      <div style="padding:10px;background:var(--accent-bg);border-top:1px solid var(--border);">
        <div style="font-size:10px;font-weight:700;color:var(--accent);margin-bottom:8px;text-transform:uppercase;">✏️ Modifier ${isJ?'le jalon':'la tâche'}</div>
        <input class="finp" id="gm-et-title" value="${t.title}" style="font-size:11.5px;margin-bottom:7px;">
        <div style="margin-bottom:7px;">
          <div style="font-size:9px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">Niveau de difficulté</div>
          <select class="finp" id="gm-et-difficulte" style="font-size:11.5px;">
            ${diffOpts.map(d=>`<option value="${d}" ${(t.difficulte||'moyenne')===d?'selected':''}>${diffCfg[d]?.lbl||d}</option>`).join('')}
          </select>
        </div>
        <div style="display:grid;grid-template-columns:${isJ?'1fr auto':'1fr auto 1fr'};gap:8px;margin-bottom:7px;align-items:end;">
          <div><div style="font-size:9px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">Début</div>
            <input class="finp" id="gm-et-start" type="date" value="${t.start}" style="font-size:11.5px;"></div>
          <div style="min-width:80px;">
            <div style="font-size:9px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">⏱ Nb jours ouvrés</div>
            <input class="finp" id="gm-et-nbjours" type="number" min="1" style="font-size:11.5px;text-align:center;"
              value="${(()=>{const s=t.start,e=isJ?t.start:(t.end||t.start);if(!s||!e)return'';const d=new Date(s),end2=new Date(e);let c=0,cur=new Date(d);while(cur<=end2){if(cur.getDay()!==0&&cur.getDay()!==6)c++;cur.setDate(cur.getDate()+1);}return c||'';})()}" placeholder="ex: 5">
          </div>
          ${!isJ?`<div><div style="font-size:9px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">Fin</div>
            <input class="finp" id="gm-et-end" type="date" value="${t.end||t.start}" style="font-size:11.5px;"></div>`:''}
        </div>
        <div style="margin-bottom:8px;">
          <div style="font-size:9px;font-weight:700;color:var(--text-muted);margin-bottom:3px;">Auditeur(s) affecté(s)</div>
          <select class="finp" id="gm-et-assignees" multiple size="4" style="font-size:11.5px;background-image:none;height:auto;">${gmAuditeurOptions(t.assignees||[])}</select>
          <div class="multi-select-hint">Ctrl+clic pour sélectionner plusieurs responsables</div>
        </div>
        <div style="display:flex;gap:6px;">
          <button class="btn p gm-save-task-edit-btn" data-ti="${ti}" style="font-size:11px;padding:3px 10px;">✓ Valider</button>
          <button class="btn gm-cancel-task-edit-btn" style="font-size:11px;padding:3px 10px;">Annuler</button>
        </div>
      </div>` : '';

    $list.append(`
      <div style="border:1px solid var(--border);border-radius:4px;margin-bottom:6px;overflow:hidden;" id="gm-task-row-${ti}">
        <div style="display:flex;align-items:center;gap:6px;padding:6px 10px;background:${isEditing?'var(--accent-bg)':isJ?'var(--yellow-bg)':'var(--surface2)'};">
          <span style="font-size:13px;flex-shrink:0;">${isJ?'🔶':'📋'}</span>
          <span style="flex:1;font-weight:600;font-size:12px;">${t.title}</span>
          ${diffBadge(t.difficulte||'moyenne')}
          ${!isJ
            ? `<span style="font-size:10px;color:var(--text-muted);">${t.start} → ${t.end||t.start}</span>`
            : `<span style="font-size:10px;color:var(--yellow);">📅 ${t.start}</span>`}
          <span style="font-size:10px;color:var(--accent);background:var(--accent-bg);padding:1px 6px;border-radius:3px;max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${assignStr}">👤 ${assignStr}</span>
          <button class="btn gm-edit-task-btn" data-ti="${ti}" style="padding:1px 6px;font-size:10px;" title="Modifier">✏️</button>
          ${!isJ?`<button class="btn gm-add-subtask-btn" data-ti="${ti}" style="padding:1px 7px;font-size:10px;">↳+</button>`:''}
          <button class="btn gm-del-task" data-ti="${ti}" style="padding:1px 6px;font-size:10px;color:var(--red);border-color:var(--red-bg);" title="Supprimer">🗑</button>
        </div>
        ${editForm}
        ${!isEditing ? subtasksHtml : ''}
      </div>`);
  });
}

function openGmModal(editIdx){
  const mission = editIdx >= 0 ? GANTT_MISSIONS[editIdx] : null;
  openUnifiedModal('mission', mission ? { type:'mission', idx: editIdx, missionId: mission.id } : null);
}


$(document).on('click','#gm-iia-v-btn',function(){
  if(gmTasks.length > 0){
    if(!confirm('⚖ Domaine V — IIA 2024\n\nCette action remplacera les tâches existantes par les 3 phases standardisées IIA 2024 (22 J.O.).\nContinuer ?')) return;
  }

  const uid=()=>'T'+Date.now().toString(36)+Math.random().toString(36).slice(2,5);

  // ── Calcul des dates à partir des dates de la mission ──────────────────────
  // Répartition par défaut : Phase1=7 J.O., Phase2=11 J.O., Phase3=4 J.O. = 22 J.O.
  // Tâches : T1=1.5, T2=2.5, T3=3 | T4=4, T5=4, T6=3 | T7=2, T8=2
  const mStart = $('#gm-start').val() || new Date().toISOString().slice(0,10);
  const mEnd   = $('#gm-end').val()   || new Date().toISOString().slice(0,10);

  // Ajoute n jours ouvrés à une date (lun-ven uniquement)
  function addWD(dateStr, n){
    const d = new Date(dateStr);
    let added = 0;
    while(added < n){
      d.setDate(d.getDate()+1);
      if(d.getDay()!==0 && d.getDay()!==6) added++;
    }
    return d.toISOString().slice(0,10);
  }
  // Dernier jour ouvré après n J.O. (inclus le jour de départ si ouvré)
  function spanWD(dateStr, n){
    const d = new Date(dateStr);
    // Avancer au premier jour ouvré si nécessaire
    while(d.getDay()===0||d.getDay()===6) d.setDate(d.getDate()+1);
    let count = 1;
    while(count < n){
      d.setDate(d.getDate()+1);
      if(d.getDay()!==0 && d.getDay()!==6) count++;
    }
    return d.toISOString().slice(0,10);
  }

  // Répartir les J.O. proportionnellement si la mission est plus courte que 22 J.O.
  const d0=new Date(mStart), d1=new Date(mEnd);
  const calDays = Math.max(1, Math.round((d1-d0)/86400000));
  const ratio = calDays < 30 ? calDays/30 : 1; // 22 J.O. ≈ 30 jours cal.

  const jo = (base) => Math.max(1, Math.round(base * ratio));

  // Durées J.O. par tâche
  const jo1=jo(1.5), jo2=jo(2.5), jo3=jo(3);
  const jo4=jo(4),   jo5=jo(4),   jo6=jo(3);
  const jo7=jo(2),   jo8=jo(2);

  // Dates de début/fin de chaque tâche (enchaînement)
  const s1 = mStart;
  const e1 = spanWD(s1, jo1);
  const s2 = addWD(e1, 1);
  const e2 = spanWD(s2, jo2);
  const s3 = addWD(e2, 1);
  const e3 = spanWD(s3, jo3);

  const s4 = addWD(e3, 1);
  const e4 = spanWD(s4, jo4);
  const s5 = addWD(e4, 1);
  const e5 = spanWD(s5, jo5);
  const s6 = addWD(e5, 1);
  const e6 = spanWD(s6, jo6);

  const s7 = addWD(e6, 1);
  const e7 = spanWD(s7, jo7);
  const s8 = addWD(e7, 1);
  const e8 = spanWD(s8, jo8);

  // Fin Phase 1/2/3
  const eP1 = e3, eP2 = e6, eP3 = e8;
  const sP1 = s1, sP2 = s4, sP3 = s7;

  // Sous-tâches : répartir équitablement dans la tâche parente
  function sub(s, e, n){
    const res=[];
    const d0=new Date(s), d1=new Date(e);
    const totalMs = d1-d0;
    const chunk = Math.floor(totalMs/n);
    for(let i=0;i<n;i++){
      const ds = new Date(d0.getTime()+i*chunk);
      const de = i===n-1 ? d1 : new Date(d0.getTime()+(i+1)*chunk-86400000);
      // Snap to weekdays
      while(ds.getDay()===0||ds.getDay()===6) ds.setDate(ds.getDate()+1);
      while(de.getDay()===0||de.getDay()===6) de.setDate(de.getDate()-1);
      if(de<ds) de.setTime(ds.getTime());
      res.push({s:ds.toISOString().slice(0,10), e:de.toISOString().slice(0,10)});
    }
    return res;
  }

  const st1=sub(s1,e1,3), st2=sub(s2,e2,3), st3=sub(s3,e3,3);
  const st4=sub(s4,e4,3), st5=sub(s5,e5,3), st6=sub(s6,e6,3);
  const st7=sub(s7,e7,3), st8=sub(s8,e8,3);

  gmTasks = [
    // ── PHASE 1 : PLANIFICATION (Normes 11.1 à 11.3) — 7 J.O. ──
    {
      id:uid(), type:'task',
      title:'📋 PHASE 1 : PLANIFICATION (Normes 11.1 à 11.3)',
      difficulte:'moyenne', nbjours: jo1+jo2+jo3,
      start:sP1, end:eP1, assignees:[], progress:0,
      subtasks:[]
    },
    {
      id:uid(), type:'task',
      title:'Tâche 1 : Cadrage et Engagement ('+jo1+' J.O.)',
      difficulte:'facile', nbjours: jo1,
      start:s1, end:e1, assignees:[], progress:0,
      subtasks:[
        {id:uid(),title:'Envoi de l\'avis de mission (lettre de mission)',difficulte:'facile',start:st1[0].s,end:st1[0].e,assignees:[]},
        {id:uid(),title:'Entretiens préliminaires avec les responsables de processus',difficulte:'facile',start:st1[1].s,end:st1[1].e,assignees:[]},
