function recalcMissionDates(m){
  const dates=[];
  (m.tasks||[]).forEach(t=>{
    if(t.start) dates.push(t.start);
    if(t.end)   dates.push(t.end);
    (t.subtasks||[]).forEach(st=>{
      if(st.start) dates.push(st.start);
      if(st.end)   dates.push(st.end);
    });
  });
  if(!dates.length) return;
  dates.sort();
  const earliest = dates[0];
  const latest   = dates[dates.length-1];
  if(!m.start || earliest < m.start) m.start = earliest;
  if(!m.end   || latest   > m.end)   m.end   = latest;
}

/* ── Décalage automatique (cascade) des tâches quand la date de début de mission change ── */
function cascadeTaskDates(m, oldStart, newStart){
  if(!oldStart || !newStart || oldStart === newStart) return;
  const d1 = new Date(oldStart), d2 = new Date(newStart);
  const diffMs = d2 - d1;
  const diffDays = Math.round(diffMs / 86400000);
  if(diffDays === 0) return;

  function shiftDate(dateStr, days){
    if(!dateStr) return dateStr;
    const d = new Date(dateStr);
    d.setDate(d.getDate() + days);
    return d.toISOString().slice(0,10);
  }

  (m.tasks||[]).forEach(t=>{
    t.start = shiftDate(t.start, diffDays);
    t.end   = shiftDate(t.end,   diffDays);
    (t.subtasks||[]).forEach(st=>{
      st.start = shiftDate(st.start, diffDays);
      st.end   = shiftDate(st.end,   diffDays);
    });
  });
  // Mettre à jour la date de fin de mission en conséquence
  if(m.end) m.end = shiftDate(m.end, diffDays);
}

/* ── Recalcul automatique de la date de fin mission depuis ses tâches ── */
function recalcMissionEndFromTasks(m){
  const dates=[];
  (m.tasks||[]).forEach(t=>{
    if(t.end)   dates.push(t.end);
    else if(t.start) dates.push(t.start);
    (t.subtasks||[]).forEach(st=>{
      if(st.end)   dates.push(st.end);
      else if(st.start) dates.push(st.start);
    });
  });
  if(!dates.length) return;
  dates.sort();
  const latest = dates[dates.length-1];
  if(latest > (m.end||'')) m.end = latest;
}

