/* ── RCM ↔ Sociétés multiples & Constats FRAP liés ── */
function _rcmPopulateSocietesMulti(selected){
  const $box=$('#rcm-f-societes-multi').empty();
  const list=(typeof SOCIETES!=='undefined'?SOCIETES:[]);
  if(!list.length){ $box.html('<span style="font-size:10.5px;color:var(--text-dim);">Aucune société enregistrée.</span>'); return; }
  list.forEach(function(s){
    const checked=(selected||[]).indexOf(s.nom)>=0?' checked':'';
    $box.append('<label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;">'
      +'<input type="checkbox" class="rcm-soc-multi-cb" value="'+escHtml(s.nom)+'"'+checked+' style="accent-color:var(--accent);"> '+escHtml(s.nom)+'</label>');
  });
}
function _rcmPopulateFrapRefs(selected){
  const $box=$('#rcm-f-frap-refs').empty();
  const list=(typeof FRAP_DATA!=='undefined'?FRAP_DATA:[]);
  if(!list.length){ $box.html('<span style="font-size:10.5px;color:var(--text-dim);">Aucune FRAP enregistrée.</span>'); return; }
  list.forEach(function(f){
    const checked=(selected||[]).indexOf(f.id)>=0?' checked':'';
    const lbl=(f.numero||f.ref||f.id)+' — '+(f.titre||'').slice(0,55)+((f.titre||'').length>55?'…':'');
    $box.append('<label style="display:flex;align-items:flex-start;gap:5px;font-size:11px;cursor:pointer;">'
      +'<input type="checkbox" class="rcm-frap-ref-cb" value="'+escHtml(f.id)+'"'+checked+' style="accent-color:var(--accent);margin-top:2px;"> '+escHtml(lbl)+'</label>');
  });
}
function _rcmPopulateAuditRefs(selected){
  const $box=$('#rcm-f-audit-refs').empty();
  const list=(typeof AUDITS!=='undefined'?AUDITS:[]);
  if(!list.length){ $box.html('<span style="font-size:10.5px;color:var(--text-dim);">Aucune mission enregistrée.</span>'); return; }
  list.forEach(function(a){
    const checked=(selected||[]).indexOf(a.ref)>=0?' checked':'';
    const lbl=(a.ref||'')+' — '+(a.title||'').slice(0,45)+((a.title||'').length>45?'…':'')+(a.societe?' ['+a.societe+']':'');
    $box.append('<label style="display:flex;align-items:flex-start;gap:5px;font-size:11px;cursor:pointer;">'
      +'<input type="checkbox" class="rcm-audit-ref-cb" value="'+escHtml(a.ref||'')+'"'+checked+' style="accent-color:var(--accent);margin-top:2px;"> '+escHtml(lbl)+'</label>');
  });
}

