    _editProcs.map(p=>'<option value="'+p+'"'+(p===r.processus?' selected':'')+'>'+p+'</option>').join('') +
    '<option value="__autre__"'+(!_procInList&&r.processus?' selected':'')+'>✏️ Saisie libre…</option>';
  $('#rcm-f-proc-in').html(_editProcOpts);
