/* ── RCM : Cascade Cycle → Processus ── */
$(document).on('change','#rcm-f-cycle-in',function(){
  const cycle=$(this).val();
  const $proc=$('#rcm-f-proc-in');
  const $custom=$('#rcm-f-proc-custom');
  $custom.hide().val('');
  if(!cycle){
    $proc.html('<option value="">— Sélectionner d\'abord un cycle —</option>');
    return;
  }
  const procs=RCM_CYCLES[cycle]||[];
  $proc.html('<option value="">— Sélectionner un processus —</option>'+
    procs.map(p=>'<option value="'+p+'">'+p+'</option>').join('')+
    '<option value="__autre__">✏️ Saisie libre…</option>');
  $proc.val('');
});
$(document).on('change','#rcm-f-proc-in',function(){
  const $custom=$('#rcm-f-proc-custom');
  if($(this).val()==='__autre__'){
    $custom.show().focus();
  } else {
    $custom.hide().val('');
  }
});
// ── Association RCM → Plans d'audit interne via Cycle Opérationnel/Processus ──
// Sens inverse de linkRCMTAFToOpenedAudit : ici c'est la sauvegarde d'une entrée RCM (Cycle renseigné)
// qui va chercher toutes les missions du Plan d'audit interne partageant ce cycle (principal ou additionnel)
// et les rattache à entry.audit_refs. Optionnel : ne fait rien si aucun cycle n'est renseigné sur l'entrée RCM.
function linkRCMEntryToAuditsByCycle(entry){
  const cycleLc=(entry.cycle||'').trim().toLowerCase();
  if(!cycleLc) return 0;
  const socLc=(entry.filiale && entry.filiale!=='Toutes filiales') ? entry.filiale.trim().toLowerCase() : '';
  if(!Array.isArray(entry.audit_refs)) entry.audit_refs=[];
  let nb=0;
  (typeof AUDITS!=='undefined' ? AUDITS : []).forEach(function(a){
    const auditCycles=_auditAllCycleLabels(a).map(function(c){return c.toLowerCase();});
    if(auditCycles.indexOf(cycleLc)<0) return;
    // Filtre société si les deux côtés en ont une renseignée (évite les faux rapprochements inter-filiales)
    if(socLc && a.societe && a.societe.trim().toLowerCase()!==socLc) return;
    if(entry.audit_refs.indexOf(a.ref)<0){ entry.audit_refs.push(a.ref); nb++; }
  });
  return nb;
}

$('#rcm-modal-save').on('click',()=>{
  const filiale=$('#rcm-f-filiale-in').val().trim();
  const tache=$('#rcm-f-tache-in').val().trim();
  if(!filiale||!tache){toast('error','!','Filiale et Tâche sont obligatoires');return;}
  const impOp=+$('#rcm-f-imp-op').val()||0;
  const impFin=+$('#rcm-f-imp-fin').val()||0;
  const impRep=+$('#rcm-f-imp-rep').val()||0;
  const descOp=$('#rcm-f-desc-op').val().trim();
  const descFin=$('#rcm-f-desc-fin').val().trim();
  const descRep=$('#rcm-f-desc-rep').val().trim();
  const vals=[impOp,impFin,impRep].filter(v=>v>0);
  const avgImpact=vals.length?Math.round(vals.reduce((a,b)=>a+b,0)/vals.length):0;
  const likelihood=+$('#rcm-f-likelihood').val()||2;
  const efficacite=+$('#rcm-f-eff').val()||3;
  const inherent=avgImpact*likelihood;
  const residuel=efficacite>0?Math.max(1,Math.round(inherent/efficacite)):inherent;
  const entry={
    id:_rcmEditId||('RCM-'+Date.now()),
    filiale, ref:$('#rcm-f-ref-in').val().trim(),
    cycle:$('#rcm-f-cycle-in').val().trim(),
    processus: ($('#rcm-f-proc-in').val()==='__autre__' ? $('#rcm-f-proc-custom').val().trim() : $('#rcm-f-proc-in').val().trim()),
    tache, objectif:$('#rcm-f-obj-in').val().trim(),
    risque:$('#rcm-f-risk-in').val().trim(),
    imp_op:impOp,imp_fin:impFin,imp_rep:impRep,
    desc_op:descOp,desc_fin:descFin,desc_rep:descRep,
    impact:avgImpact,likelihood,inherent,
    controle:$('#rcm-f-ctrl-in').val().trim(),
    efficacite,residuel,
    audit_refs:[...document.querySelectorAll('.rcm-audit-ref-cb:checked')].map(cb=>cb.value),
    societes_multi:[...document.querySelectorAll('.rcm-soc-multi-cb:checked')].map(cb=>cb.value).filter(v=>v!==filiale),
    frap_refs:[...document.querySelectorAll('.rcm-frap-ref-cb:checked')].map(cb=>cb.value)
  };
  const _nbNewAuditLinks = linkRCMEntryToAuditsByCycle(entry);
  if(_rcmEditId){
    const idx=RCM_DATA.findIndex(x=>x.id===_rcmEditId);
    if(idx>=0) RCM_DATA[idx]=entry;
    tafSyncFromRCM(entry);
  } else {
    RCM_DATA.push(entry);
  }
  $('#rcm-modal-bk').removeClass('open');
  renderRCM();
  toast('success','🛡️',_rcmEditId?'Entrée RCM mise à jour':'Entrée RCM ajoutée');
  if(_nbNewAuditLinks) toast('success','🔗',_nbNewAuditLinks+' mission(s) Plan d\'audit associée(s) via le cycle « '+entry.cycle+' ».');
});

