$('#rcm-export-btn').on('click',()=>{
  if(!XLSX||!XLSX._real){toast('error','!','Bibliothèque XLSX non disponible (erreur interne)');return;}
  const wb=XLSX.utils.book_new();
  const rows=RCM_DATA.map(r=>({
    Filiale:r.filiale, 'Réf #':r.ref, Cycle:r.cycle, Processus:r.processus,
    'Tâche':r.tache, 'Objectif du contrôle':r.objectif, 'Risque':r.risque,
    'Desc. Impact Opérationnel':r.desc_op||'', 'Impact Opérationnel':r.imp_op||'',
    'Desc. Impact Financier':r.desc_fin||'', 'Impact Financier':r.imp_fin||'',
    'Desc. Impact Réputation':r.desc_rep||'', 'Impact Réputation':r.imp_rep||'',
    Impact:r.impact, Likelihood:r.likelihood, 'Inherent Risk Level':r.inherent,
    'Contrôles de mitigation':r.controle,
    'Efficacité des Contrôles':r.efficacite, 'Residual Risk Level':r.residuel
  }));
  const ws=XLSX.utils.json_to_sheet(rows);
  ws['!cols']=[{wch:14},{wch:8},{wch:18},{wch:18},{wch:28},{wch:50},{wch:50},{wch:40},{wch:16},{wch:40},{wch:16},{wch:40},{wch:16},{wch:8},{wch:10},{wch:16},{wch:50},{wch:20},{wch:16}];
  XLSX.utils.book_append_sheet(wb,ws,'RCM');
  XLSX.writeFile(wb,'risk_control_matrix.xlsx');
  toast('success','⬇️','Export RCM téléchargé ('+rows.length+' entrées)');
});

/* ── RCM Print — Modèle TDR exact ── */

const TDR_LOGO_ARBIOCHEM = 'data:image/png;base64,';
const TDR_LOGO_HEADER    = 'data:image/png;base64,';

/* Couleur de la pastille Éval selon le score résiduel */
function tdrEvalColor(score){
  const s = score || 0;
  if(s >= 10) return '#C0392B'; /* Critique */
  if(s >= 7)  return '#E67E22'; /* Élevé    */
  if(s >= 4)  return '#F1C40F'; /* Moyen    */
  if(s >  0)  return '#27AE60'; /* Faible   */
  return '#cccccc';
}

function buildTDRDoc(data, filters){
  const today = new Date().toLocaleDateString('fr-FR',{day:'2-digit',month:'long',year:'numeric'});

  /* ── Logo filiale dynamique depuis SOCIETES ── */
  const filialeName = filters.filiale || '';
  let filialeLogoSrc = '';
  try{
    if(filialeName && typeof SOCIETES !== 'undefined'){
      const soc = SOCIETES.find(s => s.nom === filialeName);
      if(soc){ const lu = getSocLogo(socKey(soc)); if(lu) filialeLogoSrc = lu; }
    }
  }catch(e){}

  /* ── Grouper par Cycle → Processus ── */
  const cycleMap = {};
  data.forEach(r => {
    const cycle = r.cycle || 'Non spécifié';
    const proc  = r.processus || '—';
    if(!cycleMap[cycle]) cycleMap[cycle] = {};
    if(!cycleMap[cycle][proc]) cycleMap[cycle][proc] = [];
    cycleMap[cycle][proc].push(r);
  });

  /* ── Statistiques ── */
  const nbTotal = data.length;
  const nbCrit  = data.filter(r => (r.residuel||0) >= 10).length;
  const nbEleve = data.filter(r => { const s=r.residuel||0; return s>=7&&s<10; }).length;
  const nbMoyen = data.filter(r => { const s=r.residuel||0; return s>=4&&s<7; }).length;
  const nbFaible= data.filter(r => { const s=r.residuel||0; return s>0&&s<4; }).length;

  /* ── Métadonnées affichées ── */
  const periodeDisplay  = filters.cycle   ? filters.cycle   : 'Tous les cycles';
  const filialeDisplay  = filters.filiale ? filters.filiale : 'Toutes filiales';
  const niveauDisplay   = filters.niveau === 'high'   ? 'Élevé / Critique'
                        : filters.niveau === 'medium' ? 'Moyen'
                        : filters.niveau === 'low'    ? 'Faible'
                        : 'Tous niveaux';

  /* ════════════════════════════════
     PAGE 1 — Couverture A4 Paysage (style Big4)
  ═══════════════════════════════════ */
  const coverPage = `
<div class="tdr-page tdr-page-cover">

  <!-- Zone principale -->
  <div class="tdr-cover-main">

    <!-- En-tête logos -->
    <div class="tdr-cover-header">
      <img src="${TDR_LOGO_ARBIOCHEM}" class="tdr-logo-arbiochem" alt="Arbiochem-group">
      ${filialeLogoSrc
        ? `<img src="${filialeLogoSrc}" class="tdr-logo-filiale" alt="${filialeName}">`
        : `<div class="tdr-logo-filiale-placeholder">${filialeName||'{{NOM_FILIALE}}'}</div>`
      }
    </div>

    <!-- Corps central — titres -->
    <div class="tdr-cover-body">
      <div class="tdr-cover-dept">DIRECTION AUDIT &amp; CONTRÔLE</div>
      <div class="tdr-cover-sep"></div>
      <div class="tdr-cover-title">TERMES DE RÉFÉRENCE<br>(TDR)</div>
      <div class="tdr-cover-mission">Mission d'audit interne – ${filialeDisplay}</div>
      <div style="display:flex;align-items:baseline;gap:10px;justify-content:center;margin-top:3mm;">
        <span class="tdr-cover-mission" style="font-size:13pt;font-weight:600;color:#2c4a7a;margin-top:0;">Plan d'audit interne</span>
        <span class="tdr-cover-ref" style="font-size:10.5pt;color:#5a7a9a;white-space:nowrap;">Réf : ${filters.planRef || '[Plan d\'Audit — Réf.]'}</span>
      </div>
      ${filters.cycle ? `<div class="tdr-cover-ref" style="font-size:11pt;color:#2c4a7a;font-weight:600;margin-top:3mm;">Cycle : ${periodeDisplay}</div>` : ''}
      ${filters.niveau ? `<div style="font-size:10pt;color:#5a7a9a;margin-top:3mm;">Niveau : ${niveauDisplay}</div>` : ''}
      ${filters.missionRef ? `<div class="tdr-cover-ref" style="margin-top:3mm;">Référence : ${filters.missionRef}</div>` : ''}
    </div>

    <!-- Pied de page -->
    <div class="tdr-cover-footer">
      <span class="tdr-cover-confidential">Confidentiel – Diffusion restreinte &nbsp;|&nbsp; Arbiochem-group – ${new Date().getFullYear()}</span>
    </div>

  </div><!-- /tdr-cover-main -->

</div>`;

  /* ════════════════════════════════
     PAGE(S) — Tableaux RCM par cycle
  ═══════════════════════════════════ */
  let contentPages = '';

  Object.entries(cycleMap).forEach(([cycle, procMap]) => {

    /* En-tête de section cycle */
    let cycleBlock = `
<div class="tdr-page tdr-page-content">

  <!--
    STRUCTURE WRAPPER TABLE — seule solution 100 % fiable Chrome pour header/footer répétés.
    thead  → en-tête courant (répété automatiquement à chaque split de page)
    tfoot  → pied de page courant (répété automatiquement)
    tbody  → contenu RCM (le vrai tableau est imbriqué ici)
  -->
  <table class="tdr-page-wrapper-table">
    <thead class="tdr-page-wrapper-thead">
      <tr><td>
        <!-- Running header -->
        <div class="tdr-running-header" style="align-items:center;">
          <div class="tdr-running-left" style="flex-direction:column;align-items:flex-start;gap:3px;">
            <img src="${TDR_LOGO_HEADER}" class="tdr-running-logo" alt="ARBIOCHEM">
            <div class="tdr-running-title1">DIRECTION AUDIT &amp; CONTRÔLE</div>
          </div>
          <div class="tdr-running-right" style="align-self:center;">TERMES DE RÉFÉRENCE (TDR)</div>
        </div>
        <div class="tdr-running-separator" style="position:static;margin:0 0 4px;"></div>
      </td></tr>
    </thead>
    <tfoot class="tdr-page-wrapper-tfoot">
      <tr><td>
        <div class="tdr-page-footer" style="position:static;border-top:1px solid #e0e0e0;padding:6px 15mm;">
          <span>Confidentiel – Diffusion restreinte | Arbiochem-group – ${new Date().getFullYear()}</span>
          <span>${filters.missionRef ? 'Réf. : ' + filters.missionRef : ''}</span>
        </div>
      </td></tr>
    </tfoot>
    <tbody class="tdr-page-wrapper-tbody">
      <tr><td>

        <div class="tdr-p2-section" style="margin-bottom:10px;">
          <div class="tdr-p2-section-title">4. Principaux Risques à évaluer</div>
        </div>

        <!-- Titre du cycle -->

        <!-- Tableau RCM -->
        <table class="tdr-rcm-table">
          <thead>
            <tr class="tdr-rcm-thead-row">
              <th class="tdr-rcm-th tdr-th-processus"><span>Processus</span></th>
              <th class="tdr-rcm-th tdr-th-risques">
                Risques<br>
                <span class="tdr-th-sub">(Ce qui pourrait se passer si les événements ne se déroulent pas comme prévu.)</span>
              </th>
              <th class="tdr-rcm-th tdr-th-eval">Éval</th>
              <th class="tdr-rcm-th tdr-th-controles">
                Dispositif de contrôle Interne<br>
                <span class="tdr-th-sub">(Ce qui devrait exister pour atténuer les risques)</span>
              </th>
            </tr>
          </thead>
          <tbody>`;

    Object.entries(procMap).forEach(([proc, rows]) => {
      rows.forEach((r, ri) => {
        const evalColor = tdrEvalColor(r.residuel||0);
        const refTag    = r.ref
          ? `<span class="tdr-ref-tag">${r.ref}</span> `
          : '';
        const risqueText = (r.risque || '—');
        const tacheText  = r.tache
          ? `<div class="tdr-tache-text">${r.tache}</div>`
          : '';
        const ctrlText   = (r.controle || '—').replace(/\n/g, '<br>- ');
        const ctrlFormatted = ctrlText.startsWith('- ')
          ? ctrlText
          : '- ' + ctrlText;

        // Fusionner les cellules Processus avec rowspan + texte vertical
        const procCell = ri === 0
          ? `<td class="tdr-rcm-td tdr-td-processus" rowspan="${rows.length}" style="width:14mm;padding:6px 4px;">
               <div class="tdr-proc-vertical">${proc}</div>
             </td>`
          : '';

        const bgAlt = ri % 2 === 1 ? 'style="background:#fdf9f5;"' : '';

        cycleBlock += `
      <tr ${bgAlt}>
        ${procCell}
        <td class="tdr-rcm-td tdr-td-risques">
          ${refTag}<strong>${risqueText}</strong>
          ${tacheText}
        </td>
        <td class="tdr-rcm-td tdr-td-eval">
          <div class="tdr-eval-square" style="background:${evalColor};"></div>
        </td>
        <td class="tdr-rcm-td tdr-td-controles">${ctrlFormatted}</td>
      </tr>`;
      });
    });

    cycleBlock += `
          </tbody>
        </table>

        <!-- Notes de bas de page -->
        <div class="tdr-notes">
          <p><strong>Note méthodologique :</strong> Référentiel des risques évolutif ajusté selon les constats de terrain. Évaluation <em>a priori</em> fondée sur l'impact, la probabilité et l'existence du contrôle interne. Seuils de criticité&nbsp;: 🟥 Critique | 🟧 Élevé | 🟨 Moyen | 🟩 Faible.</p>
        </div>

      </td></tr>
    </tbody>
  </table><!-- /tdr-page-wrapper-table -->

</div>`;

    contentPages += cycleBlock;
  });

  /* ── PAGE 2 — Contenu Principal TDR ── */
  const annee = filters.missionRef
    ? (new Date().getFullYear())
    : (new Date().getFullYear());
  const anneeDisplay = new Date().getFullYear();
  const filiale2 = filialeDisplay || '{{NOM_FILIALE}}';

  const tdrPage2 = `
<div class="tdr-p2-page">

  <!--
    STRUCTURE WRAPPER TABLE (même pattern que pages RCM)
    thead = header courant répété · tfoot = footer répété · tbody = contenu
  -->
  <table class="tdr-page-wrapper-table">
    <thead class="tdr-page-wrapper-thead">
      <tr><td>
        <div class="tdr-running-header" style="align-items:center;">
          <div class="tdr-running-left" style="flex-direction:column;align-items:flex-start;gap:3px;">
            <img src="${TDR_LOGO_HEADER}" class="tdr-running-logo" alt="ARBIOCHEM">
            <div class="tdr-running-title1">DIRECTION AUDIT &amp; CONTRÔLE</div>
          </div>
          <div class="tdr-running-right" style="align-self:center;">TERMES DE RÉFÉRENCE (TDR)</div>
        </div>
        <div class="tdr-running-separator" style="position:static;margin:0 0 4px;"></div>
      </td></tr>
    </thead>
    <tfoot class="tdr-page-wrapper-tfoot">
      <tr><td>
        <div class="tdr-page-footer" style="position:static;border-top:1px solid #e0e0e0;padding:6px 15mm;">
          <span>Confidentiel – Diffusion restreinte | Arbiochem-group – ${anneeDisplay}</span>
          <span>${filters.missionRef ? 'Réf. : ' + filters.missionRef : ''}</span>
        </div>
      </td></tr>
    </tfoot>
    <tbody class="tdr-page-wrapper-tbody">
      <tr><td>

        <!-- Bandeau info édition -->
        <div style="background:#fff8e1;border:1px solid #f9a825;border-radius:6px;padding:7px 14px;margin:0 25mm 12px;font-size:8pt;color:#7a5c00;display:flex;align-items:center;gap:8px;" class="tdr-no-print">
          <span style="font-size:13px;">✏️</span>
          <span>Les sections ci-dessous sont <strong>modifiables</strong> — cliquez sur un texte pour l'éditer avant d'imprimer.</span>
        </div>

        <!-- Section 1 -->
        <div class="tdr-p2-section">
          <div class="tdr-p2-section-title">1. Contexte et Justification</div>
          <div contenteditable="true" class="tdr-editable-block" style="outline:none;">
            <p class="tdr-p2-text">
              Dans le cadre du Plan d'Audit <strong>${anneeDisplay}</strong>, la Direction Audit &amp; Contrôle Interne a programmé une mission portant sur le processus de gestion des stocks au sein de la filiale <strong>${filiale2}</strong>.
            </p>
            <p class="tdr-p2-text">
              Cette mission s'inscrit dans une démarche de renforcement du dispositif de contrôle interne et de maîtrise des risques, conformément aux normes professionnelles de l'audit interne et aux bonnes pratiques du référentiel COSO.
            </p>
            <p class="tdr-p2-text">Elle intervient dans un contexte marqué par :</p>
            <ul class="tdr-p2-list">
              <li>Une sensibilité élevée des stocks (biologiques et consommables)</li>
              <li>Un risque de pertes opérationnelles (mortalité, erreurs, vols)</li>
              <li>Un enjeu de fiabilité des données de production et de reporting</li>
            </ul>
          </div>
        </div>

        <hr class="tdr-p2-divider">

        <!-- Section 2 -->
        <div class="tdr-p2-section">
          <div class="tdr-p2-section-title">2. Objectifs de la Mission</div>
          <div contenteditable="true" class="tdr-editable-block" style="outline:none;">
            <p class="tdr-p2-sub-title">Objectif général :</p>
            <p class="tdr-p2-text">
              Évaluer l'efficacité du dispositif de contrôle interne relatif à la gestion des stocks afin de garantir la protection des actifs, la fiabilité des informations et l'efficacité opérationnelle.
            </p>
            <p class="tdr-p2-sub-title">Objectifs spécifiques :</p>
            <ul class="tdr-p2-list">
              <li>Vérifier la conformité aux procédures internes</li>
              <li>Évaluer la pertinence et l'efficacité des contrôles en place</li>
              <li>Identifier les zones de risques (fraude, pertes, erreurs)</li>
              <li>Apprécier la fiabilité des inventaires et du reporting</li>
              <li>Formuler des recommandations d'amélioration</li>
            </ul>
          </div>
        </div>

        <hr class="tdr-p2-divider">

        <!-- Section 3 -->
        <div class="tdr-p2-section">
          <div class="tdr-p2-section-title">3. Périmètre de la Mission</div>
          <div contenteditable="true" class="tdr-editable-block" style="outline:none;">
            <p class="tdr-p2-sub-title">Périmètre organisationnel :</p>
            <ul class="tdr-p2-list">
              <li><strong>Entité auditée :</strong> ${filiale2}</li>
              <li><strong>Direction et Service Concernés :</strong> Production, Magasin, Logistique, Finance</li>
            </ul>
            <p class="tdr-p2-sub-title">Période sous revue :</p>
            <p class="tdr-p2-text">Septembre ${anneeDisplay - 1} – Février ${anneeDisplay}</p>
          </div>
        </div>

        <hr class="tdr-p2-divider">

        <!-- Section 4 -->
        <div class="tdr-p2-section" id="tdr-section-equipe">
          <div class="tdr-p2-section-title">4. Équipe d'audit</div>
          <div contenteditable="true" class="tdr-editable-block" style="outline:none;">
            <p class="tdr-p2-sub-title">Supervision :</p>
            <p class="tdr-p2-text">{{Superviseur}}</p>
            <p class="tdr-p2-sub-title">Chef de mission :</p>
            <p class="tdr-p2-text">{{Chef de mission}}</p>
            <p class="tdr-p2-sub-title">Membres de l'équipe :</p>
            <ul class="tdr-p2-list">
              <li>{{Membre 1}}</li>
              <li>{{Membre 2}}</li>
            </ul>
          </div>
        </div>

      </td></tr>
    </tbody>
  </table><!-- /tdr-page-wrapper-table -->

</div>`;

  /* ── Assemblage final ── */
  return `<div id="tdr-print-root">${coverPage}${tdrPage2}${contentPages}</div>`;
}

function _tdrInjectPageNumbers(container) { /* numérotation désactivée */ }

$('#rcm-print-btn').on('click', () => {
  if(!RCM_DATA.length){ toast('error','!','Aucune entrée RCM à imprimer.'); return; }

  const fCycle   = $('#rcm-f-cycle').val()   || '';
  const fFiliale = $('#rcm-f-filiale').val() || '';
  const fSearch  = ($('#rcm-search').val()   || '').toLowerCase();
  const fLevel   = $('#rcm-f-level').val()   || '';

  let data = RCM_DATA.filter(r => {
    // Filiale : afficher simultanément "Toutes filiales" ET la filiale sélectionnée
    if(fFiliale && fFiliale !== 'Toutes filiales') {
      if(r.filiale !== fFiliale && r.filiale !== 'Toutes filiales') return false;
    }
    if(fCycle && r.cycle !== fCycle) return false;
    if(fLevel){
      const s = r.residuel || 0;
      if(fLevel === 'high'   && s < 10)          return false;
      if(fLevel === 'medium' && (s < 5 || s>=10)) return false;
      if(fLevel === 'low'    && s >= 5)           return false;
    }
    if(fSearch){
      const hay = (r.filiale+r.ref+r.cycle+r.processus+r.tache+r.risque+r.controle).toLowerCase();
      if(!hay.includes(fSearch)) return false;
    }
    return true;
  });

  // Tri par cycle puis par processus
  data.sort((a, b) => {
    const cA = (a.cycle || '').localeCompare(b.cycle || '', 'fr');
    if(cA !== 0) return cA;
    return (a.processus || '').localeCompare(b.processus || '', 'fr');
  });

  const missionRef = ($('#rrcm-mission-ref').val()||'').trim();
  const _loaded = window._rrcmLoadedAudit || null;
  const filters = { filiale: fFiliale, cycle: fCycle, niveau: fLevel, missionRef: missionRef, planRef: (_loaded && _loaded.planRef) ? _loaded.planRef.trim() : '' };
  const $area1 = $('#om-print-area');
  $area1.html(buildTDRDoc(data, filters)).show();
  _tdrInjectPageNumbers($area1.get(0));
  window.print();
  setTimeout(() => $('#om-print-area').hide().empty(), 1500);
});

function renderRisks(){
  try{
    const statut = $('#risk-f-statut').val()||'';
    const cat    = $('#risk-f-cat').val()||'';
    const soc    = $('#risk-f-soc').val()||'';

    // Populate société filter
    const socs = [...new Set(RISKS.map(r=>r.societe).filter(Boolean))].sort();
    const $fs = $('#risk-f-soc');
    const curSoc = $fs.val();
    $fs.find('option:not(:first-child)').remove();
    socs.forEach(s=>$fs.append(`<option value="${s}"${s===curSoc?' selected':''}>${s}</option>`));

    let rows = RISKS.filter(r=>{
      if(statut && r.statut !== statut) return false;
      if(cat && r.categorie !== cat) return false;
      if(soc && r.societe !== soc) return false;
      return true;
    });

    const total   = RISKS.length;
    const open    = RISKS.filter(r=>r.statut==='open').length;
    const mitige  = RISKS.filter(r=>r.statut==='mitigé').length;
    const clos    = RISKS.filter(r=>r.statut==='clos').length;
    const critical= RISKS.filter(r=>riskScore(r.probabilite,r.impact)>=12).length;
    $('#risk-kpi-bar').html([
      {l:'Total',     v:total,    c:'var(--accent)',  bg:'var(--accent-bg)'},
      {l:'Ouverts',   v:open,     c:'var(--orange)',  bg:'var(--orange-bg)'},
      {l:'Mitigés',   v:mitige,   c:'var(--yellow)',  bg:'var(--yellow-bg)'},
      {l:'Clos',      v:clos,     c:'var(--green)',   bg:'var(--green-bg)'},
      {l:'Critiques', v:critical, c:'var(--red)',     bg:'var(--red-bg)'},
    ].map(k=>`<div style="background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:10px 12px;display:flex;align-items:center;gap:8px;box-shadow:var(--shadow);">
      <div style="width:32px;height:32px;border-radius:7px;background:${k.bg};display:grid;place-items:center;font-size:18px;font-weight:800;color:${k.c};font-family:var(--mono);flex-shrink:0;">${k.v}</div>
      <div style="font-size:11px;color:var(--text-muted);">${k.l}</div>
    </div>`).join(''));

    // ── Risk Control Matrix — double couche : Inhérent + Résiduel (COSO) ──
    const PROBS   = ['critical','high','medium','low'];
    const IMPACTS = ['low','medium','high','critical'];
    const PLABELS = {low:'Faible',medium:'Moyen',high:'Élevé',critical:'Critique'};
    const SCORE_TO_CELL = s => {

      const RANK = {low:0,medium:1,high:2,critical:3};
      let best = null, bestDiff = 99;
      PROBS.forEach((p,pi)=> IMPACTS.forEach((im,ii)=>{
        const diff = Math.abs(riskScore(p,im)-s);
        if(diff < bestDiff){ bestDiff=diff; best={pi,ii}; }
      }));
      return best;
    };

    const resCounts = {}, resRisks = {};
    RISKS.forEach(r=>{
      const sr  = riskScoreResiduel(r);

      const cell = SCORE_TO_CELL(sr);
      if(!cell) return;
      const rp = PROBS[cell.pi], rim = IMPACTS[cell.ii];
      const k2 = rp+'|'+rim;
      resCounts[k2] = (resCounts[k2]||0)+1;
      if(!resRisks[k2]) resRisks[k2]=[];
      resRisks[k2].push({...r, _sr:sr});
    });

    const cellW = 60, cellH = 48, padL = 56, padB = 32;
    const matW = padL + cellW*4 + 2;
    const matH = padB + cellH*4 + 2;

    let svg = `<svg width="${matW}" height="${matH}" style="display:block;width:100%;" viewBox="0 0 ${matW} ${matH}">`;

    svg += `<text x="10" y="${padB+cellH*2}" text-anchor="middle" font-size="9" fill="var(--text-muted)" transform="rotate(-90,10,${padB+cellH*2})">Probabilité</text>`;
    svg += `<text x="${padL+cellW*2}" y="${matH-2}" text-anchor="middle" font-size="9" fill="var(--text-muted)">Impact</text>`;
    PROBS.forEach((p,pi)=>{
      svg += `<text x="${padL-4}" y="${padB+pi*cellH+cellH/2+1}" text-anchor="end" font-size="8" fill="var(--text-muted)" dominant-baseline="middle">${PLABELS[p]}</text>`;
    });
    IMPACTS.forEach((im,ii)=>{
      svg += `<text x="${padL+ii*cellW+cellW/2}" y="${padB-6}" text-anchor="middle" font-size="8" fill="var(--text-muted)">${PLABELS[im]}</text>`;
    });

    PROBS.forEach((p,pi)=>{
      IMPACTS.forEach((im,ii)=>{
        const x=padL+ii*cellW, y=padB+pi*cellH;
        const col = matrixCellColor(p,im);
        svg += `<rect x="${x+1}" y="${y+1}" width="${cellW-2}" height="${cellH-2}" rx="3" fill="${col}22" stroke="${col}33" stroke-width="1"/>`;
      });
    });

    const resCounts2 = {}, resRisks2 = {};
    RISKS.forEach(r=>{
      const si = riskScore(r.probabilite, r.impact);
      const sr = riskScoreResiduel(r);
      if(sr === si) return;
      const cell = SCORE_TO_CELL(sr);
      if(!cell) return;
      const rp = PROBS[cell.pi], rim = IMPACTS[cell.ii];
      const k2 = rp+'|'+rim;
      resCounts2[k2] = (resCounts2[k2]||0)+1;
      if(!resRisks2[k2]) resRisks2[k2]=[];
      resRisks2[k2].push({...r, _sr:sr});
    });

    PROBS.forEach((p,pi)=>{
      IMPACTS.forEach((im,ii)=>{
        const k=p+'|'+im;
        const n=resCounts2[k]||0;
        if(!n) return;
        const x=padL+ii*cellW, y=padB+pi*cellH;
        const col=matrixCellColor(p,im);
        const tooltip=(resRisks2[k]||[]).map(r=>r.id+' '+r.titre+' (résiduel:'+r._sr+')').join('\n');
        svg += `<rect x="${x+cellW/2+1}" y="${y+cellH/2-11}" width="22" height="22" rx="3" fill="${col}99" stroke="${col}cc" stroke-width="1.5"/>`;
        svg += `<text x="${x+cellW/2+12}" y="${y+cellH/2}" text-anchor="middle" dominant-baseline="middle" font-size="${n>9?8:10}" font-weight="800" fill="#fff">${n}</text>`;
        svg += `<title>Résiduel COSO: ${tooltip}</title>`;
      });
    });

    RISKS.forEach(r=>{
      const sr = riskScoreResiduel(r);
      if(sr === riskScore(r.probabilite, r.impact)) return;
      const pi1 = PROBS.indexOf(r.probabilite), ii1 = IMPACTS.indexOf(r.impact);
      const rc   = SCORE_TO_CELL(sr);
      if(!rc || (rc.pi===pi1 && rc.ii===ii1)) return;
      const x1=padL+ii1*cellW+cellW/2-8, y1=padB+pi1*cellH+cellH/2;
      const x2=padL+rc.ii*cellW+cellW/2+12, y2=padB+rc.pi*cellH+cellH/2;
      svg += `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="#6366f1" stroke-width="1.2" stroke-dasharray="3,2" marker-end="url(#arr)" opacity=".7"/>`;
    });

    svg = svg.replace('<svg ', `<svg `) + '';
    svg = `<svg width="${matW}" height="${matH}" style="display:block;width:100%;" viewBox="0 0 ${matW} ${matH}">
      <defs><marker id="arr" markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto"><path d="M0,0 L6,3 L0,6 Z" fill="#6366f1" opacity=".8"/></marker></defs>` +
      svg.replace(`<svg width="${matW}" height="${matH}" style="display:block;width:100%;" viewBox="0 0 ${matW} ${matH}">`, '');

    svg += `</svg>`;
    $('#risk-matrix-wrap').html(svg);

    $('#risk-matrix-legend').html([
      {c:'#22c55e', l:'Faible (1–2)'},
      {c:'#eab308', l:'Modéré (3–4)'},
      {c:'#f59e0b', l:'Élevé (6–9)'},
      {c:'#ef4444', l:'Critique (12–16)'},
      {c:'#6366f1', l:'▪ Résiduel COSO'},
    ].map(x=>`<span style="display:flex;align-items:center;gap:4px;font-size:9.5px;color:var(--text-muted);">
      <i style="width:10px;height:10px;background:${x.c};border-radius:${x.c==='#6366f1'?'1':'2'}px;display:inline-block;opacity:.85;"></i>${x.l}
    </span>`).join(''));

    // Table
    const $tb = $('#risk-tbody').empty();
    if(!rows.length){
      $('#risk-table').hide();
      $('#risk-empty').show();
      return;
    }
    $('#risk-table').show();
    $('#risk-empty').hide();

    rows.forEach((r,i)=>{
      const si  = riskScore(r.probabilite, r.impact);
      const sr  = riskScoreResiduel(r);
      const linh = scoreToLevel(si);
      const lres = scoreToLevel(sr);
      const prc = RISK_COLORS[r.probabilite]||RISK_COLORS.low;
      const irc = RISK_COLORS[r.impact]||RISK_COLORS.low;
      const stc = {open:{c:'var(--orange)',bg:'var(--orange-bg)',l:'Ouvert'},
                   'mitigé':{c:'var(--yellow)',bg:'var(--yellow-bg)',l:'Mitigé'},
                   clos:{c:'var(--green)',bg:'var(--green-bg)',l:'Clos'}}[r.statut]
                  ||{c:'var(--text-muted)',bg:'var(--surface3)',l:r.statut};

      const cosoDone = COSO_COMPONENTS.filter(c=>parseInt(r['coso_'+c.key])>0).length;
      const cosoIcon = cosoDone===5 ? '●●●●●' : cosoDone>0 ? '●'.repeat(cosoDone)+'○'.repeat(5-cosoDone) : '○○○○○';
      const cosoCol  = cosoDone===5?'var(--green)':cosoDone>0?'var(--yellow)':'var(--text-dim)';
      const ctrlLbl  = CTRL_TYPES.find(t=>t.v===r.ctrl_type)?.l||'—';
      const mitigateStratLabels = {reduce:'Réduire',transfer:'Transférer',avoid:'Éviter',accept:'Accepter'};
      const mitigateStratColors = {reduce:'var(--green)',transfer:'var(--accent)',avoid:'var(--orange)',accept:'var(--text-muted)'};
      const mitStratLbl = r.mitigate_strategy ? (mitigateStratLabels[r.mitigate_strategy]||r.mitigate_strategy) : '—';
      const mitStratCol = r.mitigate_strategy ? (mitigateStratColors[r.mitigate_strategy]||'var(--text-muted)') : 'var(--text-dim)';
      const idx = RISKS.indexOf(r);
      $tb.append(`<tr>
        <td style="font-family:var(--mono);font-size:10px;color:var(--accent);">${r.id||'—'}</td>
        <td style="font-weight:500;max-width:170px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${r.titre||''}">${r.titre||'—'}</td>
        <td style="font-size:10px;color:var(--text-muted);max-width:90px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="${r.societe||''}">${r.societe||'—'}</td>
        <td><span style="font-size:9px;background:var(--surface3);padding:1px 5px;border-radius:3px;">${r.categorie||'—'}</span></td>
        <td class="t-center"><span style="font-size:9px;font-weight:600;color:${prc.c};background:${prc.bg};padding:1px 5px;border-radius:3px;">${RISK_LEVEL_LABELS[r.probabilite]||'—'}</span></td>
        <td class="t-center"><span style="font-size:9px;font-weight:600;color:${irc.c};background:${irc.bg};padding:1px 5px;border-radius:3px;">${RISK_LEVEL_LABELS[r.impact]||'—'}</span></td>
        <td class="t-center">
          <div style="display:flex;flex-direction:column;align-items:center;gap:2px;">
            <span style="font-size:11px;font-weight:800;color:${linh.c};font-family:var(--mono);" title="Score inhérent">${si}</span>
            <span style="font-size:9px;font-weight:700;color:${lres.c};font-family:var(--mono);opacity:.9;" title="Score résiduel (après contrôle)">▸${sr}</span>
          </div>
        </td>
        <td class="t-center">
          <div style="display:flex;flex-direction:column;align-items:center;gap:1px;">
            <span style="font-size:9px;font-weight:600;color:${mitStratCol};">${mitStratLbl}</span>
            <span style="font-size:8.5px;color:var(--text-dim);">${ctrlLbl}</span>
            <span style="font-size:9px;letter-spacing:-1px;color:${cosoCol};" title="COSO ${cosoDone}/5 composantes renseignées">${cosoIcon}</span>
          </div>
        </td>
        <td class="t-center"><span style="font-size:9px;font-weight:600;color:${stc.c};background:${stc.bg};padding:1px 5px;border-radius:3px;">${stc.l}</span></td>
        <td style="font-size:10px;">
          ${r.mitigate_plan ? `<span style="display:block;max-width:85px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--text-muted);" title="${r.mitigate_plan}">${r.mitigate_plan}</span>` : '<span style="color:var(--text-dim);">—</span>'}
          ${r.mitigate_deadline ? `<span style="font-size:9px;color:var(--text-dim);font-family:var(--mono);">${r.mitigate_deadline}</span>` : ''}
        </td>
        <td style="font-size:10px;color:var(--text-muted);">${r.responsable||'—'}</td>
        <td style="font-size:10px;color:var(--text-muted);font-family:var(--mono);">${r.echeance||'—'}</td>
        <td>
          <button class="tbtn" data-risk-edit="${idx}" style="font-size:10px;padding:1px 6px;">✏</button>
          <button class="tbtn" data-risk-del="${idx}"  style="font-size:10px;padding:1px 6px;color:var(--red);margin-left:2px;">✕</button>
        </td>
      </tr>`);
    });
  }catch(e){}
}

function openRiskModal(title, risk){
  const isEdit = !!risk;
  const SEL = (name, val, opts) =>
    `<select class="finp" id="rf-${name}" style="appearance:none;">` +
    opts.map(o=>`<option value="${o.v}"${val===o.v?' selected':''}>${o.l}</option>`).join('') +
    `</select>`;
  const LEVELS = RISK_LEVELS.map(v=>({v,l:RISK_LEVEL_LABELS[v]}));
  // COSO note rows
  const cosoRows = COSO_COMPONENTS.map(c=>{
    const v = isEdit ? (risk['coso_'+c.key]||0) : 0;
    return `<div style="display:grid;grid-template-columns:1fr auto;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid var(--border);">
      <div>
        <div style="font-size:11px;font-weight:600;color:var(--text);">${c.label}</div>
        <div style="font-size:9.5px;color:var(--text-dim);">${c.desc}</div>
      </div>
      <div style="display:flex;gap:3px;align-items:center;">
        ${[1,2,3,4].map(n=>`<label style="display:flex;flex-direction:column;align-items:center;gap:1px;cursor:pointer;">
          <input type="radio" name="coso_${c.key}" value="${n}" ${v==n?'checked':''} style="accent-color:var(--accent);">
          <span style="font-size:8.5px;color:var(--text-dim);">${n}</span>
        </label>`).join('')}
        <span style="font-size:8px;color:var(--text-dim);margin-left:4px;white-space:nowrap;">Absent→Fort</span>
      </div>
    </div>`;
  }).join('');

  const html = `

  <div style="background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:5px;padding:10px 13px;margin-bottom:12px;">
    <div style="font-size:11px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px;">📋 Identification du risque</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">ID</div>
        <input class="finp" id="rf-id" value="${isEdit?risk.id||'':''}" placeholder="R-001"></div>
      <div class="frow2"><div class="flbl2">Société</div>
        <select class="finp" id="rf-societe"><option value="">—</option>
          ${SOCIETES.map(s=>`<option value="${s.nom}"${isEdit&&s.nom===risk.societe?' selected':''}>${s.nom}</option>`).join('')}
        </select></div>
    </div>
    <div class="frow2"><div class="flbl2">Intitulé du risque</div>
      <input class="finp" id="rf-titre" value="${isEdit?risk.titre||'':''}" placeholder="Décrire le risque…"></div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;">
      <div class="frow2"><div class="flbl2">Catégorie</div>
        <select class="finp" id="rf-categorie">
          ${['Opérationnel','Financier','Technologique','Conformité','Stratégique','Réputation']
            .map(c=>`<option value="${c}"${isEdit&&risk.categorie===c?' selected':''}>${c}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Responsable</div>
        <input class="finp" id="rf-responsable" value="${isEdit?risk.responsable||'':''}" placeholder="Prénom Nom"></div>
      <div class="frow2"><div class="flbl2">Échéance</div>
        <input class="finp" id="rf-echeance" type="date" value="${isEdit?risk.echeance||'':''}"></div>
    </div>
    <div class="frow2"><div class="flbl2">Description</div>
      <textarea class="finp" id="rf-desc" rows="2" style="resize:vertical;">${isEdit?risk.description||'':''}</textarea></div>
  </div>

  <div style="background:var(--red-bg);border:1px solid #fca5a5;border-radius:5px;padding:10px 13px;margin-bottom:12px;">
    <div style="font-size:11px;font-weight:700;color:var(--red);text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px;">⚠ Risque Inhérent <span style="font-size:10px;font-weight:400;color:var(--text-muted);">(avant contrôle)</span></div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;align-items:end;">
      <div class="frow2"><div class="flbl2">Probabilité</div>
        ${SEL('probabilite', isEdit?risk.probabilite:'medium', LEVELS)}</div>
      <div class="frow2"><div class="flbl2">Impact</div>
        ${SEL('impact', isEdit?risk.impact:'medium', LEVELS)}</div>
      <div class="frow2"><div class="flbl2">Score inhérent</div>

      </div>
    </div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:4px;">
      <div class="frow2"><div class="flbl2">Statut</div>
        <select class="finp" id="rf-statut">
          <option value="open"${!isEdit||risk.statut==='open'?' selected':''}>Ouvert</option>
          <option value="mitigé"${isEdit&&risk.statut==='mitigé'?' selected':''}>Mitigé</option>
          <option value="clos"${isEdit&&risk.statut==='clos'?' selected':''}>Clos</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Type de contrôle</div>
        <select class="finp" id="rf-ctrl-type">
          <option value="">— Aucun —</option>
          ${CTRL_TYPES.map(t=>`<option value="${t.v}"${isEdit&&risk.ctrl_type===t.v?' selected':''}>${t.l}</option>`).join('')}
        </select></div>
    </div>
    <div class="frow2"><div class="flbl2">Description du contrôle</div>
      <textarea class="finp" id="rf-ctrl-desc" rows="2" style="resize:vertical;">${isEdit?risk.ctrl_description||'':''}</textarea></div>
  </div>

  <div style="background:var(--purple-bg,#f3f0ff);border:1px solid #c4b5fd;border-radius:5px;padding:10px 13px;margin-bottom:12px;">
    <div style="font-size:11px;font-weight:700;color:var(--purple,#6941c6);text-transform:uppercase;letter-spacing:.06em;margin-bottom:10px;">🛡 Plan de Mitigation</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:6px;">
      <div class="frow2"><div class="flbl2">Stratégie de réponse</div>
        <select class="finp" id="rf-mitigate-strategy">
          <option value="">— Choisir —</option>
          <option value="reduce" ${isEdit&&risk.mitigate_strategy==='reduce'?'selected':''}>Réduire (contrôle)</option>
          <option value="transfer" ${isEdit&&risk.mitigate_strategy==='transfer'?'selected':''}>Transférer (assurance)</option>
          <option value="avoid" ${isEdit&&risk.mitigate_strategy==='avoid'?'selected':''}>Éviter (suppression)</option>
          <option value="accept" ${isEdit&&risk.mitigate_strategy==='accept'?'selected':''}>Accepter (tolérance)</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Échéance mitigation</div>
        <input class="finp" id="rf-mitigate-deadline" type="date" value="${isEdit?risk.mitigate_deadline||'':''}"></div>
    </div>
    <div class="frow2"><div class="flbl2">Plan d'action / Mesures de mitigation</div>
      <textarea class="finp" id="rf-mitigate-plan" rows="2" style="resize:vertical;" placeholder="Décrire les actions correctives, les contrôles à mettre en place…">${isEdit?risk.mitigate_plan||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Responsable de la mitigation</div>
      <input class="finp" id="rf-mitigate-owner" value="${isEdit?risk.mitigate_owner||'':''}" placeholder="Prénom Nom"></div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border2);border-radius:5px;padding:10px 13px;margin-bottom:12px;">
    <div style="font-size:11px;font-weight:700;color:var(--purple,#6941c6);text-transform:uppercase;letter-spacing:.06em;margin-bottom:8px;">
      🏛 COSO 2013 — Évaluation des contrôles
      <span style="font-size:9px;font-weight:400;color:var(--text-muted);"> · 1 = Absent · 2 = Insuffisant · 3 = Partiel · 4 = Efficace (Fort)</span>

    </div>
    ${cosoRows}
  </div>

  <div style="background:var(--green-bg);border:1px solid #86efac;border-radius:5px;padding:10px 13px;">
    <div style="font-size:11px;font-weight:700;color:var(--green);text-transform:uppercase;letter-spacing:.06em;margin-bottom:6px;">✓ Risque Résiduel <span style="font-size:10px;font-weight:400;color:var(--text-muted);">(calculé selon COSO)</span></div>
    <div style="display:flex;align-items:center;gap:20px;">
      <div class="t-center">
        <div style="font-size:10px;color:var(--text-muted);margin-bottom:2px;">Inhérent</div>

      </div>
      <div style="font-size:20px;color:var(--text-muted);">→</div>
      <div class="t-center">
        <div style="font-size:10px;color:var(--text-muted);margin-bottom:2px;">Résiduel</div>

      </div>
      <div style="flex:1;padding-left:10px;">

      </div>
    </div>
  </div>`;

  openModal(title, html);
  // Étiquette du bouton Enregistrer
  $('#msave').text(isEdit ? 'Enregistrer' : 'Créer').data('mode','risk-save');

  function readCosoNotes(){

    const notes = {};
    COSO_COMPONENTS.forEach(c=>{
      const v = parseInt($(`input[name="coso_${c.key}"]:checked`).val())||0;
      notes[c.key] = v;
    });
    return notes;
  }

  function cosoFacteur(notes){
    const vals = COSO_COMPONENTS.map(c=>notes[c.key]).filter(n=>n>0);
    if(vals.length < COSO_COMPONENTS.length) return null;
    const moy = vals.reduce((a,b)=>a+b,0) / vals.length;

    return Math.max(0.10, 1 - (moy - 1) / 3 * 0.85);
  }

  function updateScores(){
    const p  = $('#rf-probabilite').val();
    const im = $('#rf-impact').val();
    const si = riskScore(p, im);
    const li = scoreToLevel(si);

    $('#rf-inh-display').text(si).css({color: li.c, background: li.bg});
    $('#rf-res-inh').text(si).css('color', li.c);

    const notes   = readCosoNotes();
    const facteur = cosoFacteur(notes);
    const sr      = facteur !== null
      ? Math.max(1, Math.round(si * facteur))
      : si;
    const lr = scoreToLevel(sr);

    $('#rf-res-fin').text(sr).css('color', lr.c);
    $('#rf-res-label').text(lr.l).css('color', lr.c);

    if(facteur !== null){
      const pct = Math.round((1 - facteur) * 100);
      const nbOk = COSO_COMPONENTS.map(c=>notes[c.key]).filter(n=>n>=3).length;
      const moy  = (COSO_COMPONENTS.map(c=>notes[c.key]).reduce((a,b)=>a+b,0)/COSO_COMPONENTS.length).toFixed(2);
      $('#rf-res-note').text(`Réduction : ${pct}% · ${nbOk}/5 composantes efficaces`);
      $('#rf-coso-formula').html(
        `Moyenne COSO = ${moy}/4 → facteur = ${(facteur*100).toFixed(0)}% → `+
        `Score résiduel = ${si} × ${(facteur).toFixed(2)} = <strong>${sr}</strong>`
      );
    } else {
      const done = COSO_COMPONENTS.map(c=>notes[c.key]).filter(n=>n>0).length;
      $('#rf-res-note').text(done===0
        ? 'Renseignez les 5 composantes COSO pour calculer le risque résiduel'
        : `${done}/5 composantes renseignées — complétez pour le calcul`);
      $('#rf-coso-formula').text(done>0 ? `${done}/5 composantes saisies…` : '');
    }
  }

  // Bind tous les champs qui influencent le calcul
  $(document).on('change', '#rf-probabilite, #rf-impact', updateScores);
  $(document).on('change', 'input[name^="coso_"]', updateScores);
  updateScores();

  window._risksaveHandler = function(){
    if(!window._risksaveHandler) return;
    const titre = $('#rf-titre').val().trim();
    if(!titre){ toast('error','!','Titre requis.'); return; }

    const notes   = readCosoNotes();
    const facteur = cosoFacteur(notes);
    const si      = riskScore($('#rf-probabilite').val(), $('#rf-impact').val());
    const sr      = facteur !== null ? Math.max(1, Math.round(si * facteur)) : si;

    const cosoData = {};
    COSO_COMPONENTS.forEach(c=>{ cosoData['coso_'+c.key] = notes[c.key]||0; });

    const obj = {
      id:               $('#rf-id').val().trim() || ('R-'+(RISKS.length+1).toString().padStart(3,'0')),
      titre,
      societe:          $('#rf-societe').val(),
      categorie:        $('#rf-categorie').val(),
      statut:           $('#rf-statut').val(),
      probabilite:      $('#rf-probabilite').val(),
      impact:           $('#rf-impact').val(),
      score:            si,
      score_residuel:   sr,
      ctrl_type:        $('#rf-ctrl-type').val(),
      ctrl_description: $('#rf-ctrl-desc').val().trim(),
      mitigate_strategy:  $('#rf-mitigate-strategy').val(),
      mitigate_plan:      $('#rf-mitigate-plan').val().trim(),
      mitigate_deadline:  $('#rf-mitigate-deadline').val(),
      mitigate_owner:     $('#rf-mitigate-owner').val().trim(),
      responsable:      $('#rf-responsable').val().trim(),
      echeance:         $('#rf-echeance').val(),
      description:      $('#rf-desc').val().trim(),
      ...cosoData,
    };
    if(isEdit){
      Object.assign(risk, obj);
    } else {

      const existingIdx = RISKS.findIndex(r => r.id === obj.id);
      if(existingIdx >= 0){
        Object.assign(RISKS[existingIdx], obj);
      } else {
        RISKS.push(obj);
      }
    }
    delete window._risksaveHandler;
    closeModal();
    renderRisks();
    dbSave();
    toast('success','✓', isEdit ? 'Risque mis à jour' : 'Risque créé');
  };
}

$(document).on('click','#risk-add-btn', ()=>openRiskModal('Nouveau risque', null));
$(document).on('click','[data-risk-edit]', function(){
  const i = parseInt($(this).data('risk-edit'));
  if(RISKS[i]) openRiskModal('Modifier le risque', RISKS[i]);
});
$(document).on('click','[data-risk-del]', function(){
  const i = parseInt($(this).data('risk-del'));
  if(!RISKS[i]) return;
  if(!confirm('Supprimer ce risque ?')) return;
  RISKS.splice(i,1);
  renderRisks();
  dbSave();
  toast('success','✓','Risque supprimé');
});
$(document).on('change','#risk-f-statut,#risk-f-cat,#risk-f-soc', ()=>renderRisks());

let SOCIETES=[];
let socEditId=null;

function renderSocietes(filter=''){
    $.ajax({
        url: "/DAC/php/societe/actions.php",
        type: "POST",
        dataType: "json",
        data: {
            action: "lister"
        },

        success: function(response) {

            if (response.success) {

                SOCIETES = response.data;

                afficherSocietes(filter);

            } else {
                console.log(response.message);
            }
        },

        error: function(xhr) {

            console.log("Erreur AJAX :", xhr.responseText);

        }
    });
}

function afficherSocietes(filter = '') {

    // Garantir _uid unique sur toutes les sociétés
    SOCIETES.forEach((s,i)=>{

        if(!s._uid)
            s._uid='soc_'+i+'_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);

    });


    const $tb = $('#soc-tbody').empty();

    let rows = SOCIETES;


    if(filter){

        filter = filter.toLowerCase();

        rows = rows.filter(s =>
            (s.nom || '').toLowerCase().includes(filter) ||
            (s.code || '').toLowerCase().includes(filter) ||
            (s.pays || '').toLowerCase().includes(filter) ||
            (s.secteur || '').toLowerCase().includes(filter)
        );

    }


    $('#soc-count-badge').text(SOCIETES.length);


    if(!rows.length){

        $('#soc-empty').show();
        return;

    }


    $('#soc-empty').hide();


    rows.forEach((s,i)=>{


        const realIdx = SOCIETES.indexOf(s);


        const statMap = {
            active:{
                cls:'completed',
                lbl:'Active'
            },
            inactive:{
                cls:'planned',
                lbl:'Inactive'
            },
            suspended:{
                cls:'overdue',
                lbl:'Suspendue'
            }
        };


        const st = statMap[s.statut] || {
            cls:'planned',
            lbl:s.statut || ''
        };


        const logoUrl = getSocLogo(socKey(s));
        const logoThumb = getSocLogoThumb(socKey(s));


        const logoCell = logoThumb
        ?
        `
        <div style="width:36px;height:36px;background:#fff;border:1px solid var(--border);border-radius:6px;overflow:hidden;display:flex;align-items:center;justify-content:center;">
            <img src="${logoThumb}" style="max-width:34px;max-height:34px;object-fit:contain;" alt="${s.nom}">
        </div>
        `
        :
        `
        <div class="btn soc-logo-upload-btn"
             data-code="${s.code}"
             data-uid="${socKey(s)}"
             style="width:36px;height:36px;border-radius:6px;display:flex;align-items:center;justify-content:center;font-size:16px;cursor:pointer;">
             🏢
        </div>
        `;


        $tb.append(`

        <tr>

            <td style="padding:6px 10px;">
                ${logoCell}
            </td>


            <td>
                <span style="font-family:var(--mono);font-size:11px;color:var(--accent);font-weight:600">
                    ${s.code || '—'}
                </span>
            </td>


            <td>
                <div style="font-weight:600">${s.nom || ''}</div>
                <div style="font-size:10px;color:var(--text-muted)">
                    ${s.adresse || ''}
                </div>
            </td>


            <td>
                ${s.secteur || '—'}
            </td>


            <td>
                ${s.pays || '—'}
            </td>


            <td>
                <span>
                    ${s.groupe || '—'}
                </span>
            </td>


            <td>
                <span class="badge ${st.cls}">
                    ${st.lbl}
                </span>
            </td>


            <td>

                <button class="btn soc-edit-btn"
                        data-idx="${realIdx}">
                    ✏️
                </button>


                <button class="btn soc-del-btn"
                        data-idx="${realIdx}">
                    🗑
                </button>

            </td>


        </tr>

        `);


    });

}



$('#soc-search').on('input',function(){renderSocietes($(this).val().toLowerCase());});

let socFormLogoData = null;
let socFormLogoThumb = null;

function updateSocLogoPreview(dataUrl, filename){
  if(dataUrl){
    $('#soc-logo-img').attr('src', dataUrl).show();
    $('#soc-logo-placeholder').hide();
    $('#soc-logo-clear-btn').show();
    $('#soc-logo-name').text(filename||'Logo chargé');
    $('#soc-logo-preview').css('border-style','solid').css('border-color','var(--accent)');
  } else {
    $('#soc-logo-img').hide().attr('src','');
    $('#soc-logo-placeholder').show();
    $('#soc-logo-clear-btn').hide();
    $('#soc-logo-name').text('');
    $('#soc-logo-preview').css('border-style','dashed').css('border-color','var(--border)');
  }
}

$('#soc-logo-btn, #soc-logo-preview').on('click', function(){ $('#soc-logo-file-input').trigger('click'); });
$('#soc-logo-clear-btn').on('click', function(e){ e.stopPropagation(); socFormLogoData=null; socFormLogoThumb=null; updateSocLogoPreview(null); });
$('#soc-logo-file-input').on('change', function(){
  const file=this.files[0]; if(!file) return;
  if(!file.type.match(/image\/(jpe?g|png)/i)){ toast('error','!','Seuls les fichiers JPG et PNG sont acceptés'); this.value=''; return; }
  if(file.size>3*1024*1024){ toast('error','!','Image trop lourde (max 3 Mo)'); this.value=''; return; }
  const reader=new FileReader();
  reader.onload=function(ev){
    const original=ev.target.result;
    // Generate thumbnail 80x80
    const img=new Image();
    img.onload=function(){
      const canvas=document.createElement('canvas');
      const MAX=80; let w=img.width,h=img.height;
      if(w>h){ h=Math.round(h*MAX/w); w=MAX; } else { w=Math.round(w*MAX/h); h=MAX; }
      canvas.width=w; canvas.height=h;
      canvas.getContext('2d').drawImage(img,0,0,w,h);
      socFormLogoThumb=canvas.toDataURL('image/jpeg',0.85);
      socFormLogoData=original;
      updateSocLogoPreview(original, file.name);
    };
    img.src=original;
  };
  reader.readAsDataURL(file);
  this.value='';
});

$('#soc-save-btn').on('click',function(){

  const nom = $('#soc-nom').val().trim();
  if(!nom){ toast('error','!','Le nom de la société est requis'); $('#soc-nom').focus(); return; }
    const isEdit = socEditId !== null;

    const data = {
      action: isEdit ? 'modifier' : 'ajouter',

      code_societe: isEdit
      ? SOCIETES[socEditId].code_societe 
      : '',

      nom: nom,
      code: $('#soc-code').val().trim(),
      secteur: $('#soc-secteur').val(),
      pays: $('#soc-pays').val(),
      groupe: $('#soc-groupe').val(),
      adresse: $('#soc-adresse').val().trim(),
      email: $('#soc-email').val().trim(),
      statut: $('#soc-statut').val() || 'active',
      notes: $('#soc-notes').val().trim()
    };


  $('#soc-save-btn').prop('disabled', true); // évite le double-clic pendant la requête
   
  if(!nom){
      toast('error','!','Le nom de la société est requis');
      $('#soc-nom').focus();
      return;
  }

  $('#soc-save-btn').prop('disabled', true);
    $.ajax({
        url: "/DAC/php/societe/actions.php",
        type: "POST",
        data: data,
        dataType: "json",

        success: function(response){

            console.log(response);

            if(response.success){

                toast(
                  'success',
                  'OK',
                  isEdit ? 'Société modifiée avec succès' : 'Société ajoutée avec succès'
                );

                reinitialiser();
                
            }else{

                toast('error','Erreur',response.message);

            }

            $('#soc-save-btn').prop('disabled', false);
        },


        error:function(xhr,status,error){

            console.log("Status :",status);
            console.log("Erreur :",error);
            console.log("Réponse :",xhr.responseText);

