function afficherResponsables(filter = '') {
  // Garantir _uid unique sur tous les responsables
RESPONSABLES.forEach((r, i) => {

    if (!r._uid)
        r._uid = 'resp_' + i + '_' + Date.now() + '_' + Math.random().toString(36).slice(2, 7);

});


const $tb = $('#resp-tbody').empty();

let rows = RESPONSABLES;


if (filter) {

    filter = filter.toLowerCase();

    rows = rows.filter(r =>
        (r.nom || '').toLowerCase().includes(filter) ||
        (r.prenom || '').toLowerCase().includes(filter) ||
        (r.email || '').toLowerCase().includes(filter) ||
        (r.fonction || '').toLowerCase().includes(filter) ||
        (r.direction || '').toLowerCase().includes(filter) ||
        (r.nom_societe || '').toLowerCase().includes(filter)
    );

}


$('#resp-count-badge').text(RESPONSABLES.length);


if (!rows.length) {

    $('#resp-empty').show();
    return;

}


$('#resp-empty').hide();
  rows.forEach((r, i) => {


      const realIdx = RESPONSABLES.indexOf(r);


      const statMap = {
          active: {
              cls: 'completed',
              lbl: 'Actif'
          },
          inactive: {
              cls: 'planned',
              lbl: 'Inactif'
          },
          suspended: {
              cls: 'overdue',
              lbl: 'Suspendu'
          }
      };


      const st = statMap[r.statut] || {
          cls: 'planned',
          lbl: r.statut || ''
      };


      const initiales = ((r.prenom||'').charAt(0) + (r.nom||'').charAt(0)).toUpperCase();
      const avatarCell = `
        <div style="width:36px;height:36px;background:var(--accent);color:#fff;border-radius:50%;overflow:hidden;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;">
            ${initiales || '👤'}
        </div>
        `;


        $tb.append(`

        <tr>

          <td style="padding:6px 10px;">
              ${avatarCell}
              <div style="font-weight:600">${r.prenom || ''} ${r.nom || ''}</div>
                ${r.telephone || ''}
          </td>

          <td>
              ${r.email || '—'}
          </td>

          <td>
              ${r.fonction || '—'}
          </td>


          <td>
              ${r.direction || '—'}
          </td>

          <td>
              <span class="badge ${st.cls}">
                  ${st.lbl}
              </span>
          </td>


          <td>

              <button class="btn resp-edit-btn"
                      data-idx="${realIdx}">
                  ✏️
              </button>


              <button class="btn resp-del-btn"
                      data-idx="${realIdx}">
                  🗑
              </button>

          </td>


      </tr>

      `);


  });
}

