            }
        },

        error: function(xhr) {

            console.log("Erreur AJAX :", xhr.responseText);

        }
    });
}

function afficherAuditeurs(filter = '') {

    // Garantir _uid unique sur tous les auditeurs
    AUDITEURS.forEach((a,i)=>{

        if(!a._uid)
            a._uid='aud_'+i+'_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);

    });


    const $tb = $('#aud-tbody').empty();

    let rows = AUDITEURS;


    if(filter){

        filter = filter.toLowerCase();

        rows = rows.filter(a =>
            (a.nom || '').toLowerCase().includes(filter) ||
            (a.prenom || '').toLowerCase().includes(filter) ||
            (a.email || '').toLowerCase().includes(filter) ||
            (a.role || '').toLowerCase().includes(filter)
        );

    }


    $('#aud-count-badge').text(AUDITEURS.length);


    if(!rows.length){

        $('#aud-empty').show();
        return;

    }


    $('#aud-empty').hide();


    const todayStr = new Date().toISOString().slice(0,10);

    /* ── Calcule ancienneté en "X an(s) Y mois" à partir d'une date ISO ── */
    function calcAnciennete(dateStr, couleur) {

        if(!dateStr) return '<span style="color:var(--text-dim);font-size:11px;">—</span>';

        const d = new Date(dateStr);

        if(isNaN(d)) return `<span style="font-size:11px;color:var(--text-muted);">${dateStr}</span>`;

        const now = new Date();

        let ans  = now.getFullYear() - d.getFullYear();
        let mois = now.getMonth()    - d.getMonth();

        if(now.getDate() < d.getDate()) mois--;
        if(mois < 0){ ans--; mois += 12; }
        if(ans < 0)  { ans = 0; mois = Math.max(0, mois); }

        let label;

        if(ans === 0 && mois === 0)       label = '< 1 mois';
        else if(ans === 0)                label = `${mois} mois`;
        else if(mois === 0)               label = `${ans} an${ans>1?'s':''}`;
        else                              label = `${ans} an${ans>1?'s':''} ${mois} mois`;

        const col = couleur
            ? (ans>=10?'#1a8a4a':ans>=5?'#0070f2':ans>=2?'#6941c6':'#c47d00')
            : 'var(--text-muted)';

        const dateDisp = d.toLocaleDateString('fr-FR',{day:'2-digit',month:'short',year:'numeric'});

        return `<span style="font-size:11px;background:${col}22;color:${col};padding:1px 7px;border-radius:3px;font-weight:600;" title="Depuis le ${dateDisp}">${label}</span>`;
    }


    rows.forEach((a,i)=>{


        const realIdx = AUDITEURS.indexOf(a);


        const statMap = {
            active:{
                cls:'completed',
                lbl:'Actif'
            },
            inactive:{
                cls:'planned',
                lbl:'Inactif'
            },
            suspended:{
                cls:'overdue',
                lbl:'Suspendu'
            }
        };


        const st = statMap[a.statut] || {
            cls:'planned',
            lbl:a.statut || ''
        };


        const initiales = ((a.prenom||'').charAt(0) + (a.nom||'').charAt(0)).toUpperCase();


        const avatarCell = `
        <div style="width:36px;height:36px;background:var(--accent);color:#fff;border-radius:50%;overflow:hidden;display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:600;">
            ${initiales || '👤'}
        </div>
        `;


        $tb.append(`

        <tr>

            <td style="padding:6px 10px;">
                ${avatarCell}
                <div style="font-weight:600">${a.prenom || ''} ${a.nom || ''}</div>
                 ${a.telephone || ''}
            </td>


            <td>
                <div style="font-size:10px;color:var(--text-muted)">
                    ${a.email || ''}
                </div>
            </td>


            <td>
                ${a.role || '—'}
            </td>


            <td>
                ${calcAnciennete(a.date_entree, true)}
            </td>


            <td>
                ${a.date_entree || '—'}
            </td>
            
            <td>
                ${calcAnciennete(a.date_entree, false)}
            </td>

            <td>
                ${a.specialisation || '—'}
            </td>

            <td>
                ${a.certifications || '—'}
            </td>

            <td>
                <span class="badge ${st.cls}">
                  ${st.lbl}
                </span>
            </td>

            <td>

                <button class="btn aud-edit-btn"
                  data-idx="${realIdx}">✏️
                </button>


                <button class="btn aud-del-btn"
                  data-idx="${realIdx}">🗑
                </button>

            </td>


        </tr>

        `);


    });

}

