$(document).on('click','.daily-del-btn', function(){
  const idx = parseInt($(this).data('idx'));
  const t = DAILY_TASKS[idx]; if(!t) return;
  if(!confirm(`Supprimer "${t.titre}" ?`)) return;
  DAILY_TASKS.splice(idx,1);
  renderDailyTasks(); dbSave();
  toast('success','🗑','Tâche supprimée');
});

$(document).on('click','.daily-toggle-done', function(){
  const idx = parseInt($(this).data('idx'));
  const t = DAILY_TASKS[idx]; if(!t) return;
  t.statut = (t.statut==='done') ? 'todo' : 'done';
  if(t.statut==='done') t.avancement=100;
  else t.avancement=0;

  renderDailyTasks(); dbSave();
});

$(document).on('click','.daily-prog-btn', function(){
  const idx = parseInt($(this).data('idx'));
  const t = DAILY_TASKS[idx]; if(!t) return;
  openModal(`📊 Avancement — ${t.titre}`,
    `<div class="frow2"><div class="flbl2">Avancement : <span id="dqp-lbl" style="color:var(--accent);font-weight:700;">${t.avancement||0}%</span></div>
      <input type="range" id="dqp-range" min="0" max="100" step="5" value="${t.avancement||0}" style="width:100%;margin-top:6px;accent-color:var(--accent);">
    </div>
    <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:10px;">
      ${[0,25,50,75,100].map(v=>`<button class="btn dqp-preset" data-v="${v}" style="font-size:11px;padding:3px 10px;${v===(t.avancement||0)?'background:var(--accent);color:#fff;':''}">${v}%</button>`).join('')}
    </div>`);
  $(document).on('input.dqprange','#dqp-range',function(){$('#dqp-lbl').text($(this).val()+'%');});
  $(document).on('click.dqppreset','.dqp-preset',function(){
    $('#dqp-range').val($(this).data('v'));$('#dqp-lbl').text($(this).data('v')+'%');
    $('.dqp-preset').css({background:'',color:''});$(this).css({background:'var(--accent)',color:'#fff'});
  });
  $('#msave').text('Mettre à jour').data('mode','daily-prog-save');
  window._dqpSave = function(){
    t.avancement = parseInt($('#dqp-range').val())||0;
    if(t.avancement>=100) t.statut='done'; else if(t.avancement>0) t.statut='inprogress';

    $(document).off('input.dqprange click.dqppreset');
    delete window._dqpSave;
    closeModal(); renderDailyTasks(); dbSave();
    toast('success','✓',`Avancement : ${t.avancement}%`);
  };
});

