// ── Alertes mail ──────────────────────────────────────────────

function buildMailtoAlert(destinataire, sujet, lignes){
  if(!lignes.length){
    toast('info','✅','Aucune tâche en retard — aucun mail nécessaire.');
    return;
  }
  const corps = [
    'Bonjour,',
    '',
    'Voici la liste des tâches en retard nécessitant votre attention :',
    '',
    ...lignes,
    '',
    '---',
    'Message généré automatiquement par le tableau de bord Audit & Contrôle.',
    new Date().toLocaleDateString('fr-FR',{weekday:'long',year:'numeric',month:'long',day:'numeric'})
  ].join('\n');
  const url = 'mailto:'+(destinataire||'')+'?subject='+encodeURIComponent(sujet)+'&body='+encodeURIComponent(corps);
  window.location.href = url;
}

$(document).on('click','#daily-alert-btn',function(){
  const today = new Date(); today.setHours(0,0,0,0);
  const prioLabel = {high:'🔴 Haute',medium:'🟡 Moyenne',low:'🟢 Basse'};
  const lignes = DAILY_TASKS.filter(t=>t.date&&new Date(t.date)<today&&t.statut!=='done')
    .map(t=>{
      const j=Math.floor((today-new Date(t.date))/86400000);
      return '• "'+t.titre+'" — '+(prioLabel[t.priorite]||'—')+' — échéance '+t.date+' (+'+j+'j)'+(t.responsable?' — '+t.responsable:'');
    });
  const n=lignes.length;
  if(!n){toast('info','✅','Aucune tâche quotidienne en retard.');return;}
  openModal('📧 Alerte — Tâches quotidiennes en retard',
    '<div style="background:var(--red-bg);border:1px solid #f5b8b8;border-radius:5px;padding:10px 13px;margin-bottom:14px;font-size:12px;color:var(--red);font-weight:600;">⏰ '+n+' tâche'+(n>1?'s':'')+' en retard</div>'+
    '<div class="frow2"><div class="flbl2">Destinataire(s)</div><input class="finp" id="alert-dest-daily" placeholder="responsable@example.com" type="email"></div>'+
    '<div style="background:var(--surface2);border-radius:4px;padding:10px 12px;font-size:11px;font-family:var(--mono);color:var(--text-muted);max-height:180px;overflow-y:auto;border:1px solid var(--border);">'+
    lignes.map(l=>'<div style="padding:2px 0;border-bottom:1px solid var(--border);">'+l+'</div>').join('')+
    '</div><div style="font-size:10px;color:var(--text-dim);margin-top:8px;">⚠ Cliquez Envoyer pour ouvrir votre client mail.</div>'
  );
  $('#msave').text('📧 Envoyer').data('mode','alert-mail-daily');
  window._alertMailDailyHandler = function(){buildMailtoAlert($('#alert-dest-daily').val().trim(),'⏰ Alerte : '+n+' tâche'+(n>1?'s':'')+' quotidienne'+(n>1?'s':'')+' en retard',lignes);};
});

const DB_ALL_KEYS=['audit_societes','audit_auditeurs','audit_responsables','audit_audits','audit_actions','audit_gantt','audit_risks','audit_daily_tasks','audit_absences','audit_rcm_data','audit_soc_logos','audit_saved_at','audit_ordres_mission','daci_eisenhower'];

function dbSave(){
  try{
    localStorage.setItem('audit_societes',  JSON.stringify(SOCIETES));
    localStorage.setItem('audit_auditeurs', JSON.stringify(AUDITEURS));
    localStorage.setItem('audit_responsables', JSON.stringify(RESPONSABLES));
    localStorage.setItem('audit_audits',    JSON.stringify(AUDITS));
    localStorage.setItem('audit_actions',   JSON.stringify(ACTIONS));
    localStorage.setItem('audit_gantt',     JSON.stringify(GANTT_MISSIONS));
    localStorage.setItem('audit_risks',     JSON.stringify(RISKS));
    localStorage.setItem('audit_daily_tasks', JSON.stringify(DAILY_TASKS));
    localStorage.setItem('audit_absences',    JSON.stringify(ABSENCES));
    localStorage.setItem('audit_rcm_data',    JSON.stringify(RCM_DATA));
    localStorage.setItem('daci_eisenhower',   JSON.stringify(EIS_TASKS));
    localStorage.setItem('audit_saved_at',  new Date().toISOString());
  }catch(e){}
}

function dbLoad(){
  try{
    const s =localStorage.getItem('audit_societes');
    const a =localStorage.getItem('audit_auditeurs');
    const resp_raw=localStorage.getItem('audit_responsables');
    const au=localStorage.getItem('audit_audits');
    const ac=localStorage.getItem('audit_actions');
    const gm=localStorage.getItem('audit_gantt');
    if(s)  _reload(SOCIETES,      JSON.parse(s));
    if(a)  _reload(AUDITEURS,     JSON.parse(a));
    if(resp_raw) _reload(RESPONSABLES, JSON.parse(resp_raw));
    if(au) _reload(AUDITS, JSON.parse(au));

    AUDITS.forEach(a=>{ a.actual_start=a.actual_start||''; a.actual_end=a.actual_end||''; a.lieu=a.lieu||''; a.statut_doc=a.statut_doc||'Projet de rapport'; });
    if(ac) _reload(ACTIONS,       JSON.parse(ac));
    const rk=localStorage.getItem('audit_risks');
    if(gm) _reload(GANTT_MISSIONS,JSON.parse(gm));
    if(rk) _reload(RISKS,         JSON.parse(rk));
    const dt=localStorage.getItem('audit_daily_tasks');
    if(dt){
      const parsed=JSON.parse(dt);
      // Exclure les tâches issues des Plans d'audit (ganttRef / auditRef)
      const cleanParsed=parsed.filter(t=>!t.ganttRef && !t.auditRef);
      const existingPermIds=new Set(cleanParsed.filter(t=>t.permanent).map(t=>t.id));
      const missing=PERMANENT_TASKS_DEFAULT.filter(p=>!existingPermIds.has(p.id));
      _reload(DAILY_TASKS,[...missing,...cleanParsed]);
    }
    const abk=localStorage.getItem("audit_absences");
    if(abk) _reload(ABSENCES, JSON.parse(abk));
    const rcmk=localStorage.getItem("audit_rcm_data");
    if(rcmk) _reload(RCM_DATA, JSON.parse(rcmk));
    const eisk=localStorage.getItem("daci_eisenhower");
    if(eisk) _reload(EIS_TASKS, JSON.parse(eisk));
    return !!(s||a||au||fi||ac||gm||rk||dt||abk);
  }catch(e){return false;}
}

function patchAutoSave(){
  $('#soc-save-btn').on('click.autosave',()=>setTimeout(dbSave,50));
  $('#aud-save-btn').on('click.autosave',()=>setTimeout(dbSave,50));
  $(document).on('click.autosave','.soc-del-btn, .aud-del-btn',()=>setTimeout(dbSave,50));

}

function updateStorageInfo(){
  const savedAt=localStorage.getItem('audit_saved_at');
  let totalBytes=0;
  DB_ALL_KEYS.forEach(k=>{const v=localStorage.getItem(k);if(v)totalBytes+=v.length;});
  const kb=(totalBytes/1024).toFixed(1);
  const mb=(totalBytes/1024/1024).toFixed(2);

  const nbRecommandations = ACTIONS.reduce((s,a)=>s+(a.recommandations||[]).length,0);
  const nbRecoNonImpl = ACTIONS.reduce((s,a)=>s+(a.recommandations||[]).filter(r=>r.statut==='notimplemented').length,0);
  const nbRecoPartiel = ACTIONS.reduce((s,a)=>s+(a.recommandations||[]).filter(r=>r.statut==='partially').length,0);
  const nbRecoComplete = ACTIONS.reduce((s,a)=>s+(a.recommandations||[]).filter(r=>r.statut==='fully').length,0);

  const nbAuditsEnCours = AUDITS.filter(a=>a.status==='inprogress').length;
  const nbAuditsPlanifies = AUDITS.filter(a=>a.status==='planned').length;
  const nbAuditsCompletes = AUDITS.filter(a=>a.status==='completed').length;

  const nbAuditeursActifs = AUDITEURS.filter(a=>a.statut==='active').length;
  const nbSocietesActives = SOCIETES.filter(s=>s.statut==='active').length;

  const nbLogos = Object.keys(SOC_LOGOS||{}).length;

  $('#db-storage-info').html(`
    <div style="background:var(--surface3);padding:10px;border-radius:4px;margin-bottom:8px;">
      <div style="font-weight:600;color:var(--accent);margin-bottom:6px;">📊 Statistiques de la base de données</div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;font-size:11px;">
        <div><strong>${SOCIETES.length}</strong> société(s) <span style="color:var(--text-muted);">(${nbSocietesActives} active(s))</span></div>
        <div><strong>${AUDITEURS.length}</strong> auditeur(s) <span style="color:var(--text-muted);">(${nbAuditeursActifs} actif(s))</span></div>
        <div><strong>${AUDITS.length}</strong> plan(s) d'audit</div>
        <div><strong>${GANTT_MISSIONS.length}</strong> mission(s) Gantt</div>
        <div><strong>${ACTIONS.length}</strong> plan(s) d'action</div>
        <div><strong>${nbRecommandations}</strong> recommandation(s) totale(s)</div>
        <div><strong>${DAILY_TASKS.length}</strong> tâche(s) quotidienne(s)</div>
        <div><strong>${ABSENCES.length}</strong> absence(s) / congé(s)</div>
        <div><strong>${RISKS.length}</strong> risque(s) enregistré(s)</div>
      </div>
    </div>

    <div style="background:var(--surface3);padding:10px;border-radius:4px;margin-bottom:8px;">
      <div style="font-weight:600;color:var(--green);margin-bottom:6px;">📈 État des Plans d'audit</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;font-size:11px;">
        <div><span style="display:inline-block;width:8px;height:8px;background:var(--accent);border-radius:50%;margin-right:4px;"></span><strong>${nbAuditsEnCours}</strong> en cours</div>
        <div><span style="display:inline-block;width:8px;height:8px;background:var(--yellow);border-radius:50%;margin-right:4px;"></span><strong>${nbAuditsPlanifies}</strong> planifié(s)</div>
        <div><span style="display:inline-block;width:8px;height:8px;background:var(--green);border-radius:50%;margin-right:4px;"></span><strong>${nbAuditsCompletes}</strong> complété(s)</div>
      </div>
    </div>

    <div style="background:var(--surface3);padding:10px;border-radius:4px;margin-bottom:8px;">
      <div style="font-weight:600;color:var(--purple);margin-bottom:6px;">✓ État des Recommandations</div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;font-size:11px;">
        <div><span style="color:var(--red);">●</span> <strong>${nbRecoNonImpl}</strong> non impl.</div>
        <div><span style="color:var(--yellow);">●</span> <strong>${nbRecoPartiel}</strong> partiel(s)</div>
        <div><span style="color:var(--green);">●</span> <strong>${nbRecoComplete}</strong> complet(s)</div>
      </div>
    </div>

    <div style="background:var(--surface3);padding:10px;border-radius:4px;margin-bottom:8px;">
      <div style="font-weight:600;color:var(--text-muted);margin-bottom:6px;">💾 Informations de stockage</div>
      <div style="font-size:11px;line-height:1.6;">
        <div>📅 Dernière sauvegarde : <strong>${savedAt?new Date(savedAt).toLocaleString('fr-FR',{dateStyle:'short',timeStyle:'short'}):'Jamais'}</strong></div>
        <div>📦 Taille des données : <strong>${kb} Ko</strong> ${mb>1?`<span style="color:var(--text-muted);">(${mb} Mo)</span>`:''}</div>
        <div>🖼️ Logos sociétés : <strong>${nbLogos}</strong></div>
        <div style="margin-top:6px;padding-top:6px;border-top:1px solid var(--border2);color:var(--text-dim);font-size:10px;">
          💡 Les données sont sauvegardées automatiquement dans le navigateur (localStorage)
        </div>
      </div>
    </div>
  `);
}

$('#db-save-json').on('click',function(){
  const data={version:4,exported_at:new Date().toISOString(),
    societes:SOCIETES,auditeurs:AUDITEURS,responsables:RESPONSABLES,audits:AUDITS,
    actions:ACTIONS,gantt:GANTT_MISSIONS,
    risks:RISKS,daily_tasks:DAILY_TASKS,absences:ABSENCES,
    rcm_data:RCM_DATA,ordres_mission:ORDRES_MISSION,taf_items:TAF_ITEMS};
  const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download='audit-database-'+new Date().toISOString().slice(0,10)+'.json';
  document.body.appendChild(a);a.click();document.body.removeChild(a);
  URL.revokeObjectURL(url);
  toast('success','💾',`✅ JSON exporté — ${SOCIETES.length} sociétés · ${AUDITEURS.length} auditeurs · ${RESPONSABLES.length} responsables · ${AUDITS.length} audits · ${RISKS.length} risques · ${DAILY_TASKS.length} tâches · ${ABSENCES.length} absences · ${RCM_DATA.length} RCM · ${(ORDRES_MISSION||[]).length} ordres mission · ${(TAF_ITEMS||[]).length} TAF`);
});

$('#db-load-json-btn').on('click',()=>$('#db-load-json-input').click());
$('#db-load-json-input').on('change',function(){
  const file=this.files[0];if(!file)return;
  const reader=new FileReader();
  reader.onload=function(e){
    try{
      const data=JSON.parse(e.target.result);
      if(data.societes)    _reload(SOCIETES,      data.societes);
      if(data.auditeurs)   _reload(AUDITEURS,     data.auditeurs);
      if(data.responsables) _reload(RESPONSABLES,  data.responsables);
      if(data.audits)      _reload(AUDITS,        data.audits);
      if(data.actions)     _reload(ACTIONS,       data.actions);
      if(data.gantt)       _reload(GANTT_MISSIONS,data.gantt);
      if(data.risks)       _reload(RISKS,         data.risks);
      if(data.daily_tasks) _reload(DAILY_TASKS, data.daily_tasks.filter(t=>!t.ganttRef&&!t.auditRef));
      if(data.absences)    _reload(ABSENCES,      data.absences);
      if(data.rcm_data)    _reload(RCM_DATA,      data.rcm_data);
      if(data.ordres_mission) _reload(ORDRES_MISSION, data.ordres_mission);
      if(data.taf_items)   _reload(TAF_ITEMS,     data.taf_items);
      dbSave();tryRender(()=>dbSaveOM());
      renderAll();updateStorageInfo();
      const _jn=[
        data.societes?`${data.societes.length} sociétés`:'',
        data.auditeurs?`${data.auditeurs.length} auditeurs`:'',
        data.responsables?`${data.responsables.length} responsables`:'',
        data.audits?`${data.audits.length} audits`:'',
        data.risks?`${data.risks.length} risques`:'',
        data.daily_tasks?`${data.daily_tasks.length} tâches`:'',
        data.absences?`${data.absences.length} absences`:'',
        data.rcm_data?`${data.rcm_data.length} RCM`:'',
        data.ordres_mission?`${data.ordres_mission.length} ordres mission`:'',
        data.taf_items?`${data.taf_items.length} TAF`:'',
      ].filter(Boolean).join(' · ');
      toast('success','✓',`JSON chargé — ${_jn}`);
    }catch(err){toast('error','!','Fichier JSON invalide : '+err.message);}
  };
  reader.readAsText(file);this.value='';
});

// ── Export Excel — TOUTES LES DONNÉES ──
$('#db-export-excel').on('click',function(){
  if(!XLSX||!XLSX._real){toast('error','!','Bibliothèque XLSX non disponible (erreur interne)');return;}
  const wb=XLSX.utils.book_new();

  /* ── 1. Sociétés ── */
  const socRows=SOCIETES.map(s=>({Code:s.code,Nom:s.nom,Secteur:s.secteur,Pays:s.pays,Groupe:s.groupe,Adresse:s.adresse,Email:s.email,Statut:s.statut,Notes:s.notes}));
  const _wsSoc=XLSX.utils.json_to_sheet(socRows.length?socRows:[{Code:'',Nom:''}]);
  _wsSoc['!cols']=[{wch:10},{wch:28},{wch:14},{wch:18},{wch:14},{wch:30},{wch:28},{wch:10},{wch:30}];
  XLSX.utils.book_append_sheet(wb,_wsSoc,'Societes');

  /* ── 2. Auditeurs ── */
  const audRows=AUDITEURS.map(a=>({Prenom:a.prenom,Nom:a.nom,Email:a.email,Role:a.role,Anciennete:a.groupe,Specialisation:a.spec,Tel:a.tel,Date_Entree:a.date,Statut:a.statut,Certifications:a.cert}));
  const _wsAud=XLSX.utils.json_to_sheet(audRows.length?audRows:[{Prenom:'',Nom:''}]);
  _wsAud['!cols']=[{wch:14},{wch:18},{wch:30},{wch:22},{wch:12},{wch:25},{wch:16},{wch:12},{wch:10},{wch:18}];
  XLSX.utils.book_append_sheet(wb,_wsAud,'Auditeurs');

  /* ── 3. Responsables ── */
  const respRows=RESPONSABLES.map(r=>({Prenom:r.prenom||'',Nom:r.nom||'',Email:r.email||'',Fonction:r.fonction||'',Direction:r.direction||'',Tel:r.tel||'',Statut:r.statut||'active',Notes:r.notes||''}));
  const _wsResp=XLSX.utils.json_to_sheet(respRows.length?respRows:[{Prenom:'',Nom:''}]);
  _wsResp['!cols']=[{wch:14},{wch:20},{wch:30},{wch:28},{wch:18},{wch:18},{wch:12},{wch:30}];
  XLSX.utils.book_append_sheet(wb,_wsResp,'Responsables');

  /* ── 4. Audits ── */
  const _VALID_TYPES='Assurance / Conseil (Advisory) / Conformité (Compliance) / Audit Opérationnel / Audit Financier / Audit IT / Systèmes / Fraude / Investigation / Gouvernance / Gestion des Risques / Organisation / Formation / Autres';
  const auditExportRows=AUDITS.map(a=>({Ref:a.ref,Titre:a.title,Societe:a.societe,Debut:a.start,Fin:a.end,Statut:a.status,Avancement:a.progress,Risque:a.risk,Difficulte:a.difficulte||'',Type:a.type,Cycle:a.cycle||'',Cycle_Autre:a.cycle_custom||'',Objectifs:a.objectifs||'',Plan_Ref:a.planRef||'',Contexte:a.contexte||'',Obj_General:a.objGeneral||'',Obj_Specifiques:a.objSpecifiques||'',Services:a.services||'',Perimetre:a.perimetreFonc||''}));
  if(!auditExportRows.length) auditExportRows.push({Ref:'AUD-2025-001',Titre:'Intitulé de l\'audit',Societe:'Nom société',Debut:'2025-01-01',Fin:'2025-12-31',Statut:'planned / open / inprogress / overdue / completed',Avancement:0,Risque:'low / medium / high / critical',Type:_VALID_TYPES,Objectifs:'Décrire les objectifs…'});
  const _wsAud2=XLSX.utils.json_to_sheet(auditExportRows);
  _wsAud2['!cols']=[{wch:14},{wch:32},{wch:24},{wch:12},{wch:12},{wch:14},{wch:10},{wch:10},{wch:10},{wch:30},{wch:24},{wch:18},{wch:40},{wch:14},{wch:40},{wch:40},{wch:40},{wch:30},{wch:40}];
  XLSX.utils.book_append_sheet(wb,_wsAud2,'Audits');

  /* ── 5. Recommandations / Constats ── */
  const _actRows=[];
  ACTIONS.forEach(a=>{
    const recos=a.recommandations||[];
    if(!recos.length){
      _actRows.push({ID_Constat:a.id,Societe:a.societe||'',RefConstat:a.ref||'',Constat:a.findingTitle||'',Impacte:a.impacte||'',Criticite:a.criticite||'',Commentaire:a.commentaire||'',ID_Reco:'',Recommandation:'',Disposition:'',Responsable:'',Echeance:'',Statut:'',Avancement:'',JoursRetard:''});
    } else {
      recos.forEach((r,ri)=>{
        const _today=new Date();_today.setHours(0,0,0,0);
        let _ov='';
        if(r.echeance&&r.statut!=='fully'){const _du=new Date(r.echeance);if(!isNaN(_du)&&_du<_today)_ov=Math.floor((_today-_du)/(1000*60*60*24));}
        _actRows.push({ID_Constat:a.id,Societe:a.societe||'',Ref_Rapport:a.ref||'',Date_Rapport:a.date_rapport||'',Cycle:a.cycle||'',Code_Anomalie:a.code_anomalie||'',Intitule:a.intitule||'',Anomalie:a.findingTitle||'',Impacte:a.impacte||'',Criticite:a.criticite||'',ID_Reco:r.id||a.id+'-R'+(ri+1),Recommandation:r.recommandation||'',Disposition:r.disposition||'',Responsable:r.responsable||'',Fonction_Responsable:r.fonction_responsable||'',Echeance:r.echeance||'',Echeance_Revisee:r.echeance_revisee||'',Statut:r.statut||'notimplemented',Avancement:r.avancement||0,Appreciation_Preuve:r.appreciation_preuve||'',Alerte:r.alerte||'',Mise_A_Jour:r.mise_a_jour||'',Explication:r.explication||'',Commentaire_Auditeur:r.commentaire_auditeur||'',JoursRetard:_ov});
      });
    }
  });
  if(!_actRows.length) _actRows.push({ID_Constat:'C-001',Societe:'Nom société',Ref_Rapport:'MI/03/2025',Date_Rapport:'2026-02-04',Cycle:'Stock',Code_Anomalie:'STK-R6',Intitule:'Intitulé du constat',Anomalie:'Intitulé de l\'anomalie',Impacte:'Processus / entité',Criticite:'critical / high / medium / low',ID_Reco:'C-001-R1',Recommandation:'Recommandation de l\'auditeur',Disposition:'Mesure corrective',Responsable:'Prénom Nom',Fonction_Responsable:'Responsable Magasins',Echeance:'2026-02-28',Echeance_Revisee:'',Statut:'notimplemented / partially / fully',Avancement:0,Appreciation_Preuve:'',Alerte:'',Mise_A_Jour:'',Explication:'',Commentaire_Auditeur:'',JoursRetard:'(calculé auto)'});
  const _ws=XLSX.utils.json_to_sheet(_actRows);
  _ws['!cols']=[{wch:12},{wch:22},{wch:14},{wch:13},{wch:12},{wch:12},{wch:28},{wch:36},{wch:22},{wch:10},{wch:14},{wch:44},{wch:32},{wch:20},{wch:22},{wch:13},{wch:13},{wch:16},{wch:8},{wch:28},{wch:10},{wch:13},{wch:36},{wch:36},{wch:8}];
  XLSX.utils.book_append_sheet(wb,_ws,'Recommandations');

  /* ── 6. Risques ── */
  const _wsRisks=XLSX.utils.json_to_sheet(RISKS.length?RISKS.map(r=>({ID:r.id,Titre:r.titre||r.title||'',Societe:r.societe||'',Categorie:r.categorie||'',Severity:r.severity||r.niveau||'medium',Probabilite:r.probabilite,Impact:r.impact,Score:r.score,Statut:r.statut,Responsable:r.responsable||'',Echeance:r.echeance||'',COSO_Env_Controle:r.coso_env_controle||0,COSO_Eval_Risques:r.coso_eval_risques||0,COSO_Activites_Ctrl:r.coso_activites_ctrl||0,COSO_Info_Comm:r.coso_info_comm||0,COSO_Pilotage:r.coso_pilotage||0,Description:r.description||''})):[{ID:'',Titre:''}]);
  _wsRisks['!cols']=[{wch:10},{wch:35},{wch:22},{wch:14},{wch:10},{wch:10},{wch:10},{wch:7},{wch:10},{wch:20},{wch:12},{wch:12},{wch:12},{wch:13},{wch:12},{wch:12},{wch:40}];
  XLSX.utils.book_append_sheet(wb,_wsRisks,'Risques');

  /* ── 7. Missions (Gantt) ── */
  const missionRows=(GANTT_MISSIONS||[]).map(m=>({ID:m.id,Ref:m.ref||'',Titre:m.title||'',Societe:m.societe||'',Chef:m.chef||'',Debut:m.start||'',Fin:m.end||'',Avancement:m.progress||0,Statut:m.status||'planned',Couleur:m.color||'#0070f2'}));
  const _wsMissions=XLSX.utils.json_to_sheet(missionRows.length?missionRows:[{ID:'',Titre:''}]);
  _wsMissions['!cols']=[{wch:18},{wch:16},{wch:36},{wch:26},{wch:20},{wch:13},{wch:13},{wch:11},{wch:16},{wch:10}];
  XLSX.utils.book_append_sheet(wb,_wsMissions,'Missions');

  /* ── 8. Tâches des missions (Gantt) ── */
  const tacheRows=[];
  (GANTT_MISSIONS||[]).forEach(m=>{
    (m.tasks||[]).forEach(t=>{
      tacheRows.push({ID_Mission:m.id,ID_Tache:t.id||'',Titre:t.title||'',Debut:t.start||'',Fin:t.end||'',Avancement:t.progress||0,Type:t.type||'task',Responsable:(t.assignees||[]).join(', ')});
      (t.subtasks||[]).forEach(st=>{
        tacheRows.push({ID_Mission:m.id,ID_Tache:st.id||'',Titre:st.title||'',Debut:st.start||'',Fin:st.end||'',Avancement:st.progress||0,Type:'subtask',Responsable:(st.assignees||[]).join(', ')});
      });
    });
  });
  const _wsTaches=XLSX.utils.json_to_sheet(tacheRows.length?tacheRows:[{ID_Mission:'',ID_Tache:'',Titre:''}]);
  _wsTaches['!cols']=[{wch:18},{wch:10},{wch:36},{wch:13},{wch:13},{wch:11},{wch:12},{wch:20}];
  XLSX.utils.book_append_sheet(wb,_wsTaches,'Taches');

  /* ── 9. Tâches Quotidiennes ── */
  const _wsDT=XLSX.utils.json_to_sheet(DAILY_TASKS.length?DAILY_TASKS.map(t=>({ID:t.id,Titre:t.titre,Priorite:t.priorite||'medium',Statut:t.statut||'todo',Date:t.date||'',Responsable:t.responsable||'',Avancement:t.avancement||0,Notes:t.notes||''})):[{ID:'',Titre:''}]);
  _wsDT['!cols']=[{wch:10},{wch:36},{wch:10},{wch:14},{wch:13},{wch:20},{wch:10},{wch:40}];
  XLSX.utils.book_append_sheet(wb,_wsDT,'Taches_Quotidiennes');

  /* ── 10. Absences ── */
  const _wsAbs=XLSX.utils.json_to_sheet(ABSENCES.length?ABSENCES.map(a=>({ID:a.id||'',Auditeur:a.auditeur||'',Type:a.type||'conge',Debut:a.debut||'',Fin:a.fin||'',Note:a.note||''})):[{ID:'',Auditeur:''}]);
  _wsAbs['!cols']=[{wch:12},{wch:26},{wch:12},{wch:13},{wch:13},{wch:40}];
  XLSX.utils.book_append_sheet(wb,_wsAbs,'Absences');

  /* ── 11. RCM ── */
  const rcmRows=RCM_DATA.map(r=>({Filiale:r.filiale||'','Réf #':r.ref||'',Cycle:r.cycle||'',Processus:r.processus||'','Tâche':r.tache||'',"Objectif du contrôle":r.objectif||'',Risque:r.risque||'','Desc. Impact Opérationnel':r.desc_op||'','Impact Opérationnel':r.imp_op||0,'Desc. Impact Financier':r.desc_fin||'','Impact Financier':r.imp_fin||0,'Desc. Impact Réputation':r.desc_rep||'','Impact Réputation':r.imp_rep||0,Impact:r.impact||0,Likelihood:r.likelihood||0,'Inherent Risk Level':r.inherent||0,'Contrôles de mitigation':r.controle||'',"Efficacité des Contrôles":r.efficacite||0,'Residual Risk Level':r.residuel||0}));
  const _wsRcm=XLSX.utils.json_to_sheet(rcmRows.length?rcmRows:[{Filiale:'','Réf #':''}]);
  _wsRcm['!cols']=[{wch:16},{wch:8},{wch:32},{wch:28},{wch:36},{wch:32},{wch:36},{wch:28},{wch:8},{wch:28},{wch:8},{wch:28},{wch:8},{wch:8},{wch:8},{wch:12},{wch:36},{wch:8},{wch:12}];
  XLSX.utils.book_append_sheet(wb,_wsRcm,'RCM');

  /* ── 12. Ordres de Mission ── */
  const omRows=(ORDRES_MISSION||[]).map(o=>({Ref:o.ref||'',Societe:o.societe||'',Titre:o.title||o.titre||'',Type:o.type||'',Chef_Mission:o.chef||'',Auditeurs:(o.auditeurs||[]).join(', '),Debut:o.debut||o.start||'',Fin:o.fin||o.end||'',Objectif:o.objectif||'',Perimetre:o.perimetre||'',Budget:o.budget||'',Statut:o.statut||'',Date_Creation:o.dateCreation||'',Notes:o.notes||''}));
  const _wsOM=XLSX.utils.json_to_sheet(omRows.length?omRows:[{Ref:'',Titre:''}]);
  _wsOM['!cols']=[{wch:16},{wch:24},{wch:36},{wch:20},{wch:22},{wch:30},{wch:13},{wch:13},{wch:40},{wch:40},{wch:12},{wch:14},{wch:14},{wch:40}];
  XLSX.utils.book_append_sheet(wb,_wsOM,'Ordres_Mission');

  /* ── 13. Travail à Faire (TAF) ── */
  const tafRows=(TAF_ITEMS||[]).map(t=>({Ref:t.id||'',Categorie:t.categorie||'',Travail_A_Faire:t.titre||'',Programme_De_Travail:t.programme||'',Doc_A_Demander:t.docs||'',Personne_A_Contacter:t.contact||'',Timing:t.timing||'',Test_Plan:t.testplan||'',Test_Results:t.testresults||'',Priorite:t.priorite||'medium',Statut:t.statut||'todo',Auditeur:t.auditeur||'',Notes:t.notes||'',Mis_A_Jour:t.updated_at||''}));
  const _wsTaf=XLSX.utils.json_to_sheet(tafRows.length?tafRows:[{Ref:'',Travail_A_Faire:''}]);
  _wsTaf['!cols']=[{wch:14},{wch:18},{wch:40},{wch:40},{wch:30},{wch:24},{wch:14},{wch:30},{wch:12},{wch:10},{wch:12},{wch:20},{wch:36},{wch:13}];
  XLSX.utils.book_append_sheet(wb,_wsTaf,'TAF');

  /* ── Écriture du fichier ── */
  XLSX.writeFile(wb,'audit-database-'+new Date().toISOString().slice(0,10)+'.xlsx');
  toast('success','📊',
    `✅ Export complet — 13 onglets · ${SOCIETES.length} sociétés · ${AUDITEURS.length} auditeurs · ${RESPONSABLES.length} responsables · ${AUDITS.length} audits · ${ACTIONS.length} constats · ${RISKS.length} risques · ${(GANTT_MISSIONS||[]).length} missions · ${DAILY_TASKS.length} tâches · ${ABSENCES.length} absences · ${RCM_DATA.length} entrées RCM · ${(ORDRES_MISSION||[]).length} ordres de mission · ${(TAF_ITEMS||[]).length} TAF`
  );
});

$('#db-import-excel-btn').on('click',()=>$('#db-import-excel-input').click());
$('#db-import-excel-input').on('change',function(){
  const file=this.files[0];if(!file)return;
  if(!XLSX||!XLSX._real){toast('error','!','Bibliothèque XLSX non disponible (erreur interne)');return;}
  const mode=$('#db-import-mode').val();
  const reader=new FileReader();
  reader.onload=function(e){
    try{
      const wb=XLSX.read(new Uint8Array(e.target.result),{type:'array'});
      const imported={soc:0,aud:0,aud_plan:0,constats:0,actions:0,disps:0,risks:0,daily:0,absences:0,resp:0,om:0};

      if(wb.SheetNames.includes('Societes')){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Societes'])
          .filter(r=>r.Nom)
          .map(r=>({nom:r.Nom||'',code:r.Code||'',secteur:r.Secteur||'',pays:r.Pays||'',groupe:r.Groupe||'',adresse:r.Adresse||'',email:r.Email||'',statut:r.Statut||'active',notes:r.Notes||''}));
        if(mode==='replace') SOCIETES.length=0;
        mapped.forEach(s=>{
          if(!s._uid) s._uid='soc_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);
          if(mode==='merge'){const ex=SOCIETES.findIndex(x=>x.code===s.code&&s.code);ex>=0?Object.assign(SOCIETES[ex],s):SOCIETES.push(s);}
          else SOCIETES.push(s);
        });
        imported.soc=mapped.length;
      }

      if(wb.SheetNames.includes('Auditeurs')){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Auditeurs'])
          .filter(r=>r.Nom||r.Prenom)
          .map(r=>({prenom:r.Prenom||'',nom:r.Nom||'',email:r.Email||'',role:r.Role||'',groupe:r.Anciennete||r.Groupe||'',spec:r.Specialisation||'',tel:r.Tel||'',date:r.Date_Entree||r.Date||'',statut:r.Statut||'active',cert:r.Certifications||''}));
        if(mode==='replace') AUDITEURS.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=AUDITEURS.findIndex(x=>x.email===a.email&&a.email);ex>=0?AUDITEURS[ex]=a:AUDITEURS.push(a);}
          else AUDITEURS.push(a);
        });
        imported.aud=mapped.length;
      }

      if(wb.SheetNames.includes('Responsables')){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Responsables'])
          .filter(r=>r.Nom||r.Prenom)
          .map(r=>({prenom:r.Prenom||'',nom:r.Nom||'',email:r.Email||'',fonction:r.Fonction||'',direction:r.Direction||'',tel:r.Tel||'',statut:(r.Statut||'active').toLowerCase(),notes:r.Notes||''}));
        if(mode==='replace') RESPONSABLES.length=0;
        mapped.forEach(r=>{
          if(mode==='merge'){const ex=RESPONSABLES.findIndex(x=>x.email===r.email&&r.email);ex>=0?RESPONSABLES[ex]=r:RESPONSABLES.push(r);}
          else RESPONSABLES.push(r);
        });
        if(typeof renderResponsables==='function') renderResponsables();
        imported.resp=mapped.length;
      }
      if(wb.SheetNames.includes('Audits')){
        const VALID_AUDIT_TYPES=['Assurance','Conseil (Advisory)','Conformité (Compliance)','Audit Opérationnel','Audit Financier','Audit IT / Systèmes','Fraude / Investigation','Gouvernance','Gestion des Risques','Organisation','Formation','Autres'];
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Audits'])
          .filter(r=>r.Ref||r.Titre)
          .map(r=>{
            const rawType=(r.Type||'').toString().trim();
            const validType=VALID_AUDIT_TYPES.find(t=>t.toLowerCase()===rawType.toLowerCase())||rawType||'';
            return {
              ref:r.Ref||'',title:r.Titre||'Sans titre',societe:r.Societe||'',auditor:'',
              start:r.Debut?_excelDateToISO(r.Debut):'',end:r.Fin?_excelDateToISO(r.Fin):'',
              status:(r.Statut||'planned').toString().toLowerCase(),
              progress:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),
              risk:(r.Risque||'medium').toString().toLowerCase(),
              type:validType,
              cycle:r.Cycle||'',
              cycle_custom:r.Cycle_Autre||'',
              objectifs:r.Objectifs||'',
              group:r.Groupe||'Finance A'
            };
          });
        if(mode==='replace') AUDITS.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=AUDITS.findIndex(x=>x.ref===a.ref&&a.ref);ex>=0?AUDITS[ex]=a:AUDITS.push(a);}
          else AUDITS.push(a);
        });
        imported.aud_plan=mapped.length;
      }

      const _sheetName=wb.SheetNames.includes('Recommandations')?'Recommandations':
                       wb.SheetNames.includes('Plans_Action')?'Plans_Action':null;
      if(_sheetName){
        const rows=XLSX.utils.sheet_to_json(wb.Sheets[_sheetName]).filter(r=>r.ID_Constat||r.ID);

        const planMap=new Map();
        rows.forEach(r=>{
          const pid=(r.ID_Constat||r.ID||'').toString().trim();
          if(!pid) return;
          if(!planMap.has(pid)){
            planMap.set(pid,{
              id:pid,
              societe:r.Societe||'',
              ref:(r.Ref_Rapport||r.RefConstat||pid).toString().trim(),
              date_rapport:r.Date_Rapport?_excelDateToISO(r.Date_Rapport):'',
              cycle:(r.Cycle||'').toString().trim(),
              code_anomalie:(r.Code_Anomalie||'').toString().trim(),
              intitule:(r.Intitule||'').toString().trim(),
              findingTitle:(r.Anomalie||r.Constat||'').toString().trim(),
              impacte:r.Impacte||'',
              criticite:(r.Criticite||'medium').toString().toLowerCase(),
              commentaire:'',
              recommandations:[]
            });
          }
          const plan=planMap.get(pid);
          if(r.Societe) plan.societe=r.Societe;
          if(r.Anomalie||r.Constat) plan.findingTitle=(r.Anomalie||r.Constat||'').toString().trim();
          if(r.Impacte) plan.impacte=r.Impacte;
          if(r.Criticite) plan.criticite=r.Criticite.toString().toLowerCase();
          if(r.Ref_Rapport||r.RefConstat) plan.ref=(r.Ref_Rapport||r.RefConstat||'').toString().trim();
          if(r.Date_Rapport) plan.date_rapport=_excelDateToISO(r.Date_Rapport);
          if(r.Cycle) plan.cycle=r.Cycle.toString().trim();
          if(r.Code_Anomalie) plan.code_anomalie=r.Code_Anomalie.toString().trim();

          /* Ajouter recommandation si présente */
          const recoText=(r.Recommandation||'').toString().trim();
          if(recoText){
            const ri=plan.recommandations.length+1;
            const rid=(r.ID_Reco||pid+'-R'+ri).toString().trim();
            plan.recommandations.push({
              id:rid,
              recommandation:recoText,
              disposition:(r.Disposition||'').toString().trim(),
              responsable:(r.Responsable||r.Responsables||'').toString().trim(),
              fonction_responsable:(r.Fonction_Responsable||'').toString().trim(),
              echeance:r.Echeance?_excelDateToISO(r.Echeance):'',
              echeance_revisee:r.Echeance_Revisee?_excelDateToISO(r.Echeance_Revisee):'',
              statut:(r.Statut||'notimplemented').toString().toLowerCase(),
              avancement:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),
              appreciation_preuve:(r.Appreciation_Preuve||'').toString().trim(),
              alerte:(r.Alerte||'').toString().trim(),
              mise_a_jour:r.Mise_A_Jour?_excelDateToISO(r.Mise_A_Jour):'',
              explication:(r.Explication||'').toString().trim(),
              commentaire_auditeur:(r.Commentaire_Auditeur||'').toString().trim()
            });
            imported.disps++;
          }
        });

        const mapped=[...planMap.values()];
        imported.actions=mapped.length;
        if(mode==='replace') ACTIONS.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=ACTIONS.findIndex(x=>x.id===a.id&&a.id);ex>=0?ACTIONS[ex]=a:ACTIONS.push(a);}
          else ACTIONS.push(a);
        });
      }

      if(wb.SheetNames.includes('Risques')){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Risques'])
          .filter(r=>r.ID||r.Titre)
          .map(r=>({
            id:r.ID||'', titre:r.Titre||r.title||'', societe:r.Societe||'',
            categorie:r.Categorie||'', severity:r.Severity||r.Niveau||'medium',
            probabilite:r.Probabilite||'medium', impact:r.Impact||'medium', score:r.Score||0,
            statut:r.Statut||'open', responsable:r.Responsable||'', echeance:r.Echeance?_excelDateToISO(r.Echeance):r.Echeance_Initiale?_excelDateToISO(r.Echeance_Initiale):'',
            coso_env_controle:isNaN(+r.COSO_Env_Controle)?0:+r.COSO_Env_Controle,
            coso_eval_risques:isNaN(+r.COSO_Eval_Risques)?0:+r.COSO_Eval_Risques,
            coso_activites_ctrl:isNaN(+r.COSO_Activites_Ctrl)?0:+r.COSO_Activites_Ctrl,
            coso_info_comm:isNaN(+r.COSO_Info_Comm)?0:+r.COSO_Info_Comm,
            coso_pilotage:isNaN(+r.COSO_Pilotage)?0:+r.COSO_Pilotage,
            description:r.Description||''
          }));
        if(mode==='replace') RISKS.length=0;
        mapped.forEach(r=>{
          if(mode==='merge'){const ex=RISKS.findIndex(x=>x.id===r.id&&r.id);ex>=0?RISKS[ex]=r:RISKS.push(r);}
          else RISKS.push(r);
        });
        imported.risks=mapped.length;
      }

      /* ── Import onglet RCM ── */
      if(wb.SheetNames.includes('RCM')){
        const rcmRows=XLSX.utils.sheet_to_json(wb.Sheets['RCM'])
          .filter(r=>(r['Filiale']||r['Tâche'])&&r['Filiale']!=='[Légende]');
        const rcmMapped=rcmRows.map((r,idx)=>{
          const impOp = isNaN(+r['Impact Opérationnel'])?0:+r['Impact Opérationnel'];
          const impFin= isNaN(+r['Impact Financier'])?0:+r['Impact Financier'];
          const impRep= isNaN(+r['Impact Réputation'])?0:+r['Impact Réputation'];
          const vals=[impOp,impFin,impRep].filter(v=>v>0);
          const avgImpact = vals.length?Math.round(vals.reduce((a,b)=>a+b,0)/vals.length):isNaN(+r['Impact'])?0:+r['Impact'];
          const likelihood= isNaN(+r['Likelihood'])?0:+r['Likelihood'];
          const inherent  = (+r['Inherent Risk Level'])||avgImpact*likelihood||0;
          const efficacite= isNaN(+r['Efficacité des Contrôles'])?0:+r['Efficacité des Contrôles'];
          const residuel  = (+r['Residual Risk Level'])||
                            (efficacite>0?Math.round(inherent/efficacite):inherent)||0;
          return {
            id: r['Réf #']?r['Filiale']+'-'+r['Réf #']:('RCM-'+Date.now()+'-'+idx),
            filiale:  (r['Filiale']||'').toString().trim(),
            ref:      (r['Réf #']||'').toString().trim(),
            cycle:    (r['Cycle']||'').toString().trim(),
            processus:(r['Processus']||'').toString().trim(),
            tache:    (r['Tâche']||'').toString().trim(),
            objectif: (r['Objectif du contrôle']||'').toString().trim(),
            risque:   (r['Risque']||'').toString().trim(),
            desc_op:  (r['Desc. Impact Opérationnel']||'').toString().trim(),
            desc_fin: (r['Desc. Impact Financier']||'').toString().trim(),
            desc_rep: (r['Desc. Impact Réputation']||'').toString().trim(),
            imp_op: impOp, imp_fin: impFin, imp_rep: impRep,
            impact: avgImpact, likelihood, inherent,
            controle: (r['Contrôles de mitigation']||'').toString().trim(),
            efficacite, residuel
          };
        });
        if(mode==='replace') RCM_DATA.length=0;
        rcmMapped.forEach(r=>{
          if(mode==='merge'){const ex=RCM_DATA.findIndex(x=>x.id===r.id&&r.id);ex>=0?RCM_DATA[ex]=r:RCM_DATA.push(r);}
          else RCM_DATA.push(r);
        });
        if(typeof renderRCM==='function') renderRCM();
        imported.risks=(imported.risks||0); /* count already tracked */
      }

      if(wb.SheetNames.includes('Taches_Quotidiennes')){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Taches_Quotidiennes'])
          .filter(r=>r.Titre)
          .map(r=>({
            id:r.ID||('DT-'+Math.floor(Math.random()*99999)),
            titre:r.Titre||'', priorite:(r.Priorite||'medium').toLowerCase(),
            statut:(r.Statut||'todo').toLowerCase(),
            date:r.Date?_excelDateToISO(r.Date):'',
            responsable:r.Responsable||'',
            avancement:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),
            notes:r.Notes||''
          }));
        if(mode==='replace') DAILY_TASKS.length=0;
        mapped.forEach(t=>{
          if(mode==='merge'){const ex=DAILY_TASKS.findIndex(x=>x.id===t.id&&t.id);ex>=0?DAILY_TASKS[ex]=t:DAILY_TASKS.push(t);}
          else DAILY_TASKS.push(t);
        });
        imported.daily=mapped.length;
      }

      /* ── Import onglet Missions (Planning Gantt) ── */
      if(wb.SheetNames.includes('Missions')){
        const mRows=XLSX.utils.sheet_to_json(wb.Sheets['Missions'])
          .filter(r=>r.ID&&r.Titre&&r['[Légende]']===undefined&&r.ID!=='[Légende]');
        let mImported=0;
        mRows.forEach(r=>{
          const mid=(r.ID||'').toString().trim();
          if(!mid) return;
          const nm={
            id:mid,
            ref:(r.Ref||'').toString().trim(),
            title:(r.Titre||'').toString().trim(),
            societe:(r.Societe||'').toString().trim(),
            chef:(r.Chef||'').toString().trim(),
            start:r.Debut?_excelDateToISO(r.Debut):'',
            end:r.Fin?_excelDateToISO(r.Fin):'',
            progress:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),
            status:(r.Statut||'planned').toString().toLowerCase(),
            color:(r.Couleur||'#0070f2').toString().trim(),
            tasks:[]
          };
          if(mode==='merge'){
            const ex=GANTT_MISSIONS.findIndex(m=>m.id===mid||(nm.ref&&m.ref===nm.ref));
            if(ex>=0){ Object.assign(GANTT_MISSIONS[ex],nm); }
            else { GANTT_MISSIONS.push(nm); }
          } else {
            const ex=GANTT_MISSIONS.findIndex(m=>m.id===mid);
            if(ex<0) GANTT_MISSIONS.push(nm);
          }
          mImported++;
        });
        imported.aud_plan = (imported.aud_plan||0) + mImported;
      }

      /* ── Import onglet Taches (tâches des missions Gantt) ── */
      if(wb.SheetNames.includes('Taches')){
        const tRows=XLSX.utils.sheet_to_json(wb.Sheets['Taches'])
          .filter(r=>r.ID_Mission&&r.Titre&&r.ID_Mission!=='[Légende]');
        tRows.forEach(r=>{
          const mid=(r.ID_Mission||'').toString().trim();
          const tid=(r.ID_Tache||('T-'+Math.floor(Math.random()*99999))).toString().trim();
          const mission=GANTT_MISSIONS.find(m=>m.id===mid);
          if(!mission) return;
          const nt={
            id:tid,
            title:(r.Titre||'').toString().trim(),
            start:r.Debut?_excelDateToISO(r.Debut):'',
            end:r.Fin?_excelDateToISO(r.Fin):'',
            progress:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),
            type:(r.Type||'task').toString().toLowerCase(),
            assignees:r.Responsable?[(r.Responsable||'').toString().trim()]:[],
            subtasks:[]
          };
          const exT=mission.tasks.findIndex(t=>t.id===tid);
          if(exT>=0) Object.assign(mission.tasks[exT],nt);
          else mission.tasks.push(nt);
        });
      }

      if(wb.SheetNames.includes('Absences')){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets['Absences'])
          .filter(r=>r.Auditeur&&r.Debut&&r.Fin)
          .map(r=>({
            id:r.ID||('ABS-'+Math.floor(Math.random()*999999)),
            auditeur:(r.Auditeur||'').toString().trim(),
            type:(r.Type||'conge').toString().toLowerCase().trim(),
            debut:r.Debut?_excelDateToISO(r.Debut):'',
            fin:r.Fin?_excelDateToISO(r.Fin):'',
            note:(r.Note||'').toString().trim()
          }));
        if(mode==='replace') ABSENCES.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=ABSENCES.findIndex(x=>x.id===a.id&&a.id);ex>=0?ABSENCES[ex]=a:ABSENCES.push(a);}
          else ABSENCES.push(a);
        });
        imported.absences=mapped.length;
      }

      if(wb.SheetNames.includes('Ordres_Mission')){
        const omRows=XLSX.utils.sheet_to_json(wb.Sheets['Ordres_Mission'])
          .filter(r=>r.Ref||r.Titre);
        const omMapped=omRows.map(r=>({
          ref:(r.Ref||'').toString().trim(),
          societe:(r.Societe||'').toString().trim(),
          titre:(r.Titre||'').toString().trim(),
          type:(r.Type||'').toString().trim(),
          chef:(r.Chef_Mission||r.Chef||'').toString().trim(),
          auditeurs:r.Auditeurs?r.Auditeurs.toString().split(',').map(s=>s.trim()).filter(Boolean):[],
          debut:r.Debut?_excelDateToISO(r.Debut):'',
          fin:r.Fin?_excelDateToISO(r.Fin):'',
          objectif:(r.Objectif||'').toString().trim(),
          perimetre:(r.Perimetre||'').toString().trim(),
          budget:(r.Budget||'').toString().trim(),
          statut:(r.Statut||'').toString().toLowerCase().trim(),
          dateCreation:r.Date_Creation?_excelDateToISO(r.Date_Creation):'',
          notes:(r.Notes||'').toString().trim()
        }));
        if(mode==='replace') ORDRES_MISSION.length=0;
        omMapped.forEach(o=>{
          if(mode==='merge'){const ex=ORDRES_MISSION.findIndex(x=>x.ref===o.ref&&o.ref);ex>=0?Object.assign(ORDRES_MISSION[ex],o):ORDRES_MISSION.push(o);}
          else ORDRES_MISSION.push(o);
        });
        tryRender(()=>dbSaveOM());
        imported.om=omMapped.length;
      }

      if(wb.SheetNames.includes('TAF')){
        const tafRows=XLSX.utils.sheet_to_json(wb.Sheets['TAF'])
          .filter(r=>(r.Ref||r.Travail_A_Faire)&&r.Ref!=='[Légende]');
        const tafMapped=tafRows.map(r=>({
          id:(r.Ref||'').toString().trim(),
          categorie:(r.Categorie||'').toString().trim(),
          titre:(r.Travail_A_Faire||'').toString().trim(),
          programme:(r.Programme_De_Travail||'').toString().trim(),
          docs:(r.Doc_A_Demander||'').toString().trim(),
          contact:(r.Personne_A_Contacter||'').toString().trim(),
          timing:(r.Timing||'').toString().trim(),
          testplan:(r.Test_Plan||'').toString().trim(),
          testresults:(r.Test_Results||'').toString().trim(),
          priorite:(r.Priorite||'medium').toString().toLowerCase().trim(),
          statut:(r.Statut||'todo').toString().toLowerCase().trim(),
          auditeur:(r.Auditeur||'').toString().trim(),
          notes:(r.Notes||'').toString().trim(),
          updated_at:(r.Mis_A_Jour||'').toString().trim()
        }));
        if(mode==='replace') TAF_ITEMS.length=0;
        tafMapped.forEach(t=>{
          if(mode==='merge'){const ex=TAF_ITEMS.findIndex(x=>x.id===t.id&&t.id);ex>=0?Object.assign(TAF_ITEMS[ex],t):TAF_ITEMS.push(t);}
          else TAF_ITEMS.push(t);
        });
        tryRender(()=>tafSave());
        tryRender(()=>renderTAF());
        imported.taf=tafMapped.length;
      }

      tryRender(()=>syncMissionsFromAudits())
      dbSave();renderAll();updateStorageInfo();
      if(typeof window._reloadCurrentUser==='function') window._reloadCurrentUser();
      toast('success','📊',
        `✅ Import OK — ${imported.soc||0} sociétés · ${imported.aud||0} auditeurs · ${imported.resp||0} responsables · ${imported.aud_plan||0} audits/missions · ${imported.actions||0} constats (${imported.disps||0} reco.) · ${imported.risks||0} risques · ${imported.daily||0} tâches · ${imported.absences||0} absences · ${imported.om||0} ordres mission · ${imported.taf||0} TAF`
      );
    }catch(err){toast('error','!','Erreur import Excel : '+err.message);}
  };
  reader.readAsArrayBuffer(file);this.value='';
});

/* ── Import par module — boutons ⬆️ Importer à côté de chaque modèle ── */
let _tplImpTargetSheet = null;

$(document).on('click','.tpl-imp-btn', function(){
  if(!XLSX||!XLSX._real){toast('error','!','Bibliothèque XLSX non disponible');return;}
  _tplImpTargetSheet = $(this).data('sheet');
  $('#tpl-imp-file-input').val('').click();
});

$('#tpl-imp-file-input').on('change', function(){
  const file = this.files[0]; if(!file) return;
  if(!XLSX||!XLSX._real){toast('error','!','Bibliothèque XLSX non disponible');return;}
  const sheet = _tplImpTargetSheet; if(!sheet) return;
  const mode  = $('#db-import-mode').val() || 'merge';
  const reader = new FileReader();
  reader.onload = function(e){
    try{
      const wb = XLSX.read(new Uint8Array(e.target.result),{type:'array'});
      /* Cherche l'onglet cible — insensible à la casse + alias connus */
      const _aliases = {
        'RCM':               ['rcm','risk control matrix','risk_control_matrix','riskcontrolmatrix'],
        'Recommandations':   ['recommandations','plans_action','plans action','reco'],
        'Taches_Quotidiennes':['taches_quotidiennes','taches quotidiennes','daily','taches'],
        'Missions':          ['missions','planning','gantt'],
        'Absences':          ['absences','conges','congés'],
        'Societes':          ['societes','sociétés','filiales'],
        'Auditeurs':         ['auditeurs'],
        'Responsables':      ['responsables','resp'],
        'Audits':            ['audits','plans audit','plans_audit'],
        'Risques':           ['risques','risks'],
        'TAF':               ['taf','travail_a_faire','travail à faire'],
      };
      const _aliases4sheet = (_aliases[sheet]||[]).concat([sheet.toLowerCase()]);
      const sheetName = wb.SheetNames.find(n=>_aliases4sheet.includes(n.toLowerCase().trim())) || null;
      if(!sheetName){
        toast('error','!',`Onglet "${sheet}" introuvable. Onglets détectés : ${wb.SheetNames.join(', ') || '(aucun)'}`);
        return;
      }
      let count = 0;

      if(sheet==='Societes'){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.Nom)
          .map(r=>({nom:r.Nom||'',code:r.Code||'',secteur:r.Secteur||'',pays:r.Pays||'',groupe:r.Groupe||'',adresse:r.Adresse||'',email:r.Email||'',statut:r.Statut||'active',notes:r.Notes||''}));
        if(mode==='replace') SOCIETES.length=0;
        mapped.forEach(s=>{
          if(!s._uid) s._uid='soc_'+Date.now()+'_'+Math.random().toString(36).slice(2,7);
          if(mode==='merge'){const ex=SOCIETES.findIndex(x=>x.code===s.code&&s.code);ex>=0?Object.assign(SOCIETES[ex],s):SOCIETES.push(s);}
          else SOCIETES.push(s);
        });
        count=mapped.length; toast('success','🏢',`${count} société(s) importée(s)`);

      } else if(sheet==='Auditeurs'){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.Nom||r.Prenom)
          .map(r=>({prenom:r.Prenom||'',nom:r.Nom||'',email:r.Email||'',role:r.Role||'',groupe:r.Anciennete||r.Groupe||'',spec:r.Specialisation||'',tel:r.Tel||'',date:r.Date_Entree||r.Date||'',statut:r.Statut||'active',cert:r.Certifications||''}));
        if(mode==='replace') AUDITEURS.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=AUDITEURS.findIndex(x=>x.email===a.email&&a.email);ex>=0?AUDITEURS[ex]=a:AUDITEURS.push(a);}
          else AUDITEURS.push(a);
        });
        count=mapped.length; toast('success','👥',`${count} auditeur(s) importé(s)`);

      } else if(sheet==='Responsables'){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.Nom||r.Prenom)
          .map(r=>({prenom:r.Prenom||'',nom:r.Nom||'',email:r.Email||'',fonction:r.Fonction||'',direction:r.Direction||'',tel:r.Tel||'',statut:(r.Statut||'active').toLowerCase(),notes:r.Notes||''}));
        if(mode==='replace') RESPONSABLES.length=0;
        mapped.forEach(r=>{
          if(mode==='merge'){const ex=RESPONSABLES.findIndex(x=>x.email===r.email&&r.email);ex>=0?RESPONSABLES[ex]=r:RESPONSABLES.push(r);}
          else RESPONSABLES.push(r);
        });
        renderResponsables();
        count=mapped.length; toast('success','🧑‍💼',`${count} responsable(s) importé(s)`);

      } else if(sheet==='Audits'){
        const VALID_AUDIT_TYPES=['Assurance','Conseil (Advisory)','Conformité (Compliance)','Audit Opérationnel','Audit Financier','Audit IT / Systèmes','Fraude / Investigation','Gouvernance','Gestion des Risques','Organisation','Formation','Autres'];
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.Ref||r.Titre)
          .map(r=>{
            const rawType=(r.Type||'').toString().trim();
            const validType=VALID_AUDIT_TYPES.find(t=>t.toLowerCase()===rawType.toLowerCase())||rawType||'';
            return {ref:r.Ref||'',title:r.Titre||'Sans titre',societe:r.Societe||'',auditor:'',
              start:r.Debut?_excelDateToISO(r.Debut):'',end:r.Fin?_excelDateToISO(r.Fin):'',
              status:(r.Statut||'planned').toString().toLowerCase(),
              progress:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),
              risk:(r.Risque||'medium').toString().toLowerCase(),
              type:validType,cycle:r.Cycle||'',cycle_custom:r.Cycle_Autre||'',
              objectifs:r.Objectifs||'',group:r.Groupe||'Finance A'};
          });
        if(mode==='replace') AUDITS.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=AUDITS.findIndex(x=>x.ref===a.ref&&a.ref);ex>=0?AUDITS[ex]=a:AUDITS.push(a);}
          else AUDITS.push(a);
        });
        count=mapped.length; toast('success','◈',`${count} plan(s) d'audit importé(s)`);

      } else if(sheet==='Recommandations'){
        const rows=XLSX.utils.sheet_to_json(wb.Sheets[sheetName]).filter(r=>r.ID_Constat||r.ID);
        const planMap=new Map();
        rows.forEach(r=>{
          const pid=(r.ID_Constat||r.ID||'').toString().trim(); if(!pid) return;
          if(!planMap.has(pid)) planMap.set(pid,{id:pid,societe:r.Societe||'',ref:(r.Ref_Rapport||r.RefConstat||pid).toString().trim(),date_rapport:r.Date_Rapport?_excelDateToISO(r.Date_Rapport):'',cycle:(r.Cycle||'').toString().trim(),code_anomalie:(r.Code_Anomalie||'').toString().trim(),findingTitle:(r.Anomalie||r.Constat||'').toString().trim(),impacte:r.Impacte||'',criticite:(r.Criticite||'medium').toString().toLowerCase(),commentaire:'',recommandations:[]});
          const plan=planMap.get(pid);
          if(r.Societe) plan.societe=r.Societe;
          if(r.Anomalie||r.Constat) plan.findingTitle=(r.Anomalie||r.Constat||'').toString().trim();
          if(r.Impacte) plan.impacte=r.Impacte;
          if(r.Criticite) plan.criticite=r.Criticite.toString().toLowerCase();
          if(r.Ref_Rapport||r.RefConstat) plan.ref=(r.Ref_Rapport||r.RefConstat||'').toString().trim();
          if(r.Date_Rapport) plan.date_rapport=_excelDateToISO(r.Date_Rapport);
          if(r.Cycle) plan.cycle=r.Cycle.toString().trim();
          if(r.Code_Anomalie) plan.code_anomalie=r.Code_Anomalie.toString().trim();
          const recoText=(r.Recommandation||'').toString().trim();
          if(recoText){const ri=plan.recommandations.length+1;const rid=(r.ID_Reco||pid+'-R'+ri).toString().trim();plan.recommandations.push({id:rid,recommandation:recoText,disposition:(r.Disposition||'').toString().trim(),responsable:(r.Responsable||r.Responsables||'').toString().trim(),echeance:r.Echeance?_excelDateToISO(r.Echeance):r.Echeance_Initiale?_excelDateToISO(r.Echeance_Initiale):'',statut:(r.Statut||'notimplemented').toString().toLowerCase(),avancement:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement))});}
        });
        const mapped=[...planMap.values()];
        if(mode==='replace') ACTIONS.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=ACTIONS.findIndex(x=>x.id===a.id&&a.id);ex>=0?ACTIONS[ex]=a:ACTIONS.push(a);}
          else ACTIONS.push(a);
        });
        count=mapped.length; toast('success','◎',`${count} constat(s) / recommandation(s) importé(s)`);

      } else if(sheet==='Risques'){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.ID||r.Titre)
          .map(r=>({id:r.ID||'',titre:r.Titre||r.title||'',societe:r.Societe||'',categorie:r.Categorie||'',severity:r.Severity||r.Niveau||'medium',probabilite:r.Probabilite||'medium',impact:r.Impact||'medium',score:r.Score||0,statut:r.Statut||'open',responsable:r.Responsable||'',echeance:r.Echeance?_excelDateToISO(r.Echeance):r.Echeance_Initiale?_excelDateToISO(r.Echeance_Initiale):'',coso_env_controle:isNaN(+r.COSO_Env_Controle)?0:+r.COSO_Env_Controle,coso_eval_risques:isNaN(+r.COSO_Eval_Risques)?0:+r.COSO_Eval_Risques,coso_activites_ctrl:isNaN(+r.COSO_Activites_Ctrl)?0:+r.COSO_Activites_Ctrl,coso_info_comm:isNaN(+r.COSO_Info_Comm)?0:+r.COSO_Info_Comm,coso_pilotage:isNaN(+r.COSO_Pilotage)?0:+r.COSO_Pilotage,description:r.Description||''}));
        if(mode==='replace') RISKS.length=0;
        mapped.forEach(r=>{
          if(mode==='merge'){const ex=RISKS.findIndex(x=>x.id===r.id&&r.id);ex>=0?RISKS[ex]=r:RISKS.push(r);}
          else RISKS.push(r);
        });
        count=mapped.length; toast('success','◇',`${count} risque(s) importé(s)`);

      } else if(sheet==='Missions'){
        const mRows=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.ID&&r.Titre&&r.ID!=='[Légende]');
        mRows.forEach(r=>{
          const mid=(r.ID||'').toString().trim(); if(!mid) return;
          const nm={id:mid,ref:(r.Ref||'').toString().trim(),title:(r.Titre||'').toString().trim(),societe:(r.Societe||'').toString().trim(),chef:(r.Chef||'').toString().trim(),start:r.Debut?_excelDateToISO(r.Debut):'',end:r.Fin?_excelDateToISO(r.Fin):'',progress:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),status:(r.Statut||'planned').toString().toLowerCase(),color:(r.Couleur||'#0070f2').toString().trim(),tasks:[]};
          if(mode==='merge'){const ex=GANTT_MISSIONS.findIndex(m=>m.id===mid||(nm.ref&&m.ref===nm.ref));if(ex>=0){Object.assign(GANTT_MISSIONS[ex],nm);}else{GANTT_MISSIONS.push(nm);}}
          else{const ex=GANTT_MISSIONS.findIndex(m=>m.id===mid);if(ex<0) GANTT_MISSIONS.push(nm);}
          count++;
        });
        toast('success','▤',`${count} mission(s) importée(s)`);

      } else if(sheet==='Taches_Quotidiennes'){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.Titre)
          .map(r=>({id:r.ID||('DT-'+Math.floor(Math.random()*99999)),titre:r.Titre||'',priorite:(r.Priorite||'medium').toLowerCase(),statut:(r.Statut||'todo').toLowerCase(),date:r.Date?_excelDateToISO(r.Date):'',responsable:r.Responsable||'',avancement:isNaN(+r.Avancement)?0:Math.min(100,Math.max(0,+r.Avancement)),notes:r.Notes||''}));
        if(mode==='replace') DAILY_TASKS.length=0;
        mapped.forEach(t=>{
          if(mode==='merge'){const ex=DAILY_TASKS.findIndex(x=>x.id===t.id&&t.id);ex>=0?DAILY_TASKS[ex]=t:DAILY_TASKS.push(t);}
          else DAILY_TASKS.push(t);
        });
        count=mapped.length; toast('success','📅',`${count} tâche(s) quotidienne(s) importée(s)`);

      } else if(sheet==='Absences'){
        const mapped=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>r.Auditeur&&r.Debut&&r.Fin)
          .map(r=>({id:r.ID||('ABS-'+Math.floor(Math.random()*999999)),auditeur:(r.Auditeur||'').toString().trim(),type:(r.Type||'conge').toString().toLowerCase().trim(),debut:r.Debut?_excelDateToISO(r.Debut):'',fin:r.Fin?_excelDateToISO(r.Fin):'',note:(r.Note||'').toString().trim()}));
        if(mode==='replace') ABSENCES.length=0;
        mapped.forEach(a=>{
          if(mode==='merge'){const ex=ABSENCES.findIndex(x=>x.id===a.id&&a.id);ex>=0?ABSENCES[ex]=a:ABSENCES.push(a);}
          else ABSENCES.push(a);
        });
        count=mapped.length; toast('success','🏖️',`${count} absence(s) importée(s)`);

      } else if(sheet==='RCM'){
        const rcmRows=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>(r['Filiale']||r['Tâche'])&&r['Filiale']!=='[Légende]');
        const rcmMapped=rcmRows.map((r,idx)=>{
          const impOp=isNaN(+r['Impact Opérationnel'])?0:+r['Impact Opérationnel'];
          const impFin=isNaN(+r['Impact Financier'])?0:+r['Impact Financier'];
          const impRep=isNaN(+r['Impact Réputation'])?0:+r['Impact Réputation'];
          const vals=[impOp,impFin,impRep].filter(v=>v>0);
          const avgImpact=vals.length?Math.round(vals.reduce((a,b)=>a+b,0)/vals.length):isNaN(+r['Impact'])?0:+r['Impact'];
          const likelihood=isNaN(+r['Likelihood'])?0:+r['Likelihood'];
          const inherent=(+r['Inherent Risk Level'])||avgImpact*likelihood||0;
          const efficacite=isNaN(+r['Efficacité des Contrôles'])?0:+r['Efficacité des Contrôles'];
          const residuel=(+r['Residual Risk Level'])||(efficacite>0?Math.round(inherent/efficacite):inherent)||0;
          return {id:r['Réf #']?r['Filiale']+'-'+r['Réf #']:('RCM-'+Date.now()+'-'+idx),filiale:(r['Filiale']||'').toString().trim(),ref:(r['Réf #']||'').toString().trim(),cycle:(r['Cycle']||'').toString().trim(),processus:(r['Processus']||'').toString().trim(),tache:(r['Tâche']||'').toString().trim(),objectif:(r['Objectif du contrôle']||'').toString().trim(),risque:(r['Risque']||'').toString().trim(),desc_op:(r['Desc. Impact Opérationnel']||'').toString().trim(),desc_fin:(r['Desc. Impact Financier']||'').toString().trim(),desc_rep:(r['Desc. Impact Réputation']||'').toString().trim(),imp_op:impOp,imp_fin:impFin,imp_rep:impRep,impact:avgImpact,likelihood,inherent,controle:(r['Contrôles de mitigation']||'').toString().trim(),efficacite,residuel};
        });
        if(mode==='replace') RCM_DATA.length=0;
        rcmMapped.forEach(r=>{
          if(mode==='merge'){const ex=RCM_DATA.findIndex(x=>x.id===r.id&&r.id);ex>=0?RCM_DATA[ex]=r:RCM_DATA.push(r);}
          else RCM_DATA.push(r);
        });
        if(typeof renderRCM==='function') renderRCM();
        count=rcmMapped.length; toast('success','🛡️',`${count} entrée(s) RCM importée(s)`);
      } else if(sheet==='TAF'){
        const tafRows=XLSX.utils.sheet_to_json(wb.Sheets[sheetName])
          .filter(r=>(r.Ref||r.Travail_A_Faire)&&r.Ref!=='[Légende]');
        const tafMapped=tafRows.map(r=>({
          id:(r.Ref||'').toString().trim(),
          categorie:(r.Categorie||'').toString().trim(),
          titre:(r.Travail_A_Faire||'').toString().trim(),
          programme:(r.Programme_De_Travail||'').toString().trim(),
          docs:(r.Doc_A_Demander||'').toString().trim(),
          contact:(r.Personne_A_Contacter||'').toString().trim(),
          timing:(r.Timing||'').toString().trim(),
          testplan:(r.Test_Plan||'').toString().trim(),
          testresults:(r.Test_Results||'').toString().trim(),
          priorite:(r.Priorite||'medium').toString().toLowerCase().trim(),
          statut:(r.Statut||'todo').toString().toLowerCase().trim(),
          auditeur:(r.Auditeur||'').toString().trim(),
          notes:(r.Notes||'').toString().trim(),
          updated_at:(r.Mis_A_Jour||'').toString().trim()
        }));
        if(mode==='replace') TAF_ITEMS.length=0;
        tafMapped.forEach(t=>{
          if(mode==='merge'){const ex=TAF_ITEMS.findIndex(x=>x.id===t.id&&t.id);ex>=0?Object.assign(TAF_ITEMS[ex],t):TAF_ITEMS.push(t);}
          else TAF_ITEMS.push(t);
        });
        tafSave();
        tryRender(()=>renderTAF());
        count=tafMapped.length; toast('success','📝',`${count} TAF importé(s)`);
      }

      tryRender(()=>syncMissionsFromAudits());
      dbSave(); renderAll(); updateStorageInfo();
    }catch(err){ toast('error','!','Erreur import : '+err.message); }
  };
  reader.readAsArrayBuffer(file); this.value='';
});

/* ── Remise à zéro par module ── */
$(document).on('click','.tpl-reset-btn', function(){
  const sheet = $(this).data('sheet');
  const labels = {
    'Societes':           'les Sociétés & Filiales',
    'Auditeurs':          "l'équipe Auditeurs",
    'Responsables':       'les Responsables Recommandations',
    'Audits':             "les Plans d'audit",
    'Recommandations':    'les Recommandations',
    'Risques':            'les Risques',
    'Missions':           'le Planning Missions',
    'Taches_Quotidiennes':'les Tâches Quotidiennes',
    'Absences':           'les Absences & Congés',
    'RCM':                'la Risk Control Matrix (RCM)',
    'TAF':                'le Travail à Faire (TAF)',
  };
  const label = labels[sheet] || sheet;
  if(!confirm(`⚠️ Remise à zéro — ${label}\n\nToutes les données de ce module seront supprimées définitivement.\n\nContinuer ?`)) return;

  if(sheet==='Societes'){
    SOCIETES.splice(0, SOCIETES.length);
    renderSocietes(); renderSocietesView();
    toast('success','🏢','Sociétés remises à zéro.');
  } else if(sheet==='Auditeurs'){
    AUDITEURS.splice(0, AUDITEURS.length);
    renderAuditeurs(); renderAuditeurCards();
    toast('success','👥','Auditeurs remis à zéro.');
  } else if(sheet==='Responsables'){
    RESPONSABLES.splice(0, RESPONSABLES.length);
    renderResponsables();
    toast('success','👤','Responsables remis à zéro.');
  } else if(sheet==='Audits'){
    AUDITS.splice(0, AUDITS.length);
    renderAudits();
    toast('success','◈',"Plans d'audit remis à zéro.");
  } else if(sheet==='Recommandations'){
    ACTIONS.splice(0, ACTIONS.length);
    renderActions();
    toast('success','◎','Recommandations remises à zéro.');
  } else if(sheet==='Risques'){
    RISKS.splice(0, RISKS.length);
    renderRisks();
    toast('success','◇','Risques remis à zéro.');
  } else if(sheet==='Missions'){
    GANTT_MISSIONS.splice(0, GANTT_MISSIONS.length);
    tryRender(()=>renderGantt());
    toast('success','▤','Planning Missions remis à zéro.');
  } else if(sheet==='Taches_Quotidiennes'){
    DAILY_TASKS.splice(0, DAILY_TASKS.length);
    tryRender(()=>renderDailyTasks());
    toast('success','📅','Tâches Quotidiennes remises à zéro.');
  } else if(sheet==='Absences'){
    ABSENCES.splice(0, ABSENCES.length);
    tryRender(()=>renderAbsenceList());
    tryRender(()=>renderDispoTable());
    toast('success','🏖️','Absences remises à zéro.');
  } else if(sheet==='RCM'){
    RCM_DATA.splice(0, RCM_DATA.length);
    renderRCM();
    toast('success','🛡️','RCM remis à zéro.');
  } else if(sheet==='TAF'){
    TAF_ITEMS.splice(0, TAF_ITEMS.length);
    tryRender(()=>renderTAF());
    toast('success','📝','Travail à Faire (TAF) remis à zéro.');
  }

  dbSave();
  renderWidgets();
  updateStorageInfo();
});

