function _excelDateToISO(v){
  if(!v) return '';
  if(typeof v==='number'){

    const d=new Date(Math.round((v-25569)*86400*1000));
    if(!isNaN(d)) return d.toISOString().slice(0,10);
  }
  const s=v.toString().trim();

  const m1=s.match(/^(\d{2})[\/\-](\d{2})[\/\-](\d{4})$/);
  if(m1) return `${m1[3]}-${m1[2]}-${m1[1]}`;
  const m2=s.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if(m2) return s;
  return s;
}

$(document).on('click','.db-reset-btn',function(){
  const target=$(this).data('target');
  if(target==='societes'){
    _reload(SOCIETES,SEED_SOCIETES());
    renderSocietes();renderSocietesView();
    dbSave();updateStorageInfo();
    toast('success','✓',`Sociétés réinitialisées (${SOCIETES.length} entrées)`);
  } else if(target==='auditeurs'){
    _reload(AUDITEURS,SEED_AUDITEURS());
    renderAuditeurs();renderAuditeurCards();
    dbSave();updateStorageInfo();
    toast('success','✓',`Auditeurs réinitialisés (${AUDITEURS.length} entrées)`);
  } else if(target==='audits'){
    _reload(AUDITS,SEED_AUDITS());
    _reload(GANTT_MISSIONS,SEED_GANTT());
    tryRender(()=>syncMissionsFromAudits())
    renderAudits();renderWidgets();
    $('#nb-audits').text(AUDITS.length);

    dbSave();updateStorageInfo();
    toast('success','✓',`Plans d'audit réinitialisés — ${AUDITS.length} audit(s), ${GANTT_MISSIONS.length} mission(s) Gantt`);
    setTimeout(()=>showView('audits'),600);
  } else if(target==='actions'){
    _reload(ACTIONS,SEED_ACTIONS());
    renderActions();renderW10();renderWidgets();
    const nbOpen=ACTIONS.reduce((s,a)=>s+(a.recommandations||[]).filter(r=>r.statut!=='fully').length,0);
    $('#nb-actions').text(nbOpen||ACTIONS.length);
    dbSave();updateStorageInfo();
    toast('success','✓',`Recommandations réinitialisées — ${ACTIONS.length} constat(s)`);
    setTimeout(()=>showView('actions'),600);
  } else if(target==='risks'){
    RISKS.length=0;
    renderW10();renderWidgets();
    dbSave();updateStorageInfo();
    toast('success','✓','Risques supprimés (liste vide)');
    setTimeout(()=>showView('risks'),600);
  } else if(target==='daily'){
    DAILY_TASKS.length=0;
    tryRender(()=>renderDailyTasks())
    $('#nb-daily').text(0);
    dbSave();updateStorageInfo();
    toast('success','✓','Tâches quotidiennes supprimées — liste vide');
    setTimeout(()=>showView('daily'),600);
  } else if(target==='absences'){
    ABSENCES.length=0;
    tryRender(()=>{ renderAbsenceList(); renderDispoTable(); updateAbsenceBadge(); })
    dbSave();updateStorageInfo();
    toast('success','✓','Absences & congés supprimés');
    setTimeout(()=>showView('absences'),600);
  } else if(target==='planning'){
    _reload(GANTT_MISSIONS,SEED_GANTT());
    tryRender(()=>syncMissionsFromAudits())
    tryRender(()=>renderGantt())
    tryRender(()=>renderWidgets())
    dbSave();updateStorageInfo();
    toast('success','✓',`Planning Missions réinitialisé — ${GANTT_MISSIONS.length} mission(s) Gantt`);
    setTimeout(()=>showView('gantt'),600);
  }
});

$('#db-reset-all').on('click',function(){
  if($('#db-confirm-input').val().trim()!=='CONFIRMER'){
    toast('error','!','Tapez exactement CONFIRMER pour valider');
    $('#db-confirm-input').focus();return;
  }

  DB_ALL_KEYS.forEach(k=>localStorage.removeItem(k));
  SOC_LOGOS={};saveSocLogos();

  _reload(SOCIETES,      SEED_SOCIETES());
  _reload(AUDITEURS,     SEED_AUDITEURS());
  _reload(AUDITS,        SEED_AUDITS());
  _reload(ACTIONS,       SEED_ACTIONS());
  _reload(GANTT_MISSIONS,SEED_GANTT());
  RISKS.length=0;
  DAILY_TASKS.length=0;
  ABSENCES.length=0;
  ORDRES_MISSION.length=0;
  tryRender(()=>dbSaveOM())
  tryRender(()=>syncMissionsFromAudits())

  dbSave();
  renderAll();
  updateStorageInfo();
  $('#db-confirm-input').val('');
  toast('success','✓','Remise à zéro complète — base de données vide');
});

$('#db-clear-storage').on('click',function(){
  DB_ALL_KEYS.forEach(k=>localStorage.removeItem(k));
  SOC_LOGOS={};saveSocLogos();
  updateStorageInfo();
  toast('info','🗑','localStorage entièrement effacé');
});

function renderAll(){
  tryRender(()=>syncMissionsFromAudits());
  renderSocietes(); renderAuditeurs(); renderResponsables();
  renderAudits(); renderActions();
  renderWidgets();
  renderAuditeurCards(); renderSocietesView();
  tryRender(()=>renderW4());
  tryRender(()=>renderW10());
  tryRender(()=>renderGantt());
  tryRender(()=>renderDailyTasks());
  tryRender(()=>renderOM());

  $('#nb-audits').text(AUDITS.length);
  $('#nb-actions').text(ACTIONS.reduce((s,a)=>s+(a.recommandations||[]).filter(r=>r.statut!=='fully').length,0)||ACTIONS.length);
  const nDailyOverdue=DAILY_TASKS.filter(t=>{if(t.statut==='done')return false;const d=new Date(t.date),tod=new Date();tod.setHours(0,0,0,0);return !isNaN(d)&&d<tod;}).length;
  $('#nb-daily').text(nDailyOverdue||DAILY_TASKS.length);
  tryRender(()=>updateAbsenceBadge());
}

$(document).on('click','.cfg-tab[data-cfg="database"]',function(){updateStorageInfo();});

function injectDomV_IIA(auditRef){
  if(!auditRef) return;
  var m = GANTT_MISSIONS.find(function(x){ return x.ref === auditRef || x.id === 'M-'+auditRef; });
  if(!m) return;
  if(m.tasks && m.tasks.length > 0) return;

  var s = m.start || new Date().toISOString().slice(0,10);
  var e = m.end   || new Date().toISOString().slice(0,10);
  var u = function(){ return 'T'+Date.now().toString(36)+Math.random().toString(36).slice(2,5); };

  // Ajoute n jours ouvrés
  function addWD(ds,n){ var d=new Date(ds); var a=0; while(a<n){d.setDate(d.getDate()+1);if(d.getDay()!==0&&d.getDay()!==6)a++;} return d.toISOString().slice(0,10); }
  function spanWD(ds,n){ var d=new Date(ds); while(d.getDay()===0||d.getDay()===6)d.setDate(d.getDate()+1); var c=1; while(c<n){d.setDate(d.getDate()+1);if(d.getDay()!==0&&d.getDay()!==6)c++;} return d.toISOString().slice(0,10); }

  var calDays = Math.max(1, Math.round((new Date(e)-new Date(s))/86400000));
  var ratio = calDays < 30 ? calDays/30 : 1;
  function jo(base){ return Math.max(1, Math.round(base * ratio)); }

  var jo1=jo(1.5), jo2=jo(2.5), jo3=jo(3);
  var jo4=jo(4),   jo5=jo(4),   jo6=jo(3);
  var jo7=jo(2),   jo8=jo(2);

  var s1=s,       e1=spanWD(s1,jo1);
  var s2=addWD(e1,1), e2=spanWD(s2,jo2);
  var s3=addWD(e2,1), e3=spanWD(s3,jo3);
  var s4=addWD(e3,1), e4=spanWD(s4,jo4);
  var s5=addWD(e4,1), e5=spanWD(s5,jo5);
  var s6=addWD(e5,1), e6=spanWD(s6,jo6);
  var s7=addWD(e6,1), e7=spanWD(s7,jo7);
  var s8=addWD(e7,1), e8=spanWD(s8,jo8);
  var eP1=e3, eP2=e6, eP3=e8;
  var sP1=s1, sP2=s4, sP3=s7;

  function sub(ds,de,n){
    var res=[]; var d0=new Date(ds),d1=new Date(de);
    var totalMs=d1-d0; var chunk=Math.floor(totalMs/n);
    for(var i=0;i<n;i++){
      var dsi=new Date(d0.getTime()+i*chunk);
      var dei=i===n-1?new Date(d1):new Date(d0.getTime()+(i+1)*chunk-86400000);
      while(dsi.getDay()===0||dsi.getDay()===6) dsi.setDate(dsi.getDate()+1);
      while(dei.getDay()===0||dei.getDay()===6) dei.setDate(dei.getDate()-1);
      if(dei<dsi) dei=new Date(dsi);
      res.push({s:dsi.toISOString().slice(0,10),e:dei.toISOString().slice(0,10)});
    }
    return res;
  }
  var st1=sub(s1,e1,3),st2=sub(s2,e2,3),st3=sub(s3,e3,3);
  var st4=sub(s4,e4,3),st5=sub(s5,e5,3),st6=sub(s6,e6,3);
  var st7=sub(s7,e7,3),st8=sub(s8,e8,3);

  m.tasks = [
    {id:u(),type:'task',title:'📋 PHASE 1 : PLANIFICATION (Normes 11.1 à 11.3)',difficulte:'moyenne',start:sP1,end:eP1,assignees:[],progress:0,subtasks:[]},
    {id:u(),type:'task',title:'Tâche 1 : Cadrage et Engagement ('+jo1+' J.O.)',difficulte:'facile',start:s1,end:e1,assignees:[],progress:0,subtasks:[
      {id:u(),title:'Envoi de l\'avis de mission (lettre de mission)',difficulte:'facile',start:st1[0].s,end:st1[0].e,assignees:[]},
      {id:u(),title:'Entretiens préliminaires avec les responsables de processus',difficulte:'facile',start:st1[1].s,end:st1[1].e,assignees:[]},
      {id:u(),title:'Collecte de la documentation de base (procédures, organigrammes)',difficulte:'facile',start:st1[2].s,end:st1[2].e,assignees:[]}
    ]},
    {id:u(),type:'task',title:'Tâche 2 : Analyse des Risques et Périmètre ('+jo2+' J.O.)',difficulte:'difficile',start:s2,end:e2,assignees:[],progress:0,subtasks:[
      {id:u(),title:'Identification des risques inhérents et des contrôles clés',difficulte:'difficile',start:st2[0].s,end:st2[0].e,assignees:[]},
      {id:u(),title:'Matrice des risques de la mission (Heatmap locale)',difficulte:'difficile',start:st2[1].s,end:st2[1].e,assignees:[]},
      {id:u(),title:'Définition précise des limites du champ d\'intervention',difficulte:'moyenne',start:st2[2].s,end:st2[2].e,assignees:[]}
    ]},
    {id:u(),type:'task',title:'Tâche 3 : Programme de Travail et Ressources ('+jo3+' J.O.)',difficulte:'difficile',start:s3,end:e3,assignees:[],progress:0,subtasks:[
      {id:u(),title:'Rédaction des pas de tests (méthodologie d\'échantillonnage)',difficulte:'difficile',start:st3[0].s,end:st3[0].e,assignees:[]},
      {id:u(),title:'Confirmation de l\'indépendance de l\'équipe (Déclaration IIA)',difficulte:'facile',start:st3[1].s,end:st3[1].e,assignees:[]},
      {id:u(),title:'Budget temps détaillé par auditeur',difficulte:'moyenne',start:st3[2].s,end:st3[2].e,assignees:[]}
    ]},
    {id:u(),type:'milestone',title:'🏁 JALON 1 : Approbation du Programme de Travail (Supervision 12.3)',difficulte:'facile',start:eP1,assignees:[],progress:0,subtasks:[]},
    {id:u(),type:'task',title:'🛠️ PHASE 2 : RÉALISATION DES TRAVAUX (Normes 12.1 à 12.3)',difficulte:'difficile',start:sP2,end:eP2,assignees:[],progress:0,subtasks:[]},
    {id:u(),type:'task',title:'Tâche 4 : Tests et Collecte de Preuves ('+jo4+' J.O.)',difficulte:'difficile',start:s4,end:e4,assignees:[],progress:0,subtasks:[
      {id:u(),title:'Exécution des tests (Cheminement, conformité, performance)',difficulte:'difficile',start:st4[0].s,end:st4[0].e,assignees:[]},
      {id:u(),title:'Extraction et analyse de données (Data Analytics)',difficulte:'difficile',start:st4[1].s,end:st4[1].e,assignees:[]},
      {id:u(),title:'Entretien de validation des faits au fil de l\'eau',difficulte:'moyenne',start:st4[2].s,end:st4[2].e,assignees:[]}
    ]},
    {id:u(),type:'task',title:'Tâche 5 : Analyse des Écarts et Qualification ('+jo5+' J.O.)',difficulte:'très difficile',start:s5,end:e5,assignees:[],progress:0,subtasks:[
      {id:u(),title:'Rédaction des Feuilles de Révélation et d\'Analyse de Problèmes (FRAP/5C)',difficulte:'très difficile',start:st5[0].s,end:st5[0].e,assignees:[]},
      {id:u(),title:'Évaluation de la cause profonde (Root Cause Analysis)',difficulte:'très difficile',start:st5[1].s,end:st5[1].e,assignees:[]},
      {id:u(),title:'Estimation de l\'impact financier ou opérationnel des constats',difficulte:'difficile',start:st5[2].s,end:st5[2].e,assignees:[]}
    ]},
    {id:u(),type:'task',title:'Tâche 6 : Recommandations et Revue Qualité ('+jo6+' J.O.)',difficulte:'difficile',start:s6,end:e6,assignees:[],progress:0,subtasks:[
      {id:u(),title:'Co-construction des plans d\'action avec les audités',difficulte:'difficile',start:st6[0].s,end:st6[0].e,assignees:[]},
