function syncMissionsFromAudits(authoritativeRef){
  const colors=['#0070f2','#6941c6','#1a8a4a','#c05c00','#007d8c','#bb2222','#c47d00','#005a9e'];
  let created = 0, updated = 0, deleted = 0;
  const newlyOpened = [];

  AUDITS.forEach((a,i)=>{
    const mid='M-'+a.ref;
    const ex=GANTT_MISSIONS.find(m=>m.id===mid||m.ref===a.ref);
    if(!ex){

      const ganttStatus = (a.status==='open') ? 'inprogress' : (a.status||'planned');
      GANTT_MISSIONS.push({
        id:mid, ref:a.ref, title:a.title, societe:a.societe, chef:a.auditor,
        start:a.start, end:a.end, progress:a.progress||0,
        status:ganttStatus, color:colors[i%colors.length], tasks:[]
      });
      if(a.status==='open') newlyOpened.push(a);
      created++;
    } else {

      const wasPlanned = ex.status==='planned';
      const nowOpen    = a.status==='open';
      if(wasPlanned && nowOpen) newlyOpened.push(a);

      // Si la mission a été modifiée manuellement dans le Gantt (_manualEdit),
      // préserver ses champs et propager vers l'audit lié à la place —
      // SAUF si cet audit vient d'être modifié via le formulaire (authoritativeRef),
      // dans ce cas l'audit est la source de vérité et écrase la mission.
      if(ex._manualEdit && a.ref!==authoritativeRef){
        const ai = AUDITS.findIndex(x=>x.ref===ex.ref);
        if(ai>=0){
          if(ex.title)                AUDITS[ai].title    = ex.title;
          if(ex.societe)              AUDITS[ai].societe  = ex.societe;
          if(ex.chef)                 AUDITS[ai].auditor  = ex.chef;
          if(ex.start)                AUDITS[ai].start    = ex.start;
          if(ex.end)                  AUDITS[ai].end      = ex.end;
          if(ex.progress!==undefined) AUDITS[ai].progress = ex.progress;
        }
        // Ne mettre à jour que le statut si l'audit est passé à 'open'
        if(nowOpen && ex.status==='planned') ex.status = 'inprogress';
      } else {
        ex.ref=a.ref; ex.title=a.title; ex.societe=a.societe;
        ex.chef=a.auditor;
        // Cascade automatique : si la date de début de l'audit a changé et que la mission a des tâches
        if(a.start && ex.start && a.start !== ex.start && (ex.tasks||[]).length > 0){
          cascadeTaskDates(ex, ex.start, a.start);
        }
        ex.start=a.start; ex.end=a.end;
        ex.status = nowOpen ? 'inprogress' : a.status;
        if(ex.progress===undefined || a.ref===authoritativeRef) ex.progress=a.progress||0;
        if(ex._manualEdit && a.ref===authoritativeRef) delete ex._manualEdit;
        // Recalcul date de fin depuis les tâches
        recalcMissionEndFromTasks(ex);
      }
      updated++;
    }
  });

  const refs=new Set(AUDITS.map(a=>a.ref));
  for(let i=GANTT_MISSIONS.length-1;i>=0;i--){
    const m=GANTT_MISSIONS[i];
    if(m.ref && !refs.has(m.ref)) {
      GANTT_MISSIONS.splice(i,1);
      deleted++;
    }
  }

  newlyOpened.forEach(a=>{
    setTimeout(()=>{
      toast('success','🚀',`Mission Gantt démarrée : ${a.ref} — ${a.title}`);
    },200);
  });

  tryRender(()=>syncGanttToDaily())
}

function syncGanttToDaily(){
  /* Les missions des Plans d'audit interne ne sont plus injectées dans
     les Tâches Quotidiennes. On purge les entrées résiduelles (ganttRef/auditRef). */
  for(let i=DAILY_TASKS.length-1;i>=0;i--){
    if(DAILY_TASKS[i].ganttRef || DAILY_TASKS[i].auditRef){
      DAILY_TASKS.splice(i,1);
    }
  }
}

/* ── syncAuditsFromMission : mission Gantt → audit lié ── */
function syncAuditsFromMission(m){
  if(!m||!m.ref) return;
  const a=AUDITS.find(x=>x.ref===m.ref);
  if(!a) return;
  // Mise à jour de l'audit depuis la mission
  a.title    = m.title    || a.title;
  a.societe  = m.societe  || a.societe;
  a.auditor  = m.chef     || a.auditor;
  a.start    = m.start    || a.start;
  a.end      = m.end      || a.end;
  a.progress = (m.progress!==undefined) ? m.progress : a.progress;
  if(m.status) a.status = m.status;

  $('#nb-audits').text(AUDITS.length);

  if(isViewVisible('view-audits')) renderAudits();
}

