/* ══════════════════════════════════════════════════════════
   GESTION UTILISATEUR COURANT — récupéré depuis le navigateur
   ══════════════════════════════════════════════════════════ */
(function(){
  const STORAGE_KEY = 'audit_current_user_id';

  function getInitials(prenom, nom){
    const p = (prenom||'').trim(); const n = (nom||'').trim();
    return ((p[0]||'')+(n[0]||'')).toUpperCase() || '?';
  }

  function applyCurrentUser(auditeur){
    if(!auditeur){ 
      document.getElementById('current-user-avatar').textContent = '?';
      document.getElementById('current-user-name').textContent = 'Utilisateur inconnu';
      document.getElementById('current-user-role').textContent = '—';
      document.getElementById('topbar-user-avatar').textContent = '?';
      return;
    }
    const initials = getInitials(auditeur.prenom, auditeur.nom);
    const fullName = (auditeur.prenom||'') + ' ' + (auditeur.nom||'');
    const role = auditeur.role || 'Auditeur interne';
    document.getElementById('current-user-avatar').textContent = initials;
    document.getElementById('current-user-name').textContent = fullName.trim();
    document.getElementById('current-user-role').textContent = role;
    document.getElementById('topbar-user-avatar').textContent = initials;
    document.getElementById('topbar-profile-btn').title = fullName.trim() + ' — ' + role;
  }

  function loadCurrentUser(){
    const savedId = localStorage.getItem(STORAGE_KEY);
    if(savedId && AUDITEURS.length){
      const found = AUDITEURS.find(a => a.id === savedId || (a.prenom+' '+a.nom).trim() === savedId);
      if(found){ applyCurrentUser(found); return; }
    }
    // Fallback : premier auditeur de la liste
    if(AUDITEURS.length){ applyCurrentUser(AUDITEURS[0]); localStorage.setItem(STORAGE_KEY, AUDITEURS[0].id || (AUDITEURS[0].prenom+' '+AUDITEURS[0].nom).trim()); }
    else {
      // Aucun auditeur en base — afficher placeholder
      document.getElementById('current-user-avatar').textContent = '?';
      document.getElementById('current-user-name').textContent = 'Aucun auditeur';
      document.getElementById('current-user-role').textContent = 'Configurer dans Équipe';
      document.getElementById('topbar-user-avatar').textContent = '?';
    }
  }

  function openUserPickerModal(){
    if(!AUDITEURS.length){ toast('info','👤','Ajoutez des auditeurs dans ⚙ Configuration → Équipe Auditeurs'); return; }
    const savedId = localStorage.getItem(STORAGE_KEY);
    const opts = AUDITEURS.map(a=>{
      const id = a.id || (a.prenom+' '+a.nom).trim();
      const isCurrent = (id === savedId || (a.prenom+' '+a.nom).trim() === savedId);
      const initials = getInitials(a.prenom, a.nom);
      const role = a.role || 'Auditeur interne';
      return `<div class="user-pick-opt ${isCurrent?'active':''}" data-uid="${id}" style="display:flex;align-items:center;gap:10px;padding:9px 13px;border-radius:6px;cursor:pointer;border:2px solid ${isCurrent?'var(--accent)':'var(--border)'};background:${isCurrent?'var(--accent-bg)':'var(--surface)'};margin-bottom:7px;transition:all .15s;" onmouseover="if(!this.classList.contains('active'))this.style.background='var(--surface2)'" onmouseout="if(!this.classList.contains('active'))this.style.background='var(--surface)'">
        <div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,#0070f2,#6941c6);display:grid;place-items:center;font-size:11px;font-weight:700;color:#fff;flex-shrink:0;">${initials}</div>
        <div style="flex:1;">
          <div style="font-size:12.5px;font-weight:600;color:var(--text);">${a.prenom||''} ${a.nom||''}</div>
          <div style="font-size:10.5px;color:var(--text-muted);">${role}${a.email?' · '+a.email:''}</div>
        </div>
        ${isCurrent?'<span style="font-size:11px;color:var(--accent);font-weight:700;">✓ Actif</span>':''}
      </div>`;
    }).join('');
    openModal('👤 Changer d\'utilisateur', `
      <div style="font-size:11.5px;color:var(--text-muted);margin-bottom:14px;padding:8px 10px;background:var(--surface2);border-radius:5px;border-left:3px solid var(--accent);">
        Sélectionnez votre profil. Ce choix est mémorisé dans ce navigateur.
      </div>
      <div id="user-picker-list">${opts}</div>
    `);
    $('#msave').hide();
    $(document).on('click.userpick','.user-pick-opt', function(){
      const uid = $(this).data('uid');
      const found = AUDITEURS.find(a => (a.id||((a.prenom+' '+a.nom).trim())) === uid);
      if(!found) return;
      localStorage.setItem(STORAGE_KEY, uid);
      applyCurrentUser(found);
      closeModal();
      $('#msave').show();
      toast('success','👤', `Profil changé : ${found.prenom} ${found.nom}`);
    });
  }

  // Charger au démarrage (après dbLoad)
  setTimeout(loadCurrentUser, 200);

  // Ré-appliquer si les auditeurs changent (ex: import DB)
  window._reloadCurrentUser = loadCurrentUser;

  // Clic sur la carte utilisateur → modal
  $(document).on('click','#current-user-card, #topbar-profile-btn', function(){
    openUserPickerModal();
  });

  // Nettoyer le handler userpick à la fermeture de modale
  const _origClose = window.closeModal;
  // (déjà géré par closeModal via .off — on ajoute juste .off sur userpick)
})();

function dbSaveOM(){ try{ localStorage.setItem('audit_ordres_mission', JSON.stringify(ORDRES_MISSION)); }catch(e){} }
function dbLoadOM(){
  try{
    const d = localStorage.getItem('audit_ordres_mission');
    if(d){ const p=JSON.parse(d); ORDRES_MISSION.length=0; p.forEach(x=>ORDRES_MISSION.push(x)); }
  }catch(e){}
}

function renderOM(){
  const q = ($('#om-search').val()||'').toLowerCase();
  const fs = $('#om-filter-soc').val()||'';

  // Peupler filtre société
  const $fs=$('#om-filter-soc');
  if($fs.find('option').length<=1){
    [...new Set(ORDRES_MISSION.map(o=>o.societe).filter(Boolean))].sort()
      .forEach(s=>$fs.append(`<option value="${s}">${s}</option>`));
  }

  const filtered = ORDRES_MISSION.filter(o=>{
    if(fs && o.societe!==fs) return false;
    const txt=`${o.ref} ${o.societe} ${o.objet} ${o.chefMission}`.toLowerCase();
    if(q && !txt.includes(q)) return false;
    return true;
  });

  const $grid=$('#om-cards-grid').empty();
  $('#om-count').text(filtered.length+' ordre'+(filtered.length>1?'s':''));

  if(!filtered.length){ $('#om-empty').show(); return; }
  $('#om-empty').hide();

  const stCfg={
    planned:{label:'Planifié',cls:'om-badge-planned'},
    inprogress:{label:'En cours',cls:'om-badge-inprogress'},
    done:{label:'Terminé',cls:'om-badge-done'}
  };
  const stIco={planned:'📋',inprogress:'🔄',done:'✅'};

  filtered.forEach((o,i)=>{
    const idx=ORDRES_MISSION.indexOf(o);
    const sc=stCfg[o.statut]||stCfg.planned;
    const team=(o.equipe||[]).map(m=>`<span style="font-size:10px;background:var(--surface3);padding:1px 6px;border-radius:8px;margin:1px;">${m.nom}</span>`).join('');
    $grid.append(`
    <div style="border:1px solid var(--border);border-radius:8px;overflow:hidden;background:var(--surface);box-shadow:0 1px 4px rgba(0,0,0,.06);transition:box-shadow .15s;"
         onmouseover="this.style.boxShadow=\'0 4px 14px rgba(0,0,0,.12)\'"
         onmouseout="this.style.boxShadow=\'0 1px 4px rgba(0,0,0,.06)\'">
      <div style="background:linear-gradient(135deg,#0070f2,#1a4fa0);padding:10px 14px;display:flex;justify-content:space-between;align-items:flex-start;">
        <div>
          <div style="font-family:var(--mono);font-size:10px;color:rgba(255,255,255,.75);margin-bottom:2px;">${o.ref||'—'}</div>
          <div style="font-size:12px;font-weight:700;color:#fff;line-height:1.3;">${o.objet||'Mission d\'audit'}</div>
        </div>
        <span style="font-size:8px;" class="om-badge ${sc.cls}">${stIco[o.statut]||'📋'} ${sc.label}</span>
      </div>
      <div style="padding:10px 14px;font-size:11px;">
        <div style="display:flex;gap:14px;margin-bottom:7px;flex-wrap:wrap;">
          <span style="color:var(--text-muted);">🏢 <strong>${o.societe||'—'}</strong></span>
          <span style="color:var(--text-muted);">👤 ${o.chefMission||'—'}</span>
        </div>
        <div style="display:flex;gap:12px;margin-bottom:8px;font-size:10px;color:var(--text-muted);">
          <span>📅 Du <strong>${o.dateDebut||'—'}</strong> au <strong>${o.dateFin||'—'}</strong></span>
          <span style="margin-left:auto;">🗓️ Émis le ${o.dateEmission||'—'}</span>
        </div>
        <div style="display:flex;flex-wrap:wrap;gap:3px;margin-bottom:8px;">${team||'<span style="font-size:10px;color:var(--text-dim);">Aucun membre</span>'}</div>
        <div style="display:flex;gap:6px;justify-content:flex-end;border-top:1px solid var(--border);padding-top:8px;margin-top:2px;">
          <button class="btn om-view-btn" data-idx="${idx}" style="font-size:10px;padding:2px 10px;">👁 Aperçu</button>
          <button class="btn om-edit-btn" data-idx="${idx}" style="font-size:10px;padding:2px 10px;">✏️ Modifier</button>
          <button class="btn om-print-one-btn" data-idx="${idx}" style="font-size:10px;padding:2px 10px;background:var(--accent);color:#fff;border-color:var(--accent);">🖨️ Imprimer</button>
          <button class="btn om-del-btn" data-idx="${idx}" style="font-size:10px;padding:2px 10px;color:var(--red);border-color:var(--red-bg);">✕</button>
        </div>
      </div>
    </div>`);
  });
}

// ── Formulaire Ordre de Mission ─────────────────────────────────
function OM_FORM(o){
  const isEdit=!!o;
  const todayStr=new Date().toISOString().slice(0,10);
  const nextRef='OM-'+new Date().getFullYear()+'-'+String(ORDRES_MISSION.length+1).padStart(3,'0');
  const auds=AUDITEURS.map(a=>`<option value="${a.prenom} ${a.nom}">${a.prenom} ${a.nom} ${a.role?'('+a.role+')':''}</option>`).join('');
  const socs=SOCIETES.map(s=>`<option value="${s.nom}"${isEdit&&s.nom===o.societe?' selected':''}>${s.nom}</option>`).join('');

  // Membres actuels
  const curTeam=isEdit?(o.equipe||[]):[];

  // Champs personnalisés (formulaire 3)
  const customFields=isEdit&&o.champPersonnalises?o.champPersonnalises:[];

  return `
<div style="display:flex;flex-direction:column;gap:0;">

<div id="om-tabs" style="display:flex;gap:0;border-bottom:2px solid var(--border);margin-bottom:16px;">
  <button type="button" class="om-tab om-tab-active" data-tab="tab-audit" style="padding:7px 16px;font-size:11.5px;font-weight:600;border:none;border-bottom:2px solid var(--accent);background:none;color:var(--accent);cursor:pointer;margin-bottom:-2px;border-radius:4px 4px 0 0;">📄 Mission d'Audit</button>
  <button type="button" class="om-tab" data-tab="tab-controle" style="padding:7px 16px;font-size:11.5px;font-weight:600;border:none;border-bottom:2px solid transparent;background:none;color:var(--text-muted);cursor:pointer;margin-bottom:-2px;border-radius:4px 4px 0 0;">🔍 Mission de Contrôle</button>
  <button type="button" class="om-tab" data-tab="tab-custom" style="padding:7px 16px;font-size:11.5px;font-weight:600;border:none;border-bottom:2px solid transparent;background:none;color:var(--text-muted);cursor:pointer;margin-bottom:-2px;border-radius:4px 4px 0 0;">⚙️ Formulaire Libre</button>
</div>

<div id="tab-audit" class="om-tab-pane" style="display:flex;flex-direction:column;gap:0;">

  <div style="background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📋 Identification</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Référence <span class="t-red">*</span></div>
        <input class="finp" id="om-ref" value="${isEdit?o.ref||'':nextRef}" placeholder="${nextRef}"></div>
      <div class="frow2"><div class="flbl2">Date d'émission</div>
        <input class="finp" id="om-date-emission" type="date" value="${isEdit?o.dateEmission||todayStr:todayStr}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Société / Entité auditée <span class="t-red">*</span></div>
        <select class="finp" id="om-societe" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>${socs}
        </select></div>
      <div class="frow2"><div class="flbl2">Statut</div>
        <select class="finp" id="om-statut" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="planned"${(!isEdit||o.statut==='planned')?' selected':''}>📋 Planifié</option>
          <option value="inprogress"${isEdit&&o.statut==='inprogress'?' selected':''}>🔄 En cours</option>
          <option value="done"${isEdit&&o.statut==='done'?' selected':''}>✅ Terminé</option>
        </select></div>
    </div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">🎯 Objet & Périmètre</div>
    <div class="frow2"><div class="flbl2">Objet de la mission <span class="t-red">*</span></div>
      <input class="finp" id="om-objet" value="${isEdit?o.objet||'':''}" placeholder="Ex : Audit du cycle Stock — VETCARE…"></div>
    <div class="frow2"><div class="flbl2">Objectifs de la mission</div>
      <textarea class="finp" id="om-objectifs" rows="3" style="resize:vertical;height:64px;" placeholder="— Vérifier la fiabilité des données de stock&#10;— Évaluer les contrôles internes…">${isEdit?o.objectifs||'':''}</textarea></div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Périmètre / Cycle audité</div>
        <input class="finp" id="om-perimetre" value="${isEdit?o.perimetre||'':''}" placeholder="Ex : Cycle Stock, Processus Achats…"></div>
      <div class="frow2"><div class="flbl2">Référentiel appliqué</div>
        <input class="finp" id="om-referentiel" value="${isEdit?o.referentiel||'':''}" placeholder="Ex : COSO, ISO 31000, manuel procédures…"></div>
    </div>
    <div class="frow2"><div class="flbl2">Travaux à réaliser</div>
      <textarea class="finp" id="om-travaux" rows="2" style="resize:vertical;height:50px;" placeholder="Ex : Revue documentaire, entretiens, tests de contrôles, observation physique…">${isEdit?o.travaux||'':''}</textarea></div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📅 Calendrier & Lieu</div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;">
      <div class="frow2"><div class="flbl2">Date de début</div>
        <input class="finp" id="om-date-debut" type="date" value="${isEdit?o.dateDebut||'':todayStr}"></div>
      <div class="frow2"><div class="flbl2">Date de fin prévue</div>
        <input class="finp" id="om-date-fin" type="date" value="${isEdit?o.dateFin||'':todayStr}"></div>
      <div class="frow2"><div class="flbl2">Durée estimée (jours)</div>
        <input class="finp" id="om-duree" type="number" min="1" value="${isEdit?o.duree||'':''}" placeholder="5"></div>
    </div>
    <div class="frow2"><div class="flbl2">Lieu de mission</div>
      <input class="finp" id="om-lieu" value="${isEdit?o.lieu||'':''}" placeholder="Ex : Siège VETCARE, Antananarivo…"></div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">👥 Équipe de mission</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px;">
      <div class="frow2"><div class="flbl2">Chef de mission</div>
        <select class="finp" id="om-chef" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>${AUDITEURS.map(a=>`<option value="${a.prenom+' '+a.nom}"${isEdit&&o.chefMission===a.prenom+' '+a.nom?' selected':''}>${a.prenom} ${a.nom}${a.role?' ('+a.role+')':''}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Signataire / Directeur Audit</div>
        <input class="finp" id="om-signataire" value="${isEdit?o.signataire||'':''}" placeholder="Nom du responsable signataire…"></div>
    </div>
    <div style="font-size:11px;font-weight:600;color:var(--text-muted);margin-bottom:6px;">Membres de l'équipe</div>
    <div id="om-equipe-rows">${curTeam.map((m,i)=>OM_MEMBRE_ROW(m,i)).join('')||OM_MEMBRE_ROW(null,0)}</div>
    <button type="button" id="om-add-membre" class="btn" style="font-size:11px;padding:3px 10px;margin-top:6px;">+ Ajouter un membre</button>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📝 Notes & Instructions</div>
    <div class="frow2"><div class="flbl2">Instructions particulières / Confidentialité</div>
      <textarea class="finp" id="om-notes" rows="2" style="resize:vertical;height:50px;" placeholder="Ex : Document confidentiel. Accès restreint aux membres de la mission…">${isEdit?o.notes||'':''}</textarea></div>
  </div>

  <div style="background:#f3f0ff;border:1px solid #c4b5fd;border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:#6941c6;text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">🔍 Mission de Contrôle</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Type de contrôle</div>
        <select class="finp" id="om-type-controle" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>
          ${['Contrôle de conformité','Contrôle opérationnel','Contrôle financier','Contrôle de gestion','Audit de performance','Audit IT / Systèmes','Contrôle interne','Revue de processus','Investigation / Fraude','Évaluation des risques'].map(t=>`<option value="${t}"${isEdit&&o.typeControle===t?' selected':''}>${t}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Niveau de risque</div>
        <select class="finp" id="om-risque-niveau" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Non évalué —</option>
          <option value="critical"${isEdit&&o.risqueNiveau==='critical'?' selected':''}>🔴 Critique</option>
          <option value="high"${isEdit&&o.risqueNiveau==='high'?' selected':''}>🟠 Élevé</option>
          <option value="medium"${isEdit&&o.risqueNiveau==='medium'?' selected':''}>🟡 Moyen</option>
          <option value="low"${isEdit&&o.risqueNiveau==='low'?' selected':''}>🟢 Faible</option>
        </select></div>
    </div>
    <div class="frow2"><div class="flbl2">Risques ciblés / Domaines à contrôler</div>
      <textarea class="finp" id="om-risques-cibles" rows="2" style="resize:vertical;height:54px;" placeholder="Ex : Risque de non-conformité réglementaire, fiabilité des stocks, séparation des fonctions…">${isEdit?o.risquesCibles||'':''}</textarea></div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Assertions / Critères d'audit</div>
        <input class="finp" id="om-assertions" value="${isEdit?o.assertions||'':''}" placeholder="Ex : Exhaustivité, Exactitude, Existence…"></div>
      <div class="frow2"><div class="flbl2">Approche méthodologique</div>
        <input class="finp" id="om-methode" value="${isEdit?o.methode||'':''}" placeholder="Ex : Sondages, tests de procédures, revue analytique…"></div>
    </div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">
      <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;">✅ Tâches de la Mission</div>
      <button type="button" id="om-add-tache" class="btn" style="font-size:11px;padding:3px 10px;">+ Ajouter une tâche</button>
    </div>
    <div id="om-taches-rows">${(()=>{const taches=isEdit?(o.taches||[]):[];if(!taches.length)return OM_TACHE_ROW(null,0);return taches.map((t,i)=>OM_TACHE_ROW(t,i)).join('');})()}</div>
  </div>

  <div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:6px;padding:12px 14px;">
    <div style="font-size:10.5px;font-weight:700;color:#1a8a4a;text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📊 Résultats & Conclusions</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Note / Appréciation globale</div>
        <select class="finp" id="om-note-globale" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Non évalué —</option>
          <option value="satisfaisant"${isEdit&&o.noteGlobale==='satisfaisant'?' selected':''}>✅ Satisfaisant</option>
          <option value="partiellement"${isEdit&&o.noteGlobale==='partiellement'?' selected':''}>⚠️ Partiellement satisfaisant</option>
          <option value="insuffisant"${isEdit&&o.noteGlobale==='insuffisant'?' selected':''}>❌ Insuffisant</option>
          <option value="critique"${isEdit&&o.noteGlobale==='critique'?' selected':''}>🚨 Critique</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Date de clôture effective</div>
        <input class="finp" id="om-date-cloture" type="date" value="${isEdit?o.dateCloture||'':''}"></div>
    </div>
    <div class="frow2"><div class="flbl2">Principales constatations</div>
      <textarea class="finp" id="om-constatations" rows="3" style="resize:vertical;height:64px;" placeholder="— Constatation 1 : …&#10;— Constatation 2 : …&#10;— Constatation 3 : …">${isEdit?o.constatations||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Recommandations principales</div>
      <textarea class="finp" id="om-recommandations-om" rows="3" style="resize:vertical;height:64px;" placeholder="— Recommandation 1 : …&#10;— Recommandation 2 : …">${isEdit?o.recommandationsOM||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Conclusion générale</div>
      <textarea class="finp" id="om-conclusion" rows="2" style="resize:vertical;height:50px;" placeholder="Synthèse globale de la mission et perspectives de suivi…">${isEdit?o.conclusion||'':''}</textarea></div>
  </div>

</div>

<div id="tab-controle" class="om-tab-pane" style="display:none;flex-direction:column;gap:0;">

  <div style="background:var(--accent-bg);border:1px solid #b3d0f7;border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--accent);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📋 Identification du Contrôle</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Référence contrôle <span class="t-red">*</span></div>
        <input class="finp" id="ctrl-ref" value="${isEdit?o.ctrlRef||'':'CTR-'+new Date().getFullYear()+'-'+String(ORDRES_MISSION.length+1).padStart(3,'0')}" placeholder="CTR-2025-001"></div>
      <div class="frow2"><div class="flbl2">Date d'émission</div>
        <input class="finp" id="ctrl-date-emission" type="date" value="${isEdit?o.ctrlDateEmission||todayStr:todayStr}"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Entité / Périmètre contrôlé <span class="t-red">*</span></div>
        <select class="finp" id="ctrl-societe" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>${SOCIETES.map(s=>`<option value="${s.nom}"${isEdit&&s.nom===o.ctrlSociete?' selected':''}>${s.nom}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Type de contrôle</div>
        <select class="finp" id="ctrl-type" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>
          ${['Contrôle de conformité réglementaire','Contrôle financier & comptable','Contrôle opérationnel','Contrôle de gestion','Contrôle qualité','Contrôle des procédures internes','Contrôle des habilitations / accès','Contrôle budgétaire','Contrôle des stocks','Investigation / Fraude','Contrôle fiscal','Contrôle RH & paie'].map(t=>`<option value="${t}"${isEdit&&o.ctrlType===t?' selected':''}>${t}</option>`).join('')}
        </select></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Fréquence du contrôle</div>
        <select class="finp" id="ctrl-frequence" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>
          ${['Ponctuel','Mensuel','Trimestriel','Semestriel','Annuel','Inoppiné'].map(f=>`<option value="${f}"${isEdit&&o.ctrlFrequence===f?' selected':''}>${f}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Statut</div>
        <select class="finp" id="ctrl-statut" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="planned"${(!isEdit||o.ctrlStatut==='planned')?' selected':''}>📋 Planifié</option>
          <option value="inprogress"${isEdit&&o.ctrlStatut==='inprogress'?' selected':''}>🔄 En cours</option>
          <option value="done"${isEdit&&o.ctrlStatut==='done'?' selected':''}>✅ Terminé</option>
          <option value="suspended"${isEdit&&o.ctrlStatut==='suspended'?' selected':''}>⏸ Suspendu</option>
        </select></div>
    </div>
  </div>

  <div style="background:#f3f0ff;border:1px solid #c4b5fd;border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:#6941c6;text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">🎯 Objet, Risques & Critères</div>
    <div class="frow2"><div class="flbl2">Objet du contrôle <span class="t-red">*</span></div>
      <input class="finp" id="ctrl-objet" value="${isEdit?o.ctrlObjet||'':''}" placeholder="Ex : Contrôle de la conformité des dépenses opérationnelles…"></div>
    <div class="frow2"><div class="flbl2">Domaines / Processus à contrôler</div>
      <textarea class="finp" id="ctrl-domaines" rows="2" style="resize:vertical;height:50px;" placeholder="— Processus de validation des dépenses&#10;— Séparation des fonctions&#10;— Conformité aux procédures internes…">${isEdit?o.ctrlDomaines||'':''}</textarea></div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Niveau de risque inhérent</div>
        <select class="finp" id="ctrl-risque" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Non évalué —</option>
          <option value="critical"${isEdit&&o.ctrlRisque==='critical'?' selected':''}>🔴 Critique</option>
          <option value="high"${isEdit&&o.ctrlRisque==='high'?' selected':''}>🟠 Élevé</option>
          <option value="medium"${isEdit&&o.ctrlRisque==='medium'?' selected':''}>🟡 Moyen</option>
          <option value="low"${isEdit&&o.ctrlRisque==='low'?' selected':''}>🟢 Faible</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Référentiel / Base légale</div>
        <input class="finp" id="ctrl-referentiel" value="${isEdit?o.ctrlReferentiel||'':''}" placeholder="Ex : Code OHADA, Loi fiscale 2024, Manuel procédures…"></div>
    </div>
    <div class="frow2"><div class="flbl2">Critères de contrôle / Points de vérification</div>
      <textarea class="finp" id="ctrl-criteres" rows="3" style="resize:vertical;height:64px;" placeholder="— Vérifier que chaque pièce justificative est validée par deux signataires&#10;— S'assurer que les seuils d'approbation sont respectés&#10;— Contrôler la traçabilité des opérations…">${isEdit?o.ctrlCriteres||'':''}</textarea></div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">👥 Équipe de Contrôle</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px;">
      <div class="frow2"><div class="flbl2">Responsable du contrôle</div>
        <select class="finp" id="ctrl-responsable" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>${AUDITEURS.map(a=>`<option value="${a.prenom+' '+a.nom}"${isEdit&&o.ctrlResponsable===a.prenom+' '+a.nom?' selected':''}>${a.prenom} ${a.nom}${a.role?' ('+a.role+')':''}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Contrôleurs associés</div>
        <input class="finp" id="ctrl-controleurs" value="${isEdit?o.ctrlControleurs||'':''}" placeholder="Noms séparés par des virgules…"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Signataire / Validateur</div>
        <input class="finp" id="ctrl-signataire" value="${isEdit?o.ctrlSignataire||'':''}" placeholder="Directeur ou responsable signataire…"></div>
      <div class="frow2"><div class="flbl2">Interlocuteur entité contrôlée</div>
        <input class="finp" id="ctrl-interlocuteur" value="${isEdit?o.ctrlInterlocuteur||'':''}" placeholder="Nom & fonction du contact…"></div>
    </div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📅 Calendrier & Méthodes</div>
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;">
      <div class="frow2"><div class="flbl2">Date de début</div>
        <input class="finp" id="ctrl-date-debut" type="date" value="${isEdit?o.ctrlDateDebut||'':todayStr}"></div>
      <div class="frow2"><div class="flbl2">Date de fin prévue</div>
        <input class="finp" id="ctrl-date-fin" type="date" value="${isEdit?o.ctrlDateFin||'':todayStr}"></div>
      <div class="frow2"><div class="flbl2">Durée estimée (jours)</div>
        <input class="finp" id="ctrl-duree" type="number" min="1" value="${isEdit?o.ctrlDuree||'':''}" placeholder="3"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Méthode de contrôle</div>
        <select class="finp" id="ctrl-methode" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>
          ${['Inspection documentaire','Tests par sondage','Observation directe','Entretiens & interviews','Analyse de données','Recalcul & vérification','Confirmation externe','Revue analytique','Walkthrough','Combinaison'].map(m=>`<option value="${m}"${isEdit&&o.ctrlMethode===m?' selected':''}>${m}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Taille d'échantillon</div>
        <input class="finp" id="ctrl-echantillon" value="${isEdit?o.ctrlEchantillon||'':''}" placeholder="Ex : 30 dossiers / 100% transactions > 1M Ar…"></div>
    </div>
    <div class="frow2"><div class="flbl2">Période couverte / Exercice contrôlé</div>
      <input class="finp" id="ctrl-periode" value="${isEdit?o.ctrlPeriode||'':''}" placeholder="Ex : Exercice 2024, T3 2025, Jan–Mars 2025…"></div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">
      <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;">✅ Points de Contrôle</div>
      <button type="button" id="ctrl-add-point" class="btn" style="font-size:11px;padding:3px 10px;">+ Ajouter un point</button>
    </div>
    <div id="ctrl-points-rows">${(()=>{const pts=isEdit?(o.ctrlPoints||[]):[];if(!pts.length)return CTRL_POINT_ROW(null,0);return pts.map((p,i)=>CTRL_POINT_ROW(p,i)).join('');})()}</div>
  </div>

  <div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:6px;padding:12px 14px;">
    <div style="font-size:10.5px;font-weight:700;color:#1a8a4a;text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">📊 Résultats du Contrôle</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Conclusion du contrôle</div>
        <select class="finp" id="ctrl-conclusion-niveau" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Non évalué —</option>
          <option value="conforme"${isEdit&&o.ctrlConclusionNiveau==='conforme'?' selected':''}>✅ Conforme</option>
          <option value="partiellement"${isEdit&&o.ctrlConclusionNiveau==='partiellement'?' selected':''}>⚠️ Partiellement conforme</option>
          <option value="non-conforme"${isEdit&&o.ctrlConclusionNiveau==='non-conforme'?' selected':''}>❌ Non conforme</option>
          <option value="critique"${isEdit&&o.ctrlConclusionNiveau==='critique'?' selected':''}>🚨 Non-conformité critique</option>
        </select></div>
      <div class="frow2"><div class="flbl2">Date de clôture du contrôle</div>
        <input class="finp" id="ctrl-date-cloture" type="date" value="${isEdit?o.ctrlDateCloture||'':''}"></div>
    </div>
    <div class="frow2"><div class="flbl2">Écarts / Anomalies constatés</div>
      <textarea class="finp" id="ctrl-ecarts" rows="3" style="resize:vertical;height:64px;" placeholder="— Écart 1 : …&#10;— Écart 2 : …&#10;— Anomalie identifiée : …">${isEdit?o.ctrlEcarts||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Mesures correctives recommandées</div>
      <textarea class="finp" id="ctrl-mesures" rows="2" style="resize:vertical;height:54px;" placeholder="— Mesure 1 : Renforcer la séparation des fonctions&#10;— Mesure 2 : Former les équipes sur les procédures…">${isEdit?o.ctrlMesures||'':''}</textarea></div>
    <div class="frow2"><div class="flbl2">Synthèse générale</div>
      <textarea class="finp" id="ctrl-synthese" rows="2" style="resize:vertical;height:50px;" placeholder="Résumé global des constats et perspectives de suivi…">${isEdit?o.ctrlSynthese||'':''}</textarea></div>
  </div>

</div>

<div id="tab-custom" class="om-tab-pane" style="display:none;flex-direction:column;gap:0;">

  <div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="font-size:10.5px;font-weight:700;color:#c2410c;text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">⚙️ Configuration du Formulaire</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Titre du formulaire</div>
        <input class="finp" id="custom-titre" value="${isEdit?o.customTitre||'':''}" placeholder="Ex : Rapport d'inspection, Fiche de visite…"></div>
      <div class="frow2"><div class="flbl2">Icône / Emoji (optionnel)</div>
        <input class="finp" id="custom-icone" value="${isEdit?o.customIcone||'📝':''}" placeholder="📝" style="font-size:18px;text-align:center;max-width:80px;"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Couleur d'en-tête</div>
        <select class="finp" id="custom-couleur" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          ${[['#1e3a5f','Bleu marine (Audit)'],['#6941c6','Violet (Contrôle)'],['#c2410c','Orange (Inspection)'],['#1a8a4a','Vert (Conformité)'],['#be123c','Rouge (Risque)'],['#0e7490','Cyan (IT)']].map(([v,l])=>`<option value="${v}"${isEdit&&o.customCouleur===v?' selected':''}>${l}</option>`).join('')}
        </select></div>
      <div class="frow2"><div class="flbl2">Entité concernée</div>
        <select class="finp" id="custom-societe" style="appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 8px center;">
          <option value="">— Sélectionner —</option>${SOCIETES.map(s=>`<option value="${s.nom}"${isEdit&&s.nom===o.customSociete?' selected':''}>${s.nom}</option>`).join('')}
        </select></div>
    </div>
    <div class="frow2"><div class="flbl2">Description / Instructions</div>
      <textarea class="finp" id="custom-description" rows="2" style="resize:vertical;height:50px;" placeholder="Description libre du formulaire et instructions d'utilisation…">${isEdit?o.customDescription||'':''}</textarea></div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;margin-bottom:12px;">
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:10px;">
      <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;">📝 Champs Personnalisés</div>
      <div style="display:flex;gap:6px;">
        <button type="button" id="custom-add-text" class="btn" style="font-size:11px;padding:3px 10px;">+ Texte</button>
        <button type="button" id="custom-add-textarea" class="btn" style="font-size:11px;padding:3px 10px;">+ Paragraphe</button>
        <button type="button" id="custom-add-select" class="btn" style="font-size:11px;padding:3px 10px;">+ Liste</button>
        <button type="button" id="custom-add-date" class="btn" style="font-size:11px;padding:3px 10px;">+ Date</button>
        <button type="button" id="custom-add-check" class="btn" style="font-size:11px;padding:3px 10px;">+ Case</button>
      </div>
    </div>
    <div id="custom-fields-rows" style="display:flex;flex-direction:column;gap:8px;">
      ${customFields.map((f,i)=>CUSTOM_FIELD_ROW(f,i)).join('')}
      ${customFields.length===0?'<div style="text-align:center;color:var(--text-muted);font-size:11px;padding:20px 0;border:1px dashed var(--border);border-radius:4px;">Ajoutez des champs en cliquant sur les boutons ci-dessus</div>':''}
    </div>
  </div>

  <div style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:12px 14px;">
    <div style="font-size:10.5px;font-weight:700;color:var(--text);text-transform:uppercase;letter-spacing:.07em;margin-bottom:10px;">✍️ Signatures</div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Signataire 1 — Intitulé</div>
        <input class="finp" id="custom-sign1-label" value="${isEdit?o.customSign1Label||'Responsable':''}" placeholder="Ex : Responsable, Contrôleur…"></div>
      <div class="frow2"><div class="flbl2">Signataire 1 — Nom</div>
        <input class="finp" id="custom-sign1-nom" value="${isEdit?o.customSign1Nom||'':''}" placeholder="Nom et prénom…"></div>
    </div>
    <div class="fgrid">
      <div class="frow2"><div class="flbl2">Signataire 2 — Intitulé</div>
        <input class="finp" id="custom-sign2-label" value="${isEdit?o.customSign2Label||'Validateur':''}" placeholder="Ex : Validateur, Directeur…"></div>
      <div class="frow2"><div class="flbl2">Signataire 2 — Nom</div>
        <input class="finp" id="custom-sign2-nom" value="${isEdit?o.customSign2Nom||'':''}" placeholder="Nom et prénom…"></div>
    </div>
  </div>

</div>

</div>`;
}

function OM_TACHE_ROW(t, i){
  const auds=AUDITEURS.map(a=>`<option value="${a.prenom+' '+a.nom}"${t&&t.responsable===a.prenom+' '+a.nom?' selected':''}>${a.prenom} ${a.nom}</option>`).join('');
  const stOpts=[['todo','⬜ À faire'],['inprogress','🔄 En cours'],['done','✅ Terminé'],['blocked','🚫 Bloqué']].map(([v,l])=>`<option value="${v}"${t&&t.statut===v?' selected':''}>${l}</option>`).join('');
  return `<div class="om-tache-row" data-ri="${i}" style="display:grid;grid-template-columns:2fr 1fr 1fr 60px 28px;gap:6px;margin-bottom:6px;align-items:center;">
    <input class="finp om-tache-titre" style="height:28px;font-size:11px;padding:3px 8px;" placeholder="Description de la tâche…" value="${t?t.titre||'':''}">
    <select class="finp om-tache-resp" style="height:28px;font-size:11px;padding:2px 22px 2px 7px;appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 6px center;">
      <option value="">— Responsable —</option>${auds}
    </select>
    <select class="finp om-tache-statut" style="height:28px;font-size:11px;padding:2px 22px 2px 7px;appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 6px center;">
      ${stOpts}
    </select>
    <input class="finp om-tache-date" type="date" style="height:28px;font-size:10px;padding:2px 4px;" value="${t?t.date||'':''}">
    <button type="button" class="btn om-del-tache" style="padding:2px 6px;font-size:12px;color:var(--red);border-color:var(--red-bg);">✕</button>
  </div>`;
}

function CTRL_POINT_ROW(p, i){
  const stOpts=[['todo','⬜ À vérifier'],['ok','✅ Conforme'],['nok','❌ Non conforme'],['na','➖ N/A']].map(([v,l])=>`<option value="${v}"${p&&p.statut===v?' selected':''}>${l}</option>`).join('');
  return `<div class="ctrl-point-row" data-ri="${i}" style="display:grid;grid-template-columns:2fr 1fr 1fr 28px;gap:6px;margin-bottom:6px;align-items:center;">
    <input class="finp ctrl-point-desc" style="height:28px;font-size:11px;padding:3px 8px;" placeholder="Point à contrôler…" value="${p?p.desc||'':''}">
    <input class="finp ctrl-point-critere" style="height:28px;font-size:11px;padding:3px 8px;" placeholder="Critère / référence…" value="${p?p.critere||'':''}">
    <select class="finp ctrl-point-statut" style="height:28px;font-size:11px;padding:2px 22px 2px 7px;appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 6px center;">
      ${stOpts}
    </select>
    <button type="button" class="btn ctrl-del-point" style="padding:2px 6px;font-size:12px;color:var(--red);border-color:var(--red-bg);">✕</button>
  </div>`;
}

function CUSTOM_FIELD_ROW(f, i){
  const type=f?f.type:'text';
  let inputHtml='';
  if(type==='textarea'){
    inputHtml=`<textarea class="finp custom-field-value" rows="2" style="font-size:11px;resize:vertical;height:50px;" placeholder="Valeur…">${f?f.valeur||'':''}</textarea>`;
  } else if(type==='select'){
    const opts=(f&&f.options?f.options:[]).map(op=>`<option value="${op}">${op}</option>`).join('');
    inputHtml=`<div style="display:flex;gap:6px;align-items:center;">
      <select class="finp custom-field-value" style="height:28px;font-size:11px;flex:1;appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 6px center;">
        <option value="">— Sélectionner —</option>${opts}
      </select>
      <input class="finp custom-field-options" style="height:28px;font-size:11px;flex:2;" placeholder="Options séparées par ; (ex: Oui;Non;N/A)" value="${f&&f.options?f.options.join(';'):''}">
    </div>`;
  } else if(type==='date'){
    inputHtml=`<input class="finp custom-field-value" type="date" style="height:28px;font-size:11px;" value="${f?f.valeur||'':''}">`;
  } else if(type==='check'){
    inputHtml=`<div style="display:flex;align-items:center;gap:8px;height:28px;"><input type="checkbox" class="custom-field-value" style="width:16px;height:16px;cursor:pointer;"${f&&f.valeur==='true'?' checked':''}> <span style="font-size:11px;color:var(--text-muted);">Coché = Oui</span></div>`;
  } else {
    inputHtml=`<input class="finp custom-field-value" style="height:28px;font-size:11px;" placeholder="Valeur…" value="${f?f.valeur||'':''}">`;
  }
  return `<div class="custom-field-row" data-type="${type}" data-ri="${i}" style="background:var(--surface);border:1px solid var(--border);border-radius:4px;padding:8px 10px;">
    <div style="display:flex;gap:6px;margin-bottom:6px;align-items:center;">
      <span style="font-size:10px;padding:2px 7px;border-radius:10px;background:${type==='textarea'?'#dbeafe':type==='select'?'#f3e8ff':type==='date'?'#dcfce7':type==='check'?'#fef9c3':'#f1f5f9'};color:var(--text-muted);font-weight:600;">${type==='textarea'?'§ Paragraphe':type==='select'?'▾ Liste':type==='date'?'📅 Date':type==='check'?'☑ Case':'T Texte'}</span>
      <input class="finp custom-field-label" style="height:26px;font-size:11px;flex:1;" placeholder="Libellé du champ…" value="${f?f.label||'':''}">
      <label style="font-size:10px;color:var(--text-muted);display:flex;align-items:center;gap:4px;cursor:pointer;"><input type="checkbox" class="custom-field-required"${f&&f.required?' checked':''}> Obligatoire</label>
      <button type="button" class="btn custom-del-field" style="padding:2px 6px;font-size:12px;color:var(--red);border-color:var(--red-bg);">✕</button>
    </div>
    <div class="custom-field-input-wrap">${inputHtml}</div>
  </div>`;
}

function readOMTaches(){
  const rows=[];
  $('#om-taches-rows .om-tache-row').each(function(){
    const titre=$(this).find('.om-tache-titre').val().trim();
    if(titre) rows.push({titre,responsable:$(this).find('.om-tache-resp').val(),statut:$(this).find('.om-tache-statut').val()||'todo',date:$(this).find('.om-tache-date').val()});
  });
  return rows;
}

function OM_MEMBRE_ROW(m, i){
  const auds=AUDITEURS.map(a=>`<option value="${a.prenom+' '+a.nom}"${m&&m.nom===a.prenom+' '+a.nom?' selected':''}>${a.prenom} ${a.nom}</option>`).join('');
  return `<div class="om-membre-row" data-ri="${i}" style="display:grid;grid-template-columns:1fr 1fr 36px;gap:8px;margin-bottom:6px;align-items:center;">
    <select class="finp om-membre-nom" style="height:28px;font-size:11px;padding:2px 22px 2px 7px;appearance:none;background-image:${_SA};background-repeat:no-repeat;background-position:right 6px center;">
      <option value="">— Auditeur —</option>${auds}
    </select>
    <input class="finp om-membre-role" style="height:28px;font-size:11px;padding:3px 8px;" placeholder="Rôle (ex: Auditeur, Expert…)" value="${m&&m.role?m.role:''}">
    <button type="button" class="btn om-del-membre" style="padding:2px 6px;font-size:12px;color:var(--red);border-color:var(--red-bg);">✕</button>
  </div>`;
}

function readOMEquipe(){
  const rows=[];
  $('#om-equipe-rows .om-membre-row').each(function(){
    const nom=$(this).find('.om-membre-nom').val();
    const role=$(this).find('.om-membre-role').val();
    if(nom) rows.push({nom,role});
  });
  return rows;
}

function openOMForm(idx){
  const isEdit=idx>=0;
  const o=isEdit?ORDRES_MISSION[idx]:null;
  openModal(isEdit?'✏️ Modifier l\'Ordre de Mission':'📄 Nouvel Ordre de Mission', OM_FORM(o));
  $('.modal').css('width','860px');
  $('#msave').text(isEdit?'Enregistrer':'Créer l\'Ordre').data('mode','om-save').data('idx',isEdit?idx:-1);

  $(document).on('click.omtab','.om-tab',function(){
    $('.om-tab').each(function(){
      $(this).css({'border-bottom-color':'transparent','color':'var(--text-muted)'});
    });
    $(this).css({'border-bottom-color':'var(--accent)','color':'var(--accent)'});
    const tab=$(this).data('tab');
    $('.om-tab-pane').hide();
    $('#'+tab).show();
  });

  $(document).on('click.omaddmembre','#om-add-membre',function(){
    const n=$('#om-equipe-rows .om-membre-row').length;
    $('#om-equipe-rows').append(OM_MEMBRE_ROW(null,n));
  });
  $(document).on('click.omdelmembre','.om-del-membre',function(){
    const $rows=$('#om-equipe-rows .om-membre-row');
    if($rows.length<=1){$(this).closest('.om-membre-row').find('select').val('');$(this).closest('.om-membre-row').find('input').val('');return;}
    $(this).closest('.om-membre-row').remove();
  });
  $(document).on('click.omaddtache','#om-add-tache',function(){
    const n=$('#om-taches-rows .om-tache-row').length;
    $('#om-taches-rows').append(OM_TACHE_ROW(null,n));
  });
  $(document).on('click.omdeltache','.om-del-tache',function(){
    const $rows=$('#om-taches-rows .om-tache-row');
    if($rows.length<=1){$(this).closest('.om-tache-row').find('input').val('');$(this).closest('.om-tache-row').find('select').val('');return;}
    $(this).closest('.om-tache-row').remove();
  });

  $(document).on('click.ctrladdpoint','#ctrl-add-point',function(){
    const n=$('#ctrl-points-rows .ctrl-point-row').length;
    $('#ctrl-points-rows').append(CTRL_POINT_ROW(null,n));
  });
  $(document).on('click.ctrldelpoint','.ctrl-del-point',function(){
    const $rows=$('#ctrl-points-rows .ctrl-point-row');
    if($rows.length<=1){$(this).closest('.ctrl-point-row').find('input').val('');$(this).closest('.ctrl-point-row').find('select').val('');return;}
    $(this).closest('.ctrl-point-row').remove();
  });

  function addCustomField(type){
    const placeholder=$('#custom-fields-rows > div[style*="dashed"]');
    if(placeholder.length) placeholder.remove();
    const n=$('#custom-fields-rows .custom-field-row').length;
    $('#custom-fields-rows').append(CUSTOM_FIELD_ROW({type,label:'',valeur:'',options:[]},n));
    // Si select, re-bind options live update
    _bindSelectOptions();
  }
  function _bindSelectOptions(){
    $(document).off('input.customopts').on('input.customopts','.custom-field-options',function(){
      const opts=$(this).val().split(';').map(s=>s.trim()).filter(Boolean);
      const $sel=$(this).closest('.custom-field-input-wrap').find('.custom-field-value');
      const cur=$sel.val();
      $sel.html('<option value="">— Sélectionner —</option>'+opts.map(op=>`<option value="${op}"${op===cur?' selected':''}>${op}</option>`).join(''));
    });
  }
  _bindSelectOptions();
  $(document).on('click.customaddtext','#custom-add-text',function(){ addCustomField('text'); });
  $(document).on('click.customaddtextarea','#custom-add-textarea',function(){ addCustomField('textarea'); });
  $(document).on('click.customaddselect','#custom-add-select',function(){ addCustomField('select'); });
  $(document).on('click.customadddate','#custom-add-date',function(){ addCustomField('date'); });
  $(document).on('click.customaddcheck','#custom-add-check',function(){ addCustomField('check'); });
  $(document).on('click.customdelfield','.custom-del-field',function(){
    $(this).closest('.custom-field-row').remove();
    if(!$('#custom-fields-rows .custom-field-row').length){
      $('#custom-fields-rows').html('<div style="text-align:center;color:var(--text-muted);font-size:11px;padding:20px 0;border:1px dashed var(--border);border-radius:4px;">Ajoutez des champs en cliquant sur les boutons ci-dessus</div>');
    }
  });
}

function readCtrlPoints(){
  const rows=[];
  $('#ctrl-points-rows .ctrl-point-row').each(function(){
    const desc=$(this).find('.ctrl-point-desc').val().trim();
    if(desc) rows.push({desc,critere:$(this).find('.ctrl-point-critere').val().trim(),statut:$(this).find('.ctrl-point-statut').val()||'todo'});
  });
  return rows;
}

function readCustomFields(){
  const fields=[];
  $('#custom-fields-rows .custom-field-row').each(function(){
    const type=$(this).data('type')||'text';
    const label=$(this).find('.custom-field-label').val().trim();
    if(!label) return;
    const $val=$(this).find('.custom-field-value');
    let valeur=type==='check'?String($val.prop('checked')):$val.val()||'';
    const options=type==='select'?$(this).find('.custom-field-options').val().split(';').map(s=>s.trim()).filter(Boolean):[];
    const required=$(this).find('.custom-field-required').prop('checked');
    fields.push({type,label,valeur,options,required});
  });
  return fields;
}

function saveOM(idx){
  const ref=$('#om-ref').val().trim();
  const societe=$('#om-societe').val();
  const objet=$('#om-objet').val().trim();
  if(!ref||!societe||!objet){toast('error','!','Référence, Société et Objet sont obligatoires.');return;}
  const obj={
    id: idx>=0?ORDRES_MISSION[idx].id:('OM-'+(Date.now()%1000000)),
    ref, societe, objet,
    dateEmission:$('#om-date-emission').val(),
    statut:$('#om-statut').val()||'planned',
    objectifs:$('#om-objectifs').val().trim(),
    perimetre:$('#om-perimetre').val().trim(),
    referentiel:$('#om-referentiel').val().trim(),
    travaux:$('#om-travaux').val().trim(),
    dateDebut:$('#om-date-debut').val(),
    dateFin:$('#om-date-fin').val(),
    duree:$('#om-duree').val()||'',
    lieu:$('#om-lieu').val().trim(),
    chefMission:$('#om-chef').val(),
    signataire:$('#om-signataire').val().trim(),
    equipe:readOMEquipe(),
    notes:$('#om-notes').val().trim(),
    typeControle:$('#om-type-controle').val()||'',
    risqueNiveau:$('#om-risque-niveau').val()||'',
    risquesCibles:$('#om-risques-cibles').val().trim(),
    assertions:$('#om-assertions').val().trim(),
    methode:$('#om-methode').val().trim(),
    taches:readOMTaches(),
    noteGlobale:$('#om-note-globale').val()||'',
    dateCloture:$('#om-date-cloture').val()||'',
    constatations:$('#om-constatations').val().trim(),
    recommandationsOM:$('#om-recommandations-om').val().trim(),
    conclusion:$('#om-conclusion').val().trim(),

    ctrlRef:$('#ctrl-ref').val().trim(),
    ctrlDateEmission:$('#ctrl-date-emission').val(),
    ctrlSociete:$('#ctrl-societe').val(),
    ctrlType:$('#ctrl-type').val()||'',
    ctrlFrequence:$('#ctrl-frequence').val()||'',
    ctrlStatut:$('#ctrl-statut').val()||'planned',
    ctrlObjet:$('#ctrl-objet').val().trim(),
    ctrlDomaines:$('#ctrl-domaines').val().trim(),
    ctrlRisque:$('#ctrl-risque').val()||'',
    ctrlReferentiel:$('#ctrl-referentiel').val().trim(),
    ctrlCriteres:$('#ctrl-criteres').val().trim(),
    ctrlResponsable:$('#ctrl-responsable').val(),
    ctrlControleurs:$('#ctrl-controleurs').val().trim(),
    ctrlSignataire:$('#ctrl-signataire').val().trim(),
    ctrlInterlocuteur:$('#ctrl-interlocuteur').val().trim(),
    ctrlDateDebut:$('#ctrl-date-debut').val(),
    ctrlDateFin:$('#ctrl-date-fin').val(),
    ctrlDuree:$('#ctrl-duree').val()||'',
    ctrlMethode:$('#ctrl-methode').val()||'',
    ctrlEchantillon:$('#ctrl-echantillon').val().trim(),
    ctrlPeriode:$('#ctrl-periode').val().trim(),
    ctrlPoints:readCtrlPoints(),
    ctrlConclusionNiveau:$('#ctrl-conclusion-niveau').val()||'',
    ctrlDateCloture:$('#ctrl-date-cloture').val()||'',
    ctrlEcarts:$('#ctrl-ecarts').val().trim(),
    ctrlMesures:$('#ctrl-mesures').val().trim(),
    ctrlSynthese:$('#ctrl-synthese').val().trim(),

    customTitre:$('#custom-titre').val().trim(),
    customIcone:$('#custom-icone').val().trim()||'📝',
    customCouleur:$('#custom-couleur').val()||'#1e3a5f',
    customSociete:$('#custom-societe').val(),
    customDescription:$('#custom-description').val().trim(),
    champPersonnalises:readCustomFields(),
    customSign1Label:$('#custom-sign1-label').val().trim(),
    customSign1Nom:$('#custom-sign1-nom').val().trim(),
    customSign2Label:$('#custom-sign2-label').val().trim(),
    customSign2Nom:$('#custom-sign2-nom').val().trim(),
    createdAt: idx>=0?ORDRES_MISSION[idx].createdAt:new Date().toISOString().slice(0,10)
  };
  if(idx>=0) ORDRES_MISSION[idx]=obj;
  else ORDRES_MISSION.unshift(obj);
  $(document).off('click.omaddmembre click.omdelmembre click.omtab click.ctrladdpoint click.ctrldelpoint click.customaddtext click.customaddtextarea click.customaddselect click.customadddate click.customaddcheck click.customdelfield input.customopts');
  $('.modal').css('width','');
  closeModal();
  dbSaveOM();
  renderOM();
  toast('success','📄',idx>=0?'Ordre de Mission mis à jour':'Ordre de Mission créé — '+ref);
}

function buildOMDoc(o){
  const stLabel={planned:'Planifié',inprogress:'En cours',done:'Terminé'};
  const stCls={planned:'om-badge-planned',inprogress:'om-badge-inprogress',done:'om-badge-done'};
  const societeObj=SOCIETES.find(s=>s.nom===o.societe)||{};
  const chefObj=AUDITEURS.find(a=>a.prenom+' '+a.nom===o.chefMission)||{};

  const objetifsHTML=(o.objectifs||'')
    .split('\n').filter(l=>l.trim())
    .map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('')
    ||'<li>—</li>';

  const travauxHTML=(o.travaux||'')
    .split('\n').filter(l=>l.trim())
    .map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('')
    ||'<li>—</li>';

  const equipeRows=(o.equipe||[]).map((m,i)=>`
    <tr>
      <td>${i+1}</td>
      <td><strong>${m.nom}</strong></td>
      <td>${m.role||'Auditeur'}</td>
      <td class="t-center">✓</td>
      <td></td>
    </tr>`).join('') || '<tr><td colspan="5" style="text-align:center;color:#94a3b8;">Aucun membre renseigné</td></tr>';

  return `
<div class="om-doc">

  ${_buildPrintHeader({ ref: o.ref||'—', date: o.dateEmission||'—', subtitle: 'Ordre de Mission', societeNom: o.societe||'' })}

  <div class="om-header">
    <div class="om-header-left">
      <div style="font-size:9pt;opacity:.8;margin-bottom:4px;">DIRECTION AUDIT &amp; CONTRÔLE</div>
      <div class="om-header-title">ORDRE DE MISSION</div>
      <div class="om-header-sub">${o.objet||'Mission d\'audit'}</div>
      <div class="om-header-ref">${o.ref||'—'}</div>
    </div>
    <div style="text-align:right;">
      <div class="om-header-logo">DAC</div>
      <div style="font-size:9pt;opacity:.75;margin-top:4px;">Émis le ${o.dateEmission||'—'}</div>
      <span class="om-badge ${stCls[o.statut]||'om-badge-planned'}" style="margin-top:6px;display:inline-block;">${stLabel[o.statut]||'Planifié'}</span>
    </div>
  </div>

  <div class="om-body">

    <div class="om-section-title">1. Entité auditée</div>
    <div class="om-grid">
      <div class="om-field"><div class="om-label">Société / Filiale</div><div class="om-value">${o.societe||'—'}</div></div>
      <div class="om-field"><div class="om-label">Secteur d'activité</div><div class="om-value">${societeObj.secteur||'—'}</div></div>
      <div class="om-field"><div class="om-label">Lieu de mission</div><div class="om-value">${o.lieu||'—'}</div></div>
      <div class="om-field"><div class="om-label">Pays</div><div class="om-value">${societeObj.pays||'—'}</div></div>
    </div>

    <div class="om-section-title">2. Objet &amp; Périmètre de la mission</div>
    <div class="om-field" style="margin-bottom:10px;"><div class="om-label">Périmètre / Cycle audité</div><div class="om-value">${o.perimetre||'—'}</div></div>
    <div class="om-field" style="margin-bottom:10px;"><div class="om-label">Référentiel appliqué</div><div class="om-value">${o.referentiel||'—'}</div></div>
    <div style="margin-bottom:10px;"><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Objectifs de la mission</div>
      <ul class="om-obj-list">${objetifsHTML}</ul></div>
    <div><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Travaux à réaliser</div>
      <ul class="om-obj-list">${travauxHTML}</ul></div>

    <div class="om-section-title">3. Calendrier</div>
    <div class="om-grid">
      <div class="om-field"><div class="om-label">Date de début</div><div class="om-value">${o.dateDebut||'—'}</div></div>
      <div class="om-field"><div class="om-label">Date de fin prévue</div><div class="om-value">${o.dateFin||'—'}</div></div>
      <div class="om-field"><div class="om-label">Durée estimée</div><div class="om-value">${o.duree?o.duree+' jour(s)':'—'}</div></div>
      <div class="om-field"><div class="om-label">Date d'émission</div><div class="om-value">${o.dateEmission||'—'}</div></div>
    </div>

    <div class="om-section-title">4. Équipe de mission</div>
    <div class="om-field" style="margin-bottom:8px;"><div class="om-label">Chef de mission</div><div class="om-value"><strong>${o.chefMission||'—'}</strong>${chefObj.role?' — '+chefObj.role:''}</div></div>
    <table class="om-team-table">
      <thead><tr>
        <th style="width:30px;">N°</th>
        <th>Nom &amp; Prénom</th>
        <th>Rôle dans la mission</th>
        <th style="width:60px;text-align:center;">Habilité</th>
        <th style="width:90px;text-align:center;">Signature</th>
      </tr></thead>
      <tbody>${equipeRows}</tbody>
    </table>

    ${o.notes?`<div class="om-section-title">5. Instructions &amp; Confidentialité</div>
    <div style="background:#fef9e7;border:1px solid #f0c040;border-radius:4px;padding:10px 12px;font-size:10pt;line-height:1.6;color:#7a5c00;">${o.notes}</div>`:''}

    ${(o.typeControle||o.risqueNiveau||o.risquesCibles)?`
    <div class="om-section-title">5. Mission de Contrôle</div>
    <div class="om-grid">
      ${o.typeControle?`<div class="om-field"><div class="om-label">Type de contrôle</div><div class="om-value">${o.typeControle}</div></div>`:''}
      ${o.risqueNiveau?`<div class="om-field"><div class="om-label">Niveau de risque</div><div class="om-value">${{critical:'🔴 Critique',high:'🟠 Élevé',medium:'🟡 Moyen',low:'🟢 Faible'}[o.risqueNiveau]||o.risqueNiveau}</div></div>`:''}
    </div>
    ${o.risquesCibles?`<div class="om-field" style="margin-bottom:8px;"><div class="om-label">Risques ciblés</div><div class="om-value">${o.risquesCibles}</div></div>`:''}
    ${o.assertions?`<div class="om-field" style="margin-bottom:8px;"><div class="om-label">Assertions</div><div class="om-value">${o.assertions}</div></div>`:''}
    ${o.methode?`<div class="om-field"><div class="om-label">Approche méthodologique</div><div class="om-value">${o.methode}</div></div>`:''}
    `:''}

    ${(o.taches&&o.taches.length)?`
    <div class="om-section-title">6. Tâches de la Mission</div>
    <table class="om-team-table">
      <thead><tr>
        <th style="width:30px;">N°</th>
        <th>Tâche</th>
        <th style="width:120px;">Responsable</th>
        <th style="width:80px;text-align:center;">Statut</th>
        <th style="width:80px;text-align:center;">Date</th>
      </tr></thead>
      <tbody>${o.taches.map((t,i)=>`<tr>
        <td class="t-center">${i+1}</td>
        <td>${t.titre||'—'}</td>
        <td>${t.responsable||'—'}</td>
        <td class="t-center">${{todo:'⬜ À faire',inprogress:'🔄 En cours',done:'✅ Terminé',blocked:'🚫 Bloqué'}[t.statut]||t.statut||'—'}</td>
        <td style="text-align:center;font-family:monospace;font-size:9pt;">${t.date||'—'}</td>
      </tr>`).join('')}</tbody>
    </table>
    `:''}

    ${(o.noteGlobale||o.constatations||o.recommandationsOM||o.conclusion)?`
    <div class="om-section-title">7. Résultats &amp; Conclusions</div>
    ${o.noteGlobale?`<div class="om-field" style="margin-bottom:8px;"><div class="om-label">Appréciation globale</div>
      <div class="om-value" style="font-weight:700;font-size:11pt;">${{satisfaisant:'✅ Satisfaisant',partiellement:'⚠️ Partiellement satisfaisant',insuffisant:'❌ Insuffisant',critique:'🚨 Critique'}[o.noteGlobale]||o.noteGlobale}</div></div>`:''}
    ${o.dateCloture?`<div class="om-field" style="margin-bottom:8px;"><div class="om-label">Date de clôture</div><div class="om-value">${o.dateCloture}</div></div>`:''}
    ${o.constatations?`<div style="margin-bottom:10px;"><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Principales constatations</div>
      <ul class="om-obj-list">${o.constatations.split('\n').filter(l=>l.trim()).map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('')||'<li>—</li>'}</ul></div>`:''}
    ${o.recommandationsOM?`<div style="margin-bottom:10px;"><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Recommandations principales</div>
      <ul class="om-obj-list">${o.recommandationsOM.split('\n').filter(l=>l.trim()).map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('')||'<li>—</li>'}</ul></div>`:''}
    ${o.conclusion?`<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:4px;padding:10px 12px;font-size:10pt;color:#166534;line-height:1.6;">${o.conclusion}</div>`:''}
    `:''}

    <div class="om-section-title">${[o.typeControle,o.taches&&o.taches.length,o.noteGlobale].filter(Boolean).length>0?'8':'5'}. Signatures &amp; Approbations</div>
    <div class="om-sign-grid">
      <div class="om-sign-box">
        <div class="om-label">Chef de mission</div>
        <div class="om-sign-line"></div>
        <div class="om-sign-name">${o.chefMission||'____________________'}</div>
        <div class="om-sign-name" style="margin-top:2px;font-size:8pt;">Date : ___________</div>
      </div>
      <div class="om-sign-box">
        <div class="om-label">Directeur Audit / Signataire</div>
        <div class="om-sign-line"></div>
        <div class="om-sign-name">${o.signataire||'____________________'}</div>
        <div class="om-sign-name" style="margin-top:2px;font-size:8pt;">Date : ___________</div>
      </div>
    </div>

    <div class="om-sign-grid" style="margin-top:12px;">
      <div class="om-sign-box" style="grid-column:1/-1;">
        <div class="om-label">Accusé de réception — Responsable de l'entité auditée</div>
        <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin-top:8px;">
          <div><div style="font-size:8pt;color:#94a3b8;">Nom &amp; Prénom</div><div class="om-sign-line"></div></div>
          <div><div style="font-size:8pt;color:#94a3b8;">Fonction</div><div class="om-sign-line"></div></div>
          <div><div style="font-size:8pt;color:#94a3b8;">Date &amp; Signature</div><div class="om-sign-line"></div></div>
        </div>
      </div>
    </div>

  </div>

  <div class="om-footer">
    <div>Direction Audit &amp; Contrôle Interne — Document confidentiel</div>
    <div>Réf. ${o.ref||'—'} · Émis le ${o.dateEmission||'—'}</div>
    <div>Page 1/1</div>
  </div>

</div>`;
}

// ── Impression ──────────────────────────────────────────────────
function buildOMDocControle(o){
  if(!o.ctrlObjet&&!o.ctrlRef) return '';
  const stLabelC={planned:'Planifié',inprogress:'En cours',done:'Terminé',suspended:'Suspendu'};
  const stClsC={planned:'om-badge-planned',inprogress:'om-badge-inprogress',done:'om-badge-done',suspended:'om-badge-planned'};
  const risqLbl={critical:'🔴 Critique',high:'🟠 Élevé',medium:'🟡 Moyen',low:'🟢 Faible'};
  const conclusionLbl={conforme:'✅ Conforme',partiellement:'⚠️ Partiellement conforme','non-conforme':'❌ Non conforme',critique:'🚨 Non-conformité critique'};
  const domainesHTML=(o.ctrlDomaines||'').split('\n').filter(l=>l.trim()).map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('')||'<li>—</li>';
  const criteresHTML=(o.ctrlCriteres||'').split('\n').filter(l=>l.trim()).map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('')||'<li>—</li>';
  const ecartsHTML=(o.ctrlEcarts||'').split('\n').filter(l=>l.trim()).map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('');
  const mesuresHTML=(o.ctrlMesures||'').split('\n').filter(l=>l.trim()).map(l=>`<li>${l.replace(/^[-•]\s*/,'')}</li>`).join('');
  return `
<div class="om-doc" style="margin-top:24px;page-break-before:always;">
  ${_buildPrintHeader({ ref: o.ctrlRef||'—', date: o.ctrlDateEmission||'—', subtitle: 'Mission de Contrôle', societeNom: o.ctrlSociete||o.societe||'' })}
  <div class="om-header" style="background:linear-gradient(135deg,#6941c6 0%,#4e32a8 100%);">
    <div class="om-header-left">
      <div style="font-size:9pt;opacity:.8;margin-bottom:4px;">DIRECTION AUDIT &amp; CONTRÔLE</div>
      <div class="om-header-title">MISSION DE CONTRÔLE</div>
      <div class="om-header-sub">${o.ctrlObjet||'Contrôle interne'}</div>
      <div class="om-header-ref">${o.ctrlRef||'—'}</div>
    </div>
    <div style="text-align:right;">
      <div class="om-header-logo" style="background:rgba(255,255,255,.15);">CTR</div>
      <div style="font-size:9pt;opacity:.75;margin-top:4px;">Émis le ${o.ctrlDateEmission||'—'}</div>
      <span class="om-badge ${stClsC[o.ctrlStatut]||'om-badge-planned'}" style="margin-top:6px;display:inline-block;">${stLabelC[o.ctrlStatut]||'Planifié'}</span>
    </div>
  </div>
  <div class="om-body">
    <div class="om-section-title">1. Identification du Contrôle</div>
    <div class="om-grid">
      <div class="om-field"><div class="om-label">Entité contrôlée</div><div class="om-value">${o.ctrlSociete||'—'}</div></div>
      <div class="om-field"><div class="om-label">Type de contrôle</div><div class="om-value">${o.ctrlType||'—'}</div></div>
      <div class="om-field"><div class="om-label">Fréquence</div><div class="om-value">${o.ctrlFrequence||'—'}</div></div>
      <div class="om-field"><div class="om-label">Période couverte</div><div class="om-value">${o.ctrlPeriode||'—'}</div></div>
    </div>

    <div class="om-section-title">2. Objet, Domaines &amp; Critères</div>
    <div class="om-field" style="margin-bottom:10px;"><div class="om-label">Référentiel / Base légale</div><div class="om-value">${o.ctrlReferentiel||'—'}</div></div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:10px;">
      <div><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Domaines à contrôler</div><ul class="om-obj-list">${domainesHTML}</ul></div>
      <div><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Critères de contrôle</div><ul class="om-obj-list">${criteresHTML}</ul></div>
    </div>
    <div class="om-grid">
      <div class="om-field"><div class="om-label">Niveau de risque inhérent</div><div class="om-value">${risqLbl[o.ctrlRisque]||'Non évalué'}</div></div>
      <div class="om-field"><div class="om-label">Méthode</div><div class="om-value">${o.ctrlMethode||'—'}</div></div>
      <div class="om-field"><div class="om-label">Échantillon</div><div class="om-value">${o.ctrlEchantillon||'—'}</div></div>
    </div>

    <div class="om-section-title">3. Équipe de Contrôle</div>
    <div class="om-grid">
      <div class="om-field"><div class="om-label">Responsable du contrôle</div><div class="om-value"><strong>${o.ctrlResponsable||'—'}</strong></div></div>
      <div class="om-field"><div class="om-label">Contrôleurs associés</div><div class="om-value">${o.ctrlControleurs||'—'}</div></div>
      <div class="om-field"><div class="om-label">Interlocuteur entité</div><div class="om-value">${o.ctrlInterlocuteur||'—'}</div></div>
      <div class="om-field"><div class="om-label">Validateur / Signataire</div><div class="om-value">${o.ctrlSignataire||'—'}</div></div>
    </div>

    <div class="om-section-title">4. Calendrier</div>
    <div class="om-grid">
      <div class="om-field"><div class="om-label">Date de début</div><div class="om-value">${o.ctrlDateDebut||'—'}</div></div>
      <div class="om-field"><div class="om-label">Date de fin prévue</div><div class="om-value">${o.ctrlDateFin||'—'}</div></div>
      <div class="om-field"><div class="om-label">Durée estimée</div><div class="om-value">${o.ctrlDuree?o.ctrlDuree+' jour(s)':'—'}</div></div>
    </div>

    ${o.ctrlPoints&&o.ctrlPoints.length?`
    <div class="om-section-title">5. Points de Contrôle</div>
    <table><thead><tr>
      <th style="width:30px;">N°</th>
      <th>Point à contrôler</th>
      <th style="width:25%;">Critère / Référence</th>
      <th style="width:80px;text-align:center;">Résultat</th>
    </tr></thead><tbody>${o.ctrlPoints.map((p,i)=>`<tr>
      <td class="t-center">${i+1}</td>
      <td>${p.desc||'—'}</td>
      <td>${p.critere||'—'}</td>
      <td class="t-center">${{todo:'⬜',ok:'✅',nok:'❌',na:'➖'}[p.statut]||'⬜'} ${{todo:'À vérifier',ok:'Conforme',nok:'Non conforme',na:'N/A'}[p.statut]||''}</td>
    </tr>`).join('')}</tbody></table>`:''}

    ${(o.ctrlConclusionNiveau||o.ctrlEcarts||o.ctrlMesures||o.ctrlSynthese)?`
    <div class="om-section-title">6. Résultats du Contrôle</div>
    ${o.ctrlConclusionNiveau?`<div class="om-field" style="margin-bottom:10px;"><div class="om-label">Conclusion</div><div class="om-value" style="font-weight:700;font-size:11pt;">${conclusionLbl[o.ctrlConclusionNiveau]||o.ctrlConclusionNiveau}</div></div>`:''}
    ${o.ctrlDateCloture?`<div class="om-field" style="margin-bottom:10px;"><div class="om-label">Date de clôture</div><div class="om-value">${o.ctrlDateCloture}</div></div>`:''}
    ${ecartsHTML?`<div style="margin-bottom:10px;"><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Écarts / Anomalies</div><ul class="om-obj-list">${ecartsHTML}</ul></div>`:''}
    ${mesuresHTML?`<div style="margin-bottom:10px;"><div class="om-label" style="font-size:8pt;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:.05em;margin-bottom:4px;">Mesures correctives</div><ul class="om-obj-list">${mesuresHTML}</ul></div>`:''}
    ${o.ctrlSynthese?`<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:4px;padding:10px 12px;font-size:10pt;color:#166534;line-height:1.6;">${o.ctrlSynthese}</div>`:''}
    `:''}

    <div class="om-section-title">7. Signatures</div>
    <div class="om-sign-grid">
      <div class="om-sign-box"><div class="om-label">Responsable du contrôle</div><div class="om-sign-line"></div><div class="om-sign-name">${o.ctrlResponsable||'____________________'}</div><div class="om-sign-name" style="margin-top:2px;font-size:8pt;">Date : ___________</div></div>
      <div class="om-sign-box"><div class="om-label">Validateur / Signataire</div><div class="om-sign-line"></div><div class="om-sign-name">${o.ctrlSignataire||'____________________'}</div><div class="om-sign-name" style="margin-top:2px;font-size:8pt;">Date : ___________</div></div>
    </div>
  </div>
  <div class="om-footer">
    <div>Direction Audit &amp; Contrôle Interne — Document confidentiel</div>
    <div>Réf. ${o.ctrlRef||'—'} · Émis le ${o.ctrlDateEmission||'—'}</div>
    <div>Page 1/1</div>
  </div>
</div>`;
}

function buildOMDocCustom(o){
  if(!o.customTitre&&!(o.champPersonnalises&&o.champPersonnalises.length)) return '';
  const couleur=o.customCouleur||'#1e3a5f';
  const icone=o.customIcone||'📝';
  const champs=o.champPersonnalises||[];
  const champsHTML=champs.map((f,i)=>{
    let valHtml='';
    if(f.type==='check') valHtml=f.valeur==='true'?'<span style="color:#1a8a4a;font-weight:700;">☑ Oui</span>':'<span style="color:#64748b;">☐ Non</span>';
    else valHtml=f.valeur||'<span style="color:#94a3b8;">—</span>';
    return `<div class="om-field" style="margin-bottom:10px;"><div class="om-label">${f.label||'Champ '+(i+1)}${f.required?' <span class="t-red">*</span>':''}</div><div class="om-value">${valHtml}</div></div>`;
  }).join('');
  return `
<div class="om-doc" style="margin-top:24px;page-break-before:always;">
  ${_buildPrintHeader({ subtitle: (o.customTitre||'Formulaire Personnalisé'), societeNom: o.customSociete||o.societe||'' })}
  <div class="om-header" style="background:linear-gradient(135deg,${couleur} 0%,${couleur}cc 100%);">
    <div class="om-header-left">
      <div style="font-size:9pt;opacity:.8;margin-bottom:4px;">DIRECTION AUDIT &amp; CONTRÔLE</div>
      <div class="om-header-title">${icone} ${(o.customTitre||'Formulaire personnalisé').toUpperCase()}</div>
      <div class="om-header-sub">${o.customSociete||''}</div>
    </div>
    <div style="text-align:right;">
      <div class="om-header-logo" style="background:rgba(255,255,255,.15);font-size:22px;">${icone}</div>
      <div style="font-size:9pt;opacity:.75;margin-top:4px;">${new Date().toLocaleDateString('fr-FR')}</div>
    </div>
  </div>
  <div class="om-body">
    ${o.customDescription?`<div style="background:#fef9e7;border:1px solid #f0c040;border-radius:4px;padding:10px 12px;font-size:10pt;line-height:1.6;color:#7a5c00;margin-bottom:16px;">${o.customDescription}</div>`:''}
    ${champsHTML||'<div style="text-align:center;color:#94a3b8;padding:20px;">Aucun champ renseigné</div>'}
    <div class="om-section-title">Signatures</div>
    <div class="om-sign-grid">
      <div class="om-sign-box"><div class="om-label">${o.customSign1Label||'Responsable'}</div><div class="om-sign-line"></div><div class="om-sign-name">${o.customSign1Nom||'____________________'}</div><div class="om-sign-name" style="margin-top:2px;font-size:8pt;">Date : ___________</div></div>
      <div class="om-sign-box"><div class="om-label">${o.customSign2Label||'Validateur'}</div><div class="om-sign-line"></div><div class="om-sign-name">${o.customSign2Nom||'____________________'}</div><div class="om-sign-name" style="margin-top:2px;font-size:8pt;">Date : ___________</div></div>
    </div>
  </div>
  <div class="om-footer">
    <div>Direction Audit &amp; Contrôle Interne — Document confidentiel</div>
    <div>${o.customTitre||'Formulaire personnalisé'} · ${o.customSociete||'—'}</div>
    <div>Page 1/1</div>
  </div>
</div>`;
}

function printOM(o){
  const allDocs=buildOMDoc(o)+buildOMDocControle(o)+buildOMDocCustom(o);
  $('#om-print-area').html(allDocs).show();
  window.print();
  setTimeout(()=>$('#om-print-area').hide().empty(), 1000);
}

// ── Aperçu dans une fenêtre modale ─────────────────────────────
function previewOM(o){
  const allDocs=buildOMDoc(o)+buildOMDocControle(o)+buildOMDocCustom(o);
  openModal('👁 Aperçu — '+o.ref, `<div style="max-height:70vh;overflow-y:auto;border:1px solid var(--border);border-radius:4px;padding:10px;background:#fff;">${allDocs}</div>`);
  $('.modal').css('width','860px');
  $('#msave').text('🖨️ Imprimer').data('mode','om-preview-print').data('omref', ORDRES_MISSION.indexOf(o));
}

