});

// ═══════════════════════════════════════════════════════════════
// RÉCAPITULATIF RECOMMANDATIONS
// ═══════════════════════════════════════════════════════════════

/* ── Calcul du statut effectif d'une recommandation ──────────────────────────
   Règles métier :
   1. Clos                → r.statut === 'fully'  OU  appreciation_preuve = "Satisfaisant"
   2. Dossier à suivre   → appreciation_preuve contient "partiellement"  (Partiellement Satisfaisant)
   3. Échu               → date échéance ≤ aujourd'hui  (et pas Clos, pas Dossier à suivre)
   4. Non échue          → date échéance > aujourd'hui  (et pas Clos, pas Dossier à suivre)
   5. Fallback           → partially (Dossier à suivre sans date)
   ──────────────────────────────────────────────────────────────────────────── */
function computeStatutEffectif(r, today) {
  var apprRaw  = (r.appreciation_preuve || '').toLowerCase().trim();
  var isSatisf    = apprRaw.includes('satisfaisant') && !apprRaw.includes('pas') && !apprRaw.includes('partiel');
  var isPartiel   = apprRaw.includes('partiel');
  var isPasSatisf = apprRaw.includes('pas');

  // 1. Clos
  if(r.statut === 'fully' || isSatisf) return 'fully';

  // 2. Dossier à suivre (appréciation partiellement satisfaisante)
  if(isPartiel) return 'partially';

  // 3 & 4. Basé sur l'échéance
  var echeRef = r.echeance_revisee || r.echeance;
  if(echeRef) {
    var d = new Date(echeRef); d.setHours(0,0,0,0);
    if(!isNaN(d)) {
      if(d > today)  return 'nonechu';   // Non échue
      else           return 'echu';      // Échu
    }
  }
  // 5. Fallback
  return 'partially';
}

function getAllRecos(filterSociete, filterCriticite, filterStatut, filterCycle, filterResponsable) {
  var today = new Date(); today.setHours(0,0,0,0);
  var rows = [];
  ACTIONS.forEach(function(a) {
    if(filterSociete   && a.societe    !== filterSociete)   return;
    if(filterCriticite && a.criticite  !== filterCriticite) return;
    if(filterCycle     && a.cycle      !== filterCycle)     return;
    var recos = (a.recommandations && a.recommandations.length)
      ? a.recommandations
      : [{id:a.id+'-R1', recommandation:'—', disposition:'—', responsable:'—', echeance:'', statut:'notimplemented', avancement:0}];
    recos.forEach(function(r) {
      var statutEffectif = computeStatutEffectif(r, today);
      if(filterStatut && statutEffectif !== filterStatut) return;
      if(filterResponsable && (r.responsable||'') !== filterResponsable) return;
      rows.push({ action: a, reco: r, statutEffectif: statutEffectif });
    });
  });
  return rows;
}

function renderRecapReco() {
  var filterSociete     = $('#rr-filter-societe').val()     || '';
  var filterCriticite   = $('#rr-filter-criticite').val()   || '';
  var filterStatut      = $('#rr-filter-statut').val()      || '';
  var filterCycle       = $('#rr-filter-cycle').val()       || '';
  var filterResponsable = $('#rr-filter-responsable').val() || '';

  var rows = getAllRecos(filterSociete, filterCriticite, filterStatut, filterCycle, filterResponsable);
  var total   = rows.length;
  var clos    = rows.filter(function(r){ return r.statutEffectif==='fully'; }).length;
  var suivre  = rows.filter(function(r){ return r.statutEffectif==='partially'; }).length;
  var echu    = rows.filter(function(r){ return r.statutEffectif==='echu'; }).length;
  var nonechu = rows.filter(function(r){ return r.statutEffectif==='nonechu'; }).length;
  var txImpl = total > 0 ? Math.round(clos / total * 100) : 0;

  // ── Peupler filtre société (une seule fois) ──
  if($('#rr-filter-societe').find('option').length <= 1) {
    var socs = [];
    ACTIONS.forEach(function(a){ if(a.societe && socs.indexOf(a.societe)<0) socs.push(a.societe); });
    socs.sort().forEach(function(s){ $('#rr-filter-societe').append('<option value="'+s+'">'+s+'</option>'); });
    if(filterSociete) $('#rr-filter-societe').val(filterSociete);
  }

  // ── Peupler filtre cycle (une seule fois) ──
  if($('#rr-filter-cycle').find('option').length <= 1) {
    var cycles = [];
    ACTIONS.forEach(function(a){ if(a.cycle && cycles.indexOf(a.cycle)<0) cycles.push(a.cycle); });
    cycles.sort().forEach(function(c){ $('#rr-filter-cycle').append('<option value="'+c+'">'+c+'</option>'); });
    if(filterCycle) $('#rr-filter-cycle').val(filterCycle);
  }

  // ── Peupler filtre responsable (une seule fois) ──
  if($('#rr-filter-responsable').find('option').length <= 1) {
    var resps = [];
    ACTIONS.forEach(function(a){ (a.recommandations||[]).forEach(function(r){ if(r.responsable && resps.indexOf(r.responsable)<0) resps.push(r.responsable); }); });
    resps.sort().forEach(function(resp){ $('#rr-filter-responsable').append('<option value="'+resp+'">'+resp+'</option>'); });
    if(filterResponsable) $('#rr-filter-responsable').val(filterResponsable);
  }

  // ── Barre globale ──
  var barColor = txImpl>=80?'linear-gradient(90deg,#22c55e,#16a34a)':txImpl>=40?'linear-gradient(90deg,#f59e0b,#d97706)':'linear-gradient(90deg,#f87171,#dc2626)';
  var pctColor = txImpl>=80?'var(--green)':txImpl>=40?'#d97706':'var(--red)';
  $('#rr-global-bar').css({width: txImpl+'%', background: barColor});
  $('#rr-global-pct').text(txImpl+'%').css('color', pctColor);

  // ── Mise à jour en-tête / pied A4 ──
  var now = new Date();
  var dateStr = now.toLocaleDateString('fr-FR',{day:'2-digit',month:'long',year:'numeric'});
  $('#rr-a4-date').text('Édité le '+dateStr);
  $('#rr-a4-footer-date').text('Édité le '+dateStr);
  var filtresActifs = [];
  if(filterSociete) filtresActifs.push('Société : '+filterSociete);
  if(filterCriticite) filtresActifs.push('Criticité : '+filterCriticite);
  if(filterStatut) filtresActifs.push('Statut : '+filterStatut);
  if(filterCycle) filtresActifs.push('Cycle : '+filterCycle);
  if(filterResponsable) filtresActifs.push('Responsable : '+filterResponsable);
  $('#rr-a4-filtres').text(filtresActifs.length ? 'Filtres : '+filtresActifs.join(' · ') : 'Aucun filtre actif');

  // ── Stocker les données KPI pour la reconstruction inline au moment du print ──
  // (placé après barColor/pctColor qui sont nécessaires ici)
  window._rrLastKpi = {
    total:total, clos:clos, suivre:suivre, echu:echu, nonechu:nonechu,
    txImpl:txImpl, listCount: total + ' recommandation' + (total>1?'s':''),
    barColor:barColor, pctColor:pctColor.replace(/var\(--green\)/,'#16a34a').replace(/var\(--red\)/,'#dc2626')
  };

  // ── Donut statut ──
  var donutData = [
    {label:'Clos / Fully Impl.',     v:clos,    c:'#22c55e'},
    {label:'Dossier à suivre',       v:suivre,  c:'#f59e0b'},
    {label:'Échu / Not Impl.',       v:echu,    c:'#db2777'},
    {label:'Non échue',              v:nonechu, c:'#0070f2'},
  ].filter(function(d){ return d.v>0; });

  var svg = document.getElementById('rr-donut-statut');
  if(svg) {
    var cx=70,cy=70,r=52,ri=30;
    var tot = donutData.reduce(function(s,d){ return s+d.v; },0)||1;
    var startAngle = -Math.PI/2, paths = '', labels = '';
    donutData.forEach(function(d){
      var angle = (d.v/tot)*2*Math.PI;
      var endAngle = startAngle+angle;
      // cas 100% : un seul segment = cercle complet
      if(Math.abs(angle - 2*Math.PI) < 0.0001) {
        paths += '<circle cx="'+cx+'" cy="'+cy+'" r="'+r+'" fill="'+d.c+'"/>'
               + '<circle cx="'+cx+'" cy="'+cy+'" r="'+ri+'" fill="var(--surface)"/>';
        var pct = 100;
        labels += '<text x="'+cx+'" y="'+(cy-8)+'" text-anchor="middle" dominant-baseline="middle" font-size="9.5" font-weight="800" fill="#fff" font-family="IBM Plex Mono,monospace">'+pct+'%</text>';
      } else {
        var x1=cx+r*Math.cos(startAngle), y1=cy+r*Math.sin(startAngle);
        var x2=cx+r*Math.cos(endAngle),   y2=cy+r*Math.sin(endAngle);
        var xi1=cx+ri*Math.cos(endAngle), yi1=cy+ri*Math.sin(endAngle);
        var xi2=cx+ri*Math.cos(startAngle), yi2=cy+ri*Math.sin(startAngle);
        var lg = angle>Math.PI?1:0;
        paths += '<path d="M'+x1.toFixed(2)+','+y1.toFixed(2)+' A'+r+','+r+' 0 '+lg+',1 '+x2.toFixed(2)+','+y2.toFixed(2)+' L'+xi1.toFixed(2)+','+yi1.toFixed(2)+' A'+ri+','+ri+' 0 '+lg+',0 '+xi2.toFixed(2)+','+yi2.toFixed(2)+' Z" fill="'+d.c+'" stroke="var(--surface)" stroke-width="2"/>';
        if(angle > 0.25) {
          var midAngle = startAngle + angle/2;
          var lx = cx + (ri+r)/2*Math.cos(midAngle);
          var ly = cy + (ri+r)/2*Math.sin(midAngle);
          var pct = Math.round(d.v/tot*100);
          labels += '<text x="'+lx.toFixed(1)+'" y="'+ly.toFixed(1)+'" text-anchor="middle" dominant-baseline="middle" font-size="9.5" font-weight="800" fill="#fff" font-family="IBM Plex Mono,monospace">'+pct+'%</text>';
        }
      }
      startAngle = endAngle;
    });
    if(!donutData.length) paths='<circle cx="70" cy="70" r="52" fill="var(--surface3)"/><circle cx="70" cy="70" r="30" fill="var(--surface)"/>';
    svg.innerHTML = paths + labels
      +'<text x="70" y="65" text-anchor="middle" font-size="15" font-weight="800" fill="var(--text)" font-family="IBM Plex Mono,monospace">'+total+'</text>'
      +'<text x="70" y="78" text-anchor="middle" font-size="9" fill="var(--text-muted)" font-family="IBM Plex Sans,sans-serif">recos</text>';
    $('#rr-donut-statut-legend').html(donutData.map(function(d){
      var pct = total>0?Math.round(d.v/total*100):0;
      return '<div style="margin-bottom:8px;">'
        +'<div style="display:flex;align-items:center;gap:6px;margin-bottom:3px;">'
        +'<span style="width:10px;height:10px;border-radius:3px;background:'+d.c+';flex-shrink:0;display:inline-block;"></span>'
        +'<span style="font-size:11px;color:var(--text);flex:1;font-weight:500;">'+d.label+'</span>'
        +'<span style="font-size:11px;font-weight:800;font-family:var(--mono);color:'+d.c+';">'+d.v+'</span>'
        +'<span style="font-size:10px;color:var(--text-muted);margin-left:3px;">('+pct+'%)</span>'
        +'</div>'
        +'<div style="height:4px;border-radius:2px;background:var(--surface3);overflow:hidden;">'
        +'<div style="height:4px;width:'+pct+'%;background:'+d.c+';border-radius:2px;transition:width .5s;"></div>'
        +'</div>'
        +'</div>';
    }).join(''));
    if(!donutData.length) $('#rr-donut-statut-legend').html('<div style="font-size:11px;color:var(--text-dim);">Aucune donnée</div>');
  }

  // ── Société · Responsable · Fonction (nav par société) ──
  var respBySoc = {}; // { societe: [{resp, fonc, v}] }
  rows.forEach(function(r){
    var resp = (r.reco && r.reco.responsable) ? r.reco.responsable : '—';
    var soc  = (r.action && r.action.societe)  ? r.action.societe  : '—';
    if(!respBySoc[soc]) respBySoc[soc] = {};
    if(!respBySoc[soc][resp]){
      var audFound = (AUDITEURS||[]).find(function(u){
        return (u.prenom+' '+u.nom)===resp || (u.prenom+' '+u.nom).toLowerCase()===resp.toLowerCase();
      });
      respBySoc[soc][resp] = { fonc: audFound ? (audFound.role||audFound.poste||'—') : '—', v:0 };
    }
    respBySoc[soc][resp].v++;
  });

  var socKeys = Object.keys(respBySoc).sort();

  function _renderRespNav(activeSoc) {
    var navHtml = socKeys.map(function(s){
      var isActive = s === activeSoc;
      return '<button data-soc="'+s+'" style="'
        +'font-size:9px;font-weight:700;padding:3px 9px;border-radius:12px;border:1px solid '+(isActive?'#6366f1':'#e5e7eb')+';'
        +'background:'+(isActive?'#6366f1':'#f9fafb')+';color:'+(isActive?'#fff':'#6b7280')+';'
        +'cursor:pointer;white-space:nowrap;transition:all .15s;">'+s+'</button>';
    }).join('');
    $('#rr-resp-nav').html(navHtml || '<span style="font-size:10px;color:#aaa;">Aucune société</span>');

    var entries = Object.keys(respBySoc[activeSoc]||{}).map(function(k){
      return {resp:k, fonc:respBySoc[activeSoc][k].fonc, v:respBySoc[activeSoc][k].v};
    }).sort(function(a,b){ return b.v-a.v; });

    if(!entries.length){
      $('#rr-resp-list').html('<div style="font-size:10px;color:#aaa;padding:4px 0;">Aucun responsable</div>');
    } else {
      $('#rr-resp-list').html(entries.map(function(e){
        return '<div style="display:flex;align-items:center;gap:6px;padding:4px 0;border-bottom:1px solid #f3f4f6;">'
          +'<div style="flex:1;min-width:0;">'
          +'<div style="font-size:10.5px;font-weight:700;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">'+e.resp+'</div>'
          +'<div style="font-size:9px;color:#6b7280;">💼 '+e.fonc+'</div>'
          +'</div>'
          +'<span style="font-size:11px;font-weight:800;font-family:var(--mono);color:#6366f1;flex-shrink:0;">'+e.v+'</span>'
          +'</div>';
      }).join(''));
    }
  }

  if(socKeys.length){
    // lire la société active mémorisée ou prendre la première
    var _activeSoc = window._rrActiveSoc && respBySoc[window._rrActiveSoc] ? window._rrActiveSoc : socKeys[0];
    window._rrActiveSoc = _activeSoc;
    _renderRespNav(_activeSoc);
  } else {
    $('#rr-resp-nav').html('');
    $('#rr-resp-list').html('<div style="font-size:10px;color:#aaa;padding:4px 0;">Aucune donnée</div>');
  }

  // délégation click onglet société
  $('#rr-resp-nav').off('click.rrSoc').on('click.rrSoc','button[data-soc]',function(){
    window._rrActiveSoc = $(this).data('soc');
    _renderRespNav(window._rrActiveSoc);
  });

  // ── Tableau détaillé — dispatché par société ──
  var critIco = {critical:'🔴',high:'🟠',medium:'🟡',low:'🟢'};
  var today = new Date(); today.setHours(0,0,0,0);

  function getRecoBadge(r, statutEffectif) {
    var badges = {
      fully:    '<span style="display:inline-flex;align-items:center;gap:3px;padding:3px 8px;border-radius:20px;font-size:7.5pt;font-weight:700;background:#dcfce7;color:#166534;border:1px solid #86efac;white-space:nowrap;">✅ Fully Impl.</span>',
      partially:'<span style="display:inline-flex;align-items:center;gap:3px;padding:3px 8px;border-radius:20px;font-size:7.5pt;font-weight:700;background:#fff3cd;color:#7a5c00;border:1px solid #f0c040;white-space:nowrap;">📂 Partially Impl.</span>',
      echu:     '<span style="display:inline-flex;align-items:center;gap:3px;padding:3px 8px;border-radius:20px;font-size:7.5pt;font-weight:700;background:#fee2e2;color:#991b1b;border:1px solid #fca5a5;white-space:nowrap;">❌ Not Impl.</span>',
      nonechu:  '<span style="display:inline-flex;align-items:center;gap:3px;padding:3px 8px;border-radius:20px;font-size:7.5pt;font-weight:700;background:#e8f1fd;color:#0064d9;border:1px solid #93c5fd;white-space:nowrap;">📅 Non échue</span>',
    };
    return badges[statutEffectif] || badges.partially;
  }

  var C = 'padding:5px 6px;font-size:9px;vertical-align:middle;border-bottom:1px solid var(--border);';
  var html = '';

  // Grouper par société
  var bySoc = {};
  var socOrder = [];
  rows.forEach(function(item){
    var soc = item.action.societe || '—';
    if(!bySoc[soc]){ bySoc[soc]=[]; socOrder.push(soc); }
    bySoc[soc].push(item);
  });

  socOrder.forEach(function(soc){
    var items = bySoc[soc];
    html += '<tr>'
      +'<td colspan="7" style="padding:6px 10px;background:#1a3a5c;color:#fff;font-size:9.5px;font-weight:700;letter-spacing:.04em;border-bottom:2px solid #0f2540;">'
      +'🏢 '+soc+' <span style="font-weight:400;opacity:.75;font-size:8.5px;margin-left:6px;">'+items.length+' recommandation'+(items.length>1?'s':'')+'</span>'
      +'</td></tr>';
    items.forEach(function(item, i){
      var a=item.action, r=item.reco, statutEffectif=item.statutEffectif;
      var echeDisp = r.echeance ? r.echeance.replace(/^(\d{4})-(\d{2})-(\d{2})$/,'$3/$2/$1') : '—';
      var anomalie = (a.anomalie||a.findingTitle||a.title||'—').replace(/"/g,'&quot;');
      var rowBg = i%2===0 ? '' : 'background:#fafafa;';
      // Retard
      var retardHtml = '<span style="color:var(--text-dim);">—</span>';
      if(statutEffectif === 'fully') {
        retardHtml = '<span style="color:#16a34a;font-weight:700;">✅</span>';
      } else if(r.echeance) {
        var ech = new Date(r.echeance); ech.setHours(0,0,0,0);
        var diff = Math.floor((today - ech) / 86400000);
        if(diff > 0) {
          retardHtml = '<span style="font-family:monospace;font-weight:800;color:#dc2626;font-size:9px;">+'+diff+'j</span>';
        } else if(diff === 0) {
          retardHtml = '<span style="font-family:monospace;font-weight:700;color:#d97706;font-size:9px;">Auj.</span>';
        } else {
          var reste=Math.abs(diff), color=reste<=7?'#d97706':reste<=30?'#0070f2':'#6b7280';
          retardHtml = '<span style="font-family:monospace;font-weight:700;color:'+color+';font-size:9px;">'+reste+'j</span>';
        }
      }
      html += '<tr style="'+rowBg+'">'
        +'<td style="'+C+'text-align:center;" title="'+(a.criticite||'—')+'">'+(critIco[a.criticite]||'⚪')+'</td>'
        +'<td style="'+C+'word-break:break-word;white-space:normal;">'+anomalie+'</td>'
        +'<td style="'+C+'color:#0070f2;font-weight:500;word-break:break-word;white-space:normal;">'+(r.disposition||'—')+'</td>'
        +'<td style="'+C+'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:0;">'+(r.responsable||'—')+'</td>'
        +'<td style="'+C+'font-family:monospace;font-size:8.5px;white-space:nowrap;text-align:center;">'+echeDisp+'</td>'
        +'<td style="'+C+'text-align:center;">'+getRecoBadge(r, statutEffectif)+'</td>'
        +'<td style="'+C+'text-align:center;white-space:nowrap;">'+retardHtml+'</td>'
        +'</tr>';
    });
  });

  if(!html) html = '<tr><td colspan="7" class="nodata">Aucune recommandation ne correspond aux filtres.</td></tr>';
  $('#rr-tbody').html(html);
  $('#rr-list-count').text(total + ' recommandation' + (total>1?'s':''));
}

// ── Filtres
$(document).on('change','#rr-filter-societe,#rr-filter-criticite,#rr-filter-statut,#rr-filter-cycle,#rr-filter-responsable', function(){ renderRecapReco(); });
$(document).on('click','#rr-reset-filters', function(){
  $('#rr-filter-societe').val('');
  $('#rr-filter-criticite').val('');
  $('#rr-filter-statut').val('');
  $('#rr-filter-cycle').val('');
  $('#rr-filter-responsable').val('');
  renderRecapReco();
});

// ── Impression — Récapitulatif des Recommandations (vue filtrée)
$(document).on('click','#rr-print-btn', function(){

  // Lire les filtres actifs
  var fSociete     = $('#rr-filter-societe').val()     || '';
  var fCriticite   = $('#rr-filter-criticite').val()   || '';
  var fStatut      = $('#rr-filter-statut').val()      || '';
  var fCycle       = $('#rr-filter-cycle').val()       || '';
  var fResponsable = $('#rr-filter-responsable').val() || '';
  var missionRef   = $('#rr-mission-ref').val().trim();

  // Résumé des filtres
  var filtresActifs = [];
  if(fSociete)     filtresActifs.push('Société : ' + fSociete);
  if(fCriticite)   filtresActifs.push('Criticité : ' + fCriticite);
  if(fStatut)      filtresActifs.push('Statut : ' + fStatut);
  if(fCycle)       filtresActifs.push('Cycle : ' + fCycle);
  if(fResponsable) filtresActifs.push('Responsable : ' + fResponsable);
  if(missionRef)   filtresActifs.push('Mission : ' + missionRef);
  var filtresLine = filtresActifs.length
    ? filtresActifs.join(' &nbsp;|&nbsp; ')
    : 'Tous les filtres : Toutes valeurs';

  // ── Capturer les graphiques depuis le DOM ──
  // 1. Donut statut : sérialiser le SVG et remplacer les var(--...) par des couleurs fixes
  var svgEl = document.getElementById('rr-donut-statut');
  var svgHtml = svgEl ? svgEl.outerHTML
    .replace(/var\(--surface\)/g,  '#ffffff')
    .replace(/var\(--surface3\)/g, '#f1f5f9')
    .replace(/var\(--text\)/g,     '#1a1a2e')
    .replace(/var\(--text-muted\)/g,'#6b7785')
    : '<svg width="140" height="140"></svg>';

  // Légende donut
  var legendHtml = $('#rr-donut-statut-legend').html() || '';
  legendHtml = legendHtml
    .replace(/var\(--surface3\)/g, '#f1f5f9')
    .replace(/var\(--text\)/g,     '#1a1a2e')
    .replace(/var\(--text-muted\)/g,'#6b7785')
    .replace(/var\(--text-dim\)/g, '#aab');

  // 2. Barres criticité
  var critHtml = $('#rr-bar-criticite').html() || '';
  critHtml = critHtml
    .replace(/var\(--surface3\)/g, '#f1f5f9')
    .replace(/var\(--text\)/g,     '#1a1a2e')
    .replace(/var\(--text-muted\)/g,'#6b7785')
    .replace(/var\(--text-dim\)/g, '#aab');

  // 3. Société · Responsable · Fonction — reconstruction pour impression (toutes sociétés)
  var _printRespBySoc = {};
  getAllRecos(fSociete, fCriticite, fStatut, fCycle, fResponsable).forEach(function(r){
    var resp = (r.reco && r.reco.responsable) ? r.reco.responsable : '—';
    var soc  = (r.action && r.action.societe)  ? r.action.societe  : '—';
    if(!_printRespBySoc[soc]) _printRespBySoc[soc] = {};
    if(!_printRespBySoc[soc][resp]){
      var audFound = (AUDITEURS||[]).find(function(u){ return (u.prenom+' '+u.nom)===resp || (u.prenom+' '+u.nom).toLowerCase()===resp.toLowerCase(); });
      _printRespBySoc[soc][resp] = { fonc: audFound?(audFound.role||audFound.poste||'—'):'—', v:0 };
    }
    _printRespBySoc[soc][resp].v++;
  });
  var respHtml = Object.keys(_printRespBySoc).sort().map(function(soc){
    var entries = Object.keys(_printRespBySoc[soc]).map(function(k){ return {resp:k, fonc:_printRespBySoc[soc][k].fonc, v:_printRespBySoc[soc][k].v}; }).sort(function(a,b){ return b.v-a.v; });
    return '<div style="margin-bottom:6px;">'
      +'<div style="font-size:8pt;font-weight:700;color:#1a1a2e;background:#f1f5f9;border-radius:4px;padding:2px 7px;margin-bottom:4px;display:inline-block;">🏢 '+soc+'</div>'
      +entries.map(function(e){
        return '<div style="display:flex;align-items:center;gap:6px;padding:2px 4px;border-bottom:1px solid #f3f4f6;">'
          +'<div style="flex:1;"><div style="font-size:8pt;font-weight:600;color:#1a1a2e;">'+e.resp+'</div>'
          +'<div style="font-size:7.5pt;color:#6b7280;">💼 '+e.fonc+'</div></div>'
          +'<span style="font-size:8.5pt;font-weight:800;color:#6366f1;">'+e.v+'</span>'
          +'</div>';
      }).join('')
      +'</div>';
  }).join('') || '<div style="font-size:8pt;color:#aaa;">Aucune donnée</div>';

  // Tableau et KPI
  var tbodyHtml  = $('#rr-tbody').html() || '<tr><td colspan="6" style="text-align:center;color:#888;padding:16px;">Aucune donnée</td></tr>';
  tbodyHtml = tbodyHtml
    .replace(/var\(--border\)/g,      '#e5e7eb')
    .replace(/var\(--text-muted\)/g,  '#6b7785')
    .replace(/var\(--text-dim\)/g,    '#9ca3af')
    .replace(/var\(--accent\)/g,      '#0070f2')
    .replace(/var\(--red\)/g,         '#dc2626')
    .replace(/var\(--mono\)/g,        'monospace')
    .replace(/var\(--text\)/g,        '#1a1a2e')
    .replace(/var\(--[^)]+\)/g,       '#888');



  // ── KPI : reconstruction inline à partir des données stockées ──
  // On ne capture PLUS le HTML du DOM (qui contient class="widget" et hérite
  // des règles CSS globales overflow:hidden / display:flex qui tronquent les labels).
  var _k = window._rrLastKpi || {};
  var _kpiDefs = [
    { label:'Total',              val:_k.total||0,    color:'#6366f1', bg:'#ede9fe' },
    { label:'✅ Clos / Fully',    val:_k.clos||0,     color:'#16a34a', bg:'#dcfce7' },
    { label:'📂 À suivre',        val:_k.suivre||0,   color:'#d97706', bg:'#fef3c7' },
    { label:'⏰ Échu',            val:_k.echu||0,     color:'#9d174d', bg:'#fce7f3' },
    { label:'📅 Non échue',       val:_k.nonechu||0,  color:'#0070f2', bg:'#e8f1fd' },
    { label:'Taux impl.',         val:(_k.txImpl||0)+'%',
      color:(_k.txImpl||0)>=80?'#16a34a':(_k.txImpl||0)>=40?'#d97706':'#dc2626',
      bg:   (_k.txImpl||0)>=80?'#dcfce7':(_k.txImpl||0)>=40?'#fef3c7':'#fee2e2' },
  ];
  var kpiHtml = _kpiDefs.map(function(k){
    return '<div style="padding:10px 8px;text-align:center;background:'+k.bg
      +';border:1px solid '+k.color+'33;border-radius:6px;">'
      +'<div style="font-size:20px;font-weight:800;font-family:monospace;color:'+k.color+';">'+k.val+'</div>'
      +'<div style="font-size:9.5px;color:'+k.color+';font-weight:600;margin-top:3px;line-height:1.2;">'+k.label+'</div>'
      +'</div>';
  }).join('');

  var listCount  = _k.listCount || '';
  var globalPct  = (_k.txImpl||0)+'%';
  var globalBar  = document.getElementById('rr-global-bar');
  var globalW    = globalBar ? globalBar.style.width      : (_k.txImpl||0)+'%';
  var globalBg   = _k.barColor || 'linear-gradient(90deg,#22c55e,#16a34a)';
  var globalColor= _k.pctColor || '#16a34a';

  var today = new Date().toLocaleDateString('fr-FR',{day:'2-digit',month:'long',year:'numeric'});

  var printDoc = `
<div class="rr-print-doc" style="font-family:'IBM Plex Sans','Segoe UI',Arial,sans-serif;color:#1a1a2e;background:#fff;padding:12mm 15mm 14mm;">

  <!-- En-tête commun avec logo -->
  ${_buildPrintHeader({ subtitle: 'Récapitulatif des Recommandations', date: today })}

  <!-- Infos mission/filtres -->
  <div style="text-align:right;font-size:8pt;color:#6b7280;margin-top:-10px;margin-bottom:14px;">
    ${missionRef ? '<div>Mission : <strong>' + missionRef + '</strong></div>' : ''}
    <div style="font-style:italic;">${filtresLine}</div>
  </div>

  <!-- KPI Cards -->
  <div style="display:grid;grid-template-columns:repeat(6,1fr);gap:8px;margin-bottom:14px;">
    ${kpiHtml}
  </div>

  <!-- Graphiques (2 colonnes) -->
  <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:18px;page-break-inside:avoid;">

    <!-- Société · Responsable · Fonction -->
    <div style="border:1px solid #e5e7eb;border-radius:8px;padding:12px;">
      <div style="font-size:9pt;font-weight:700;color:#1a1a2e;margin-bottom:10px;border-bottom:1px solid #f1f5f9;padding-bottom:6px;">Société · Responsable · Fonction</div>
      <div style="padding:4px 0;">${respHtml}</div>
    </div>

    <!-- Répartition par statut -->
    <div style="border:1px solid #e5e7eb;border-radius:8px;padding:12px;">
      <div style="font-size:9pt;font-weight:700;color:#1a1a2e;margin-bottom:10px;border-bottom:1px solid #f1f5f9;padding-bottom:6px;">Répartition par statut</div>
      <div style="display:flex;align-items:center;gap:12px;">
        ${svgHtml}
        <div style="flex:1;">${legendHtml}</div>
      </div>
    </div>

  </div>

  <!-- Tableau détaillé -->
  <div style="font-size:9pt;font-weight:700;color:#0d2240;margin-bottom:6px;">
    Liste détaillée &nbsp;<span style="font-size:8pt;font-weight:400;color:#888;">${listCount}</span>
  </div>
  <table style="width:100%;border-collapse:collapse;font-size:8pt;table-layout:fixed;">
    <colgroup>
      <col style="width:4%"><!-- Crit. icône seule -->
      <col style="width:24%"><!-- Anomalie -->
      <col style="width:24%"><!-- Disposition -->
      <col style="width:13%"><!-- Responsable -->
      <col style="width:8%"><!-- Échéance -->
      <col style="width:20%"><!-- Statut badge pill -->
      <col style="width:7%"><!-- Retard -->
    </colgroup>
    <thead>
      <tr style="background:#0d2240;color:#fff;">
        <th style="padding:5px 4px;text-align:center;border:1px solid #1a3a6b;font-weight:700;">Crit.</th>
        <th style="padding:5px 6px;text-align:left;border:1px solid #1a3a6b;font-weight:700;">Anomalie</th>
        <th style="padding:5px 6px;text-align:left;border:1px solid #1a3a6b;font-weight:700;">Disposition</th>
        <th style="padding:5px 6px;text-align:left;border:1px solid #1a3a6b;font-weight:700;">Responsable</th>
        <th style="padding:5px 6px;text-align:center;border:1px solid #1a3a6b;font-weight:700;">Échéance</th>
        <th style="padding:5px 4px;text-align:center;border:1px solid #1a3a6b;font-weight:700;">Statut</th>
        <th style="padding:5px 4px;text-align:center;border:1px solid #1a3a6b;font-weight:700;">Retard</th>
      </tr>
    </thead>
    <tbody>
      ${tbodyHtml}
    </tbody>
  </table>

  <!-- Pied de page (style TDR) -->
  <div style="margin-top:16px;padding-top:6px;border-top:1px solid #e0e0e0;display:flex;justify-content:space-between;font-size:7.5pt;color:#aaa;font-style:italic;">
    <span>Confidentiel – Diffusion restreinte | Direction Audit &amp; Contrôle</span>
    <span>${missionRef ? 'Réf. : ' + missionRef : ''}</span>
  </div>

</div>`;

  var $area = $('#om-print-area');
  $area.html(printDoc).show();

  var _prevTitle = document.title;
  document.title = 'Récapitulatif des Recommandations'
    + (missionRef ? ' — ' + missionRef : '')
    + (fSociete   ? ' — ' + fSociete   : '');
  window.print();
  setTimeout(function(){
    document.title = _prevTitle;
    $area.hide().empty();
  }, 1500);
});

/* ══════════════════════════════════════════════
   RAPPORT D'AUDIT — Vue imprimable IIA
   Vue imprimable — Rapport d'Audit Interne
═══════════════════════════════════════════════ */

function _raPopulateAuditSelect() {
  var $sel = $('#ra-select-audit');
  var prev = $sel.val();
  $sel.find('option:not(:first-child)').remove();
  (AUDITS||[]).forEach(function(a, i) {
    var label = (a.ref||'') + ' — ' + (a.title||'') + (a.societe?' ['+a.societe+']':'');
    $sel.append('<option value="'+i+'">'+label+'</option>');
  });
  if(prev) $sel.val(prev);
}

/* ── Couleurs criticité ── */
function _raCritColor(c) {
  var map = {critical:['#b91c1c','#fee2e2'], high:['#c05c00','#fef0e4'], medium:['#a16207','#fef9c3'], low:['#15803d','#dcfce7']};
  return map[c] || ['#374151','#f3f4f6'];
}
function _raCritLabel(c) {
  var map = {critical:'Critique',high:'Élevé',medium:'Moyen',low:'Faible'};
  return map[c] || c;
}
function _raStatusLabel(s) {
  var map = {notimplemented:'Non implémentée',partially:'Partiellement implémentée',fully:'Implémentée'};
  return map[s] || s;
}
function _raStatusColor(s) {
  var map = {notimplemented:'#b91c1c',partially:'#c05c00',fully:'#15803d'};
  return map[s] || '#374151';
}
function _raFmtDate(d) {
  if(!d) return '—';
  try { var dt=new Date(d); if(isNaN(dt)) return d; return dt.toLocaleDateString('fr-FR',{day:'2-digit',month:'long',year:'numeric'}); } catch(e){ return d; }
}
function _raFmtDateShort(d) {
  if(!d) return '—';
  try { var dt=new Date(d); if(isNaN(dt)) return d; return dt.toLocaleDateString('fr-FR',{day:'2-digit',month:'short',year:'numeric'}); } catch(e){ return d; }
}

/* ══════════════════════════════════════════════════════════
   POINTS FORTS CONSTATÉS — Store + UI
══════════════════════════════════════════════════════════ */
var POINTS_FORTS = [];
function pfSave(){ try{ localStorage.setItem('daci_points_forts', JSON.stringify(POINTS_FORTS)); }catch(e){} }
function pfLoad(){ try{ var d=localStorage.getItem('daci_points_forts'); if(d) POINTS_FORTS=JSON.parse(d); }catch(e){} }
pfLoad();

/* ══════════════════════════════════════════════════════════════
   MODULE MATRICE D'EISENHOWER
   ══════════════════════════════════════════════════════════════ */
var EIS_TASKS = [];

function eisSave(){ try{ localStorage.setItem('daci_eisenhower', JSON.stringify(EIS_TASKS)); }catch(e){} }
function eisLoad(){ try{ var d=localStorage.getItem('daci_eisenhower'); if(d) _reload(EIS_TASKS, JSON.parse(d)); }catch(e){} }
eisLoad();

var _eisView = 'matrix'; // 'matrix' | 'list'

/* ─── Labels ─── */
var EIS_Q_LABELS = {
  q1:'Q1 – Important & Urgent',
  q2:'Q2 – Important & Non Urgent',
  q3:'Q3 – Non Important & Urgent',
  q4:'Q4 – Non Important & Non Urgent'
};
var EIS_Q_ACTIONS = { q1:'⚡ Priorité', q2:'📅 Planifier', q3:'↗ Déléguer', q4:'🗑 Abandonner' };
var EIS_Q_COLORS  = { q1:'#bb2222', q2:'#1a8a4a', q3:'#c47d00', q4:'#6941c6' };
var EIS_STATE_LABELS = { todo:'À faire', inprogress:'En cours', done:'Terminée', cancelled:'Abandonnée' };
var EIS_STATE_BADGES = {
  todo:       'badge planned',
  inprogress: 'badge inprogress',
  done:       'badge completed',
  cancelled:  'badge planned'
};
var EIS_PRIO_LABELS = { normal:'Normal', high:'Haute', critical:'Critique' };
var EIS_PRIO_BADGES = { normal:'badge low', high:'badge medium', critical:'badge critical' };

/* ─── Render principal ─── */
function renderEisenhower(){
  /* filtres */
  var filterResp  = $('#eis-filter-resp').val()||'';
  var filterState = $('#eis-filter-state').val()||'';

  /* populate responsables dropdown — from AUDITEURS + task data */
  var $fr = $('#eis-filter-resp');
  var curR = $fr.val();
  $fr.find('option:not(:first-child)').remove();
  var fromAuds = (AUDITEURS||[]).filter(function(a){ return a.statut!=='inactive'; }).map(function(a){ return a.prenom+' '+a.nom; });
  var fromTasks = EIS_TASKS.map(function(t){ return t.responsable; }).filter(Boolean);
  var resps = [...new Set([...fromAuds, ...fromTasks])].sort();
  resps.forEach(function(r){ $fr.append('<option value="'+r+'">'+r+'</option>'); });
  if(curR) $fr.val(curR);

  var filtered = EIS_TASKS.filter(function(t){
    if(filterResp  && t.responsable!==filterResp)  return false;
    if(filterState && t.statut!==filterState)        return false;
    return true;
  });

  /* KPI */
  ['q1','q2','q3','q4'].forEach(function(q){
    $('#eis-kpi-'+q).text(EIS_TASKS.filter(function(t){return t.quadrant===q&&t.statut!=='cancelled';}).length);
  });

  /* Badge sidebar */
  var nQ1 = EIS_TASKS.filter(function(t){return t.quadrant==='q1'&&t.statut==='inprogress';}).length;
  $('#nb-eisenhower').toggle(nQ1>0).text(nQ1);

  if(_eisView==='matrix'){
    $('#eis-matrix-view').show();
    $('#eis-list-view').hide();
    ['q1','q2','q3','q4'].forEach(function(q){
      var tasks = filtered.filter(function(t){return t.quadrant===q;});
      var html='';
      if(!tasks.length){
        html='<div style="font-size:10.5px;color:var(--text-dim);text-align:center;padding:12px 0;">Aucune tâche</div>';
      } else {
        tasks.forEach(function(t){
          var realIdx = EIS_TASKS.indexOf(t);
          var col = EIS_Q_COLORS[q];
          var isOverdue = t.dateEcheance && t.statut!=='done' && t.statut!=='cancelled' && new Date(t.dateEcheance) < new Date();
          html += '<div style="background:var(--surface);border:0.5px solid var(--border);border-left:3px solid '+col+';border-radius:var(--radius-sm);padding:7px 9px;cursor:pointer;" class="eis-card" data-idx="'+realIdx+'">';
          html += '<div style="font-size:11.5px;font-weight:600;margin-bottom:4px;line-height:1.35;">'+escHtml(t.nom)+'</div>';
          html += '<div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:3px;">';
          html += '<span style="font-size:10px;color:var(--text-muted);">👤 '+escHtml(t.responsable||'—')+'</span>';
          if(t.delegue && q==='q3') html += '<span style="font-size:10px;color:var(--text-muted);">↗ '+escHtml(t.delegue)+'</span>';
          html += '</div>';
          html += '<div style="display:flex;align-items:center;gap:5px;margin-top:5px;flex-wrap:wrap;">';
          html += '<span class="'+EIS_STATE_BADGES[t.statut||'todo']+'">'+EIS_STATE_LABELS[t.statut||'todo']+'</span>';
          if(t.priorite && t.priorite!=='normal') html += '<span class="'+EIS_PRIO_BADGES[t.priorite]+'">'+EIS_PRIO_LABELS[t.priorite]+'</span>';
          if(t.difficulte) html += '<span style="font-size:9.5px;font-weight:600;padding:1px 5px;border-radius:3px;background:'+(EIS_DIFF_STYLES[t.difficulte]||{bg:'var(--surface3)'}).bg+';color:'+(EIS_DIFF_STYLES[t.difficulte]||{color:'var(--text-muted)'}).color+';">'+EIS_DIFF_ICONS[t.difficulte]+' '+EIS_DIFF_LABELS[t.difficulte]+'</span>';
          if(isOverdue) html += '<span class="badge overdue">⏰ En retard</span>';
          if(t.dateEcheance) html += '<span style="font-size:9.5px;color:var(--text-muted);margin-left:auto;">'+formatDateFr(t.dateEcheance)+'</span>';
          if(t.dureeVal) html += '<span style="font-size:9.5px;color:var(--text-muted);display:flex;align-items:center;gap:2px;">⏱ '+eisDureeLabel(t.dureeVal,t.dureeUnite)+'</span>';
          html += '</div>';
          html += '<div style="display:flex;gap:4px;margin-top:6px;">';
          html += '<button class="tbtn eis-edit-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;">✏️</button>';
          html += '<button class="tbtn eis-del-btn"  data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;color:var(--red);">🗑</button>';
          html += '<button class="tbtn eis-done-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;color:var(--green);margin-left:auto;" title="Marquer terminée">✓</button>';
          html += '</div>';
          html += '</div>';
        });
      }
      $('#eis-cards-'+q).html(html);
    });
  } else {
    /* Vue liste */
    $('#eis-matrix-view').hide();
    $('#eis-list-view').show();
    $('#eis-empty').toggle(!filtered.length);
    $('#eis-table').toggle(!!filtered.length);
    var html='';
    filtered.forEach(function(t){
      var realIdx = EIS_TASKS.indexOf(t);
      var col = EIS_Q_COLORS[t.quadrant||'q1'];
      var isOverdue = t.dateEcheance && t.statut!=='done' && t.statut!=='cancelled' && new Date(t.dateEcheance)<new Date();
      html += '<tr>';
      html += '<td><span style="background:'+col+';color:#fff;font-size:9px;font-weight:700;padding:2px 7px;border-radius:10px;">'+(t.quadrant||'').toUpperCase()+'</span><div style="font-size:9px;color:var(--text-muted);margin-top:2px;">'+EIS_Q_ACTIONS[t.quadrant||'q1']+'</div></td>';
      html += '<td style="font-weight:500;max-width:220px;">'+escHtml(t.nom)+'<div style="font-size:10px;color:var(--text-muted);margin-top:2px;">'+escHtml((t.notes||'').slice(0,60))+(t.notes&&t.notes.length>60?'…':'')+'</div></td>';
      html += '<td style="font-size:11.5px;">'+escHtml(t.responsable||'—')+'</td>';
      html += '<td style="font-size:11.5px;color:var(--text-muted);">'+escHtml(t.delegue||'—')+'</td>';
      html += '<td style="font-size:11.5px;">'+(t.dateEcheance?'<span style="color:'+(isOverdue?'var(--red)':'var(--text)')+';">'+formatDateFr(t.dateEcheance)+'</span>':'—')+'</td>';
      html += '<td style="font-size:11px;white-space:nowrap;color:var(--text-muted);">'+(t.dureeVal?'⏱ '+eisDureeLabel(t.dureeVal,t.dureeUnite):'—')+'</td>';
      html += '<td>'+(t.difficulte?'<span style="font-size:9.5px;font-weight:600;padding:2px 7px;border-radius:3px;background:'+(EIS_DIFF_STYLES[t.difficulte]||{bg:'var(--surface3)'}).bg+';color:'+(EIS_DIFF_STYLES[t.difficulte]||{color:'var(--text-muted)'}).color+';">'+EIS_DIFF_ICONS[t.difficulte]+' '+EIS_DIFF_LABELS[t.difficulte]+'</span>':'—')+'</td>';
      html += '<td><span class="'+EIS_PRIO_BADGES[t.priorite||'normal']+'">'+EIS_PRIO_LABELS[t.priorite||'normal']+'</span></td>';
      html += '<td><span class="'+EIS_STATE_BADGES[t.statut||'todo']+'">'+EIS_STATE_LABELS[t.statut||'todo']+'</span></td>';
      html += '<td><button class="tbtn eis-edit-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;">✏️</button> <button class="tbtn eis-del-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;color:var(--red);">🗑</button></td>';
      html += '</tr>';
    });
    $('#eis-tbody').html(html);
  }
  /* Toujours mettre à jour le panneau gauche */
  renderEisLeftPanel();
}

/* ─── Helpers ─── */
function escHtml(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function formatDateFr(d){ if(!d) return ''; try{ var dt=new Date(d); return dt.toLocaleDateString('fr-FR',{day:'2-digit',month:'short',year:'numeric'}); }catch(e){return d;} }

/* ─── Ouvrir modal ─── */
function eisPopulateAuditeurSelects(respVal, delegVal){
  var auds = (AUDITEURS||[]).filter(function(a){ return a.statut!=='inactive'; });
  var opts = '<option value="">— Sélectionner un auditeur —</option>';
  auds.forEach(function(a){
    var v = a.prenom+' '+a.nom;
    var poste = a.poste ? ' — '+a.poste : '';
    opts += '<option value="'+v+'"'+(v===respVal?' selected':'')+'>'+v+poste+'</option>';
  });
  $('#eis-responsable').html(opts);
  if(respVal && !auds.find(function(a){ return a.prenom+' '+a.nom===respVal; })){
    $('#eis-responsable').append('<option value="'+escHtml(respVal)+'" selected>'+escHtml(respVal)+'</option>');
  }

  var opts2 = '<option value="">— Aucun —</option>';
  auds.forEach(function(a){
    var v = a.prenom+' '+a.nom;
    var poste = a.poste ? ' — '+a.poste : '';
    opts2 += '<option value="'+v+'"'+(v===delegVal?' selected':'')+'>'+v+poste+'</option>';
  });
  $('#eis-delegue').html(opts2);
  if(delegVal && !auds.find(function(a){ return a.prenom+' '+a.nom===delegVal; })){
    $('#eis-delegue').append('<option value="'+escHtml(delegVal)+'" selected>'+escHtml(delegVal)+'</option>');
  }
}

function eisOpenModal(idx){
  var isEdit = idx!==undefined && idx>=0;
  var t = isEdit ? EIS_TASKS[idx] : {};
  $('#eis-modal-title').text(isEdit ? '✏️ Modifier la tâche' : '➕ Nouvelle tâche');
  $('#eis-edit-idx').val(isEdit ? idx : '');
  $('#eis-name').val(t.nom||'');
  $('#eis-quadrant').val(t.quadrant||'q1');
  $('#eis-priority').val(t.priorite||'normal');
  eisPopulateAuditeurSelects(t.responsable||'', t.delegue||'');
  $('#eis-date-debut').val(t.dateDebut||'');
  $('#eis-date-fin').val(t.dateEcheance||'');
  $('#eis-state').val(t.statut||'todo');
  $('#eis-notes').val(t.notes||'');
  /* Durée */
  $('#eis-duree-val').val(t.dureeVal||'');
  $('#eis-duree-unite').val(t.dureeUnite||'h');
  /* Difficulté */
  var diff = t.difficulte||'moyen';
  $('#eis-difficulte').val(diff);
  eisRefreshDiffBtns(diff);
  $('#eis-modal').addClass('open');
  setTimeout(function(){ $('#eis-name').focus(); },80);
}

/* ═══════════════════════════════════════════════════════════
   CONFIG — MATRICE D'EISENHOWER
   ═══════════════════════════════════════════════════════════ */

/* Clé localStorage pour les préférences par défaut */
var EIS_CFG_KEY = 'daci_eisenhower_cfg';

function eisCfgLoad(){
  try{ var d=localStorage.getItem(EIS_CFG_KEY); return d?JSON.parse(d):{quadrant:'q1',priorite:'normal',difficulte:'moyen',unite:'h'}; }catch(e){ return {quadrant:'q1',priorite:'normal',difficulte:'moyen',unite:'h'}; }
}
function eisCfgSave(cfg){ try{ localStorage.setItem(EIS_CFG_KEY, JSON.stringify(cfg)); }catch(e){} }

function renderCfgEisenhower(){
  var all   = EIS_TASKS;
  var total = all.length;
  var done      = all.filter(function(t){ return t.statut==='done'; }).length;
  var inprog    = all.filter(function(t){ return t.statut==='inprogress'; }).length;
  var todo      = all.filter(function(t){ return t.statut==='todo'; }).length;
  var cancelled = all.filter(function(t){ return t.statut==='cancelled'; }).length;
  var overdue   = all.filter(function(t){ return t.dateEcheance && t.statut!=='done' && t.statut!=='cancelled' && new Date(t.dateEcheance)<new Date(); }).length;
  var avgDuree  = (function(){
    var items = all.filter(function(t){ return t.dureeVal; });
    if(!items.length) return null;
    var totalH = items.reduce(function(acc,t){
      var v = parseFloat(t.dureeVal)||0;
      var u = t.dureeUnite||'h';
      if(u==='j') v*=8; else if(u==='sem') v*=40;
      return acc+v;
    },0);
    return Math.round(totalH*10)/10;
  })();

  /* KPI stats */
  var kpis = [
    { label:'Total tâches',    val:total,     color:'var(--accent)',  icon:'🎯' },
    { label:'À faire',         val:todo,      color:'var(--text)',     icon:'📋' },
    { label:'En cours',        val:inprog,    color:'var(--purple)',   icon:'⚙️' },
    { label:'Terminées',       val:done,      color:'var(--green)',    icon:'✅' },
    { label:'Abandonnées',     val:cancelled, color:'var(--text-muted)',icon:'🚫' },
    { label:'En retard',       val:overdue,   color:'var(--red)',      icon:'⏰' },
  ];
  var statsHtml = kpis.map(function(k){
    return '<div style="background:var(--surface2);border-radius:var(--radius-sm);padding:10px 12px;display:flex;flex-direction:column;gap:2px;">'
      +'<div style="font-size:18px;font-weight:800;color:'+k.color+';font-family:var(--mono);">'+k.val+'</div>'
      +'<div style="font-size:10px;color:var(--text-muted);">'+k.icon+' '+k.label+'</div>'
      +'</div>';
  }).join('');
  if(avgDuree!==null){
    statsHtml += '<div style="background:var(--surface2);border-radius:var(--radius-sm);padding:10px 12px;display:flex;flex-direction:column;gap:2px;grid-column:span 2;">'
      +'<div style="font-size:16px;font-weight:800;color:var(--cyan);font-family:var(--mono);">⏱ '+avgDuree+'h</div>'
      +'<div style="font-size:10px;color:var(--text-muted);">Charge totale estimée (hors closes)</div>'
      +'</div>';
  }
  $('#cfg-eis-stats').html(statsHtml);

  /* Répartition par quadrant */
  var qHtml = '';
  ['q1','q2','q3','q4'].forEach(function(q){
    var count = all.filter(function(t){ return t.quadrant===q; }).length;
    var pct   = total>0 ? Math.round(count/total*100) : 0;
    var col   = EIS_Q_COLORS[q];
    qHtml += '<div>'
      +'<div style="display:flex;justify-content:space-between;margin-bottom:3px;">'
      +'<span style="font-size:11px;font-weight:600;">'+EIS_Q_LABELS[q]+'</span>'
      +'<span style="font-size:11px;font-family:var(--mono);color:'+col+';font-weight:700;">'+count+' <span style="color:var(--text-dim);font-size:9.5px;">('+pct+'%)</span></span>'
      +'</div>'
      +'<div style="height:5px;background:var(--surface3);border-radius:3px;overflow:hidden;">'
      +'<div style="height:100%;border-radius:3px;background:'+col+';width:'+pct+'%;transition:width .4s;"></div>'
      +'</div>'
      +'</div>';
  });
  $('#cfg-eis-quadrant-stats').html(qHtml||'<div style="color:var(--text-dim);font-size:11.5px;">Aucune tâche.</div>');

  /* Répartition par difficulté */
  var dHtml = '';
  [['facile','🟢'],['moyen','🟡'],['difficile','🔴']].forEach(function(pair){
    var d = pair[0], icon = pair[1];
    var count = all.filter(function(t){ return (t.difficulte||'moyen')===d; }).length;
    var pct   = total>0 ? Math.round(count/total*100) : 0;
    var ds    = EIS_DIFF_STYLES[d];
    dHtml += '<div>'
      +'<div style="display:flex;justify-content:space-between;margin-bottom:3px;">'
      +'<span style="font-size:11px;font-weight:600;">'+icon+' '+EIS_DIFF_LABELS[d]+'</span>'
      +'<span style="font-size:11px;font-family:var(--mono);color:'+ds.color+';font-weight:700;">'+count+' <span style="color:var(--text-dim);font-size:9.5px;">('+pct+'%)</span></span>'
      +'</div>'
      +'<div style="height:5px;background:var(--surface3);border-radius:3px;overflow:hidden;">'
      +'<div style="height:100%;border-radius:3px;background:'+ds.color+';width:'+pct+'%;transition:width .4s;"></div>'
      +'</div>'
      +'</div>';
  });
  $('#cfg-eis-diff-stats').html(dHtml||'<div style="color:var(--text-dim);font-size:11.5px;">Aucune tâche.</div>');

  /* Charger les valeurs par défaut sauvegardées */
  var cfg = eisCfgLoad();
  $('#cfg-eis-def-quadrant').val(cfg.quadrant||'q1');
  $('#cfg-eis-def-priorite').val(cfg.priorite||'normal');
  $('#cfg-eis-def-difficulte').val(cfg.difficulte||'moyen');
  $('#cfg-eis-def-unite').val(cfg.unite||'h');
}

/* Sauvegarder les valeurs par défaut */
$('#cfg-eis-save-defaults').on('click', function(){
  var cfg = {
    quadrant:   $('#cfg-eis-def-quadrant').val(),
    priorite:   $('#cfg-eis-def-priorite').val(),
    difficulte: $('#cfg-eis-def-difficulte').val(),
    unite:      $('#cfg-eis-def-unite').val()
  };
  eisCfgSave(cfg);
  toast('Valeurs par défaut enregistrées.','success');
});

/* Purger les tâches closes */
$('#cfg-eis-del-closed').on('click', function(){
  var n = EIS_TASKS.filter(function(t){ return t.statut==='done'||t.statut==='cancelled'; }).length;
  if(!n){ toast('Aucune tâche close à supprimer.','info'); return; }
  if(!confirm('Supprimer définitivement les '+n+' tâche(s) close(s) ?')) return;
  for(var i=EIS_TASKS.length-1;i>=0;i--){
    if(EIS_TASKS[i].statut==='done'||EIS_TASKS[i].statut==='cancelled') EIS_TASKS.splice(i,1);
  }
  eisSave();
  renderCfgEisenhower();
  toast(n+' tâche(s) close(s) supprimée(s).','success');
});

/* Réinitialiser toute la matrice */
$('#cfg-eis-reset-all').on('click', function(){
  if(!EIS_TASKS.length){ toast('La matrice est déjà vide.','info'); return; }
  if(!confirm('⚠️ Supprimer TOUTES les tâches Eisenhower ? Cette action est irréversible.')) return;
  EIS_TASKS.length=0;
  eisSave();
  renderCfgEisenhower();
  toast('Matrice Eisenhower réinitialisée.','info');
});

/* Export JSON */
$('#cfg-eis-export-json').on('click', function(){
  try{
    var data = JSON.stringify(EIS_TASKS, null, 2);
    var blob = new Blob([data],{type:'application/json'});
    var url  = URL.createObjectURL(blob);
    var a    = document.createElement('a');
    a.href   = url;
    a.download = 'eisenhower_taches_'+new Date().toISOString().slice(0,10)+'.json';
    a.click();
    URL.revokeObjectURL(url);
    toast('Export JSON téléchargé.','success');
  }catch(e){ toast('Erreur lors de l\'export.','error'); }
});

/* Appliquer les défauts dans le modal Eisenhower à l'ouverture */
var _eisOrigOpenModal = eisOpenModal;
eisOpenModal = function(idx){
  _eisOrigOpenModal(idx);
  if(idx===undefined){
    var cfg = eisCfgLoad();
    $('#eis-quadrant').val(cfg.quadrant||'q1');
    $('#eis-priority').val(cfg.priorite||'normal');
    $('#eis-difficulte').val(cfg.difficulte||'moyen');
    eisRefreshDiffBtns(cfg.difficulte||'moyen');
    $('#eis-duree-unite').val(cfg.unite||'h');
  }
};

/* ─── Panneau gauche : Tâches Closes ─── */
function renderEisLeftPanel(){
  var filterType = $('#eis-left-filter-type').val()||'';

  var closed = EIS_TASKS.filter(function(t){
    var s = t.statut||'todo';
    if(s!=='done' && s!=='cancelled') return false;
    if(filterType && s!==filterType) return false;
    return true;
  });

  var cntDone     = EIS_TASKS.filter(function(t){ return t.statut==='done'; }).length;
  var cntCancelled= EIS_TASKS.filter(function(t){ return t.statut==='cancelled'; }).length;
  $('#eis-left-cnt-done').text(cntDone+' ✓');
  $('#eis-left-cnt-cancel').text(cntCancelled+' ✕');

  $('#eis-left-empty').toggle(!closed.length);

  var html='';
  closed.forEach(function(t){
    var realIdx = EIS_TASKS.indexOf(t);
    var isDone = t.statut==='done';
    var qcol   = EIS_Q_COLORS[t.quadrant||'q1'];
    var ds     = EIS_DIFF_STYLES[t.difficulte]||{};
    html += '<div style="background:var(--surface);border:1px solid var(--border);border-left:3px solid '+(isDone?'var(--green)':'var(--border2)')+';border-radius:var(--radius-sm);padding:6px 8px;opacity:'+(isDone?'1':'.65')+';">';
    /* badge statut */
    html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:3px;">';
    html += '<span style="font-size:9px;font-weight:700;padding:1px 6px;border-radius:9px;background:'+(isDone?'var(--green-bg)':'var(--surface3)')+';color:'+(isDone?'var(--green)':'var(--text-muted)')+';">'+(isDone?'✅ Terminée':'🚫 Abandonnée')+'</span>';
    html += '<span style="font-size:9px;font-weight:700;padding:1px 6px;border-radius:9px;background:'+qcol+';color:#fff;">'+(t.quadrant||'').toUpperCase()+'</span>';
    html += '</div>';
    /* nom */
    html += '<div style="font-size:11px;font-weight:600;line-height:1.3;margin-bottom:3px;text-decoration:'+(isDone?'none':'line-through')+';color:var(--text);">'+escHtml(t.nom)+'</div>';
    /* meta */
    html += '<div style="display:flex;flex-wrap:wrap;gap:3px;margin-bottom:4px;">';
    if(t.responsable) html += '<span style="font-size:9.5px;color:var(--text-muted);">👤 '+escHtml(t.responsable)+'</span>';
    if(t.dateEcheance) html += '<span style="font-size:9.5px;color:var(--text-muted);">📅 '+formatDateFr(t.dateEcheance)+'</span>';
    if(t.dureeVal) html += '<span style="font-size:9.5px;color:var(--text-muted);">⏱ '+eisDureeLabel(t.dureeVal,t.dureeUnite)+'</span>';
    if(t.difficulte && ds.color) html += '<span style="font-size:9px;font-weight:600;padding:1px 5px;border-radius:3px;background:'+ds.bg+';color:'+ds.color+';">'+EIS_DIFF_ICONS[t.difficulte]+' '+EIS_DIFF_LABELS[t.difficulte]+'</span>';
    html += '</div>';
    /* actions */
    html += '<div style="display:flex;gap:4px;">';
    html += '<button class="tbtn eis-reopen-btn" data-idx="'+realIdx+'" style="font-size:9.5px;padding:2px 6px;color:var(--accent);">↩ Réouvrir</button>';
    html += '<button class="tbtn eis-del-btn"    data-idx="'+realIdx+'" style="font-size:9.5px;padding:2px 6px;color:var(--red);">🗑</button>';
    html += '</div>';
    html += '</div>';
  });

  $('#eis-left-list').find('.eis-left-card-wrap').remove();
  var $wrap = $('<div class="eis-left-card-wrap" style="display:flex;flex-direction:column;gap:4px;"></div>').html(html);
  $('#eis-left-list').append($wrap);
}

$('#eis-left-filter-type').on('change', function(){ renderEisLeftPanel(); });

/* ─── Labels Durée / Difficulté ─── */
var EIS_DIFF_LABELS = { facile:'Facile', moyen:'Moyen', difficile:'Difficile' };
var EIS_DIFF_ICONS  = { facile:'🟢', moyen:'🟡', difficile:'🔴' };
var EIS_DIFF_STYLES = {
  facile:    { border:'#a8d9b8', bg:'#f2fdf5', color:'#1a8a4a' },
  moyen:     { border:'#f0c890', bg:'#fef3da', color:'#c47d00' },
  difficile: { border:'#e8b4b4', bg:'#fdecea', color:'#bb2222' }
};
var EIS_UNITE_LABELS = { h:'h', j:'j', sem:'sem.' };

function eisDureeLabel(val, unite){
  if(!val) return '';
  return val + ' ' + (EIS_UNITE_LABELS[unite]||unite);
}

function eisRefreshDiffBtns(selected){
  $('.eis-diff-opt').each(function(){
    var v = $(this).data('val');
    if(v===selected){
      var s = EIS_DIFF_STYLES[v];
      $(this).css({ border:'1.5px solid '+s.border, background:s.bg, color:s.color });
    } else {
      $(this).css({ border:'1.5px solid var(--border)', background:'var(--surface2)', color:'var(--text-muted)' });
    }
  });
}

$(document).on('click','.eis-diff-opt',function(){
  var val = $(this).data('val');
  $('#eis-difficulte').val(val);
  eisRefreshDiffBtns(val);
});

/* ─── Boutons toolbar vue ─── */
function _eisSetViewBtn(active){
