  btns.forEach(function(b){
    if(b==='#'+active){
      $(b).css({background:'var(--accent-bg)',borderColor:'var(--accent)',color:'var(--accent)',fontWeight:'600'});
    } else {
      $(b).css({background:'',borderColor:'',color:'',fontWeight:''});
    }
  });
}
$('#eis-view-matrix').on('click', function(){
