});


/* ─── Render vue Tâches Closes ─── */
function renderEisClosed(){
  var filterQ    = $('#eis-closed-filter-q').val()||'';
  var filterType = $('#eis-closed-filter-type').val()||'';

  var closed = EIS_TASKS.filter(function(t){
    var s = t.statut||'todo';
    if(s!=='done' && s!=='cancelled') return false;
    if(filterType && s!==filterType) return false;
    if(filterQ && t.quadrant!==filterQ) return false;
    return true;
  });

  var countDone      = EIS_TASKS.filter(function(t){ return t.statut==='done'; }).length;
  var countCancelled = EIS_TASKS.filter(function(t){ return t.statut==='cancelled'; }).length;
  $('#eis-closed-count-done').text(countDone);
  $('#eis-closed-count-cancelled').text(countCancelled);

  $('#eis-closed-empty').toggle(!closed.length);
  $('#eis-closed-table').toggle(!!closed.length);

  var html='';
  closed.forEach(function(t){
    var realIdx = EIS_TASKS.indexOf(t);
    var col = EIS_Q_COLORS[t.quadrant||'q1'];
    var isDone = t.statut==='done';
    var statBadge = isDone
      ? '<span class="badge completed" style="background:#e4f5ec;color:#1a8a4a;">✅ Terminée</span>'
      : '<span class="badge planned" style="background:var(--surface3);color:var(--text-muted);">🚫 Abandonnée</span>';
    html += '<tr style="opacity:'+(isDone?'1':'.7')+';text-decoration:'+(isDone?'none':'line-through')+';">';
    html += '<td>'+statBadge+'</td>';
    html += '<td><span style="background:'+col+';color:#fff;font-size:9px;font-weight:700;padding:2px 7px;border-radius:10px;">'+(t.quadrant||'').toUpperCase()+'</span><div style="font-size:9px;color:var(--text-muted);margin-top:2px;">'+EIS_Q_ACTIONS[t.quadrant||'q1']+'</div></td>';
    html += '<td style="font-weight:500;max-width:220px;text-decoration:inherit;">'+escHtml(t.nom)+'</td>';
    html += '<td style="font-size:11.5px;">'+escHtml(t.responsable||'—')+'</td>';
    html += '<td style="font-size:11.5px;color:var(--text-muted);">'+(t.dateEcheance?formatDateFr(t.dateEcheance):'—')+'</td>';
    html += '<td style="font-size:11px;white-space:nowrap;color:var(--text-muted);">'+(t.dureeVal?'⏱ '+eisDureeLabel(t.dureeVal,t.dureeUnite):'—')+'</td>';
    html += '<td>'+(t.difficulte?'<span style="font-size:9.5px;font-weight:600;padding:2px 7px;border-radius:3px;background:'+(EIS_DIFF_STYLES[t.difficulte]||{bg:'var(--surface3)'}).bg+';color:'+(EIS_DIFF_STYLES[t.difficulte]||{color:'var(--text-muted)'}).color+';">'+EIS_DIFF_ICONS[t.difficulte]+' '+EIS_DIFF_LABELS[t.difficulte]+'</span>':'—')+'</td>';
    html += '<td style="font-size:10.5px;color:var(--text-muted);max-width:200px;">'+escHtml((t.notes||'').slice(0,80))+(t.notes&&t.notes.length>80?'…':'')+'</td>';
    html += '<td><button class="tbtn eis-reopen-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;color:var(--accent);" title="Réouvrir la tâche">↩ Réouvrir</button> <button class="tbtn eis-del-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;color:var(--red);">🗑</button></td>';
    html += '</tr>';
  });
  $('#eis-closed-tbody').html(html);
}

/* ─── Filtres vue Closes ─── */
$('#eis-closed-filter-q, #eis-closed-filter-type').on('change', function(){ if(_eisView==='closed') renderEisenhower(); });

/* ─── Réouvrir une tâche close → statut "todo" ─── */
$(document).on('click','.eis-reopen-btn',function(e){
  e.stopPropagation();
  var t = EIS_TASKS[+$(this).data('idx')];
  if(t){ t.statut='todo'; eisSave(); renderEisenhower(); toast('Tâche réouverte.','info'); }
});

