$('#eis-add-btn').on('click', function(){ eisOpenModal(); });

/* ─── Fermer modal ─── */
$('#eis-modal-close, #eis-modal-cancel').on('click', function(){ $('#eis-modal').removeClass('open'); });

/* ─── Save modal ─── */
$('#eis-modal-save').on('click', function(){
  var nom  = $('#eis-name').val().trim();
  var resp = $('#eis-responsable').val().trim();
  if(!nom){ toast('Veuillez renseigner l\'intitulé de la tâche.','error'); return; }
  if(!resp){ toast('Veuillez sélectionner un responsable.','error'); return; }
  var obj = {
    nom: nom,
    quadrant:     $('#eis-quadrant').val(),
    priorite:     $('#eis-priority').val(),
    responsable:  resp,
    delegue:      $('#eis-delegue').val().trim(),
    dateDebut:    $('#eis-date-debut').val(),
    dateEcheance: $('#eis-date-fin').val(),
    statut:       $('#eis-state').val(),
    notes:        $('#eis-notes').val().trim(),
    dureeVal:     $('#eis-duree-val').val().trim(),
    dureeUnite:   $('#eis-duree-unite').val(),
    difficulte:   $('#eis-difficulte').val()||'moyen',
    _uid: 'eis_'+Date.now()+'_'+Math.random().toString(36).slice(2,7)
  };
  var idx = $('#eis-edit-idx').val();
  if(idx!==''){ Object.assign(EIS_TASKS[+idx], obj); }
  else { EIS_TASKS.push(obj); }
  eisSave();
  $('#eis-modal').removeClass('open');
  renderEisenhower();
  toast(idx!=='' ? 'Tâche mise à jour.' : 'Tâche ajoutée.','success');
});

/* ─── Éditer depuis carte/liste ─── */
$(document).on('click','.eis-edit-btn',function(e){
  e.stopPropagation();
  eisOpenModal(+$(this).data('idx'));
});

/* ─── Supprimer ─── */
$(document).on('click','.eis-del-btn',function(e){
  e.stopPropagation();
  if(!confirm('Supprimer cette tâche ?')) return;
  EIS_TASKS.splice(+$(this).data('idx'),1);
  eisSave();
  renderEisenhower();
  toast('Tâche supprimée.','info');
});

/* ─── Terminer rapidement ─── */
$(document).on('click','.eis-done-btn',function(e){
  e.stopPropagation();
  var t = EIS_TASKS[+$(this).data('idx')];
  if(t){ t.statut='done'; eisSave(); renderEisenhower(); toast('Tâche marquée terminée.','success'); }
});

/* ─── Filtres ─── */
$('#eis-filter-resp, #eis-filter-state').on('change', function(){ renderEisenhower(); });

