  $('#eis-delegue-wrap label, #eis-delegue-wrap .flbl2').css('color', q==='q3' ? 'var(--accent)' : '');
});


/* ── Points Forts ── */
function renderPointsForts(){
  /* populate audit filter */
  var $f=$('#pf-filter-audit');
  var curF=$f.val();
  $f.find('option:not(:first-child)').remove();
  (AUDITS||[]).forEach(function(a){ $f.append('<option value="'+a.ref+'">'+a.ref+' — '+a.title+'</option>'); });
  if(curF) $f.val(curF);

  var filter=$f.val()||'';
  var rows = POINTS_FORTS.filter(function(p){ return !filter||p.auditRef===filter; });

  $('#pf-empty').toggle(!rows.length);
  $('#pf-table').toggle(!!rows.length);

  var html='';
  rows.forEach(function(p,i){
    var realIdx = POINTS_FORTS.indexOf(p);
    var audit = (AUDITS||[]).find(function(a){ return a.ref===p.auditRef; });
    html += '<tr data-idx="'+realIdx+'">' +
      '<td><span style="font-family:var(--mono);font-size:10.5px;color:var(--accent);">'+p.auditRef+'</span>'+(audit?'<div style="font-size:10px;color:var(--text-muted);margin-top:1px;">'+audit.title+'</div>':'')+'</td>' +
      '<td style="font-weight:600;font-size:11.5px;">'+p.processus+'</td>' +
      '<td style="max-width:260px;font-size:11.5px;line-height:1.5;">'+p.pointFort+'</td>' +
      '<td style="max-width:220px;font-size:11.5px;color:var(--text-muted);line-height:1.5;">'+( p.impact||'—')+'</td>' +
      '<td><div style="display:flex;gap:4px;">' +
        '<button class="tbtn pf-edit-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;">✏️</button>' +
        '<button class="tbtn pf-del-btn" data-idx="'+realIdx+'" style="font-size:10px;padding:2px 7px;color:var(--red);">🗑</button>' +
      '</div></td>' +
    '</tr>';
  });
  $('#pf-tbody').html(html);
}

/* populate audit select in modal */
function pfPopulateAuditSel(selRef){
  var $s=$('#pf-audit-sel').empty().append('<option value="">— Sélectionner —</option>');
  (AUDITS||[]).forEach(function(a){ $s.append('<option value="'+a.ref+'"'+(a.ref===selRef?' selected':'')+'>'+a.ref+' — '+a.title+'</option>'); });
}

function pfOpenModal(idx){
  var isEdit = idx !== undefined && idx >= 0;
  $('#pf-modal-title').text(isEdit ? '✏️ Modifier Point Fort' : '➕ Nouveau Point Fort');
  $('#pf-edit-idx').val(isEdit ? idx : '');
  var p = isEdit ? POINTS_FORTS[idx] : {};
  pfPopulateAuditSel(p.auditRef||'');
  $('#pf-processus').val(p.processus||'');
  $('#pf-pointfort').val(p.pointFort||'');
  $('#pf-impact').val(p.impact||'');
  $('#pf-modal').addClass('open');
  $('#pf-processus').focus();
}

function pfCloseModal(){ $('#pf-modal').removeClass('open'); }

$('#pf-add-btn').on('click', function(){ pfOpenModal(); });
$('#pf-modal-close,#pf-modal-cancel').on('click', pfCloseModal);
$('#pf-modal').on('click', function(e){ if($(e.target).is('#pf-modal')) pfCloseModal(); });

$('#pf-modal-save').on('click', function(){
  var auditRef = $('#pf-audit-sel').val();
  var processus = $('#pf-processus').val().trim();
  var pointFort = $('#pf-pointfort').val().trim();
  var impact    = $('#pf-impact').val().trim();
  if(!auditRef||!processus||!pointFort){ toast('error','⚠️','Audit, Processus et Point Fort sont obligatoires.'); return; }
  var idx = parseInt($('#pf-edit-idx').val());
  var obj = { auditRef, processus, pointFort, impact };
  if(!isNaN(idx) && idx >= 0) POINTS_FORTS[idx] = obj;
  else POINTS_FORTS.push(obj);
  pfSave(); pfCloseModal(); renderPointsForts();
  toast('success','✅', (isNaN(idx)||idx<0)?'Point fort ajouté.':'Point fort mis à jour.');
});

$(document).on('click','.pf-edit-btn',function(){ pfOpenModal(parseInt($(this).data('idx'))); });
$(document).on('click','.pf-del-btn',function(){
  var idx=parseInt($(this).data('idx'));
  POINTS_FORTS.splice(idx,1); pfSave(); renderPointsForts();
  toast('success','🗑️','Point fort supprimé.');
});
$(document).on('change','#pf-filter-audit',function(){ renderPointsForts(); });

/* ── Fonction principale ── */
function renderRapportAudit() {
  var idxStr = $('#ra-select-audit').val();
  var $root = $('#ra-a4-root');
  var $msg = $('#ra-no-audit-msg');
  var $wrapper = $('#ra-preview-wrapper');

  if(idxStr==='' || idxStr===null || typeof idxStr==='undefined') {
    $msg.show(); $root.closest('#ra-preview-wrapper').hide(); $root.html('');
    return;
  }
  $msg.hide(); $wrapper.show();

  var idx = parseInt(idxStr);
  var audit = (AUDITS||[])[idx];
  if(!audit) { $root.html('<p style="padding:20px;color:#888;">Audit introuvable.</p>'); return; }

  var filterCrit = $('#ra-filter-criticite').val() || '';
  var showExec   = $('#ra-chk-executive').is(':checked');
  var showRecos  = $('#ra-chk-recos').is(':checked');


  /* Collect findings for this audit */
  var today = new Date(); today.setHours(0,0,0,0);
  var findings = (ACTIONS||[]).filter(function(a){
    return (a.societe && audit.societe && a.societe===audit.societe) ||
           (a.cycle   && audit.cycle   && a.cycle===audit.cycle)     ||
           (a.ref     && audit.ref     && a.ref===audit.ref);
  });
  if(filterCrit) findings = findings.filter(function(a){ return a.criticite===filterCrit; });

  /* KPIs */
  var allRecos = [];
  findings.forEach(function(a){ (a.recommandations||[]).forEach(function(r){ allRecos.push({a:a,r:r}); }); });
  var total  = allRecos.length;
  var fully  = allRecos.filter(function(x){ return x.r.statut==='fully'; }).length;
  var partly = allRecos.filter(function(x){ return x.r.statut==='partially'; }).length;
  var notimp = allRecos.filter(function(x){ return x.r.statut==='notimplemented'||!x.r.statut; }).length;
  var txImpl = total>0 ? Math.round(fully/total*100) : 0;
  var cntCrit = findings.filter(function(a){ return a.criticite==='critical'; }).length;
  var cntHigh = findings.filter(function(a){ return a.criticite==='high'; }).length;

  /* ── Conclusion d'engagement — basée sur la Cotation du Référentiel IIA (AI.docx) ──
     Niveau 1 : Système de contrôle interne inadéquat
       → constats critiques présents, OU taux d'implémentation < 30 % avec constats élevés
     Niveau 2 : Système de contrôle interne adéquat, mais avec des réserves
       → constats élevés ≥ 1, OU taux d'implémentation < 70 %
     Niveau 3 : Système de contrôle interne satisfaisant
       → aucun critique, aucun élevé significatif, taux ≥ 70 %
  ── */
  var opinion='', opinionColor='', opinionBg='', opinionKey='';
  if(cntCrit>0 || (cntHigh>0 && txImpl<30)){
    opinionKey='inadequat';
    opinion='Système de contrôle interne inadéquat';
    opinionColor='#b91c1c'; opinionBg='#fee2e2';
  } else if(cntHigh>=1 || txImpl<70){
    opinionKey='reserve';
    opinion='Système de contrôle interne adéquat, mais avec des réserves';
    opinionColor='#c05c00'; opinionBg='#fef0e4';
  } else {
    opinionKey='satisfaisant';
    opinion='Système de contrôle interne satisfaisant';
    opinionColor='#15803d'; opinionBg='#dcfce7';
  }

  var now = new Date();
  var dateRapport = audit.date_rapport ? _raFmtDate(audit.date_rapport) : now.toLocaleDateString('fr-FR',{day:'2-digit',month:'long',year:'numeric'});

  /* ── Build equipe string ── */
  var equipeStr = '';
  if(audit.auditor) equipeStr += audit.auditor;
  if(audit.superviseur) equipeStr += (equipeStr?', ':'')+audit.superviseur+' (Superviseur)';
  if(audit.equipe&&audit.equipe.length) {
    audit.equipe.forEach(function(m){ if(m!==audit.auditor&&m!==audit.superviseur) equipeStr+=(equipeStr?', ':'')+m; });
  }

  /* ── Période sous revue ── */
  var psr='—';
  if(audit.periodeRevue){
    var p=audit.periodeRevue;
    if(p.debMois&&p.debAnnee&&p.finMois&&p.finAnnee) psr=p.debMois+'/'+p.debAnnee+' → '+p.finMois+'/'+p.finAnnee;
    else if(audit.start&&audit.end) psr=_raFmtDateShort(audit.start)+' → '+_raFmtDateShort(audit.end);
  } else if(audit.start&&audit.end){ psr=_raFmtDateShort(audit.start)+' → '+_raFmtDateShort(audit.end); }

  /* ── Helper: constat row ── */
  function buildConstatRows() {
    if(!findings.length) return '<tr><td colspan="4" style="text-align:center;color:#9ca3af;padding:20px;font-style:italic;">Aucun constat enregistré pour cet audit.</td></tr>';
    return findings.map(function(a, ni) {
      var cc = _raCritColor(a.criticite);
      return '<tr style="background:'+(ni%2===0?'#fff':'#f9fafb')+';">' +
        '<td style="padding:7px 10px;border-bottom:1px solid #e5e7eb;font-weight:600;color:#1a1a2e;font-size:10px;white-space:nowrap;">' + (a.code_anomalie||a.ref||a.id||'—') + '</td>' +
        '<td style="padding:7px 10px;border-bottom:1px solid #e5e7eb;"><span style="background:'+cc[1]+';color:'+cc[0]+';padding:2px 7px;border-radius:3px;font-size:9px;font-weight:700;">' + _raCritLabel(a.criticite) + '</span></td>' +
        '<td style="padding:7px 10px;border-bottom:1px solid #e5e7eb;font-size:10px;word-wrap:break-word;overflow-wrap:break-word;">' + (a.intitule||'—') + '</td>' +
        '<td style="padding:7px 10px;border-bottom:1px solid #e5e7eb;font-size:10px;color:#4b5563;">' + (a.impacte||'—') + '</td>' +
      '</tr>';
    }).join('');
  }

  /* ── Helper: recommandations détaillées — format guide IIA ── */
  function buildRecoSection() {
    if(!showRecos) return [];
    if(!findings.length) return [];

    var PAGE  = 'background:#fff;font-family:Arial,Helvetica,sans-serif;font-size:10.5px;color:#1a1a1a;border:0.5px solid #d3d1c7;border-radius:5px;overflow:hidden;margin-bottom:20px;page-break-inside:avoid;break-inside:avoid;';
    var HEAD  = 'background:#f9f8f6;border-bottom:0.5px solid #d3d1c7;padding:7px 12px;display:flex;align-items:flex-start;gap:8px;justify-content:space-between;';
    var ROW   = 'display:flex;border-bottom:0.5px solid #ede9e0;';
    var ROWL  = 'display:flex;';
    var LBL   = 'width:115px;min-width:115px;font-weight:bold;font-size:9px;color:#555;background:#faf9f7;border-right:0.5px solid #ede9e0;padding:6px 8px;line-height:1.4;';
    var VAL   = 'flex:1;padding:6px 10px;font-size:10px;color:#2c2c2a;line-height:1.5;';
    var VALW  = 'flex:1;padding:6px 10px;font-size:10px;color:#7a2a1a;line-height:1.5;';
    var VALE  = 'flex:1;padding:6px 10px;font-size:10px;color:#aaa;font-style:italic;line-height:1.5;';
    var DOT_R = 'width:16px;height:16px;min-width:16px;border-radius:50%;background:#c0392b;color:#fff;font-size:8px;font-weight:bold;display:inline-flex;align-items:center;justify-content:center;margin-top:1px;flex-shrink:0;';
    var DOT_G = 'width:16px;height:16px;min-width:16px;border-radius:50%;background:#888;color:#fff;font-size:8px;font-weight:bold;display:inline-flex;align-items:center;justify-content:center;margin-top:1px;flex-shrink:0;';
    var DOT_D = 'width:16px;height:16px;min-width:16px;border-radius:50%;background:#444;color:#fff;font-size:8px;font-weight:bold;display:inline-flex;align-items:center;justify-content:center;margin-top:1px;flex-shrink:0;';
    var ITEM  = 'display:flex;gap:7px;align-items:flex-start;margin-bottom:5px;';
    var ITEML = 'display:flex;gap:7px;align-items:flex-start;';

    var blocks = [];

    findings.forEach(function(a, fi) {
      var blockHtml = '';
      var cc    = _raCritColor(a.criticite);
      var recos = a.recommandations || [];

      var bCrit = '<span style="display:inline-block;padding:2px 8px;border-radius:3px;font-size:8.5px;font-weight:bold;white-space:nowrap;background:'+cc[0]+';color:#fff;">'+_raCritLabel(a.criticite)+'</span>';
      var bRef  = '<span style="display:inline-block;padding:2px 8px;border-radius:3px;font-size:8.5px;font-weight:bold;white-space:nowrap;background:#eee;color:#555;border:0.5px solid #ccc;">'+(a.code_anomalie||a.ref||a.id||'\u2014')+'</span>';

      blockHtml += '<div class="ra-constat-block" style="'+PAGE+'">';

      /* En-tête */
      blockHtml +=
        '<div style="'+HEAD+'">' +
          '<span style="color:#c0392b;font-weight:bold;font-size:10px;white-space:nowrap;padding-top:1px;">'+( fi+1)+'.</span>' +
          '<span style="font-size:11px;font-weight:bold;flex:1;line-height:1.4;">'+( a.intitule||a.findingTitle||'Constat sans titre')+'</span>' +
          '<div style="display:flex;gap:4px;align-items:center;flex-shrink:0;">'+bCrit+bRef+'</div>' +
        '</div>';

      /* Description */
      var descVal = (a.findingTitle||a.commentaire) ?
        (a.findingTitle||a.intitule||'\u2014') + (a.commentaire && a.commentaire !== a.findingTitle ? '<div style="margin-top:4px;color:#4b5563;">'+a.commentaire+'</div>' : '') :
        null;
      blockHtml +=
        '<div style="'+ROW+'">' +
          '<span style="'+LBL+'">Description</span>' +
          (descVal ?
            '<span style="'+VAL+'">'+descVal+'</span>' :
            '<span style="'+VALE+'">Description de l\'\u00e9tat actuel du processus audit\u00e9 et des crit\u00e8res d\'observation.</span>') +
        '</div>';

      /* Causes */
      blockHtml +=
        '<div style="'+ROW+'">' +
          '<span style="'+LBL+'">Causes</span>' +
          (a.causes ?
            '<span style="'+VAL+'">'+a.causes+'</span>' :
            '<span style="'+VALE+'">Explications de l\'\u00e9cart entre les crit\u00e8res de r\u00e9f\u00e9rence et les faits.</span>') +
        '</div>';

      /* Conséquences / Risques */
      var consVal = null;
      if(a.consequences||a.impacte) {
        consVal = (a.consequences||'');
      }
      blockHtml +=
        '<div style="'+ROW+'">' +
          '<span style="'+LBL+'">Risques</span>' +
          (consVal ?
            '<span style="'+VALW+'">'+consVal+'</span>' :
