      var recoItems = recos.length ?
        recos.map(function(r,ri){ var last=ri===recos.length-1; return '<div style="'+( last?ITEML:ITEM)+'"><span style="'+DOT_R+'">'+( ri+1)+'</span><span>'+( r.recommandation||'\u2014')+'</span></div>'; }).join('') :
        '<span style="color:#aaa;font-style:italic;">Aucune recommandation enregistr\u00e9e.</span>';
      blockHtml +=
        '<div style="'+ROW+'">' +
          '<span style="'+LBL+'">Recommandations</span>' +
          '<span style="'+VAL+'">'+recoItems+'</span>' +
        '</div>';

      /* Actions — dots gris */
      var actionItems = recos.length ?
        recos.map(function(r,ri){ var last=ri===recos.length-1; return '<div style="'+( last?ITEML:ITEM)+'"><span style="'+DOT_G+'">'+( ri+1)+'</span><span>'+( r.disposition||'<em style="color:#aaa;">Non renseign\u00e9</em>')+'</span></div>'; }).join('') :
        '<span style="color:#aaa;font-style:italic;">\u2014</span>';
      blockHtml +=
        '<div style="'+ROW+'">' +
          '<span style="'+LBL+'">Actions mises en \u0153uvre</span>' +
          '<span style="'+VAL+'">'+actionItems+'</span>' +
