      var LBL_ECH = 'width:60.43px;min-width:60.43px;font-weight:bold;font-size:9px;color:#555;background:#faf9f7;border-right:0.5px solid #ede9e0;border-left:0.5px solid #ede9e0;padding:6px 8px;line-height:1.4;text-align:right;';
      var VAL_ECH = 'width:97.75px;min-width:97.75px;max-width:97.75px;padding:6px 8px;font-size:10px;color:#2c2c2a;line-height:1.5;text-align:right;';

      var respItems = recos.length ?
        recos.map(function(r,ri){
          var last = ri===recos.length-1;
          var nom  = (r.responsable||'\u2014')+(r.fonction_responsable?' \u2014 '+r.fonction_responsable:'');
          return '<div style="'+( last?ITEML:ITEM)+'"><span style="'+DOT_D+'">'+( ri+1)+'</span><span>'+nom+'</span></div>';
        }).join('') :
        '<span style="color:#aaa;font-style:italic;">\u2014</span>';

      var echItems = recos.length ?
