          var last    = ri===recos.length-1;
          var dateStr = (r.echeance_revisee||r.echeance)?_raFmtDateShort(r.echeance_revisee||r.echeance):'\u2014';
          var isRev   = !!r.echeance_revisee;
          var dHtml   = isRev
            ? '<span style="color:#b45309;font-weight:600;white-space:nowrap;">'+dateStr+'</span><br><em style="font-size:8px;color:#9ca3af;">(r\u00e9vis\u00e9e)</em>'
            : '<span style="white-space:nowrap;">'+dateStr+'</span>';
          return '<div style="'+( last?ITEML:ITEM)+';justify-content:flex-end;">'+dHtml+'</div>';
        }).join('') :
        '<span style="color:#aaa;font-style:italic;">\u2014</span>';

      blockHtml +=
        '<div style="'+ROWL+'">' +
          /* Colonne Responsable — prend tout l'espace restant */
          '<div style="flex:1;display:flex;border-right:0.5px solid #ede9e0;">' +
            '<span style="'+LBL+'">Responsable de mises en \u0153uvre</span>' +
            '<span style="'+VAL+'">'+respItems+'</span>' +
          '</div>' +
          /* Colonne Échéance — largeur fixe, décalée à droite */
          '<div style="display:flex;flex-shrink:0;">' +
            '<span style="'+LBL_ECH+'">\u00c9ch\u00e9ance</span>' +
            '<span style="'+VAL_ECH+'">'+echItems+'</span>' +
          '</div>' +
        '</div>';

