    : (audit.societe ? '<div style="font-size:14px;font-weight:700;color:#374151;">'+audit.societe+'</div>' : '');

  html += '<div style="position:relative;width:210mm;height:297mm;padding:0 56px 0;display:flex;flex-direction:column;box-sizing:border-box;background:#fff;">' +

    /* ── LOGO SOCIÉTÉ MÈRE — haut-centre, position absolue dans le contenu ── */
