      '<div style="width:48px;height:3px;background:linear-gradient(90deg,#0070f2,#60a5fa);border-radius:2px;margin:4px auto;"></div>' +
      '<div style="margin:8px auto 0;background:'+opinionBg+';border:2px solid '+opinionColor+';border-radius:10px;padding:18px 36px;display:inline-block;">' +
