      '</div>' +

      /* Ligne basse : mention gauche | bloc filiale droite — dans le flux, jamais footer document */
      '<div style="display:flex;align-items:flex-end;justify-content:space-between;padding-top:12px;border-top:1px solid #e5e7eb;">' +
        '<div></div>' +
