          ? '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:5px;">' +
              '<div style="font-size:7px;font-weight:700;text-transform:uppercase;letter-spacing:.15em;color:#c0c8d4;">Entité auditée</div>' +
