      _raSectionTitle('1. Synthèse Exécutive') +
      /* KPI grid — 5 cases */
      '<div style="display:grid;grid-template-columns:repeat(5,1fr);gap:12px;margin-bottom:20px;">' +
        _raKpiBox(findings.length, 'Constats identifiés', '#111827', '#fff', '#1e40af') +
