        '<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.1em;color:'+opinionColor+';margin-bottom:4px;">Conclusion d\'Engagement</div>' +
        '<div style="font-size:14px;font-weight:800;color:'+opinionColor+';margin-bottom:6px;">'+opinion+'</div>' +
        '<div style="font-size:10.5px;color:#374151;line-height:1.6;">' +
          (opinionKey==='inadequat' ?
