      '</colgroup>' +
      '<thead><tr style="background:#1a3a5c;color:#fff;">' +
        '<th style="padding:8px 10px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.07em;border-right:1px solid #2d5a8c;white-space:nowrap;">Réf.</th>' +
        '<th style="padding:8px 10px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.07em;border-right:1px solid #2d5a8c;">Criticité</th>' +
        '<th style="padding:8px 10px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.07em;border-right:1px solid #2d5a8c;">Intitulé</th>' +
