      '</tr></thead>' +
      '<tbody>' + buildConstatRows() + '</tbody>' +
    '</table>' +

  '</div>';

  /* ── PAGE 3b : POINTS FORTS CONSTATÉS ── */
  (function(){
    var pfRaw = (audit.pointsForts||'').trim();
    var pfFromText = pfRaw ? pfRaw.split('\n').map(function(l){ var p=l.split('|'); return {processus:(p[0]||'').trim(),pointFort:(p[1]||'').trim(),impact:(p[2]||'').trim()}; }).filter(function(r){ return r.processus||r.pointFort; }) : [];
    var pfFromStore = (POINTS_FORTS||[]).filter(function(p){ return p.auditRef===audit.ref; });
    var pfRows = pfFromText.concat(pfFromStore);
    var TH = 'padding:9px 12px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.07em;border-right:1px solid #2d5a8c;white-space:nowrap;';
    var TD = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:10px;vertical-align:top;line-height:1.5;border-right:1px solid #e5e7eb;';
    var TDL = 'padding:8px 12px;border-bottom:1px solid #e5e7eb;font-size:10px;vertical-align:top;line-height:1.5;';
    var rows = pfRows.length ?
      pfRows.map(function(r,i){ return '<tr style="background:'+(i%2===0?'#fff':'#f9fafb')+';"><td style="'+TD+'font-weight:600;color:#1a3a5c;">'+r.processus+'</td><td style="'+TD+'color:#15803d;">'+r.pointFort+'</td><td style="'+TDL+'color:#1e40af;">'+r.impact+'</td></tr>'; }).join('') :
      '<tr><td colspan="3" style="padding:16px;text-align:center;color:#9ca3af;font-style:italic;font-size:10px;">Aucun point fort renseigné.</td></tr>';
    html += '<div style="padding:40px 56px;border-bottom:2px solid #e5e7eb;page-break-before:always;">' +
