      '<table style="width:100%;border-collapse:collapse;font-size:10.5px;">' +
        '<thead>' +
          '<tr style="background:#1a3a5c;color:#fff;">' +
            '<th style="padding:9px 14px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.07em;width:30%;border-right:1px solid #2d5a8c;">Opinion</th>' +
            '<th style="padding:9px 14px;text-align:left;font-size:9px;text-transform:uppercase;letter-spacing:.07em;">Signification</th>' +
          '</tr>' +
        '</thead>' +
        '<tbody>' +
          '<tr style="background:#fff;">' +
            '<td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;border-right:1px solid #e5e7eb;font-weight:700;color:#b91c1c;vertical-align:top;">' +
              '<span style="display:inline-block;background:#fee2e2;border:1px solid #fca5a5;border-radius:4px;padding:3px 8px;font-size:9.5px;">Système de contrôle interne inadéquat</span>' +
            '</td>' +
            '<td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;color:#374151;line-height:1.6;vertical-align:top;">Les constats font état de faiblesses significatives du contrôle et d&#x2019;un besoin urgent de mesures correctives. Au moment de l&#x2019;audit, les mesures en place ne sont pas suffisantes, ou ne progressent pas suffisamment, pour atténuer la gravité des lacunes identifiées.</td>' +
          '</tr>' +
          '<tr style="background:#fafafa;">' +
            '<td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;border-right:1px solid #e5e7eb;font-weight:700;color:#c05c00;vertical-align:top;">' +
              '<span style="display:inline-block;background:#fef0e4;border:1px solid #fdba74;border-radius:4px;padding:3px 8px;font-size:9.5px;">Système de contrôle interne adéquat, mais avec des réserves</span>' +
            '</td>' +
            '<td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;color:#374151;line-height:1.6;vertical-align:top;">Un certain nombre de constats, dont certains sont significatifs, ont été constatés. Lorsque des mesures ont été engagées pour remédier à ces constats et à d&#x2019;autres problèmes connus de la direction, elles en sont à un stade trop peu avancé pour que l&#x2019;on puisse formuler une opinion d&#x2019;audit satisfaisante.</td>' +
          '</tr>' +
          '<tr style="background:#fff;">' +
            '<td style="padding:10px 14px;border-right:1px solid #e5e7eb;font-weight:700;color:#15803d;vertical-align:top;">' +
              '<span style="display:inline-block;background:#dcfce7;border:1px solid #86efac;border-radius:4px;padding:3px 8px;font-size:9.5px;">Système de contrôle interne satisfaisant</span>' +
            '</td>' +
            '<td style="padding:10px 14px;color:#374151;line-height:1.6;vertical-align:top;">Les constats indiquent que, dans l&#x2019;ensemble, les contrôles sont satisfaisants, même si certaines améliorations peuvent être recommandées.</td>' +
          '</tr>' +
        '</tbody>' +
      '</table>' +
    '</div>' +


  '</div>';

  $root.html(html);
}

/* ══════════════════════════════════════════════════════════
   HELPER GLOBAL — En-tête imprimable commun à tous les documents
   Logo ARBIOCHEM (société dans Sociétés & Filiales dont nom contient
   "ARBIOCHEM", sinon premier logo disponible) + séparateur +
   "DIRECTION AUDIT & CONTRÔLE"
══════════════════════════════════════════════════════════ */
function _buildPrintHeader(options) {
  /* options = { ref:'', date:'', subtitle:'', societeNom:'' } */
  options = options || {};

  /* ── Trouver le logo ARBIOCHEM parmi les sociétés ── */
  var logoSrc = null;

  /* 1. Chercher société dont le nom contient "ARBIOCHEM" */
  var arbiSoc = (SOCIETES || []).find(function(s){
    return s.nom && s.nom.toUpperCase().indexOf('ARBIOCHEM') !== -1;
  });
  if(arbiSoc) logoSrc = getSocLogo(socKey(arbiSoc));

  /* 2. Fallback : logo de la société auditée (si fourni) */
  if(!logoSrc && options.societeNom) {
    var auditedSoc = (SOCIETES || []).find(function(s){
      return s.nom === options.societeNom;
    });
    if(auditedSoc) logoSrc = getSocLogo(socKey(auditedSoc));
  }

  /* 3. Fallback final : premier logo disponible */
  if(!logoSrc) {
    var allSocs = SOCIETES || [];
    for(var i = 0; i < allSocs.length; i++){
      var lu = getSocLogo(socKey(allSocs[i]));
      if(lu){ logoSrc = lu; break; }
    }
  }

  /* ── HTML de l'image logo ── */
  var logoHtml = logoSrc
    ? '<img src="' + logoSrc + '" style="height:44px;max-width:160px;object-fit:contain;" alt="Logo">'
    : '<div style="height:44px;display:flex;align-items:center;font-size:18px;font-weight:900;color:#0070f2;letter-spacing:-1px;">ARBIOCHEM</div>';

  /* ── Partie droite ── */
  var rightHtml = '';
  if(options.subtitle){
    rightHtml += '<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.12em;color:#1a1a2e;">' + options.subtitle + '</div>';
  }
  if(options.ref){
    rightHtml += '<div style="font-size:9px;color:#6b7280;margin-top:2px;">Réf. : <strong style="color:#1a1a2e;">' + options.ref + '</strong></div>';
  }


  return '<div style="display:flex;align-items:center;justify-content:space-between;padding-bottom:10px;border-bottom:2px solid #1a1a2e;margin-bottom:18px;">' +
    /* Gauche : logo au-dessus, DAC en dessous */
    '<div style="display:flex;flex-direction:column;align-items:flex-start;gap:4px;">' +
      logoHtml +
      '<div style="font-size:9px;font-weight:800;color:#1a1a2e;text-transform:uppercase;letter-spacing:.08em;line-height:1.3;">Direction Audit &amp; Contr&#244;le</div>' +
    '</div>' +
    /* Droite : infos doc */
    '<div style="text-align:right;">' + rightHtml + '</div>' +
  '</div>';
}

/* ── Helpers de mise en page ── */
function _raInfoRow(label, val) {
  return '<div>' +
    '<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#9ca3af;margin-bottom:2px;">'+label+'</div>' +
    '<div style="font-size:11px;color:#111827;font-weight:500;">'+val+'</div>' +
  '</div>';
}
function _raSectionTitle(title, norm) {
  return '<div style="margin-bottom:18px;">' +
    '<div style="font-size:14px;font-weight:800;color:#1a3a5c;border-left:4px solid #0070f2;padding-left:10px;">'+title+'</div>' +
  '</div>';
}
function _raKpiBox(val, label, textC, bgC, borderC) {
  return '<div style="background:'+bgC+';border:1px solid '+(borderC||'#e5e7eb')+';border-radius:8px;padding:14px 16px;text-align:center;">' +
    '<div style="font-size:24px;font-weight:900;color:'+textC+';">'+val+'</div>' +
    '<div style="font-size:9.5px;color:#6b7280;margin-top:3px;">'+label+'</div>' +
  '</div>';
}
function _raSignBox(role, name) {
  return '<div style="border:1px solid #e5e7eb;border-radius:6px;padding:14px;text-align:center;">' +
    '<div style="font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:#6b7280;margin-bottom:4px;">'+role+'</div>' +
    '<div style="font-size:11px;font-weight:600;color:#111827;margin-bottom:24px;">'+name+'</div>' +
    '<div style="height:1px;background:#e5e7eb;margin-bottom:4px;"></div>' +
    '<div style="font-size:9px;color:#9ca3af;">Date &amp; Signature</div>' +
  '</div>';
}

/* ── Event handlers ── */
$(document).on('change','#ra-select-audit,#ra-filter-criticite', function(){ renderRapportAudit(); _raUpdateWorkflow(); });
$(document).on('change','#ra-chk-executive,#ra-chk-recos', function(){ renderRapportAudit(); });
$(document).on('click','#ra-refresh-btn', function(){ _raPopulateAuditSelect(); renderRapportAudit(); _raUpdateWorkflow(); });

/* ── Workflow statut document ── */
function _raUpdateWorkflow() {
  var idx = parseInt($('#ra-select-audit').val());
  var $wf = $('#ra-statut-workflow');
  if(isNaN(idx) || !AUDITS[idx]) {
    $wf.css({opacity:'.4','pointer-events':'none'}).attr('title','Sélectionnez un audit pour modifier le statut');
    $wf.find('.ra-wf-btn').css({background:'#f3f4f6',color:'#6b7280','font-weight':'600'});
    return;
  }
  $wf.css({opacity:'1','pointer-events':'auto'}).attr('title','');
  var cur = AUDITS[idx].statut_doc || 'Projet de rapport';
  var colors = {
    'Projet de rapport':  { bg:'#eff6ff', color:'#1d4ed8', activeBg:'#1d4ed8', activeColor:'#fff' },
    'Rapport provisoire': { bg:'#fff7ed', color:'#c2410c', activeBg:'#c2410c', activeColor:'#fff' },
    'Rapport définitif':  { bg:'#f0fdf4', color:'#15803d', activeBg:'#16a34a', activeColor:'#fff' }
  };
  $wf.find('.ra-wf-btn').each(function(){
    var s = $(this).data('statut');
    var c = colors[s];
    if(s === cur) $(this).css({background:c.activeBg, color:c.activeColor, 'font-weight':'700'});
    else          $(this).css({background:'#f3f4f6',  color:'#6b7280',      'font-weight':'600'});
  });
}

$(document).on('click','.ra-wf-btn', function(){
  var idx = parseInt($('#ra-select-audit').val());
  if(isNaN(idx) || !AUDITS[idx]) return;
  var s = $(this).data('statut');
  AUDITS[idx].statut_doc = s;
  dbSave();
  _raUpdateWorkflow();
  renderRapportAudit();
});


$(document).on('click','#ra-print-btn', function(){
  var $root = $('#ra-a4-root');
  if(!$root.html().trim()){ alert('Veuillez d\'abord sélectionner un audit.'); return; }
  var idxStr = $('#ra-select-audit').val();
  var audit  = (AUDITS||[])[parseInt(idxStr)||0] || {};
  var title  = (audit.ref||'RA') + ' — ' + (audit.title||'Rapport');
  var content = $root.html();

  /* ═══════════════════════════════════════════════════════════════
     CSS A4 COMPLET — impression fidèle
     Principes :
       • @page : A4 portrait, marges 12mm (sauf haut 10mm pour header)
       • Chaque section du rapport est un .ra-section  → page-break-before:always
       • Tableaux : table-layout:fixed, word-wrap, pas de débordement
       • Blocs constat (.ra-constat-block) : break-inside:avoid
       • Couleurs préservées : -webkit-print-color-adjust:exact
       • Images (logos) préservées
  ═══════════════════════════════════════════════════════════════ */
  var CSS = [
    '*{margin:0;padding:0;box-sizing:border-box;}',
    '@page{size:210mm 297mm;margin:10mm 12mm 18mm 12mm;}',
    'body{background:#fff;font-family:"IBM Plex Sans","Segoe UI",Arial,sans-serif;font-size:10px;color:#1a1a2e;-webkit-print-color-adjust:exact;print-color-adjust:exact;}',
    '.ra-print-page{width:100%;}',
    '.ra-print-page > div{page-break-before:always;break-before:page;width:100%;box-sizing:border-box;}',
    '.ra-print-page > div:first-child{page-break-before:auto;break-before:auto;}',
    'table{width:100% !important;border-collapse:collapse;table-layout:fixed;word-wrap:break-word;font-size:9px;}',
    'th,td{word-wrap:break-word;overflow-wrap:break-word;max-width:0;}',
    'thead{display:table-header-group;}',
    'tfoot{display:table-footer-group;}',
    'tr{page-break-inside:avoid;break-inside:avoid;}',
    '.ra-constat-block{page-break-inside:avoid !important;break-inside:avoid !important;}',
    '[style*="display:grid"]{page-break-inside:avoid;break-inside:avoid;}',
    'img{max-width:100%;height:auto;}',
    '#ra-print-trigger{display:none;}',
    'a{text-decoration:none;color:inherit;}'
  ].join('\n');

  var fullHtml =
    '<!DOCTYPE html>' +
    '<html lang="fr">' +
    '<head>' +
      '<meta charset="utf-8">' +
      '<title>' + title + '</title>' +
      '<style>' + CSS + '</style>' +
    '</head>' +
    '<body>' +
    '<div class="ra-print-page">' + content + '</div>' +
    '</body></html>';

  /* Injecter le script auto-print via DOM après création du blob
     — évite tout problème d'échappement lié au contenu HTML          */
  var parser  = new DOMParser();
  var doc     = parser.parseFromString(fullHtml, 'text/html');
  var scr     = doc.createElement('script');
  scr.textContent = [
    'window.addEventListener("load", function(){',
    /* Numérotation JS : injecte un div de pied de page dans chaque section */
    '  var sections = document.querySelectorAll(".ra-print-page > div");',
    '  var total = sections.length;',
    '  sections.forEach(function(sec, idx){',
    '    if(idx === 0) return;',
    '    var footer = document.createElement("div");',
    '    footer.className = "ra-js-footer";',
    '    footer.innerHTML = "Confidentiel \u2013 Diffusion restreinte | Arbiochem-group"',
    '      + " &nbsp;&bull;&nbsp; "',
    '      + "Page " + (idx+1) + " sur " + total;',
    '    sec.appendChild(footer);',
    '  });',
    '  setTimeout(function(){ window.print(); }, 400);',
    '});',
    'window.addEventListener("afterprint", function(){',
    '  window.close();',
    '});'
  ].join('\n');
  doc.head.appendChild(scr);

  /* CSS du pied de page JS — injecté via DOM pour éviter l échappement */
  var footerStyle = doc.createElement('style');
  footerStyle.textContent =
    /* Chaque section A4 est le conteneur de référence du footer */
    '.ra-print-page > div{position:relative;box-sizing:border-box;min-height:297mm;padding-bottom:32px !important;}' +
    '.ra-js-footer{' +
      'position:absolute;bottom:14mm;left:56px;right:56px;' +
      'display:block;text-align:center;' +
      'font-family:"IBM Plex Sans",Arial,sans-serif;' +
      'font-size:7.5pt;color:#6b7280;letter-spacing:.04em;' +
      'padding:5px 0 0;border-top:0.5px solid #e5e7eb;' +
    '}' +
    '@media print{' +
      '.ra-js-footer{page-break-inside:avoid;break-inside:avoid;}' +
    '}';
  doc.head.appendChild(footerStyle);
  var finalHtml = '<!DOCTYPE html>' + doc.documentElement.outerHTML;

  /* Blob URL — indépendant des blocages de popups */
  var blob = new Blob([finalHtml], {type:'text/html;charset=utf-8'});
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href   = url;
  a.target = '_blank';
  a.rel    = 'noopener';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  /* Libérer l'URL après ouverture */
  setTimeout(function(){ URL.revokeObjectURL(url); }, 10000);
});

/* ══════════════════════════════════════════════════════════
   PRÉVISUALISATION RAPPORT D'AUDIT — Modale plein-écran
   Découpe le contenu A4 en sections navigables avec zoom
══════════════════════════════════════════════════════════ */
(function(){
  var _raModalZoom = 0.85;
  var _raModalZoomSteps = [0.50, 0.65, 0.75, 0.85, 1.0, 1.15, 1.3];
  var _raModalZoomIdx  = 3; /* index de départ: 0.85 */
  var _raActiveSec = 'cover';

  /* ── Labels des sections ── */
  var SEC_LABELS = {
    cover:    'Page de garde',
    exec:     'Synthèse exécutive',
    constats: 'Tableau des constats',
    pforts:   'Points forts',
    recos:    'Recommandations détaillées',
    annexe:   'Annexe — Référentiel'
  };

  /* ── Ouvre la modale ── */
  function raOpenPreview() {
    var $root = $('#ra-a4-root');
    if(!$root.html().trim()){
      alert('Veuillez d\'abord sélectionner un audit et cliquer sur Actualiser.');
      return;
    }

    /* Mettre à jour le titre */
    var idxStr = $('#ra-select-audit').val();
    var audit  = (AUDITS||[])[parseInt(idxStr)||0] || {};
    $('#ra-modal-title').text('Rapport — ' + (audit.ref||'') + (audit.title?' · '+audit.title:''));

    /* Construire les KPIs de la toolbar */
    var findings = (ACTIONS||[]).filter(function(a){
      return (a.societe && audit.societe && a.societe===audit.societe) ||
             (a.cycle   && audit.cycle   && a.cycle===audit.cycle)     ||
             (a.ref     && audit.ref     && a.ref===audit.ref);
    });
    var allRecos = [];
    findings.forEach(function(a){ (a.recommandations||[]).forEach(function(r){ allRecos.push({a:a,r:r}); }); });
    var total = allRecos.length;
    var fully = allRecos.filter(function(x){ return x.r.statut==='fully'; }).length;
    var txImpl = total>0 ? Math.round(fully/total*100) : 0;
    var cntCrit = findings.filter(function(a){ return a.criticite==='critical'; }).length;
    var cntHigh = findings.filter(function(a){ return a.criticite==='high'; }).length;

    var kpiHtml =
      _raMiniKpi(findings.length, 'Constats', '#1e40af', '#dbeafe') +
      _raMiniKpi(cntCrit, 'Critiques', '#b91c1c', '#fee2e2') +
      _raMiniKpi(cntHigh, 'Élevés', '#c05c00', '#fef0e4') +
      _raMiniKpi(txImpl+'%', 'Mise en oeuvre', '#15803d', '#dcfce7');
    $('#ra-modal-kpis').html(kpiHtml);

    /* Découper le contenu A4 en pages/sections */
    raRenderModalPages($root.html(), audit);

    /* Afficher la modale */
    $('#ra-modal-preview').css('display','flex');
    document.body.style.overflow = 'hidden';

    /* Activer la section "cover" */
    raActivateSection('cover');
    raApplyZoom();
  }

  function _raMiniKpi(val, label, color, bg) {
    return '<div style="background:'+bg+';border-radius:4px;padding:3px 8px;display:flex;flex-direction:column;align-items:center;min-width:42px;">' +
      '<span style="font-size:13px;font-weight:800;color:'+color+';line-height:1;">'+val+'</span>' +
      '<span style="font-size:8px;color:'+color+';opacity:.75;white-space:nowrap;">'+label+'</span>' +
    '</div>';
  }

  /* ── Découpe le HTML A4 en sections ── */
  function raRenderModalPages(a4Html, audit) {
    /* Cherche les séparateurs border-bottom dans le HTML du rapport */
    /* Les sections sont délimitées par des div avec border-bottom:2px solid */
    var $tmp = $('<div>').html(a4Html);
    var $divs = $tmp.children('div');

    /* Fallback : si la structure est plate, on utilise le tout en une page */
    var sections = [];
    if($divs.length >= 2) {
      $divs.each(function(i, el) {
        sections.push($(el).prop('outerHTML'));
      });
    } else {
      sections = [a4Html];
    }

    /* Associer les clés de section */
    var secKeys = ['cover','exec','constats','pforts','recos','annexe'];
    var $pages = $('#ra-modal-pages').empty();
    var $thumbs = $('#ra-modal-thumbs').empty();

    sections.forEach(function(secHtml, i) {
      var key = secKeys[i] || ('page-'+(i+1));
      var label = SEC_LABELS[key] || ('Page '+(i+1));

      /* Page A4 */
      var $page = $('<div>')
        .attr({'id':'ra-modal-page-'+key, 'data-sec':key})
        .css({
          width:'794px',
          background:'#fff',
          borderRadius:'3px',
          boxShadow:'0 6px 32px rgba(0,0,0,.35)',
          fontFamily:"'IBM Plex Sans','Segoe UI',Arial,sans-serif",
          fontSize:'11px',
          color:'#1a1a2e',
          boxSizing:'border-box',
          flexShrink:0,
          position:'relative'
        })
        .html(secHtml);
      $pages.append($page);

      /* Miniature */
      var $thumb = $('<div>')
        .attr('data-sec', key)
        .css({
          background: i===0 ? '#0070f2' : '#374151',
          color: i===0 ? '#fff' : '#d1d5db',
          border: '2px solid '+(i===0 ? '#0070f2':'#4b5563'),
          borderRadius:'4px',
          padding:'3px 9px',
          fontSize:'9px',
          cursor:'pointer',
          whiteSpace:'nowrap',
          fontWeight: i===0 ? '700' : '400',
          transition:'all .15s'
        })
        .text((i+1)+'. '+label)
        .on('click', function(){ raActivateSection(key); });
      $thumbs.append($thumb);
    });

    /* Mettre à jour le compteur */
    $('#ra-modal-page-info').text(sections.length + ' section(s)');
  }

  /* ── Scroll vers une section ── */
  function raActivateSection(key) {
    _raActiveSec = key;

    /* Mettre à jour les boutons nav */
    $('.ra-sec-btn').each(function(){
      var isActive = $(this).data('sec') === key;
      $(this).css({
        background: isActive ? '#0070f2' : '#374151',
        color: isActive ? '#fff' : '#d1d5db',
        fontWeight: isActive ? '700' : '400'
      });
    });

    /* Mettre à jour les miniatures */
    $('#ra-modal-thumbs > div').each(function(){
      var isActive = $(this).data('sec') === key;
      $(this).css({
        background: isActive ? '#0070f2' : '#374151',
        color: isActive ? '#fff' : '#d1d5db',
        border: '2px solid '+(isActive ? '#0070f2' : '#4b5563'),
        fontWeight: isActive ? '700' : '400'
      });
    });

    /* Scroll fluide vers la page */
    var $target = $('#ra-modal-page-'+key);
    if($target.length) {
      var $body = $('#ra-modal-body');
      var offset = $target.position() ? $target.position().top : 0;
      /* Prend en compte le zoom */
      $body.animate({ scrollTop: $body.scrollTop() + offset * _raModalZoom - 20 }, 300);
    }
  }

  /* ── Zoom ── */
  function raApplyZoom() {
    _raModalZoom = _raModalZoomSteps[_raModalZoomIdx];
    $('#ra-zoom-label').text(Math.round(_raModalZoom*100)+'%');
    $('#ra-modal-pages').css('transform','scale('+_raModalZoom+')');
    /* Ajuster hauteur du conteneur pour éviter le scroll inutile */
    var naturalH = $('#ra-modal-pages').height();
    $('#ra-modal-pages').css('margin-bottom', (naturalH * _raModalZoom - naturalH)+'px');
  }

  /* ── Fermeture ── */
  function raClosePreview() {
    $('#ra-modal-preview').css('display','none');
    document.body.style.overflow = '';
  }

  /* ── Event handlers ── */
  $(document).on('click','#ra-preview-btn', function(){
    raOpenPreview();
  });

  $(document).on('click','#ra-modal-close', function(){
    raClosePreview();
  });

  /* Fermer en cliquant en dehors du contenu */
  $(document).on('click','#ra-modal-preview', function(e){
    if(e.target.id === 'ra-modal-preview') raClosePreview();
  });

  /* Navigation sections */
  $(document).on('click','.ra-sec-btn', function(){
    raActivateSection($(this).data('sec'));
  });

  /* Zoom */
  $(document).on('click','#ra-zoom-in', function(){
    if(_raModalZoomIdx < _raModalZoomSteps.length-1){ _raModalZoomIdx++; raApplyZoom(); }
  });
  $(document).on('click','#ra-zoom-out', function(){
    if(_raModalZoomIdx > 0){ _raModalZoomIdx--; raApplyZoom(); }
  });
  $(document).on('click','#ra-zoom-fit', function(){
    /* Calculer le zoom adapté à la largeur de la fenêtre */
    var availW = $('#ra-modal-body').width() - 40;
    var fitted = Math.min(1.0, availW / 794);
    /* Trouver l'index le plus proche */
    var bestIdx = 0;
    _raModalZoomSteps.forEach(function(z,i){ if(Math.abs(z-fitted) < Math.abs(_raModalZoomSteps[bestIdx]-fitted)) bestIdx=i; });
    _raModalZoomIdx = bestIdx;
    raApplyZoom();
  });

  /* Bouton imprimer dans la modale */
  $(document).on('click','#ra-modal-print-btn', function(){
    $('#ra-print-btn').trigger('click');
  });

  /* Touche Escape */
  $(document).on('keydown', function(e){
    if(e.key==='Escape' && _elVisible($('#ra-modal-preview').e[0])) raClosePreview();
  });

})(); /* fin IIFE prévisualisation */

/* ══════════════════════════════════════════════
   RAPPORT RCM — Vue imprimable intégrée
   Conforme aux normes 2400–2440 des Standards IIA (IPPF 2017 / référence historique)
═══════════════════════════════════════════════ */
/* ── Sélecteur Mission → TERMES DE REFERENCE ── */
window._rrcmLoadedAudit = null;

function _rrcmPopulateAuditSelect(){
  const $sel = $('#rrcm-audit-select');
  const prev = $sel.val();
  $sel.find('option:not(:first-child)').remove();
  (AUDITS||[]).forEach(function(a,i){
    const label = a.ref + ' — ' + (a.title||'') + (a.societe?' ['+a.societe+']':'');
    $sel.append('<option value="'+i+'">'+label+'</option>');
  });
  if(prev) $sel.val(prev);
}

$(document).on('click','#rrcm-audit-load-btn',function(){
  const idx = parseInt($('#rrcm-audit-select').val());
  if(isNaN(idx)||idx<0||!AUDITS[idx]){ toast('error','!','Sélectionnez une mission dans la liste.'); return; }
  const a = AUDITS[idx];
  window._rrcmLoadedAudit = a;
  /* Pré-remplir le N° de mission */
  if(a.ref) $('#rrcm-mission-ref').val(a.ref);

  /* Pré-remplir le filtre Filiale depuis la société de la mission */
  if(a.societe){
    const $fi = $('#rrcm-f-filiale');
    if($fi.find('option[value="'+a.societe+'"]').length===0){
      $fi.append('<option value="'+a.societe+'">'+a.societe+'</option>');
    }
    $fi.val(a.societe);
  }

  /* Pré-remplir le filtre Cycle depuis le cycle de la mission */
  if(a.cycle){
    const $cy = $('#rrcm-f-cycle');
    if($cy.find('option[value="'+a.cycle+'"]').length===0){
      $cy.append('<option value="'+a.cycle+'">'+a.cycle+'</option>');
    }
    $cy.val(a.cycle);
  }

  /* Badge */
  $('#rrcm-audit-preview-badge').show().html('📌 <strong>'+a.ref+'</strong> · '+a.societe);

  /* Panneau prévisualisation rubriques */
  $('#rrcm-tdr-mission-label').text(a.ref + ' — ' + a.title);
  $('#rrcm-preview-contexte').text(a.contexte||'').css('font-style', a.contexte?'normal':'italic').html(
    a.contexte ? a.contexte.replace(/\n/g,'<br>') : '<span style="color:var(--text-dim);">Non renseigné</span>'
  );
  let objHtml = '';
  if(a.objGeneral) objHtml += '<div style="font-size:9.5px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">Objectif général</div><div style="margin-bottom:6px;">'+a.objGeneral+'</div>';
  if(a.objSpecifiques) objHtml += '<div style="font-size:9.5px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">Objectifs spécifiques</div><div>'+a.objSpecifiques.replace(/\n/g,'<br>')+'</div>';
  if(!objHtml) objHtml = '<span style="color:var(--text-dim);">Non renseigné</span>';
  $('#rrcm-preview-objectifs').html(objHtml);
  let perHtml = '';
  if(a.services) perHtml += '<div style="font-size:9.5px;font-weight:700;color:var(--text-muted);margin-bottom:2px;">Direction et Service Concernés</div><div style="margin-bottom:6px;">'+a.services+'</div>';
  if(!perHtml) perHtml = '<span style="color:var(--text-dim);">Non renseigné</span>';
  $('#rrcm-preview-perimetre').html(perHtml);
  $('#rrcm-tdr-sections-panel').show();

  _refreshRapportRCM();
  toast('success','📋','Mission chargée : '+a.ref);
});

$(document).on('click','#rrcm-audit-clear-btn',function(){
  window._rrcmLoadedAudit = null;
  $('#rrcm-mission-ref').val('');
  $('#rrcm-audit-preview-badge').hide();
  $('#rrcm-tdr-sections-panel').hide();
  /* Réinitialiser aussi les filtres Filiale et Cycle */
  $('#rrcm-f-filiale').val('');
  $('#rrcm-f-cycle').val('');
  _refreshRapportRCM();
});

/* Patcher buildTDRDoc pour injecter les données de l'audit dans les sections 1/2/3 */
const _buildTDRDocOrig = buildTDRDoc;
buildTDRDoc = function(data, filters){
  const html = _buildTDRDocOrig(data, filters);
  if(!window._rrcmLoadedAudit) return html;
  const a = window._rrcmLoadedAudit;

  /* Section 1 — Contexte */
  const newCtx = a.contexte
    ? '<p class="tdr-p2-text" style="white-space:pre-wrap;">'+a.contexte+'</p>'
    : '<p class="tdr-p2-text" style="color:#888;font-style:italic;">(Non renseigné)</p>';

  /* Section 2 — Objectifs */
  let newObj = '';
  if(a.objGeneral) newObj += '<p class="tdr-p2-sub-title">Objectif général :</p><p class="tdr-p2-text">'+a.objGeneral+'</p>';
  if(a.objSpecifiques){
    const lines = a.objSpecifiques.split('\n').filter(function(l){return l.trim();});
    newObj += '<p class="tdr-p2-sub-title">Objectifs spécifiques :</p><ul class="tdr-p2-list">'+lines.map(function(l){return '<li>'+l.replace(/^[-•]\s*/,'')+'</li>';}).join('')+'</ul>';
  }
  if(!newObj) newObj = '<p class="tdr-p2-text" style="color:#888;font-style:italic;">(Non renseigné)</p>';

  /* Section 3 — Périmètre */
  let newPer = '<p class="tdr-p2-sub-title">Périmètre organisationnel :</p><ul class="tdr-p2-list"><li><strong>Entité auditée :</strong> '+(a.societe||'—')+'</li>';
  if(a.services) newPer += '<li><strong>Direction et Service Concernés :</strong> '+a.services+'</li>';
  newPer += '</ul>';
  /* Période sous revue */
  if(a.periodeRevue && (a.periodeRevue.debMois || a.periodeRevue.finMois)) {
    const _mlbl = ['','Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
    const deb = (a.periodeRevue.debMois ? _mlbl[parseInt(a.periodeRevue.debMois,10)] : '') + (a.periodeRevue.debAnnee ? ' '+a.periodeRevue.debAnnee : '');
    const fin = (a.periodeRevue.finMois ? _mlbl[parseInt(a.periodeRevue.finMois,10)] : '') + (a.periodeRevue.finAnnee ? ' '+a.periodeRevue.finAnnee : '');
    const duree = a.periodeRevue.dureeM ? ' <span style="color:#555;font-size:8.5pt;">('+(a.periodeRevue.dureeM)+' mois)</span>' : '';
    newPer += '<p class="tdr-p2-sub-title">Période sous revue :</p><p class="tdr-p2-text">'+[deb,fin].filter(Boolean).join(' – ')+duree+'</p>';
  }

  const newEquipe = (function(){
    const chef = a.auditor || '';
    const sup  = a.superviseur || '';
    const membres = (Array.isArray(a.equipe) ? a.equipe : []).filter(function(m){ return m !== chef && m !== sup; });

    /* Helper : retrouver l'auditeur par son nom complet stocké (format "Prénom NOM") */
    function _findAud(nomComplet){
      if(!nomComplet) return null;
      return (AUDITEURS||[]).find(function(u){ return (u.prenom+' '+u.nom) === nomComplet; }) || null;
    }

    /* Helper : afficher en ordre NOM Prénom (NOM en gras majuscules, Prénom normal) */
    function _displayNom(nomComplet){
      if(!nomComplet) return '';
      var aud = _findAud(nomComplet);
      if(aud){
        return '<strong>'+aud.nom+'</strong> '+aud.prenom;
      }
      /* Fallback : le nom stocké est "Prénom NOM" — on tente de séparer au premier espace */
      var idx = nomComplet.indexOf(' ');
      if(idx < 0) return '<strong>'+nomComplet+'</strong>';
      var prenomPart = nomComplet.slice(0, idx);
      var nomPart    = nomComplet.slice(idx+1);
      return '<strong>'+nomPart+'</strong> '+prenomPart;
    }

    /* Helper : retrouver le rôle/fonction */
    function _getFonction(nomComplet){
      var aud = _findAud(nomComplet);
      if(!aud) return '';
      return [aud.role, aud.poste].filter(Boolean).join(' — ');
    }

    /* Construction en liste — même style que les sections 1/2/3 */
    var html = '';

    html += '<p class="tdr-p2-sub-title">Supervision :</p>';
    html += '<p class="tdr-p2-text">'+(sup ? _displayNom(sup)+(_getFonction(sup) ? ' <span style="color:#555;font-size:8.5pt;">— '+_getFonction(sup)+'</span>' : '') : '<span style="color:#888;font-style:italic;">Non renseigné</span>')+'</p>';

    html += '<p class="tdr-p2-sub-title">Chef de mission :</p>';
    html += '<p class="tdr-p2-text">'+(chef ? _displayNom(chef)+(_getFonction(chef) ? ' <span style="color:#555;font-size:8.5pt;">— '+_getFonction(chef)+'</span>' : '') : '<span style="color:#888;font-style:italic;">Non renseigné</span>')+'</p>';

    html += '<p class="tdr-p2-sub-title">Membres de l\'équipe :</p>';
    if(membres.length){
      html += '<ul class="tdr-p2-list">'+membres.map(function(m){
        var fn = _getFonction(m);
        return '<li>'+_displayNom(m)+(fn ? ' <span style="color:#555;font-size:8.5pt;">— '+fn+'</span>' : '')+'</li>';
      }).join('')+'</ul>';
    } else {
      html += '<p class="tdr-p2-text" style="color:#888;font-style:italic;">Aucun membre renseigné</p>';
    }

    return html;
  })();

  /* Remplacements dans le HTML généré */
  const tmp = document.createElement('div');
  tmp.innerHTML = html;

  /* Trouver les blocs éditables des sections 1/2/3/4 */
  const sectionTitles = tmp.querySelectorAll('.tdr-p2-section-title');
  sectionTitles.forEach(function(el){
    const txt = el.textContent.trim();
    const editable = el.nextElementSibling;
    if(!editable) return;
    if(txt.startsWith('1. Contexte')) editable.innerHTML = newCtx;
    else if(txt.startsWith('2. Objectifs')) editable.innerHTML = newObj;
    else if(txt.startsWith('3. Périmètre')) editable.innerHTML = newPer;
    else if(txt.startsWith('4. Équipe')) editable.innerHTML = newEquipe;
  });

  return tmp.innerHTML;
};

function renderRapportRCM() {
  /* Peupler les filtres depuis RCM_DATA */
  const $fi = $('#rrcm-f-filiale');
  const $cy = $('#rrcm-f-cycle');

  const prevFi = $fi.val();
  const prevCy = $cy.val();

  const filiales = [...new Set(RCM_DATA.map(r => r.filiale).filter(Boolean))].sort();
  const _dbCyc2  = RCM_DATA.map(r => r.cycle).filter(Boolean);
  const cycles   = [...new Set([...Object.keys(RCM_CYCLES), ..._dbCyc2])];

  $fi.html('<option value="">Toutes filiales</option>' + filiales.map(f => `<option value="${f}">${f}</option>`).join(''));
  $cy.html('<option value="">Tous les cycles</option>' + cycles.map(c => `<option value="${c}">${c}</option>`).join(''));

  if(prevFi) $fi.val(prevFi);
  if(prevCy) $cy.val(prevCy);

  _refreshRapportRCM();
}

function _refreshRapportRCM() {
  const fFiliale = $('#rrcm-f-filiale').val() || '';
  const fCycle   = $('#rrcm-f-cycle').val()   || '';
  const fLevel   = $('#rrcm-f-level').val()   || '';

  let data = RCM_DATA.filter(r => {
    // Filiale : afficher simultanément "Toutes filiales" ET la filiale sélectionnée
    if(fFiliale && fFiliale !== 'Toutes filiales') {
      if(r.filiale !== fFiliale && r.filiale !== 'Toutes filiales') return false;
    }
    if(fCycle && r.cycle !== fCycle) return false;
    if(fLevel) {
      const s = r.residuel || 0;
      if(fLevel === 'high'   && s < 10)           return false;
      if(fLevel === 'medium' && (s < 5 || s >= 10)) return false;
      if(fLevel === 'low'    && s >= 5)            return false;
    }
    return true;
  });

  // Tri par cycle puis par processus
  data.sort((a, b) => {
    const cA = (a.cycle || '').localeCompare(b.cycle || '', 'fr');
    if(cA !== 0) return cA;
    return (a.processus || '').localeCompare(b.processus || '', 'fr');
  });

  const filters = { filiale: fFiliale, cycle: fCycle, niveau: fLevel };

  if(!data.length) {
    $('#rrcm-preview').html(
      '<div style="text-align:center;padding:60px 20px;color:#888;font-size:13px;">Aucune entrée RCM pour les filtres sélectionnés.</div>'
    );
    return;
  }

  /* Génère le HTML TDR et l'injecte dans la prévisualisation */
  filters.missionRef = ($('#rrcm-mission-ref').val()||'').trim();
  filters.planRef = (window._rrcmLoadedAudit && window._rrcmLoadedAudit.planRef) ? window._rrcmLoadedAudit.planRef.trim() : '';
  const html = buildTDRDoc(data, filters);

  /* Mise à jour de l'indicateur de filtres actifs */
  const $af = $('#rrcm-active-filters');
  if(fFiliale || fCycle || fLevel) {
    $af.show();
    if(fFiliale) { $('#rrcm-af-filiale').show(); $('#rrcm-af-filiale-val').text(fFiliale); }
    else $('#rrcm-af-filiale').hide();
    if(fCycle) { $('#rrcm-af-cycle').show(); $('#rrcm-af-cycle-val').text(fCycle); }
    else $('#rrcm-af-cycle').hide();
    if(fLevel) {
      $('#rrcm-af-level').show();
      $('#rrcm-af-level-val').text(fLevel==='high'?'Élevé / Critique':fLevel==='medium'?'Moyen':'Faible');
    } else $('#rrcm-af-level').hide();
  } else {
    $af.hide();
  }

  /* Encapsule dans un conteneur "page blanche" style impression */
  $('#rrcm-preview').html(
    `<div style="
      background:#fff;
      box-shadow:0 2px 16px rgba(0,0,0,.18);
      border-radius:6px;
      overflow:hidden;
      max-width:960px;
      margin:0 auto;
    ">${html}</div>`
  );
}

/* Filtres → refresh automatique */
$(document).on('change', '#rrcm-f-filiale, #rrcm-f-cycle, #rrcm-f-level', () => _refreshRapportRCM());

/* Bouton Imprimer */
$(document).on('click', '#rrcm-print-btn', () => {
  if(!RCM_DATA.length) { toast('error','!','Aucune entrée RCM à imprimer.'); return; }

  const fFiliale = $('#rrcm-f-filiale').val() || '';
  const fCycle   = $('#rrcm-f-cycle').val()   || '';
  const fLevel   = $('#rrcm-f-level').val()   || '';

  let data = RCM_DATA.filter(r => {
    // Filiale : afficher simultanément "Toutes filiales" ET la filiale sélectionnée
    if(fFiliale && fFiliale !== 'Toutes filiales') {
      if(r.filiale !== fFiliale && r.filiale !== 'Toutes filiales') return false;
    }
    if(fCycle && r.cycle !== fCycle) return false;
    if(fLevel) {
      const s = r.residuel || 0;
      if(fLevel === 'high'   && s < 10)            return false;
      if(fLevel === 'medium' && (s < 5 || s >= 10)) return false;
      if(fLevel === 'low'    && s >= 5)             return false;
    }
    return true;
  });

  // Tri par cycle puis par processus
  data.sort((a, b) => {
    const cA = (a.cycle || '').localeCompare(b.cycle || '', 'fr');
    if(cA !== 0) return cA;
    return (a.processus || '').localeCompare(b.processus || '', 'fr');
  });

  if(!data.length) { toast('error','!','Aucune entrée RCM pour les filtres sélectionnés.'); return; }

  const missionRef = $('#rrcm-mission-ref').val().trim();
  const planRef = (window._rrcmLoadedAudit && window._rrcmLoadedAudit.planRef) ? window._rrcmLoadedAudit.planRef.trim() : '';
  const filters = { filiale: fFiliale, cycle: fCycle, niveau: fLevel, missionRef: missionRef, planRef: planRef };
  const $area3 = $('#om-print-area');
  $area3.html(buildTDRDoc(data, filters)).show();
  _tdrInjectPageNumbers($area3.get(0));
  /* ── Titre identifiable dans la boîte de dialogue d'impression ── */
  const _prevTitle = document.title;
  document.title = 'Termes de Référence (TDR)' + (missionRef ? ' — ' + missionRef : '') + (fFiliale ? ' — ' + fFiliale : '');
  window.print();
  setTimeout(() => {
    document.title = _prevTitle;
    $('#om-print-area').hide().empty();
  }, 1500);
});
let RENDEZ_VOUS = [];
try { const s=localStorage.getItem('dac_rdv'); if(s) RENDEZ_VOUS=JSON.parse(s)||[]; } catch(e){}

function dbSaveRDV(){
  try { localStorage.setItem('dac_rdv', JSON.stringify(RENDEZ_VOUS)); } catch(e){}
}

let ucalZoom  = 'month';
let ucalYear  = new Date().getFullYear();
let ucalMonth = new Date().getMonth();
let ucalDay   = new Date().getDate();

function ucalGetEvents() {
  const evs = [];
  const showM   = $('#ucal-show-missions').prop('checked');
  const showT   = $('#ucal-show-tasks').prop('checked');
  const showA   = $('#ucal-show-absences').prop('checked');
  const showR   = $('#ucal-show-rdv').prop('checked');

  if(showM) {
    (GANTT_MISSIONS||[]).forEach(m=>{
      if(!m.start||!m.end) return;
      const st = ganttStatusOf(m);
      const col = st==='late'?'#ef4444':st==='completed'?'#22c55e':'#3b82f6';
      evs.push({id:'M-'+m.id, type:'mission', title:'📋 '+(m.title||m.id), start:m.start, end:m.end,
        color:col, textColor:'#fff', desc:'Mission · '+(m.societe||'')+(m.chef?' · Chef: '+m.chef:''),
        badge:st==='late'?'⚠️':st==='completed'?'✅':'🔵'});
    });
  }

  if(showT) {
    (GANTT_MISSIONS||[]).forEach(m=>{
      (m.tasks||[]).forEach(t=>{
        if(!t.start||!t.end||t.type==='milestone') return;
        evs.push({id:'T-'+t.id, type:'task', title:'✅ '+t.title, start:t.start, end:t.end||t.start,
          color:'#1e9c6a', textColor:'#fff', desc:'Tâche de '+(m.title||m.id)+(t.assignees&&t.assignees.length?' · '+t.assignees[0]:'')});
      });
      // Jalons
      (m.tasks||[]).filter(t=>t.type==='milestone'&&t.start).forEach(t=>{
        evs.push({id:'ML-'+t.id, type:'milestone', title:'🏁 '+t.title, start:t.start, end:t.start,
          color:'#f59e0b', textColor:'#fff', desc:'Jalon · '+(m.title||m.id), isDiamond:true});
      });
    });
  }

  if(showA) {
    const ATYPE = {conge:{c:'#e67e22',l:'Congé'},maladie:{c:'#ef4444',l:'Maladie'},formation:{c:'#6941c6',l:'Formation'},recuperation:{c:'#0891b2',l:'Récup.'}};
    (ABSENCES||[]).filter(a=>a.statut==='valide').forEach(a=>{
      const at = ATYPE[a.type]||{c:'#e67e22',l:'Absence'};
      evs.push({id:'A-'+a.id, type:'absence', title:'🏖️ '+a.auditeur.split(' ')[0]+' — '+at.l,
        start:a.debut, end:a.fin, color:at.c, textColor:'#fff',
        desc:at.l+' · '+a.auditeur+(a.note?' · '+a.note:''), absData:a});
    });
  }

  // Rendez-vous
  if(showR) {
    (RENDEZ_VOUS||[]).forEach(r=>{
      evs.push({id:'R-'+r.id, type:'rdv', title:'📌 '+r.titre, start:r.date, end:r.dateFin||r.date,
        color:'#8b5cf6', textColor:'#fff',
        desc:(r.lieu?'📍 '+r.lieu+' · ':'')+r.description+(r.participants?' · '+r.participants:''),
        rdvData:r});
    });
  }

  return evs;
}

// ── Helpers ───────────────────────────────────────────────────
function ucalParseDate(s){ if(!s)return null; const p=s.split('-'); return new Date(+p[0],+p[1]-1,+p[2]); }
function ucalDateStr(d){ return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'); }
function ucalEventsOnDay(evs, dateStr){
  return evs.filter(e=>{
    if(!e.start) return false;
    return dateStr >= e.start.slice(0,10) && dateStr <= (e.end||e.start).slice(0,10);
  });
}
const UCAL_MONTHS = ['Janvier','Février','Mars','Avril','Mai','Juin','Juillet','Août','Septembre','Octobre','Novembre','Décembre'];
const UCAL_DAYS_S = ['Lun','Mar','Mer','Jeu','Ven','Sam','Dim'];
const UCAL_DAYS_F = ['Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi','Dimanche'];

function ucalPeriodLabel(){
  if(ucalZoom==='day')   return UCAL_DAYS_F[((new Date(ucalYear,ucalMonth,ucalDay).getDay()+6)%7)]+' '+ucalDay+' '+UCAL_MONTHS[ucalMonth]+' '+ucalYear;
  if(ucalZoom==='week'){
    const mon = new Date(ucalYear,ucalMonth,ucalDay);
    const dow = (mon.getDay()+6)%7;
    mon.setDate(mon.getDate()-dow);
    const sun = new Date(mon); sun.setDate(sun.getDate()+6);
    return mon.getDate()+' '+UCAL_MONTHS[mon.getMonth()].slice(0,3)+' — '+sun.getDate()+' '+UCAL_MONTHS[sun.getMonth()].slice(0,3)+' '+ucalYear;
  }
  if(ucalZoom==='month') return UCAL_MONTHS[ucalMonth]+' '+ucalYear;
  return 'Année '+ucalYear;
}

function ucalChip(e, compact){
  const maxLen = compact ? 18 : 32;
  const label = e.title.length > maxLen ? e.title.slice(0,maxLen)+'…' : e.title;
  return '<div class="ucal-ev" data-evid="'+e.id+'" title="'+e.title+(e.desc?'\n'+e.desc:'')+'" '+
    'style="background:'+e.color+';color:'+(e.textColor||'#fff')+';border-radius:3px;padding:1px 5px;font-size:'+(compact?'9':'10')+'px;font-weight:600;'+
    'white-space:nowrap;overflow:hidden;text-overflow:ellipsis;cursor:pointer;margin-bottom:1px;'+
    (e.isDiamond?'text-align:center;':'')+'">'+label+'</div>';
}

// ── VIEW: DAY ─────────────────────────────────────────────────
function ucalRenderDay(evs){
  const dateStr = ucalDateStr(new Date(ucalYear,ucalMonth,ucalDay));
  const dayEvs  = ucalEventsOnDay(evs, dateStr);
  const today   = ucalDateStr(new Date());
  const isToday = dateStr===today;

  let h = '<div style="padding:16px;">';
  h += '<div style="font-size:13px;font-weight:700;color:var(--text);margin-bottom:14px;display:flex;align-items:center;gap:8px;">'+
    '<span style="width:36px;height:36px;border-radius:50%;background:'+(isToday?'var(--accent)':'var(--surface2)')+';color:'+(isToday?'#fff':'var(--text)')+
    ';display:grid;place-items:center;font-size:16px;font-weight:800;">'+ucalDay+'</span>'+
    UCAL_MONTHS[ucalMonth]+' '+ucalYear+'</div>';

  if(!dayEvs.length){
    h += '<div style="text-align:center;padding:40px;color:var(--text-muted);font-size:12px;">Aucun événement ce jour</div>';
  } else {

    const groups = [{key:'mission',icon:'📋',label:'Missions'},{key:'task',icon:'✅',label:'Tâches'},{key:'milestone',icon:'🏁',label:'Jalons'},{key:'absence',icon:'🏖️',label:'Absences'},{key:'rdv',icon:'📌',label:'Rendez-vous'}];
    groups.forEach(g=>{
      const gEvs = dayEvs.filter(e=>e.type===g.key);
      if(!gEvs.length) return;
      h += '<div style="margin-bottom:14px;"><div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.08em;color:var(--text-muted);margin-bottom:6px;">'+g.icon+' '+g.label+'</div>';
      gEvs.forEach(e=>{
        h += '<div class="ucal-ev" data-evid="'+e.id+'" style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;border:1px solid var(--border);border-left:4px solid '+e.color+';border-radius:5px;margin-bottom:6px;cursor:pointer;background:var(--surface);transition:background .12s;">'+
          '<div style="flex:1;"><div style="font-size:12.5px;font-weight:600;color:var(--text);">'+e.title+'</div>'+
          (e.desc?'<div style="font-size:11px;color:var(--text-muted);margin-top:3px;">'+e.desc+'</div>':'')+
          '<div style="font-size:10px;color:var(--text-dim);margin-top:3px;">'+e.start+(e.end&&e.end!==e.start?' → '+e.end:'')+'</div></div>'+
          '<div style="width:10px;height:10px;border-radius:50%;background:'+e.color+';flex-shrink:0;margin-top:3px;"></div></div>';
      });
      h += '</div>';
    });
  }
  h += '</div>';
  return h;
}

// ── VIEW: WEEK ────────────────────────────────────────────────
function ucalRenderWeek(evs){
  const mon = new Date(ucalYear,ucalMonth,ucalDay);
  const dow = (mon.getDay()+6)%7;
  mon.setDate(mon.getDate()-dow);
  const today = ucalDateStr(new Date());

  let h = '<div>';
  // Header row
  h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);border-bottom:2px solid var(--border);background:var(--surface2);">';
  for(let i=0;i<7;i++){
    const d = new Date(mon); d.setDate(d.getDate()+i);
    const ds = ucalDateStr(d);
    const isT = ds===today;
    const isWk = d.getDay()===0||d.getDay()===6;
    h += '<div style="padding:8px 6px;text-align:center;border-right:'+(i<6?'1px solid var(--border)':'none')+';">'+
      '<div style="font-size:9.5px;font-weight:600;color:var(--text-muted);text-transform:uppercase;">'+UCAL_DAYS_S[i]+'</div>'+
      '<div style="width:26px;height:26px;border-radius:50%;margin:3px auto 0;display:grid;place-items:center;font-size:13px;font-weight:700;'+
      'background:'+(isT?'var(--accent)':'transparent')+';color:'+(isT?'#fff':isWk?'var(--text-muted)':'var(--text)')+';">'+d.getDate()+'</div></div>';
  }
  h += '</div>';
  // Body
  h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);min-height:400px;">';
  for(let i=0;i<7;i++){
    const d = new Date(mon); d.setDate(d.getDate()+i);
    const ds = ucalDateStr(d);
    const isT = ds===today;
    const isWk = d.getDay()===0||d.getDay()===6;
    const dayEvs = ucalEventsOnDay(evs, ds);
    h += '<div style="border-right:'+(i<6?'1px solid var(--border)':'none')+';padding:4px;min-height:380px;background:'+(isWk?'rgba(0,0,0,.018)':isT?'rgba(0,112,242,.03)':'transparent')+';">';
    dayEvs.forEach(e=>{ h += ucalChip(e,true); });
    h += '</div>';
  }
  h += '</div></div>';
  return h;
}

// ── VIEW: MONTH ───────────────────────────────────────────────
function ucalRenderMonth(evs){
  const today = ucalDateStr(new Date());
  const firstDay = new Date(ucalYear,ucalMonth,1);
  const lastDay  = new Date(ucalYear,ucalMonth+1,0);
  const startDow = (firstDay.getDay()+6)%7; // Mon-based

  let h = '<div>';
  // Day headers
  h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);background:var(--surface2);border-bottom:1px solid var(--border);">';
  UCAL_DAYS_S.forEach((d,i)=>{
    const isWk = i>=5;
    h += '<div style="padding:7px 4px;text-align:center;font-size:9.5px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:'+(isWk?'var(--text-dim)':'var(--text-muted)')+';">'+d+'</div>';
  });
  h += '</div>';
  // Grid
  h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);">';
  // Empty cells before month start
  for(let i=0;i<startDow;i++){
    const prev = new Date(ucalYear,ucalMonth,1-startDow+i);
    h += '<div style="min-height:90px;padding:4px;border-right:1px solid var(--border);border-bottom:1px solid var(--border);background:rgba(0,0,0,.016);"><div style="font-size:10px;color:var(--text-dim);margin-bottom:2px;">'+prev.getDate()+'</div></div>';
  }
  // Month days
  for(let day=1;day<=lastDay.getDate();day++){
    const d = new Date(ucalYear,ucalMonth,day);
    const ds = ucalDateStr(d);
    const dow = (d.getDay()+6)%7;
    const isT = ds===today;
    const isWk = d.getDay()===0||d.getDay()===6;
    const dayEvs = ucalEventsOnDay(evs,ds);
    const col = (startDow+day-1)%7;
    h += '<div class="ucal-day-cell" data-date="'+ds+'" style="min-height:90px;padding:3px 4px;border-right:'+(col<6?'1px solid var(--border)':'none')+';border-bottom:1px solid var(--border);'+
      'background:'+(isWk?'rgba(0,0,0,.018)':isT?'rgba(0,112,242,.05)':'transparent')+';vertical-align:top;cursor:pointer;">';
    h += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:2px;">'+
      '<div style="width:20px;height:20px;border-radius:50%;display:grid;place-items:center;font-size:11px;font-weight:'+(isT?'800':'600')+';'+
      'background:'+(isT?'var(--accent)':'transparent')+';color:'+(isT?'#fff':isWk?'var(--text-dim)':'var(--text)')+';">'+day+'</div>'+
      (dayEvs.length>3?'<span style="font-size:9px;color:var(--text-dim);">+'+dayEvs.length+'</span>':'')+
    '</div>';
    dayEvs.slice(0,3).forEach(e=>{ h += ucalChip(e,true); });
    h += '</div>';
  }
  // Trailing cells
  const total = startDow + lastDay.getDate();
  const trailing = (7 - total%7)%7;
  for(let i=1;i<=trailing;i++){
    const col = (startDow+lastDay.getDate()+i-1)%7;
    h += '<div style="min-height:90px;padding:4px;border-right:'+(col<6?'1px solid var(--border)':'none')+';border-bottom:1px solid var(--border);background:rgba(0,0,0,.016);"><div style="font-size:10px;color:var(--text-dim);margin-bottom:2px;">'+i+'</div></div>';
  }
  h += '</div></div>';
  return h;
}

// ── VIEW: YEAR ────────────────────────────────────────────────
function ucalRenderYear(evs){
  let h = '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:var(--border);">';
  for(let m=0;m<12;m++){
    const firstDay = new Date(ucalYear,m,1);
    const lastDay  = new Date(ucalYear,m+1,0);
    const startDow = (firstDay.getDay()+6)%7;
    const today = ucalDateStr(new Date());
    h += '<div style="background:var(--surface);padding:10px;">';
    h += '<div style="font-size:11px;font-weight:700;color:var(--text);margin-bottom:6px;cursor:pointer;" class="ucal-year-month" data-m="'+m+'">'+UCAL_MONTHS[m]+'</div>';
    h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);gap:1px;margin-bottom:3px;">';
    UCAL_DAYS_S.forEach(d=>{ h += '<div style="font-size:7.5px;color:var(--text-dim);text-align:center;font-weight:600;">'+d[0]+'</div>'; });
    h += '</div>';
    h += '<div style="display:grid;grid-template-columns:repeat(7,1fr);gap:1px;">';
    for(let i=0;i<startDow;i++) h += '<div></div>';
    for(let day=1;day<=lastDay.getDate();day++){
      const ds = ucalYear+'-'+String(m+1).padStart(2,'0')+'-'+String(day).padStart(2,'0');
      const dayEvs = ucalEventsOnDay(evs,ds);
      const isT = ds===today;
      const d = new Date(ucalYear,m,day);
      const isWk = d.getDay()===0||d.getDay()===6;
      const dotColor = dayEvs.length ? dayEvs[0].color : 'transparent';
      h += '<div style="font-size:8.5px;text-align:center;cursor:pointer;border-radius:50%;padding:1px 0;position:relative;' +
        'background:'+(isT?'var(--accent)':'transparent')+';color:'+(isT?'#fff':isWk?'var(--text-dim)':'var(--text)')+';font-weight:'+(isT?'700':'400')+';" '+
        'class="ucal-year-day" data-date="'+ds+'" title="'+dayEvs.map(e=>e.title).join(', ')+'">'+day+
        (dayEvs.length?'<span style="position:absolute;bottom:-1px;left:50%;transform:translateX(-50%);width:4px;height:4px;border-radius:50%;background:'+dotColor+';display:block;"></span>':'')+
        '</div>';
    }
    h += '</div></div>';
  }
  h += '</div>';
  return h;
}

// ── Main render ───────────────────────────────────────────────
function renderUCal(){
  const evs = ucalGetEvents();
  $('#ucal-period-label').text(ucalPeriodLabel());
  let html = '';
  if(ucalZoom==='day')   html = ucalRenderDay(evs);
  else if(ucalZoom==='week')  html = ucalRenderWeek(evs);
  else if(ucalZoom==='month') html = ucalRenderMonth(evs);
  else                        html = ucalRenderYear(evs);
  $('#ucal-body').html(html);
}

$(document).on('click','.ucal-zoom-btn',function(){
  $('.ucal-zoom-btn').css({background:'var(--surface2)',color:'var(--text-muted)'});
  $(this).css({background:'var(--accent)',color:'#fff'});
  ucalZoom=$(this).data('zoom');
  renderUCal();
});

$(document).on('click','#ucal-today',function(){
  const t=new Date(); ucalYear=t.getFullYear(); ucalMonth=t.getMonth(); ucalDay=t.getDate(); renderUCal();
});

$(document).on('click','#ucal-prev',function(){
  if(ucalZoom==='day'){const d=new Date(ucalYear,ucalMonth,ucalDay-1);ucalYear=d.getFullYear();ucalMonth=d.getMonth();ucalDay=d.getDate();}
  else if(ucalZoom==='week'){const d=new Date(ucalYear,ucalMonth,ucalDay-7);ucalYear=d.getFullYear();ucalMonth=d.getMonth();ucalDay=d.getDate();}
  else if(ucalZoom==='month'){ucalMonth--;if(ucalMonth<0){ucalMonth=11;ucalYear--;}}
  else{ucalYear--;}
  renderUCal();
});

$(document).on('click','#ucal-next',function(){
  if(ucalZoom==='day'){const d=new Date(ucalYear,ucalMonth,ucalDay+1);ucalYear=d.getFullYear();ucalMonth=d.getMonth();ucalDay=d.getDate();}
  else if(ucalZoom==='week'){const d=new Date(ucalYear,ucalMonth,ucalDay+7);ucalYear=d.getFullYear();ucalMonth=d.getMonth();ucalDay=d.getDate();}
  else if(ucalZoom==='month'){ucalMonth++;if(ucalMonth>11){ucalMonth=0;ucalYear++;}}
  else{ucalYear++;}
  renderUCal();
});

$(document).on('click','.ucal-day-cell',function(){
  const ds=$(this).data('date'); if(!ds)return;
  const p=ds.split('-'); ucalYear=+p[0];ucalMonth=+p[1]-1;ucalDay=+p[2];
  ucalZoom='day';
  $('.ucal-zoom-btn').css({background:'var(--surface2)',color:'var(--text-muted)'});
  $('.ucal-zoom-btn[data-zoom="day"]').css({background:'var(--accent)',color:'#fff'});
  renderUCal();
});

$(document).on('click','.ucal-year-day',function(){
  const ds=$(this).data('date'); if(!ds)return;
  const p=ds.split('-'); ucalYear=+p[0];ucalMonth=+p[1]-1;ucalDay=+p[2];
  ucalZoom='day';
  $('.ucal-zoom-btn').css({background:'var(--surface2)',color:'var(--text-muted)'});
  $('.ucal-zoom-btn[data-zoom="day"]').css({background:'var(--accent)',color:'#fff'});
  renderUCal();
});

$(document).on('click','.ucal-year-month',function(){
  ucalMonth=+$(this).data('m'); ucalZoom='month';
  $('.ucal-zoom-btn').css({background:'var(--surface2)',color:'var(--text-muted)'});
  $('.ucal-zoom-btn[data-zoom="month"]').css({background:'var(--accent)',color:'#fff'});
  renderUCal();
});

$(document).on('change','#ucal-show-missions,#ucal-show-tasks,#ucal-show-absences,#ucal-show-rdv',function(){ renderUCal(); });

$(document).on('click','.nav-item[data-view="calendrier"]',function(){ setTimeout(renderUCal,50); });

