  toast('info','◉', oc>0 ? 'Bienvenue — '+oc+' recommandation'+(oc>1?'s':'')+' non implémentée'+(oc>1?'s':'') : 'Bienvenue — Base de données vide, prête à l\'emploi');
})();

(function(){
  var _lastSaveTs = null;

  function _readSavedAt(){
    try{ var s=localStorage.getItem('audit_saved_at'); return s?new Date(s):null; }catch(e){ return null; }
  }

  function _updateIndicator(saving){
    var $ind  = document.getElementById('autosave-indicator');
    var $icon = document.getElementById('autosave-icon');
    var $lbl  = document.getElementById('autosave-label');
    if(!$ind) return;

    if(saving){
      $icon.textContent = '⏳';
      $lbl.textContent  = 'Sauvegarde…';
      $ind.style.borderColor = 'var(--accent)';
      $ind.style.color       = 'var(--accent)';
      return;
    }

    var ts = _lastSaveTs || _readSavedAt();
    if(!ts){ $lbl.textContent='Aucune sauvegarde'; return; }

    var diff = Math.floor((Date.now() - ts.getTime()) / 1000);
    var label;
    if(diff < 5)        label = 'Sauvegardé';
    else if(diff < 60)  label = 'Il y a ' + diff + ' s';
    else if(diff < 3600){ var m=Math.floor(diff/60); label='Il y a '+m+' min'+(m>1?'':''); }
    else                label = ts.toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'});

    if(diff < 10){
      $ind.style.borderColor = '#1a8a4a';
      $ind.style.color       = '#1a8a4a';
      $ind.style.background  = '#e4f5ec';
      $icon.textContent      = '✓';
    } else {
      $ind.style.borderColor = 'var(--border)';
      $ind.style.color       = 'var(--text-muted)';
      $ind.style.background  = 'var(--surface2)';
      $icon.textContent      = '💾';
    }
    $lbl.textContent = label;
  }

  function _autoSave(){
    _updateIndicator(true);
    setTimeout(function(){
      try{
        dbSave();
        _lastSaveTs = new Date();
      }catch(e){}
      _updateIndicator(false);
    }, 80);
  }

  setInterval(function(){ _updateIndicator(false); }, 10000);

  setInterval(function(){ _autoSave(); }, 30000);

  window.addEventListener('blur', function(){ _autoSave(); });
  document.addEventListener('visibilitychange', function(){
    if(document.visibilityState === 'hidden') _autoSave();
  });

  setTimeout(function(){
    _lastSaveTs = _readSavedAt();
    _updateIndicator(false);
  }, 500);

  var _origDbSave = dbSave;
  window._dbSaveOrig = _origDbSave;

  var _patchedDbSave = function(){
    _origDbSave();
    _lastSaveTs = new Date();
    _updateIndicator(false);
  };

  try{ dbSave = _patchedDbSave; }catch(e){}

})();

