function tafOpenModal(id){
  var opts='<option value="">— Sélectionner —</option>'+AUDITEURS.map(function(a){return '<option>'+a.prenom+' '+a.nom+'</option>';}).join('');
  $('#taf-cfg-auditeur').html(opts);
  var socOpts='<option value="">— Sélectionner —</option>'+(typeof SOCIETES!=='undefined'?SOCIETES:[]).map(function(s){return '<option value="'+escHtml(s.nom)+'">'+escHtml(s.nom)+'</option>';}).join('');
  $('#taf-cfg-societe').html(socOpts);
  var rcmOpts='<option value="">— Aucun —</option>'+(typeof RCM_DATA!=='undefined'?RCM_DATA:[]).map(function(r){
    var lbl = r.id+' — '+(r.tache||r.risque||'').slice(0,55)+((r.tache||r.risque||'').length>55?'…':'');
    return '<option value="'+escHtml(r.id)+'">'+escHtml(lbl)+'</option>';
  }).join('');
  $('#taf-cfg-rcm-ref').html(rcmOpts);
  if(id){ $('#taf-modal-title').text('✏️ Modifier le TAF'); tafCfgLoadForm(id); }
  else { $('#taf-modal-title').text('➕ Nouveau TAF'); tafCfgReset(); }
  $('#taf-modal-bk').addClass('open');
}
window.tafOpenModal = tafOpenModal;
function tafCloseModal(){ $('#taf-modal-bk').removeClass('open'); }

// ── Navigation vers l'entrée RCM liée depuis une ligne TAF ──
function tafGoToRCM(rcmId){
  if(!rcmId) return;
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="rcm"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('rcm');
  setTimeout(function(){
    if(typeof renderRCM === 'function') renderRCM();
    var $row = $('#rcm-tbody tr[data-rcm-id="'+rcmId+'"]');
    if($row.length && $row[0].scrollIntoView) $row[0].scrollIntoView({behavior:'smooth', block:'center'});
  }, 60);
}
window.tafGoToRCM = tafGoToRCM;

// ── Correspondance score Résiduel RCM (échelle rcmLevelBadge) ↔ Priorité TAF ──
function rcmResiduelToTafPrio(score){
  score = score || 0;
  if(score >= 10) return 'critical';
  if(score >= 5)  return 'high';
  if(score >= 2)  return 'medium';
  return 'low';
}

// ── Lien TAF ↔ RCM : copie Société/Entité, Catégorie/Cycle, Priorité, Conséquences de l'entrée RCM sélectionnée vers le TAF ──
function tafApplyRCMLink(rcmId){
  if(!rcmId) return;
  var r = (typeof RCM_DATA!=='undefined' ? RCM_DATA : []).find(function(x){ return x.id === rcmId; });
  if(!r) return;
  if(r.filiale && r.filiale!=='Toutes filiales') $('#taf-cfg-societe').val(r.filiale);
  var cyc = r.cycle || '';
  if(r.processus) cyc = cyc ? (cyc+' / '+r.processus) : r.processus;
  if(cyc) $('#taf-cfg-categorie').val(cyc);
  $('#taf-cfg-priorite').val(rcmResiduelToTafPrio(r.residuel));
  var parts = [];
  if(r.risque)   parts.push(r.risque);
  if(r.desc_op)  parts.push('Impact opérationnel : '+r.desc_op);
  if(r.desc_fin) parts.push('Impact financier : '+r.desc_fin);
  if(r.desc_rep) parts.push('Impact réputation : '+r.desc_rep);
  if(parts.length) $('#taf-cfg-consequences').val(parts.join('\n'));
  toast('success','🛡️','Champs synchronisés depuis le RCM '+rcmId+'.');
}

// ── Répercute les changements d'une entrée RCM sur tous les TAF qui lui sont liés, puis en cascade sur les FRAP liées à ces TAF ──
function tafSyncFromRCM(rcmObj){
  if(!rcmObj || !rcmObj.id) return;
  var linked = TAF_ITEMS.filter(function(t){ return t.rcm_ref === rcmObj.id; });
  if(!linked.length) return;
  var cyc = rcmObj.cycle || '';
  if(rcmObj.processus) cyc = cyc ? (cyc+' / '+rcmObj.processus) : rcmObj.processus;
  var parts = [];
  if(rcmObj.risque)   parts.push(rcmObj.risque);
  if(rcmObj.desc_op)  parts.push('Impact opérationnel : '+rcmObj.desc_op);
  if(rcmObj.desc_fin) parts.push('Impact financier : '+rcmObj.desc_fin);
  if(rcmObj.desc_rep) parts.push('Impact réputation : '+rcmObj.desc_rep);
  linked.forEach(function(t){
    if(rcmObj.filiale && rcmObj.filiale!=='Toutes filiales') t.societe = rcmObj.filiale;
    if(cyc) t.categorie = cyc;
    t.priorite = rcmResiduelToTafPrio(rcmObj.residuel);
    if(parts.length) t.consequences = parts.join('\n');
    t.updated_at = new Date().toLocaleDateString('fr-FR',{day:'2-digit',month:'2-digit',year:'numeric'});
    if(typeof frapSyncFromTAF === 'function') frapSyncFromTAF(t);
  });
  tafSave();
  if(typeof renderTAF === 'function' && document.getElementById('taf-tbody')) renderTAF();
  toast('success','🛡️',linked.length+' TAF lié(s) mis à jour depuis le RCM (+ FRAP en cascade).');
}

// ── Exécuter un risque RCM : ouvre la création d'un TAF pré-lié à ce RCM (chaîne RCM → TAF → FRAP) ──
function rcmExecuteToTAF(rcmId){
  var r = (typeof RCM_DATA!=='undefined'?RCM_DATA:[]).find(function(x){ return x.id === rcmId; });
  if(!r){ toast('error','⚠️','Entrée RCM introuvable.'); return; }
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="taf"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('taf');
  setTimeout(function(){
    tafOpenModal(null);
    $('#taf-cfg-ref').val('');
    $('#taf-cfg-titre').val(r.tache || r.risque || '');
    $('#taf-cfg-rcm-ref').val(r.id);
    tafApplyRCMLink(r.id);
  }, 60);
}

// ── Exécuter un TAF : ouvre la création d'une FRAP pré-liée à ce TAF ──
function tafExecuteToFRAP(tafId){
  var t = TAF_ITEMS.find(function(x){ return x.id === tafId; });
  if(!t){ toast('error','⚠️','TAF introuvable.'); return; }
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="frap"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('frap');
  setTimeout(function(){
    frapOpenModal({ taf_ref: t.id, titre: t.titre || '' });
    frapApplyTAFLink(t.id);
  }, 60);
}

