function tafCfgReset(){
  ['ref','categorie','titre','programme','docs','contact','timing','testplan','notes','consequences'].forEach(function(f){$('#taf-cfg-'+f).val('');});
  $('#taf-cfg-testresults').val('');$('#taf-cfg-priorite').val('medium');
  $('#taf-cfg-statut').val('todo');$('#taf-cfg-auditeur').val('');$('#taf-cfg-societe').val('');$('#taf-cfg-rcm-ref').val('');$('#taf-cfg-edit-id').val('');
  TAF_FICHES_TEMP = [];
  $('#taf-cfg-fiche-input').val('');
  tafRenderFichesList();
  _tafPopulateSocietesMulti([]);
  _tafPopulateFrapLinked('');
}
/* ── TAF ↔ Sociétés multiples & Constats FRAP liés (lecture seule, dérivé de FRAP.taf_ref) ── */
function _tafPopulateSocietesMulti(selected){
  var $box=$('#taf-cfg-societes-multi').empty();
  var list=(typeof SOCIETES!=='undefined'?SOCIETES:[]);
  if(!list.length){ $box.html('<span style="font-size:10.5px;color:var(--text-dim);">Aucune société enregistrée.</span>'); return; }
  list.forEach(function(s){
    var checked=(selected||[]).indexOf(s.nom)>=0?' checked':'';
    $box.append('<label style="display:flex;align-items:center;gap:4px;font-size:11px;cursor:pointer;">'
      +'<input type="checkbox" class="taf-soc-multi-cb" value="'+escHtml(s.nom)+'"'+checked+' style="accent-color:var(--accent);"> '+escHtml(s.nom)+'</label>');
  });
}
function _tafPopulateFrapLinked(tafId){
  var $box=$('#taf-cfg-frap-linked').empty();
  var linked=(typeof FRAP_DATA!=='undefined'?FRAP_DATA:[]).filter(function(f){ return tafId && f.taf_ref===tafId; });
  if(!linked.length){ $box.html('<span style="font-style:italic;">Aucun constat FRAP lié pour l\'instant — se rattache automatiquement quand une FRAP sélectionne ce TAF.</span>'); return; }
  $box.html(linked.map(function(f){
    return '<div>📋 <strong>'+escHtml(f.numero||f.id)+'</strong> — '+escHtml((f.titre||'').slice(0,60))+((f.titre||'').length>60?'…':'')+'</div>';
  }).join(''));
}
function tafCfgLoadForm(id){
  var t=TAF_ITEMS.filter(function(x){return x.id===id;})[0];if(!t)return;
  $('#taf-cfg-ref').val(t.id);$('#taf-cfg-categorie').val(t.categorie||'');
  $('#taf-cfg-societe').val(t.societe||'');
  $('#taf-cfg-rcm-ref').val(t.rcm_ref||'');
  $('#taf-cfg-titre').val(t.titre||'');$('#taf-cfg-programme').val(t.programme||'');
  $('#taf-cfg-docs').val(t.docs||'');$('#taf-cfg-contact').val(t.contact||'');
  $('#taf-cfg-timing').val(t.timing||'');$('#taf-cfg-testplan').val(t.testplan||'');
  $('#taf-cfg-testresults').val(t.testresults||'');$('#taf-cfg-priorite').val(t.priorite||'medium');
  $('#taf-cfg-statut').val(t.statut||'todo');$('#taf-cfg-auditeur').val(t.auditeur||'');
  $('#taf-cfg-consequences').val(t.consequences||'');
  $('#taf-cfg-notes').val(t.notes||'');$('#taf-cfg-edit-id').val(t.id);
  TAF_FICHES_TEMP = t.fiches_test ? JSON.parse(JSON.stringify(t.fiches_test)) : [];
  $('#taf-cfg-fiche-input').val('');
  tafRenderFichesList();
  _tafPopulateSocietesMulti(t.societes_multi||[]);
  _tafPopulateFrapLinked(t.id);
}
