<script>
/* ── Sidebar toggle (desktop : collapse / mobile : off-canvas + overlay) ── */
(function(){
  var btn = document.getElementById('btn-sidebar-toggle');
  var backdrop = document.getElementById('sidebar-backdrop');
  if(!btn) return;
  btn.setAttribute('role','button');
  btn.setAttribute('tabindex','0');
  btn.setAttribute('aria-label','Masquer/afficher le menu');
  function isMobile(){ return window.innerWidth<=880; }
  function toggleSidebar(){
    if(isMobile()){
      document.body.classList.toggle('sidebar-mobile-open');
    } else {
      document.body.classList.toggle('sidebar-hidden');
    }
  }
  function closeMobileSidebar(){ document.body.classList.remove('sidebar-mobile-open'); }
  btn.addEventListener('click', toggleSidebar);
  btn.addEventListener('keydown', function(e){
    if(e.key==='Enter'||e.key===' '){ e.preventDefault(); toggleSidebar(); }
  });
  if(backdrop) backdrop.addEventListener('click', closeMobileSidebar);
  // Ferme la sidebar mobile après sélection d'une vue
  document.addEventListener('click', function(e){
    if(isMobile() && e.target.closest('.nav-item[data-view]')) closeMobileSidebar();
  });
  window.addEventListener('resize', function(){
    if(!isMobile()) closeMobileSidebar();
  });
})();
</script>
<style>
.reco-note-icon{display:inline-flex;align-items:center;justify-content:center;width:15px;height:15px;border-radius:50%;background:var(--accent-bg);color:var(--accent);font-size:9px;font-weight:700;cursor:default;flex-shrink:0;border:1px solid rgba(0,112,242,.25);line-height:1;vertical-align:middle;margin-left:4px;}
.reco-note-icon:hover{background:var(--accent);color:#fff;}
#reco-tip-box{position:fixed;z-index:9999;background:var(--surface);border:1px solid var(--border2);border-radius:8px;box-shadow:0 8px 28px rgba(0,0,0,.18);padding:12px 14px;max-width:320px;min-width:200px;pointer-events:none;display:none;font-size:11.5px;line-height:1.5;}
#reco-tip-box.visible{display:block;}
.reco-tip-section{margin-bottom:8px;}
.reco-tip-section:last-child{margin-bottom:0;}
.reco-tip-label{font-size:9.5px;font-weight:700;text-transform:uppercase;letter-spacing:.07em;color:var(--text-muted);margin-bottom:3px;}
.reco-tip-text{font-size:11px;color:var(--text);line-height:1.45;}
.reco-tip-sep{height:1px;background:var(--border);margin:7px 0;}
</style>
<div id="reco-tip-box"></div>
<script>
(function(){
  var box=document.getElementById('reco-tip-box');
  var hide;
  document.addEventListener('mouseover',function(e){
    var ico=e.target.closest('.reco-note-icon');
    if(!ico)return;
    clearTimeout(hide);
    var expl=ico.dataset.expl||'';
    var comm=ico.dataset.comm||'';
    var h='';
    if(expl) h+='<div class="reco-tip-section"><div class="reco-tip-label">💬 Explication</div><div class="reco-tip-text">'+expl+'</div></div>';
    if(expl&&comm) h+='<div class="reco-tip-sep"></div>';
    if(comm) h+='<div class="reco-tip-section"><div class="reco-tip-label">📝 Commentaire auditeur</div><div class="reco-tip-text">'+comm+'</div></div>';
    box.innerHTML=h;
    box.classList.add('visible');
    pos(e);
  });
  document.addEventListener('mousemove',function(e){if(e.target.closest('.reco-note-icon'))pos(e);});
  document.addEventListener('mouseout',function(e){if(e.target.closest('.reco-note-icon'))hide=setTimeout(function(){box.classList.remove('visible');},120);});
  function pos(e){
    var vw=window.innerWidth,vh=window.innerHeight,bw=330,bh=box.offsetHeight||120;
    var x=e.clientX+14,y=e.clientY+14;
    if(x+bw>vw-8)x=e.clientX-bw-10;
    if(y+bh>vh-8)y=e.clientY-bh-10;
    box.style.left=x+'px';box.style.top=y+'px';
  }
})();

/* ══════════════════════════════════════════════════════════════════
   FRAP — Fiches de Relevé d'Anomalies et de Pratiques
   ══════════════════════════════════════════════════════════════════ */

/* escHtml est déclarée dans un IIFE Eisenhower (scope fermé) — on expose globalement */
if(typeof escHtml === 'undefined'){
  window.escHtml = function(s){ return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); };
}

/* toast est déclarée dans un $(function(){}) jQuery ready (scope fermé) — on expose globalement */
if(typeof toast === 'undefined'){
  window.toast = function(type, icon, msg){
    var $t = $('<div class="toast '+type+'"><span style="font-size:13px">'+icon+'</span>'+msg+'</div>');
    $('#toasts').append($t);
    setTimeout(function(){ $t.fadeOut(280, function(){ $t.remove(); }); }, 3000);
  };
}

var FRAP_DATA = [];

// ── Données par défaut (démo) ──────────────────────────────────────
var FRAP_DEFAULT = [
  {
    id:'FRAP-001',
    numero:'1',
    titre:"Absence de filtrage des entrées sur site et inexistence d'un registre de suivi des flux (entrées/sorties)",
    criticite:'critique',
    ref:'C-004',
    societe:'',
    cycle:'Sécurité physique',
    auditeur:'',
    description:"Absence de filtrage des entrées sur site et inexistence d'un registre de suivi des flux (entrées/sorties). Aucun dispositif ne permet de tracer les mouvements de personnes ou de matériels.",
    causes:"Absence de procédure formalisée et de moyens dédiés à la sécurité des accès.",
    consequences:"Vol, sabotage, détournements non détectés. Impossibilité de reconstituer les accès en cas d'incident.",
    recommandations:[
      "Mettre en place un poste de contrôle à l'entrée du site avec identification obligatoire de toute personne, accompagné d'une procédure formalisée de gestion des visiteurs et intervenants extérieurs.",
      "Instaurer un registre électronique des entrées/sorties conservé 12 mois minimum."
    ],
    actions:[
      "Construction d'un abri à l'entrée du site pour le contrôleur",
      "Mise en place d'un registre numérique de contrôle d'accès"
    ],
    created_at: new Date().toISOString().slice(0,10),
    updated_at: new Date().toISOString().slice(0,10)
  }
];

function frapLoad(){
  try {
    var r = localStorage.getItem('dac_frap');
    FRAP_DATA = r ? JSON.parse(r) : JSON.parse(JSON.stringify(FRAP_DEFAULT));
  } catch(e) {
    FRAP_DATA = JSON.parse(JSON.stringify(FRAP_DEFAULT));
  }
}
function frapSave(){
  try {
    localStorage.setItem('dac_frap', JSON.stringify(FRAP_DATA));
  } catch(e){
    toast('error','⚠️','Stockage local plein — les pièces jointes n\'ont pas pu être enregistrées. Réduisez leur taille/nombre.');
  }
  updateFRAPBadge();
}
frapLoad();

function updateFRAPBadge(){
  var n = FRAP_DATA.length;
  $('#nb-frap').text(n).toggle(n > 0);
}
updateFRAPBadge();

// ── Labels criticité ───────────────────────────────────────────────
var FRAP_CRIT_LABELS = {critique:'Critique', majeur:'Majeur', modere:'Modéré', mineur:'Mineur'};

// ── Correspondance échelle Priorité TAF (critical/high/medium/low) ↔ Criticité FRAP (critique/majeur/modere/mineur) ──
var TAF_PRIO_TO_FRAP_CRIT = {critical:'critique', high:'majeur', medium:'modere', low:'mineur'};

// ── Lien FRAP ↔ TAF : copie Criticité, Société/Entité, Cycle/Processus, Conséquences/Risques du TAF sélectionné vers la FRAP ──
function frapApplyAuditRefLink(auditRef){
  if(!auditRef) return;
  var a = (typeof AUDITS!=='undefined' ? AUDITS : []).find(function(x){ return x.ref === auditRef; });
  if(!a) return;
  // Hérite la Référence interne depuis la mission du Plan d'audit interne
  $('#frap-f-ref').val(a.ref||'');
  if(a.societe && !$('#frap-f-societe').val()) $('#frap-f-societe').val(a.societe);
  toast('success','🔗','Référence héritée de la mission '+a.ref+'.');
}

function frapApplyTAFLink(tafId){
  if(!tafId) return;
  var t = (typeof TAF_ITEMS!=='undefined' ? TAF_ITEMS : []).find(function(x){ return x.id === tafId; });
  if(!t) return;
  if(t.priorite && TAF_PRIO_TO_FRAP_CRIT[t.priorite]) $('#frap-f-crit').val(TAF_PRIO_TO_FRAP_CRIT[t.priorite]);
  if(t.societe) $('#frap-f-societe').val(t.societe);
  if(t.categorie) $('#frap-f-cycle').val(t.categorie);
  if(t.consequences) $('#frap-f-consequences').val(t.consequences);
  toast('success','🔗','Champs synchronisés depuis le TAF '+tafId+'.');
}

// ── Répercute les changements d'un TAF sur toutes les FRAP qui lui sont liées ──
function frapSyncFromTAF(tafObj){
  if(!tafObj || !tafObj.id) return;
  var linked = FRAP_DATA.filter(function(f){ return f.taf_ref === tafObj.id; });
  if(!linked.length) return;
  linked.forEach(function(f){
    if(tafObj.priorite && TAF_PRIO_TO_FRAP_CRIT[tafObj.priorite]) f.criticite = TAF_PRIO_TO_FRAP_CRIT[tafObj.priorite];
    if(tafObj.societe) f.societe = tafObj.societe;
    if(tafObj.categorie) f.cycle = tafObj.categorie;
    if(tafObj.consequences) f.consequences = tafObj.consequences;
    f.updated_at = new Date().toISOString().slice(0,10);
  });
  frapSave();
  if(typeof renderFRAP === 'function' && document.getElementById('frap-cards-container')) renderFRAP();
  toast('success','🔗',linked.length+' FRAP liée(s) mise(s) à jour.');
}

// ── Zone Preuve — état temporaire des PJ pendant l'édition dans la modale ──
var FRAP_PREUVES_TEMP = [];
var FRAP_PREUVE_MAX_SIZE = 4 * 1024 * 1024; // 4 Mo par fichier

function frapFileIcon(name){
  var ext = String(name||'').split('.').pop().toLowerCase();
  if(ext === 'pdf') return '📕';
  if(['doc','docx'].indexOf(ext) >= 0) return '📄';
  if(['xls','xlsx','csv'].indexOf(ext) >= 0) return '📊';
  return '📎';
}

function frapFileSizeFmt(bytes){
  bytes = +bytes || 0;
  if(bytes < 1024) return bytes + ' o';
  if(bytes < 1024*1024) return Math.round(bytes/1024) + ' Ko';
  return (bytes/(1024*1024)).toFixed(1) + ' Mo';
}

function frapRenderPreuvesList(){
  var box = document.getElementById('frap-preuves-list');
  if(!box) return;
  if(!FRAP_PREUVES_TEMP.length){
    box.innerHTML = '<div style="font-size:10.5px;color:var(--text-dim);font-style:italic;">Aucune pièce jointe.</div>';
    return;
  }
  box.innerHTML = FRAP_PREUVES_TEMP.map(function(p){
    var isImg = /^image\//.test(p.type||'');
    var shortName = p.name && p.name.length > 15 ? p.name.slice(0,13)+'…' : (p.name||'PJ');
    return '<div class="frap-preuve-chip">'
      + '<span class="frap-preuve-rm" data-pid="'+p.id+'" title="Retirer">×</span>'
      + (isImg
          ? '<img class="frap-preuve-thumb frap-preuve-open-temp" data-pid="'+p.id+'" src="'+p.dataUrl+'" alt="'+escHtml(p.name||'')+'">'
          : '<div class="frap-preuve-file frap-preuve-open-temp" data-pid="'+p.id+'" title="'+escHtml(p.name||'')+'">'+frapFileIcon(p.name)+'</div>')
      + '<div class="frap-preuve-name" title="'+escHtml(p.name||'')+'">'+escHtml(shortName)+'</div>'
      + '<div class="frap-preuve-size">'+frapFileSizeFmt(p.size)+'</div>'
    +'</div>';
  }).join('');
}

function frapHandleFiles(fileList){
  var files = Array.prototype.slice.call(fileList || []);
  if(!files.length) return;
  files.forEach(function(file){
    if(file.size > FRAP_PREUVE_MAX_SIZE){
      toast('error','⚠️','"'+file.name+'" dépasse 4 Mo — ignoré.');
      return;
    }
    var reader = new FileReader();
    reader.onload = function(ev){
      FRAP_PREUVES_TEMP.push({
        id:      'pv_'+Date.now()+'_'+Math.random().toString(36).slice(2,7),
        name:    file.name,
        type:    file.type || '',
        size:    file.size,
        dataUrl: ev.target.result,
        addedAt: new Date().toISOString().slice(0,10)
      });
      frapRenderPreuvesList();
    };
    reader.onerror = function(){
      toast('error','⚠️','Lecture impossible pour "'+file.name+'".');
    };
    reader.readAsDataURL(file);
  });
}

function frapRemovePreuve(id){
  FRAP_PREUVES_TEMP = FRAP_PREUVES_TEMP.filter(function(p){ return p.id !== id; });
  frapRenderPreuvesList();
}

// Convertit un data URL (base64) en Blob pour ouverture/téléchargement
function frapDataUrlToBlob(dataUrl){
  var parts = dataUrl.split(',');
  var mimeMatch = parts[0].match(/data:([^;]+);/);
  var mime = mimeMatch ? mimeMatch[1] : 'application/octet-stream';
  var binary = atob(parts[1]);
  var arr = new Uint8Array(binary.length);
  for(var i=0;i<binary.length;i++){ arr[i] = binary.charCodeAt(i); }
  return new Blob([arr], {type: mime});
}

// Ouvre (image/PDF) ou télécharge (autres formats) une pièce jointe de la Zone Preuve
function frapOpenPreuve(p){
  if(!p || !p.dataUrl) return;
  try {
    var blob = frapDataUrlToBlob(p.dataUrl);
    var url  = URL.createObjectURL(blob);
    var isViewable = /^image\//.test(p.type||'') || p.type === 'application/pdf' || /\.pdf$/i.test(p.name||'');
    if(isViewable){
      window.open(url, '_blank');
    } else {
      var a = document.createElement('a');
      a.href = url; a.download = p.name || 'piece-jointe';
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
    }
    setTimeout(function(){ URL.revokeObjectURL(url); }, 30000);
  } catch(e){
    window.open(p.dataUrl, '_blank');
  }
}
var FRAP_CRIT_CLASS  = {critique:'frap-b-critique', majeur:'frap-b-majeur', modere:'frap-b-modere', mineur:'frap-b-mineur'};

// ── Rendu principal ────────────────────────────────────────────────
function renderFRAP(){
  // Peupler filtre sociétés
  var socSel = document.getElementById('frap-filter-societe');
  var prevSoc = socSel ? socSel.value : '';
  if(socSel){
    var socs = [];
    FRAP_DATA.forEach(function(f){ if(f.societe && socs.indexOf(f.societe)<0) socs.push(f.societe); });
    var opts = '<option value="">Toutes sociétés</option>';
    socs.sort().forEach(function(s){ opts += '<option value="'+escHtml(s)+'">'+escHtml(s)+'</option>'; });
    socSel.innerHTML = opts;
    if(prevSoc) socSel.value = prevSoc;
  }

  var filtered = frapGetFiltered();

  $('#frap-count-badge').text(FRAP_DATA.length);

  var container = document.getElementById('frap-cards-container');
  var emptyEl   = document.getElementById('frap-empty');
  if(!container) return;

  if(filtered.length === 0){
    container.innerHTML = '';
    if(emptyEl) emptyEl.style.display = 'block';
    return;
  }
  if(emptyEl) emptyEl.style.display = 'none';

  var html = '';
  filtered.forEach(function(f){
    html += frapCardHtml(f, true);
  });

  container.innerHTML = html;
}

// ── Construction HTML d'une carte FRAP (réutilisée à l'écran ET à l'impression) ──
function frapCardHtml(f, includeActions){
  var critClass = FRAP_CRIT_CLASS[f.criticite]||'frap-b-critique';
  var critLabel = FRAP_CRIT_LABELS[f.criticite]||f.criticite;
  var socBadge  = f.societe ? '<span class="frap-badge frap-b-soc">'+escHtml(f.societe)+'</span>' : '';
  var refBadge  = f.ref     ? '<span class="frap-badge frap-b-ref">'+escHtml(f.ref)+'</span>' : '';
  var tafBadge  = f.taf_ref ? '<span class="frap-badge frap-b-taf" title="Constat TAF lié — cliquer pour ouvrir" onclick="frapGoToTAF(\''+escHtml(f.taf_ref)+'\')">🔗 '+escHtml(f.taf_ref)+'</span>' : '';
  // Le lien RCM est indirect : FRAP → TAF → RCM. On l'affiche s'il existe via le TAF lié.
  var linkedTAFForRCM = (f.taf_ref && typeof TAF_ITEMS!=='undefined') ? TAF_ITEMS.find(function(t){ return t.id === f.taf_ref; }) : null;
  var chainedRcmId = linkedTAFForRCM ? linkedTAFForRCM.rcm_ref : '';
  var rcmBadge  = chainedRcmId ? '<span class="frap-badge frap-b-rcm" title="Risque RCM lié (via le TAF) — cliquer pour ouvrir" onclick="frapGoToRCM(\''+escHtml(chainedRcmId)+'\')">🛡️ '+escHtml(chainedRcmId)+'</span>' : '';

  // Recommandations — structure alignée sur « Ajouter une recommandation » (module Suivi Recommandations)
  var recoHtml = '';
  var _recoStatutLbl={notimplemented:['Non implémenté','var(--red)','var(--red-bg)'],partially:['Partiellement implémenté','var(--yellow)','var(--yellow-bg)'],fully:['Implémenté','var(--green)','var(--green-bg)']};
  if(f.recommandations && f.recommandations.length){
    f.recommandations.forEach(function(r,i){
      // Rétro-compatibilité : anciennes FRAP où la recommandation était une simple chaîne de texte
      if(typeof r==='string') r={recommandation:r};
      var sl=_recoStatutLbl[r.statut]||['Non implémenté','var(--red)','var(--red-bg)'];
      recoHtml += '<div class="frap-list-item"><span class="frap-dot frap-dot-reco">'+(i+1)+'</span><div>'
        +'<div>'+escHtml(r.recommandation||'')+'</div>'
        +'<div style="display:flex;gap:6px;flex-wrap:wrap;margin-top:3px;">'
          +(r.responsable?'<span style="font-size:9.5px;color:var(--text-muted);">👤 '+escHtml(r.responsable)+'</span>':'')
          +(r.echeance?'<span style="font-size:9.5px;color:var(--text-muted);">📅 '+escHtml(r.echeance)+'</span>':'')
          +'<span style="font-size:9px;font-weight:600;color:'+sl[1]+';background:'+sl[2]+';padding:1px 6px;border-radius:3px;">'+sl[0]+'</span>'
          +'<span style="font-size:9px;color:var(--text-dim);">'+(r.avancement||0)+'%</span>'
        +'</div></div></div>';
    });
  } else {
    recoHtml = '<span class="frap-empty">Aucune recommandation saisie.</span>';
  }

  // Actions
  var actHtml = '';
  if(f.actions && f.actions.length){
    f.actions.forEach(function(a,i){
      actHtml += '<div class="frap-list-item"><span class="frap-dot frap-dot-action">'+(i+1)+'</span><span>'+escHtml(a)+'</span></div>';
    });
  } else {
    actHtml = '<span class="frap-empty">Aucune action saisie.</span>';
  }

  // Causes / Conséquences
  var causesHtml = f.causes
    ? escHtml(f.causes)
    : '<span class="frap-empty">Explications de l\'écart entre les critères de référence et les faits.</span>';
  var consHtml = f.consequences
    ? '<span class="frap-warn">'+escHtml(f.consequences)+'</span>'
    : '<span class="frap-empty">Non renseigné.</span>';

  // Cycle / Auditeur
  var metaRow = '';
  if(f.cycle || f.auditeur){
    metaRow = '<div class="frap-row">'
      +(f.cycle    ? '<div class="frap-lbl">Cycle / Processus</div><div class="frap-val">'+escHtml(f.cycle)+'</div>' : '')
      +'</div>';
  }

  // Zone Preuve (pièces jointes)
  var preuvesHtml = '';
  if(f.preuves && f.preuves.length){
    var chips = f.preuves.map(function(p){
      var isImg = /^image\//.test(p.type||'');
      var shortName = p.name && p.name.length > 15 ? p.name.slice(0,13)+'…' : (p.name||'PJ');
      return '<div class="frap-preuve-chip">'
        + (isImg
            ? '<img class="frap-preuve-card-thumb frap-preuve-open-saved" data-fid="'+escHtml(f.id)+'" data-pid="'+escHtml(p.id)+'" src="'+p.dataUrl+'" alt="'+escHtml(p.name||'')+'" title="'+escHtml(p.name||'')+'">'
            : '<div class="frap-preuve-card-file frap-preuve-open-saved" data-fid="'+escHtml(f.id)+'" data-pid="'+escHtml(p.id)+'" title="'+escHtml(p.name||'')+'">'+frapFileIcon(p.name)+'</div>')
        + '<div class="frap-preuve-name">'+escHtml(shortName)+'</div>'
      +'</div>';
    }).join('');
    preuvesHtml = '<div class="frap-row"><div class="frap-lbl">📎 Zone Preuve</div><div class="frap-val"><div class="frap-preuve-list">'+chips+'</div></div></div>';
  }

  var actionsHtml = includeActions
    ? '<div class="frap-card-actions">'
        +'<button class="frap-card-btn" onclick="frapEdit(\''+escHtml(f.id)+'\')">✏️ Modifier</button>'
        +'<button class="frap-card-btn" onclick="frapPrintOne(\''+escHtml(f.id)+'\')">🖨️ Imprimer</button>'
        +'<button class="frap-card-btn danger" onclick="frapDelete(\''+escHtml(f.id)+'\')">🗑️ Supprimer</button>'
      +'</div>'
    : '';

  return '<div class="frap-card" data-frap-id="'+escHtml(f.id)+'">'
    +'<div class="frap-head">'
      +'<span class="frap-num">'+escHtml(f.numero)+'.</span>'
      +'<span class="frap-tit">'+escHtml(f.titre)+'</span>'
      +'<div class="frap-badges">'
        +'<span class="frap-badge '+critClass+'">'+critLabel+'</span>'
        +refBadge
        +socBadge
        +tafBadge
        +rcmBadge
      +'</div>'
    +'</div>'
    +metaRow
    +'<div class="frap-row"><div class="frap-lbl">Description</div><div class="frap-val">'+escHtml(f.description||'—')+'</div></div>'
    +'<div class="frap-row"><div class="frap-lbl">Causes</div><div class="frap-val">'+causesHtml+'</div></div>'
    +'<div class="frap-row"><div class="frap-lbl">Conséquences / Risques</div><div class="frap-val">'+consHtml+'</div></div>'
    +'<div class="frap-row"><div class="frap-lbl">Recommandations</div><div class="frap-val">'+recoHtml+'</div></div>'
    +'<div class="frap-row"><div class="frap-lbl">Actions mises en œuvre</div><div class="frap-val">'+actHtml+'</div></div>'
    + preuvesHtml
    + actionsHtml
  +'</div>';
}

// ── Navigation vers l'entrée RCM liée depuis une carte FRAP ──
function frapGoToRCM(rcmId){
  if(!rcmId) return;
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="rcm"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('rcm');
  setTimeout(function(){
    if(typeof renderRCM === 'function') renderRCM();
    var $row = $('#rcm-tbody tr[data-rcm-id="'+rcmId+'"]');
    if($row.length && $row[0].scrollIntoView) $row[0].scrollIntoView({behavior:'smooth', block:'center'});
  }, 60);
}
window.frapGoToRCM = frapGoToRCM;

// ── Navigation vers le TAF lié depuis une carte FRAP ──
function frapGoToTAF(tafId){
  if(!tafId) return;
  $('.nav-item[data-view]').attr('aria-current','false');
  $('.nav-item[data-view="taf"]').attr('aria-current','page');
  if(typeof showView === 'function') showView('taf');
  setTimeout(function(){
    _tafSearch = tafId;
    var $s = $('#taf-search');
    if($s.length) $s.val(tafId);
    if(typeof renderTAF === 'function') renderTAF();
    var $row = $('#taf-tbody tr[data-id="'+tafId+'"]');
    if($row.length && $row[0].scrollIntoView) $row[0].scrollIntoView({behavior:'smooth', block:'center'});
  }, 60);
}
window.frapGoToTAF = frapGoToTAF;

// ── Filtre courant (partagé entre l'affichage écran et l'impression) ──
function frapGetFiltered(){
  var search  = ($('#frap-search').val()||'').toLowerCase().trim();
  var fCrit   = $('#frap-filter-crit').val()||'';
  var fSoc    = $('#frap-filter-societe').val()||'';
  return FRAP_DATA.filter(function(f){
    if(fCrit && f.criticite !== fCrit) return false;
    if(fSoc  && f.societe  !== fSoc)  return false;
    if(search){
      var hay = (f.numero+' '+f.titre+' '+f.cycle+' '+f.description+' '+f.ref).toLowerCase();
      if(hay.indexOf(search)<0) return false;
    }
    return true;
  });
}

// ── Modal helpers ──────────────────────────────────────────────────
function frapBuildRecoRow(val){
  val = val || '';
  var row = document.createElement('div');
  row.style.cssText = 'display:flex;gap:5px;align-items:center;';
  row.innerHTML = '<input class="finp frap-reco-inp" style="flex:1;font-size:11.5px;" value="'+escHtml(val)+'" placeholder="Texte de la recommandation…">'
    +'<button style="border:none;background:none;color:#bb2222;cursor:pointer;font-size:14px;line-height:1;padding:2px 4px;" onclick="this.closest(\'div\').remove()">×</button>';
  return row;
}
function frapBuildActionRow(val){
  val = val || '';
  var row = document.createElement('div');
  row.style.cssText = 'display:flex;gap:5px;align-items:center;';
  row.innerHTML = '<input class="finp frap-action-inp" style="flex:1;font-size:11.5px;" value="'+escHtml(val)+'" placeholder="Action mise en œuvre…">'
    +'<button style="border:none;background:none;color:#bb2222;cursor:pointer;font-size:14px;line-height:1;padding:2px 4px;" onclick="this.closest(\'div\').remove()">×</button>';
  return row;
}

function frapOpenModal(item){
  item = item || {};
  $('#frap-modal-title').text(item.id ? '✏️ Modifier FRAP' : '➕ Nouvelle FRAP');
  $('#frap-f-edit-id').val(item.id||'');
  $('#frap-f-num').val(item.numero||'');
  $('#frap-f-ref').val(item.ref||'');
  $('#frap-f-titre').val(item.titre||'');
  $('#frap-f-crit').val(item.criticite||'critique');
  $('#frap-f-cycle').val(item.cycle||'');
  $('#frap-f-desc').val(item.description||'');
  $('#frap-f-causes').val(item.causes||'');
  $('#frap-f-consequences').val(item.consequences||'');

  // Peupler la mission liée (Plan d'audit interne) — la Référence interne hérite de cette mission
  var auditOpts = '<option value="">— Aucune —</option>';
  var _frapLinkedAuditRef = (item.audit_refs && item.audit_refs[0]) || '';
  (typeof AUDITS !== 'undefined' ? AUDITS : []).forEach(function(a){
    var lbl = (a.ref||'') + ' — ' + (a.title||'') + (a.societe?' ['+a.societe+']':'');
    var sel = (a.ref === _frapLinkedAuditRef) ? ' selected' : '';
    auditOpts += '<option value="'+escHtml(a.ref||'')+'"'+sel+'>'+escHtml(lbl)+'</option>';
  });
  $('#frap-f-audit-ref').html(auditOpts);

  // Peupler le lien TAF
  var tafOpts = '<option value="">— Aucun —</option>';
  (typeof TAF_ITEMS !== 'undefined' ? TAF_ITEMS : []).forEach(function(t){
    var lbl = t.id + ' — ' + (t.titre||'').slice(0,60) + ((t.titre||'').length>60?'…':'');
    var sel = (t.id === item.taf_ref) ? ' selected' : '';
    tafOpts += '<option value="'+escHtml(t.id)+'"'+sel+'>'+escHtml(lbl)+'</option>';
  });
  $('#frap-f-taf-ref').html(tafOpts);

  // Peupler sociétés
  var socOpts = '<option value="">— Sélectionner —</option>';
  (typeof SOCIETES !== 'undefined' ? SOCIETES : []).forEach(function(s){
    var sel = (s.nom === item.societe) ? ' selected' : '';
    socOpts += '<option value="'+escHtml(s.nom)+'"'+sel+'>'+escHtml(s.nom)+'</option>';
  });
  $('#frap-f-societe').html(socOpts);

  // Peupler auditeurs
  var audOpts = '<option value="">— Sélectionner —</option>';
  (typeof AUDITEURS !== 'undefined' ? AUDITEURS : []).forEach(function(a){
    var n = (a.prenom||'') + ' ' + (a.nom||'');
    var sel = (n.trim() === (item.auditeur||'')) ? ' selected' : '';
    audOpts += '<option value="'+escHtml(n.trim())+'"'+sel+'>'+escHtml(n.trim())+'</option>';
  });
  $('#frap-f-auditeur').html(audOpts);

  // Recommandations — structure alignée sur « Ajouter une recommandation » (module Suivi Recommandations)
  var _frapRecos = (item.recommandations||[]).map(function(r){ return (typeof r==='string') ? {recommandation:r} : r; });
  $('#frap-recos-list').html(_frapRecos.length ? _frapRecos.map(function(r,i){ return RECO_ROW(r,i); }).join('') : RECO_ROW(null,0));

  // Actions
  var actList = document.getElementById('frap-actions-list');
  actList.innerHTML = '';
  (item.actions||['']).forEach(function(a){ actList.appendChild(frapBuildActionRow(a)); });
  if(!(item.actions||[]).length) actList.appendChild(frapBuildActionRow(''));

  // Zone Preuve (pièces jointes) — recharger l'état temporaire depuis la FRAP éditée
  FRAP_PREUVES_TEMP = item.preuves ? JSON.parse(JSON.stringify(item.preuves)) : [];
  $('#frap-f-preuve-input').val('');
  frapRenderPreuvesList();

  $('#frap-modal-bk').addClass('open');
}

function frapCloseModal(){
  $('#frap-modal-bk').removeClass('open');
  FRAP_PREUVES_TEMP = [];
  $('#frap-f-preuve-input').val('');
}

// ── Lire les recommandations FRAP depuis le DOM — structure alignée sur « Ajouter une recommandation » ──
function readFrapRecos(existingRecos){
  const recos=[];
  $('#frap-recos-list .reco-row').each(function(i){
    const $r=$(this);
    const existing = existingRecos ? existingRecos[i] : null;
    const rid = (existing && existing.id) ? existing.id : ('FR-TMP-'+i);
    const recommandation = $r.find('[name="reco"]').val()||'';
    if(!recommandation.trim()) return; // ignorer les lignes laissées vides
    recos.push({
      id: rid,
      recommandation:       recommandation,
      disposition:          $r.find('[name="disposition"]').val()||'',
      responsable:          $r.find('[name="responsable"]').val()||'',
      fonction_responsable: $r.find('[name="fonction_responsable"]').val()||'',
      echeance:             $r.find('[name="echeance"]').val()||'',
      echeance_revisee:     $r.find('[name="echeance_revisee"]').val()||'',
      mise_a_jour:          $r.find('[name="mise_a_jour"]').val()||'',
      alerte:               $r.find('[name="alerte"]').val()||'',
      appreciation_preuve:  $r.find('[name="appreciation_preuve"]').val()||'',
      explication:          $r.find('[name="explication"]').val()||'',
      commentaire_auditeur: $r.find('[name="commentaire_auditeur"]').val()||'',
      statut:               $r.find('[name="statut"]').val()||'notimplemented',
      avancement:           parseInt($r.find('[name="avancement"]').val())||0
    });
  });
  return recos;
}

function frapSaveModal(){
  var editId = $('#frap-f-edit-id').val();
  var num    = $('#frap-f-num').val().trim();
  var titre  = $('#frap-f-titre').val().trim();
  if(!num || !titre){ toast('error','❌','N° Constat et Titre sont obligatoires.'); return; }

  var _prevFrapItem = editId ? FRAP_DATA.find(function(f){ return f.id === editId; }) : null;
  var _prevFrapRecos = _prevFrapItem ? (_prevFrapItem.recommandations||[]).map(function(r){ return (typeof r==='string')?{recommandation:r}:r; }) : [];
  var recos = readFrapRecos(_prevFrapRecos);
  var acts = [];
  document.querySelectorAll('.frap-action-inp').forEach(function(inp){
    var v = inp.value.trim(); if(v) acts.push(v);
  });
  var _selAuditRef = $('#frap-f-audit-ref').val();
  var auditRefsVal = _selAuditRef ? [_selAuditRef] : [];

  var now = new Date().toISOString().slice(0,10);
  if(editId){
    var idx = FRAP_DATA.findIndex(function(f){ return f.id === editId; });
    if(idx >= 0){
      Object.assign(FRAP_DATA[idx], {
        numero:       num,
        ref:          $('#frap-f-ref').val().trim(),
        audit_refs:   auditRefsVal,
        taf_ref:      $('#frap-f-taf-ref').val(),
        titre:        titre,
        criticite:    $('#frap-f-crit').val(),
        societe:      $('#frap-f-societe').val(),
        cycle:        $('#frap-f-cycle').val().trim(),
        auditeur:     $('#frap-f-auditeur').val(),
        description:  $('#frap-f-desc').val().trim(),
        causes:       $('#frap-f-causes').val().trim(),
        consequences: $('#frap-f-consequences').val().trim(),
        recommandations: recos,
        actions:      acts,
        preuves:      FRAP_PREUVES_TEMP.slice(),
        updated_at:   now
      });
    }
    toast('success','✅','FRAP modifiée.');
  } else {
    FRAP_DATA.push({
      id:           'FRAP-'+Date.now(),
      numero:       num,
      ref:          $('#frap-f-ref').val().trim(),
      audit_refs:   auditRefsVal,
      taf_ref:      $('#frap-f-taf-ref').val(),
      titre:        titre,
      criticite:    $('#frap-f-crit').val(),
      societe:      $('#frap-f-societe').val(),
      cycle:        $('#frap-f-cycle').val().trim(),
      auditeur:     $('#frap-f-auditeur').val(),
      description:  $('#frap-f-desc').val().trim(),
      causes:       $('#frap-f-causes').val().trim(),
      consequences: $('#frap-f-consequences').val().trim(),
      recommandations: recos,
      actions:      acts,
      preuves:      FRAP_PREUVES_TEMP.slice(),
      created_at:   now,
      updated_at:   now
    });
    toast('success','✅','FRAP ajoutée.');
  }

  frapSave();
  frapCloseModal();
  renderFRAP();
}

function frapEdit(id){
  var item = FRAP_DATA.find(function(f){ return f.id === id; });
  if(item) frapOpenModal(item);
}
window.frapEdit = frapEdit;

function frapDelete(id){
  if(!confirm('Supprimer cette FRAP ?')) return;
  FRAP_DATA = FRAP_DATA.filter(function(f){ return f.id !== id; });
  frapSave();
  renderFRAP();
  toast('success','🗑️','FRAP supprimée.');
}
window.frapDelete = frapDelete;

// ── Impression FRAP (individuelle, avec en-tête & pied de page) ────

// Formatte une date 'YYYY-MM-DD' (ou objet Date) en dd/mm/yyyy
function frapDateFR(s){
  if(!s) return new Date().toLocaleDateString('fr-FR');
  if(s instanceof Date) return fmtDate(s);
  var p = String(s).split('-');
  if(p.length===3 && p[0].length===4) return p[2]+'/'+p[1]+'/'+p[0];
  return escHtml(s);
}

// En-tête imprimable FRAP : logo + "Direction Audit & Contrôle Interne" +
// titre du document + bandeau Référence / Entité auditée / Date
function _buildFrapPrintHeader(f){
  var socList = (typeof SOCIETES !== 'undefined' && SOCIETES) ? SOCIETES : [];
  var logoSrc = null;
  var arbiSoc = socList.find(function(s){
    return s.nom && s.nom.toUpperCase().indexOf('ARBIOCHEM') !== -1;
  });
  if(arbiSoc) logoSrc = getSocLogo(socKey(arbiSoc));
  if(!logoSrc && f.societe){
    var auditedSoc = socList.find(function(s){ return s.nom === f.societe; });
    if(auditedSoc) logoSrc = getSocLogo(socKey(auditedSoc));
  }
  if(!logoSrc){
    for(var i=0;i<socList.length;i++){
      var lu = getSocLogo(socKey(socList[i]));
      if(lu){ logoSrc = lu; break; }
    }
  }
  var logoHtml = logoSrc
    ? '<img src="'+logoSrc+'" style="height:48px;max-width:170px;object-fit:contain;" alt="Logo">'
    : '<div style="height:48px;display:flex;align-items:center;font-size:19px;font-weight:900;color:#0070f2;letter-spacing:-1px;">ARBIOCHEM</div>';

  var refVal  = f.ref || f.numero || f.id || '—';
  var socVal  = f.societe || '—';
  var dateVal = frapDateFR(f.created_at);

  return ''
    +'<div style="display:flex;align-items:flex-start;justify-content:space-between;padding-bottom:10px;border-bottom:2px solid #1a1a2e;margin-bottom:10px;">'
      +'<div style="display:flex;flex-direction:column;align-items:flex-start;gap:4px;">'
        +logoHtml
        +'<div style="font-size:9px;font-weight:800;color:#1a1a2e;text-transform:uppercase;letter-spacing:.08em;">Direction Audit &amp; Contr&#244;le Interne</div>'
      +'</div>'
      +'<div style="text-align:right;max-width:260px;">'
        +'<div style="font-size:11.5px;font-weight:800;color:#1a1a2e;line-height:1.35;">Fiche de R&#233;v&#233;lation et d&#8217;Analyse de Probl&#232;me (FRAP)</div>'
      +'</div>'
    +'</div>'
    +'<div style="display:flex;gap:12px;margin-bottom:16px;">'
      +'<div style="flex:1;background:#faf9f7;border:1px solid #ede9e0;border-radius:4px;padding:6px 10px;">'
        +'<div style="font-size:8px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#9ca3af;">R&#233;f&#233;rence FRAP</div>'
        +'<div style="font-size:11px;font-weight:700;color:#1a1a2e;">'+escHtml(refVal)+'</div>'
      +'</div>'
      +'<div style="flex:1;background:#faf9f7;border:1px solid #ede9e0;border-radius:4px;padding:6px 10px;">'
        +'<div style="font-size:8px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#9ca3af;">Entit&#233; audit&#233;e</div>'
        +'<div style="font-size:11px;font-weight:700;color:#1a1a2e;">'+escHtml(socVal)+'</div>'
      +'</div>'
      +'<div style="flex:1;background:#faf9f7;border:1px solid #ede9e0;border-radius:4px;padding:6px 10px;">'
        +'<div style="font-size:8px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:#9ca3af;">Date</div>'
        +'<div style="font-size:11px;font-weight:700;color:#1a1a2e;">'+dateVal+'</div>'
      +'</div>'
    +'</div>';
}

// Pied de page imprimable FRAP : 3 blocs signature
function _buildFrapPrintFooter(f){
  function signBox(label, name){
    return '<div style="border:1px solid #e2e8f0;border-radius:5px;padding:10px 12px;">'
      +'<div style="font-size:9px;font-weight:700;color:#374151;text-transform:uppercase;letter-spacing:.05em;">'+label+'</div>'
      +(name ? '<div style="font-size:9px;color:#6b7280;margin-top:2px;">'+escHtml(name)+'</div>' : '')
      +'<div style="border-bottom:1px solid #94a3b8;margin-top:'+(name?38:52)+'px;"></div>'
      +'<div style="font-size:8px;color:#94a3b8;text-align:center;margin-top:4px;">Signature</div>'
    +'</div>';
  }
  return '<div style="margin-top:22px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:14px;page-break-inside:avoid;">'
    + signBox('Auditeur', f.auditeur)
    + signBox('Chef de mission', '')
    + signBox('Responsable audit&#233;', '')
  +'</div>';
}

// Construit une page A4 complète (en-tête + carte FRAP + pied de page) pour une FRAP
function frapBuildPrintDoc(f){
  return '<div class="frap-print-doc" style="width:210mm;min-height:297mm;box-sizing:border-box;padding:14mm 12mm;background:#fff;page-break-after:always;">'
    + _buildFrapPrintHeader(f)
    + frapCardHtml(f, false)
    + _buildFrapPrintFooter(f)
  +'</div>';
}

// Impression d'une seule FRAP (bouton 🖨️ sur la carte)
function frapPrintOne(id){
  var f = FRAP_DATA.find(function(x){ return x.id === id; });
  if(!f){ toast('error','!','FRAP introuvable.'); return; }
  $('#om-print-area').html(frapBuildPrintDoc(f)).show();
  window.print();
  setTimeout(function(){ $('#om-print-area').hide().empty(); }, 800);
}
window.frapPrintOne = frapPrintOne;

// Impression groupée : chaque FRAP filtrée sur sa propre page, avec en-tête et pied de page
function frapPrint(){
  var filtered = frapGetFiltered();
  if(!filtered.length){ toast('error','!','Aucune FRAP à imprimer.'); return; }
  var docs = filtered.map(function(f){ return frapBuildPrintDoc(f); }).join('');
  $('#om-print-area').html(docs).show();
  window.print();
  setTimeout(function(){ $('#om-print-area').hide().empty(); }, 800);
}

// ── Événements ────────────────────────────────────────────────────
$(document).ready(function(){
  $('#frap-add-btn').on('click', function(){ frapOpenModal(); });
  $('#frap-print-btn').on('click', frapPrint);
  $('#frap-modal-close, #frap-modal-cancel').on('click', frapCloseModal);
  $('#frap-modal-save').on('click', frapSaveModal);
  $('#frap-f-taf-ref').on('change', function(){ frapApplyTAFLink(this.value); });
  $('#frap-f-audit-ref').on('change', function(){ frapApplyAuditRefLink(this.value); });
  $('#frap-add-reco').on('click', function(){
    var n = $('#frap-recos-list .reco-row').length;
    $('#frap-recos-list').append(RECO_ROW(null, n));
  });
  $(document).on('input','#frap-recos-list .reco-av-range',function(){
    $(this).closest('.reco-row').find('.reco-av-lbl').text($(this).val()+'%');
  });
  $(document).on('click','#frap-recos-list .reco-row-del',function(){
    var $rows=$('#frap-recos-list .reco-row');
    if($rows.length<=1){ toast('error','!','Au moins une recommandation est requise.'); return; }
    $(this).closest('.reco-row').remove();
    $('#frap-recos-list .reco-row').each(function(i){
      $(this).attr('data-ri',i);
      $(this).find('span[style*="accent"]').first().text('Recommandation '+(i+1));
      $(this).find('.reco-row-del').attr('data-ri',i);
    });
  });
  $('#frap-add-action').on('click', function(){
    document.getElementById('frap-actions-list').appendChild(frapBuildActionRow(''));
  });
  // Zone Preuve — pièces jointes
  $('#frap-add-preuve').on('click', function(){
    document.getElementById('frap-f-preuve-input').click();
  });
  $('#frap-f-preuve-input').on('change', function(){
    frapHandleFiles(this.files);
    this.value = '';
  });
  $('#frap-preuve-dropzone').on('dragover', function(e){
    e.preventDefault(); e.stopPropagation();
    $(this).addClass('dragover');
  }).on('dragleave drop', function(e){
    e.preventDefault(); e.stopPropagation();
    $(this).removeClass('dragover');
  }).on('drop', function(e){
    var dt = e.originalEvent && e.originalEvent.dataTransfer;
    if(dt && dt.files && dt.files.length) frapHandleFiles(dt.files);
  });
  $(document).on('click', '.frap-preuve-rm', function(e){
    e.stopPropagation();
    frapRemovePreuve($(this).data('pid'));
  });
  $(document).on('click', '.frap-preuve-open-temp', function(){
    var pid = $(this).data('pid');
    var p = FRAP_PREUVES_TEMP.find(function(x){ return x.id === pid; });
    if(p) frapOpenPreuve(p);
  });
  $(document).on('click', '.frap-preuve-open-saved', function(){
    var fid = $(this).data('fid'), pid = $(this).data('pid');
    var f = FRAP_DATA.find(function(x){ return x.id === fid; });
    var p = f && f.preuves && f.preuves.find(function(x){ return x.id === pid; });
    if(p) frapOpenPreuve(p);
  });
  $('#frap-search, #frap-filter-crit, #frap-filter-societe').on('input change', function(){
    renderFRAP();
  });
  // Fermer modal sur clic fond
  $('#frap-modal-bk').on('click', function(e){
    if(e.target === this) frapCloseModal();
  });
});
</script>

<!-- MODALE — Sélection de mission (impression ciblée depuis une carte Société) -->
<div id="soc-mission-picker-modal" style="display:none;position:fixed;inset:0;z-index:9600;background:rgba(0,0,0,.55);align-items:center;justify-content:center;">
  <div style="background:#fff;border-radius:8px;padding:16px 18px;width:420px;max-width:92vw;max-height:72vh;overflow-y:auto;box-shadow:0 8px 40px rgba(0,0,0,.35);">
    <div id="soc-mp-title" style="font-size:13px;font-weight:700;margin-bottom:4px;color:#1a1a2e;">Sélectionner une mission</div>
    <div style="font-size:10.5px;color:#6c7682;margin-bottom:10px;">Plusieurs missions existent pour cette société. Choisissez celle à imprimer.</div>
    <div id="soc-mp-list" style="display:flex;flex-direction:column;gap:6px;"></div>
    <div style="text-align:right;margin-top:14px;">
      <button id="soc-mp-cancel" class="btn" style="font-size:11px;padding:4px 14px;">Annuler</button>
    </div>
  </div>
</div>

<!-- MODALE — Affecter un membre de l'équipe à une ou plusieurs missions (Équipe Auditeurs — Missions & Charge) -->
<div id="aud-assign-modal" style="display:none;position:fixed;inset:0;z-index:9600;background:rgba(0,0,0,.55);align-items:center;justify-content:center;">
  <div style="background:#fff;border-radius:8px;padding:16px 18px;width:460px;max-width:92vw;max-height:74vh;overflow-y:auto;box-shadow:0 8px 40px rgba(0,0,0,.35);">
    <div id="aud-assign-title" style="font-size:13px;font-weight:700;margin-bottom:4px;color:#1a1a2e;">Affecter à des missions</div>
    <div style="font-size:10.5px;color:#6c7682;margin-bottom:10px;">Cochez les missions du Plan d'audit interne auxquelles rattacher ce membre de l'équipe.</div>
    <div id="aud-assign-list" style="display:flex;flex-direction:column;gap:2px;"></div>
    <div style="text-align:right;margin-top:14px;display:flex;gap:8px;justify-content:flex-end;">
      <button id="aud-assign-cancel" class="btn" style="font-size:11px;padding:4px 14px;">Annuler</button>
      <button id="aud-assign-save" class="btn p" style="font-size:11px;padding:4px 14px;">Enregistrer</button>
    </div>
  </div>
</div>

<script src="https://code.jquery.com/jquery-3.7.1.min.js"></script>
</body>
